#  -----------------------------------------------------------------------------
#  sub is_number
#  -----------------------------------------------------------------------------
#  sub is_number is a moidifed version of getNum() 
#  Checking Whether a String Is a Valid Number
#  http://www.unix.org.ua/orelly/perl/cookbook/ch02_02.htm
#  -----------------------------------------------------------------------------
sub is_number 
{   use POSIX qw(strtod);
    my $str = shift;
    $str =~ s/^\s+//;
    $str =~ s/\s+$//;
    $! = 0;
    my($num, $unparsed) = strtod($str);
    if (($str eq '') || ($unparsed != 0) || $!) 
    {   return (0);
    } else 
    {   return (1);
    }
} 
    
    
    
    
    
sub SciMiner_email_password_check
{   my $email               = shift;
    my $passCodeEntered     = shift;
    
    use DBI;
  
    #  Load working environment for ANNOTATION
    my %annoENV = anno_environmental_file_open ( );
    my $annoBaseDir = $annoENV{ANNOPath};

    #  Database Access Information
    my $SciMinerDB   = "DBI:mysql:database=".$annoENV{DB} || return (-1, "!ERROR: No database specified");
    my $username    = $annoENV{username} || return (-1, "!ERROR: No username specified");
    my $password    = $annoENV{password} || return (-1, "!ERROR: No password specified");

    #  ------------------------------------------------------------------------
    #  Retrieve User Information from SciMinerDB
    #  ------------------------------------------------------------------------
    my $dbh         = DBI->connect($SciMinerDB, $username, $password, {PrintError => 0}) || 
                      return (-1, "!ERROR: Couldn't connect to database ".$DBI::errstr);
    my $sql         = "SELECT passCode, activationStatus, suspended FROM user where email = \"$email\"";
    my $sth         = $dbh->prepare($sql);
    $sth->execute();
    my @row         = $sth->fetchrow_array;
    my $passCode    = $row[0];
    
	if ((defined $row[2]) && ($row[2] == 1))
	{	return('SUSPENDED');
	}

	if ((defined $row[1]) && ($row[1] == 0))
	{	return('INACTIVE');
	}

    if ((defined $passCode) && (defined $passCodeEntered) && ($passCode eq $passCodeEntered))
    {   #  This is legitimnate user
        return ('CORRECT');
    }else
    {   return ('INCORRECT');
    }
}





sub get_realname_by_email
{   my $email               = shift;
    
    use DBI;
  
