sub calculate_new_document_count
{	my $pmidArrRef			= shift;

	use DBI;
  
    #  Load working environment for ANNOTATION
    my %annoENV = anno_environmental_file_open ( );
    my $annoBaseDir = $annoENV{ANNOPath};

    #  Database Access Information
    my $SciMinerDB   = "DBI:mysql:database=".$annoENV{DB} || return (-1, "!ERROR: No database specified");
    my $username    = $annoENV{username} || return (-1, "!ERROR: No username specified");
    my $password    = $annoENV{password} || return (-1, "!ERROR: No password specified");

    #  ------------------------------------------------------------------------
    #  Retrieve User Information from SciMinerDB
    #  ------------------------------------------------------------------------
    my $dbh         = DBI->connect($SciMinerDB, $username, $password, {PrintError => 0}) || 
                      return (-1, "!ERROR: Couldn't connect to database ".$DBI::errstr);
    my $docString	= join (",", @{$pmidArrRef});
    my $sql         = "SELECT pmid FROM document";
    my $sth         = $dbh->prepare($sql);
    $sth->execute();
    my @row         = ();
    my $totalinput	= scalar @{$pmidArrRef};

	my %pmidProcessed	= ();
	while(@row = $sth->fetchrow_array)
	{   $pmidProcessed{$row[0]}	= 1;
	}

	my $processedCnt	= 0;
	#  Check the total number of papers previously processed
	for (my $i=0; $i < $totalinput; $i++)
	{	if (defined $pmidProcessed{$$pmidArrRef[$i]})
		{	$processedCnt++;
		}
	}

	return($totalinput-$processedCnt);
}





# subroutine: search_entrez_with_pubmed_query
# Date: 09/21/2007
# This subroutine performs a Entrez search with the given query string
# and returns the result and PMIDs by array reference.
sub search_entrez_with_pubmed_query
{   use LWP::UserAgent;                 
    use LWP::Simple;
    
    my $queryString = shift;

    # Initialize Web UserAgent
    my $ua = LWP::UserAgent->new;
    $ua->agent('Mozilla/5.0');
    $ua->timeout(60);
    push @{ $ua->requests_redirectable }, 'POST';

    # Links and directories
    my $ESEARCH     = 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi?';
    my $EFETCH      = 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi?';
    my $ELINK       = 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils/elink.fcgi?';

    # variables to be used
    my $retmax          = 1000000;      my $dayspast        = '';
    my $fetchHTML       = 'YES';        my $redoFetch       = 'NO';         
    my @pmids           = ();
    my $fetched         = '';
    my $fetchStatus     = 1;
    my $count           = 0;
    my @tmpLines		= ();

    # Search with the query term and fetch the PMID
    if ((defined $queryString) && ($queryString ne ""))
    {   my $url     = $ESEARCH."db=pubmed&reldate=$dayspast&datetype=edat&".
                      "retmax=$retmax&usehistory=y&format=xml&term=$queryString";
    	$fetched = get($url);
    	if ((not defined $fetched) || ($fetched eq ""))
    	{   $fetchStatus = -1;  # Just return -1 when the fetch is unsuccessful
    	} 
    	if ($fetchStatus == 1)
    	{   $count   = 0;
            if ($fetched =~ /<Count>(\d+)<\/Count>/)
            {   $count = $1;
                if ( $count == 0 )
                {   $fetchStatus = 0;
                }else
                {   @tmpLines = split (/\n/, $fetched);
                    foreach my $line (@tmpLines)
                    {   $line =~ s/\r|\n//g;
                        if( $line =~ /<Id>(\d+)<\/Id>/msgi )
                        {   push @pmids, $1;
                        }
                    }
                }
            }else
            {   $fetchStatus = 0;
            }
    	}
    }else
    {   # But in fact, there will be no this case.
        #$fetchStatus = -2;    # If the query string is not defined, return -2
    }

    # Return status, resultString, and pmid array
    return ($fetchStatus, $fetched, $count, \@pmids);
}





# subroutine: process_PMID_list_text
# Date: 09/21/2007
# This subroutine process the listText from user to create an array of PMIDs.
sub process_PMID_list_text
{   my $listText    = shift;

    my $status      = 0;
    my @pmids       = ();
    my @tmpSplit    = split (/\n/, $listText);
    my $countOfSplit = scalar @tmpSplit;
    my %pmidCheck   = ();
    
    # Briefly check the format
    if ($listText =~ /<Id>\d+<\/Id>/msgi)
    {   foreach my $line (@tmpSplit)
        {   $line =~ s/\r|\n//g;
            if ($line =~ /<Id>(\d+)<\/Id>/msgi)
            {   if (not defined $pmidCheck{$1})
                {   push @pmids, $1;
                    $pmidCheck{$1} = 1;
                }
            }
        }
    }else
    {   foreach my $line (@tmpSplit)
        {   $line =~ s/\r|\n//g;
            if ((defined $line) && ($line ne "") &&($line !~ /\D/))
            {   if (not defined $pmidCheck{$line})
                {   push @pmids, $line;
                    $pmidCheck{$line} = 1;
                }
            }
        }
    }
    
    # check the number of pmids in the array
    my $count = scalar @pmids;
    return ($count, \@pmids);
}





sub display_errorMessage_SciMiner_CGI
{   my $errorMessageRef = shift;
    
    if (not defined $errorMessageRef)
    {   return;
    }
    
    print "<font color=\"red\">";
    for (my $i=0; $i < scalar @{$errorMessageRef}; $i++)
    {   if ($$errorMessageRef[$i] ne "")
        {   print " Error ".($i+1).": $$errorMessageRef[$i]<br>";
        }
    }
    print "</font><font color=\"black\">";
}





sub check_query_number_validity
{   my $queryType             = shift;
    my $queryNumber           = shift;
    my $errorMessageRef       = shift;
    
    use DBI;
  
    #  Load working environment for ANNOTATION
    my %annoENV = anno_environmental_file_open ( );
    my $annoBaseDir = $annoENV{ANNOPath};

    #  Database Access Information
    my $SciMinerDB   = "DBI:mysql:database=".$annoENV{DB} || return (-1, "!ERROR: No database specified");
    my $username    = $annoENV{username} || return (-1, "!ERROR: No username specified");
    my $password    = $annoENV{password} || return (-1, "!ERROR: No password specified");

    #  ------------------------------------------------------------------------
    #  Retrieve User Information from SciMinerDB
    #  ------------------------------------------------------------------------
    my $dbh         = DBI->connect($SciMinerDB, $username, $password, {PrintError => 0}) || 
                      return (-1, "!ERROR: Couldn't connect to database ".$DBI::errstr);
    my $sql         = "SELECT status, deleted FROM query where queryID = $queryNumber";
    my $sth         = $dbh->prepare($sql);
    $sth->execute();
    my @row         = $sth->fetchrow_array;
   
    if (not defined $row[0])
    {   push @{$errorMessageRef}, "There is no query matching your $queryType query number";
    }else
    {   if ($row[0] != 3)
        {   push @{$errorMessageRef}, "Query #$queryNumber ($queryType) has not completed thus can't be used in analysis";
        }
        if ($row[1] == 1)
        {   push @{$errorMessageRef}, "Query #$queryNumber ($queryType) has been deleted. You can't use this query result";
        }
    }
}





sub check_query_number_validity_with_userinfo
{   my $queryType               = shift;
    my $queryNumber             = shift;
    my $errorMessageRef         = shift;
    my $email                   = shift;
    
    use DBI;
  
    #  Load working environment for ANNOTATION
    my %annoENV = anno_environmental_file_open ( );
    my $annoBaseDir = $annoENV{ANNOPath};

    #  Database Access Information
    my $SciMinerDB   = "DBI:mysql:database=".$annoENV{DB} || return (-1, "!ERROR: No database specified");
    my $username    = $annoENV{username} || return (-1, "!ERROR: No username specified");
    my $password    = $annoENV{password} || return (-1, "!ERROR: No password specified");

    #  ------------------------------------------------------------------------
    #  Retrieve User Information from SciMinerDB
    #  ------------------------------------------------------------------------
    my $dbh         = DBI->connect($SciMinerDB, $username, $password, {PrintError => 0}) || 
                      return (-1, "!ERROR: Couldn't connect to database ".$DBI::errstr);
    my $sql         = "SELECT userID FROM user where email = \"$email\"";
    my $sth         = $dbh->prepare($sql);
    $sth->execute();
    my @row         = $sth->fetchrow_array;
    my $userID      = 0;
    
    if ((defined $row[0]) && ($row[0] ne ""))
    {   $userID     = $row[0];
    }


    #  ------------------------------------------------------------------------
    #  Retrieve query Information from DB
    #  ------------------------------------------------------------------------
    $sql         = "SELECT userID, status, deleted FROM query where queryID = $queryNumber";
    $sth         = $dbh->prepare($sql);
    $sth->execute();
    @row         = $sth->fetchrow_array;
   
    if (not defined $row[0])
    {   push @{$errorMessageRef}, "There is no query matching your $queryType query number";
    }else
    {   if ($row[0] != $userID)
        {   push @{$errorMessageRef}, "Query #$queryNumber ($queryType) does not belong to you. Check your query number again.";
        }    
        if ($row[1] != 3)
        {   push @{$errorMessageRef}, "Query #$queryNumber ($queryType) has not completed thus can't be used in analysis.";
        }
        if ($row[2] == 1)
        {   push @{$errorMessageRef}, "Query #$queryNumber ($queryType) has been deleted. You can't use this query result.";
        }
    }
}





sub load_PMID_list_file
{	my $fileName	= shift;
	open (FILE, $fileName) || return();
	my @PMIDList	= ();
	
	while(<FILE>)
	{	my $line = $_;
		$line =~ s/\r|\n//g;
		push @PMIDList, $line;
	}
	close FILE;
	
	return(\@PMIDList);
}












































































































































































































































































































































































































































































