#
#   SECTION_2   Analysis Queue Processing
#
################################################################################
#  -----------------------------------------------------------------------------
#  process_post_mining_analysis_queue
#  -----------------------------------------------------------------------------
sub process_post_mining_analysis_queue
{   my $email                       = shift;   
    my $targetQueryNumber           = shift;
    my $bgQueryNumber               = shift;
    
    my $GeneEnrichmentCheck         = shift;
    my $GOEnrichmentCheck           = shift;
    my $MeSHEnrichmentCheck         = shift;
    my $PathwayEnrichmentCheck      = shift;
    my $PPICheck                    = shift;

    my $GeneEnrichmentSelection     = shift;
    my $GOEnrichmentSelection       = shift;
    my $MeSHEnrichmentSelection     = shift;
    my $PathwayEnrichmentSelection  = shift;
    my $PPISelection                = shift;
    my $PValueThreshold             = shift;
    
    # URL of the local server from the cgi 
    my $tmpLocalURL					= shift;

	# Minimum number of paper
	my $MinPaperMethodTG			= shift;
	my $MinTopPaperTG				= shift;
	my $MinPaperMethodBG			= shift;
	my $MinTopPaperBG				= shift;
	
	my $TGListFileContent			= shift;
	my $BGListFileContent			= shift;
	

    use DBI;
  
  	my $status						= 1;
  	my $message						= '';
  	
    #  Load working environment for ANNOTATION
    my %annoENV 					= anno_environmental_file_open ( );
    my $annoBaseDir 				= $annoENV{ANNOPath};
    my %currentQueueEnv				= ();

	#  Update the SciMinerServerURL
	$annoENV{SciMinerServerURL}	= $tmpLocalURL;

       
                                    	
    #  Database Access Information
    my $SciMinerDB   = "DBI:mysql:database=".$annoENV{DB} || return (-1, "!ERROR: No database specified");
    my $username    = $annoENV{username} || return (-1, "!ERROR: No username specified");
    my $password    = $annoENV{password} || return (-1, "!ERROR: No password specified");

    #  ------------------------------------------------------------------------
    #  Retrieve User Information from SciMinerDB
    #  ------------------------------------------------------------------------
    my $dbh         = DBI->connect($SciMinerDB, $username, $password, {PrintError => 0}) || 
                      return (-1, "!ERROR: Couldn't connect to database ".$DBI::errstr);
    my $sql         = "SELECT userID FROM user where email like \"$email\"";
    my $sth         = $dbh->prepare($sql);
    $sth->execute();
    my @row         = $sth->fetchrow_array;
    my $userID      = $row[0];
    
    #  Check for userID
    if ((not defined $userID) || ($userID eq ""))
    {   $status 	= 0;
    	$message	= "<font color=\"red\">!ERROR! Your email <b>'$email'</b> is not registered. Please use your registered email only.</font>";
    	return ($status, $message);
    }
    #  ------------------------------------------------------------------------
    #  Update SciMinerDB for this query and get the queryID
    #  ------------------------------------------------------------------------
    my $analID     = '';
    
    #  -------------------------------------------------------------------------
    #  Test types selection confirmation for DB insertion 
    #  -------------------------------------------------------------------------
    my $geneStatus		= 0;
    my $goStatus		= 0;
    my $meshStatus		= 0;
    my $pathwayStatus	= 0;
    my $ppiStatus		= 0;
    
    if ($GeneEnrichmentCheck eq 'on')
    {	$geneStatus		= 1;
    }
    if ($GOEnrichmentCheck eq 'on')
    {	$goStatus		= 1;
    }
    if ($MeSHEnrichmentCheck eq 'on')
    {	$meshStatus		= 1;
    }
    if ($PathwayEnrichmentCheck eq 'on')
    {	$pathwayStatus	= 1;
    }
    if ($PPICheck eq 'on')
    {	$ppiStatus		= 1;
    }

    #  Insert new query information 
	if ((defined $bgQueryNumber) && ($bgQueryNumber ne ""))
	{   $dbh->do("INSERT INTO `analysis` (userID, TQueryID, BGQueryID, dateCreate, status, gene, go, mesh, pathway, ppi) VALUES ($userID, $targetQueryNumber, $bgQueryNumber, curdate(), 1, $geneStatus, $goStatus, $meshStatus, $pathwayStatus, $ppiStatus)") || LogAnalysis( "!ERROR:  $DBI::errstr") ;   
	}else
	{	$dbh->do("INSERT INTO `analysis` (userID, TQueryID, BGQueryID, dateCreate, status, gene, go, mesh, pathway, ppi) VALUES ($userID, $targetQueryNumber, 0, curdate(), 1, $geneStatus, $goStatus, $meshStatus, $pathwayStatus, $ppiStatus)") || LogAnalysis( "!ERROR:  $DBI::errstr") ;   
	}
    
    
    #  Retrieve the queryID of the recently inserted query
    $sth            = $dbh->prepare("SELECT analID FROM analysis ORDER BY analID DESC LIMIT 1");
    $sth->execute();
    @row            = $sth->fetchrow_array;#($result);
    $analID         = $row[0];
    
    
    
    #  ------------------------------------------------------------------------
    #  Get query base names
    #  ------------------------------------------------------------------------  
    my $targetQueryNumber2BaseName  = '';
    my $bgQueryNumber2BaseName      = '';

    my %tgQueryEnv                  = ();
    my %bgQueryEnv                  = ();
	
    $sth                            = $dbh->prepare("SELECT resultURL, queryName, numPMID, numGene, miningMode FROM query where queryID = $targetQueryNumber");
    $sth->execute();
    @row                            = $sth->fetchrow_array;#($result);
    my @tqLinkSplit                 = split (/\//, $row[0]);
    $tgQueryEnv{resultURL}          = $row[0];
    $tgQueryEnv{queryName}          = $row[1];
    $tgQueryEnv{numPMID}            = $row[2];
    $tgQueryEnv{numGene}            = $row[3];
    $tgQueryEnv{miningMode}			= $row[4];
    $tgQueryEnv{baseName}           = $tqLinkSplit[$#tqLinkSplit-1];
    $targetQueryNumber2BaseName     = $tqLinkSplit[$#tqLinkSplit-1];
    
    if ((($GeneEnrichmentCheck eq "on") && ($GeneEnrichmentSelection eq 'Selected')) || 
            (($GOEnrichmentCheck eq "on") && ($GOEnrichmentSelection eq 'Selected')) || 
            (($MeSHEnrichmentCheck eq "on") && ($MeSHEnrichmentSelection eq 'Selected')) ||
            (($PathwayEnrichmentCheck eq "on") && ($PathwayEnrichmentSelection eq 'Selected')) || 
            (($PPICheck eq "on") && ($PPISelection eq 'Selected')))
    {   $sth                        = $dbh->prepare("SELECT resultURL, queryName, numPMID, numGene FROM query where queryID = $bgQueryNumber");
        $sth->execute();
        @row                        = $sth->fetchrow_array;#($result);
        my @bgLinkSplit             = split (/\//, $row[0]);
        $bgQueryNumber2BaseName     = $bgLinkSplit[$#bgLinkSplit-1];
    
        $bgQueryEnv{resultURL}          = $row[0];
        $bgQueryEnv{queryName}          = $row[1];
        $bgQueryEnv{numPMID}            = $row[2];
        $bgQueryEnv{numGene}            = $row[3];
        $bgQueryEnv{baseName}           = $bgLinkSplit[$#tqLinkSplit-1];
    }

    #  ------------------------------------------------------------------------
    #  Write the query info into a file
    #  ------------------------------------------------------------------------    
    my @tmpSplit        = split(/\@/, $email);
    my $fileNameBase    = 'Analysis_'.$analID.'__'.$tmpSplit[0];
    my $confFileName    = $annoENV{SciMinerPath}."Work/".$fileNameBase.'.conf';
    my $queryAnalInfo	= "-- Analysis Info --\n";
	my $currentProcessingTime	= 0;
	
	
	#  Creating currentQueueEnv hash 
	$currentQueueEnv{analID}						= $analID;
	$currentQueueEnv{email}							= $email;
	$currentQueueEnv{fileNameBase}					= $fileNameBase;
	$currentQueueEnv{targetQueryNumber}				= $targetQueryNumber;
	$currentQueueEnv{targetQueryNumber2BaseName}	= $targetQueryNumber2BaseName;
    $currentQueueEnv{PValueThreshold}				= $PValueThreshold;
    $currentQueueEnv{GeneEnrichmentSelection}		= $GeneEnrichmentSelection;
    $currentQueueEnv{GOEnrichmentSelection}			= $GOEnrichmentSelection;
    $currentQueueEnv{MeSHEnrichmentSelection}		= $MeSHEnrichmentSelection;
    $currentQueueEnv{PathwayEnrichmentSelection}	= $PathwayEnrichmentSelection;
    $currentQueueEnv{PPISelection}					= $PPISelection;
    $currentQueueEnv{SciMinerServerURL}				= $tmpLocalURL;
    $currentQueueEnv{MinPaperMethodTG}				= $MinPaperMethodTG;
    $currentQueueEnv{MinTopPaperTG}					= $MinTopPaperTG;
    $currentQueueEnv{MinPaperMethodBG}				= $MinPaperMethodBG;
    $currentQueueEnv{MinTopPaperBG}					= $MinTopPaperBG;	
    $currentQueueEnv{miningMode}					= $tgQueryEnv{miningMode};	
    $currentQueueEnv{TGListFileContent}				= $TGListFileContent;	
    $currentQueueEnv{BGListFileContent}				= $BGListFileContent;	
    
    
    #  Write configuration into file
    open (CONF, ">".$confFileName) || print "! Can't write into file. Contact the admin<br>";
    
    print CONF "analID\t$analID\n";
    print CONF "email\t$email\n";
    print CONF "fileNameBase\t$fileNameBase\n";
    
    print CONF "targetQueryNumber\t$targetQueryNumber\n";
    print CONF "targetQueryNumber2BaseName\t$targetQueryNumber2BaseName\n";
    $queryAnalInfo .= "Target query number: $targetQueryNumber\t($targetQueryNumber2BaseName)\n";
    
    if (defined $bgQueryNumber)
    {   print CONF "bgQueryNumber\t$bgQueryNumber\n";
        print CONF "bgQueryNumber2BaseName\t$bgQueryNumber2BaseName\n";
		$queryAnalInfo .= "Background query number: $bgQueryNumber\t($bgQueryNumber2BaseName)\n";
		$currentQueueEnv{bgQueryNumber}					= $bgQueryNumber;	
		$currentQueueEnv{bgQueryNumber2BaseName}		= $bgQueryNumber2BaseName;
    }else
    {   print CONF "bgQueryNumber\t\n";
        print CONF "bgQueryNumber2BaseName\t\n";
        $currentQueueEnv{bgQueryNumber}					= '';	
		$currentQueueEnv{bgQueryNumber2BaseName}		= '';
    }
    
    if (defined $GeneEnrichmentCheck)
    {   print CONF "GeneEnrichmentCheck\t$GeneEnrichmentCheck\n";
    	$queryAnalInfo .= "Gene Enrichment Test: Selected\n";
    	$currentQueueEnv{GeneEnrichmentCheck}			= $GeneEnrichmentCheck;
    	$currentProcessingTime							+= 5;
    }else
    {   print CONF "GeneEnrichmentCheck\t\n";
    	$currentQueueEnv{GeneEnrichmentCheck}			= '';
    }
    
    if (defined $GOEnrichmentCheck)
    {   print CONF "GOEnrichmentCheck\t$GOEnrichmentCheck\n";
    	$queryAnalInfo .= "Gene Ontology (GO) Test: Selected\n";
    	$currentQueueEnv{GOEnrichmentCheck}				= $GOEnrichmentCheck;
		if ($currentQueueEnv{GOEnrichmentSelection} eq 'FullHUGO')
		{	$currentProcessingTime						+= 30;
		}
    	$currentProcessingTime							+= 15;
    }else
    {   print CONF "GOEnrichmentCheck\t\n";
    	$currentQueueEnv{GOEnrichmentCheck}				= '';
    }
    
    if (defined $MeSHEnrichmentCheck)
    {   print CONF "MeSHEnrichmentCheck\t$MeSHEnrichmentCheck\n";
    	$queryAnalInfo .= "MeSH Enrichment Test: Selected\n";
    	$currentQueueEnv{MeSHEnrichmentCheck}			= $MeSHEnrichmentCheck;
    	$currentProcessingTime							+= 10;
    }else
    {   print CONF "MeSHEnrichmentCheck\t\n";
    	$currentQueueEnv{MeSHEnrichmentCheck}			= '';
    }
    
    if (defined $PathwayEnrichmentCheck)
    {   print CONF "PathwayEnrichmentCheck\t$PathwayEnrichmentCheck\n";
    	$queryAnalInfo .= "Pathway Enrichment Test: Selected\n";
    	$currentQueueEnv{PathwayEnrichmentCheck}		= $PathwayEnrichmentCheck;
    	$currentProcessingTime							+= 10;
    }else
    {   print CONF "PathwayEnrichmentCheck\t\n";
    	$currentQueueEnv{PathwayEnrichmentCheck}		= '';
    }
    
    if (defined $PPICheck)
    {   print CONF "PPICheck\t$PPICheck\n";
    	$queryAnalInfo .= "PPI Enrichment Test: Selected\n";
    	$currentQueueEnv{PPICheck}						= $PPICheck;
		if ($currentQueueEnv{PPISelection} eq 'FullHUGO')
		{	$currentProcessingTime						+= 30;
		}
    	$currentProcessingTime							+= 15;
    }else
    {   print CONF "PPICheck\t\n";
    	$currentQueueEnv{PPICheck}					= '';
    }            
    print CONF "PValueThreshold\t$PValueThreshold\n";
    print CONF "GeneEnrichmentSelection\t$GeneEnrichmentSelection\n";
    print CONF "GOEnrichmentSelection\t$GOEnrichmentSelection\n";
    print CONF "MeSHEnrichmentSelection\t$MeSHEnrichmentSelection\n";
    print CONF "PathwayEnrichmentSelection\t$PathwayEnrichmentSelection\n";
    print CONF "PPISelection\t$PPISelection\n";
    print CONF "SciMinerServerURL\t$tmpLocalURL\n";
    print CONF "MinPaperMethodTG\t$MinPaperMethodTG\n";
    print CONF "MinTopPaperTG\t$MinTopPaperTG\n";
    print CONF "MinPaperMethodBG\t$MinPaperMethodBG\n";
    print CONF "MinTopPaperBG\t$MinTopPaperBG\n";
    print CONF "miningMode\t$tgQueryEnv{miningMode}\n";
    print CONF "TGListFileContent\t$TGListFileContent\n";
    print CONF "BGListFileContent\t$BGListFileContent\n";
    
    close (CONF);    



        	

    #  -------------------------------------------------------------------------
    #  Generate temporary result html file and symbolic link
    #  -------------------------------------------------------------------------
    #  Final Result Directory
    mkdir ("$annoENV{SciMinerPath}Work/FinalResults/") 				|| print "";
    mkdir ("$annoENV{SciMinerPath}Work/FinalResults/$fileNameBase/") || print "";
    mkdir ("$annoENV{SciMinerWebPath}FinalResults/") 				|| print "";
    mkdir ("$annoENV{SciMinerWebPath}FinalResults/$fileNameBase/") 	|| print "";
    
	generate_temporary_result_html ("$annoENV{SciMinerServerURL}/SciMiner/FinalResults/$fileNameBase/analysisSummary.html",
                                    "$annoENV{SciMinerWebPath}FinalResults/$fileNameBase/analysisSummary.html",
                                    \%currentQueueEnv, 
                                    "$annoENV{SciMinerServerURL}/SciMiner/",
                                    \%tgQueryEnv, \%bgQueryEnv);
                                    
                                    
    #  Initiate the SciMiner Analysis auto process if not running
    my $psResult = `ps -ef | grep 'MonitorSciMinerAnalysis.pl'`;
    my $SciMinerAnalysisMonitorStatus = 0;
    my @tmpLineSplit = split (/\n/, $psResult);

    foreach my $line (@tmpLineSplit)
    {   if ($line =~ /perl/)
        {   # There is a process running with 'SciMinerAnalysisMonitor.pl'
            $SciMinerAnalysisMonitorStatus = 1;
        }
    }
    
    #  Launch SciMinerAnalysisMonitor.pl only when it's not running
    if (! $SciMinerAnalysisMonitorStatus)
    {   if (-f "$annoENV{SciMinerPath}/Work/AnalysisList")
        {   unlink ("$annoENV{SciMinerPath}/Work/AnalysisList");
        }
        if (-f "$annoENV{SciMinerPath}/Work/AnalysisQueue")
        {   unlink ("$annoENV{SciMinerPath}/Work/AnalysisQueue");
        }
    	system ("$annoENV{Perl} $annoENV{SciMinerPath}/Scripts/Main/MonitorSciMinerAnalysis.pl &");
    }
    
    #  Give the order in the queue
    sleep(1);
    my $aheadFileCnt = 0;
    if (-f "$annoENV{SciMinerPath}/Work/AnalysisQueue")
    {   open (CURRENT, "$annoENV{SciMinerPath}/Work/AnalysisQueue");
        my $currentAnalysisNumber = <CURRENT>;
        close CURRENT;
        $currentAnalysisNumber =~ s/\r|\n//g;
        $aheadFileCnt = $analID - $currentAnalysisNumber;
    }
    
	my $startProcessingTimeSeconds	= 	$aheadFileCnt*120;		# average 120 second per analysis
	
	my $startProcessingTimeStr		=	'';
	if ($startProcessingTimeSeconds >= 3600)
	{	my $hours	= int($startProcessingTimeSeconds / 3600);
		$startProcessingTimeStr		= "within $hours hour(s)";
	}elsif ($startProcessingTimeSeconds <= 60)
	{	$startProcessingTimeStr		= "within 1 minute";
	}else
	{	my $minutes	= int($startProcessingTimeSeconds / 60);
		$startProcessingTimeStr		= "within $minutes minute(s)";
	}
	
	my $currentProcessingTimeStr	= '';
	if ($currentProcessingTime >= 3600)
	{	my $hours	= int($currentProcessingTime / 3600);
		$currentProcessingTimeStr	= "~ $hours hours";
	}elsif ($currentProcessingTime <= 60)
	{	$currentProcessingTimeStr		= "less than 1 minute";
	}else
	{	my $minutes	= int($currentProcessingTime / 60);
		$currentProcessingTimeStr		= "~ $minutes minutes";
	}



   	#  !_! New formatted table for result summary
    print 	"<br><br><br>
    		<table border='1' width='800' align='center' style=\"text-align: center\">
				<tr class='titleBarName1'>
					<th width='300'>User Email</th>
					<th width='500'>$email</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Analysis ID #</th>
					<th>$analID</th>
				</tr>
				";
	if ($currentQueueEnv{GeneEnrichmentCheck} eq 'on')
	{	print "	<tr class='titleBarName1'>
					<th>Target List Enrichment</th>
					<th>Selected</th>
				</tr>
				";
	}else
	{	print "	<tr class='titleBarName1'>
					<th>Target List Enrichment</th>
					<th>&nbsp;</th>
				</tr>
				";
	}
	if ($currentQueueEnv{GOEnrichmentCheck} eq 'on')
	{	print "	<tr class='titleBarName1'>
					<th>Gene Ontology (GO) Enrichment</th>
					<th>Selected</th>
				</tr>
				";
	}else
	{	print "	<tr class='titleBarName1'>
					<th>Gene Ontology (GO) Enrichment</th>
					<th>&nbsp;</th>
				</tr>
				";
	}
	if ($currentQueueEnv{MeSHEnrichmentCheck} eq 'on')
	{	print "	<tr class='titleBarName1'>
					<th>MeSH Term Enrichment</th>
					<th>Selected</th>
				</tr>
				";
	}else
	{	print "	<tr class='titleBarName1'>
					<th>MeSH Term Enrichment</th>
					<th>&nbsp;</th>
				</tr>
				";
	}
	if ($currentQueueEnv{PathwayEnrichmentCheck} eq 'on')
	{	print "	<tr class='titleBarName1'>
					<th>Pathway Enrichment</th>
					<th>Selected</th>
				</tr>
				";
	}else
	{	print "	<tr class='titleBarName1'>
					<th>Pathway Enrichment</th>
					<th>&nbsp;</th>
				</tr>
				";
	}
	
	if ($currentQueueEnv{PPICheck} eq 'on')
	{	print "	<tr class='titleBarName1'>
					<th>PPI Network Integrity</th>
					<th>Selected</th>
				</tr>
				";
	}else
	{	print "	<tr class='titleBarName1'>
					<th>PPI Network Integrity</th>
					<th>&nbsp;</th>
				</tr>
				";
	}
	print "		<tr class='titleBarName1'>	
					<th>
						&nbsp;
					</th>
					<th>
						&nbsp;
					</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Number of queued analyses<br>ahead of your analysis</th>
					<th>$aheadFileCnt</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Submission Time</th>
					<th>".get_current_time_full()."</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Estimated initaition time</th>
					<th>$startProcessingTimeStr</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Estimated processing time</th>
					<th>$currentProcessingTimeStr</th>
				</tr>
    		</table>";


    print "<p align='center' class='titleBarName1'> Your analysis has been successfully submitted.<br>";
    print "The result will be sent to $email when it's ready.<br><br>";
    
    print "There are <b>$aheadFileCnt</b> submission(s) ahead of this. <br>";
    print "<b> BOOKMARK THE FOLLOWING URL FOR YOUR RESULT FOR YOUR FUTURE REFERENCE.</b><br><br>";
    
    my $resultHTMLURL = $annoENV{SciMinerServerURL}."SciMiner/FinalResults/$fileNameBase/analysisSummary.html";
    print "<a href=\"$resultHTMLURL\">$resultHTMLURL</a><br><br>";

	if (( defined $annoENV{'SendMail'}) && ($annoENV{'SendMail'}))
	{	send_initial_email($resultHTMLURL, $email, $fileNameBase, $queryAnalInfo );
	}
    print "An email with this link has been sent out for your convenience.</p>";   


    return ($status, $message); 
    
    
    
    
    
	
										
	
 
    		
    		
    		
   
   
	
	
	
}



















#  -----------------------------------------------------------------------------
#  process_current_analysis_queue
#  -----------------------------------------------------------------------------
sub process_current_analysis_queue
{   my $pname		= 'SciMiner_v2.2';
    
    my $cssFileName						= 'sciminer-modern.css';
    my $sciminerJScriptFileName			= 'sciminer.js';
    my $tooltipScriptFileName			= 'wz_tooltip.js';
    
    #  Load working environment for ANNOTATION
    my %annoENV 	= anno_environmental_file_open ( );
    my $annoBaseDir = $annoENV{ANNOPath};


    #  Connect to the SciMiner DB
    my $SciMinerDB   = "DBI:mysql:database=".$annoENV{DB} 		|| return (-1, "!ERROR: No database specified");
    my $username    = $annoENV{username} 						|| return (-1, "!ERROR: No username specified");
    my $password    = $annoENV{password} 						|| return (-1, "!ERROR: No password specified");
    my $dbh = DBI->connect($SciMinerDB, $username, $password, {PrintError => 0});
    if (!$dbh) {
        warn "Could not open database: " . ($DBI::errstr || 'unknown error');
        return (-1, "!ERROR: Couldn't connect to database " . ($DBI::errstr || 'unknown error'));
    }


	#  Read the 'CurrentQueue' file
    open (QUEUE, "$annoENV{SciMinerPath}/Work/AnalysisQueue" ) 	|| return (-1, "No Queue file");
    my $currentQueue   = <QUEUE>;
    $currentQueue   =~ s/\r|\n//g;
    close (QUEUE);
    
    #  Load analysis configuration file
    my @confFileList    = glob ("$annoENV{SciMinerPath}/Work/Analysis_".$currentQueue."__*.conf");
    my %currentQueueEnv = ();
    my %hugoSymbol2ID	= ();
    
    if (defined $confFileList[0])
    {   open (CONF, $confFileList[0]);
        while(<CONF>)
        {   my $line = $_;
            $line =~ s/\r|\n//g;
            my @tmpSplit = split (/\t/, $line);
            $currentQueueEnv{$tmpSplit[0]} = $tmpSplit[1];
        }
            
		# Reset the current server URL from the configuration
		if (defined $currentQueueEnv{SciMinerServerURL})
		{   $annoENV{SciMinerServerURL}	= $currentQueueEnv{SciMinerServerURL};
		}
		
        close (CONF);
    }else
    {   #  The configuration file does not exist
        LogAnalysis("!ERROR! There is no analysis configuration file found.");
        return();
    }
    
    #  Create result directories
    my @nameSplit1          = split (/\//, $confFileList[0]);
    my @nameSplit2          = split (/\.conf/, $nameSplit1[$#nameSplit1]);
    my $finalResultDir      = "$annoENV{SciMinerPath}/Work/FinalResults/$nameSplit2[0]/";
    my $finalResultWebDir   = "$annoENV{SciMinerWebPath}/FinalResults/$nameSplit2[0]/";
    mkdir ("$annoENV{SciMinerPath}/Work/FinalResults/") || print "";
    mkdir ($finalResultDir) || print "";
    mkdir ("$annoENV{SciMinerWebPath}/FinalResults/") || print "";
    mkdir ($finalResultWebDir) || print "";
  
    
    #  Retrieve nbci gene ID mapped to hugo ID
    my %symbol2ncbiEntrezGeneIDRef	= ();
    my $geneSTH						= $dbh->prepare("SELECT approvedSymbol, entrezGeneIDMappedData from gene");
    $geneSTH->execute;
    
  	my @symRow						= ();
    my %symbol2ncbiEntrezGeneID		= ();
	while(@symRow = $geneSTH->fetchrow_array)
    {   if (defined $symRow[1])
        {   if ($symRow[1] !~ /[\,| ]/)
        	{	$symbol2ncbiEntrezGeneID{$symRow[0]}	= $symRow[1];
        	}else
        	{	$symbol2ncbiEntrezGeneID{$symRow[0]}	= "";
        	}
        }else
        {   # Skip this line, since we need pmid
        }
    }
    

    #  -------------------------------------------------------------------------
    #  Load selected tg and bg query information
    #  -------------------------------------------------------------------------
    my %tgQueryEnv                  = ();
    my %bgQueryEnv                  = ();

    #  Process targetQueryNumber
    if (defined $currentQueueEnv{targetQueryNumber})
    {   my $sth                     = $dbh->prepare("SELECT resultURL, queryName, numPMID, numGene FROM query where queryID = $currentQueueEnv{targetQueryNumber}");
        $sth->execute();
        my @row                     = $sth->fetchrow_array;#($result);
        my @tgLinkSplit             = split (/\//, $row[0]);
        $tgQueryEnv{resultURL}          = $row[0];
        $tgQueryEnv{queryName}          = $row[1];
        $tgQueryEnv{numPMID}            = $row[2];
        $tgQueryEnv{numGene}            = $row[3];
        $tgQueryEnv{baseName}           = $tgLinkSplit[$#tgLinkSplit-1];
    }

    if (defined $currentQueueEnv{bgQueryNumber})
    {   if ((($currentQueueEnv{GeneEnrichmentCheck} eq "on") && ($currentQueueEnv{GeneEnrichmentSelection} eq 'Selected')) || 
            (($currentQueueEnv{GOEnrichmentCheck} eq "on") && ($currentQueueEnv{GOEnrichmentSelection} eq 'Selected')) || 
            (($currentQueueEnv{MeSHEnrichmentCheck} eq "on") && ($currentQueueEnv{MeSHEnrichmentSelection} eq 'Selected')) ||
            (($currentQueueEnv{PathwayEnrichmentCheck} eq "on") && ($currentQueueEnv{PathwayEnrichmentSelection} eq 'Selected')) || 
            (($currentQueueEnv{PPICheck} eq "on") && ($currentQueueEnv{PPISelection} eq 'Selected')))
        {   my $sth                     = $dbh->prepare("SELECT resultURL, queryName, numPMID, numGene FROM query where queryID = $currentQueueEnv{bgQueryNumber}");
            $sth->execute();
            my @row                     = $sth->fetchrow_array;#($result);
            my @bgLinkSplit             = split (/\//, $row[0]);

            $bgQueryEnv{resultURL}          = $row[0];
            $bgQueryEnv{queryName}          = $row[1];
            $bgQueryEnv{numPMID}            = $row[2];
            $bgQueryEnv{numGene}            = $row[3];
            $bgQueryEnv{baseName}           = $bgLinkSplit[$#bgLinkSplit-1];
        }
    }
    
	#  Generate $queryAnalInfo summary string
	my $queryAnalInfo	= 	"-- Analysis Info --\n".
						  	"Aanlsys ID              : $currentQueueEnv{analID}\n".
						  	"Base name               : $currentQueueEnv{fileNameBase}\n".
						  	"Target query            : $currentQueueEnv{targetQueryNumber}\t$currentQueueEnv{targetQueryNumber2BaseName}\n";
	if (defined $currentQueueEnv{bgQueryNumber})
	{	$queryAnalInfo .=	"Background query        : $currentQueueEnv{bgQueryNumber}\t$currentQueueEnv{bgQueryNumber2BaseName}\n";
	}
						  	
	if ($currentQueueEnv{GeneEnrichmentCheck} eq 'on')
	{	$queryAnalInfo .= 	"Gene Enrichment Test    : Selected\n";
	}							
	if ($currentQueueEnv{GeneEnrichmentCheck} eq 'on')
	{	$queryAnalInfo .= 	"Gene Ontology Test      : Selected\n";
	}	
	if ($currentQueueEnv{GeneEnrichmentCheck} eq 'on')
	{	$queryAnalInfo .= 	"MeSH Enrichment Test    : Selected\n";
	}	
	if ($currentQueueEnv{GeneEnrichmentCheck} eq 'on')
	{	$queryAnalInfo .= 	"Pathway Enrichment Test : Selected\n";
	}	
	if ($currentQueueEnv{GeneEnrichmentCheck} eq 'on')
	{	$queryAnalInfo .= 	"PPI Enrichment Test     : Selected\n";
	}	

    #  -------------------------------------------------------------------------
    #  Generate temporary result html file and symbolic link
    #  -------------------------------------------------------------------------
    #generate_temporary_result_html ("$annoENV{SciMinerServerURL}/SciMiner/FinalResults/$nameSplit2[0]/analysisSummary.html",
    #                                "$finalResultWebDir/analysisSummary.html",
    #                                \%currentQueueEnv, 
    #                                "$annoENV{SciMinerServerURL}/SciMiner/",
    #                                \%tgQueryEnv, \%bgQueryEnv);
    #`ln -s $finalResultDir/analysisSummary.html $finalResultWebDir/analysisSummary.html`;
    #`cp $finalResultDir/analysisSummary.html $finalResultWebDir/analysisSummary.html`;
 
 	#  Copy css and java script file to the final result directory
    `cp /home/hurlab/apache-tomcat-9.0.37/webapps/SciMiner1.1/css/sciminer-modern.css $finalResultWebDir/`;
    `cp $annoENV{SciMinerWebPath}/$sciminerJScriptFileName $finalResultWebDir/`;
    `cp $annoENV{SciMinerWebPath}/$tooltipScriptFileName $finalResultWebDir/`;
    
    #  Copy the Image directory
    `cp -R $annoENV{SciMinerWebPath}/Images $finalResultWebDir/`;
    
 	#  Get the total number of PMIDs in SciMinerDB
 	my $getTotalPMIDsth			= $dbh->prepare("SELECT count(*) from document");
    $getTotalPMIDsth->execute();
    my @tmprow                  = $getTotalPMIDsth->fetchrow_array;#($result);
    my $totalPMIDinSciMiner		= $tmprow[0];
            
    my $resultSummaryWebHTMLURL    	= "";
    my $shortResultSummaryHTMLURL	= "";

	
	#  Check and perform Gene Enrichment
    my $errorMessage        = "";
    my $GEStatus            = '';
    my $GOStatus            = '';
    my $MeSHStatus          = '';
    my $PPIStatus           = '';
    my $PathwayStatus       = '';
    
    if ($currentQueueEnv{"GeneEnrichmentCheck"} eq 'on')
    {   LogAnalysis("Gene Enrichment Analysis");
        ($GEStatus, $errorMessage) = gene_enrichment_analysis(\%annoENV, \%currentQueueEnv, $dbh, $finalResultDir, $finalResultWebDir, \%tgQueryEnv, \%bgQueryEnv, \%hugoSymbol2ID, $totalPMIDinSciMiner);
        if ($GEStatus == -1)
        {   if (defined $errorMessage)
            {   # send_error_email_to_admin("! Error in Gene EnrichmentTest: $errorMessage");
            }else
            {   send_error_email_to_admin("! Error in Gene EnrichmentTest,, possible file handling error.\n$queryAnalInfo");
            }
            goto SkipAnalysisProcessPosition;
        }
    }
    
    #  Check and perform GO Enrichment
    if ($currentQueueEnv{"GOEnrichmentCheck"} eq 'on')
    {   LogAnalysis("GO Enrichment Analysis");
        ($GOStatus, $errorMessage) = go_enrichment_analysis(\%annoENV, \%currentQueueEnv, $dbh, $finalResultDir, \%hugoSymbol2ID, $totalPMIDinSciMiner, \%tgQueryEnv, \%bgQueryEnv, \%symbol2ncbiEntrezGeneID);
        if ($GOStatus == -1)
        {   if (defined $errorMessage)
            {   # send_error_email_to_admin("! Error in GOEnrichmentTest: $errorMessage");
            }else
            {   send_error_email_to_admin("! Error in GOEnrichmentTest,, possible file handling error.\n$queryAnalInfo");
            }
            goto SkipAnalysisProcessPosition;
        }
    }

    #  Check and perform MeSH Enrichment
    if ($currentQueueEnv{"MeSHEnrichmentCheck"} eq 'on')
    {   LogAnalysis("MeSH Enrichment Analysis");
        ($MeSHStatus, $errorMessage) = mesh_enrichment_analysis(\%annoENV, \%currentQueueEnv, $dbh, $finalResultDir, $finalResultWebDir, \%tgQueryEnv, \%bgQueryEnv, \%hugoSymbol2ID, $totalPMIDinSciMiner);
        if ($MeSHStatus == -1)
        {   if (defined $errorMessage)
            {   # send_error_email_to_admin("! Error in MeSHEnrichmentTest: $errorMessage");
            }else
            {   send_error_email_to_admin("! Error in MeSHEnrichmentTest,, possible file handling error.\n$queryAnalInfo");
            }
            goto SkipAnalysisProcessPosition;
        }
    }


    #  Check and perform PPI Enrichment
    my $bgNumOfGenes                = 0;
    if ($currentQueueEnv{"PPICheck"} eq 'on')
    {   LogAnalysis("PPI Enrichment Analysis");
        ($PPIStatus, $errorMessage) = PPI_enrichment_analysis(\%annoENV, \%currentQueueEnv, $dbh, $finalResultDir, \$bgNumOfGenes, \%hugoSymbol2ID, $totalPMIDinSciMiner, \%tgQueryEnv, \%bgQueryEnv);
        if ($PPIStatus == -1)
        {   if (defined $errorMessage)
            {   # send_error_email_to_admin("! Error in PPI EnrichmentTest: $errorMessage");
            }else
            {   send_error_email_to_admin("! Error in PPI EnrichmentTest,, possible file handling error.\n$queryAnalInfo");
            }
            goto SkipAnalysisProcessPosition;
        }
    }
    
    
    
    #  Check and perform Pathway Enrichment
    if ($currentQueueEnv{"PathwayEnrichmentCheck"} eq 'on')
    {   LogAnalysis("Pathway Enrichment Analysis");
        ($PathwayStatus, $errorMessage) = Pathway_enrichment_analysis(\%annoENV, \%currentQueueEnv, $dbh, $finalResultDir, $finalResultWebDir, \%hugoSymbol2ID, $totalPMIDinSciMiner, \%tgQueryEnv, \%bgQueryEnv, \%symbol2ncbiEntrezGeneID);
        if ($PathwayStatus == -1)
        {   if (defined $errorMessage)
            {   # send_error_email_to_admin("! Error in PathwayEnrichmentTest: $errorMessage");
            }else
            {   send_error_email_to_admin("! Error in PathwayEnrichmentTest,, possible file handling error.\n$queryAnalInfo");
            }
            goto SkipAnalysisProcessPosition;
        }
    }
    
    
    
    #  Generate output HTML file    
    $resultSummaryWebHTMLURL    	= "$annoENV{SciMinerServerURL}"."SciMiner/FinalResults/$currentQueueEnv{fileNameBase}/analysisSummary.html";
    $shortResultSummaryHTMLURL		= "FinalResults/$currentQueueEnv{fileNameBase}/analysisSummary.html";
    generate_analysis_output_result($finalResultDir, $finalResultWebDir, \%annoENV, \%currentQueueEnv, $dbh,
                                    $GEStatus, $GOStatus, $MeSHStatus, $PathwayStatus, $PPIStatus, \%tgQueryEnv, \%bgQueryEnv,
                                    $bgNumOfGenes, \%hugoSymbol2ID, $cssFileName, $sciminerJScriptFileName, \%symbol2ncbiEntrezGeneID);
	
	LogAnalysis("Removing completed anlaysis queue # $nameSplit2[0]");
    remove_completed_analysis_update_status ("$annoENV{SciMinerPath}/Work/", $nameSplit2[0], $dbh, $currentQueue, 3, $resultSummaryWebHTMLURL, $currentQueueEnv{email}, $queryAnalInfo, $shortResultSummaryHTMLURL, \%annoENV);
    return();
    
    SkipAnalysisProcessPosition:
	$resultSummaryWebHTMLURL    	= "$annoENV{SciMinerServerURL}"."SciMiner/FinalResults/$currentQueueEnv{fileNameBase}/analysisSummary.html";
    $shortResultSummaryHTMLURL		= "FinalResults/$currentQueueEnv{fileNameBase}/analysisSummary.html";

    # Replace the temporary result file with noresult message
    generate_analysys_result_summary_with_noresult($finalResultWebDir, "$finalResultWebDir/analysisSummary.html", "", 
    		\%currentQueueEnv, $annoENV{SciMinerServerURL}, $dbh, $currentQueueEnv{analID} , $errorMessage, \%tgQueryEnv, \%bgQueryEnv);

	# Resulting Summary Web HTML URL
    LogQuery("Result available at: $resultSummaryWebHTMLURL");

	# Either of the data set has zero paper.
    remove_completed_analysis_update_status ("$annoENV{SciMinerPath}/Work/", $nameSplit2[0], $dbh, $currentQueue, 2, $resultSummaryWebHTMLURL, $currentQueueEnv{email}, $queryAnalInfo, $shortResultSummaryHTMLURL, \%annoENV);    
}










#  -----------------------------------------------------------------------------
#  3.1  gene_enrichment_analysis
#  -----------------------------------------------------------------------------
sub gene_enrichment_analysis
{   my $annoENVRef          = shift;   
    my $currentQueueEnvRef  = shift;
    my $dbh                 = shift;
    my $finalResultDir      = shift;
    my $finalResultWebDir	= shift;
    my $tgQueryEnvRef       = shift;
    my $bgQueryEnvRef       = shift;
    my $hugoSymbol2IDRef	= shift;
    my $totalPMIDinSciMiner	= shift;
    
    #  Module for Fisher's exact test
    use Text::NSP::Measures::2D::Fisher::twotailed;
    
    #  Initialize
    my $tgPMIDCount         = $$tgQueryEnvRef{numPMID};
    my $bgPMIDCount         = 0;

    my %hugoID2Symbol       = ();
    my %hugoID2Name         = ();

    my @tgHugoIDs           = ();
    my $tgHugoIDCnt         = '';
    my $tgHugoIDCntTotal	= 0;
    my %tgHugoID2Occur      = ();
    my %tgHugoID2Paper      = ();
    my %tgHugoID2PMID 		= ();	
    
    my @bgHugoIDs           = ();
    my $bgHugoIDCnt         = '';
    my $bgHugoIDCntTotal	= 0;
    my %bgHugoID2Occur      = ();
    my %bgHugoID2Paper      = ();
    my %bgHugoID2PMID		= ();
    
    my $tgMinTopCheck		= 'true';
    my $bgMinTopCheck		= 'false';
    my $tgTotalPMID			= $$tgQueryEnvRef{'numPMID'};
    my $bgTotalPMID			= '';
        
    #  Files to be loaded
    my $tgMergedSumFile     = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{targetQueryNumber2BaseName}/SciMinerBase.MerSum.sorted.txt";
    my $bgMergedSumFile     = "";
    my $tgPMIDListFile		= "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{targetQueryNumber2BaseName}/$$currentQueueEnvRef{targetQueryNumber2BaseName}_list.txt";
    my $bgPMIDListFile		= "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{bgQueryNumber2BaseName}/$$currentQueueEnvRef{bgQueryNumber2BaseName}_list.txt";
    
    if ($$currentQueueEnvRef{GeneEnrichmentSelection} eq 'Selected')
    {   #  Use selected queryfile as background
        $bgMergedSumFile    = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{bgQueryNumber2BaseName}/SciMinerBase.MerSum.sorted.txt";
        $bgPMIDCount        = $$bgQueryEnvRef{'numPMID'};
        $bgMinTopCheck		= 'true';
        $bgTotalPMID		= $$bgQueryEnvRef{'numPMID'};        
    }else
    {   $bgMergedSumFile    = "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpus";
        my $bgPMIDCntFile   = $bgMergedSumFile.'PMIDCnt';
        $bgMinTopCheck		= 'true';
        $bgTotalPMID		= $totalPMIDinSciMiner;
                
        if ((-f $bgPMIDCntFile) && (-s $bgPMIDCntFile > 0))
        {   open (BGPMIDFILE, $bgPMIDCntFile);
            my $line = <BGPMIDFILE>;
            $line =~ s/\r|\n//g;
            if (is_number($line))
            {   $bgPMIDCount = $line;
            }else
            {   $bgPMIDCount = retrieve_document_count_in_sciminer_db($dbh);
            }
            close BGPMIDFILE;
        }else
        {   $bgPMIDCount = retrieve_document_count_in_sciminer_db($dbh);
        }
    }
    

    #  Load the targetQueryResult Gene results
    load_merged_summary_file_with_parameters ($tgMergedSumFile, \%hugoID2Symbol, $hugoSymbol2IDRef, \%hugoID2Name,
                                              \@tgHugoIDs, \$tgHugoIDCnt, \$tgHugoIDCntTotal, \%tgHugoID2Occur, \%tgHugoID2Paper, 
                                              $tgMinTopCheck, $tgTotalPMID, $$currentQueueEnvRef{MinTopPaperTG}, $$currentQueueEnvRef{MinPaperMethodTG},
                                              \%tgHugoID2PMID, $$currentQueueEnvRef{TGListFileContent});
	#  Load the full PMID list file for target set
	my $tgPMIDFullListRef	= load_PMID_list_file ($tgPMIDListFile);
                          
                                              
    #  Load the background Gene results
    load_merged_summary_file_with_parameters ($bgMergedSumFile, \%hugoID2Symbol, $hugoSymbol2IDRef, \%hugoID2Name, 
                                              \@bgHugoIDs, \$bgHugoIDCnt, \$bgHugoIDCntTotal, \%bgHugoID2Occur, \%bgHugoID2Paper,
                                              $bgMinTopCheck, $bgTotalPMID, $$currentQueueEnvRef{MinTopPaperBG}, $$currentQueueEnvRef{MinPaperMethodBG},
                                              \%bgHugoID2PMID, $$currentQueueEnvRef{BGListFileContent});
	#  Load the full PMID list file for background set
	my $bgPMIDFullListRef	= load_PMID_list_file ($bgPMIDListFile);
	
	
	                                              
    LogAnalysis("Loading mersum files with parameter completed");

    #  Now, perform fisher's exact test over the set
    if (($tgHugoIDCnt eq "") || ($tgHugoIDCnt == 0))
    {   #  This cannot be completed since one of the set has no gene
        LogAnalysis("Target set has 0 gene. Analysis aborted");
        return (-1, "Target set has 0 gene. Analysis aborted");
    }
    if (($bgHugoIDCnt eq "") || ($bgHugoIDCnt == 0))
    {   LogAnalysis("Background set has 0 gene. Analysis aborted");
        return (-1, "Background set has 0 gene. Analysis aborted");
    }
    if (not defined $$tgPMIDFullListRef[0])
    {   LogAnalysis("Target set has 0 PMID. Analysis aborted");
        return (-1, "Target set has 0 PMID. Analysis aborted");
    }
    if (not defined $$bgPMIDFullListRef[0])
    {   LogAnalysis("Target set has 0 PMID. Analysis aborted");
        return (-1, "Target set has 0 PMID. Analysis aborted");
    }
    
    #  Initialize result hashes or variables
    my %hugoID2Pvalue               = ();
    my %hugoID2Matrix               = ();
    
    LogAnalysis("Now performing fisher's exact test");

    my $np1 = $tgPMIDCount;            
    my $np2 = $bgPMIDCount;             
    my $npp = $np1 + $np2;
    my $n1p = 0;                        # number of PMIDs with the given code
    my $n11 = 0;                        # number of PMIDs common
    my $n12 = 0;
    my $n21 = 0;
    my $n22 = 0;
    my $twotailedPvalue = 0;
    my $errorCode = "";
    my $ratioCorpus = 0;
    my $ratioFull   = 0;
    my %tPlusString		= ();
    my %tMinusString	= ();
    my %commonString	= ();
    my %bPlusString		= ();
    my %bMinusString	= ();
    my %commonCount		= ();
    my %tUniqCount		= ();
    my %bUniqCount		= ();
    my %tUniqString		= ();
    my %bUniqString		= ();
    
#          word2   ~word2                       corpus         full
#  word1    n11      n12 | n1p       MeSH+        n11          n12     n1p
# ~word1    n21      n22 | n2p       MeSH-        n21          n22     n2p
#           --------------
#           np1      np2   npp                    np1          np2     npp
 
           
    #  Perform chi-square // Fisher-exact test .. Since it's 2 by 2, stay with fisher-exact test
    #  This calculation is done through Text::NSP package
    foreach my $hugoID (@tgHugoIDs)
    {   #  Initialize string and count
        $tPlusString{$hugoID}	= '';
        $tMinusString{$hugoID}	= '';
        $commonString{$hugoID}	= '';
        $bPlusString{$hugoID}	= '';
        $bMinusString{$hugoID}	= '';
        $commonCount{$hugoID}	= 0;
        $tUniqCount{$hugoID}	= 0;
        $bUniqCount{$hugoID}	= 0;
        $tUniqString{$hugoID}	= '';
        $bUniqString{$hugoID}	= '';
        
        
        $tPlusString{$hugoID} = join (",", keys %{$tgHugoID2PMID{$hugoID}});
        $bPlusString{$hugoID} = join (",", keys %{$bgHugoID2PMID{$hugoID}});
        
        #  Check for bgPMIDs
        if (defined $bgHugoID2PMID{$hugoID})
        {	foreach my $bgTmpPMID (keys %{$bgHugoID2PMID{$hugoID}})
        	{	if (defined $tgHugoID2PMID{$hugoID}->{$bgTmpPMID})
        		{	#  Overlapping PMID
        			$tgHugoID2PMID{$hugoID}->{$bgTmpPMID}	= 2;
        			$bgHugoID2PMID{$hugoID}->{$bgTmpPMID}	= 2;
        			$commonString{$hugoID}	.= $bgTmpPMID.',';
        			$commonCount{$hugoID}++;
        		}else
        		{	$bUniqCount{$hugoID}++;
        			$bUniqString{$hugoID}	.= $bgTmpPMID.',';
        		}
        	}
        }

		#  Generate the PMID strings for target set
		foreach my $tgTmpPMID (@{$tgPMIDFullListRef})
		{	if (defined $tgHugoID2PMID{$hugoID}->{$tgTmpPMID})
			{	if ($tgHugoID2PMID{$hugoID}->{$tgTmpPMID} == 1)
				{	$tUniqCount{$hugoID}++;
        			$tUniqString{$hugoID}	.= $tgTmpPMID.',';
				}
			}else
			{	$tMinusString{$hugoID}	.= $tgTmpPMID.',';
			}
		}
		
		#  Generate the PMID strings for background set
		foreach my $bgTmpPMID (@{$bgPMIDFullListRef})
		{	if (defined $bgHugoID2PMID{$hugoID}->{$bgTmpPMID})
			{	# do nothing
			}else
			{	$bMinusString{$hugoID}	.= $bgTmpPMID.',';
			}
		}
    

		# Perform the Fisher's exact test
    	$n11 = $tgHugoID2Paper{$hugoID};
        if (defined $bgHugoID2Paper{$hugoID})
        {   $n12 = $bgHugoID2Paper{$hugoID};
        }else
        {   $n12 = 0;
        }
        $n1p = $n11 + $n12;                             # Note that n1p = n11 + n12
        $n21 = $np1 - $n11;
        $n22 = $np2 - $n12;
        
        $twotailedPvalue = calculateStatistic (n11 => $n11, 
                                               n1p => $n1p,
                                               np1 => $np1,
                                               npp => $npp);
        if ( ($errorCode = getErrorCode()))
        {   $hugoID2Pvalue{$hugoID} = -1;
        }else
        {   $hugoID2Pvalue{$hugoID} = sprintf("%.3e",$twotailedPvalue);
        }
        
        $hugoID2Matrix{$hugoID} = $np1."\t".$n11."\t".$n21."\t".$tUniqCount{$hugoID}."\t".$commonCount{$hugoID}."\t".$bUniqCount{$hugoID}."\t".$n12."\t".$n22."\t".$np2."\t";
        $ratioCorpus    = $n11/$np1;
        $ratioFull      = $n12/$np2;
            
        if (($n12 != 0) && ($n11 != 0))
        {   $hugoID2Matrix{$hugoID} .= sprintf("%.2f\t%.2f\t%.1f",$ratioCorpus, $ratioFull, ($ratioCorpus)/($ratioFull));
        }else
        {   # This is very unlike to happen. But in case it happens. 
        	my $tmpTag		= $tgZeroTag;
        	if ($n12 == 0)
        	{	$tmpTag		= $bgZeroTag;
        	}
            $hugoID2Matrix{$hugoID} .= sprintf("%.2f\t%.2f\t",$ratioCorpus, $ratioFull).$tmpTag;
        }
    }
    
    #  Sort hugoIDs by Pvalue
    my @sortedTgHugoIDs = sort {$hugoID2Pvalue{$a} <=> $hugoID2Pvalue{$b}} keys %hugoID2Pvalue;
    
    
    #  Result printout   
    open (TMP, ">$finalResultWebDir/GeneEnrichmentResult.txt");
    print TMP "#Symbol\tID\tName\tt-total\tt+\tt-\tt+uniq\tcommon\tb+uniq\tb+\tb-\tb-total\tt-ratiot\tb-ratio\t(t-ratio)/(b-ratio)\tp-value\tt-#target\tt-#target\tb-#target\tb-#target\n";

    foreach my $hugoID (@sortedTgHugoIDs)
    {   print TMP $hugoID2Symbol{$hugoID}."\t".$hugoID."\t".$hugoID2Name{$hugoID}."\t";
        print TMP $hugoID2Matrix{$hugoID}."\t".$hugoID2Pvalue{$hugoID}."\t";
        print TMP $tgHugoIDCnt."\t".$tgHugoIDCntTotal."\t".
        		  $bgHugoIDCnt."\t".$bgHugoIDCntTotal."\n";
    }
    close TMP;
    
    #  Result String printout   
    open (PMIDString, ">$finalResultWebDir/GeneEnrichmentResult.pmid");
    print PMIDString "#Symbol\tID\tt+\tt-\tt+uniq\tcommon\tb+uniq\tb+\tb-\n";
    foreach my $hugoID (@sortedTgHugoIDs)
    {   print PMIDString $hugoID2Symbol{$hugoID}."\t".$hugoID."\t";
        print PMIDString $tPlusString{$hugoID}."\t".$tMinusString{$hugoID}."\t";
        print PMIDString $tUniqString{$hugoID}."\t".$commonString{$hugoID}."\t".$bUniqString{$hugoID}."\t";
        print PMIDString $bPlusString{$hugoID}."\t".$bMinusString{$hugoID}."\n";
    }
    close PMIDString;
    
    #  Generate tgHUID and bgHUGO ID files
    open (TGHUGOID, ">$finalResultWebDir/tgHugoIDs.txt");
    open (BGHUGOID, ">$finalResultWebDir/bgHugoIDs.txt");
	foreach my $hugoID (@sortedTgHugoIDs)
	{	print TGHUGOID "$hugoID\n";
	}   close TGHUGOID;
	
	foreach my $hugoID (@bgHugoIDs)
	{	print BGHUGOID "$hugoID\n";
	}   close BGHUGOID;
	
	#  12/31/2008 
	#  Add targets that are only found in the background set
	open (BGONLY, ">$finalResultWebDir/bgOnlyTargets.txt");
	print BGONLY "#Symbol\tID\tName\tb-total\n";
	foreach my $hugoID (@bgHugoIDs)
	{	if (not defined $tPlusString{$hugoID})
		{	print BGONLY $hugoID2Symbol{$hugoID}."\t".$hugoID."\t".$hugoID2Name{$hugoID}."\t";
        	print BGONLY $bgHugoID2Paper{$hugoID}."\n";
		}
	}	
	close BGONLY;
	`cp $finalResultWebDir/bgOnlyTargets.txt $finalResultWebDir/bgOnlyTargets.xls`;
	
    #  Catch the most-informative code
    return(1);
}



















#  -----------------------------------------------------------------------------
#  3.2 go_enrichment_analysis
#  -----------------------------------------------------------------------------
sub go_enrichment_analysis
{   my $annoENVRef          		= shift;   
    my $currentQueueEnvRef  		= shift;
    my $dbh                 		= shift;
    my $finalResultDir      		= shift;
	my $hugoSymbol2IDRef			= shift;
	my $totalPMIDinSciMiner			= shift;
	my $tgQueryEnvRef				= shift;	
	my $bgQueryEnvRef				= shift;
	my $symbol2ncbiEntrezGeneIDRef	= shift;
	
	    
    #  First, Load the gene set files
    #  Initialize
    my %hugoID2Symbol       = ();
    my %hugoID2Name         = ();

    my @tgHugoIDs           = ();
    my $tgHugoIDCnt         = '';
    my $tgHugoIDCntTotal	= 0;
    my %tgHugoID2Occur      = ();
    my %tgHugoID2Paper      = ();
    my %tgHugoID2PMID		= ();
                                             
    my @bgHugoIDs           = ();
    my $bgHugoIDCnt         = '';
    my $bgHugoIDCntTotal	= 0;
    my %bgHugoID2Occur      = ();
    my %bgHugoID2Paper      = ();
    my %bgHugoID2PMID		= ();
    
    #  Directories and Files to be used
    my $goOutputDir         = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/GO/";
    mkdir ($goOutputDir) || print "";

    my $tgMergedSumFile     = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{targetQueryNumber2BaseName}/SciMinerBase.MerSum.sorted.txt";
    my $bgMergedSumFile     = "";

    my $tgGOFile            = $goOutputDir."TEST.GO";
    my $bgGOFile            = "";
    
    my $tgMinTopCheck		= 'true';
    my $bgMinTopCheck		= 'false';
    
    my $tgTotalPMID			= $$tgQueryEnvRef{'numPMID'};
    my $bgTotalPMID			= '';
    
    
    if ($$currentQueueEnvRef{GOEnrichmentSelection} eq 'Selected')
    {   #  Use selected queryfile as background
        $bgMergedSumFile    = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{bgQueryNumber2BaseName}/SciMinerBase.MerSum.sorted.txt";
        $bgGOFile           = $goOutputDir."BACKGROUND.GO";
        $bgMinTopCheck		= 'true';
        $bgTotalPMID		= $$bgQueryEnvRef{'numPMID'};
    }elsif ($$currentQueueEnvRef{GOEnrichmentSelection} eq 'Whole')
    {   $bgMergedSumFile    = "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpus";
        $bgGOFile           = "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpus.GO";
        $bgMinTopCheck		= 'true';
        $bgTotalPMID		= $totalPMIDinSciMiner;
    }elsif ($$currentQueueEnvRef{GOEnrichmentSelection} eq 'FullHUGO')
    {   $bgMergedSumFile    = "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullHUGOList";
        $bgGOFile           = "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullHUGOList.GO";
        $bgMinTopCheck		= 'false';
        if (! -f $bgMergedSumFile)
        {   LogAnalysis("FullHUGOList is being created");
        	open (FULLHUGO, ">$bgMergedSumFile");
            # Create such file
            my $sql         = "SELECT approvedSymbol, hgncID, approvedName FROM gene";
            my $sth         = $dbh->prepare($sql);
            $sth->execute();
            my @row         = $sth->fetchrow_array;
            while(@row = $sth->fetchrow_array)
            {   print FULLHUGO $row[0]."\t".$row[1]."\t".$row[2]."\t1\t1\tNULL\tNULL\n";
            }
            close FULLHUGO;
        }
        
        #  Check for fullBGGeneSummary.html
        if (! -f "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/fullBGGeneSummary.html")
        {   LogAnalysis("FULLGENE is being created");
        	open (FULLGENE, ">$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/fullBGGeneSummary.html");
        	open (FULLGENETXT, ">$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/fullBGGeneSummary.txt");
        	
        	print FULLGENE  "<head>
						    <title>SciMiner Result Report Page</title>
						    <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
						    <link rel=\"stylesheet\" href=\"$cssURLFileName\" type=\"text/css\" />
						    <style type=\"text/css\"> body {	margin-left:10px;	}</style>
						    </head>
						    <body bgcolor=\"#EAF4F4\">
						    <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Full Gene List Page</b></p>
						    <a href=\"fullBGGeneSummary.txt\">Full list in text file</a>
							<hr>
							<p class=\"titleBarName1\"><b>Here are the full list of targets (HUGO based) in SciMiner.</b></p>
							";
		  
			# Generate table for the actual gene
			print FULLGENE "  <table border=\"1\" width=\"590\">
				                <tr class=\"titleBarName1\">
				                    <th width=\"40\">
				                        HUGO
				                    </th>
				                    <th width=\"60\">
				                        Symbol
				                    </th>
				                    <th width=\"400\">
				                        Target Name
				                    </th>
				                    <th width=\"40\">
				                        MiMI
				                    </th>                            
				                </tr>";
				                
				                
            # Create such file
            my $sql         = "SELECT approvedSymbol, hgncID, approvedName FROM gene";
            my $sth         = $dbh->prepare($sql);
            $sth->execute();
            my @row         = $sth->fetchrow_array;
            while(@row = $sth->fetchrow_array)
            {   print FULLGENE "<tr>
		                        <td width=\"40\">
		                            <a href=\"$hgncLinkURL$row[1]\">$row[1]</a>
		                        </td>
		                        <td width=\"60\">
		                            ";
		        if (defined $$symbol2ncbiEntrezGeneIDRef{$row[0]})
		        {	my $tmpNCBIID	= $$symbol2ncbiEntrezGeneIDRef{$row[0]};
		        	print FULLGENE "	<a href=\"$ncbiGeneLink$tmpNCBIID\">$row[0]</a>
		        				</td>
		                        <td width=\"400\">
		                            $row[2]
		                        </td>
		                        <td width=\"40\">
		                        	<a href=\"$mimiNameLink$$symbol2ncbiEntrezGeneIDRef{$row[0]}\"><img src=\"/SciMiner1.1/SciMiner/Images/cytoicon.jpg\"></a>
		                        </td>
		                        </tr>";
		        }else
		        {	print FULLGENE "	<a href=\"$ncbiGeneSearch".($row[1])." AND Human[Orgn]\">$row[1]</a>
		        				</td>
		                        <td width=\"400\">
		                            $row[2]
		                        </td>
		                        <td width=\"40\">
		                        	&nbsp;
		                        </td>
		                        </tr>
		         				";
		        }
		        print FULLGENETXT $row[1]."\t".$row[0]."\t".$row[2]."\n";			
            }
	        print FULLGENE 	"
	        				</table>
	        				<br><br>
	        				<br>
	        				</body>";
            close FULLGENE;
            close FULLGENETXT;
        }
		
		# Copy the file
		if (! -f "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/fullBGGeneSummary.html")
		{	`cp $$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/fullBGGeneSummary.html $$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/`;
		}
		if (! -f "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/fullBGGeneSummary.txt")
		{	`cp $$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/fullBGGeneSummary.txt $$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/`;  
		}
    }
    
    #my $goSigFullOutFile        = "$$annoENVRef{SciMinerPath}/Work/FinalResults/$$currentQueueEnvRef{bgQueryNumber2BaseName}/GOSignificance.full";
    #my $goSigExplicitOutFile    = "$$annoENVRef{SciMinerPath}/Work/FinalResults/$$currentQueueEnvRef{bgQueryNumber2BaseName}/GOSignificance.explicit";    
    #  Load the targetQueryResult Gene results
    load_merged_summary_file_with_parameters ($tgMergedSumFile, \%hugoID2Symbol, $hugoSymbol2IDRef, \%hugoID2Name,
                                              \@tgHugoIDs, \$tgHugoIDCnt, \$tgHugoIDCntTotal, \%tgHugoID2Occur, \%tgHugoID2Paper, 
                                              $tgMinTopCheck, $tgTotalPMID, $$currentQueueEnvRef{MinTopPaperTG}, $$currentQueueEnvRef{MinPaperMethodTG},
                                             \%tgHugoID2PMID, $$currentQueueEnvRef{TGListFileContent});

	                                              

    #  Load the background Gene results
    load_merged_summary_file_with_parameters ($bgMergedSumFile, \%hugoID2Symbol, $hugoSymbol2IDRef, \%hugoID2Name, 
                                              \@bgHugoIDs, \$bgHugoIDCnt, \$bgHugoIDCntTotal, \%bgHugoID2Occur, \%bgHugoID2Paper,
                                              $bgMinTopCheck, $bgTotalPMID, $$currentQueueEnvRef{MinTopPaperBG}, $$currentQueueEnvRef{MinPaperMethodBG},
                                             \%bgHugoID2PMID, $$currentQueueEnvRef{BGListFileContent});


    #  Now, perform fisher's exact test over the set
    if ($tgHugoIDCnt == 0)
    {   #  This cannot be completed since one of the set has no gene
        LogAnalysis("Target set has 0 gene. Analysis aborted");
        return (-1, "Target set has 0 gene. Analysis aborted");
    }
    if ($bgHugoIDCnt == 0)
    {   LogAnalysis("Background set has 0 gene. Analysis aborted");
        return (-1, "Background set has 0 gene. Analysis aborted" );
    }
    
    
    # --------------------------------------------------------------------------
    #  Second, get hugoID2GO from SciMinerDB
    my %hugoID2GOID                         = ();
    my $sql = "SELECT hgncID, goID FROM gene2external";
    my $sth = $dbh->prepare($sql);
    my @row = ();
    $sth->execute();
        
    while(@row = $sth->fetchrow_array)
    {   if (defined $row[1])
        {   $hugoID2GOID{$row[0]}           = $row[1];
        }else
        {   # Skip this line, since we need pmid
            $hugoID2GOID{$row[0]}           = "";
        }
    }

    # --------------------------------------------------------------------------
    #  Third, we need to extract all GO
    #  Load GO tree file
    open (GOTREE, "$$annoENVRef{SciMinerPath}/Work/GO/GOCode") || return(-1);
    LogAnalysis("Loading Gene Ontology code data file");
    my %GO2DESC             = ();
    my %GOCODE2ID           = ();
    my %GOID2CODE           = ();
    my %GOIDOccurrence      = ();
    while(<GOTREE>)
    {   my $line = $_;     $line =~ s/\r|\n//g;
        my @tmpSplit = split (/\t/, $line);
        $GO2DESC{$tmpSplit[2]} = $tmpSplit[3];
        $GOCODE2ID{$tmpSplit[0]} = $tmpSplit[2];
        if (defined $GOID2CODE{$tmpSplit[2]}) 
        {   $GOID2CODE{$tmpSplit[2]} .= $tmpSplit[0].'<_>';
        }else
        {   $GOID2CODE{$tmpSplit[2]} = $tmpSplit[0].'<_>';
        }
        if (defined $GOIDOccurrence{$tmpSplit[2]})
        {   $GOIDOccurrence{$tmpSplit[2]} += 1;
        }else
        {   $GOIDOccurrence{$tmpSplit[2]} = 1;
        }
    }   close GOTREE;
    LogAnalysis("Loading Gene Ontology code data file completed");
    
 
    # --------------------------------------------------------------------------
    #  Step4. Create Full GO Files
    Create_Full_GO_File ( $tgGOFile, 
                          \@tgHugoIDs, \%hugoID2Symbol, \%hugoID2Name, \%hugoID2GOID,
                          \%GOID2CODE, \%GOCODE2ID, \%GO2DESC);
                          
                          
   
    if ($$currentQueueEnvRef{GOEnrichmentSelection} eq 'FullHUGO')
    {   if(! -f $bgGOFile)
        {   Create_Full_GO_File ( $bgGOFile, 
                          \@bgHugoIDs, \%hugoID2Symbol, \%hugoID2Name, \%hugoID2GOID,
                          \%GOID2CODE, \%GOCODE2ID, \%GO2DESC);
        }
        `cp $$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullHUGOList.GO $goOutputDir/BACKGROUND.GO`;
        $bgGOFile = "$goOutputDir/BACKGROUND.GO";
        
    }else
    {   if ($$currentQueueEnvRef{GOEnrichmentSelection} eq 'Whole') 
        {   if (! -f $bgGOFile)
            {   Create_Full_GO_File ( $bgGOFile, 
                              \@bgHugoIDs, \%hugoID2Symbol, \%hugoID2Name, \%hugoID2GOID,
                              \%GOID2CODE, \%GOCODE2ID, \%GO2DESC);
            }
            `cp $bgGOFile $goOutputDir/BACKGROUND.GO`;
        }else
        {   Create_Full_GO_File ( $bgGOFile, 
                              \@bgHugoIDs, \%hugoID2Symbol, \%hugoID2Name, \%hugoID2GOID,
                              \%GOID2CODE, \%GOCODE2ID, \%GO2DESC);
        }
    }
    
                          
    
    # --------------------------------------------------------------------------
    #  Step5. Perform fisher exact test 
    LogAnalysis("Performing GO fisher's exact test");    
    Perform_Fisher_Exact_Test_GO_Significance ($goOutputDir, $annoENVRef, $currentQueueEnvRef,
    										   \@tgHugoIDs, $tgGOFile,
                                               \@bgHugoIDs, $bgGOFile, 
                                               \%hugoID2Symbol, \%hugoID2Name, \%hugoID2GOID, \%GO2DESC, $symbol2ncbiEntrezGeneIDRef);


    # --------------------------------------------------------------------------
    #  Step6. Create Summary file
    LogAnalysis("Creating a GO summary file");
    open (SUMMARY, ">".$goOutputDir.'GOSummary');
    print SUMMARY 	$tgTotalPMID."\t".$bgTotalPMID."\t".
    				$tgHugoIDCnt."\t".$tgHugoIDCntTotal."\t".
        		  	$bgHugoIDCnt."\t".$bgHugoIDCntTotal."\n";
    close SUMMARY;                                               

    # --------------------------------------------------------------------------
    #  Step7. Create Zipped File
    LogAnalysis("Creating a zip file for all GO");    
    `zip -rq $$annoENVRef{SciMinerWebPath}FinalResults/$$currentQueueEnvRef{fileNameBase}/GO_Compressed $goOutputDir`;
    
    
    #  Step8. Generate tgHUID and bgHUGO ID files
	if (! -f "$$annoENVRef{SciMinerWebPath}FinalResults/$$currentQueueEnvRef{fileNameBase}/tgHugoIDs.txt")
	{	open (TGHUGOID, ">$$annoENVRef{SciMinerWebPath}FinalResults/$$currentQueueEnvRef{fileNameBase}/tgHugoIDs.txt");
		foreach my $hugoID (@tgHugoIDs)
		{	print TGHUGOID "$hugoID\n";
		}   close TGHUGOID;
	}
    
	if (! -f "$$annoENVRef{SciMinerWebPath}FinalResults/$$currentQueueEnvRef{fileNameBase}/bgHugoIDs.txt")
	{	open (BGHUGOID, ">$$annoENVRef{SciMinerWebPath}FinalResults/$$currentQueueEnvRef{fileNameBase}/bgHugoIDs.txt");	
		foreach my $hugoID (@bgHugoIDs)
		{	print BGHUGOID "$hugoID\n";
		}   close BGHUGOID;
	}
    
    return(1, "");   
}










sub Perform_Fisher_Exact_Test_GO_Significance
{   my $goOutputDir                 = shift;
	my $annoENVRef					= shift;
	my $currentQueueEnvRef			= shift;
    
    my $tgHugoIDsRef                = shift;
    my $targetFullGOFile            = shift;
    my $bgHugoIDsRef                = shift;
    my $bgFullGOFile                = shift;
    my $hugoID2SymbolRef            = shift;
    my $hugoID2NameRef              = shift;
    my $hugoID2GOIDRef              = shift;
    my $GO2DESCRef                  = shift;
    my $symbol2ncbiEntrezGeneIDRef	= shift;

	LogAnalysis("!! Starting to perform fisher exact test for GO enrichment");
    #  Module for Fisher's exact test
    use Text::NSP::Measures::2D::Fisher::twotailed;
	my $goWebOutputDir				= "$$annoENVRef{SciMinerWebPath}FinalResults/$$currentQueueEnvRef{fileNameBase}/GO/";
	
	#  Creating web result directory for GO
	mkdir ($goWebOutputDir) || print "";
	
    my %testGO2HUGOIDs              = ();
    my %testGO2HUGOIDCount          = ();
    my %backgroundGO2HUGOIDs        = ();
    my %backgroundGO2HUGOIDCount    = ();
    my $testedHUGOIDCount           = scalar @{$tgHugoIDsRef};
    my $backgroundHUGOIDCount       = scalar @{$bgHugoIDsRef};
    my %testCategoryLevelGO         = ();
    my %backgroundCategoryLevelGO   = ();

    my %tgCategoryGOExplicit        = ();
    my %tgGOExplicitHUGOIDCnt       = ();
    my %tgGOExplicitHUGOIDs         = ();
    my %bgCategoryGOExplicit        = ();
    my %bgGOExplicitHUGOIDCnt       = ();
    my %bgGOExplicitHUGOIDs         = ();

    my %tgCategoryGOFull            = ();
    my %bgCategoryGOFull            = ();
    my $additionalExtension         = '.txt';
    
    open (TESTFILE, $targetFullGOFile) || return(-1, "!ERROR: Can't open $targetFullGOFile ...");
    open (BACKGROUND, $bgFullGOFile) || return(-1, "!ERROR: Can't open $bgFullGOFile ...");

    while(<TESTFILE>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        my @tmpSplit = split(/\t/, $line);

        # Skip any level 1 entry or no GO entry
        if ((not defined $tmpSplit[5]) || ($tmpSplit[5] == 1))
        {   next;
        }else
        {   #$testReal{$tmpSplit[0]} = 1;
        }

        if (not defined $testCategoryLevelGO{$tmpSplit[4]})
        {   my %tmpLevel2GO = ();
            $tmpLevel2GO{$tmpSplit[5]} = $tmpSplit[7].';';
            $testCategoryLevelGO{$tmpSplit[4]} = \%tmpLevel2GO;
        }else
        {   if (defined $testCategoryLevelGO{$tmpSplit[4]}->{$tmpSplit[5]})
            {   if ($testCategoryLevelGO{$tmpSplit[4]}->{$tmpSplit[5]} !~ /\b$tmpSplit[7]\b/)
                {   $testCategoryLevelGO{$tmpSplit[4]}->{$tmpSplit[5]} .= $tmpSplit[7].';';
                }
            }else
            {   $testCategoryLevelGO{$tmpSplit[4]}->{$tmpSplit[5]} = $tmpSplit[7].';';
            }
        }

        #  Process all GO (implicit + explicit) (or EXTENDED + ORIGINAL)
        if (not defined $tgCategoryGOFull{$tmpSplit[4]})
        {   $tgCategoryGOFull{$tmpSplit[4]} = $tmpSplit[7].';';
        }else
        {   if ($tgCategoryGOFull{$tmpSplit[4]} !~ /\b$tmpSplit[7]\b/)
            {   $tgCategoryGOFull{$tmpSplit[4]} .= $tmpSplit[7].';';
            }
        }
        
        if (not defined $testGO2HUGOIDs{$tmpSplit[7]})
        {   my %tmpHash				= ();
        	$tmpHash{$tmpSplit[0]}	= 1;
        	$testGO2HUGOIDs{$tmpSplit[7]} = \%tmpHash;
        }else
        {   $testGO2HUGOIDs{$tmpSplit[7]}->{$tmpSplit[0]} = 1;
        }
        

        #  Process explicit only GO
        if ($tmpSplit[6] eq 'ORIGINAL')
        {   #  Collect explicitly assigned GO
            if (not defined $tgCategoryGOExplicit{$tmpSplit[4]})
            {   $tgCategoryGOExplicit{$tmpSplit[4]} = $tmpSplit[7].';';
            }else
            {   if ($tgCategoryGOExplicit{$tmpSplit[4]} !~ /\b$tmpSplit[7]\b/)
                {   $tgCategoryGOExplicit{$tmpSplit[4]} .= $tmpSplit[7].';';
                }
            }
            
            #  Collect genes with explicitly assigned GO
            if (not defined $tgGOExplicitHUGOIDs{$tmpSplit[7]})
            {   my %tmpHash				= ();
		    	$tmpHash{$tmpSplit[0]}	= 1;
		    	$tgGOExplicitHUGOIDs{$tmpSplit[7]} = \%tmpHash;
            }else
            {   $tgGOExplicitHUGOIDs{$tmpSplit[7]}->{$tmpSplit[0]} = 1;
            } 
        }
    }
    close (TESTFILE);

    while(<BACKGROUND>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        my @tmpSplit = split(/\t/, $line);
		
		# Skip any level 1 entry or no GO entry
        if ((not defined $tmpSplit[5]) || ($tmpSplit[5] == 1))
        {   next;
        }else
        {   #$backgroundReal{$tmpSplit[0]} = 1;
        }

        if (not defined $backgroundCategoryLevelGO{$tmpSplit[4]})
        {   my %tmpLevel2GO = ();
            $tmpLevel2GO{$tmpSplit[5]} = $tmpSplit[7].';';
            $backgroundCategoryLevelGO{$tmpSplit[4]} = \%tmpLevel2GO;
        }else
        {   if (defined $backgroundCategoryLevelGO{$tmpSplit[4]}->{$tmpSplit[5]})
            {   $backgroundCategoryLevelGO{$tmpSplit[4]}->{$tmpSplit[5]} .= $tmpSplit[7].';';
            }else
            {   $backgroundCategoryLevelGO{$tmpSplit[4]}->{$tmpSplit[5]} = $tmpSplit[7].';';
            }
        }

        #  Process all GO (implicit + explicit) (or EXTENDED + ORIGINAL)
        if (not defined $bgCategoryGOFull{$tmpSplit[4]})
        {   $bgCategoryGOFull{$tmpSplit[4]} = $tmpSplit[7].';';
        }else
        {   if ($bgCategoryGOFull{$tmpSplit[4]} !~ /\b$tmpSplit[7]\b/)
            {   $bgCategoryGOFull{$tmpSplit[4]} .= $tmpSplit[7].';';
            }
        }
        
        if (not defined $backgroundGO2HUGOIDs{$tmpSplit[7]})
        {   my %tmpHash				= ();
        	$tmpHash{$tmpSplit[0]}	= 1;
        	$backgroundGO2HUGOIDs{$tmpSplit[7]} = \%tmpHash;
        }else
        {   $backgroundGO2HUGOIDs{$tmpSplit[7]}->{$tmpSplit[0]} = 1;
        }
        
        
        #  Process explicit only GO
        if ($tmpSplit[6] eq 'ORIGINAL')
        {   #  Collect explicitly assigned GO
            if (not defined $bgCategoryGOExplicit{$tmpSplit[4]})
            {   $bgCategoryGOExplicit{$tmpSplit[4]} = $tmpSplit[7].';';
            }else
            {   if ($bgCategoryGOExplicit{$tmpSplit[4]} !~ /\b$tmpSplit[7]\b/)
                {   $bgCategoryGOExplicit{$tmpSplit[4]} .= $tmpSplit[7].';';
                }
            }
            
            #  Collect genes with explicitly assigned GO
            if (not defined $bgGOExplicitHUGOIDs{$tmpSplit[7]})
            {   my %tmpHash				= ();
		    	$tmpHash{$tmpSplit[0]}	= 1;
		    	$bgGOExplicitHUGOIDs{$tmpSplit[7]} = \%tmpHash;
            }else
            {   $bgGOExplicitHUGOIDs{$tmpSplit[7]}->{$tmpSplit[0]} = 1;
            } 
        }
    }
    close (BACKGROUND);


	#  -------------------------------------------------------------------------
	#		Calculate hugoID count
	#  -------------------------------------------------------------------------

	
	foreach my $tmpGOID (keys %testGO2HUGOIDs)
	{	$testGO2HUGOIDCount{$tmpGOID} 		= scalar (keys %{$testGO2HUGOIDs{$tmpGOID}});
	}
	foreach my $tmpGOID (keys %backgroundGO2HUGOIDs)
	{	$backgroundGO2HUGOIDCount{$tmpGOID} = scalar (keys %{$backgroundGO2HUGOIDs{$tmpGOID}});
	}
	
	foreach my $tmpGOID (keys %tgGOExplicitHUGOIDs)
	{	$tgGOExplicitHUGOIDCnt{$tmpGOID} 	= scalar (keys %{$tgGOExplicitHUGOIDs{$tmpGOID}});
	}
	foreach my $tmpGOID (keys %bgGOExplicitHUGOIDs)
	{	$bgGOExplicitHUGOIDCnt{$tmpGOID} 	= scalar (keys %{$bgGOExplicitHUGOIDs{$tmpGOID}});
	}
		
#    $testRealCount          = scalar (keys %testReal);
#    $backgroundRealCount    = scalar (keys %backgroundReal);
#    $additionalExtension    = '_realGO';
    
#    $testRealCount          = $testedHUGOIDCount;
#    $backgroundRealCount    = $backgroundHUGOIDCount;
    $additionalExtension    = '';

    # -------------------------------------------------------------------------------
    #           Create Temporary file cor Fisher Exact Test
    # -------------------------------------------------------------------------------
    
    
    
    #  Initialize result hashes or variables
    
    
    my $np1 = $testedHUGOIDCount;             
    my $np2 = $backgroundHUGOIDCount;            
    my $npp = $np1 + $np2;
    my $n1p = 0;                        # number of PMIDs with the given code
    my $n11 = 0;                        # number of PMIDs common
    my $n12 = 0;
    my $n21 = 0;
    my $n22 = 0;
    my $twotailedPvalue = 0;
    my $errorCode = "";
    my $ratioTarget = 0;
    my $ratioBackground   = 0;
       
#          word2   ~word2                       corpus         full
#  word1    n11      n12 | n1p       MeSH+        n11          n12     n1p
# ~word1    n21      n22 | n2p       MeSH-        n21          n22     n2p
#           --------------
#           np1      np2   npp                    np1          np2     npp

    
    #  Perform Fisher's exact test by category Selected Level Only
    foreach my $GOTopCategory ( keys %testCategoryLevelGO )
    {   my @collectedLines          = ();
        my %PValueByGO              = ();
        my %MatrixByGO              = ();
        for (my $level = 2; $level <= 5; $level++)
        {   if (defined $testCategoryLevelGO{$GOTopCategory}->{$level})
            {   # Perform Fisher-test
                my $finalOutFileName    = $goOutputDir.$GOTopCategory.'_Level'.$level.$additionalExtension;
                my $excelFileName		= $finalOutFileName.'.xls';
                open (OUTPUT, ">".$finalOutFileName);
                my @tmpSplit = split (/\;/, $testCategoryLevelGO{$GOTopCategory}->{$level});
                my @sortedGO = sort {$testGO2HUGOIDCount{$b} <=> $testGO2HUGOIDCount{$a}} @tmpSplit;
                foreach my $go (@sortedGO)
                {   $n11 = $testGO2HUGOIDCount{$go};
                    if (defined $backgroundGO2HUGOIDCount{$go})
                    {   $n12 = $backgroundGO2HUGOIDCount{$go};
                    }else
                    {   $n12 = 0;
                    }
                    $n1p = $n11 + $n12;                             # Note that n1p = n11 + n12
                    $n21 = $np1 - $n11;
                    $n22 = $np2 - $n12;
        
                    $twotailedPvalue = calculateStatistic (n11 => $n11, 
                                                           n1p => $n1p,
                                                           np1 => $np1,
                                                           npp => $npp);
                    if ( ($errorCode = getErrorCode()))
                    {   $PValueByGO{$go} = -1;
                    }else
                    {   $PValueByGO{$go} = sprintf("%.3e",$twotailedPvalue);
                    }
                    
                    $MatrixByGO{$go}    = $np1."\t".$n11."\t".$n21."\t".$n12."\t".$n22."\t".$np2."\t".$PValueByGO{$go}."\t";
                    $ratioTarget        = $n11/$np1;
                    $ratioBackground    = $n12/$np2;
                        
                        
                    if (($n12 != 0) && ($n11 != 0))
                    {   $MatrixByGO{$go} .= sprintf("%.2f\t%.2f\t%.1f",$ratioTarget, $ratioBackground, ($ratioTarget)/($ratioBackground));
                    }else
                    {   # This is very unlike to happen. But in case it happens. 
                    	my $tmpTag		= $tgZeroTag;
						if ($n12 == 0)
						{	$tmpTag		= $bgZeroTag;
						}
                        $MatrixByGO{$go} .= sprintf("%.2f\t%.2f\t",$ratioTarget, $ratioBackground).$tmpTag;
                    }
                }
     
                my @PValueSortedGOIDs = sort {$PValueByGO{$a} <=> $PValueByGO{$b}} @sortedGO;
                foreach my $go (@PValueSortedGOIDs)
                {   my $outLine = $go."\t".$$GO2DESCRef{$go}."\t".$MatrixByGO{$go};
                    print OUTPUT $outLine."\n";
                    push @collectedLines, 'Level'.$level."\t".$outLine;
                }
                close (OUTPUT);
                `ln -s $finalOutFileName $excelFileName`;
                LogAnalysis("Outputfile is $finalOutFileName completed");
            }
        }

        #  Creating GO Detailed List files
        my %PValueByLevelGO             = ();
        my %lineContentByLevelGO        = ();
        my @tmpLevelGOIDs               = ();
        my %LevelGO2Desc                = ();
        my %LevelGO2GO                  = ();
        foreach my $tmpLine (@collectedLines)
        {   my @tmp                     = split (/\t/, $tmpLine);
            my $levelGO                 = $tmp[0].'_'.$tmp[1];
            $PValueByLevelGO{$levelGO}  = $tmp[9];
            $LevelGO2Desc{$levelGO}     = $$GO2DESCRef{$tmp[1]};
            $LevelGO2GO{$levelGO}       = $tmp[1];
            $lineContentByLevelGO{$levelGO} = $tmpLine;
            push @tmpLevelGOIDs, $levelGO;
        }
        
        open (OUTPUT, ">".$goOutputDir.$GOTopCategory.'_SelectedLevel.txt');
        print OUTPUT "#Level	GOID	GOTerm	t-total	t+	t-	b+	b-	b-total	p-value	t-ratio	b-ratio	(t-ratio)/(b-ratio)\n";

        my @sortedLevelGOIDs = sort {$PValueByLevelGO{$a} <=> $PValueByLevelGO{$b}} @tmpLevelGOIDs;
        my $detailDir = $goWebOutputDir.$GOTopCategory.'_SelectedLevel_DIR';
        mkdir ($detailDir) || print "";
        my $rank = 1;
        
        foreach my $levelGO (@sortedLevelGOIDs)
        {   print OUTPUT $lineContentByLevelGO{$levelGO}."\n";
            my $tmpFileName = $rank.'_'.$levelGO.'_'.$LevelGO2Desc{$levelGO};
            $tmpFileName =~ s/\'|\,|\.|\:|\;|\\|\// /g;
            $tmpFileName =~ s/\s+/ /g;
            if (length($tmpFileName) > 40)
            {   $tmpFileName = substr($tmpFileName, 0, 40);
            }
            open (DETAIL, ">".$detailDir.'/'.$tmpFileName.'.txt') || return( -1, "!ERROR: Can't create $tmpFileName for levelGO");
            print DETAIL "#CLASS\tHugoID\tSymbol\tNCBIGeneID\tName\n";

            my @testHUGOIDs                 = keys %{$testGO2HUGOIDs{$LevelGO2GO{$levelGO}}};
            my @backgroundHUGOIDs			= keys %{$backgroundGO2HUGOIDs{$LevelGO2GO{$levelGO}}};
            my %testHUGOIDsCheck            = ();
            
            #  Process HUGO IDs
            my @commonHUGOIDs				= ();
            my @tgOnlyHUGOIDs				= ();
            my @bgOnlyHUGOIDs				= ();
            
            foreach my $hugoID (@testHUGOIDs)
            {	$testHUGOIDsCheck{$hugoID} = 1;
            }
            
            foreach my $hugoID (@backgroundHUGOIDs)
            {   if (not defined $testHUGOIDsCheck{$hugoID})
            	{	push @bgOnlyHUGOIDs, $hugoID;
            		$testHUGOIDsCheck{$hugoID}	= 3;
            	}else
            	{	push @commonHUGOIDs, $hugoID;
            		$testHUGOIDsCheck{$hugoID}	= 2;
            	}
            }
            
            foreach my $hugoID (@testHUGOIDs)
            {	if ($testHUGOIDsCheck{$hugoID} == 1)
            	{	push @tgOnlyHUGOIDs, $hugoID;
            	}
            }
            
            #  Print out DETAIL file
            #  TGOnly, Common, BGOnly
            #
            print DETAIL "#TESTONLY: ".(scalar @tgOnlyHUGOIDs)."\n";
            print DETAIL "#COMMON: ".(scalar @commonHUGOIDs)."\n";
            print DETAIL "#BACKGROUNDONLY: ".(scalar @bgOnlyHUGOIDs)."\n";
            
            foreach my $hugoID (@tgOnlyHUGOIDs)
            {   print DETAIL "TESTONLY\t".$hugoID."\t";
                print DETAIL $$hugoID2SymbolRef{$hugoID}."\t";
                if (defined $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}})
                {	print DETAIL $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}}."\t";
                }else
                {	print DETAIL "\t";
                }
                print DETAIL $$hugoID2NameRef{$hugoID}."\n";
            }
            print DETAIL "\n";
            
            foreach my $hugoID (@commonHUGOIDs)
            {   print DETAIL "COMMON\t".$hugoID."\t";
                print DETAIL $$hugoID2SymbolRef{$hugoID}."\t";
                if (defined $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}})
                {	print DETAIL $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}}."\t";
                }else
                {	print DETAIL "\t";
                }
                print DETAIL $$hugoID2NameRef{$hugoID}."\n";
            }
            print DETAIL "\n";

            foreach my $hugoID (@bgOnlyHUGOIDs)
            {   print DETAIL "BACKGROUNDONLY\t".$hugoID."\t";
                print DETAIL $$hugoID2SymbolRef{$hugoID}."\t";
                if (defined $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}})
                {	print DETAIL $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}}."\t";
                }else
                {	print DETAIL "\t";
                }
                print DETAIL $$hugoID2NameRef{$hugoID}."\n";
            }
            close (DETAIL);
            $rank++;
        }
        close OUTPUT;
    }
    
    
    
   
    
    #  --------------------------------------------------------------------
    #  Perform Fisher's exact test on explicit GO assignment only
    #  --------------------------------------------------------------------
    foreach my $GOTopCategory ( keys %tgCategoryGOExplicit )
    {   my @collectedLines          = ();
        my %PValueByGO              = ();
        my %MatrixByGO              = ();
        
        # Perform Fisher-test
        my $finalOutFileName    = $goOutputDir.$GOTopCategory.'_ExplicitOnly.txt';
        open (OUTPUT, ">".$finalOutFileName);
        print OUTPUT "#GOID	GOTerm	t-total	t+	t-	b+	b-	b-total	p-value	t-ratio	b-ratio	(t-ratio)/(b-ratio)\n";

        my @goSplits = split (/\;/, $tgCategoryGOExplicit{$GOTopCategory});
        foreach my $go (@goSplits)
        {   $n11 = $tgGOExplicitHUGOIDCnt{$go};
            if (defined $bgGOExplicitHUGOIDCnt{$go})
            {   $n12 = $bgGOExplicitHUGOIDCnt{$go};
            }else
            {   $n12 = 0;
            }
            $n1p = $n11 + $n12;                             # Note that n1p = n11 + n12
            $n21 = $np1 - $n11;
            $n22 = $np2 - $n12;

            $twotailedPvalue = calculateStatistic (n11 => $n11, 
                                                    n1p => $n1p,
                                                    np1 => $np1,
                                                    npp => $npp);
            if ( ($errorCode = getErrorCode()))
            {   $PValueByGO{$go} = -1;
            }else
            {   $PValueByGO{$go} = sprintf("%.3e",$twotailedPvalue);
            }
            
            $MatrixByGO{$go}    = $np1."\t".$n11."\t".$n21."\t".$n12."\t".$n22."\t".$np2."\t".$PValueByGO{$go}."\t";
            $ratioTarget        = $n11/$np1;
            $ratioBackground    = $n12/$np2;
                
            if (($n12 != 0) && ($n11 != 0))
            {   $MatrixByGO{$go} .= sprintf("%.2f\t%.2f\t%.1f",$ratioTarget, $ratioBackground, ($ratioTarget)/($ratioBackground));
            }else
            {   # This is very unlike to happen. But in case it happens. 
            	my $tmpTag		= $tgZeroTag;
		    	if ($n12 == 0)
		    	{	$tmpTag		= $bgZeroTag;
		    	}
                $MatrixByGO{$go} .= sprintf("%.2f\t%.2f\t",$ratioTarget, $ratioBackground).$tmpTag;
            }
        }

        my @PValueSortedGOIDs = sort {$PValueByGO{$a} <=> $PValueByGO{$b}} @goSplits;
        my $detailDir = $goWebOutputDir.$GOTopCategory.'_ExplicitOnly_DIR';
        mkdir ($detailDir) || print "";
        my $rank = 1;
        
        
        foreach my $go (@PValueSortedGOIDs)
        {   my $outLine = $go."\t".$$GO2DESCRef{$go}."\t".$MatrixByGO{$go};
            print OUTPUT $outLine."\n";
            my $tmpFileName = $rank.'_'.$$GO2DESCRef{$go};
            $tmpFileName =~ s/\'|\,|\.|\:|\;|\\|\// /g;
            $tmpFileName =~ s/\s+/ /g;
            if (length($tmpFileName) > 40)
            {   $tmpFileName = substr($tmpFileName, 0, 40);
            }
            open (DETAIL, ">".$detailDir.'/'.$tmpFileName.'.txt') || return( -1, "!ERROR: Can't create $tmpFileName for levelGO");
            print DETAIL "#CLASS\tHugoID\tSymbol\tNCBIGeneID\tName\n";
            
            my @testHUGOIDs                 = keys %{$tgGOExplicitHUGOIDs{$go}};  
            my @backgroundHUGOIDs			= keys %{$bgGOExplicitHUGOIDs{$go}}; 
            my %testHUGOIDsCheck            = ();
            
            #  Process HUGO IDs
            my @commonHUGOIDs				= ();
            my @tgOnlyHUGOIDs				= ();
            my @bgOnlyHUGOIDs				= ();
            
            foreach my $hugoID (@testHUGOIDs)
            {	$testHUGOIDsCheck{$hugoID} = 1;
            }
            
            foreach my $hugoID (@backgroundHUGOIDs)
            {   if (not defined $testHUGOIDsCheck{$hugoID})
            	{	push @bgOnlyHUGOIDs, $hugoID;
            		$testHUGOIDsCheck{$hugoID}	= 3;
            	}else
            	{	push @commonHUGOIDs, $hugoID;
            		$testHUGOIDsCheck{$hugoID}	= 2;
            	}
            }
            
            foreach my $hugoID (@testHUGOIDs)
            {	if ($testHUGOIDsCheck{$hugoID} == 1)
            	{	push @tgOnlyHUGOIDs, $hugoID;
            	}
            }
            
            #  Print out DETAIL file
            #  TGOnly, Common, BGOnly
            #
            print DETAIL "#TESTONLY: ".(scalar @tgOnlyHUGOIDs)."\n";
            print DETAIL "#COMMON: ".(scalar @commonHUGOIDs)."\n";
            print DETAIL "#BACKGROUNDONLY: ".(scalar @bgOnlyHUGOIDs)."\n";
            
            foreach my $hugoID (@tgOnlyHUGOIDs)
            {   print DETAIL "TESTONLY\t".$hugoID."\t";
                print DETAIL $$hugoID2SymbolRef{$hugoID}."\t";
                if (defined $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}})
                {	print DETAIL $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}}."\t";
                }else
                {	print DETAIL "\t";
                }
                print DETAIL $$hugoID2NameRef{$hugoID}."\n";
            }
            print DETAIL "\n";
            
            foreach my $hugoID (@commonHUGOIDs)
            {   print DETAIL "COMMON\t".$hugoID."\t";
                print DETAIL $$hugoID2SymbolRef{$hugoID}."\t";
                if (defined $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}})
                {	print DETAIL $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}}."\t";
                }else
                {	print DETAIL "\t";
                }
                print DETAIL $$hugoID2NameRef{$hugoID}."\n";
            }
            print DETAIL "\n";

            foreach my $hugoID (@bgOnlyHUGOIDs)
            {   print DETAIL "BACKGROUNDONLY\t".$hugoID."\t";
                print DETAIL $$hugoID2SymbolRef{$hugoID}."\t";
                if (defined $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}})
                {	print DETAIL $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}}."\t";
                }else
                {	print DETAIL "\t";
                }
                print DETAIL $$hugoID2NameRef{$hugoID}."\n";
            }
            close (DETAIL);
            $rank++;
        }
        close (OUTPUT);
    }
        
        

    
    
    #  --------------------------------------------------------------------
    #  Perform Fisher's exact test on Full GO assignment only
    #  --------------------------------------------------------------------
    foreach my $GOTopCategory ( keys %tgCategoryGOFull )
    {   my @collectedLines          = ();
        my %PValueByGO              = ();
        my %MatrixByGO              = ();
        
        # Perform Fisher-test
        my $finalOutFileName    = $goOutputDir.$GOTopCategory.'_Full.txt';
        open (OUTPUT, ">".$finalOutFileName);
        print OUTPUT "#GOID	GOTerm	t-total	t+	t-	b+	b-	b-total	p-value	t-ratio	b-ratio	(t-ratio)/(b-ratio)\n";
        
        my @goSplits = split (/\;/, $tgCategoryGOFull{$GOTopCategory});
        foreach my $go (@goSplits)
        {   $n11 = $testGO2HUGOIDCount{$go};
            if (defined $backgroundGO2HUGOIDCount{$go})
            {   $n12 = $backgroundGO2HUGOIDCount{$go};
            }else
            {   $n12 = 0;
            }
            $n1p = $n11 + $n12;                             # Note that n1p = n11 + n12
            $n21 = $np1 - $n11;
            $n22 = $np2 - $n12;

            $twotailedPvalue = calculateStatistic (n11 => $n11, 
                                                    n1p => $n1p,
                                                    np1 => $np1,
                                                    npp => $npp);
            if ( ($errorCode = getErrorCode()))
            {   $PValueByGO{$go} = -1;
            }else
            {   $PValueByGO{$go} = sprintf("%.3e",$twotailedPvalue);
            }
            
            $MatrixByGO{$go}    = $np1."\t".$n11."\t".$n21."\t".$n12."\t".$n22."\t".$np2."\t".$PValueByGO{$go}."\t";
            $ratioTarget        = $n11/$np1;
            $ratioBackground    = $n12/$np2;
                
            if (($n12 != 0) && ($n11 != 0))
            {   $MatrixByGO{$go} .= sprintf("%.2f\t%.2f\t%.1f",$ratioTarget, $ratioBackground, ($ratioTarget)/($ratioBackground));
            }else
            {   # This is very unlike to happen. But in case it happens. 
            	my $tmpTag		= $tgZeroTag;
		    	if ($n12 == 0)
		    	{	$tmpTag		= $bgZeroTag;
		    	}
                $MatrixByGO{$go} .= sprintf("%.2f\t%.2f\t",$ratioTarget, $ratioBackground).$tmpTag;
            }
        }

        my @PValueSortedGOIDs = sort {$PValueByGO{$a} <=> $PValueByGO{$b}} @goSplits;
        my $detailDir = $goWebOutputDir.$GOTopCategory.'_Full_DIR';
        mkdir ($detailDir) || print "";
        my $rank = 1;
        
        foreach my $go (@PValueSortedGOIDs)
        {   my $outLine = $go."\t".$$GO2DESCRef{$go}."\t".$MatrixByGO{$go};
            print OUTPUT $outLine."\n";
            my $tmpFileName = $rank.'_'.$$GO2DESCRef{$go};
            $tmpFileName =~ s/\'|\,|\.|\:|\;|\\|\// /g;
            $tmpFileName =~ s/\s+/ /g;
            if (length($tmpFileName) > 40)
            {   $tmpFileName = substr($tmpFileName, 0, 40);
            }
            open (DETAIL, ">".$detailDir.'/'.$tmpFileName.'.txt') || return( -1, "!ERROR: Can't create $tmpFileName for levelGO");
            print DETAIL "#CLASS\tHugoID\tSymbol\tNCBIGeneID\tName\n";
                        
            my @testHUGOIDs                 = keys %{$testGO2HUGOIDs{$go}};
            my @backgroundHUGOIDs			= keys %{$backgroundGO2HUGOIDs{$go}};
            my %testHUGOIDsCheck            = ();
            
            #  Process HUGO IDs
            my @commonHUGOIDs				= ();
            my @tgOnlyHUGOIDs				= ();
            my @bgOnlyHUGOIDs				= ();
            
            foreach my $hugoID (@testHUGOIDs)
            {	$testHUGOIDsCheck{$hugoID} = 1;
            }
            
            foreach my $hugoID (@backgroundHUGOIDs)
            {   if (not defined $testHUGOIDsCheck{$hugoID})
            	{	push @bgOnlyHUGOIDs, $hugoID;
            		$testHUGOIDsCheck{$hugoID}	= 3;
            	}else
            	{	push @commonHUGOIDs, $hugoID;
            		$testHUGOIDsCheck{$hugoID}	= 2;
            	}
            }
            
            foreach my $hugoID (@testHUGOIDs)
            {	if ($testHUGOIDsCheck{$hugoID} == 1)
            	{	push @tgOnlyHUGOIDs, $hugoID;
            	}
            }
            
            #  Print out DETAIL file
            #  TGOnly, Common, BGOnly
            #
            print DETAIL "#TESTONLY: ".(scalar @tgOnlyHUGOIDs)."\n";
            print DETAIL "#COMMON: ".(scalar @commonHUGOIDs)."\n";
            print DETAIL "#BACKGROUNDONLY: ".(scalar @bgOnlyHUGOIDs)."\n";
            
            foreach my $hugoID (@tgOnlyHUGOIDs)
            {   print DETAIL "TESTONLY\t".$hugoID."\t";
                print DETAIL $$hugoID2SymbolRef{$hugoID}."\t";
                if (defined $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}})
                {	print DETAIL $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}}."\t";
                }else
                {	print DETAIL "\t";
                }
                print DETAIL $$hugoID2NameRef{$hugoID}."\n";
            }
            print DETAIL "\n";
            
            foreach my $hugoID (@commonHUGOIDs)
            {   print DETAIL "COMMON\t".$hugoID."\t";
                print DETAIL $$hugoID2SymbolRef{$hugoID}."\t";
                if (defined $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}})
                {	print DETAIL $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}}."\t";
                }else
                {	print DETAIL "\t";
                }
                print DETAIL $$hugoID2NameRef{$hugoID}."\n";
            }
            print DETAIL "\n";

            foreach my $hugoID (@bgOnlyHUGOIDs)
            {   print DETAIL "BACKGROUNDONLY\t".$hugoID."\t";
                print DETAIL $$hugoID2SymbolRef{$hugoID}."\t";
                if (defined $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}})
                {	print DETAIL $$symbol2ncbiEntrezGeneIDRef{$$hugoID2SymbolRef{$hugoID}}."\t";
                }else
                {	print DETAIL "\t";
                }
                print DETAIL $$hugoID2NameRef{$hugoID}."\n";
            }
            close (DETAIL);
            $rank++;
        }
        close (OUTPUT);
    }
}





# ------------------------------------------------------------------------------
# Name  : Create_Full_GO_File_From_HUGO_IDs_v2
# Date  : 08-23-2007
# Func  : Create FULL GO Format Files from HUGO IDs
#         Unlike the previous version, this v2 does not use GENE2GO. Instead
#         this uses %HUGOSym2GO
sub Create_Full_GO_File
{   my $localOutFileName        = shift;
    my $localHUGOIDs            = shift;
    my $localHUGOID2Symbol      = shift;
    my $localHUGOID2Name        = shift;
    my $localHUGOID2GO          = shift;
    my $localGOID2CODE          = shift;
    my $localGOCODE2ID          = shift;
    my $localGO2DESC            = shift;
    
    my $fileStatus              = 1;
    
    open (OUTGO, ">".$localOutFileName) || return(-1);
    foreach my $hugoID (@{$localHUGOIDs})
    {   my $newoutStr = $hugoID."\t".$$localHUGOID2Symbol{$hugoID}."\t".$$localHUGOID2Name{$hugoID}."\t";
        if (defined $$localHUGOID2GO{$hugoID})
        {   my @GOSplit = split (/\|/, $$localHUGOID2GO{$hugoID});
            my (%GOExtensionCheck, %GOIDLevel, %GOCategory, @TotalGOID);
            foreach my $go (@GOSplit)
            {   if (defined $$localGOID2CODE{$go}) 
                {   push @TotalGOID, $go;
                    $GOExtensionCheck{$go} = 'ORIGINAL';
                    $GOCategory{$go} = Get_GO_Category($go, $localGOID2CODE);
                    $GOIDLevel{$go} = Get_GO_Level($go, $localGOID2CODE);
                    my ($GOParentIDs, $GOParentIDLevel)  = GO_Get_All_Parents($go, $localGOID2CODE, $localGOCODE2ID);
                    for (my $i=0; $i < scalar @$GOParentIDs; $i++)
                    {   if (defined $GOExtensionCheck{$$GOParentIDs[$i]}) 
                        {   # If previously defined, then ignore this parental node.
                        }else
                        {   $GOExtensionCheck{$$GOParentIDs[$i]} = 'EXTENDED';
                            $GOIDLevel{$$GOParentIDs[$i]} = $$GOParentIDLevel[$i];
                            $GOCategory{$$GOParentIDs[$i]} = Get_GO_Category($$GOParentIDs[$i], $localGOID2CODE); 
                            push @TotalGOID, $$GOParentIDs[$i];
                        }
                    }
                }else
                {   # Do not process any GO ID not in the current GO Code tree
                }
            }
            foreach (@TotalGOID) 
            {   print OUTGO $newoutStr."GO_INFO\t";
                print OUTGO $GOCategory{$_}."\t";
                print OUTGO $GOIDLevel{$_}."\t";
                print OUTGO $GOExtensionCheck{$_}."\t";
                print OUTGO $_."\t";
                print OUTGO $$localGO2DESC{$_}."\n";
            }
        }else
        {   print OUTGO $newoutStr."NO_GO\n";
        }
    }
    close (OUTGO);
    return (1);
}





#  -----------------------------------------------------------------------------
#  Name  : GO_Get_All_Parents
#  Date  : Last modified 08/22/2007
#  Func  : Return all possible parent GO for a given node (GO Code)
sub GO_Get_All_Parents
{   my ($GOID, $CodeByID, $IDByCode)=@_;
    my @GOCodeArray = split (/\<\_\>/, $$CodeByID{$GOID} );
    my @extendedGOIDArray=();    my %extendedGOIDHash=();
    my @extendedGOLevel=();


    for (my $i=0; $i <= $#GOCodeArray; $i++)
    {   my @codeSplit = split (/\s/, $GOCodeArray[$i]);
        my $pos=0;
        while ($codeSplit[$pos] != 0)
        {   $pos++;
        }

        for (my $k=$pos-1; $k > 1; $k--)
        {   $codeSplit[$k]=0;
            my $tmpCode = join ( ' ', @codeSplit);
            if (not defined $$IDByCode{$tmpCode} ) 
            {   print "Not defined code\t".$tmpCode."HHH\n";
            }
            
            if (defined $extendedGOIDHash{$$IDByCode{$tmpCode}}) 
            {   # Already included at the previous steps
            }else
            {   push @extendedGOIDArray, $$IDByCode{$tmpCode};
                push @extendedGOLevel, $k;
                $extendedGOIDHash{$$IDByCode{$tmpCode}} = 'YES';
            }
        }
    }
    return (\@extendedGOIDArray, \@extendedGOLevel);   # Returns only extended IDs
}





sub Get_GO_Category
{   my ($GOID, $CodeByID) = @_;
    if ($$CodeByID{$GOID} =~ /^1/)
    {   return ('MF');
    }elsif ($$CodeByID{$GOID} =~ /^2/)
    {   return ('BP');
    }elsif ($$CodeByID{$GOID} =~ /^3/)
    {   return ('CC');
    }else
    {   return ('ERROR');
    }
}




sub Get_GO_Level
{   my ($GOID, $CodeByID) = @_;
    my @GOCodeArray = split (/\<\_\>/, $$CodeByID{$GOID});
    
    # Return the level of the first incidence. 
    my @codeSplit = split (/\s/, $GOCodeArray[0]);
    my $pos=0;
    while ($codeSplit[$pos] != 0)
    {   $pos++;
    }   return ($pos);
}



















#  -----------------------------------------------------------------------------
#  3.3 mesh_enrichment_analysis
#  -----------------------------------------------------------------------------
sub mesh_enrichment_analysis
{   my $annoENVRef          = shift;   
    my $currentQueueEnvRef  = shift;
    my $dbh                 = shift;
    my $finalResultDir      = shift;
    my $finalResultWebDir	= shift;
    my $tgQueryEnvRef		= shift;
    my $bgQueryEnvRef		= shift;
    my $hugoSymbol2IDRef	= shift;
    my $totalPMIDinSciMiner	= shift;



    
    #  Module for Fisher's exact test
    use Text::NSP::Measures::2D::Fisher::twotailed;
    
    
    #  First, Load the gene set files
    #  Initialize
    my %MeSHCode2Desc       = ();
    #my %MeSHParentDescByCode= ();

    my @tgMeSHCodes         = ();
    my %tgMeSHCode2Full     = ();
    my %tgMeSHCode2Pos      = ();
    my %tgMeSHCode2Neg      = ();    

    my @bgMeSHCodes         = ();
    my %bgMeSHCode2Full     = ();
    my %bgMeSHCode2Pos      = ();
    my %bgMeSHCode2Neg      = ();    

    
    #  Directories and Files to be used
    my $outputDir           = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/";
    mkdir ($outputDir) || print "";

    my $tgSourceFile        = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{targetQueryNumber2BaseName}/MeSHCodeDistribution.txt";
    my $tgPMIDFile			= "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{targetQueryNumber2BaseName}/MeSHCodeDistribution.pmid";
    my $bgSourceFile        = "";
    my $bgPMIDFile			= "";
    
    my $tgTempFile          = "$$currentQueueEnvRef{targetQueryNumber2BaseName}.MeSH";
    my $bgTempFile          = "";
    
    
    #  Load the full MeSH distribution
    #my $MeSHTreeFile	    = "$annoENV{SciMinerPath}/Work/MeSH/mtrees2008.bin";
	#my $MeSHDistFile	    = "$annoENV{SciMinerPath}/Work/MeSH/NCIBIDBXMeSHDist.txt";
    #my $MeSHCode2DistRef    = load_mesh_term_distribution ($MeSHDistFile, $$currentQueueEnvRef{analID});
    
    my $outputFileHeader    = "\#DescID\tMeSH\tCompStatus\tTGSize\tTG+\tTG-\tBG+\tBG-\tBGSize\tTG-Ratio\tBG-Ratio\tTG-R/BG-R\tP-value\n";
    my $outputFileHeader2	= "\#DescID\tMeSH\tCompStatus\tTGSize\tTG+\tTG-\tT+uniq\tCommon\tB+uniq\tBG+\tBG-\tBGSize\tTG-Ratio\tBG-Ratio\tTG-R/BG-R\tP-value\n";
    LogAnalysis("MeSHOutfile $outputDir/MeSHEnrichmentResult.txt");
    open (OUTPUT, ">$outputDir/MeSHEnrichmentResult.txt") || LogAnalysis("Can't create MeSHEnrichmentResult.txt file");

    if ($$currentQueueEnvRef{MeSHEnrichmentSelection} eq 'Selected')
    {   #  Use selected queryfile as background
        $bgSourceFile       = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{bgQueryNumber2BaseName}/MeSHCodeDistribution.txt";
        $bgTempFile         = "$$currentQueueEnvRef{bgQueryNumber2BaseName}.MeSH";
        $bgPMIDFile			= "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{bgQueryNumber2BaseName}/MeSHCodeDistribution.pmid";
    }elsif ($$currentQueueEnvRef{MeSHEnrichmentSelection} eq 'Whole')
    {   $bgSourceFile       = "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpusMeSH";
        $bgTempFile         = "FullSciMinerDBCorpusMeSH.MeSH";
    }elsif ($$currentQueueEnvRef{MeSHEnrichmentSelection} eq 'FullMeSH')
    {   #  This has already been done along with the mining step.
        my %MeSHTermAlreadyFound = ();
        open (TGMeSH, $tgSourceFile);
        while(<TGMeSH>)
        {   my $line = $_;
            $line =~ s/\r|\n//g;
            if ($line !~ /^\#/)
            {   my @tmpSplit = split (/\t/, $line);
                if (not defined $MeSHTermAlreadyFound{$tmpSplit[1]})
                {   my $newOupString = $tmpSplit[0]."\t".$tmpSplit[1]."\t0\t";
                    for (my $i=2; $i <= 12; $i++)
                    {   $newOupString .= $tmpSplit[$i]."\t";
                    }   $newOupString .= $tmpSplit[13];
                    print OUTPUT $newOupString."\n";
                    $MeSHTermAlreadyFound{$tmpSplit[1]} = 1;
                }else
                {   # Just skip the overlapping entries.
                }
            }
        }
        
        close OUTPUT;
        close TGMeSH;
        
        #  Copy the pmid file
        `cp $tgPMIDFile $outputDir/MeSHEnrichmentResult.pmid`;
        return(1,"");
    }
    

    
    #  Load mesh distribution result files  
    my ($tgLoadStatus, $tgMessage) = load_mesh_dist_file_with_parameters_simplified ($tgSourceFile, \%MeSHCode2Desc, \@tgMeSHCodes, \%tgMeSHCode2Full, \%tgMeSHCode2Pos, \%tgMeSHCode2Neg);
    my ($bgLoadStatus, $bgMessage) = load_mesh_dist_file_with_parameters_simplified ($bgSourceFile, \%MeSHCode2Desc, \@bgMeSHCodes, \%bgMeSHCode2Full, \%bgMeSHCode2Pos, \%bgMeSHCode2Neg); #, \%MeSHParentDescByCode);
                                         
    #  Now, perform fisher's exact test over the set
    if ($tgLoadStatus == -1)
    {   if (defined $tgMessage)
        {   return(-1, $tgMessage); 
        }else
        {   return(-1); 
        }
    }
    if ($bgLoadStatus == -1)
    {   if (defined $bgMessage)
        {   return(-1, $bgMessage); 
        }else
        {   return(-1); 
        }
    }    
  
	# Load pmid list for target and background
	my %tgDescIDPlus2PMIDs			= ();
	my %tgDescIDMinus2PMIDs			= ();
	my %bgDescIDPlus2PMIDs			= ();
	my %bgDescIDMinus2PMIDs			= ();

	my ($tgDescID2PMIDsStatus) 		= load_mesh_pmid_list ($tgPMIDFile, \%tgDescIDPlus2PMIDs, \%tgDescIDMinus2PMIDs );
	my ($bgDescID2PMIDsStatus) 		= load_mesh_pmid_list ($bgPMIDFile, \%bgDescIDPlus2PMIDs, \%bgDescIDMinus2PMIDs );
	
	#  If any of the PMID list file does not exist, then set the file status 0
	my $pmidListFileStatus			= $tgDescID2PMIDsStatus * $bgDescID2PMIDsStatus;
	
    my $tgMeSHCnt           		= scalar @tgMeSHCodes;       
    my $bgMeSHCnt           		= scalar @bgMeSHCodes;            
    
    my $tgMeSHFullCnt       		= 0;
    my $bgMeSHFullCnt       		= 0;
    
    if ($tgMeSHCnt == 0)
    {   #  This cannot be completed since one of the set has no gene
        LogAnalysis("Target set has 0 gene. Analysis aborted");
        return (-1,"Target set has 0 MeSH. Analysis aborted");
    }else
    {   foreach my $descID (@tgMeSHCodes)
        {   if (defined $tgMeSHCode2Full{$descID})
            {   if ($tgMeSHCode2Full{$descID} != 0)
                {   $tgMeSHFullCnt = $tgMeSHCode2Full{$descID};
                    last;
                }
            }
        }
    }
    if ($bgMeSHCnt == 0)
    {   LogAnalysis("Background set has 0 gene. Analysis aborted");
        return (-1, "Background set has 0 MeSH. Analysis aborted");
    }else
    {   foreach my $descID (@bgMeSHCodes)
        {   if (defined $bgMeSHCode2Full{$descID})
            {   if ($bgMeSHCode2Full{$descID} != 0)
                {   $bgMeSHFullCnt = $bgMeSHCode2Full{$descID};
                    last;
                }
            }
        }
    }
    
    #  Perform fisher exact test
    my %PValueByMeSH      = ();
    my %MatrixByMeSH      = ();
  
    my $np1 = $tgMeSHFullCnt;
    my $np2 = $bgMeSHFullCnt;
    my $npp = $np1 + $np2;
    my $n1p = 0;                        # number of PMIDs with the given code
    my $n11 = 0;                        # number of PMIDs common
    my $n12 = 0;
    my $n21 = 0;
    my $n22 = 0;
    my $twotailedPvalue = 0;
    my $errorCode = "";
    my $ratioTarget = 0;
    my $ratioBackground   = 0;
       
    my %tPlusString		= ();
    my %tMinusString	= ();
    my %commonString	= ();
    my %bPlusString		= ();
    my %bMinusString	= ();
    my %commonCount		= ();
    my %tUniqCount		= ();
    my %bUniqCount		= ();
    my %tUniqString		= ();
    my %bUniqString		= ();
#          word2   ~word2                       corpus         full
#  word1    n11      n12 | n1p       MeSH+        n11          n12     n1p
# ~word1    n21      n22 | n2p       MeSH-        n21          n22     n2p
#           --------------
#           np1      np2   npp                    np1          np2     npp

    
	#  Perform Fisher's exact test by category
    foreach my $descID ( @tgMeSHCodes )
    {   #  Initialize string and count
        $tPlusString{$descID}		= '';
        $tMinusString{$descID}		= '';
        $commonString{$descID}		= '';
        $bPlusString{$descID}		= '';
        $bMinusString{$descID}		= '';
        $commonCount{$descID}		= 0;
        $tUniqCount{$descID}		= 0;
        $bUniqCount{$descID}		= 0;
        $tUniqString{$descID}		= '';
        $bUniqString{$descID}		= '';
    	
    	if ($pmidListFileStatus)
    	{	$tPlusString{$descID} 	= join (",", keys %{$tgDescIDPlus2PMIDs{$descID}});
    		$tMinusString{$descID} 	= join (",", keys %{$tgDescIDMinus2PMIDs{$descID}});

    		if (defined $bgDescIDPlus2PMIDs{$descID})
    		{	$bPlusString{$descID} 	= join (",", keys %{$bgDescIDPlus2PMIDs{$descID}});
	    		$bMinusString{$descID} 	= join (",", keys %{$bgDescIDMinus2PMIDs{$descID}});
	    		
				#  Check for commmon
				foreach my $bgPmid (keys %{$bgDescIDPlus2PMIDs{$descID}})
				{	if (defined $tgDescIDPlus2PMIDs{$descID}->{$bgPmid})
					{	$tgDescIDPlus2PMIDs{$descID}->{$bgPmid}	= 2;
						$bgDescIDPlus2PMIDs{$descID}->{$bgPmid} = 2;
						$commonString{$descID}	.= $bgPmid.',';
						$commonCount{$descID}++;
					}else
					{	$bUniqCount{$descID}++;
						$bUniqString{$descID}		.= $bgPmid.',';
					}
				}
				
				foreach my $tgPmid (keys %{$tgDescIDPlus2PMIDs{$descID}})
				{	if ($tgDescIDPlus2PMIDs{$descID}->{$tgPmid} == 1)
					{	$tUniqCount{$descID}++;
						$tUniqString{$descID}		.= $tgPmid.',';
					}
				}
    		}
    	}
        

		#  Perform fisher's exact test    
    	$n11 = $tgMeSHCode2Pos{$descID};
        $n21 = $tgMeSHCode2Neg{$descID};
    
        if (defined $bgMeSHCode2Pos{$descID})
        {   $n12 = $bgMeSHCode2Pos{$descID};
            $n22 = $np2 - $n12;
        }else
        {   $n12 = 0;
            $n22 = $np2;
        }       
        
        $n1p = $n11 + $n12;
        
        $twotailedPvalue = calculateStatistic (n11 => $n11, 
                                               n1p => $n1p,
                                               np1 => $np1,
                                               npp => $npp);
    

        if ( ($errorCode = getErrorCode()))
        {   $PValueByMeSH{$descID} = -1;
        }else
        {   $PValueByMeSH{$descID} = sprintf("%.3e",$twotailedPvalue);
        }
        
        if ($pmidListFileStatus)
        {	$MatrixByMeSH{$descID}    = $descID."\t".$MeSHCode2Desc{$descID}."\t".$pmidListFileStatus."\t".$np1."\t".$n11."\t".$n21."\t".$tUniqCount{$descID}."\t".$commonCount{$descID}."\t".$bUniqCount{$descID}."\t".$n12."\t".$n22."\t".$np2."\t";
        }else
        {	$MatrixByMeSH{$descID}    = $descID."\t".$MeSHCode2Desc{$descID}."\t".$pmidListFileStatus."\t".$np1."\t".$n11."\t".$n21."\t".$n12."\t".$n22."\t".$np2."\t";
        }
        
        $ratioTarget        = $n11/$np1;
        $ratioBackground    = $n12/$np2;
            
        if (($n12 != 0) && ($n11 != 0))
        {   $MatrixByMeSH{$descID} .= sprintf("%.2f\t%.2f\t%.1f",$ratioTarget, $ratioBackground, ($ratioTarget)/($ratioBackground));
        }else
        {   # This is very unlike to happen. But in case it happens. 
        	my $tmpTag		= $tgZeroTag;
        	if ($n12 == 0)
        	{	$tmpTag		= $bgZeroTag;
        	}
            $MatrixByMeSH{$descID} .= sprintf("%.2f\t%.2f\t",$ratioTarget, $ratioBackground).$tmpTag;
        }
    }
    
    my @PValueSortedMeSHTreeCodes = sort {$PValueByMeSH{$a} <=> $PValueByMeSH{$b}} @tgMeSHCodes;
    
    if ($pmidListFileStatus)
    {	print OUTPUT $outputFileHeader2;
    	open (PMIDSTRING, ">$outputDir/MeSHEnrichmentResult.pmid") || LogAnalysis("Can't create MeSHEnrichmentResult.pmid file");
    	foreach my $descID (@PValueSortedMeSHTreeCodes)
    	{	print PMIDSTRING 	$descID."\t".$MeSHCode2Desc{$descID}."\t".
								$tPlusString{$descID}."\t".$tMinusString{$descID}."\t".
								$tUniqString{$descID}."\t".$commonString{$descID}."\t".$bUniqString{$descID}."\t".
								$bPlusString{$descID}."\t".$bMinusString{$descID}."\n";
    	}
    	close PMIDSTRING;
    }else
    {	print OUTPUT $outputFileHeader;
    }
    
    foreach my $descID (@PValueSortedMeSHTreeCodes)
    {   print OUTPUT $MatrixByMeSH{$descID}."\t".$PValueByMeSH{$descID}."\n";
    }
    close (OUTPUT);
    return(1);
}





sub load_mesh_pmid_list 
{	my $PMIDFile					= shift;
	my $TreeCodePlus2PMIDsRef		= shift;
	my $TreeCodeMinus2PMIDsRef		= shift;
	
	if ((not defined $PMIDFile) || (! -f $PMIDFile))
	{	LogAnalysis("! load_mesh_pmid_list() PMIDFile does not exist...");
		return(0);
	}
	
	open (FILE, $PMIDFile) || return(0);
	while (<FILE>)
	{	my $line = $_;
		$line =~ s/\r|\n//g;
		my @tmpSplit 	= split (/\t/, $line);
		if (defined $tmpSplit[2])
		{	my @tmp2	= split (/\,/, $tmpSplit[2]);
			foreach my $pmid (@tmp2)
			{	$$TreeCodePlus2PMIDsRef{$tmpSplit[0]}->{$pmid}	= 1;
			}
		}
		if (defined $tmpSplit[3])
		{	my @tmp2	= split (/\,/, $tmpSplit[3]);
			foreach my $pmid (@tmp2)
			{	$$TreeCodeMinus2PMIDsRef{$tmpSplit[0]}->{$pmid}	= 1;
			}
		}
	}
	return(1)
}




                                              
sub load_mesh_dist_file_with_parameters_simplified
{   my $sourceFile              = shift;
    my $MeSHCode2DescRef        = shift;
    my $MeSHCodesRef            = shift;
    my $MeSHCode2FullRef        = shift;
    my $MeSHCode2PosRef         = shift;
    my $MeSHCode2NegRef         = shift;

    open (INFILE, $sourceFile) || return(-1,"No specified MeSH source file $sourceFile");
    while(<INFILE>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        if ($line !~ /^\#/)
        {   my @tmpSplit = split (/\t/, $line);
            if (not defined $$MeSHCode2DescRef{$tmpSplit[0]})
            {   $$MeSHCode2DescRef{$tmpSplit[0]}    = $tmpSplit[1];
            } 
            push @{$MeSHCodesRef}, $tmpSplit[0];
            $$MeSHCode2FullRef{$tmpSplit[0]}        = $tmpSplit[2];
            $$MeSHCode2PosRef{$tmpSplit[0]}         = $tmpSplit[3];
            $$MeSHCode2NegRef{$tmpSplit[0]}         = $tmpSplit[4];
        }
    }
    close INFILE;
    return(1,"");
}












#  -----------------------------------------------------------------------------
#  3.5 PPI_enrichment_analysis 
#  -----------------------------------------------------------------------------
sub PPI_enrichment_analysis
{   my $annoENVRef          = shift;   
    my $currentQueueEnvRef  = shift;
    my $dbh                 = shift;
    my $finalResultDir      = shift;
    my $bgNumOfGenesRef     = shift;
    my $hugoSymbol2IDRef	= shift;
    my $totalPMIDinSciMiner	= shift;
    my $tgQueryEnvRef		= shift;
    my $bgQueryEnvRef		= shift;
    
    my $humanCheck          = 1;
    
    #  Module for Fisher's exact test
    use Text::NSP::Measures::2D::Fisher::twotailed;

    
    #  Location of MiMI datafile
    my $MiMIDataDir         = "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/";
    my $MasterIntFile       = $MiMIDataDir."MASTER_INTERACTION.txt";
    my $MasterNameFile      = $MiMIDataDir."MASTER_NAME_DATA.txt";
    
    my $PPIOutputDir        = "$$annoENVRef{SciMinerPath}/Work/FinalResults/$$currentQueueEnvRef{fileNameBase}/PPI/";
    mkdir ($PPIOutputDir) || print "";
 
    my $PPIOutputWebDir     = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/PPI/";
    mkdir ($PPIOutputWebDir) || print "";   

    my %symbol2moleculeID = ();
    my %symbol2status = ();
    my %moleculeID2type = ();
    my %moleculeID2taxID = ();
    my %moleculeID2interactingPartner = ();
    my %moleculeID2interactingPartnerFull = ();
    my %moleculeID2name = ();
    my %moleculeID2dbRef = ();
    
    
    #  -------------------------------------------------------------------------
    #  Load MiMI Data Into Memory
    #  -------------------------------------------------------------------------
    my %queryResulBySymbol      = ();
            
    if ((-f $MasterIntFile) && (-s $MasterIntFile > 0))
    {   open (MASTERINT, $MasterIntFile) || return(-1, "Can't open MASTER_INTERACTION.txt file"); 
        while(<MASTERINT>)
        {   my $line = $_;
            $line =~ s/\r|\n//g;
            my @tmp = split (/\t/, $line);
            if (($humanCheck) && ($tmp[3] != 9606))
            {   #  If checked for human and the record is not a human record
                next;
            }
            
            if (not defined $queryResulBySymbol{$tmp[0]})
            {   $queryResulBySymbol{$tmp[0]} = $line."\n";
            }else
            {   $queryResulBySymbol{$tmp[0]} .= $line."\n";
            }
        }   close MASTERINT;  
    }else
    {   return(-1, "No MASTER_INTERACTION.txt file is available"); 
    }
    
    if ((-f $MasterNameFile) && (-s $MasterNameFile > 0))
    {   open (MOLECULENAME, "$MasterNameFile");
        while(<MOLECULENAME>)
        {   my $line = $_;
            $line =~ s/\r|\n//g;
            my @tmpSplit = split (/\t/, $line);
            if (not defined $tmpSplit[2])
            {   next;
            }
            if ($tmpSplit[1] eq 'name')
            {   if (not defined $moleculeID2name{$tmpSplit[0]})
                {   $moleculeID2name{$tmpSplit[0]} = $tmpSplit[2].'|';
                }else
                {   $moleculeID2name{$tmpSplit[0]} .= $tmpSplit[2].'|';
                }
            }else
            {   if (not defined $moleculeID2dbRef{$tmpSplit[0]})
                {   $moleculeID2dbRef{$tmpSplit[0]} = $tmpSplit[1].';'.$tmpSplit[2].'|';
                }else
                {   $moleculeID2dbRef{$tmpSplit[0]} .= $tmpSplit[1].';'.$tmpSplit[2].'|';
                }
            }
        }
        close MOLECULENAME;
    }else
    {   return(-1, "No MASTER_NAME_DATA.txt file is available"); 
    }



    #  -------------------------------------------------------------------------
    #  Load Gene List Into Memory
    #  -------------------------------------------------------------------------
    my %hugoID2Symbol           = ();
    my %hugoID2Name             = ();

    my @tgHugoIDs               = ();
    my @tgSymbols               = ();
    my $tgHugoIDCnt             = '';
    my $tgHugoIDCntTotal		= '';
    my %tgHugoID2Occur          = ();
    my %tgHugoID2Paper          = ();
    my %tgHugoID2PMID			= ();
   
    my @bgHugoIDs               = ();
    my @bgSymbols               = ();
    my $bgHugoIDCnt             = '';
    my $bgHugoIDCntTotal		= '';
    my %bgHugoID2Occur          = ();
    my %bgHugoID2Paper          = ();
    my %bgHugoID2PMID			= ();
    
    
    my $tgMinTopCheck		= 'true';
    my $bgMinTopCheck		= 'false';
    my $tgTotalPMID			= $$tgQueryEnvRef{'numPMID'};
    my $bgTotalPMID			= '';
    
    #  Files to be loaded
    my $tgMergedSumFile			= "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{targetQueryNumber2BaseName}/SciMinerBase.MerSum.sorted.txt";
    my $bgMergedSumFile			= "";
    my $tgBaseMiMISummaryFile	= $PPIOutputDir."TEST.MiMIBase";
    
    if ($$currentQueueEnvRef{PPISelection} eq 'Selected')
    {   #  Use selected queryfile as background
        $bgMergedSumFile	= "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{bgQueryNumber2BaseName}/SciMinerBase.MerSum.sorted.txt";
        $bgMinTopCheck		= 'true';
        $bgTotalPMID		= $$bgQueryEnvRef{'numPMID'};
    }elsif ($$currentQueueEnvRef{PPISelection} eq 'FullHUGO')
    {	$bgMergedSumFile	= "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullHUGOList";	
    	$bgMinTopCheck		= 'false';
        $bgTotalPMID		= $totalPMIDinSciMiner;

		if (! -f $bgMergedSumFile)
        {   LogAnalysis("FullHUGOList is being created");
        	open (FULLHUGO, ">$bgMergedSumFile");
            # Create such file
            my $sql         = "SELECT approvedSymbol, hgncID, approvedName FROM gene";
            my $sth         = $dbh->prepare($sql);
            $sth->execute();
            my @row         = $sth->fetchrow_array;
            while(@row = $sth->fetchrow_array)
            {   print FULLHUGO $row[0]."\t".$row[1]."\t".$row[2]."\t1\t1\tNULL\tNULL\n";
            }
            close FULLHUGO;
        }
    }else
    {   if (not defined $$annoENVRef{'miningMode'})
    	{	$bgMergedSumFile	= "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpus";	
    	}else
    	{	
    		#  These change will be overriden in the following lines. 
    		#  Currently, SciMiner only relies on FullSciMinerDBCorpus which is based on the SciMiner mining method
    		if ($$annoENVRef{'miningMode'} eq 'NCBIGeneRIF')
			{	$bgMergedSumFile	= "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBNCBIGeneRIF";
			}elsif ($$annoENVRef{'miningMode'} eq 'NCBIGene2PubMed')
			{	$bgMergedSumFile	= "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBNCBIGene2PubMed";
			}else 
			{	$bgMergedSumFile	= "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpus";	
			}
    	}
    	$bgMergedSumFile	= "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpus";
    	$bgMinTopCheck		= 'false';
        $bgTotalPMID		= $totalPMIDinSciMiner;
    }










    #  Load the targetQueryResult Gene results
    load_merged_summary_file_with_parameters ($tgMergedSumFile, \%hugoID2Symbol, $hugoSymbol2IDRef, \%hugoID2Name, 
    										 \@tgHugoIDs, \$tgHugoIDCnt, \$tgHugoIDCntTotal, \%tgHugoID2Occur, \%tgHugoID2Paper, 
    										 $tgMinTopCheck, $tgTotalPMID, $$currentQueueEnvRef{MinTopPaperTG}, $$currentQueueEnvRef{MinPaperMethodTG},
                                             \%tgHugoID2PMID, $$currentQueueEnvRef{TGListFileContent});
    #  Load the background Gene results
    load_merged_summary_file_with_parameters ($bgMergedSumFile, \%hugoID2Symbol, $hugoSymbol2IDRef, \%hugoID2Name, 
    										 \@bgHugoIDs, \$bgHugoIDCnt, \$bgHugoIDCntTotal, \%bgHugoID2Occur, \%bgHugoID2Paper,
    										 $bgMinTopCheck, $bgTotalPMID, $$currentQueueEnvRef{MinTopPaperBG}, $$currentQueueEnvRef{MinPaperMethodBG},
                                             \%bgHugoID2PMID, $$currentQueueEnvRef{BGListFileContent});

    #  Check the number of symbol (hugo ID) count. If any is zero, then return error message
    if ($tgHugoIDCnt == 0)
    {   #  This cannot be completed since one of the set has no gene
        LogAnalysis("Target set has 0 gene. Analysis aborted");
        return (-1, "Target set has 0 gene. Analysis aborted");
    }else
    {   foreach my $hugoID (@tgHugoIDs)
        {   push @tgSymbols, $hugoID2Symbol{$hugoID};
        }
    }
    
    if ($bgHugoIDCnt == 0)
    {   LogAnalysis("Background set has 0 gene. Analysis aborted");
        return (-1, "Background set has 0 gene. Analysis aborted");
    }else
    {   foreach my $hugoID (@bgHugoIDs)
        {   push @bgSymbols, $hugoID2Symbol{$hugoID};
        }
    }


    LogAnalysis("BG file is $bgMergedSumFile");
    #  Check non-overlapping hugoID in bacground corpus if they have PPI info
    my $fullOverlappingBetweenCorpus = 1;
    foreach my $tgHUGOID (@tgHugoIDs)
    {   if (defined $queryResulBySymbol{$hugoID2Symbol{$tgHUGOID}})
        {   if (not defined $bgHugoID2Occur{$tgHUGOID})
            {   #  This HUGOID is only specific to the fgCorpus
                #  There should not be any statistical test
                $fullOverlappingBetweenCorpus = 0;
                LogAnalysis("$tgHUGOID $hugoID2Symbol{$tgHUGOID} is not defined in background set\n\n\n");
                last;
            }
        }
    }





    #  -------------------------------------------------------------------------
    #  Create basic summary
    #  -------------------------------------------------------------------------
    my ($BaseStatus, $CntGeneWithInt, $CntGeneWithDirectInt, $CntTotalDirectInt, $CntMaxDegreeDirectInt) = 
    create_MiMIBase_file ($tgBaseMiMISummaryFile, \@tgSymbols, \%queryResulBySymbol, 
                          \%symbol2status, \%symbol2moleculeID, \%moleculeID2type,
                          \%moleculeID2taxID, \%moleculeID2interactingPartnerFull, 
                          \%moleculeID2interactingPartner, \%moleculeID2name, 
                          \%moleculeID2dbRef);






    #  -------------------------------------------------------------------------
    #  Statistical significance test
    #  -------------------------------------------------------------------------
    LogAnalysis("Now starting to generate random network");
    $$bgNumOfGenesRef   = scalar @bgHugoIDs;
    if ($fullOverlappingBetweenCorpus)
    {   my $statTestOutFile = $PPIOutputDir."SigTest";
        perform_randomization_ppi_MiMI (scalar (@tgHugoIDs), $CntGeneWithInt, $CntGeneWithDirectInt, $CntTotalDirectInt, $CntMaxDegreeDirectInt,                     
                                        $statTestOutFile, $tgBaseMiMISummaryFile, \@bgHugoIDs, \%hugoID2Symbol, \%queryResulBySymbol, 
                                       \%symbol2status, \%symbol2moleculeID, \%moleculeID2type,
                                       \%moleculeID2taxID, \%moleculeID2interactingPartnerFull, 
                                       \%moleculeID2interactingPartner, \%moleculeID2name, 
                                       \%moleculeID2dbRef, \%bgHugoID2Occur, 
                                       $$currentQueueEnvRef{PPISelection});
    }else
    {       LogAnalysis("Random network couldn't not be generated since background set does not fully include the target set");
    }
    

	#  Create IDcount summary file
	open (PPISUMMARY, 	">".$PPIOutputDir."PPIIDSummary");
	print PPISUMMARY	$tgTotalPMID."\t".$bgTotalPMID."\t".
    					$tgHugoIDCnt."\t".$tgHugoIDCntTotal."\t".
        		  		$bgHugoIDCnt."\t".$bgHugoIDCntTotal."\n";
    close PPISUMMARY;
    return(1);
}





sub perform_randomization_ppi_MiMI
{   my $tgTotalGeneCount                        = shift;
    my $tgCntGeneWithInt                        = shift;
    my $tgCntGeneWithDirectInt                  = shift;
    my $tgCntTotalDirectInt                     = shift;
    my $tgCntMaxDegreeDirectInt                 = shift;                           

    my $statTestOutFile                         = shift;
    
    my $MiMIBaseFile                            = shift;
    my $IDsRef                                  = shift;
    my $hugoID2SymbolRef                        = shift;
                            
    my $queryResulBySymbolRef                   = shift;
    my $symbol2statusRef                        = shift;
    my $symbol2moleculeIDRef                    = shift;
    my $moleculeID2typeRef                      = shift;
    my $moleculeID2taxIDRef                     = shift;
    my $moleculeID2interactingPartnerFullRef    = shift;
    my $moleculeID2interactingPartnerRef        = shift;
    my $moleculeID2nameRef                      = shift;
    my $moleculeID2dbRefRef                     = shift;
    
    my $bgHugoID2OccurRef                       = shift;
    my $PPISelection							= shift;

    ## TTTTTTTTTTTTTTTTTTTTTTTTT
    my $numOfRepetition                         = 100;
   
   
    #  Start to process symbol with -- Background Set
    my @querySymbol         = ();
    my %num2Symbol          = ();
    my $totalNumPaperCnt    = 0;
    my $finalOutputString   = "";


    foreach my $hugoID (@{$IDsRef})
    {   push @querySymbol, $$hugoID2SymbolRef{$hugoID};
        for (my $k=$totalNumPaperCnt; $k < $totalNumPaperCnt+$$bgHugoID2OccurRef{$hugoID}; $k++)
        {   $num2Symbol{$k} = $$hugoID2SymbolRef{$hugoID};
        }   
        $totalNumPaperCnt += $$bgHugoID2OccurRef{$hugoID};
    }
    
    LogAnalysis("Total target count is $tgTotalGeneCount and random sets are being generated.");
    
    
    for (my $i=0; $i <= $#querySymbol; $i++)
    {   #  Handle the frequency
        my @resultSplit = split (/\n/, $$queryResulBySymbolRef{$querySymbol[$i]});
        if ((defined $$queryResulBySymbolRef{$querySymbol[$i]}) && ($$queryResulBySymbolRef{$querySymbol[$i]} ne ""))
        {   $$symbol2statusRef{$querySymbol[$i]} = 'MATCH';
        }else
        {   $$symbol2statusRef{$querySymbol[$i]} = 'NOMATCH';
            next;
        }

        # Process fetched result
        foreach my $resultLine (@resultSplit)
        {   my @tmpSplit = split (/\t/, $resultLine);
            # Check and add moleculeID
            if (not defined $$symbol2moleculeIDRef{$querySymbol[$i]})
            {   $$symbol2moleculeIDRef{$querySymbol[$i]} = $tmpSplit[1].'|';
            }else
            {   if ($$symbol2moleculeIDRef{$querySymbol[$i]} =~ /\b$tmpSplit[1]\|/)
                {   # Do not add this moleculeID again
                }else
                {   # Add this new molecule ID
                    $$symbol2moleculeIDRef{$querySymbol[$i]} .= $tmpSplit[1].'|';
                }   
            }
            
            # Assign moleculeType
            $$moleculeID2typeRef{$tmpSplit[1]} = $tmpSplit[2];
            $$moleculeID2taxIDRef{$tmpSplit[1]} = $tmpSplit[3];

            # Assign interacting Partner
            my $intPartnerFull = $tmpSplit[4].';'.$tmpSplit[5].';'.$tmpSplit[6].';'.$tmpSplit[7].'|';

            # Skip if any ion partner will be ignored
            my $partnerLastChar = substr($tmpSplit[6], -1, 1);
            if (($partnerLastChar eq '+') || ($partnerLastChar eq '-'))
            {   # This will not be included to the interacting partner
                next;
            }
            if (not defined $$moleculeID2interactingPartnerFullRef{$tmpSplit[1]})
            {   $$moleculeID2interactingPartnerFullRef{$tmpSplit[1]} = $intPartnerFull;
                $$moleculeID2interactingPartnerRef{$tmpSplit[1]} = $tmpSplit[4].'|';
            }else
            {   if ($$moleculeID2interactingPartnerRef{$tmpSplit[1]} =~ /\b$tmpSplit[4]\|/)
                {   # Do not add this moleculeID again
                }else
                {   # Add this new interacting molecule ID
                    $$moleculeID2interactingPartnerRef{$tmpSplit[1]} .= $tmpSplit[4].'|';
                    $$moleculeID2interactingPartnerFullRef{$tmpSplit[1]} .= $intPartnerFull;
                }   
            }
        }
    }



    #  -------------------------------------------------------------------------
    for (my $i=0; $i < $numOfRepetition; $i++)
    {   #  Generate ramdomly selected 
        # LogAnalysis("PPI Network Randomization test $i / $numOfRepetition  $tgTotalGeneCount");
        my $numGeneSelected = 0;
        my %selectedSymbol = ();
        while()
        {   my $ranNum = int(rand($totalNumPaperCnt));
            if (not defined $selectedSymbol{$num2Symbol{$ranNum}})
            {   $selectedSymbol{$num2Symbol{$ranNum}} = 1;
                $numGeneSelected++;
                if ($numGeneSelected == $tgTotalGeneCount)
                {   last;
                }
            }
        }
        
        my @querySymbol = keys %selectedSymbol;
        
        # Generate temporary file string
        my $tmpFileName = $statTestOutFile.int(rand(10000000000));

        open (SUMMARY, ">".$tmpFileName) || LogAnalysis( "!ERROR: Can't create $tmpFileName");
        for (my $i=0; $i <= $#querySymbol; $i++)
        {   if ($$symbol2statusRef{$querySymbol[$i]} eq 'MATCH')
            {   my @molIDs = split (/\|/, $$symbol2moleculeIDRef{$querySymbol[$i]});
                for (my $j=0; $j <= $#molIDs; $j++)
                {   print SUMMARY $querySymbol[$i]."\t".$$symbol2statusRef{$querySymbol[$i]}."\t".$molIDs[$j]."\t";
                    print SUMMARY $$moleculeID2typeRef{$molIDs[$j]}."\t";
                    print SUMMARY $$moleculeID2taxIDRef{$molIDs[$j]}."\t";
                    if (defined $$moleculeID2nameRef{$molIDs[$j]})
                    {   print SUMMARY $$moleculeID2nameRef{$molIDs[$j]}."\t";
                    }else
                    {   print SUMMARY "\t";
                    }
                    if (defined $$moleculeID2dbRefRef{$molIDs[$j]})
                    {   print SUMMARY $$moleculeID2dbRefRef{$molIDs[$j]}."\t";
                    }else
                    {   print SUMMARY "\t";
                    }
                    if (defined $$moleculeID2interactingPartnerFullRef{$molIDs[$j]})
                    {   print SUMMARY $$moleculeID2interactingPartnerFullRef{$molIDs[$j]}."\n";
                    }else
                    {   print SUMMARY "\n";
                    }
                }
            }else
            {   print SUMMARY $querySymbol[$i]."\t".$$symbol2statusRef{$querySymbol[$i]}."\n";
            
            }
        }
        close SUMMARY;
    
        #  -------------------------------------------------------------------------
        #    Create Network Files
        #  -------------------------------------------------------------------------
        open (MiMI, $tmpFileName) || LogAnalysis( "! Can't open $tmpFileName");
        my (%moleculeID2ROSSymbol, %ROSSymbol2MoleculeID, %ROSSymbol2IntMolID, %ROSSymbol2IntRefID, %ROSSymbol2IntName, %ROSSymbol2Interaction, %geneWithInteraction, $directCnt);
        while(<MiMI>)
        {   my $line = $_;       $line=~ s/\r|\n//g;
            my @tmp = split (/\t/, $line);
            if (($tmp[1] ne "NOMATCH") && (defined $tmp[7]))
            {   # There are matches
                $geneWithInteraction{$tmp[0]} = 1;
                $moleculeID2ROSSymbol{$tmp[2]} = $tmp[0];
                if (defined $ROSSymbol2MoleculeID{$tmp[0]})
                {   $ROSSymbol2MoleculeID{$tmp[0]}[scalar @{$ROSSymbol2MoleculeID{$tmp[0]}}] = $tmp[2];
                }else
                {   my @tmpArray = ();      push @tmpArray, $tmp[2];
                    $ROSSymbol2MoleculeID{$tmp[0]} = \@tmpArray;
                }
                my @tmpSplit = split (/\|/, $tmp[7]);
                foreach my $tmpIntMoleculeStr (@tmpSplit)
                {   my @tmpSplit2 = split (/\;/, $tmpIntMoleculeStr);
                    if (defined $ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]})
                    {   $ROSSymbol2IntRefID{$tmp[0]}->{$tmp[2]}->[@{$ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}}] = $tmpSplit2[0];
                        $ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}->[@{$ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}}] = $tmpSplit2[1];
                        $ROSSymbol2IntName{$tmp[0]}->{$tmp[2]}->[@{$ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}}] = $tmpSplit2[2];
                    }else
                    {   my (@arr0, @arr1, @arr2);
                        push @arr0, $tmpSplit2[0];      push @arr1, $tmpSplit2[1];      push @arr2, $tmpSplit2[2];
                        $ROSSymbol2IntRefID{$tmp[0]}->{$tmp[2]} = \@arr0;
                        $ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]} = \@arr1;
                        $ROSSymbol2IntName{$tmp[0]}->{$tmp[2]} = \@arr2;
                    }
                }
            }
        }   close MiMI;


        # ------------------------------------------------------------------------------------------------------------------------
        my @Symbols             = sort (keys %ROSSymbol2MoleculeID);
        my $networkFileName     = $tmpFileName.'_Network.sif';
        my $networkSummaryName  = $tmpFileName.'_Network.txt';
        my %directCountCheck    = ();
        my %intPair             = ();
        my %degreeCount         = ();
        
        open (OUT, ">$networkFileName") || LogAnalysis( "! Can't create $networkFileName"); 
        foreach my $symbol (@Symbols)
        {   foreach my $molID (@{$ROSSymbol2MoleculeID{$symbol}})
            {   for (my $i=0; $i < @{$ROSSymbol2IntMolID{$symbol}->{$molID}}; $i++)
                {   if (defined $moleculeID2ROSSymbol{@{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i]})
                    {   my $secondSymbol = $moleculeID2ROSSymbol{@{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i]};
                        if ( $symbol ne $secondSymbol)
                        {   my $tmpCandidate        = $symbol."\tpp\t".$secondSymbol;
                            my $reverseCandidate    = $secondSymbol."\tpp\t".$symbol;
                            if (not defined $directCountCheck{$tmpCandidate})
                            {   print OUT $tmpCandidate."\n";
                                $intPair{$symbol}->{$secondSymbol} = 1;
                                $intPair{$secondSymbol}->{$symbol} = 1;
                                $directCountCheck{$tmpCandidate} = 1;
                                $directCountCheck{$reverseCandidate} = 1;                                
                                
                                $directCnt++;
                                if (defined $degreeCount{$symbol})
                                {   $degreeCount{$symbol}++;
                                }else
                                {   $degreeCount{$symbol} = 1;
                                }
                            
                                if (defined $degreeCount{$secondSymbol})
                                {   $degreeCount{$secondSymbol}++;
                                }else
                                {   $degreeCount{$secondSymbol} = 1;
                                }
                            }
                        }
                    }
                }
            }
        }   
        close OUT;

        my $interactionPairCount = scalar (keys %intPair);
        my @geneWithInteractionArray = keys %geneWithInteraction;
        my @sortedDegreeCountKey = sort {$degreeCount{$b} <=> $degreeCount{$a}}  keys %degreeCount;
                
        if ($interactionPairCount == 0)
        {   # There is no interaction within the given gene set
            $finalOutputString .=   ($#geneWithInteractionArray+1)."\t".
                                    "0\t0\t\t0\t\t0\n";
        }else
        {   $finalOutputString .= ($#geneWithInteractionArray+1)."\t".
                              ($#sortedDegreeCountKey +1)."\t".
                              $directCnt."\t".
                              $sortedDegreeCountKey[0]."\t".$degreeCount{$sortedDegreeCountKey[0]}."\t".
                              $sortedDegreeCountKey[$#sortedDegreeCountKey]."\t".$degreeCount{$sortedDegreeCountKey[$#sortedDegreeCountKey]}."\n";
        }
        
        unlink($tmpFileName);
        unlink($tmpFileName.'_Network.sif');
        unlink($tmpFileName.'_Network.txt');
    }

    #  Print result file
    open (RANDOMRESULT, ">".$statTestOutFile);
    print RANDOMRESULT $finalOutputString;
    close RANDOMRESULT;
    
    # Now, calculate Z-score and T-statistics in R
    my $tmpRandNum = int(rand(10000000));
    my $tmpCMDFile = $statTestOutFile.$tmpRandNum.'.cmd';
    my $tmpREFFile  = $statTestOutFile.$tmpRandNum.'.ref';
    open (TMPREF, ">".$tmpREFFile);
    print TMPREF $tgCntGeneWithInt."\t".$tgCntGeneWithDirectInt."\t".$tgCntTotalDirectInt."\t".$tgCntMaxDegreeDirectInt;
    close TMPREF;
    
    my $tmpOutputFile = $statTestOutFile.'.ZTStat.txt';
    my $cmdString = "randDataOriginal = read.table (\"$statTestOutFile\", header=FALSE, sep=\"\\t\")\n
                     randData = randDataOriginal[,c(1,2,3,5)]
                     rosRef = read.table (\"$tmpREFFile\", header=FALSE, sep=\"\\t\")
                     averData = mean (randData)
                     stdevData = sd (randData)
                     ZScoreData = (rosRef-averData)/stdevData
                     ZScorePvalue = c()
                     Titles	= c(\"Number of targets with any interaction\", \"Targets interacting within corpus\", \"Direct interactions within corpus\", \"Maximum degree of interactions\")
                     XAxis	= c(\"Number of targets\", \"Number of targets\", \"Number of direct interactions\", \"Maximum degree\")
                    for (i in 1:4)
                    {   ZScorePvalue = c(ZScorePvalue, 1-pnorm(ZScoreData[1,i], mean=0, sd=1))
                    }
                    AdjustedStdev = stdevData/sqrt($numOfRepetition)
                    TTestStatistic = c()
                    TTestPvalue = c()
                    library(MASS)
                    if(dev.cur() == 1) dev.new() #get(getOption(\"device\"))()
                    
#                    devlist = dev.list()
#                    write(devlist, file=\"/tmp/devices\", sep=\"\t\")
                    for (i in 1:4)
                    {   tResult = t.test(randData[,i], mu=rosRef[1,i])
                    	colMax		= max (randData[,i], rosRef[1,i])
						colMin		= min (randData[,i], rosRef[1,i])
                        TTestStatistic  = c(TTestStatistic, tResult\$statistic)
                        TTestPvalue = c(TTestPvalue , tResult\$p.value)
                        #outFileName = paste(\"/tmp/ttt\", \".\", i, \".jpg\", sep=\"\")
                        outFileNamePS = paste(\"$statTestOutFile\", \".\", i, \".ps\", sep=\"\")
#                        outFileNameJPG = paste(\"$statTestOutFile\", \".\", i, \".jpg\", sep=\"\")
                        postscript(file=outFileNamePS, title=\"Iterated random sets\", bg=\"white\", width=480, height=480, horizontal=FALSE)
                        #jpeg(filename=outFileName, width=480, height=480, pointsize=12, bg=\"white\")
                        truehist(randData[,i], nbins=\"FD\", prob=TRUE, main = Titles[i], xlim = c((colMin - 2), (colMax + 2)), xlab=XAxis[i], ylab=\"Proportion of random sets\")
                        abline(v=rosRef[1,i], col=\"red\", lwd=5)
                        dev.off()
                    }
                    write(c(as.matrix(rosRef), as.matrix(averData), as.matrix(stdevData), as.matrix(ZScoreData), as.matrix(ZScorePvalue), as.matrix(TTestStatistic), as.matrix(TTestPvalue)),  file=\"$tmpOutputFile\", ncol=4, sep=\"\\t\")";

    open (TMPCMD, ">".$tmpCMDFile);
    print TMPCMD $cmdString;
    close (TMPCMD);
    
    `R --no-restore --no-save --silent < $tmpCMDFile`;

    if (-f "$statTestOutFile.1.ps")
    {   `convert $statTestOutFile.1.ps $statTestOutFile.1.jpg`;
    }
    if (-f "$statTestOutFile.2.ps")
    {   `convert $statTestOutFile.2.ps $statTestOutFile.2.jpg`;
    }
    if (-f "$statTestOutFile.3.ps")
    {   `convert $statTestOutFile.3.ps $statTestOutFile.3.jpg`;
    }
    if (-f "$statTestOutFile.4.ps")
    {   `convert $statTestOutFile.4.ps $statTestOutFile.4.jpg`;
    }
 
    # ($tmpCMDFile);
    open (RESULT, $tmpOutputFile);
    my @content = <RESULT>;
    print @content;
    close (RESULT);

    # unlink ($tmpREFFile);

    
}





sub create_MiMIBase_file
{   my $MiMIBaseFile                            = shift;
    my $symbolsRef                              = shift;
    my $queryResulBySymbolRef                   = shift;
    my $symbol2statusRef                        = shift;
    my $symbol2moleculeIDRef                    = shift;
    my $moleculeID2typeRef                      = shift;
    my $moleculeID2taxIDRef                     = shift;
    my $moleculeID2interactingPartnerFullRef    = shift;
    my $moleculeID2interactingPartnerRef        = shift;
    my $moleculeID2nameRef                      = shift;
    my $moleculeID2dbRefRef                     = shift;
        
    
     
    my $CntGeneWithInt                          = 0;
    my $CntGeneWithDirectInt                    = 0;
    my $CntTotalDirectInt                       = 0;
    my $CntMaxDegreeDirectInt                   = 0;
    
 
    

    #  Start to process symbol with MiMIBase
    my @querySymbol = @{$symbolsRef};
    LogAnalysis("Start to generate direct within network...");
    for (my $i=0; $i <= $#querySymbol; $i++)
    {   if ((defined $$queryResulBySymbolRef{$querySymbol[$i]}) && ($$queryResulBySymbolRef{$querySymbol[$i]} ne ""))
        {   $$symbol2statusRef{$querySymbol[$i]} = 'MATCH';
        }else
        {   $$symbol2statusRef{$querySymbol[$i]} = 'NOMATCH';
            next;
        }

        # Process fetched result
        my @resultSplit = split (/\n/, $$queryResulBySymbolRef{$querySymbol[$i]});
        foreach my $resultLine (@resultSplit)
        {   my @tmpSplit = split (/\t/, $resultLine);
            # Check and add moleculeID
            if (not defined $$symbol2moleculeIDRef{$querySymbol[$i]})
            {   $$symbol2moleculeIDRef{$querySymbol[$i]} = $tmpSplit[1].'|';
            }else
            {   if ($$symbol2moleculeIDRef{$querySymbol[$i]} =~ /\b$tmpSplit[1]\|/)
                {   # Do not add this moleculeID again
                }else
                {   # Add this new molecule ID
                    $$symbol2moleculeIDRef{$querySymbol[$i]} .= $tmpSplit[1].'|';
                }   
            }
            
            # Assign moleculeType
            $$moleculeID2typeRef{$tmpSplit[1]} = $tmpSplit[2];
            $$moleculeID2taxIDRef{$tmpSplit[1]} = $tmpSplit[3];

            # Assign interacting Partner
            my $intPartnerFull = $tmpSplit[4].';'.$tmpSplit[5].';'.$tmpSplit[6].';'.$tmpSplit[7].'|';

            # Skip if any ion partner will be ignored
            my $partnerLastChar = substr($tmpSplit[6], -1, 1);
            if (($partnerLastChar eq '+') || ($partnerLastChar eq '-'))
            {   # This will not be included to the interacting partner
                next;
            }
            if (not defined $$moleculeID2interactingPartnerFullRef{$tmpSplit[1]})
            {   $$moleculeID2interactingPartnerFullRef{$tmpSplit[1]} = $intPartnerFull;
                $$moleculeID2interactingPartnerRef{$tmpSplit[1]} = $tmpSplit[4].'|';
            }else
            {   if ($$moleculeID2interactingPartnerRef{$tmpSplit[1]} =~ /\b$tmpSplit[4]\|/)
                {   # Do not add this moleculeID again
                }else
                {   # Add this new interacting molecule ID
                    $$moleculeID2interactingPartnerRef{$tmpSplit[1]} .= $tmpSplit[4].'|';
                    $$moleculeID2interactingPartnerFullRef{$tmpSplit[1]} .= $intPartnerFull;
                }   
            }
        }
    }


    # Print out the final result
    open (SUMMARY, ">".$MiMIBaseFile) || LogAnalysis( "!ERROR: Can't create $MiMIBaseFile");
    for (my $i=0; $i <= $#querySymbol; $i++)
    {   if ($$symbol2statusRef{$querySymbol[$i]} eq 'MATCH')
        {   my @molIDs = split (/\|/, $$symbol2moleculeIDRef{$querySymbol[$i]});
            for (my $j=0; $j <= $#molIDs; $j++)
            {   print SUMMARY $querySymbol[$i]."\t".$$symbol2statusRef{$querySymbol[$i]}."\t".$molIDs[$j]."\t";
                print SUMMARY $$moleculeID2typeRef{$molIDs[$j]}."\t";
                print SUMMARY $$moleculeID2taxIDRef{$molIDs[$j]}."\t";
                if (defined $$moleculeID2nameRef{$molIDs[$j]})
                {   print SUMMARY $$moleculeID2nameRef{$molIDs[$j]}."\t";
                }else
                {   print SUMMARY "\t";
                }
                if (defined $$moleculeID2dbRefRef{$molIDs[$j]})
                {   print SUMMARY $$moleculeID2dbRefRef{$molIDs[$j]}."\t";
                }else
                {   print SUMMARY "\t";
                }
                if (defined $$moleculeID2interactingPartnerFullRef{$molIDs[$j]})
                {   print SUMMARY $$moleculeID2interactingPartnerFullRef{$molIDs[$j]}."\n";
                }else
                {   print SUMMARY "\n";
                }
            }
        }else
        {   print SUMMARY $querySymbol[$i]."\t".$$symbol2statusRef{$querySymbol[$i]}."\n";
        
        }
    }

    close SUMMARY;


    
    
    #  -------------------------------------------------------------------------
    #    Create Network Files
    #  -------------------------------------------------------------------------
    open (MiMI, $MiMIBaseFile) || LogAnalysis( "! Can't open $MiMIBaseFile");
    my (%moleculeID2ROSSymbol, %ROSSymbol2MoleculeID, %ROSSymbol2IntMolID, %ROSSymbol2IntRefID, %ROSSymbol2IntName, %ROSSymbol2Interaction, %geneWithInteraction, $directCnt);
    while(<MiMI>)
    {   my $line = $_;       $line=~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        if (($tmp[1] ne "NOMATCH") && (defined $tmp[7]))
        {   # There are matches
            $geneWithInteraction{$tmp[0]} = 1;
            $moleculeID2ROSSymbol{$tmp[2]} = $tmp[0];
            if (defined $ROSSymbol2MoleculeID{$tmp[0]})
            {   $ROSSymbol2MoleculeID{$tmp[0]}[scalar @{$ROSSymbol2MoleculeID{$tmp[0]}}] = $tmp[2];
            }else
            {   my @tmpArray = ();      push @tmpArray, $tmp[2];
                $ROSSymbol2MoleculeID{$tmp[0]} = \@tmpArray;
            }
            my @tmpSplit = split (/\|/, $tmp[7]);
            foreach my $tmpIntMoleculeStr (@tmpSplit)
            {   my @tmpSplit2 = split (/\;/, $tmpIntMoleculeStr);
                if (defined $ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]})
                {   $ROSSymbol2IntRefID{$tmp[0]}->{$tmp[2]}->[@{$ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}}] = $tmpSplit2[0];
                    $ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}->[@{$ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}}] = $tmpSplit2[1];
                    $ROSSymbol2IntName{$tmp[0]}->{$tmp[2]}->[@{$ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}}] = $tmpSplit2[2];
                }else
                {   my (@arr0, @arr1, @arr2);
                    push @arr0, $tmpSplit2[0];      push @arr1, $tmpSplit2[1];      push @arr2, $tmpSplit2[2];
                    $ROSSymbol2IntRefID{$tmp[0]}->{$tmp[2]} = \@arr0;
                    $ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]} = \@arr1;
                    $ROSSymbol2IntName{$tmp[0]}->{$tmp[2]} = \@arr2;
                }
            }
        }
    }   close MiMI;





    # ------------------------------------------------------------------------------------------------------------------------
    my @Symbols             = sort (keys %ROSSymbol2MoleculeID);
    my $networkFileName     = $MiMIBaseFile.'_Network.sif';
    my $networkSummaryName  = $MiMIBaseFile.'_Network.txt';
    my %directCountCheck    = ();
    my %intPair             = ();
    my %degreeCount         = ();
    
    
    open (OUT, ">$networkFileName") || LogAnalysis( "! Can't create $networkFileName"); 
    foreach my $symbol (@Symbols)
    {   foreach my $molID (@{$ROSSymbol2MoleculeID{$symbol}})
        {   for (my $i=0; $i < @{$ROSSymbol2IntMolID{$symbol}->{$molID}}; $i++)
            {   if (defined $moleculeID2ROSSymbol{@{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i]})
                {   my $secondSymbol = $moleculeID2ROSSymbol{@{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i]};
                    if ( $symbol ne $secondSymbol)
                    {   my $tmpCandidate        = $symbol."\tpp\t".$secondSymbol;
                        my $reverseCandidate    = $secondSymbol."\tpp\t".$symbol;
                        if (not defined $directCountCheck{$tmpCandidate})
                        {   print OUT $tmpCandidate."\n";
                            $intPair{$symbol}->{$secondSymbol} = 1;
                            $intPair{$secondSymbol}->{$symbol} = 1;
                            $directCountCheck{$tmpCandidate} = 1;
                            $directCountCheck{$reverseCandidate} = 1;
                            $directCnt++;
                            if (defined $degreeCount{$symbol})
                            {   $degreeCount{$symbol}++;
                            }else
                            {   $degreeCount{$symbol} = 1;
                            }
                        
                            if (defined $degreeCount{$secondSymbol})
                            {   $degreeCount{$secondSymbol}++;
                            }else
                            {   $degreeCount{$secondSymbol} = 1;
                            }
                        }
                    }
                }
            }
        }
    }   
    close OUT;
  	
  	
  	
  	
  	
  	my $interactionPairCount = scalar (keys %intPair);
    my @geneWithInteractionArray = keys %geneWithInteraction;
    my @sortedDegreeCountKey = sort {$degreeCount{$b} <=> $degreeCount{$a}}  keys %degreeCount;
            
    if ($interactionPairCount == 0)
    {   # There is no interaction within the given gene set
        return(-1, "! There is no interaction in the given gene set");
    }
    
    
    open (OUT, ">$networkSummaryName") || LogAnalysis( "! Can't create $networkSummaryName"); 

    my $headerString =     
        "#Genes_With_Any_Interaction\t".($#geneWithInteractionArray+1)."\n".
        "#Genes_With_Interaction_Within_Set\t".($#sortedDegreeCountKey +1)."\n".
        "#Interactions_Within_Set\t".$directCnt."\n".
        "#Max_Degree\t$sortedDegreeCountKey[0]\t$degreeCount{$sortedDegreeCountKey[0]}\n".
        "#Min_Degree\t$sortedDegreeCountKey[$#sortedDegreeCountKey]\t$degreeCount{$sortedDegreeCountKey[$#sortedDegreeCountKey]}\n";
    print OUT $headerString;

    foreach (@sortedDegreeCountKey)
    {   print OUT $_."\t".$degreeCount{$_}."\n";
    }   close OUT;





    #  -------------------------------------------------------------------------
    #   Assigning return values
    #  -------------------------------------------------------------------------
    $CntGeneWithInt                             = $#geneWithInteractionArray+1;
    $CntGeneWithDirectInt                       = $#sortedDegreeCountKey +1;
    $CntTotalDirectInt                          = $directCnt;
    $CntMaxDegreeDirectInt                      = $degreeCount{$sortedDegreeCountKey[0]};


    #  -------------------------------------------------------------------------
    #
    #  Create extended network .................................................
    #  
    #  -------------------------------------------------------------------------


    
    %moleculeID2ROSSymbol   = ();
    %ROSSymbol2MoleculeID   = ();
    %ROSSymbol2IntMolID     = ();
    %ROSSymbol2IntRefID     = ();
    %ROSSymbol2IntName      = ();
    %ROSSymbol2Interaction  = ();
    %geneWithInteraction    = ();
    %intPair                = ();
    %degreeCount            = ();
    $directCnt              = 0;
    
    
    my (%moleculeID2MoleculeType, %molBID2Name, %molBID2molAID, %molID2refID, %molID2refName, , $indirectCnt, %geneDirectInteraction, %geneInDirectInteraction);

    LogAnalysis("Start to generate INDIRECT within network...");
    open (MiMI, $MiMIBaseFile) || LogAnalysis( "! Can't open $MiMIBaseFile");
    while(<MiMI>)
    {   my $line = $_;       
        $line=~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        if (($tmp[1] ne "NOMATCH") && (defined $tmp[7]))
        {   # There are matches
            # Check organism
            #if ($speciesCheck)
            #{   if (not defined $taxonCheck{$tmp[4]})
            #    {   # just move to the next entry
            #        next;
            #    }
            #}
            
            $geneWithInteraction{$tmp[0]} = 1;
            $moleculeID2ROSSymbol{$tmp[2]} = $tmp[0];
            $moleculeID2MoleculeType{$tmp[2]} = $tmp[3];
            if (defined $ROSSymbol2MoleculeID{$tmp[0]})
            {   $ROSSymbol2MoleculeID{$tmp[0]}[@{$ROSSymbol2MoleculeID{$tmp[0]}}] = $tmp[2];
            }else
            {   my @tmpArray = ();      push @tmpArray, $tmp[2];
                $ROSSymbol2MoleculeID{$tmp[0]} = \@tmpArray;
            }
            
            my @tmpSplit = split (/\|/, $tmp[7]);
            foreach my $tmpIntMoleculeStr ( @tmpSplit)
            {   my @tmpSplit2 = split (/\;/, $tmpIntMoleculeStr);
                $molID2refID{$tmpSplit2[1]} = $tmpSplit2[0];
                $molID2refName{$tmpSplit2[1]} = $tmpSplit2[2];
                if (defined $ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]})
                {   $ROSSymbol2IntRefID{$tmp[0]}->{$tmp[2]}->[@{$ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}}] = $tmpSplit2[0];
                    $ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}->[@{$ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}}] = $tmpSplit2[1];
                    $ROSSymbol2IntName{$tmp[0]}->{$tmp[2]}->[@{$ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]}}] = $tmpSplit2[2];
                }else
                {   my (@arr0, @arr1, @arr2);
                    push @arr0, $tmpSplit2[0];      push @arr1, $tmpSplit2[1];      push @arr2, $tmpSplit2[2];
                    $ROSSymbol2IntRefID{$tmp[0]}->{$tmp[2]} = \@arr0;
                    $ROSSymbol2IntMolID{$tmp[0]}->{$tmp[2]} = \@arr1;
                    $ROSSymbol2IntName{$tmp[0]}->{$tmp[2]} = \@arr2;
                }

                if (defined $molBID2Name{$tmpSplit2[1]})
                {   # check if any duplicate
                    my $dupCheckPass = 1;
                    foreach (@{$molBID2molAID{$tmpSplit2[1]}})
                    {   if ($_ eq $tmp[2])
                        {   $dupCheckPass = 0;
                            last;
                        }
                    }
                    if ($dupCheckPass)
                    {   $molBID2molAID{$tmpSplit2[1]}->[@{$molBID2molAID{$tmpSplit2[1]}}] = $tmp[2];
                    }
                }else
                {   $molBID2Name{$tmpSplit2[1]} = $tmpSplit2[2];
                    my @arr3 = ();
                    push @arr3, $tmp[2];
                    $molBID2molAID{$tmpSplit2[1]} = \@arr3;
                }
            }
        }
    }   close MiMI;





    # -----------------------------------------------------------------------------
    @Symbols = sort (keys %ROSSymbol2MoleculeID);
    $networkFileName = $MiMIBaseFile.'_ExtNetwork.sif';
    $networkSummaryName = $MiMIBaseFile.'_ExtNetwork_Summary.txt';
    my $indirectOnlyFileName = $MiMIBaseFile.'_ExtNetwork_InDirect_List.txt';

    open (OUT, ">$networkFileName") || die "! Can't write to $networkFileName\n\n";
    open (EXTOUT, ">$networkFileName.indirect.whole") || die "! Can't write to $networkFileName.indirect\n\n";
    open (EXTOUT2, ">$networkFileName.indirect.whole2") || die "! Can't write to $networkFileName.indirect\n\n";
    my %indirectIntPair = ();
    foreach my $symbol (@Symbols)
    {   foreach my $molID (@{$ROSSymbol2MoleculeID{$symbol}})
        {   for (my $i=0; $i < @{$ROSSymbol2IntMolID{$symbol}->{$molID}}; $i++)
            {   if (defined $moleculeID2ROSSymbol{@{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i]})
                {   if ( $symbol ne $moleculeID2ROSSymbol{@{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i]})
                    {   print OUT $symbol."\t".$moleculeID2MoleculeType{$molID}.'_'.
                                  $moleculeID2MoleculeType{@{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i]}."\t".
                                  $moleculeID2ROSSymbol{@{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i]}."\n";
                        $indirectIntPair{$symbol}{$moleculeID2ROSSymbol{@{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i]}} = 1;
                        $indirectIntPair{$moleculeID2ROSSymbol{@{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i]}}{$symbol} = 1;
                    }
                }else
                {   # For any molecule ID that does not have direct connection to input proteins
                    # Check if there is secondary interaction
                    my @tmpMolBIDArray = @{$molBID2molAID{@{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i]}};
                    foreach my $molAID (@tmpMolBIDArray)
                    {   if ((defined $moleculeID2ROSSymbol{$molAID}) &&
                            ($symbol ne $moleculeID2ROSSymbol{$molAID}))
                        {   # There is indirect interaction between molA and molB
                            if (not defined $indirectIntPair{$symbol}{$moleculeID2ROSSymbol{$molAID}})
                            {   $indirectIntPair{$symbol}{$moleculeID2ROSSymbol{$molAID}} = 1;
                                $indirectIntPair{$moleculeID2ROSSymbol{$molAID}}{$symbol} = 1;
                                print OUT $symbol."\tindirect\t".$moleculeID2ROSSymbol{$molAID}."\n";
                                my $tmpMolID = @{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i];
                                print EXTOUT $symbol."\tindirect\t".$moleculeID2ROSSymbol{$molAID}."\t".
                                      $molID2refID{$tmpMolID}."\t".$tmpMolID."\t".$molID2refName{$tmpMolID}."\n";
                                print EXTOUT2 $symbol."\tindirect\t".$moleculeID2ROSSymbol{$molAID}."\t".
                                      $molID2refID{$tmpMolID}."\t".$tmpMolID."\t".$molID2refName{$tmpMolID}."\n";
                            }else
                            {   my $tmpMolID = @{$ROSSymbol2IntMolID{$symbol}->{$molID}}[$i];
                                print EXTOUT2 $symbol."\tindirect\t".$moleculeID2ROSSymbol{$molAID}."\t".
                                      $molID2refID{$tmpMolID}."\t".$tmpMolID."\t".$molID2refName{$tmpMolID}."\n";
                            }
                        }
                    }
                }
            }
        }
    }   close OUT;   close EXTOUT;    close EXTOUT2;

    # -----------------------------------------------------------------------------

    open (OUT, ">$networkSummaryName") || die "! Can't write to $networkSummaryName\n\n";

    # Checking direct interaction
    open (FILE, $networkFileName);
    while(<FILE>)
    {   my $line= $_;       $line=~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        if ($tmp[1] eq 'indirect')
        {   next;
        }
        if (defined $intPair{$tmp[0]}{$tmp[2]})
        {   # Do not count
        }else
        {   $intPair{$tmp[0]}{$tmp[2]} = 1;
            $intPair{$tmp[2]}{$tmp[0]} = 1;
            $geneDirectInteraction{$tmp[0]} = 1;
            $geneDirectInteraction{$tmp[2]} = 1;
            if (defined $degreeCount{$tmp[0]})
            {   $degreeCount{$tmp[0]}++;
            }else
            {   $degreeCount{$tmp[0]} = 1;
            }
        
            if (defined $degreeCount{$tmp[2]})
            {   $degreeCount{$tmp[2]}++;
            }else
            {   $degreeCount{$tmp[2]} = 1;
            }
            $directCnt++;
        }
    }   close FILE;
    # Checking indirect interaction
    open (FILE, $networkFileName);
    while(<FILE>)
    {   my $line= $_;       $line=~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        if ($tmp[1] ne 'indirect')
        {   next;
        }
        if (defined $intPair{$tmp[0]}{$tmp[2]})
        {   # Do not count
        }else
        {   $intPair{$tmp[0]}{$tmp[2]} = 1;
            $intPair{$tmp[2]}{$tmp[0]} = 1;
            $geneInDirectInteraction{$tmp[0]} = 1;
            $geneInDirectInteraction{$tmp[2]} = 1;
            if (defined $degreeCount{$tmp[0]})
            {   $degreeCount{$tmp[0]}++;
            }else
            {   $degreeCount{$tmp[0]} = 1;
            }
            if (defined $degreeCount{$tmp[2]})
            {   $degreeCount{$tmp[2]}++;
            }else
            {   $degreeCount{$tmp[2]} = 1;
            }
            $indirectCnt++;
        }
    }   close FILE;

    @geneWithInteractionArray = keys %geneWithInteraction;
    my @GeneDirectInteraction = keys %geneDirectInteraction;
    my @GeneInDirectInteraction = keys %geneInDirectInteraction;
    @sortedDegreeCountKey = sort {$degreeCount{$b} <=> $degreeCount{$a}}  keys %degreeCount;
    my $geneCntOnlyIndirect = 0;
    
    open (INDIRECTONLY, ">".$indirectOnlyFileName);
    foreach (@GeneInDirectInteraction)
    {   if (not defined $geneDirectInteraction{$_})
        {   $geneCntOnlyIndirect++;
            print INDIRECTONLY $_."\n";
        }
    }
    $headerString =    
        "#Genes_With_Any_Interaction\t".($#geneWithInteractionArray+1)."\n".
        "#Total_Nodes\t".($#sortedDegreeCountKey +1)."\n".
        "#Direct_Interaction\t".($directCnt/2)."\n".
        "#Genes_Direct_Interaction\t".($#GeneDirectInteraction+1)."\n".
        "#Indirect_Interaction\t$indirectCnt\n".
        "#Genes_Indirect_Interaction\t".($#GeneInDirectInteraction+1)."\n".
        "#Genes_ONLY_InDirect\t$geneCntOnlyIndirect\n".
        "#Max_Degree\t$sortedDegreeCountKey[0]\t$degreeCount{$sortedDegreeCountKey[0]}\n".
        "#Min_Degree\t$sortedDegreeCountKey[$#sortedDegreeCountKey]\t$degreeCount{$sortedDegreeCountKey[$#sortedDegreeCountKey]}\n";
    print $headerString;
    print OUT $headerString;
    foreach (@sortedDegreeCountKey)
    {   print OUT $_."\t".$degreeCount{$_}."\n";
    }   close OUT;

    print "\n! Process completed...\n\n";


    open (INDLIST, $indirectOnlyFileName);
    open (INDIRECT, "$networkFileName.indirect.whole") || die "! Can't write to $networkFileName.indirect\n\n";
    open (INDIRECTONLY, ">$networkFileName.indirect.only") || die "! Can't write to $networkFileName.only\n\n";
    my %inDirectOnlyCheck = ();
    while(<INDLIST>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        $inDirectOnlyCheck{$tmp[0]} = 1;
    }   close INDLIST;

    while(<INDIRECT>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        if (((defined $inDirectOnlyCheck{$tmp[0]}) && ($inDirectOnlyCheck{$tmp[0]})) ||
            ((defined $inDirectOnlyCheck{$tmp[2]}) && ($inDirectOnlyCheck{$tmp[2]})))
        {   print INDIRECTONLY $line."\n";
        }
    }   close INDIRECT;


    open (INDIRECTONLY, $networkFileName.".indirect.only") || die "! Can't load $networkFileName.indirect.only\n\n";
    open (INDIRECTONLYSIMPLE, ">".$networkFileName.".indirect.only.simple") || die "! Can't write to $networkFileName.only.simple\n\n";
    my %intMolIDCnt = ();
    while(<INDIRECTONLY>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        if (defined $intMolIDCnt{$tmp[4]})
        {   $intMolIDCnt{$tmp[4]}++;
        }else
        {   $intMolIDCnt{$tmp[4]} = 1;
        }
    }   close INDIRECTONLY;

    my @sortedKeys = sort {$intMolIDCnt{$b} <=> $intMolIDCnt{$a}} keys %intMolIDCnt;
    foreach (@sortedKeys)
    {   print INDIRECTONLYSIMPLE $molID2refID{$_}."\t".$_."\t".$molID2refName{$_}."\t".
              $intMolIDCnt{$_}."\n";
    }   close INDIRECTONLYSIMPLE;



    open (INDIRECT, "$networkFileName.indirect.whole2") || die "! Can't write to $networkFileName.indirect\n\n";
    open (SIMPLE, ">$networkFileName.indirect.whole2.simple");
    my (%intMolID2RefID, %intMolID2Name, %intermediatCnt);
    while(<INDIRECT>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        $intMolID2RefID{$tmp[4]} = $tmp[3];
        $intMolID2Name{$tmp[4]} = $tmp[5];
        if (not defined $moleculeID2ROSSymbol{$tmp[4]})
        {   if (not defined $intermediatCnt{$tmp[4]})
            {   $intermediatCnt{$tmp[4]} = 1;
            }else
            {   $intermediatCnt{$tmp[4]}++;
            }
        }
    }   close INDIRECT;

    my @sortedKeysByCnt = sort {$intermediatCnt{$b} <=> $intermediatCnt{$a}} keys %intermediatCnt;
    foreach (@sortedKeysByCnt)
    {   print SIMPLE $intMolID2RefID{$_}."\t".$_."\t".$intMolID2Name{$_}."\t".$intermediatCnt{$_}."\n";
    }   close SIMPLE;

    
    
    
    
    
    #  Return result with direct interaction count
    return (1, $CntGeneWithInt, $CntGeneWithDirectInt, $CntTotalDirectInt, $CntMaxDegreeDirectInt);
    
}




















#  -----------------------------------------------------------------------------
#  3-4. Pathway_enrichment_analysis
#  -----------------------------------------------------------------------------
sub Pathway_enrichment_analysis
{   my $annoENVRef          		= shift;   
    my $currentQueueEnvRef  		= shift;
    my $dbh                 		= shift;
    my $finalResultDir      		= shift;
    my $finalResultWebDir			= shift;
    my $hugoSymbol2IDRef 			= shift;	
    my $totalPMIDinSciMiner			= shift;
    my $tgQueryEnvRef				= shift;
    my $bgQueryEnvRef				= shift;
    my $symbol2ncbiEntrezGeneIDRef	= shift;    
    
    #  First, Load the gene set files
    #  Initialize
    my %hugoID2Symbol       = ();
    my %hugoID2Name         = ();

    my @tgHugoIDs           = ();
    my $tgHugoIDCnt         = '';
    my $tgHugoIDCntTotal	= 0;
    my %tgHugoID2Occur      = ();
    my %tgHugoID2Paper      = ();
    my %tgHugoID2PMID		= ();
    
    my @bgHugoIDs           = ();
    my $bgHugoIDCnt         = '';
    my $bgHugoIDCntTotal	= 0;
    my %bgHugoID2Occur      = ();
    my %bgHugoID2Paper      = ();
    my %bgHugoID2PMID		= ();
    
    my $tgMinTopCheck		= 'true';
    my $bgMinTopCheck		= 'false';
    my $tgTotalPMID			= $$tgQueryEnvRef{'numPMID'};
    my $bgTotalPMID			= '';
    
    my $compStatus			= 1;
    
    #  Directories and Files to be used
    my $pathwayOutputDir         = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/Pathway/";
    mkdir ($pathwayOutputDir) || print "";
    
    my $pathwayWebOutputDir      = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/Pathway/";
    mkdir ($pathwayWebOutputDir) || print "";
    
    my $tgMergedSumFile     = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{targetQueryNumber2BaseName}/SciMinerBase.MerSum.sorted.txt";
    my $bgMergedSumFile     = "";

    my $tgPathwayFile            = $pathwayOutputDir."TEST.Pathway.txt";
    my $bgPathwayFile            = "";
    
    if ($$currentQueueEnvRef{PathwayEnrichmentSelection} eq 'Selected')
    {   #  Use selected queryfile as background
        $bgMergedSumFile    = "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{bgQueryNumber2BaseName}/SciMinerBase.MerSum.sorted.txt";
        $bgPathwayFile      = $pathwayOutputDir."BACKGROUND.Pathway.txt";
        $bgMinTopCheck		= 'true';
        $bgTotalPMID		= $$bgQueryEnvRef{'numPMID'};
    }elsif ($$currentQueueEnvRef{PathwayEnrichmentSelection} eq 'Whole')
    {   $bgMergedSumFile    = "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpus";
        $bgPathwayFile      = "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpus.Pathway";
        $bgMinTopCheck		= 'true';
        $bgTotalPMID		= $totalPMIDinSciMiner; 
        $compStatus			= 0;       
    }elsif ($$currentQueueEnvRef{PathwayEnrichmentSelection} eq 'FullHUGO')
    {   $bgMergedSumFile    = "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullHUGOList";
        $bgPathwayFile      = "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullHUGOList.Pathway";
        $bgMinTopCheck		= 'false';
        $compStatus			= 0;
        
        if (! -f $bgMergedSumFile)
        {   LogAnalysis("FullHUGOList is being created");
        	open (FULLHUGO, ">$bgMergedSumFile");
            # Create such file
            my $sql         = "SELECT approvedSymbol, hgncID, approvedName FROM gene";
            my $sth         = $dbh->prepare($sql);
            $sth->execute();
            my @row         = $sth->fetchrow_array;
            while(@row = $sth->fetchrow_array)
            {   print FULLHUGO $row[0]."\t".$row[1]."\t".$row[2]."\t1\t1\tNULL\tNULL\n";
            }
            close FULLHUGO;
        }
        
        #  Check for fullBGGeneSummary.html
        if (! -f "$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/fullBGGeneSummary.html")
        {   LogAnalysis("FULLGENE is being created");
        	open (FULLGENE, ">$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/fullBGGeneSummary.html");
        	open (FULLGENETXT, ">$$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/fullBGGeneSummary.txt");
        	
        	print FULLGENE  "<head>
						    <title>SciMiner Result Report Page</title>
						    <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
						    <link rel=\"stylesheet\" href=\"$cssURLFileName\" type=\"text/css\" />
						    <style type=\"text/css\"> body {	margin-left:10px;	}</style>
						    </head>
						    <body bgcolor=\"#EAF4F4\">
						    <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Full Gene List Page</b></p>
						    <a href=\"fullBGGeneSummary.txt\">Full list in text file</a>
							<hr>
							<p class=\"titleBarName1\"><b>Here are the full list of targets (HUGO based) in SciMiner.</b></p>
							";
		  
			# Generate table for the actual gene
			print FULLGENE "  <table border=\"1\" width=\"590\">
				                <tr class=\"titleBarName1\">
				                    <th width=\"40\">
				                        HUGO
				                    </th>
				                    <th width=\"60\">
				                        Symbol
				                    </th>
				                    <th width=\"400\">
				                        Target Name
				                    </th>
				                    <th width=\"40\">
				                        MiMI
				                    </th>                            
				                </tr>";
				                
				                
            # Create such file
            my $sql         = "SELECT approvedSymbol, hgncID, approvedName FROM gene";
            my $sth         = $dbh->prepare($sql);
            $sth->execute();
            my @row         = $sth->fetchrow_array;
            while(@row = $sth->fetchrow_array)
            {   print FULLGENE "<tr>
		                        <td width=\"40\">
		                            <a href=\"$hgncLinkURL$row[1]\">$row[1]</a>
		                        </td>
		                        <td width=\"60\">
		                            ";
		        if (defined $$symbol2ncbiEntrezGeneIDRef{$row[0]})
		        {	my $tmpNCBIID	= $$symbol2ncbiEntrezGeneIDRef{$row[0]};
		        	print FULLGENE "	<a href=\"$ncbiGeneLink$tmpNCBIID\">$row[0]</a>
		        				</td>
		                        <td width=\"400\">
		                            $row[2]
		                        </td>
		                        <td width=\"40\">
		                        	<a href=\"$mimiNameLink$$symbol2ncbiEntrezGeneIDRef{$row[0]}\"><img src=\"/SciMiner1.1/SciMiner/Images/cytoicon.jpg\"></a>
		                        </td>
		                        </tr>";
		        }else
		        {	print FULLGENE "	<a href=\"$ncbiGeneSearch".($row[1])." AND Human[Orgn]\">$row[1]</a>
		        				</td>
		                        <td width=\"400\">
		                            $row[2]
		                        </td>
		                        <td width=\"40\">
		                        	&nbsp;
		                        </td>
		                        </tr>
		         				";
		        }
		        print FULLGENETXT $row[1]."\t".$row[0]."\t".$row[2]."\n";			
            }
	        print FULLGENE 	"
	        				</table>
	        				<br><br>
	        				<br>
	        				</body>";
            close FULLGENE;
            close FULLGENETXT;
        }
		
		# Copy the file
        		# Copy the file
		if (! -f "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/fullBGGeneSummary.html")
		{	`cp $$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/fullBGGeneSummary.html $$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/`;
		}
		if (! -f "$$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/fullBGGeneSummary.txt")
		{	`cp $$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/fullBGGeneSummary.txt $$annoENVRef{SciMinerWebPath}/FinalResults/$$currentQueueEnvRef{fileNameBase}/`;  
		}
    }
    
    #my $goSigFullOutFile        = "$$annoENVRef{SciMinerPath}/Work/FinalResults/$$currentQueueEnvRef{bgQueryNumber2BaseName}/GOSignificance.full";
    #my $goSigExplicitOutFile    = "$$annoENVRef{SciMinerPath}/Work/FinalResults/$$currentQueueEnvRef{bgQueryNumber2BaseName}/GOSignificance.explicit";    
    #  Load the targetQueryResult Gene results
    load_merged_summary_file_with_parameters ($tgMergedSumFile, \%hugoID2Symbol, $hugoSymbol2IDRef, \%hugoID2Name,
                                              \@tgHugoIDs, \$tgHugoIDCnt, \$tgHugoIDCntTotal, \%tgHugoID2Occur, \%tgHugoID2Paper, 
                                              $tgMinTopCheck, $tgTotalPMID, $$currentQueueEnvRef{MinTopPaperTG}, $$currentQueueEnvRef{MinPaperMethodTG},
                                              \%tgHugoID2PMID, $$currentQueueEnvRef{TGListFileContent});                                             

    #  Load the background Gene results
    load_merged_summary_file_with_parameters ($bgMergedSumFile, \%hugoID2Symbol, $hugoSymbol2IDRef, \%hugoID2Name, 
                                              \@bgHugoIDs, \$bgHugoIDCnt, \$bgHugoIDCntTotal, \%bgHugoID2Occur, \%bgHugoID2Paper,
                                              $bgMinTopCheck, $bgTotalPMID, $$currentQueueEnvRef{MinTopPaperBG}, $$currentQueueEnvRef{MinPaperMethodBG},
                                              \%bgHugoID2PMID, $$currentQueueEnvRef{BGListFileContent});





    #  Now, perform fisher's exact test over the set
    if ($tgHugoIDCnt == 0)
    {   #  This cannot be completed since one of the set has no gene
        LogAnalysis("Target set has 0 gene. Analysis aborted");
        return (-1,"Target set has 0 gene. Analysis aborted");
    }
    if ($bgHugoIDCnt == 0)
    {   LogAnalysis("Background set has 0 gene. Analysis aborted");
        return (-1,"Background set has 0 gene. Analysis aborted");
    }
    LogAnalysis("tgcount is $tgHugoIDCnt   $bgHugoIDCnt");

    #  Load reactome pathway name from files --- this is temporary way -- 
    open (KEGG, "$$annoENVRef{SciMinerPath}/Work/Dictionary/KEGG_lst");
    open (REACTOME, "$$annoENVRef{SciMinerPath}/Work/Dictionary/Reactome_lst");
    
    my %pathwayID2PathwayName        = ();
    while(<REACTOME>)
    {   my $line = $_;		$line =~ s/\r|\n//g;
        my @tmpSplit = split (/\t/, $line);
	    $pathwayID2PathwayName{$tmpSplit[0]} = $tmpSplit[4];
    }	close REACTOME;
    while(<KEGG>)
    {   my $line = $_;		$line =~ s/\r|\n//g;
        my @tmpSplit = split (/\t/, $line);
	    $pathwayID2PathwayName{$tmpSplit[0]} = $tmpSplit[1];
    }	close KEGG;
    LogAnalysis("Hugo and Kegg data have been loaded");

    # --------------------------------------------------------------------------
    #  Second, get hugoID2GO from SciMinerDB
    my %hugoID2keggID                       = ();
    my %hugoID2reacID                       = ();
    my $sql = "SELECT hgncID, keggID, reactomePathwayID FROM gene2external";
    my $sth = $dbh->prepare($sql);
    my @row = ();
    $sth->execute();
        
    while(@row = $sth->fetchrow_array)
    {   if (defined $row[1])
        {   $hugoID2keggID{$row[0]}           = $row[1];
            $hugoID2reacID{$row[0]}           = $row[2];
        }else
        {   # Skip this line, since we need pmid
            $hugoID2keggID{$row[0]}             = "";
            $hugoID2reacID{$row[0]}           = "";
        }
    }





    # --------------------------------------------------------------------------
    #  Step4. Create Full Pathway Files
    LogAnalysis("Creating full Pathway file");
    Create_Full_Pathway_File ( $tgPathwayFile, \@tgHugoIDs, \%hugoID2Symbol, \%hugoID2Name, \%hugoID2keggID, \%hugoID2reacID, 
                          \%pathwayID2PathwayName);
                          
    if ($$currentQueueEnvRef{PathwayEnrichmentSelection} eq 'FullHUGO')
    {   if(! -f $bgPathwayFile)
        {   Create_Full_Pathway_File ( $bgPathwayFile, \@bgHugoIDs, \%hugoID2Symbol, \%hugoID2Name, \%hugoID2keggID, \%hugoID2reacID, 
                          \%pathwayID2PathwayName);
        }
        `cp $$annoENVRef{SciMinerPath}/Work/FullSciMinerDB/FullHUGOList.Pathway $pathwayOutputDir/BACKGROUND.Pathway.txt`;
        $bgPathwayFile = "$pathwayOutputDir/BACKGROUND.Pathway.txt";
        
    }else
    {   if ($$currentQueueEnvRef{PathwayEnrichmentSelection} eq 'Whole') 
        {   if (! -f $bgPathwayFile)
            {   Create_Full_Pathway_File ( $bgPathwayFile, \@bgHugoIDs, \%hugoID2Symbol, \%hugoID2Name, \%hugoID2keggID, \%hugoID2reacID, 
                          \%pathwayID2PathwayName);
            }
            `cp $bgPathwayFile $pathwayOutputDir/BACKGROUND.Pathway.txt`;
        }else
        {   Create_Full_Pathway_File ( $bgPathwayFile, \@bgHugoIDs, \%hugoID2Symbol, \%hugoID2Name, \%hugoID2keggID, \%hugoID2reacID, 
                          \%pathwayID2PathwayName);
        }
    }
    




    # --------------------------------------------------------------------------
    #  Step5. Perform fisher exact test 
    LogAnalysis("Performing Pathway fisher's exact test");    
    Perform_Fisher_Exact_Test_Pathway_Significance ($pathwayOutputDir, \@tgHugoIDs, $tgPathwayFile,
                                                \@bgHugoIDs, $bgPathwayFile, 
                                                \%hugoID2Symbol, \%hugoID2Name, \%hugoID2keggID, \%hugoID2reacID, 
                                                \%pathwayID2PathwayName, $$currentQueueEnvRef{PValueThreshold},
                                                $compStatus);
    return(1, "");                                               
}










sub Perform_Fisher_Exact_Test_Pathway_Significance
{   my $pathwayOutputDir            = shift;
    my $tgHugoIDsRef                = shift;
    my $targetFullGOFile            = shift;
    my $bgHugoIDsRef                = shift;
    my $bgFullGOFile                = shift;
    my $hugoID2SymbolRef            = shift;
    my $hugoID2NameRef              = shift;
    my $hugoID2KeggIDRef            = shift;
    my $hugoID2ReacIDRef            = shift;
    my $pathwayID2PathwayNameRef    = shift;
    my $PValueThreshold             = shift;
    my $compStatus					= shift;

    my $GO2DESCRef  = 0;

    #  Module for Fisher's exact test
    use Text::NSP::Measures::2D::Fisher::twotailed;

    my %testGO2HUGOIDs              = ();
    my %testGO2HUGOIDCount          = ();
    my %backgroundGO2HUGOIDs        = ();
    my %backgroundGO2HUGOIDCount    = ();
    my $testedHUGOIDCount           = scalar @{$tgHugoIDsRef};
    my $backgroundHUGOIDCount       = scalar @{$bgHugoIDsRef};

  
    open (TESTFILE, $targetFullGOFile) || return(-1, "!ERROR: Can't open $targetFullGOFile ...");
    open (BACKGROUND, $bgFullGOFile) || return(-1, "!ERROR: Can't open $bgFullGOFile ...");
    open (SUMMARY, ">".$targetFullGOFile.'.summary') || return(-1);

    my $CntHugoIDWithPathway    = 0;
    my $pathwayFound            = 0;
    
    LogAnalysis("Loading : target pathway $targetFullGOFile");
    my %tggene2pathMat = ();
    my @tggeneIDs 		= ();
    my %path2desc 		= ();
    my %tgpathCnt 		= ();
    my %tggene2pathCnt 	= ();
    my %tgPathDef   	= ();
    my %tgPath2hugoID	= ();
    
    while(<TESTFILE>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        my @tmpSplit = split(/\t/, $line);
        push @tggeneIDs, $tmpSplit[0];
        my $curPathCnt = 0;
        $pathwayFound = 0;
        
        # KEGG Pathways
        if ((defined $tmpSplit[4]) && ($tmpSplit[4] =~ /\</))
        {   $pathwayFound = 1;
            my @tmp1 = split (/\<\_\>/, $tmpSplit[4]);
            $curPathCnt += scalar @tmp1;
            foreach my $tmp1Content (@tmp1)
            {   my @tmp2 = split (/\;/, $tmp1Content);
                $tggene2pathMat{$tmpSplit[0]}->{$tmp2[0]} = '*';
                $tgPathDef{$tmp2[0]} = 1;
                if (not defined $tgpathCnt{$tmp2[0]})
                {   $tgpathCnt{$tmp2[0]} = 1;
                    $path2desc{$tmp2[0]} = $tmp2[1];
                }else
                {   $tgpathCnt{$tmp2[0]} += 1;
                }
                
                #  Assign hugoID list 2 pathway
                if (not defined $tgPath2hugoID{$tmp2[0]})
                {	my %tmpHash					= ();
                	$tmpHash{$tmpSplit[0]}		= 1;
                	$tgPath2hugoID{$tmp2[0]}	= \%tmpHash;
                }else
                {	$tgPath2hugoID{$tmp2[0]}->{$tmpSplit[0]}	= 1;
                }
            }
        }
        
        # Reactome Pathways
        if ((defined $tmpSplit[5]) && ($tmpSplit[5] =~ /\</))
        {   $pathwayFound = 1;
            my @tmp1 = split (/\<\_\>/, $tmpSplit[5]);
            $curPathCnt += scalar @tmp1;
            foreach my $tmp1Content (@tmp1)
            {   my @tmp2 = split (/\;/, $tmp1Content);
                $tggene2pathMat{$tmpSplit[0]}->{$tmp2[0]} = '*';
                $tgPathDef{$tmp2[0]} = 1;
                if (not defined $tgpathCnt{$tmp2[0]})
                {   $tgpathCnt{$tmp2[0]} = 1;
                    $path2desc{$tmp2[0]} = $tmp2[1];
                }else
                {   $tgpathCnt{$tmp2[0]} += 1;
                }
                
                #  Assign hugoID list 2 pathway
                if (not defined $tgPath2hugoID{$tmp2[0]})
                {	my %tmpHash					= ();
                	$tmpHash{$tmpSplit[0]}			= 1;
                	$tgPath2hugoID{$tmp2[0]}	= \%tmpHash;
                }else
                {	$tgPath2hugoID{$tmp2[0]}->{$tmpSplit[0]}	= 1;
                }
            }
        }
        $tggene2pathCnt{$tmpSplit[0]} = $curPathCnt;
        
        #  Check for any pathway
        if ($pathwayFound)
        {   $CntHugoIDWithPathway++;
        }
    }   close TESTFILE;
    
    my @tgpathways = keys %tgPathDef;
    print SUMMARY "targets total\t$testedHUGOIDCount\n".
                  "targets with pathway\t$CntHugoIDWithPathway\n".
                  "pathways\t".(scalar @tgpathways)."\n";
    close SUMMARY;


    open (SUMMARY, ">".$bgFullGOFile.'.summary') || return(-1);
    $CntHugoIDWithPathway    = 0;
    $pathwayFound            = 0;
    my %bgPathDef   = ();
   
    LogAnalysis("Loading : background pathway $bgFullGOFile");
    my %bggene2pathMat 		= ();
    my @bggeneIDs 			= ();
    my %bgpathCnt 			= ();
    my %bggene2pathCnt 		= (); 
    my %bgPath2hugoID		= ();      
    while(<BACKGROUND>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        my @tmpSplit = split(/\t/, $line);
        push @bggeneIDs, $tmpSplit[0];
        my $curPathCnt = 0;
        $pathwayFound = 0;
        # KEGG Pathways
        if ((defined $tmpSplit[4]) && ($tmpSplit[4] =~ /\</))
        {   $pathwayFound = 1;
            my @tmp1 = split (/\<\_\>/, $tmpSplit[4]);
            $curPathCnt += scalar @tmp1;
            foreach my $tmp1Content (@tmp1)
            {   my @tmp2 = split (/\;/, $tmp1Content);
                $bggene2pathMat{$tmpSplit[0]}->{$tmp2[0]} = '*';
                $bgPathDef{$tmp2[0]} = 1;
                if (not defined $bgpathCnt{$tmp2[0]})
                {   $bgpathCnt{$tmp2[0]} = 1;
                    $path2desc{$tmp2[0]} = $tmp2[1];
                }else
                {   $bgpathCnt{$tmp2[0]} += 1;
                }
                
                #  Assign hugoID list 2 pathway
                if (not defined $bgPath2hugoID{$tmp2[0]})
                {	my %tmpHash					= ();
                	$tmpHash{$tmpSplit[0]}			= 1;
                	$bgPath2hugoID{$tmp2[0]}	= \%tmpHash;
                }else
                {	$bgPath2hugoID{$tmp2[0]}->{$tmpSplit[0]}	= 1;
                }
            }
        }
        
        # Reactome Pathways
        if ((defined $tmpSplit[5]) && ($tmpSplit[5] =~ /\</))
        {   $pathwayFound = 1;
            my @tmp1 = split (/\<\_\>/, $tmpSplit[5]);
            $curPathCnt += scalar @tmp1;
            foreach my $tmp1Content (@tmp1)
            {   my @tmp2 = split (/\;/, $tmp1Content);
                $bggene2pathMat{$tmpSplit[0]}->{$tmp2[0]} = '*';
                $bgPathDef{$tmp2[0]} = 1;
                if (not defined $bgpathCnt{$tmp2[0]})
                {   $bgpathCnt{$tmp2[0]} = 1;
                    $path2desc{$tmp2[0]} = $tmp2[1];
                }else
                {   $bgpathCnt{$tmp2[0]} += 1;
                }
                
                #  Assign hugoID list 2 pathway
                if (not defined $bgPath2hugoID{$tmp2[0]})
                {	my %tmpHash					= ();
                	$tmpHash{$tmpSplit[0]}			= 1;
                	$bgPath2hugoID{$tmp2[0]}	= \%tmpHash;
                }else
                {	$bgPath2hugoID{$tmp2[0]}->{$tmpSplit[0]}	= 1;
                }
            }
        }
        $bggene2pathCnt{$tmpSplit[0]} = $curPathCnt;
        
         #  Check for any pathway
        if ($pathwayFound)
        {   $CntHugoIDWithPathway++;
        }
    }   close BACKGROUND;
   
    my @bgpathways = keys %bgPathDef;
    print SUMMARY "targets total\t$backgroundHUGOIDCount\n".
                  "targets with pathway\t$CntHugoIDWithPathway\n".
                  "pathways\t".(scalar @bgpathways)."\n";
    close SUMMARY;



    #  -------------------------------------------------------------------------
    #  Generating PathwayMatrix Files
    #  -------------------------------------------------------------------------
    my $tgFullGOFileMatrix1 = $targetFullGOFile."Matrix1.txt";
    my $tgFullGOFileMatrix2 = $targetFullGOFile."Matrix2.txt"; 
    my $bgFullGOFileMatrix1 = $bgFullGOFile."Matrix1.txt"; 
    my $bgFullGOFileMatrix2 = $bgFullGOFile."Matrix2.txt"; 
  
      
    my @tmpTgPathKeys = ();
    foreach (keys %tgpathCnt)
    {   if (defined $path2desc{$_})
        {   push @tmpTgPathKeys, $_;
        }
    }

    my @tmpBgPathKeys = ();
    foreach (keys %bgpathCnt)
    {   if (defined $path2desc{$_})
        {   push @tmpBgPathKeys, $_;
        }
    }
    
    my @sortedTgPathwayKeys = sort {$tgpathCnt{$b} <=> $tgpathCnt{$a}} @tmpTgPathKeys;
    my @sortedBgPathwayKeys = sort {$bgpathCnt{$b} <=> $bgpathCnt{$a}} @tmpBgPathKeys;      
    
    open (TGMAT1, ">".$tgFullGOFileMatrix1) || LogAnalysis("!ERROR: Can't write to $tgFullGOFileMatrix1");
    open (TGMAT2, ">".$tgFullGOFileMatrix2) || LogAnalysis("!ERROR: Can't write to $tgFullGOFileMatrix2");

    print TGMAT1 "#\t\t\tPathwayID;Name\t";
    print TGMAT2 "#\t\t\tPathwayID;Name\t";
    foreach my $tmpPathwayID (@sortedTgPathwayKeys)
    {   print TGMAT1 $tmpPathwayID.';'.$path2desc{$tmpPathwayID}."\t";
    	print TGMAT2 $tmpPathwayID.';'.$path2desc{$tmpPathwayID}."\t";
    }   print TGMAT1 "\n"; print TGMAT2 "\n";
    print TGMAT1 "\t\t\t# of genes\t"; print TGMAT2 "\t\t\t# of genes\t";
    
    foreach (@sortedTgPathwayKeys)
    {   print TGMAT1 $tgpathCnt{$_}."\t";
        print TGMAT2 $tgpathCnt{$_}."\t";
    }   print TGMAT1 "\n"; print TGMAT2 "\n";
    print TGMAT1 "HUGO\tSymbol\tName\t# of pathways\n"; print TGMAT2 "HUGO\tSymbol\tName\t# of pathways\n";
    
    for (my $i=0; $i <= $#tggeneIDs; $i++)
    {   print TGMAT1 $tggeneIDs[$i]."\t";
        print TGMAT1 $$hugoID2SymbolRef{$tggeneIDs[$i]}."\t";
        print TGMAT1 $$hugoID2NameRef{$tggeneIDs[$i]}."\t";
        print TGMAT1 $tggene2pathCnt{$tggeneIDs[$i]}."\t";
        print TGMAT2 $tggeneIDs[$i]."\t";
        print TGMAT2 $$hugoID2SymbolRef{$tggeneIDs[$i]}."\t";
        print TGMAT2 $$hugoID2NameRef{$tggeneIDs[$i]}."\t";
        print TGMAT2 $tggene2pathCnt{$tggeneIDs[$i]}."\t";
        foreach (@sortedTgPathwayKeys)
        {   if (not defined $tggene2pathMat{$tggeneIDs[$i]}->{$_})
            {   print TGMAT1 "\t"; print TGMAT2 "0\t";
            }else
            {   print TGMAT1 $tggene2pathMat{$tggeneIDs[$i]}->{$_}."\t";
                print TGMAT2 "1\t";
            }
        }   print TGMAT1 "\n"; print TGMAT2 "\n";
    }   close TGMAT1; close TGMAT2;



    open (BGMAT1, ">".$bgFullGOFileMatrix1) || anaLog("!ERROR: Can't write to $bgFullGOFileMatrix1");
    open (BGMAT2, ">".$bgFullGOFileMatrix2) || anaLog("!ERROR: Can't write to $bgFullGOFileMatrix2");

    print BGMAT1 "#\t\t\tPathwayID;Name\t";
    print BGMAT2 "#\t\t\tPathwayID;Name\t";
    foreach my $tmpPathwayID (@sortedBgPathwayKeys)
    {   print BGMAT1 $tmpPathwayID.';'.$path2desc{$tmpPathwayID}."\t";
    	print BGMAT2 $tmpPathwayID.';'.$path2desc{$tmpPathwayID}."\t";
    }   print BGMAT1 "\n"; print BGMAT2 "\n";
    print BGMAT1 "\t\t\t# of genes\t"; print BGMAT2 "\t\t\t# of genes\t";

    foreach (@sortedBgPathwayKeys)
    {   print BGMAT1 $bgpathCnt{$_}."\t";
        print BGMAT2 $bgpathCnt{$_}."\t";
    }   print BGMAT1 "\n"; print BGMAT2 "\n";
    print BGMAT1 "HUGO\tSymbol\tName\t# of pathways\n"; print BGMAT2 "HUGO\tSymbol\tName\t# of pathways\n";
    
    for (my $i=0; $i <= $#tggeneIDs; $i++)
    {   print BGMAT1 $bggeneIDs[$i]."\t";
        print BGMAT1 $$hugoID2SymbolRef{$bggeneIDs[$i]}."\t";
        print BGMAT1 $$hugoID2NameRef{$bggeneIDs[$i]}."\t";
        print BGMAT1 $bggene2pathCnt{$bggeneIDs[$i]}."\t";
        print BGMAT2 $bggeneIDs[$i]."\t";
        print BGMAT2 $$hugoID2SymbolRef{$bggeneIDs[$i]}."\t";
        print BGMAT2 $$hugoID2NameRef{$bggeneIDs[$i]}."\t";
        print BGMAT2 $bggene2pathCnt{$bggeneIDs[$i]}."\t";
        foreach (@sortedBgPathwayKeys)
        {   if (not defined $bggene2pathMat{$bggeneIDs[$i]}->{$_})
            {   print BGMAT1 "\t"; print BGMAT2 "0\t";
            }else
            {   print BGMAT1 $bggene2pathMat{$bggeneIDs[$i]}->{$_}."\t";
                print BGMAT2 "1\t";
            }
        }   print BGMAT1 "\n"; print BGMAT2 "\n";
    }   close BGMAT1; close BGMAT2;
    
    
    
    
    #  -------------------------------------------------------------------------
    #   Significant Test
    #  -------------------------------------------------------------------------
    my $numberOfTGPathways              = scalar @sortedTgPathwayKeys;
    my $np1 = $testedHUGOIDCount;             
    my $np2 = $backgroundHUGOIDCount;            
    my $npp = $np1 + $np2;
    my $n1p = 0;                        # number of PMIDs with the given code
    my $n11 = 0;                        # number of PMIDs common
    my $n12 = 0;
    my $n21 = 0;
    my $n22 = 0;
    my $twotailedPvalue = 0;
    my $errorCode = "";
    my $ratioTarget = 0;
    my $ratioBackground   = 0;

    my %tPlusString		= ();
    my %tMinusString	= ();
    my %commonString	= ();
    my %bPlusString		= ();
    my %bMinusString	= ();
    my %commonCount		= ();
    my %tUniqCount		= ();
    my %bUniqCount		= ();
    my %tUniqString		= ();
    my %bUniqString		= ();    
       
#          word2   ~word2                       corpus         full
#  word1    n11      n12 | n1p       MeSH+        n11          n12     n1p
# ~word1    n21      n22 | n2p       MeSH-        n21          n22     n2p
#           --------------
#           np1      np2   npp                    np1          np2     npp

    
    #  Perform Fisher's exact test by category Selected Level Only
    my %PValueByPathway             = ();
    my %MatrixByPathway             = ();
    my $BFPValueThreshold           = $PValueThreshold / $numberOfTGPathways;
    foreach my $pathway ( @sortedTgPathwayKeys )
    {   #  Initialize string and count
        $tPlusString{$pathway}	= '';
        $tMinusString{$pathway}	= '';
        $commonString{$pathway}	= '';
        $bPlusString{$pathway}	= '';
        $bMinusString{$pathway}	= '';
        $commonCount{$pathway}	= 0;
        $tUniqCount{$pathway}	= 0;
        $bUniqCount{$pathway}	= 0;
        $tUniqString{$pathway}	= '';
        $bUniqString{$pathway}	= '';
        
        $tPlusString{$pathway} = join (",", keys %{$tgPath2hugoID{$pathway}});
        $bPlusString{$pathway} = join (",", keys %{$bgPath2hugoID{$pathway}});
        
        #  Check for bgPathway
        if (defined $bgPath2hugoID{$pathway})
        {	my $count	= scalar @{$bgHugoIDsRef};
        	foreach my $bgHugoID (keys %{$bgPath2hugoID{$pathway}})
        	{	if (defined $tgPath2hugoID{$pathway}->{$bgHugoID})
        		{	#  Overlapping PMID
        			$tgPath2hugoID{$pathway}->{$bgHugoID}	= 2;
        			$bgPath2hugoID{$pathway}->{$bgHugoID}	= 2;
        			$commonString{$pathway}	.= $bgHugoID.',';
        			$commonCount{$pathway}++;
        		}else
        		{	$bUniqCount{$pathway}++;
        			$bUniqString{$pathway}	.= $bgHugoID.',';
        		}
        	}
        }

		#  Generate the pathway strings for target set
		foreach my $tgHugoID (@tggeneIDs) 										#(keys %{$tgPath2hugoID{$pathway}})
		{	if (defined $tgPath2hugoID{$pathway}->{$tgHugoID})
			{	if ($tgPath2hugoID{$pathway}->{$tgHugoID} == 1)
				{	$tUniqCount{$pathway}++;
        			$tUniqString{$pathway}	.= $tgHugoID.',';
				}
			}else
			{	$tMinusString{$pathway}	.= $tgHugoID.',';
			}
		}
		
		#  Generate the PMID strings for background set
		foreach my $bgHugoID (@bggeneIDs)										#(keys %{$bgPath2hugoID{$pathway}})
		{	if (defined $bgPath2hugoID{$pathway}->{$bgHugoID})
			{	# do nothing
			}else
			{	$bMinusString{$pathway}	.= $bgHugoID.',';
			}
		}
		
		#  Perform fisher's exact test
        $n11 = $tgpathCnt{$pathway};
        if (defined $bgpathCnt{$pathway})
        {   $n12 = $bgpathCnt{$pathway};
        }else
        {   $n12 = 0;
        }
        $n1p = $n11 + $n12;                             # Note that n1p = n11 + n12
        $n21 = $np1 - $n11;
        $n22 = $np2 - $n12;

        $twotailedPvalue = calculateStatistic (n11 => $n11, 
                                               n1p => $n1p,
                                               np1 => $np1,
                                               npp => $npp);
        if ( ($errorCode = getErrorCode()))
        {   $PValueByPathway{$pathway} = -1;
        }else
        {   $PValueByPathway{$pathway} = sprintf("%.3e",$twotailedPvalue);
        }
        
        if ($compStatus)
        {	$MatrixByPathway{$pathway} 	= $np1."\t".$n11."\t".$n21."\t".$tUniqCount{$pathway}."\t".$commonCount{$pathway}."\t".$bUniqCount{$pathway}."\t".$n12."\t".$n22."\t".$np2."\t".$PValueByPathway{$pathway}."\t";;
        }else
        {	$MatrixByPathway{$pathway} 	= $np1."\t".$n11."\t".$n21."\t".$n12."\t".$n22."\t".$np2."\t".$PValueByPathway{$pathway}."\t";;
        }
        
        $ratioTarget            = $n11/$np1;
        $ratioBackground        = $n12/$np2;
            
        if (($n12 != 0) && ($n11 != 0))
        {   $MatrixByPathway{$pathway} .= sprintf("%.2f\t%.2f\t%.1f",$ratioTarget, $ratioBackground, ($ratioTarget)/($ratioBackground));
        }else
        {   # This is very unlike to happen. But in case it happens. 
        	my $tmpTag		= $tgZeroTag;
        	if ($n12 == 0)
        	{	$tmpTag		= $bgZeroTag;
        	}
            $MatrixByPathway{$pathway} .= sprintf("%.2f\t%.2f\t",$ratioTarget, $ratioBackground).$tmpTag;
        }
        
        
        #  Determine nominal / bonferroni corrected
        if ($PValueByPathway{$pathway} <= $PValueThreshold)
        {   $MatrixByPathway{$pathway} .= "\tNominal_Sig";
        }else
        {   $MatrixByPathway{$pathway} .= "\tNot_Sig";
        }
        
        #if ($PValueByPathway{$pathway} <= $BFPValueThreshold)
        #{   $MatrixByPathway{$pathway} .= "\tBonFC_Sig";
        #}else
        #{   $MatrixByPathway{$pathway} .= "\tNot_Sig";
        #}
    }
        
        
    #  ---------------------------------------------------------------------
    LogAnalysis("Significant test of Pathway completed");

    #  Creating corpus MeSH distribution
    my @PValueSortedPathways = sort {$PValueByPathway{$a} <=> $PValueByPathway{$b}} @sortedTgPathwayKeys;    
    
    #  Result printout   
    open (TMP, ">$pathwayOutputDir/SigTest_Pathway.txt") ||LogAnalysis("!ERROR: Can't write to $pathwayOutputDir/SigTest_Pathway.txt");
    if ($compStatus)
    {	print TMP "#PathwayID\tName\tt-total\tt+\tt-\tt+uniq\tcommon\tb+uniq\tb+\tb-\tb-total\tp-value\tt-ratiot\tb-ratio\t(t-ratio)/(b-ratio)\tSigTest\n";
    }else
    {	print TMP "#PathwayID\tName\tt-total\tt+\tt-\tb+\tb-\tb-total\tp-value\tt-ratiot\tb-ratio\t(t-ratio)/(b-ratio)\tSigTest\n";
    }
    
    foreach my $pathway (@PValueSortedPathways)
    {   print TMP $pathway."\t".$$pathwayID2PathwayNameRef{$pathway}."\t".$MatrixByPathway{$pathway}."\n";
    }
    close TMP;
    
    #  Result String printout   
    open (HUGOString, ">$pathwayOutputDir/SigTest_Pathway.hugoID");
    print HUGOString "#PathwayID\tName\tt+\tt-\tt+uniq\tcommon\tb+uniq\tb+\tb-\n";
    foreach my $pathway (@sortedTgPathwayKeys)
    {   print HUGOString $pathway."\t".$$pathwayID2PathwayNameRef{$pathway}."\t";
    	print HUGOString $tPlusString{$pathway}."\t".$tMinusString{$pathway}."\t";
        print HUGOString $tUniqString{$pathway}."\t".$commonString{$pathway}."\t".$bUniqString{$pathway}."\t";
        if ($compStatus)
        {	print HUGOString $bPlusString{$pathway}."\t".$bMinusString{$pathway}."\n";
        }else
        {	print HUGOString $bPlusString{$pathway}."\t\t\n";
        }
    }
    close HUGOString;
    
    ##  Generate tgHUID and bgHUGO ID files
    #open (TGHUGOID, ">$finalResultWebDir/tgHugoIDs.txt");
    #open (BGHUGOID, ">$finalResultWebDir/bgHugoIDs.txt");
	#foreach my $hugoID (@sortedTgHugoIDs)
	#{	print TGHUGOID "$hugoID\n";
	#}   close TGHUGOID;
	#	
	#foreach my $hugoID (@bgHugoIDs)
	#{	print BGHUGOID "$hugoID\n";
	#}   close BGHUGOID;
	
    #  Catch the most-informative code
    return(1);
}










sub Create_Full_Pathway_File
{   my $localOutFileName            = shift;
    my $localHUGOIDs                = shift;
    my $localHUGOID2Symbol          = shift;
    my $localHUGOID2Name            = shift;
    my $localHUGOID2KeggID          = shift;
    my $localHUGOID2ReacID          = shift; 
    my $pathwayID2PathwayNameRef    = shift;
    
    my $fileStatus              = 1;
    my %minedPathwayCnt         = ();
    
    open (OUTGO, ">".$localOutFileName) || return(-1);

    
    foreach my $hugoID (@{$localHUGOIDs})
    {   my $newoutStr = $hugoID."\t".$$localHUGOID2Symbol{$hugoID}."\t".$$localHUGOID2Name{$hugoID}."\t";
        my $pathwayFound    = 0;
        #Pathway Output - KEGG
        print OUTGO $newoutStr."\t";
        if ((defined $$localHUGOID2KeggID{$hugoID}) && ($$localHUGOID2KeggID{$hugoID} =~ /\S/))
        {   my @tmpSplit = split (/\|/, $$localHUGOID2KeggID{$hugoID});
            foreach my $keggID (@tmpSplit)
            {   if (defined $$pathwayID2PathwayNameRef{$keggID})
                {   print OUTGO $keggID.';'.$$pathwayID2PathwayNameRef{$keggID}.'<_>';
                    if (defined $minedPathwayCnt{$keggID}) 
                    {   $minedPathwayCnt{$keggID}++;
                    }else
                    {   $minedPathwayCnt{$keggID} = 1;
                    }
                }else
                {   print OUTGO $keggID.';<_>';
                }
            }   print OUTGO "\t";
        }else
        {   print OUTGO "\t";
        }

        #Pathway Output - Reactome
        if ((defined $$localHUGOID2ReacID{$hugoID}) && ($$localHUGOID2ReacID{$hugoID}) =~ /\S/)
        {   my @tmpSplit = split (/\|/, $$localHUGOID2ReacID{$hugoID});
            foreach my $ReacID (@tmpSplit)
            {   if (defined $$pathwayID2PathwayNameRef{$ReacID})
                {   print OUTGO $ReacID.';'.$$pathwayID2PathwayNameRef{$ReacID}.'<_>';
                    if (defined $minedPathwayCnt{$ReacID}) 
                    {   $minedPathwayCnt{$ReacID}++;
                    }else
                    {   $minedPathwayCnt{$ReacID} = 1;
                    }
                }else
                {   print OUTGO $ReacID.';<_>';
                }
            }   print OUTGO "\t";
        }else
        {   print OUTGO"\t";
        }        
        print OUTGO "\n";
        
    }
    close (OUTGO);
    
 
    return (1);
}










sub remove_completed_analysis_update_status
{   my $workDir         			= shift;
    my $fileNameBase    			= shift;
    my $dbh             			= shift;
    my $analysisNumber  			= shift;
    my $status          			= shift;
    my $analURL						= shift;
    my $email						= shift;
    my $queryAnalInfo				= shift;
    my $shortResultSummaryHTMLURL	= shift;
    my $annoENVRef					= shift;
    
    `cp $workDir/$fileNameBase.* $workDir/FinalResults/$fileNameBase/`;
    `rm -Rf $workDir/$fileNameBase.*`;
    `rm -Rf $workDir/AnalysisQueue`;
    
    #  Update Query table current status of the db
    $dbh->do("UPDATE analysis SET dateEnd=curdate(), timestampEnd=curtime(), status=$status, analURL=\"$shortResultSummaryHTMLURL\" WHERE analID = $analysisNumber");
    
    #  Send email notice for completed anlaysis
    if (( defined $$annoENVRef{'SendMail'}) && ($$annoENVRef{'SendMail'}))
	{	send_result_email($analURL, $email, $queryAnalInfo);
	}
}









































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































