sub create_go_top10_result_table
{   my $CategoryType        = shift;
    my $GOResultFile        = shift;
    my $txtLinkFile         = shift;
    my $xlsLinkFile         = shift;
    my $PValueThreshold     = shift;
    my $GOBaseURL           = shift;
    my $levelLinkFileExt    = shift;
    my $annoENVRef			= shift;
    my $currentQueueEnvRef	= shift;
    my $dirBaseName			= shift;
    my $cssURL				= shift;

    if (not defined $levelLinkFileExt)
    {   $levelLinkFileExt = '.txt';
    }

	my $tableIDBase			= '';
	my $ImageClose			= "/SciMiner1.1/SciMiner/Images/closed.gif";

	#  Create table ID
	if ($CategoryType =~ /Biological/)
	{	$tableIDBase	= 'BP';
	}elsif ($CategoryType =~ /Molecular/)
	{	$tableIDBase	= 'MF';
	}else
	{	$tableIDBase	= 'CC';
	}
	
	if ($CategoryType =~ /Level/)
	{	$tableIDBase	.= 'Level';
	}elsif ($CategoryType =~ /Explicit/)
	{	$tableIDBase	.= 'Explicit';
	}else
	{	$tableIDBase	.= 'Full';
	}

    open (FILE, $GOResultFile );
    my @top10GOLine = ();
    my $rankCount = 0;
    my $tgCorpusSize = 0;
    my $bgCorpusSize = 0;

	#  Load the result file and create the html full result file
    while(<FILE>)
    {   my $line = $_;
    	if ($line =~ /^#/)
    	{	next;
    	}
        $line =~ s/\r|\n//g;
        if ($rankCount == 0)
        {   my @tmpSplit = split(/\t/, $line);
            if ($tmpSplit[0] =~ /^Level/)
            {   shift @tmpSplit;
            }
             
            $tgCorpusSize = $tmpSplit[2];
            $bgCorpusSize = $tmpSplit[7];
        }
        push @top10GOLine, $line;
        $rankCount++;
    }
    close FILE;
    
	#  Read the summary file and generate an html file
	my $fullHTMLFile		= $$annoENVRef{SciMinerWebPath}."FinalResults/$$currentQueueEnvRef{fileNameBase}/GO/$dirBaseName".'.html';
	my $fullHTMLURL			= "GO/$dirBaseName".'.html';
	
	#  Load the list of detail files
	my @detailGOFiles		= glob($$annoENVRef{SciMinerWebPath}."FinalResults/$$currentQueueEnvRef{fileNameBase}/GO/$dirBaseName".'_DIR/*.txt');
	my $currentDir			= "$$currentQueueEnvRef{fileNameBase}/GO/$dirBaseName".'_DIR/';
	my %detailFilePath		= ();
	my %detailShortFile		= ();
	
	foreach my $tmpFile (@detailGOFiles)
	{	my @tmpSplitFile	= split(/\//, $tmpFile);
		my @tmpSplitFile2	= split(/\_/, $tmpSplitFile[$#tmpSplitFile]);
		$detailFilePath{$tmpSplitFile2[0]}	= $dirBaseName.'_DIR/'.$tmpSplitFile[$#tmpSplitFile];
		$detailShortFile{$tmpSplitFile2[0]}	= $tmpSplitFile[$#tmpSplitFile];
	}
	
	
	
    open (FULLRESULT, ">".$fullHTMLFile);
    my $fullResultString =  "<head>
						    <title>SciMiner: $CategoryType full result page</title>
						    <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
						    <link rel=\"stylesheet\" href=\"../$cssURL\" type=\"text/css\" />
                			<script language=\"JavaScript1.2\" src=\"../sciminer.js\"></script>
						    <style type=\"text/css\"> body {	margin-left:10px;	}</style>
						    </head>
