						    <a class=\"titleBarName1\" id='meshTableSwitch' onclick=\"javascript:show_hide_column('$tableIDBase','5_6_7_10');\" onmouseover=\"Tip('Click here to toggle table details.')\" onmouseout=\"UnTip()\"><u>Switch table detail</u></a>
						    
						    <table border=\"1\" id=\"$tableIDBase\">
						    <tr class=\"tableHeader1\">
		                        <th width=\"40\">
		                            Rank
		                        </th>
		                        <th width=\"50\" onmouseover=\"Tip('<b>Level</b>: Hierarchical level of the Gene Ontology tree structure.<br>Level2 has the most broaden meaning under three GO categories of Biological Processes, Molecular Functions, and Cellular Components.<br><br>Click Level to download an EXCEL file with all GO from the selected level.')\" onmouseout=\"UnTip()\">
		                            Level
		                        </th>
		                        <th width=\"80\" onmouseover=\"Tip('Click each GO ID to see the list of genes from the test and background set.<br><br>You may find this feature useful to retrieve all other genes that are not in your test set <br>when the background set is All HUGO gene set.')\" onmouseout=\"UnTip()\">
		                            GO ID
		                        </th>                            
		                        <th width=\"300\"onmouseover=\"Tip('Clich each GO term to see more detail on the selected term from the EBI QuickGO.')\" onmouseout=\"UnTip()\">
		                            GO Term
		                        </th>
		                        <th width=\"50\" bgcolor=\"$tgCColor\" onmouseover=\"Tip('</b>t+</t>: # of genes <b>with</b> the selected GO in the <b>test</b> set.')\" onmouseout=\"UnTip()\">
		                            t+
		                        </th>
		                        <th width=\"50\" bgcolor=\"$tgCColor\" onmouseover=\"Tip('</b>t-</t>: # of genes <b>without</b> the selected GO in the <b>test</b> set.')\" onmouseout=\"UnTip()\">
		                            t-
		                        </th>
		                        <th width=\"50\" bgcolor=\"$bgCColor\" onmouseover=\"Tip('</b>b+</t>: # of genes <b>with</b> the selected GO in the <b>background</b> set.')\" onmouseout=\"UnTip()\">
		                            b+
		                        </th>
		                        <th width=\"50\" bgcolor=\"$bgCColor\" onmouseover=\"Tip('</b>b-</t>: # of genes <b>without</b> the selected GO in the <b>background</b> set.')\" onmouseout=\"UnTip()\">
		                            b-
		                        </th>
		                        <th width=\"70\" onmouseover=\"Tip('P-value by Fishers Exact Test on 2x2 table<br><br><img src=&quot;../Images/2x2Table.jpg&quot; width=&quot;50&quot; height=&quot;50&quot;><br><br>P-values lower than the specified threshold will be in <font color=&quot;red&quot;>red</font>')\" onmouseout=\"UnTip()\">
		                            p-value
		                        </th>
		                        <th width=\"50\" onmouseover=\"Tip('Ratio of t+ in the test set')\" onmouseout=\"UnTip()\">
		                            t-ratio
		                        </th>
		                        <th width=\"50\" onmouseover=\"Tip('Ratio of b+ in the background set')\" onmouseout=\"UnTip()\">
		                            b-ratio
		                        </th>
		                        <th width=\"70\" onmouseover=\"Tip('This implies the enrichment folds in the test set, calculated by<br>&nbsp;&nbsp;&nbsp;(t-ratio)&nbsp;&nbsp;/&nbsp;&nbsp;(b-ratio)<br><br>You may find <b>enrichment folds greater than 2 to be interesting</b>.<br><br><p style=&quot;background-color:$tgCColor&quot;>Enrichment in <b>test</b> set</p><p style=&quot;background-color:$bgCColor&quot;>Enrichment in <b>background</b> set</p><p style=&quot;background-color:$tgCColor&quot;>bZero: There is <b>NO</b> such GO in the background set.</p>')\" onmouseout=\"UnTip()\">
		                                    enrichment<br>folds
		                                </th>
                        </tr>";


    # Top 10 most GO
    my $resultString = "<br>
    
    					<span class=\"trigger\" onclick=\"showBranch('branchGO$tableIDBase');swapFolder('folderGO$tableIDBase')\">
							<table width=\"100%\" border=\"0\" onmouseover=\"Tip('Click here to hide/show the detail!')\" onmouseout=\"UnTip()\">
								<tr>
									<td width=\"50\">
										<img src=\"$ImageClose\" id=\"folderGO$tableIDBase\" border=\"0\">
									</td>
									<td>
										<p align=\"center\" class=\"sectionTitleName2\">Top 10 most enriched <b>GO terms ($CategoryType)</b> (sorted by p-value)</p>
									</td>
								</tr>
							</table>
						</span>
			
					    <span style=\"display:none;\" class=\"branch\" id=\"branchGO$tableIDBase\">
					    
                    <a style=\"background-color:#F5CCF4;\" class=\"titleBarName1\" id='goTableSwitch' onclick=\"javascript:show_hide_column('$tableIDBase','5_6_7_10');\" onmouseover=\"Tip('Click here to toggle table details.')\" onmouseout=\"UnTip()\"><u>Switch table detail</u></a>
                    <table border=\"1\" id=\"$tableIDBase\">
                        <tr class=\"tableHeader1\">
                            <th width=\"40\">
		                            Rank
		                        </th>
		                        <th width=\"50\" onmouseover=\"Tip('<b>Level</b>: Hierarchical level of the Gene Ontology tree structure.<br>Level2 has the most broaden meaning under three GO categories of Biological Processes, Molecular Functions, and Cellular Components.<br><br>Click Level to download an EXCEL file with all GO from the selected level.')\" onmouseout=\"UnTip()\">
		                            Level
		                        </th>
		                        <th width=\"80\" onmouseover=\"Tip('Click each GO ID to see the list of genes from the test and background set.<br><br>You may find this feature useful to retrieve all other genes that are not in your test set <br>when the background set is All HUGO gene set.')\" onmouseout=\"UnTip()\">
		                            GO ID
		                        </th>                            
		                        <th width=\"300\"onmouseover=\"Tip('Clich each GO term to see more detail on the selected term from the EBI QuickGO.')\" onmouseout=\"UnTip()\">
		                            GO Term
		                        </th>
		                        <th width=\"50\" bgcolor=\"$tgCColor\" onmouseover=\"Tip('</b>t+</t>: # of genes <b>with</b> the selected GO in the <b>test</b> set.')\" onmouseout=\"UnTip()\">
		                            t+
		                        </th>
		                        <th width=\"50\" bgcolor=\"$tgCColor\" onmouseover=\"Tip('</b>t-</t>: # of genes <b>without</b> the selected GO in the <b>test</b> set.')\" onmouseout=\"UnTip()\">
		                            t-
		                        </th>
		                        <th width=\"50\" bgcolor=\"$bgCColor\" onmouseover=\"Tip('</b>b+</t>: # of genes <b>with</b> the selected GO in the <b>background</b> set.')\" onmouseout=\"UnTip()\">
		                            b+
		                        </th>
		                        <th width=\"50\" bgcolor=\"$bgCColor\" onmouseover=\"Tip('</b>b-</t>: # of genes <b>without</b> the selected GO in the <b>background</b> set.')\" onmouseout=\"UnTip()\">
		                            b-
		                        </th>
		                        <th width=\"70\" onmouseover=\"Tip('P-value by Fishers Exact Test on 2x2 table<br><br><img src=&quot;/SciMiner1.1/SciMiner/Images/2x2Table.jpg&quot; width=&quot;50&quot; height=&quot;50&quot;><br><br>P-values lower than the specified threshold will be in <font color=&quot;red&quot;>red</font>')\" onmouseout=\"UnTip()\">
		                            p-value
		                        </th>
		                        <th width=\"50\" onmouseover=\"Tip('Ratio of t+ in the test set')\" onmouseout=\"UnTip()\">
		                            t-ratio
		                        </th>
		                        <th width=\"50\" onmouseover=\"Tip('Ratio of b+ in the background set')\" onmouseout=\"UnTip()\">
		                            b-ratio
		                        </th>
		                        <th width=\"70\" onmouseover=\"Tip('This implies the enrichment folds in the test set, calculated by<br>&nbsp;&nbsp;&nbsp;(t-ratio)&nbsp;&nbsp;/&nbsp;&nbsp;(b-ratio)<br><br>You may find <b>enrichment folds greater than 2 to be interesting</b>.<br><br><p style=&quot;background-color:$tgCColor&quot;>Enrichment in <b>test</b> set</p><p style=&quot;background-color:$bgCColor&quot;>Enrichment in <b>background</b> set</p><p style=&quot;background-color:$tgCColor&quot;>bZero: There is <b>NO</b> such GO in the background set.</p>')\" onmouseout=\"UnTip()\">
		                                    enrichment<br>folds
		                                </th>
                        </tr>";
    
	my $tmpTop10GOLineCount	= scalar @top10GOLine;
    for (my $j=0; $j < $tmpTop10GOLineCount; $j++)    
    {   if (defined $top10GOLine[$j])
        {   # there are legitimate MeSH
            my @tmpSplit = split (/\t/, $top10GOLine[$j]);
            my $level = "&nbsp;";
            my $categoryTag = "";
            if ($tmpSplit[0] =~ /^Level/)
            {   if ($CategoryType =~ /Biological Process/)
                {   $categoryTag    = 'BP_';
                }elsif ($CategoryType =~ /Molecular Function/)
                {   $categoryTag    = 'MF_';
                }elsif ($CategoryType =~ /Cellular Component/)
                {   $categoryTag    = 'CC_';
                } 
                $level = "<a href=\"$GOBaseURL$categoryTag$tmpSplit[0]$levelLinkFileExt\" target=\"_blank\">$tmpSplit[0]</a>";
