            $tmpResultString .= "</td><td>$tmpSplit[9]</td><td>$tmpSplit[10]</td>";

            if ($tmpSplit[11] eq $tgZeroTag )
			{	$tmpResultString .= "<td bgcolor=\"$bgCColor\">";
			}elsif ($tmpSplit[11] eq $bgZeroTag)
			{	$tmpResultString .= "<td bgcolor=\"$tgCColor\">";
			}elsif ($tmpSplit[11] > 1)
			{	$tmpResultString .= "<td bgcolor=\"$tgCColor\">";
			}elsif ($tmpSplit[11] < 1)
			{	$tmpResultString .= "<td bgcolor=\"$bgCColor\">";
			}else
			{	$tmpResultString .= "<td>";
			}
            $tmpResultString .= "$tmpSplit[11]</td></tr>";               
            
            #  Add to fullResultString
            $fullResultString .= $tmpResultString;
            
            #  Add resultString only when the index is less than 10                 
			if ($j < 10)
			{	$resultString .= "<tr><td>".($j+1)."</td><td>".$level."</td><td>";
		        if (defined $detailFilePath{$tmpRankNum})
		        {	#$resultString .= "<a href=\"GO/$detailFilePath{$tmpRankNum}\">$tmpSplit[0]</a>";
		        	$resultString .= "<a href=\"javascript:generate_go_detail_html('$tmpSplit[0]','$currentDir','$detailShortFile{$tmpRankNum}');\">$tmpSplit[0]</a>";
		        }else
		        {	$resultString .= "$tmpSplit[0]";			
		        }
				$resultString	.= "</td><td><a href=\"$goBrowserLinkURL4$tmpSplit[0]\">$tmpSplit[1]</a></td><td>$tmpSplit[3]</td><td>$tmpSplit[4]</td><td>$tmpSplit[5]</td><td>$tmpSplit[6]</td><td>";
		        if ($tmpSplit[8] < $PValueThreshold)
		        {   $resultString .= "<font color=\"red\">".sprintf("%.2e",$tmpSplit[8])."</font>";
		        }else
		        {	$resultString .=  sprintf("%.2e",$tmpSplit[8]);
		        }
		        $resultString .= "</td><td>$tmpSplit[9]</td><td>$tmpSplit[10]</td>";

		        if ($tmpSplit[11] eq $tgZeroTag )
				{	$resultString .= "<td bgcolor=\"$bgCColor\">";
				}elsif ($tmpSplit[11] eq $bgZeroTag)
				{	$resultString .= "<td bgcolor=\"$tgCColor\">";
				}elsif ($tmpSplit[11] > 1)
				{	$resultString .= "<td bgcolor=\"$tgCColor\">";
				}elsif ($tmpSplit[11] < 1)
				{	$resultString .= "<td bgcolor=\"$bgCColor\">";
				}else
				{	$resultString .= "<td>";
				}
		        $resultString .= "$tmpSplit[11]</td></tr>";  
				
			}
        }else
        {   #  Do not print blank lines
        }
    }    # for
    
    $fullResultString .= "</table>
    					  <br><br>";
    $resultString .= "</table>
    				  ";
    
    #  Add full html URL
    
    $resultString 		.= "<p class=\"smallText2\"> Full result (<a href=\"$fullHTMLURL\">HTML</a>), ";
    $fullResultString 	.= "<p class=\"smallText2\"> Full result&nbsp;&nbsp;";
    
    if ((defined $txtLinkFile) && ($txtLinkFile ne ""))
    {   $resultString .= "&nbsp;(<a href=\"$txtLinkFile\">TXT</a>)&nbsp;&nbsp;";
    	$fullResultString .= "&nbsp;(<a href=\"$dirBaseName.txt\">TXT</a>)&nbsp;&nbsp;";
    }
    if ((defined $xlsLinkFile) && ($xlsLinkFile ne ""))
    {   $resultString .= "&nbsp;(<a href=\"$xlsLinkFile\">EXCEL</a>)&nbsp;&nbsp;";
    	$fullResultString .= "&nbsp;(<a href=\"$dirBaseName.xls\">EXCEL</a>)&nbsp;&nbsp;";
    }
    
    $resultString .= "<a href=\"#TOP\">Back to top</a>&nbsp;"."</p></span>";
    $fullResultString .= '<br><br></p>';

	print FULLRESULT $fullResultString;
	close FULLRESULT;
	
	return($resultString);
}    




















sub generate_temporary_result_html
{   my $htmlURL                 = shift;
    my $resultHTMLFile          = shift;
    my $currentQueueEnvRef      = shift;
    my $SciMinerURL              = shift;
    my $tgQueryEnvRef			= shift;
    my $bgQueryEnvRef			= shift;
    
    if (defined $tgQueryEnvRef)
    {	LogAnalysis($htmlURL);
    }else
    {	LogQuery($htmlURL);
    }

    my $cssURL 					= $SciMinerURL."css/sciminer-modern.css";
       
    open (RESULT, ">".$resultHTMLFile);
    print RESULT "  <head>
                    <meta http-equiv=\"refresh\" content=\"10;url=$htmlURL\">
                    <title>SciMiner Result Report Page</title>
                    <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
                    <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
                	<style type=\"text/css\"> body {	margin-left:10px;	}</style>
                    </head>
                    
                    <body bgcolor=\"#EAF4F4\">
                    <p class=\"pageName\" align=\"center\"><b>SciMiner Result Report Page</b></p>
                    <hr>
                    <p class='titleBarName1'><b>Your query/analysis is being processed. Refereshing in 10 seconds<b><br>
                    <a href=\"$htmlURL\">$htmlURL</a><br><br>
                    Your query and search options were</p>
                    <table border=\"1\" width=\"850\">
                    ";



    my $bgPrintOut  = 0;
    if ((defined $tgQueryEnvRef) && ($tgQueryEnvRef ne ""))
    {	if ((($$currentQueueEnvRef{GeneEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{GeneEnrichmentSelection} eq 'Selected')) || 
		    (($$currentQueueEnvRef{GOEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{GOEnrichmentSelection} eq 'Selected')) || 
		    (($$currentQueueEnvRef{MeSHEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{MeSHEnrichmentSelection} eq 'Selected')) ||
		    (($$currentQueueEnvRef{PathwayEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{PathwayEnrichmentSelection} eq 'Selected')) || 
		    (($$currentQueueEnvRef{PPICheck} eq "on") && ($$currentQueueEnvRef{PPISelection} eq 'Selected')))
		{   $bgPrintOut = 1;
		}
    }
    
    # Running condition (options)
    my %itemContent		= ();
    my $otherOption		= '';
    my $enrichmentTest	= '';
    my $ppiSelection	= '';
    
    foreach my $keyTerm (sort(keys %{$currentQueueEnvRef}))
    {   if ((defined $keyTerm) && ($keyTerm ne "") && (defined $$currentQueueEnvRef{$keyTerm}))
        {   if ($keyTerm eq 'queryID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Query ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'analID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Analysis ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'userName')
        	{   $itemContent{1}		=	print_tmpKey_tmpTerm_for_selected_option('User name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'email')
        	{	$itemContent{2}		=	print_tmpKey_tmpTerm_for_selected_option('Email', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Query information
        	elsif ($keyTerm eq 'queryName')
        	{   $itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Query name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'queryString')
        	{   $itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Query string', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'count')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('PMID count #', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Mining Mode / Species Extension information
        	elsif ($keyTerm eq 'speciesExtension')
        	{   $itemContent{6}		=	print_tmpKey_tmpTerm_for_selected_option('Species Extension', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'miningMode')
        	{   if (defined $tgQueryEnvRef)
				{	# Do nothing for this
				}
        		$itemContent{7}		=	print_tmpKey_tmpTerm_for_selected_option('Mining Mode', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Some analysis information
        	elsif ($keyTerm eq 'targetQueryNumber')
        	{   my $additionalString	= "&nbsp;&nbsp;(Name:&nbsp;'$$tgQueryEnvRef{queryName}',&nbsp;# of PMIDs:&nbsp;'$$tgQueryEnvRef{numPMID}',&nbsp;# of genes:&nbsp;'$$tgQueryEnvRef{numGene}')"."&nbsp;&nbsp;(<a href=\"../../$$tgQueryEnvRef{resultURL}\">Result Page</a>)&nbsp;&nbsp;$$currentQueueEnvRef{'MinPaperMethodTG'}&nbsp;($$currentQueueEnvRef{MinTopPaperTG})";
        		$itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Target Query #', $$currentQueueEnvRef{$keyTerm}.$additionalString);
        	}elsif ($keyTerm eq 'bgQueryNumber')
        	{   my $additionalString	= '';
        		if (!$bgPrintOut)
                {   next;
                }else
                { 	$additionalString   = "&nbsp;&nbsp;(Name:&nbsp;'$$bgQueryEnvRef{queryName}',&nbsp;# of PMIDs:&nbsp;'$$bgQueryEnvRef{numPMID}',&nbsp;# of genes:&nbsp;'$$bgQueryEnvRef{numGene}')"."&nbsp;&nbsp;(<a href=\"../../$$bgQueryEnvRef{resultURL}\">Result Page</a>)&nbsp;&nbsp;$$currentQueueEnvRef{'MinPaperMethodBG'}&nbsp;($$currentQueueEnvRef{MinTopPaperBG})";
                }
        		$itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Background Query #', $$currentQueueEnvRef{$keyTerm}.$additionalString);
        	}
        	#elsif ($keyTerm eq 'targetQueryNumber')
        	#{   $itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Target Query #', $$currentQueueEnvRef{$keyTerm});
        	#}elsif ($keyTerm eq 'bgQueryNumber')
        	#{   $itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Background Query #', $$currentQueueEnvRef{$keyTerm});
        	#}
        	elsif ($keyTerm eq 'PValueThreshold')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('P-value Threshold', $$currentQueueEnvRef{$keyTerm});
        	}
        	#elsif ($keyTerm eq 'MinPaper')
        	#{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('Minimum Papers', $$currentQueueEnvRef{$keyTerm});
        	#}

        	elsif (($keyTerm eq 'GeneEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene list";
        	}elsif (($keyTerm eq 'GOEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene Ontology";
        	}elsif (($keyTerm eq 'MeSHEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"MeSH term";
        	}elsif (($keyTerm eq 'PathwayEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}$enrichmentTest		.=	"Pathway";
        	}elsif (($keyTerm eq 'PPICheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Protein-Protein Interaction";
        	}elsif ($keyTerm eq 'PPISelection') 
        	{   $ppiSelection		.=	"(PPI Selection: ".$$currentQueueEnvRef{$keyTerm}.')';
        	}
        	
			#  Check for other options
        	elsif ($keyTerm eq 'phenotypeOnlyFilter')
        	{   $otherOption		.= "Remove_phenotype_gene, ";
        	}elsif ($keyTerm eq 'useLengthOption')
        	{   $otherOption		.= "Use_symbol_length_option, ";
        	}elsif ($keyTerm eq 'wordLengthThreshold')
        	{   $otherOption		.= "Always_accept_symbol_longer_than: $$currentQueueEnvRef{$keyTerm}";
        	}
        }
    }
    
    #  Print out sorted query/analysis options
    my @sortedKey	= sort {$a <=> $b} keys %itemContent;
    foreach my $sortedTermKey (@sortedKey)
    {   if (defined $itemContent{$sortedTermKey})
    	{	print RESULT $itemContent{$sortedTermKey};
    	}
    }

	#  Process enrichment options
	if ($enrichmentTest)
    {   if (($ppiSelection) && ($$currentQueueEnvRef{"PPICheck"} =~ /on/i))
    	{	$enrichmentTest	.= $ppiSelection;
    	}
    	print RESULT print_tmpKey_tmpTerm_for_selected_option('Enrichment tests', $enrichmentTest);
    }
    
    
    #  Score Threshold
    if ((defined $$currentQueueEnvRef{useScoreThreshold}) && ($$currentQueueEnvRef{useScoreThreshold}))
    {   print RESULT print_tmpKey_tmpTerm_for_selected_option('Score threshold', $$currentQueueEnvRef{scoreThreshold});
    }
    
    
    #  Process other options
    if ($otherOption)
    {   print RESULT print_tmpKey_tmpTerm_for_selected_option('Other', $otherOption);
    }
    
    
    
    print RESULT "</table>
			<br><br>
            <p class='titleBarName1'><b>Your query/analysis is being processed. Refereshing in 10 seconds<b><br>
            <a href=\"$htmlURL\">$htmlURL</a><br><br><br>
            <a href=\"$SciMinerURL\"><font class=\"sectionTitleName2\">SciMiner Homepage</font></a></p>
            </body>
            </html>";
    
    close RESULT;
}




















sub print_if_not_zero
{	my $value		= shift;
	my $string		= shift;

	if ($value == 0)
	{	return($value);
	}else
	{	return($string);
	}
}



















sub generate_analysis_output_result
{   my $finalResultDir          	= shift;
    my $finalResultWebDir       	= shift;
    my $annoENVRef              	= shift;
    my $currentQueueEnvRef      	= shift;
    my $dbh                     	= shift;
    my $GEStatus                	= shift;
    my $GOStatus                	= shift;
    my $MeSHStatus              	= shift;
    my $PathwayStatus           	= shift;
    my $PPIStatus               	= shift;
    my $tgQueryEnvRef           	= shift;
    my $bgQueryEnvRef           	= shift;
    my $bgNumOfGenes            	= shift;
    my $hugoSymbol2IDRef			= shift;
    my $cssFileName					= shift;
    my $sciminerJScriptFileName		= shift;
    my $symbol2ncbiEntrezGeneIDRef	= shift;
    

    #  Initialize variables
    my $serverBaseURL       = $$annoENVRef{SciMinerServerURL};
    my $serverURL           = $serverBaseURL."SciMiner/FinalResults/$$currentQueueEnvRef{fileNameBase}/";
    my $cssURL				= $cssFileName;
    my $SciMinerURL          = $serverBaseURL."SciMiner/";
    
    my $currentBaseDir		= $$currentQueueEnvRef{fileNameBase};
    my $tgResultBaseDir		= $$currentQueueEnvRef{targetQueryNumber2BaseName};
    my $bgResultBaseDir		= $$currentQueueEnvRef{bgQueryNumber2BaseName};
    
    my $mimiIconURL 		= "../../Images/cytoicon.jpg";

    #  Generate individual result files
    my $resultSummaryHTML       = "$finalResultWebDir/analysisSummary.html";
    my $resultSummaryWebHTML    = "$serverURL/analysisSummary.html";

	my $ImageOpen			= "/SciMiner1.1/SciMiner/Images/open.gif";
	my $ImageClose			= "/SciMiner1.1/SciMiner/Images/closed.gif";
	
    LogAnalysis("!! Started to generate the final analysis result file");
    #  Read the summary file and generate an html file
    open (RESULT, ">".$resultSummaryHTML);
    print RESULT "<head>
                <title>SciMiner Analysis Result Report Page</title>
                <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
                <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
                <script language=\"JavaScript1.2\" src=\"sciminer.js\"></script>
                <style type=\"text/css\"> body {	margin-left:10px;	}</style>
                </head>
                <body bgcolor=\"#EAF4F4\" onload=\"switch_to_simple_mode_on_load()\">
                <script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
                <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Analysis Summary Page</b></p>
                <p class='titleBarName1'> <b>Congratulation! Your analysis with SciMiner has been successfully completed.</b> 
                &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<a href=\"\">[ Display Reset ]</a><br>
                &nbsp;&nbsp;Jump to <a href=\"#GeneEnrichment\">\(Gene Enrichment\)</a>&nbsp;
                        <a href=\"#GOEnrichment\">\(GO Enrichment\)</a>&nbsp;
                        <a href=\"#MeSHEnrichment\">\(MeSH Enrichment\)</a>&nbsp;
                        <a href=\"#PathwayEnrichment\">\(Pathway Enrichment\)</a>&nbsp;
                        <a href=\"#PPIEnrichment\">\(PPI Enrichment\)</a>&nbsp;<br></p>
                
                
                <div class=\"trigger\" onclick=\"showBranch('branchSummary');swapFolder('folderSummary')\">
					<table width=\"100%\" border=\"0\" onmouseover=\"Tip('Click here to hide/show the detail!')\" onmouseout=\"UnTip()\">
						<tr>
							<td width=\"10\">
								<img src=\"$ImageOpen\" id=\"folderSummary\" border=\"0\">
							</td>
							<td>
								<p align=\"center\" class=\"sectionTitleName1\">Analysis Option Summary</p>
							</td>
						</tr>
					</table>
				</div>
				
                <span style=\"display:block;\" class=\"branch\" id=\"branchSummary\">
                <table border=\"1\" width=\"850\">
                ";

    #  -------------------------------------------------------------------------
    # Running condition (options)
    my $bgPrintOut  = 0;
    if ((($$currentQueueEnvRef{GeneEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{GeneEnrichmentSelection} eq 'Selected')) || 
        (($$currentQueueEnvRef{GOEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{GOEnrichmentSelection} eq 'Selected')) || 
        (($$currentQueueEnvRef{MeSHEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{MeSHEnrichmentSelection} eq 'Selected')) ||
        (($$currentQueueEnvRef{PathwayEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{PathwayEnrichmentSelection} eq 'Selected')) || 
        (($$currentQueueEnvRef{PPICheck} eq "on") && ($$currentQueueEnvRef{PPISelection} eq 'Selected')))
    {   $bgPrintOut = 1;
    }

    #  -------------------------------------------------------------------------    
    # Running condition (options)
    my %itemContent		= ();
    my $otherOption		= '';
    my $enrichmentTest	= '';
    my $ppiSelection	= '';
    foreach my $keyTerm (sort(keys %{$currentQueueEnvRef}))
    {   if ((defined $keyTerm) && ($keyTerm ne "") && (defined $$currentQueueEnvRef{$keyTerm}))
        {   if ($keyTerm eq 'queryID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Query ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'analID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Analysis ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'userName')
        	{   $itemContent{1}		=	print_tmpKey_tmpTerm_for_selected_option('User name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'email')
        	{	$itemContent{2}		=	print_tmpKey_tmpTerm_for_selected_option('Email', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Query information
        	elsif ($keyTerm eq 'queryName')
        	{   $itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Query name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'queryString')
        	{   $itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Query string', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'count')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('PMID count #', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Some analysis information
        	elsif ($keyTerm eq 'targetQueryNumber')
        	{   my $additionalString	= "&nbsp;&nbsp;(Name:&nbsp;'$$tgQueryEnvRef{queryName}',&nbsp;# of PMIDs:&nbsp;'$$tgQueryEnvRef{numPMID}',&nbsp;# of genes:&nbsp;'$$tgQueryEnvRef{numGene}')"."&nbsp;&nbsp;(<a href=\"../../$$tgQueryEnvRef{resultURL}\">Result Page</a>)&nbsp;&nbsp;$$currentQueueEnvRef{'MinPaperMethodTG'}&nbsp;($$currentQueueEnvRef{MinTopPaperTG})";
        		$itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Target Query #', $$currentQueueEnvRef{$keyTerm}.$additionalString);
        	}elsif ($keyTerm eq 'bgQueryNumber')
        	{   my $additionalString	= '';
        		if (!$bgPrintOut)
                {   next;
                }else
                { 	$additionalString   = "&nbsp;&nbsp;(Name:&nbsp;'$$bgQueryEnvRef{queryName}',&nbsp;# of PMIDs:&nbsp;'$$bgQueryEnvRef{numPMID}',&nbsp;# of genes:&nbsp;'$$bgQueryEnvRef{numGene}')"."&nbsp;&nbsp;(<a href=\"../../$$bgQueryEnvRef{resultURL}\">Result Page</a>)&nbsp;&nbsp;$$currentQueueEnvRef{'MinPaperMethodBG'}&nbsp;($$currentQueueEnvRef{MinTopPaperBG})";
                }
        		$itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Background Query #', $$currentQueueEnvRef{$keyTerm}.$additionalString);
        	}elsif ($keyTerm eq 'PValueThreshold')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('P-value Threshold', $$currentQueueEnvRef{$keyTerm});
        	}

        	elsif (($keyTerm eq 'GeneEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene list";
        	}elsif (($keyTerm eq 'GOEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene Ontology";
        	}elsif (($keyTerm eq 'MeSHEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"MeSH term";
        	}elsif (($keyTerm eq 'PathwayEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}$enrichmentTest		.=	"Pathway";
        	}elsif (($keyTerm eq 'PPICheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Protein-Protein Interaction";
        	}elsif ($keyTerm eq 'PPISelection') 
        	{   $ppiSelection		.=	"(PPI Selection: ".$$currentQueueEnvRef{$keyTerm}.')';
        	}
        	
			#  Check for other options
        	elsif ($keyTerm eq 'phenotypeOnlyFilter')
        	{   $otherOption		.= "Remove_phenotype_gene, ";
        	}elsif ($keyTerm eq 'useLengthOption')
        	{   $otherOption		.= "Use_symbol_length_option, ";
        	}elsif ($keyTerm eq 'wordLengthThreshold')
        	{   $otherOption		.= "Always_accept_symbol_longer_than: $$currentQueueEnvRef{$keyTerm}";
        	}
        }
    }
    
    #  Print out sorted query/analysis options
    my @sortedKey	= sort {$a <=> $b} keys %itemContent;
    foreach my $sortedTermKey (@sortedKey)
    {   if (defined $itemContent{$sortedTermKey})
    	{	print RESULT $itemContent{$sortedTermKey};
    	}
    }

	#  Process enrichment options
	if ($enrichmentTest)
    {   if (($ppiSelection) && ($$currentQueueEnvRef{"PPICheck"} =~ /on/i))
    	{	$enrichmentTest	.= ' '.$ppiSelection;
    	}
    	print RESULT print_tmpKey_tmpTerm_for_selected_option('Enrichment tests', $enrichmentTest);
    }
    
    #  Process other options
    if ($otherOption)
    {   print RESULT print_tmpKey_tmpTerm_for_selected_option('Other', $otherOption);
    }
    
    
    print RESULT "</table>
			      <br>
					</span>
				  <p>&nbsp;</p>
                  ";

    #  -------------------------------------------------------------------------
    #  GeneEnrichment Result if any
    if ((defined $GEStatus) && ($GEStatus))
    {   if (-f "$finalResultWebDir/GeneEnrichmentResult.txt")
        {   ## Make a link to the file
            #`ln -s $finalResultDir/GeneEnrichmentResult $finalResultWebDir/GeneEnrichmentResult.txt`;
            #`ln -s $finalResultDir/GeneEnrichmentResult $finalResultWebDir/GeneEnrichmentResult.xls`;  
            # Copy the result files
            #`cp $finalResultDir/GeneEnrichmentResult $finalResultWebDir/GeneEnrichmentResult.txt`;
            #`cp $finalResultDir/GeneEnrichmentResult $finalResultWebDir/GeneEnrichmentResult.xls`;              
            `ln -s $finalResultWebDir/GeneEnrichmentResult.txt $finalResultWebDir/GeneEnrichmentResult.xls`;
            mkdir ("$finalResultWebDir/Gene") || print "";
            
            #  Generate selected-gene html files
            shrink_by_hugoID_2_new_html ("$finalResultWebDir/tgHugoIDs.txt", "$$annoENVRef{SciMinerWebPath}FinalResults/$tgResultBaseDir/geneSummary.html",
            							 "$finalResultWebDir/tgHugoIDs.html", "$tgResultBaseDir" );
            shrink_by_hugoID_2_new_html ("$finalResultWebDir/bgHugoIDs.txt", "$$annoENVRef{SciMinerWebPath}FinalResults/$bgResultBaseDir/geneSummary.html",
            							 "$finalResultWebDir/bgHugoIDs.html", "$bgResultBaseDir" );
            
            open (GENE, "$finalResultWebDir/GeneEnrichmentResult.txt");
            open (GENEFULLHTML, ">$finalResultWebDir/GeneEnrichmentResult.html");
            
            my $geneFullHTMLString	= "<head>
                <title>SciMiner Full Gene Enrichment</title>
                <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
                <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
                <script language=\"JavaScript1.2\" src=\"$sciminerJScriptFileName\"></script>
                <style type=\"text/css\"> body {	margin-left:10px;	}</style>
                </head>
                <body bgcolor=\"#EAF4F4\" onload=\"switch_to_simple_mode_on_load()\">
                <script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
                <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Full Gene Enrichment</b></p>
     						
			  	<input type=\"hidden\" name=\"currentBaseDir\" value=\"$currentBaseDir\">
			  	<input type=\"hidden\" name=\"tgResultBaseDir\" value=\"$tgResultBaseDir\">
			  	<input type=\"hidden\" name=\"bgResultBaseDir\" value=\"$bgResultBaseDir\">

			  	<input type=\"hidden\" name=\"listFile\" value=\"\">
			  	<input type=\"hidden\" name=\"listColumnNum\" value=\"3\">
				<input type=\"hidden\" name=\"listColumnName\" value=\"t-\">
				";

            my @top10GeneLine   = ();
            my $lineCnt         = 0;
            my $tgCorpusSize    = 0;
            my $bgCorpusSize    = 0;
            my $tgHugoIDCnt		= 0;
            my $tgHugoIDCntTot	= 0;
            my $bgHugoIDCnt		= 0;
            my $bgHugoIDCntTot	= 0;
            
            while(<GENE>)
            {   my $line = $_;
                $line =~ s/\r|\n//g;
                if ($line =~ /^\#/)
                {   # This is a header line to be skipped
                    next;
                }
                push @top10GeneLine, $line;
                if ($tgCorpusSize == 0)
                {   my @tmpSplit 	= split(/\t/, $line);
                    $tgCorpusSize 	= $tmpSplit[3];
                    $bgCorpusSize 	= $tmpSplit[11];
                    $tgHugoIDCnt	= $tmpSplit[16];
            		$tgHugoIDCntTot	= $tmpSplit[17];
            		$bgHugoIDCnt	= $tmpSplit[18];
            		$bgHugoIDCntTot	= $tmpSplit[19];
                }
                
                $lineCnt++;
            }
            close GENE;
            
            
           
            # Top 10 most gene terms genes
            print RESULT "  <hr>
            				<a name=\"GeneEnrichment\"></a>
            				
            				<div class=\"trigger\" onclick=\"showBranch('branchGene');swapFolder('folderGene')\">
								<table width=\"100%\" border=\"0\" onmouseover=\"Tip('Click here to hide/show the detail!')\" onmouseout=\"UnTip()\">
									<tr>
										<td width=\"10\">
											<img src=\"$ImageClose\" id=\"folderGene\" border=\"0\">
										</td>
										<td>
											<p align=\"center\" class=\"sectionTitleName1\">Target Enrichment</p>
										</td>
									</tr>
								</table>
							</div>
				
						    <span style=\"display:none;\" class=\"branch\" id=\"branchGene\">
						    
            				<p class=\"titleBarName1\">Here is summary of the targets (genes and proteins) from each query (search) result. Please note that <b>Tested set</b> refers to the identified targets from the <b>Target Query</b> and <b>Background set</b> refers to the identified targets from the <b>Background Query</b>. If no background query number is specified above, then the background set is full HUGO gene set (for Gene Ontology terms, pathways, and protein-protein intearctions) and full PubMed (for MeSH terms)<br>
                            	<table border=\"1\" width=\"430\">
                            		<tr class=\"titleBarName1\">
                            			<th width=\"120\">
                            				&nbsp;
                            			</th>
                            			<th width=\"100\" onmouseover=\"Tip('The number of papers in tested or background set.<br>Click the number for more detail.')\" onmouseout=\"UnTip()\">
                            				Corpus size
                            			</th>
                            			<th width=\"150\" onmouseover=\"Tip('The number of total targets originally identified.<br>Click the number for more detail.')\" onmouseout=\"UnTip()\">
                            				# of targets (total)
                            			</th>
                            			<th width=\"150\" onmouseover=\"Tip('The number of targets that are used in this analysis<br>such as by applying minimum number of papers.<br>Click the number for more detail.')\" onmouseout=\"UnTip()\">
                            				# of targets (used)
                            			</th>
                            		</tr>
                            		<tr class=\"titleBarName1\">
                            			<th onmouseover=\"Tip('This corresponds to SciMiner result of the Target Query # above.<br>Click each number for more detail.')\" onmouseout=\"UnTip()\">
                            				Tested set
                            			</th>
                            			<td>
                            				<a href=\"../$tgResultBaseDir/pmidList.html\">$tgCorpusSize</a>
                            			</td>
                            			<td>
                            				<a href=\"../$tgResultBaseDir/geneSummary.html\">$tgHugoIDCntTot</a>
                            			</td>
                            			<td>
                            				<a href=\"tgHugoIDs.html\"><b>$tgHugoIDCnt</b></a>
                            			</td>
                            			
