                    	$bgCorpusSize 	= $tmpSplit[11];
					}else
					{	$tgCorpusSize 	= $tmpSplit[3];
                    	$bgCorpusSize 	= $tmpSplit[8];
					}
                }
                $lineCnt++;
            }
