		        for (my $j=0; $j < scalar @top10PathwayLine; $j++)    
		        {   if (defined $top10PathwayLine[$j])
		            {   # there are legitimate MeSH

		                my @tmpSplit = split (/\t/, $top10PathwayLine[$j]);
