		                {   $tmpPathwayString .= "<a href=\"$keggLinkURL$tmpSplit[0]\">$tmpSplit[0]</a></td><td><a href=\"$keggLinkURL$tmpSplit[0]\">$tmpSplit[1]</a></td>";
		                }else
		                {   $tmpPathwayString .= "<a href=\"$reactomeLinkURL$tmpSplit[0]\">$tmpSplit[0]</a></td><td><a href=\"$reactomeLinkURL$tmpSplit[0]\">$tmpSplit[1]</a></td>";
		                }
		                                    
		                $tmpPathwayString .= "<td>".print_if_not_zero($tmpSplit[3], "<a href=\"javascript:generate_gene_list_html('$tmpSplit[3]', 't_plus', '2', '$currentBaseDir', '$tgResultBaseDir', '$tmpSplit[0]', '$tmpSplit[1]');\">$tmpSplit[3]</a>")."</td><td>";
		                $tmpPathwayString .= print_if_not_zero($tmpSplit[4], "<a href=\"javascript:generate_gene_list_html('$tmpSplit[4]', 't_minus', '3', '$currentBaseDir', '$tgResultBaseDir', '$tmpSplit[0]', '$tmpSplit[1]');\">$tmpSplit[4]</a>")."</td><td>";
		                $tmpPathwayString .= print_if_not_zero($tmpSplit[5], "<a href=\"javascript:generate_gene_list_from_pathway_bminus_html('$tmpSplit[5]', 'b_plus', '7', '$currentBaseDir', '$bgResultBaseDir', '$tmpSplit[0]', '$tmpSplit[1]');\">$tmpSplit[5]</a>")."</td><td>$tmpSplit[6]</td><td>";
		                
						if ($tmpSplit[8] < $$currentQueueEnvRef{PValueThreshold})
						{   $tmpPathwayString .= "<font color=\"red\">".sprintf("%.2e",$tmpSplit[8])."</font>";
