    #  -------------------------------------------------------------------------
    #  PPI Result if any
    if ((defined $PPIStatus) && ($PPIStatus))
    {   #  Read the PPI Result File
        if (-f "$finalResultDir/PPI/TEST.MiMIBase_Network.txt")
        {   # Make a link to the file
            #`ln -s $finalResultDir/PPI/TEST.MiMIBase_Network.txt $finalResultWebDir/PPI/TEST.MiMIBase_Network.txt`;
            #`ln -s $finalResultDir/PPI/TEST.MiMIBase_Network.txt $finalResultWebDir/PPI/TEST.MiMIBase_Network.xls`;        
            #`ln -s $finalResultDir/PPI/TEST.MiMIBase_Network.sif $finalResultWebDir/PPI/TEST.MiMIBase_Network.sif`;
			
			`cp $finalResultDir/PPI/TEST.MiMIBase_Network.txt $finalResultWebDir/PPI/TEST.MiMIBase_Network.txt`;
            `cp $finalResultDir/PPI/TEST.MiMIBase_Network.txt $finalResultWebDir/PPI/TEST.MiMIBase_Network.xls`;        
            `cp $finalResultDir/PPI/TEST.MiMIBase_Network.sif $finalResultWebDir/PPI/TEST.MiMIBase_Network.sif`;
            open (PPI, "$finalResultDir/PPI/TEST.MiMIBase_Network.txt");

            my $tgGeneWithAnyInt    = 0;
            my $tgDirectInteraction = 0;
            my $tgGeneWithinNet     = 0;
            my $tgMaxDegreeGene     = '';
            my $tgMaxDegreeCnt      = 0;
            my $tgMinDegreeGene     = '';  
            my $tgMinDegreeCnt      = 0;

			my $tgCorpusSize		= 0;
		    my $bgCorpusSize		= 0;
		    my $tgHugoIDCnt			= 0;
		    my $tgHugoIDCntTot		= 0;
		    my $bgHugoIDCnt			= 0;
		    my $bgHugoIDCntTot		= 0;
		    
		    #  Load the PPIIDSummary file for ID counts
		    if (-f "$finalResultDir/PPI/PPIIDSummary")
		    {	open (PPIIDSummary, "$finalResultDir/PPI/PPIIDSummary") || LogAnalysis("!!!!! PPIIDSummary couldnot be loaded.");
		    	my $tmpLine		= <PPIIDSummary>;
		    	$tmpLine		=~ s/\r|\n//g;
		    	my @tmpSplit	= split(/\t/, $tmpLine);
		    	$tgCorpusSize	= $tmpSplit[0];
				$bgCorpusSize	= $tmpSplit[1];
				$tgHugoIDCnt	= $tmpSplit[2];
				$tgHugoIDCntTot	= $tmpSplit[3];
				$bgHugoIDCnt	= $tmpSplit[4];
				$bgHugoIDCntTot	= $tmpSplit[5];
		    	close PPIIDSummary;
		    }
        
        
            my @top10PPILine   = ();
            my $lineCnt         = 0;
            #my $tgCorpusSize    = 0;
            #my $bgCorpusSize    = 0;
            while(<PPI>)
            {   my $line = $_;
                $line =~ s/\r|\n//g;
                if ($line =~ /^\#/)
                {   if ($line =~ /^\#(\S+)\s+(\d+)/)
                    {   my $headerType  = $1;
                        my $tmpCount    = $2;
                        if ($headerType eq 'Genes_With_Any_Interaction')
                        {   $tgGeneWithAnyInt       = $tmpCount;
                        }elsif ($headerType eq 'Genes_With_Interaction_Within_Set')
                        {   $tgGeneWithinNet        = $tmpCount;
                        }elsif ($headerType eq 'Interactions_Within_Set')
                        {   $tgDirectInteraction    = $tmpCount;
                        }
                    }elsif ($line =~ /^\#Max_Degree\s+(\S+)\s+(\d+)/)
                    {   $tgMaxDegreeGene        = $1;
                        $tgMaxDegreeCnt         = $2;
                    }elsif ($line =~ /^\#Min_Degree\s+(\S+)\s+(\d+)/)
                    {   $tgMinDegreeGene        = $1;
                        $tgMinDegreeCnt         = $2;
                    }
                }else
                {   push @top10PPILine, $line;
                    if ($lineCnt == 9)
                    {   last;
                    }
                    $lineCnt++;
                }
            }
            close PPI;
            
            

            # Top 10 most PPI Genes
			my $compStatus			= 1;
