                                    <th width=\"300\">Num of genes (total)</th>
                                    <td width=\"200\">$$tgQueryEnvRef{numGene}</td>
                                </tr>
                                
                                <tr class=\"titleBarName1\" onmouseover=\"Tip('<b>Num of targets (used)</b>: The number of targets that were used in this analysis after filtering if any was used')\" onmouseout=\"UnTip()\">
