                                    <td width=\"200\">$tgHugoIDCnt</td>
                                </tr>
                                <tr class=\"titleBarName1\" onmouseover=\"Tip('<b>Num of targets with any interaction</b>: The number of targets that have <b>ANY</b> interaction data available from the MiMI database.')\" onmouseout=\"UnTip()\">
