                                    <td width=\"200\">$tgGeneWithAnyInt</td>
                                </tr>
                                <tr class=\"titleBarName1\" onmouseover=\"Tip('<b>Num of targets interacting within corpus</b>: The number of targets that have directly interacting partners whitin the test set.')\" onmouseout=\"UnTip()\">
                                    <th width=\"300\">&nbsp;Num of targets interacting within corpus</th>
                                    <td width=\"200\">&nbsp;$tgGeneWithinNet</td>
                                </tr>
                                <tr class=\"titleBarName1\" onmouseover=\"Tip('<b>Num of direct interaction within corpus</b>: The number of interactions among the targets from the test set.')\" onmouseout=\"UnTip()\">
                                    <th width=\"300\">&nbsp;Num of direct interaction within corpus</th>
                                    <td width=\"200\">&nbsp;$tgDirectInteraction</td>
                                </tr>
                                <tr class=\"titleBarName1\" onmouseover=\"Tip('<b>Maximum degree target</b>: The target with the biggest number of directly interacting partners (among the test set).')\" onmouseout=\"UnTip()\">
                                    <th width=\"300\">Maximum degree target</th>";
			if (defined $$hugoSymbol2IDRef{$tgMaxDegreeGene})
            {   print RESULT "<td width=\"200\">&nbsp;<a href=\"$hgncLinkURL$$hugoSymbol2IDRef{$tgMaxDegreeGene}\">$tgMaxDegreeGene</a>&nbsp;&nbsp;&nbsp;(Degree&nbsp;=&nbsp;$tgMaxDegreeCnt)</td>";            
            }else
            {   print RESULT "<td width=\"200\">&nbsp;$tgMaxDegreeGene&nbsp;&nbsp;&nbsp;(Degree&nbsp;=&nbsp;$tgMaxDegreeCnt)</td>";            
            }
            print RESULT "	</tr>
                                <tr class=\"titleBarName1\" onmouseover=\"Tip('<b>Minimum degree target</b>: The target with the lowest number of directly interacting partners (among the test set).')\" onmouseout=\"UnTip()\">
                                    <th width=\"300\">Minimum degree target</th>";
                                    
			if (defined $$hugoSymbol2IDRef{$tgMinDegreeGene})
            {   print RESULT "<td width=\"200\">&nbsp;<a href=\"$hgncLinkURL$$hugoSymbol2IDRef{$tgMinDegreeGene}\">$tgMinDegreeGene</a>&nbsp;&nbsp;&nbsp;(Degree&nbsp;=&nbsp;$tgMinDegreeCnt)</td>";            
            }else
            {   print RESULT "<td width=\"200\">&nbsp;$tgMinDegreeGene&nbsp;&nbsp;&nbsp;(Degree&nbsp;=&nbsp;$tgMinDegreeCnt)</td>";            
            }                    
                                    
			print RESULT "	</tr>
                            </table>
                            <br>
