                                    <th width=\"50\">&nbsp;Rank</th>
                                    <th width=\"150\">&nbsp;Target Symbol</th>
                                    <th width=\"200\">&nbsp;Num of Direct Interactions</th>
                                    <th width=\"100\" onmouseover=\"Tip('Click here to view the interacting partners in Cytoscape. <br><br>Note that this link will show <b>any known</b> interacting partnets and not limited to the targets in the test set.<br><br>If you want to see the interactions only within the current test set,<br><b>download</b> Merged network(SIF(MiMI Network File)) below, and <b>IMPORT</b> the downloaded SIF file in your Cytoscape.')\" onmouseout=\"UnTip()\">&nbsp;MiMI Network</th>
                                </tr>";
                               
            for (my $j=0; $j <10; $j++)    
            {   if (defined $top10PPILine[$j])
                {   # there are legitimate genes
                    my @tmpSplit = split (/\t/, $top10PPILine[$j]);
                    
                    print RESULT "  <tr>
                                        <td width=\"50\">&nbsp;".($j+1)."</td>
                                        <td width=\"150\">&nbsp;<a href=\"$hgncLinkURL";
                    if (defined $$hugoSymbol2IDRef{$tmpSplit[0]})
                    {   print RESULT $$hugoSymbol2IDRef{$tmpSplit[0]};
                    }else
                    {   print RESULT $tmpSplit[0];
                    }
                    
                    print RESULT "\">$tmpSplit[0]</a></td>
                                        <td width=\"200\">&nbsp;$tmpSplit[1]</td>";
                    if ((defined $$symbol2ncbiEntrezGeneIDRef{$tmpSplit[0]}) && ($$symbol2ncbiEntrezGeneIDRef{$tmpSplit[0]} ne ""))
                    {	print RESULT "<td width=\"100\">&nbsp;<a href=\"$mimiNameLink$$symbol2ncbiEntrezGeneIDRef{$tmpSplit[0]}\" onmouseover=\"Tip('Click here to view the interacting partners of <b>$tmpSplit[0]</b> in Cytoscape. <br><br>Note that this link will show <b>any known</b> interacting partnets and not limited to the targets in the test set.<br><br>If you want to see the interactions only within the current test set,<br><b>download</b> Merged network(SIF(MiMI Network File)) below, and <b>IMPORT</b> the downloaded SIF file in your Cytoscape.')\" onmouseout=\"UnTip()\"><img src=\"$mimiIconURL\"></a></td>";
                    }else
                    {	print RESULT "<td width=\"100\">&nbsp;</td>";
                    }
                    print RESULT "
                                    </tr>";
                }else
                {   print RESULT "<tr>
                                    <td width=\"50\">
                                        ".($j+1)."
                                    </td>
