                `cp $finalResultDir/PPI/SigTest.2.jpg $finalResultWebDir/PPI/SigTest.2.jpg`;        
                `cp $finalResultDir/PPI/SigTest.3.jpg $finalResultWebDir/PPI/SigTest.3.jpg`;        
                `cp $finalResultDir/PPI/SigTest.4.jpg $finalResultWebDir/PPI/SigTest.4.jpg`;  
                 
                print RESULT "  <p align=\"center\" class=\"sectionTitleName2\">Network Significance Test (100 iteration of random genes with size of <b>$$tgQueryEnvRef{numGene}</b> from total of <b>$bgNumOfGenes</b> genes)</p>
                				<p class=\"titleBarName1\">
                					This <b>Network Significance Test</b> section will test the integrity of the Protein-Protein Interaction network among the test set targets. This is based on the assumption that targets commonly related to a certain topic will be more likely to have frequent protein-protein interaction with each others. Therefore, if a set of targets identified by text-mining (SciMiner) from a certain query have more frequent direct interactions among the targets compared to randomly generated sets, it can, in part, support the validity of using text-mining method to identify related targets from a set of related papers. <b>100</b> random network of the same number of target in the test set will be generated from the background set. The test set had <b>$$tgQueryEnvRef{numGene}</b> targets. Thus $$tgQueryEnvRef{numGene} are randomly selected from the background which had a total of <b>$bgNumOfGenes</b> targets. If the background set was <b>full HUGO</b> set, all the targets will have an equal chance of being selected. If the background set was either <b>Selected background above</b> or <b>Whole document in SciMinerDB</b>, the probability of each target begin selected is determined by the <b>observed frequency</b> of each target as in (# of papers with the target / # of all papers).Two statistical measures are given below; standard Z-test and one-sample T-test. 
                				</p>
                                <table border=\"1\">
                                    <tr class=\"titleBarName1\">
                                        <th width=\"80\">&nbsp;</th>
                                        <th width=\"180\" onmouseover=\"Tip('<b>Targets with any interaction</b>: The number of targets with ANY known interaction data from the MiMI database. The interactions are NOT limited to the targets in the set.')\" onmouseout=\"UnTip()\">
                                        	Targets with any interaction
                                        </th>
                                        <th width=\"200\" onmouseover=\"Tip('<b>Targets interacting within corpus</b>: The number of targets interacting with other targets in the tested set.')\" onmouseout=\"UnTip()\">
                                        	Targets interacting within corpus
                                        </th>
                                        <th width=\"200\" onmouseover=\"Tip('<b>Direct interactions within corpus</b>: The number of direct interations among the targets in the tested set.')\" onmouseout=\"UnTip()\">
                                        	Direct interactions within corpus
                                        </th>
                                        <th width=\"100\" onmouseover=\"Tip('<b>Max degree</b>: The maximal degree in the network of the targets in the tested set.')\" onmouseout=\"UnTip()\">
                                        	Max degree
                                        </th>
                                    </tr>";
                open (STAT, "$finalResultDir/PPI/SigTest.ZTStat.txt");
                my @statLines = ();
                while(<STAT>)
                {   my $line = $_;
                    $line =~ s/\r|\n//g;
                    push @statLines, $line;
                }
                close STAT;



                if (defined $statLines[0])
                {   my @tmpSplit = split (/\t/, $statLines[0]);
                    print RESULT "<tr class=\"titleBarName1\" style=\"background-color:#BDF9DC;\" onmouseover=\"Tip('<b>Tested</b>: The values from your selected <b>tested</b> set. SciMiner query #$$tgQueryEnvRef{queryName}')\" onmouseout=\"UnTip()\">
                                        <th>Tested</th>
