                                        <td><b>$tmpSplit[3]</b></td>
                                  </tr>";
                }
                
                if (defined $statLines[1])
                {   my @tmpSplit = split (/\t/, $statLines[1]);
                    print RESULT "<tr class=\"titleBarName1\" onmouseover=\"Tip('<b>Mean</b>: The mean value of the 100 random networks')\" onmouseout=\"UnTip()\">
                                        <th>Mean</th>
                                        <td>".sprintf("%.2f", $tmpSplit[0])."</td>
                                        <td>".sprintf("%.2f", $tmpSplit[1])."</td>
                                        <td>".sprintf("%.2f", $tmpSplit[2])."</td>
                                        <td>".sprintf("%.2f", $tmpSplit[3])."</td>
                                  </tr>";
                }

                if (defined $statLines[2])
                {   my @tmpSplit = split (/\t/, $statLines[2]);
                    print RESULT "<tr class=\"titleBarName1\" onmouseover=\"Tip('<b>STDEV</b>: The standard deviation of the 100 random networks')\" onmouseout=\"UnTip()\">
                                        <th>STDEV</th>
                                        <td>".sprintf("%.2f", $tmpSplit[0])."</td>
                                        <td>".sprintf("%.2f", $tmpSplit[1])."</td>
                                        <td>".sprintf("%.2f", $tmpSplit[2])."</td>
                                        <td>".sprintf("%.2f", $tmpSplit[3])."</td>
                                  </tr>";
                }
                
                
                #  Color codes
                #	DBD1DA	light violet
                #	DAF5CE	light green
                #	BDF9DC	light blue
                #	F8F9BD	light yellow
                
                if (defined $statLines[3])
                {   my @tmpSplit = split (/\t/, $statLines[3]);
                    print RESULT "<tr class=\"titleBarName1\" style=\"background-color:#DBD1DA;\" onmouseover=\"Tip('<b>Z-Score</b>: The standard z-score of the test set value in a distribution of the 100 random network samples.')\" onmouseout=\"UnTip()\">
                                        <th>Z-Score</th>
                                        <td>".sprintf("%.1f", $tmpSplit[0])."</td>
                                        <td>".sprintf("%.1f", $tmpSplit[1])."</td>
                                        <td>".sprintf("%.1f", $tmpSplit[2])."</td>
                                        <td>".sprintf("%.1f", $tmpSplit[3])."</td>
                                  </tr>";
                }
                
                if (defined $statLines[4])
                {   my @tmpSplit = split (/\t/, $statLines[4]);
                    print RESULT "<tr class=\"titleBarName1\" style=\"background-color:#DBD1DA;\" onmouseover=\"Tip('<b>P-value(Z)</b>: The probability of seeing the above Z-score or higher from the distribution of the 100 random network samples.')\" onmouseout=\"UnTip()\">
                                        <th>P-value(Z)</th>
                                        <td>".simple_pvalue_two_format ($tmpSplit[0], $$currentQueueEnvRef{PValueThreshold})."</td>
                                        <td>".simple_pvalue_two_format ($tmpSplit[1], $$currentQueueEnvRef{PValueThreshold})."</td>
                                        <td>".simple_pvalue_two_format ($tmpSplit[2], $$currentQueueEnvRef{PValueThreshold})."</td>
                                        <td>".simple_pvalue_two_format ($tmpSplit[3], $$currentQueueEnvRef{PValueThreshold})."</td>
                                  </tr>";
                }
 
                if (defined $statLines[5])
                {   my @tmpSplit = split (/\t/, $statLines[5]);
                    print RESULT "<tr class=\"titleBarName1\" style=\"background-color:#F8F9BD;\" onmouseover=\"Tip('<b>T-Stat</b>: The one-sample T-statistics of the test set value in a distribution of the 100 random network samples.')\" onmouseout=\"UnTip()\">
                                        <th>T-Stat</th>
                                        <td>".sprintf("%.1f", $tmpSplit[0])."</td>
                                        <td>".sprintf("%.1f", $tmpSplit[1])."</td>
                                        <td>".sprintf("%.1f", $tmpSplit[2])."</td>
                                        <td>".sprintf("%.1f", $tmpSplit[3])."</td>
                                  </tr>";
                }
                
                if (defined $statLines[6])
                {   my @tmpSplit = split (/\t/, $statLines[6]);
                    print RESULT "<tr class=\"titleBarName1\" style=\"background-color:#F8F9BD;\" onmouseover=\"Tip('<b>P-value(T)</b>: You can reject the numm hypothesis that the tested value is not different from the sample mean where p-value < significance level.')\" onmouseout=\"UnTip()\">
                                        <th>P-value(T)</th>
                                        <td>".simple_pvalue_two_format ($tmpSplit[0], $$currentQueueEnvRef{PValueThreshold})."</td>
                                        <td>".simple_pvalue_two_format ($tmpSplit[1], $$currentQueueEnvRef{PValueThreshold})."</td>
                                        <td>".simple_pvalue_two_format ($tmpSplit[2], $$currentQueueEnvRef{PValueThreshold})."</td>
                                        <td>".simple_pvalue_two_format ($tmpSplit[3], $$currentQueueEnvRef{PValueThreshold})."</td>
                                  </tr>";
                }               

                print RESULT "</table><br>";
				
				
				#                <p class=\"titleBarName1\">Summary file <a href=\"$serverURL/PPI/SigTest.ZTStat.txt\"> (TXT, </a>&nbsp;&nbsp;
                #                        <a href=\"PPI/SigTest.ZTStat.xls\"> EXCEL) </a><br>
                #              Randomization data <a href=\"$serverURL/PPI/SigTest.txt\"> (TXT, </a>&nbsp;&nbsp;
                #                        <a href=\"PPI/SigTest.xls\"> EXCEL) </a>
                #              </p>
                
                print RESULT "
                                        <p align=\"center\" class=\"sectionTitleName2\">Distrubution of randomly generated networks</p>
                                        <p class=\"smallText3\">
                					This section will histograms of the random network samples. <b><font color=\"red\">Red bars</font> represent the targets from the <b>tested set (target query)</b> being tested.<br>
                				
                                        <table border=\"1\" width=\"1200\">
                                            <tr>
                                                <th width=\"300\" onmouseover=\"Tip('<b>Targets with any interaction</b>: The number of targets with ANY known interaction data from the MiMI database. The interactions are NOT limited to the targets in the set.')\" onmouseout=\"UnTip()\">Targets with any interaction</th>
                                                <th width=\"300\" onmouseover=\"Tip('<b>Targets interacting within corpus</b>: The number of targets interacting with other targets in the tested set.')\" onmouseout=\"UnTip()\">Targets interacting within corpus</th>
                                                <th width=\"300\" onmouseover=\"Tip('<b>Direct interactions within corpus</b>: The number of direct interations among the targets in the tested set.')\" onmouseout=\"UnTip()\">Direct interactions within corpus</th>
                                                <th width=\"300\" onmouseover=\"Tip('<b>Max degree</b>: The maximal degree in the network of the targets in the tested set.')\" onmouseout=\"UnTip()\">Max degree</th>
                                            </tr>
                                            <tr>
                                                <td width=\"300\" onmouseover=\"Tip('<b>Targets with any interaction</b>: The number of targets with ANY known interaction data from the MiMI database. The interactions are NOT limited to the targets in the set.')\" onmouseout=\"UnTip()\">&nbsp;<a href=\"PPI/SigTest.1.jpg\"><img src=\"PPI/SigTest.1.jpg\" width=280 height=300></a></td>
                                                <td width=\"300\" onmouseover=\"Tip('<b>Targets interacting within corpus</b>: The number of targets interacting with other targets in the tested set.')\" onmouseout=\"UnTip()\"><a href=\"PPI/SigTest.2.jpg\"><img src=\"PPI/SigTest.2.jpg\" width=280 height=300></a></td>
                                                <td width=\"300\" onmouseover=\"Tip('<b>Direct interactions within corpus</b>: The number of direct interations among the targets in the tested set.')\" onmouseout=\"UnTip()\"><a href=\"PPI/SigTest.3.jpg\"><img src=\"PPI/SigTest.3.jpg\" width=280 height=300></a></td>
                                                <td width=\"300\" onmouseover=\"Tip('<b>Max degree</b>: The maximal degree in the network of the targets in the tested set.')\" onmouseout=\"UnTip()\"><a href=\"PPI/SigTest.4.jpg\"><img src=\"PPI/SigTest.4.jpg\" width=280 height=300></a></td>
                                                                                                                                  
                                            </tr>
                                        </table>
                                        <a href=\"#TOP\">Back to top</a>&nbsp;</p>";
            }else
            {   print RESULT "<p class=\"smallText3\">!NOTE: Random network generation could not be completed. <br>
            				  Possible reasons could be 1) too small size of targets 2) missing target in the background set.</p>";
            }
            
            print RESULT "</span>
			             ";
        }
    }
    
    
    print RESULT "<p>&nbsp;</p>
            <p class=\"titleBarName1\"><a href=\"$SciMinerURL\"><font class=\"sectionTitleName2\">SciMiner Homepage</font></a></p>
            </body>
            </html>";
    
    close RESULT;
    
    # copy the result file to the web server 
