sub simple_pvalue_two_format
{	my $value		= shift;
	my $threshold	= shift;
	
	if ($value < $threshold)
	{	return ("<font color=\"red\">".sprintf("%.1e", $value).'&nbsp;('.sprintf("%.3f", $value).')'."</font>");
	}else
	{	return (sprintf("%.1e", $value).'&nbsp;('.sprintf("%.3f", $value).')');
	}
}   












































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































# ------------------------------------------------------------------------------
#
#
#                   process_current_query_queue
#
#
# ------------------------------------------------------------------------------
sub process_current_query_queue
{   my $pname							= 'SciMiner_v2.2';
    my $corpusRefetchOption				= 0;
    my $cssFileName						= 'sciminer-modern.css';
    my $sciminerJScriptFileName			= 'sciminer.js';
	my $tooltipScriptFileName			= 'wz_tooltip.js';
	
    #  Load working environment for ANNOTATION
    my %annoENV = anno_environmental_file_open ( );
    my $annoBaseDir = $annoENV{ANNOPath};

	#  MeSH tree/dist file names
	my $MeSHTreeFile	= "$annoENV{SciMinerPath}/Work/MeSH/mtrees2008.bin";
	my $MeSHDistFile	= "$annoENV{SciMinerPath}/Work/MeSH/NCIBIDBXMeSHDistExplicit.txt";
	
    #  Initialize variables, hashes, arrays
    my $currentQueue                    = '';
    my $CorpusReserviorOriginalDoc      = "$annoENV{SciMinerPath}/CorpusData/Original/";
    my $CorpusReserviorProcessedDoc     = "$annoENV{SciMinerPath}/CorpusData/Processed/";
    my $CorpusReserviorTmpOriginalDoc   = "$annoENV{SciMinerPath}/CorpusData/TmpOriginal/";
    my $CorpusReserviorTmpProcessedDoc  = "$annoENV{SciMinerPath}/CorpusData/TmpProcessed/";
    my $fileCopyRequired				= 1;
    
    #  Read the 'CurrentQueue' file
    open (QUEUE, "$annoENV{SciMinerPath}/Work/CurrentQueue" ) || return (-1, "No Queue file");
    $currentQueue   = <QUEUE>;
    $currentQueue   =~ s/\r|\n//g;
    close (QUEUE);
    
    #  Read the current PMID list from queued file
    my @confFileList    = glob ("$annoENV{SciMinerPath}/Work/Query_".$currentQueue."__*.conf");
    my @listFileList    = glob ("$annoENV{SciMinerPath}/Work/Query_".$currentQueue."__*.list");
    my %currentQueueEnv = ();
    my @PMIDList        = ();
    
    open (CONF, $confFileList[0]);
    while(<CONF>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        my @tmpSplit = split (/\t/, $line);
        $currentQueueEnv{$tmpSplit[0]} = $tmpSplit[1];
    }
    close (CONF);
    
    
    # Reset the current URL from the configuration
    if (defined $currentQueueEnv{SciMinerServerURL})
    {   $annoENV{SciMinerServerURL}	= $currentQueueEnv{SciMinerServerURL};
    }
    
   
    open (LIST, $listFileList[0]);
    while(<LIST>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        push @PMIDList, $line;
    }
    close (LIST);
    
    
    #  Mark the starting of the query process
   	LogQuery("~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~");
    LogQuery("--- Processing Query_$currentQueue is initiated!");
 
    #  Generate PMID list string for DB Query
    my $pmidFull    = join (',', @PMIDList);
        
    #  Final Result Directory
    my @nameSplit1          = split (/\//, $confFileList[0]);
    my @nameSplit2          = split (/\.conf/, $nameSplit1[$#nameSplit1]);
    my $finalResultDir      = "$annoENV{SciMinerPath}Work/FinalResults/$nameSplit2[0]/";
    my $finalResultWebDir   = "$annoENV{SciMinerWebPath}FinalResults/$nameSplit2[0]/";
    mkdir ("$annoENV{SciMinerPath}Work/FinalResults/") || print "";
    mkdir ($finalResultDir) || print "";
    mkdir ("$annoENV{SciMinerWebPath}FinalResults/") || print "";
    mkdir ($finalResultWebDir) || print "";
    

	#  Copy the PMID list file to the web result directory
	LogQuery("~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~");
	`cp $annoENV{SciMinerPath}/Work/$nameSplit2[0].list $finalResultWebDir/$nameSplit2[0]_list.txt`;
	LogQuery("PMID list file at $annoENV{SciMinerPath}Work/$nameSplit2[0].list");
	LogQuery("Configuration  at $finalResultWebDir/$nameSplit2[0]_list.txt");
	    
    #  -------------------------------------------------------------------------
    #  Generate temporary result html file
    #  -------------------------------------------------------------------------
#    generate_temporary_result_html ("$annoENV{SciMinerServerURL}/SciMiner/FinalResults/$nameSplit2[0]/result.html",
#                                    "$finalResultDir/result.html",
#                                    \%currentQueueEnv, 
#                                    "$annoENV{SciMinerServerURL}/SciMiner/");
#    `ln -s $finalResultDir/result.html $finalResultWebDir/result.html`;

    #generate_temporary_result_html ("$annoENV{SciMinerServerURL}/SciMiner/FinalResults/$nameSplit2[0]/result.html",
    #                                "$finalResultWebDir/result.html",
    #                                \%currentQueueEnv, 
    #                                "$annoENV{SciMinerServerURL}/SciMiner/");
    #`cp -f $finalResultDir/result.html $finalResultWebDir/result.html`;
    
    #  Copy css and java script file to the final result directory
    `cp /home/hurlab/apache-tomcat-9.0.37/webapps/SciMiner1.1/css/sciminer-modern.css $finalResultWebDir/`;
    `cp $annoENV{SciMinerWebPath}/$sciminerJScriptFileName $finalResultWebDir/`;
	`cp $annoENV{SciMinerWebPath}/$tooltipScriptFileName $finalResultWebDir/`;
	    
    #  Copy the Image directory
    `cp -R $annoENV{SciMinerWebPath}/Images $finalResultWebDir/`;

    #  Connect to the SciMiner DB
    my $SciMinerDB   = "DBI:mysql:database=".$annoENV{DB} || return (-1, "!ERROR: No database specified");
    my $username    = $annoENV{username} || return (-1, "!ERROR: No username specified");
    my $password    = $annoENV{password} || return (-1, "!ERROR: No password specified");
    my $dbh = DBI->connect($SciMinerDB, $username, $password, {PrintError => 0});
    if (!$dbh) {
        warn "Could not open database: " . ($DBI::errstr || 'unknown error');
        return (-1, "!ERROR: Couldn't connect to database " . ($DBI::errstr || 'unknown error'));
    }


    #  Update Query table current status of the db
    $dbh->do("UPDATE query SET dateStart=curdate(), timestampStart=curtime(), status=2 WHERE queryID = $currentQueue");

	
    #  Retrieve the status of documents 
    my %pmid2docID              = ();
    my %docID2pmid              = ();
    my %docID2medline           = ();
    my %docID2medlineSize       = ();
    my %docID2html              = ();
    my %pmid2htmlSize           = ();
    my %docID2htmlStatus        = ();
    my %docID2statusProcessed   = ();
    my %docID2statusMined       = ();
    my %pmid2Title              = ();
    my %pmid2Abstract           = ();
    my %pmid2lang               = ();
    my %pmid2journal			= ();
    my $sql = "SELECT docID, pmid, medline, medlineSize, html, htmlSize, statusProcessed, statusMined, title, abstract, lang, journal
               FROM document
               WHERE pmid in ($pmidFull)";
    my $sth = $dbh->prepare($sql);
    my @row = ();
    $sth->execute();
        
    while(@row = $sth->fetchrow_array)
    {   if (defined $row[1])
        {   $pmid2docID{$row[1]}            = $row[0];
            $docID2pmid{$row[0]}            = $row[1];
            $docID2medline{$row[0]}         = $row[2];
            $docID2medlineSize{$row[0]}     = $row[3];
            $docID2html{$row[0]}            = $row[4];
            $pmid2htmlSize{$row[1]}         = $row[5];
            $docID2statusProcessed{$row[0]} = $row[6];            
            $docID2statusMined{$row[0]}     = $row[7];
            $pmid2Title{$row[1]}            = $row[8];
            $pmid2Abstract{$row[1]}         = $row[9];
            $pmid2lang{$row[1]}             = $row[10];
            $pmid2journal{$row[1]}          = $row[11];

        }else
        {   # Skip this line, since we need pmid
        }
    }
    
    
   	#  Retrieve ncbiEntrezGeneID and hugoID
   	$sql	= "SELECT approvedSymbol, entrezGeneIDMappedData from gene";
	$sth	= $dbh->prepare($sql); 
	$sth->execute();
	
	my %symbol2ncbiEntrezGeneID				= ();
	while(@row = $sth->fetchrow_array)
    {   if (defined $row[1])
        {   if ($row[1] !~ /[\,| ]/)
        	{	$symbol2ncbiEntrezGeneID{$row[0]}	= $row[1];
        	}else
        	{	$symbol2ncbiEntrezGeneID{$row[0]}	= "";
        	}
        }else
        {   # Skip this line, since we need pmid
        }
    }
	
    #  Create a list of PMID to be fetched and processed
    my @medlinePMIDToBeFetched  = ();
    my @htmlPMIDToBeFetched     = ();
    my @PMIDToBeProcessed       = ();
    my @PMIDToBeMined           = ();
    my @PMIDNotToBeReMined      = ();
    
    
    
    for (my $i=0; $i <= $#PMIDList; $i++)
    {   if (not defined $pmid2docID{$PMIDList[$i]})
        {   #  This is new pmid. Fetch both medline and html
            push @medlinePMIDToBeFetched, $PMIDList[$i];
            push @htmlPMIDToBeFetched, $PMIDList[$i];
            push @PMIDToBeProcessed, $PMIDList[$i];    
            push @PMIDToBeMined, $PMIDList[$i];        
        }else
        {   #  This has been found in SciMinerDB.
            if ($docID2statusMined{$pmid2docID{$PMIDList[$i]}} == 1)
            {   #  This record has been fully processed and mined.
                #  TODO: Add here codes for mined but fetching should be done again. 
                #  TODO: 
                push @PMIDNotToBeReMined, $PMIDList[$i];
            }elsif ($docID2statusMined{$pmid2docID{$PMIDList[$i]}} == 0)
            {   #  This record has not been mined yet.
                if ($docID2statusProcessed{$pmid2docID{$PMIDList[$i]}} == 1 )
                {   #  This record has been processed but not mined
                    push @PMIDToBeMined, $PMIDList[$i];
                    #push @PMIDToBeProcessed, $PMIDList[$i];
                    
                }elsif ($docID2statusProcessed{$pmid2docID{$PMIDList[$i]}} == 0)
                {   #  This record has not been processed.
                    push @PMIDToBeMined, $PMIDList[$i];
                    push @PMIDToBeProcessed, $PMIDList[$i];
                    
                    #  Check if MEDLINE has been fetched
                    if (! $docID2medline{$pmid2docID{$PMIDList[$i]}})
                    {   #  MEDLINE record has not been downloaded
                        push @medlinePMIDToBeFetched, $PMIDList[$i];
                    }
                    
                    # ----------------------------------------------------------
                    #  docID2html code
                    # ----------------------------------------------------------
                    #   1   :   success
                    #   2   :   pdf (skipped)
                    #   3   :   no link was found
                    #   4   :   there is link but failed to fetch
                    #   5   :   there was an error in checking the link
                    #   0   :   not tried yet
                    #
                    #   Thus, code 4,5, and 0 should be regularily re-tried
                    #  Check if HTML has been fetched
                    if ($docID2html{$pmid2docID{$PMIDList[$i]}} == 1)
                    {   #  MEDLINE record has been successfully downloaded
                    }elsif ($docID2html{$pmid2docID{$PMIDList[$i]}} == 2)
                    {   #  This PMID has a PDF file in external link
                    }elsif ($docID2html{$pmid2docID{$PMIDList[$i]}} == 3)
                    {   #  There was no proper link to HTML
                    }elsif ($docID2html{$pmid2docID{$PMIDList[$i]}} == 4)
                    {   #  There is a link but failed to fetch in the previous attempt
                        push @htmlPMIDToBeFetched, $PMIDList[$i];
                    }elsif ($docID2html{$pmid2docID{$PMIDList[$i]}} == 5)
                    {   #  There was an error in checking the link itserlf
                        push @htmlPMIDToBeFetched, $PMIDList[$i];
                    }elsif ($docID2html{$pmid2docID{$PMIDList[$i]}} == 0)
                    {   #  Either error in downloading HTML or no HTML
                        push @htmlPMIDToBeFetched, $PMIDList[$i];
                    }
                }
            }
        }
    }
    
    # Printout pmids to be processed and mined
    #foreach (@medlinePMIDToBeFetched)
    #{   LogQuery("medline to be fetched $_");
    #}
    #foreach (@htmlPMIDToBeFetched)
    #{   LogQuery("html to be fetched $_");
    #}

    if (not defined $PMIDToBeMined[0])
    {   LogQuery("! NOTE: There is no PMID to be mined. Just create a summary.");
    }
    
    #  Clearing tmpCorpusDirectory
    `rm -Rf $CorpusReserviorTmpOriginalDoc`;
    `rm -Rf $CorpusReserviorTmpProcessedDoc`;    
    mkdir ($CorpusReserviorTmpOriginalDoc) || print "";
    mkdir ($CorpusReserviorTmpProcessedDoc) || print "";


    
    
    
    
    my $numToBeFetched = scalar @medlinePMIDToBeFetched;
    LogQuery("! # of documents TO BE FETCHED/PROCESSED : $numToBeFetched");
    my $numToBeMined = scalar @PMIDToBeMined;
    LogQuery("! # of documents TO BE MINED             : $numToBeMined");
    my $numNotToBeMined = scalar @PMIDNotToBeReMined;
    LogQuery("! # of documents NOT TO BE MINED         : $numNotToBeMined");

 

    #  ----------------------------------------------------------------------------------
    #  Fetching Medline and HTML 
    #  ----------------------------------------------------------------------------------
    my ($tmpMedLineStatusRef, $tmpMedLineSizeRef)   = Fetch_MEDLINE_From_PMID_List (\@medlinePMIDToBeFetched, $CorpusReserviorTmpOriginalDoc, $CorpusReserviorOriginalDoc, $corpusRefetchOption, \%pmid2lang, \%pmid2journal, $fileCopyRequired, \%annoENV);
    my ($tmpHTMLStatusRef, $tmpHTMLSizeRef, $tmpPMIDLinkURLRef, $tmpPMIDLinkURLUpdateRef, $tmpPMIDJournalTypeRef) = ();
    
    if ((defined $annoENV{ProcessFullTextHtml}) && ($annoENV{ProcessFullTextHtml} =~ /TRUE/i))
    {	($tmpHTMLStatusRef, $tmpHTMLSizeRef, $tmpPMIDLinkURLRef, $tmpPMIDLinkURLUpdateRef, $tmpPMIDJournalTypeRef)         = Fetch_HTML_From_PMID_List (\@htmlPMIDToBeFetched, $CorpusReserviorTmpOriginalDoc, $CorpusReserviorOriginalDoc, $corpusRefetchOption, \%pmid2lang, $tmpMedLineStatusRef, \%annoENV);
    }
    
    
    #  ----------------------------------------------------------------------------------
    #  Any document in the SciMinerDB 'document' table must have been pre-processed
    #  ----------------------------------------------------------------------------------
    
    
    #  ----------------------------------------------------------------------------------
    #  Insert downloaded documents into SciMinerDB
    #  ----------------------------------------------------------------------------------
    LogQuery("--- Document updating/inserting into db, if needed");
    insert_update_newly_downloaded_documents_into_SciMiner ($dbh, \%pmid2docID, \@medlinePMIDToBeFetched, \@htmlPMIDToBeFetched, $tmpMedLineStatusRef, $tmpMedLineSizeRef, $tmpHTMLStatusRef, $tmpHTMLSizeRef, $tmpPMIDLinkURLRef, $tmpPMIDLinkURLUpdateRef, $tmpPMIDJournalTypeRef);

    
    #  ----------------------------------------------------------------------------------
    #  Update tmpPMIDLinkURLRef for PMIDs that have not been re-processed
    #  ----------------------------------------------------------------------------------
    update_PMIDLinkURLRefHash ($tmpPMIDLinkURLRef, $dbh );


 
    
    #  ----------------------------------------------------------------------------------
    #  Load MeSH Data
    #  ----------------------------------------------------------------------------------
    LogQuery("--- Loading MeSH data tree structure");
#	my ($mtreeID2descIDRef, $mtreeID2treeCodeRef, $treeCode2mtreeIDRef, $treeCode2descIDRef, $descID2treeCodesRef, $MeSHdescID2termRef, $MeSHTerm2descIDRef) 						= load_mesh_tree_data_from_SciMinerDB ($dbh, $currentQueue);
#    my ($MeSHCode2DistRef) 												= load_mesh_term_distribution ($MeSHDistFile, $currentQueue);

	my ($MeSHdescID2termRef, $MeSHTerm2descIDRef)	= load_mesh_tree_data_from_SciMinerDB_simplified ($dbh, $currentQueue);
    my ($MeSHTerm2DistRef) 							= load_mesh_term_distribution_simplified ($MeSHDistFile, $currentQueue);
    
	    
        
    #  ----------------------------------------------------------------------------------
    #  Pre-Process the downloaded files
    #  ----------------------------------------------------------------------------------
    LogQuery("--- Prelink processing retrieved documents, if needed");
	my ($documentSourceRef, $processedStatusRef) = process_medline_html_document_with_mesh_tree_simplified(
			$CorpusReserviorTmpOriginalDoc, $CorpusReserviorTmpProcessedDoc, \%annoENV, \%pmid2Title, \%pmid2Abstract, 
			$MeSHdescID2termRef, $MeSHTerm2descIDRef, $MeSHTerm2DistRef,
		 	$dbh, \%pmid2docID, \%pmid2lang, $tmpPMIDJournalTypeRef );


    #  ----------------------------------------------------------------------------------
    #  Update document source in the 'document' table depending on html or medline
    #  ----------------------------------------------------------------------------------
    update_document_source_processed ($dbh, \%pmid2docID, $documentSourceRef, $processedStatusRef, \%pmid2Title, \%pmid2Abstract, \%pmid2lang, \%pmid2journal);
    

    
    #  ----------------------------------------------------------------------------------
    #  Update/Insert processed sentences into SciMinerDB
    #  ----------------------------------------------------------------------------------
    LogQuery("--- Inserting sentences into the sentence table, if needed");        
    insert_update_processed_documents_into_SciMiner_sentence($dbh, $CorpusReserviorTmpProcessedDoc, \%pmid2docID, \@PMIDToBeMined);    


    
    #  ----------------------------------------------------------------------------------
    #  Createee missing preLink file here before proceeding with mining process
    #  ----------------------------------------------------------------------------------
    generate_missing_preSciMiner_document ($dbh, $CorpusReserviorTmpProcessedDoc, \%pmid2docID, \@PMIDToBeMined);



    #  ----------------------------------------------------------------------------------
    #  Write PMID to docID table as "CurrentList", which contains the \%pmid2docID information
    #  ----------------------------------------------------------------------------------
    create_PMID_list_for_SciMiner_process ("$annoENV{SciMinerPath}/Work/CurrentList", \@PMIDList, \%pmid2docID);



    #  ----------------------------------------------------------------------------------
    #  Prepare required dictionary and filtering list (default)
    #  ----------------------------------------------------------------------------------
    my %dictionaryFileName  = ();
    create_SciMiner_default_files ($dbh, \%annoENV, \%dictionaryFileName);



    #  ----------------------------------------------------------------------------------
    #  ----------------------------------------------------------------------------------
    #                           Perform SciMiner mining process
    #  ----------------------------------------------------------------------------------
    #  ----------------------------------------------------------------------------------
    my ($symbolMiningResultRef, $nameMiningResultRef) = perform_SciMiner_mining_process (
    		\%annoENV, \%dictionaryFileName, $pname, \@PMIDList, \@PMIDToBeMined, 
    		\@PMIDNotToBeReMined, \%pmid2docID, $dbh, $finalResultDir, $finalResultWebDir, 
    		\%currentQueueEnv, \%pmid2Title, \%pmid2Abstract, \%pmid2htmlSize, $currentQueue, 
			$MeSHdescID2termRef, $MeSHTerm2descIDRef, $MeSHTerm2DistRef,
    		\%pmid2journal, $cssFileName, 
    		$sciminerJScriptFileName, \%symbol2ncbiEntrezGeneID, $tmpPMIDLinkURLRef);



    #  ----------------------------------------------------------------------------------
    #  Update Whole Document Summary in the SciMinerDB
    #  ----------------------------------------------------------------------------------
    LogQuery("! Updating SciMiner whole document summary");
    if ((-f "$finalResultWebDir/SciMinerBase.MerSum.sorted.txt") && (-s "$finalResultWebDir/SciMinerBase.MerSum.sorted.txt" > 0))       # -s
    {   update_whole_document_summary("$annoENV{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpus2HUGO", 
                                      "$annoENV{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpus",
                                      "$annoENV{SciMinerPath}/Work/FullSciMinerDB/FullSciMinerDBCorpusPMIDCnt",
                                      "$finalResultWebDir/SciMinerBase.MerSum.sorted.txt",
                                      $dbh);
    }
    

    #  ----------------------------------------------------------------------------------
    #  Remove completed files and update the status
    #  ----------------------------------------------------------------------------------
    LogQuery("! Deleting the completed query $currentQueueEnv{fileNameBase}");
    remove_completed_queue_update_status (\%annoENV, $currentQueueEnv{fileNameBase}, $dbh, $currentQueue);
    
}




sub update_PMIDLinkURLRefHash
{	my $tmpPMIDLinkURLRef		= shift;
	my $dbh						= shift;
	
	my $sql = "SELECT pmid, linkURLOriginal FROM document";
    my $sth = $dbh->prepare($sql);
    my @row = ();
    $sth->execute();
        
    while(@row = $sth->fetchrow_array)
    {   if (defined $row[1])
        {   $$tmpPMIDLinkURLRef{$row[0]}	= $row[1];
        }else
        {   # Skip this line, since we need pmid
        }
    }
}   



sub update_whole_document_summary
{   my $wholePMID2HUGOFile      = shift;
    my $wholeHUGO2PMIDFile      = shift;
    my $wholePMIDCntFile        = shift;
    my $SciMinerBaseFile		= shift;
    my $dbh                     = shift;
    
    open (PMIDFILE, $wholePMID2HUGOFile);
    my %pmid2HUGOIDString       = ();
    
    while(<PMIDFILE>)
    {   my $line = $_;
        if ($line =~ /^#/)
        {	next;
        }
        $line =~ s/\r|\n//g;
       	my @tmp = split (/\t/, $line);
        $pmid2HUGOIDString{$tmp[0]} = $tmp[1];
    }   close PMIDFILE;
    
    
    my $changeMade              = 0;
    my %hugoID2Symbol           = ();
    my %hugoID2Name             = ();
    my %hugoID2PaperCnt         = ();
    my %additionalPMID2HUGOID   = ();

    open (FILE, $SciMinerBaseFile);
    while(<FILE>)
    {   my $line = $_;
        if ($line =~ /^#/)
        {	next;
        }
        $line =~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        my @tmp2 = split (/,/, $tmp[6]);
        $hugoID2Symbol{$tmp[1]} = $tmp[0];
        $hugoID2Name{$tmp[1]} = $tmp[2];
        
        foreach my $pmid (@tmp2)
        {   if (defined $additionalPMID2HUGOID{$pmid})
            {   $additionalPMID2HUGOID{$pmid} .= $tmp[1].',';
            }else
            {   $additionalPMID2HUGOID{$pmid} = $tmp[1].',';
            }
        }
    }   close FILE;

    #  Check replace old pmid2HUGOID with new result (update)
    foreach my $pmid (keys %additionalPMID2HUGOID)
    {   $pmid2HUGOIDString{$pmid} = $additionalPMID2HUGOID{$pmid};
    }
    
    #  Create a new wholePMID2HUGOFile
    open (PMIDFILE, ">".$wholePMID2HUGOFile);
    foreach my $pmid (keys %pmid2HUGOIDString)
    {   print PMIDFILE $pmid."\t".$pmid2HUGOIDString{$pmid}."\n";
        my @tmpSplit = split (/\,/, $pmid2HUGOIDString{$pmid});
        foreach my $hugoID (@tmpSplit)
        {   if (defined $hugoID2PaperCnt{$hugoID})
            {   $hugoID2PaperCnt{$hugoID}++;
            }else
            {   $hugoID2PaperCnt{$hugoID} = 1;
            }
        }
    }   close PMIDFILE;
    
    #  Create a new wholeHUGO2PMIDFile
    if (-f $wholeHUGO2PMIDFile)
    {   if (-f "$wholeHUGO2PMIDFile.old")
    	{	`rm -Rf $wholeHUGO2PMIDFile.old`;
    	}
    	
    	`mv $wholeHUGO2PMIDFile $wholeHUGO2PMIDFile.old`;
        open (PMIDFILEIN, $wholeHUGO2PMIDFile.'.old');
        open (PMIDFILEOUT, ">".$wholeHUGO2PMIDFile);
        while(<PMIDFILEIN>)
        {   my $line = $_;
        	if ($line =~ /^#/)
        	{	next;
        	}
            my @tmp = split (/\t/, $line);
            $hugoID2Symbol{$tmp[1]} = $tmp[0];
            $hugoID2Name{$tmp[1]} = $tmp[2];
        }   close PMIDFILEIN;
        
        #  Write into new file
        foreach my $hugoID (keys %hugoID2PaperCnt)
        {   print PMIDFILEOUT $hugoID2Symbol{$hugoID}."\t".$hugoID."\t".
                              $hugoID2Name{$hugoID}."\t"."1"."\t".$hugoID2PaperCnt{$hugoID}."\n";
        }   close PMIDFILEOUT;
    }else
    {   #  This is new set. There is no need to read the previous file.
        open (PMIDFILEOUT, ">".$wholeHUGO2PMIDFile);
        foreach my $hugoID (keys %hugoID2PaperCnt)
        {   print PMIDFILEOUT $hugoID2Symbol{$hugoID}."\t".$hugoID."\t".
                              $hugoID2Name{$hugoID}."\t"."1"."\t".$hugoID2PaperCnt{$hugoID}."\n";
        }   close PMIDFILEOUT;
    }

    #  Create wholePMIDCntFile which contains the number of total processed document
    if (defined $wholePMIDCntFile)
    {   open (DOCCNT, ">".$wholePMIDCntFile);
    	my $docCount	= retrieve_document_count_in_sciminer_db($dbh);
        print DOCCNT $docCount."\n";
        close DOCCNT;
    }
}





sub retrieve_document_count_in_sciminer_db
{   my $dbh             = shift;
    my $sql                     = "SELECT count(*) FROM document";
    my $sth                     = $dbh->prepare($sql);
    $sth->execute();
    my @row                     = $sth->fetchrow_array;
    if (defined $row[0])
    {   return ($row[0]);
    }else
    {   return (0);
    }
}





sub remove_completed_queue_update_status
{   my $annoENVRef      = shift;
    my $fileNameBase    = shift;
    my $dbh             = shift;
    my $queryNumber     = shift;
    
    `rm -Rf $$annoENVRef{SciMinerPath}/Work/$fileNameBase.*`;
    `rm -Rf $$annoENVRef{SciMinerPath}/Work/CurrentQueue`;
    `rm -Rf $$annoENVRef{SciMinerPath}/Work/CurrentList`;
    
    #  Update Query table current status of the db
    $dbh->do("UPDATE query SET dateEnd=curdate(), timestampEnd=curtime(), status=3 WHERE queryID = $queryNumber");
    
}





sub load_mesh_tree_data_from_SciMinerDB
{	my $dbh								= shift;
	my $queryNumber						= shift;

	#  Get the mtree structure from SciMinerDB
	my %mtreeID2descID			= ();
	my %mtreeID2treeCode		= ();
	my %treeCode2mtreeID		= ();
	my %treeCode2descID			= ();
	my %descID2treeCodes		= ();
	
    my $sql                     = "SELECT mtreeID, descID, treeCode FROM mtree";
    my $sth                     = $dbh->prepare($sql);
    my @row                     = ();
    $sth->execute();
    while(@row=$sth->fetchrow_array)
    {   $mtreeID2descID{$row[0]} 		= $row[1];
    	$mtreeID2treeCode{$row[0]}		= $row[2];
    	if (defined $descID2treeCodes{$row[1]} )
    	{	push @{$descID2treeCodes{$row[1]}}, $row[2];
    	}else
    	{   my @tmpArray 					= ();
    		push @tmpArray, $row[2];
    		$descID2treeCodes{$row[1]} 		= \@tmpArray;
    	}
    	$treeCode2mtreeID{$row[2]}		= $row[0];
    	$treeCode2descID{$row[2]}		= $row[1];
    }

	#  Get the descID2descTerm information
	my %MeSHdescID2term			= ();
	my %MeSHTerm2descID			= ();
    $sql                     	= "SELECT descID, descriptorName FROM mdesc";
    $sth                     	= $dbh->prepare($sql);
    $sth->execute();
    while(@row=$sth->fetchrow_array)
    {   $MeSHdescID2term{$row[0]} 		= $row[1];
    	$MeSHTerm2descID{$row[1]} 		= $row[0];
    }
	

	return (\%mtreeID2descID, \%mtreeID2treeCode, \%treeCode2mtreeID, \%treeCode2descID, \%descID2treeCodes, \%MeSHdescID2term, \%MeSHTerm2descID);
}










