sub load_mesh_term_distribution
{   my $MeSHDistFile					= shift;
	my $queryNumber						= shift;
	
	my %MeSHCode2Dist					= ();
#	my %MeSHCode2Desc					= ();
	
	#  Read the tree file. If there is no tree file, we are in trouble
	if (-f $MeSHDistFile)
	{	open (DISTRIBUTION, $MeSHDistFile);
		while(<DISTRIBUTION>)
		{   my $line 		= $_;
			$line 			=~ s/\r|\n//g;

			my @tmpSplit	= split (/\t/, $line);
			if (not defined $tmpSplit[1])
			{   next;
			}
			
			$MeSHCode2Dist{$tmpSplit[0]}	= $tmpSplit[1];
#			$MeSHCode2Desc{$tmpSplit[0]}	= $tmpSplit[1];			
		}
		close DISTRIBUTION;

#		return (\%MeSHCode2Dist, \%MeSHCode2Desc);
		return (\%MeSHCode2Dist);
	}else
	{   send_error_email_to_admin ("There is no mesh distribution file at $MeSHDistFile\n\n"."SciMiner is now aborting...at $queryNumber\n\n");
		LogQuery("There is no mesh tree file at $MeSHDistFile   SciMiner is now aborting...");
		die;
	}
}





sub load_mesh_term_distribution_simplified
{   my $MeSHDistFile					= shift;
