	}
}




sub load_mesh_tree_data
{   my $MeSHTreeFile					= shift;
	my $queryNumber						= shift;
	
	my %code2desc		= ();
	my %desc2codes		= ();
	my %desc2codeCnt	= ();
		
	#  Read the tree file. If there is no tree file, we are in trouble
	if (-f $MeSHTreeFile)
	{	open (TREE, $MeSHTreeFile);
		while(<TREE>)
		{   my $line 		= $_;
			$line 			=~ s/\r|\n//g;

			my @tmpSplit	= split (/\;/, $line);
			if (not defined $tmpSplit[1])
			{   next;
			}
			$code2desc{$tmpSplit[1]}	= $tmpSplit[0];

			if (defined $desc2codes{$tmpSplit[0]})
			{   push @{$desc2codes{$tmpSplit[0]}}, $tmpSplit[1];
				$desc2codeCnt{$tmpSplit[0]}++;
			}else
			{	my @newArray = ();
				push @newArray, $tmpSplit[1];
				$desc2codes{$tmpSplit[0]} = \@newArray;
				$desc2codeCnt{$tmpSplit[0]} = 1;
			}
		}
		close TREE;

		return (\%code2desc, \%desc2codes, \%desc2codeCnt);
	}else
	{   send_error_email_to_admin ("There is no mesh tree file at $MeSHTreeFile\n\n"."SciMiner is now aborting...at $queryNumber\n\n");
		LogQuery("There is no mesh tree file at $MeSHTreeFile   SciMiner is now aborting...");
		die;
	}
}	
	





sub send_error_email_to_admin
{   my $message		= shift;
	
	#  Load working environment for ANNOTATION
    my %annoENVLocal = anno_environmental_file_open ( );

	if ((not defined $annoENVLocal{'SendMain'}) || (! $annoENVLocal{'SendMain'}))
	{	return();
	}

	my $randNum  = int(rand(1000000000));
	my $messageFile = $randNum.'.message';

	
    LogQuery("! Sending an warning email to the system admin !!!");
    open (TMP, ">$messageFile");
    print TMP "\n\nSciMiner has encountered an critical error... \n\n".
    		  "Error message : $message\n\n";
    close TMP;
    `mail -s \"!!! SciMiner System Error\" \"$adminEmail\" < $messageFile`;
    unlink ($messageFile);
}




















































































































































































































































































sub process_merge_queries
{	my $email					= shift;
	my $mergedName				= shift;
	my $threshold				= shift;
	my $mergeQueryIDsRef		= shift;
	my $tmpLocalURL				= shift;
	
	use DBI;


	my $pname                           = 'SciMiner_v2.2';
    my $corpusRefetchOption             = 0;
    my $cssFileName						= 'sciminer-modern.css';
    my $sciminerJScriptFileName			= 'sciminer.js';
    
    
    #  Load working environment for ANNOTATION
    my %annoENV 				= anno_environmental_file_open ( );
    my $annoBaseDir 			= $annoENV{ANNOPath};
    my %currentQueueEnv			= ();
		

	#  Update the SciMinerServerURL
	$annoENV{SciMinerServerURL}	= $tmpLocalURL;
		
    #  Database Access Information
    my $SciMinerDB   = "DBI:mysql:database=".$annoENV{DB} || return (-1, "!ERROR: No database specified");
    my $username    = $annoENV{username} || return (-1, "!ERROR: No username specified");
    my $password    = $annoENV{password} || return (-1, "!ERROR: No password specified");

    #  ------------------------------------------------------------------------
    #  Retrieve User Information from SciMinerDB
    #  ------------------------------------------------------------------------
    my $dbh         = DBI->connect($SciMinerDB, $username, $password, {PrintError => 0}) || return (-1, "!ERROR: Couldn't connect to database ".$DBI::errstr);

    my $sql         = "SELECT userID, passCode, institute, name FROM user where email = \"$email\"";
    my $sth         = $dbh->prepare($sql);
    $sth->execute();
    my @row         = $sth->fetchrow_array;
    my $userID      = $row[0];
    my $passCode    = $row[1];
    my $instCheck	= 0;
    my $userName	= '';
    if ((defined $row[2]) && ($row[2] ne "") && (defined $annoENV{Institution}) && ($annoENV{Institution} eq $row[2]))
    {	$instCheck	= 1;
    }
    if ((defined $row[3]) && ($row[3] ne ""))
    {	$userName	= $row[3];
    }
    
    #  ------------------------------------------------------------------------
    #  Retrieve base names
    #  ------------------------------------------------------------------------
    my $queryIDmergedString	= join (",", @{$mergeQueryIDsRef});
    $sql         = "SELECT queryID, resultURL FROM query where queryID in ($queryIDmergedString)";
    $sth         = $dbh->prepare($sql);
    $sth->execute();

	my %queryID2baseName	= ();
    while(@row = $sth->fetchrow_array)
    {   if (defined $row[1])
        {   my @tmpSplit	= split (/\//, $row[1]);
        	$queryID2baseName{$row[0]}	= $tmpSplit[1];
        }
    }



    #  ------------------------------------------------------------------------
    #  Create a new queryID
    #  ------------------------------------------------------------------------
	#  Insert new query information 
    $dbh->do("INSERT INTO `query` (userID, queryName, status, listType, dateCreate, dateStart, timestampStart, numPMID, miningMode) VALUES ($userID, \"$mergedName\", 1, \"MergedQuery\", curdate(), curdate(), curtime(), 0, \"MergedQuery\")") || LogQuery ("!ERROR: INSERT INTO `query` (userID, queryName, status, listType, dateCreate, numPMID, miningMode) VALUES ($userID, \"$mergedName\", 1, \"MergedQuery\", curdate(), 0, \"MergedQuery\")\n") ;   
    
    #  Retrieve the queryID of the recently inserted query
    $sth            = $dbh->prepare("SELECT queryID FROM query ORDER BY queryID DESC LIMIT 1");
    $sth->execute();
    @row            = $sth->fetchrow_array;#($result);
    my $queryID     = $row[0];
    
    
    #  ------------------------------------------------------------------------
    #  Write the query info into a file
    #  ------------------------------------------------------------------------    
    my @tmpSplit        = split(/\@/, $email);
    my $fileNameBase    = 'Query_'.$queryID.'__'.$tmpSplit[0];
    my $confFileName    = "/tmp/".$fileNameBase.'.conf';
    my $listFileName    = "/tmp/".$fileNameBase.'.list';
    

    #  Final Result Directory
    mkdir ("$annoENV{SciMinerPath}Work/FinalResults/") 					|| print "";
    mkdir ("$annoENV{SciMinerPath}Work/FinalResults/$fileNameBase/") 	|| print "";
    mkdir ("$annoENV{SciMinerWebPath}FinalResults/") 					|| print "";
    mkdir ("$annoENV{SciMinerWebPath}FinalResults/$fileNameBase/") 		|| print "";
  	my $finalResultWebDir	= "$annoENV{SciMinerWebPath}/FinalResults/$fileNameBase/";
	my $finalResultDir		= "$annoENV{SciMinerPath}Work/FinalResults/$fileNameBase/";

    #  Create links to the original files
    my $docLinkDir              = $finalResultWebDir.'Docs';
    mkdir ($docLinkDir) 		|| print "";	
	
	#  ------------------------------------------------------------------------
    #  Load 
    #  ------------------------------------------------------------------------    
    LogQuery("!!! Started to load query files to be merged...");
    my %processedPMIDs			= ();
    my @revertedQueryIDs		= sort { $b <=> $a } @{$mergeQueryIDsRef};

    my %mergedPMIDs				= ();
    my $totalSentence2GeneCnt	= 0;
    
    open (RAWMERGED, 		">".$finalResultWebDir.'SciMinerBase.Both.txt');
    my $line	= '';
    my @tmpPMIDLists	= ();
    my $tmpPMIDString	= '';
    my $resultString	= '';
    foreach my $tmpQueryID (@revertedQueryIDs)
    {	if (defined $queryID2baseName{$tmpQueryID})
    	{	#  Check configuration file for miningmethod.
    		#  For GeneRIF or gene2pubmed method, simply load the SciMinerBase.MerSum.sorted.txt
    		
    		#  Open CONF file
    		open (CONF, "$annoENV{SciMinerWebPath}FinalResults/$queryID2baseName{$tmpQueryID}/$queryID2baseName{$tmpQueryID}".'.conf');
    		my $g2pubmedOrGeneRIF		= 0;
    		while(<CONF>)
    		{	$line					= $_;
				$line					=~ s/\r|\n//g;
				@tmpSplit				= split(/\t/, $line);
				if ((defined $tmpSplit[0]) && ($tmpSplit[0] eq 'miningMode'))
				{	if (($tmpSplit[1] eq 'NCBIGene2PubMed') || ($tmpSplit[1] eq 'NCBIGeneRIF'))
					{	$g2pubmedOrGeneRIF	= 1;
					}
				}
    		}	
    		close CONF;
    		
 		
			if ($g2pubmedOrGeneRIF)
			{	open (RESULTFILE, "$annoENV{SciMinerWebPath}FinalResults/$queryID2baseName{$tmpQueryID}/SciMinerBase.MerSum.sorted.txt");
				while(<RESULTFILE>)
				{	$line				= $_;
					$line				=~ s/\r|\n//g;
					if ($line !~ /^\#/)
					{	@tmpSplit		= split(/\t/, $line);
						@tmpPMIDLists	= split(/\,/, $tmpSplit[6]);
						foreach my $tmpPMID (@tmpPMIDLists)
						{	print RAWMERGED "0\t$tmpPMID\t0\t0\t$tmpSplit[1]\t".
											"$tmpSplit[0]\t$tmpSplit[0]\t$tmpSplit[0]\t0\t99\t".
											"NCBI Gene2PubMed GeneRIF DATA\t30\t\tSciMiner_v2.2\t1\t".
											"1\tGene2PubMedGeneRIF\t0\t0\t0\t".
											"\t0\t0\t0\t0\t\t0\n";
						}
					}
				}
				close RESULTFILE;
			}else
			{	#  Open List File
				open (LIST, "$annoENV{SciMinerWebPath}FinalResults/$queryID2baseName{$tmpQueryID}/$queryID2baseName{$tmpQueryID}".'_list.txt');
				@tmpPMIDLists			= ();
				while(<LIST>)
				{	$line					= $_;
					$line					=~ s/\r|\n//g;
					$mergedPMIDs{$line}		= 1;
					push @tmpPMIDLists, $line;
				}
				close LIST;
	
				$tmpPMIDString			= join (",",@tmpPMIDLists);
				$sql         = "SELECT * FROM sentence2gene where pmid in ($tmpPMIDString)";
				$sth         = $dbh->prepare($sql);
				$sth->execute();
				my $tmpQueryID=0;
				$resultString	= '';

				while(@row = $sth->fetchrow_array)
				{	$resultString	= '';
					for ($tmpQueryID=0; $tmpQueryID < scalar @row; $tmpQueryID++)
					{	if (not defined $row[$tmpQueryID])
						{	$resultString .= "\t";
						}else
						{	$resultString .= "$row[$tmpQueryID]\t";
						}
					}
					chomp($resultString);
					print RAWMERGED $resultString."\n";
					$totalSentence2GeneCnt++;
				}
			}
    	}
    }
    
    close RAWMERGED	;
    
    
    #  Create an array of PMIDs
    my @uniqPMIDs			= keys %mergedPMIDs;
    my $uniqPMIDCount		= scalar @uniqPMIDs;
    
    
    #  -------------------------------------------------------------------------
    #  Step 6. Summarization and merge the results
    #  -------------------------------------------------------------------------
    my %HUGO2ApprovedGeneName           = ();

    #  After the summarization process, we now have the pmid2passGeneCount hash
	my %pmid2passGeneCount      		= ();

    LogQuery("! Generating SciMiner Summary Results - Both");
    if (-s "$finalResultWebDir"."SciMinerBase.Both.txt" > 0)	# -s "
    {   SciMiner_Summarize_Both_Result (\%HUGO2ApprovedGeneName, $finalResultWebDir, 'SciMinerBase.Both', $dbh, \%pmid2passGeneCount, $threshold, $queryID);
    }


    #  ----------------------------------------------------------------------------------
    #  Step 7. MeSH Handling
    #  ----------------------------------------------------------------------------------     
	#  MeSH tree/dist file names
	my $MeSHTreeFile	= "$annoENV{SciMinerPath}/Work/MeSH/mtrees2008.bin";
	my $MeSHDistFile	= "$annoENV{SciMinerPath}/Work/MeSH/NCIBIDBXMeSHDistExplicit.txt";
	
	my ($MeSHdescID2termRef, $MeSHTerm2descIDRef)	= load_mesh_tree_data_from_SciMinerDB_simplified ($dbh, $queryID);
    my ($MeSHTerm2DistRef) 		= load_mesh_term_distribution_simplified ($MeSHDistFile, $queryID);


    #  ----------------------------------------------------------------------------------
    #  Step 7-1. MeSH statistics handling
    #  ----------------------------------------------------------------------------------     
    LogQuery("! Generating MeSH distribution from corpus");
    #generate_mesh_distribution_from_corpus (
    #	$MeSHdescID2termRef, $MeSHTerm2descIDRef, $MeSHTerm2DistRef,
    #	$dbh, \@uniqPMIDs, $annoENV{"WholePMID"}, $finalResultDir, $finalResultWebDir); 


    #  -------------------------------------------------------------------------
    #  Step 8-1. Generate the base PMID list html
    #  -------------------------------------------------------------------------
    LogQuery("! Generating base PMID list -- pmidlist.html");
    my $pmidListHTMLFile            = "$finalResultWebDir/pmidList.html";
    

    #  -------------------------------------------------------------------------
    #  Step 8-2. Generate a PMID list file
    #  -------------------------------------------------------------------------
	my $pmidListFile				= $finalResultWebDir.$fileNameBase.'_list.txt';
	open (PMIDLIST, ">$pmidListFile");
	
	my $pmidNewLineString			= join ("\n", @uniqPMIDs);
	my $pmidTotalCount				= scalar @uniqPMIDs;
	
	print PMIDLIST $pmidNewLineString;
	close PMIDLIST;
	undef $pmidNewLineString;

 	#  Copy css and java script file to the final result directory
    `cp /home/hurlab/apache-tomcat-9.0.37/webapps/SciMiner1.1/css/sciminer-modern.css $finalResultWebDir/`;
    `cp $annoENV{SciMinerWebPath}/$sciminerJScriptFileName $finalResultWebDir/`;
    
    #  Copy the Image directory
    `cp -R $annoENV{SciMinerWebPath}/Images $finalResultWebDir/`;








	#  -------------------------------------------------------------------------
    #  Retrieve PMID2Title, PMID2Journal Reference
    #  -------------------------------------------------------------------------
	my %pmid2title					= ();
	my %pmid2journal				= ();
  my %pmid2abstract               = ();
	my %medlineSymbolicLink			= ();
	my %medlineEndnoteSymLink		= ();
	my %htmlSymbolicLink			= ();
	my %pmid2htmlSize				= ();
	my %tmpPMIDLinkURL				= ();

	my $pmidString					= join (",", @uniqPMIDs);
    $sth            				= $dbh->prepare("SELECT pmid, title, journal, linkURLOriginal, abstract FROM document WHERE pmid in ($pmidString)");
    $sth->execute();
	while(@row = $sth->fetchrow_array)
	{	if (defined $row[1])
		{	$pmid2title{$row[0]}		= $row[1];
		}
		if (defined $row[2])
		{	$pmid2journal{$row[0]}		= $row[2];
		}
		if (defined $row[3])
		{	$tmpPMIDLinkURL{$row[0]}	= $row[3];
		}
        if (defined $row[4])
        {   $pmid2abstract{$row[0]}     = $row[4];
        }
	}
    
    #  -------------------------------------------------------------------------
    my $numPassGeneCountByPMIDRef   = generate_base_pmid_list_html ($finalResultDir, $finalResultWebDir, $pmidListHTMLFile, \%pmid2passGeneCount, $fileNameBase, $annoENV{SciMinerServerURL}, \%pmid2title, $docLinkDir, \%medlineSymbolicLink, \%medlineEndnoteSymLink, \%htmlSymbolicLink, \%pmid2htmlSize, $annoENV{SciMinerPath}."CorpusData/Original/", \%pmid2journal, $cssFileName, $instCheck, \%tmpPMIDLinkURL, \%pmid2abstract);
    


	#  -------------------------------------------------------------------------
    #  Step 8-1. Retrieve user name and from userID
    #  -------------------------------------------------------------------------
    my %userID2userName			= ();
    $sth						= $dbh->prepare("SELECT userID, name FROM user");
	$sth->execute;
    while(@row	= $sth->fetchrow_array)
    {	if (defined $row[1])
    	{	$userID2userName{$row[0]}	= $row[1];
    	}
    }


   	#  Retrieve ncbiEntrezGeneID and hugoID
   	$sql	= "SELECT approvedSymbol, entrezGeneIDMappedData from gene";
	$sth	= $dbh->prepare($sql); 
	$sth->execute();
	my %symbol2ncbiEntrezGeneID				= ();
	while(@row = $sth->fetchrow_array)
    {   if (defined $row[1])
        {   if ($row[1] !~ /[\,| ]/)
        	{	$symbol2ncbiEntrezGeneID{$row[0]}	= $row[1];
        	}else
        	{	$symbol2ncbiEntrezGeneID{$row[0]}	= "";
        	}
        }else
        {   # Skip this line, since we need pmid
        }
    }



	#  -------------------------------------------------------------------------
    #  Step 8-2. Generate the gene summary html
    #  -------------------------------------------------------------------------
    LogQuery("! Generating the summary html -- geneSummary.html");
    my $resultSummaryHTML   = "$finalResultWebDir/geneSummary.html";
    
    $currentQueueEnv{queryID}					= $queryID;
    $currentQueueEnv{email}						= $email;
    $currentQueueEnv{queryName}					= $mergedName;
    $currentQueueEnv{count}						= $pmidTotalCount;
    $currentQueueEnv{fileNameBase}				= $fileNameBase;
    $currentQueueEnv{SciMinerServerURL}			= $tmpLocalURL;
    $currentQueueEnv{InstitutionCheck}			= $instCheck;
    $currentQueueEnv{useScoreThreshold}			= 1;
    $currentQueueEnv{scoreThreshold}			= $threshold;
    
    open (CONF, ">".$finalResultWebDir.$fileNameBase.'.conf');
    foreach my $tmpKey (keys %currentQueueEnv)
    {	print CONF $tmpKey."\t".$currentQueueEnv{$tmpKey}."\n";
    }
    close CONF;
    
    my %hgncID2passedContent				= ();
    my %pmid2passedContent					= ();
    my $maxRecordPerItem					= 3;

   generate_summary_html_from_merged_result(
    	$finalResultDir, $finalResultWebDir, "$finalResultWebDir/SciMinerBase.MerSum.sorted.txt", $resultSummaryHTML, \%currentQueueEnv, $totalSentence2GeneCnt, $currentQueueEnv{fileNameBase}, $annoENV{SciMinerServerURL}, \%hgncID2passedContent, \%pmid2passedContent, \%pmid2title, \%pmid2abstract, \%medlineSymbolicLink, \%medlineEndnoteSymLink, \%htmlSymbolicLink, \%pmid2htmlSize, $numPassGeneCountByPMIDRef, \%pmid2journal, $maxRecordPerItem, $cssFileName, $sciminerJScriptFileName, \%symbol2ncbiEntrezGeneID, \%tmpPMIDLinkURL, \%userID2userName);
   # `cp -f $resultSummaryHTML $finalResultWebDir`;    
                                        


    #  ----------------------------------------------------------------------------------
    #  Step 9. Generate result email and simple html for display.
    #  ----------------------------------------------------------------------------------     
    my $resultHTMLFile      = "$finalResultWebDir/result.html";
    LogQuery("! Generating the primary result file -- result.html");
    `ln -s $finalResultWebDir/SciMinerBase.MerSum.sorted.txt $finalResultWebDir/SciMinerBase.MerSum.sorted.xls`;
    SciMiner_Generate_Final_Result_File_From_Merged_Result ($finalResultDir, $finalResultWebDir, $resultHTMLFile, "geneSummary.html",  "pmidList.html", \%currentQueueEnv, $currentQueueEnv{fileNameBase}, $annoENV{SciMinerServerURL}, $dbh, $queryID, $annoENV{WholePMID}, $cssFileName, $sciminerJScriptFileName, \%symbol2ncbiEntrezGeneID, \%tmpPMIDLinkURL);
    
    									
    									
	#  Update the current query to be completed
	$dbh->do("UPDATE query set numPMID = $uniqPMIDCount, dateEnd = curdate(), timestampEnd = curtime(), status = 3, resultURL = \"FinalResults/$fileNameBase/result.html\" WHERE queryID = $queryID");
    
}





sub SciMiner_Generate_Final_Result_File_From_Merged_Result
{   my $finalResultDir          	= shift;
    my $finalResultWebDir       	= shift;
    my $resultHTMLFile         	 	= shift;
    my $resultSummaryHTML      	 	= shift;
    my $pmidListHTMLFile        	= shift;
    my $currentQueueEnvRef      	= shift;
    my $fileNameBase            	= shift;
    my $serverBaseURL           	= shift;
    my $dbh                     	= shift;
    my $queryID                 	= shift;
    my $WholePMID               	= shift;
    my $cssFileName					= shift;
    my $sciminerJScriptFileName		= shift;
    my $symbol2ncbiEntrezGeneIDRef	= shift;
    my $tmpPMIDLinkURLRef			= shift;



    #  Calculate line count
    my $mergedBeforeCount        	= 0;
    my $mergedAfterCount         	= 0;
    my $finalMergedGeneCount      	= 0;
 
    my $serverURL   	= $serverBaseURL."SciMiner/FinalResults/$fileNameBase/";
    my $SciMinerURL  	= $serverBaseURL."SciMiner/";
    my $cssURL			= $cssFileName;
    my $mimiIconURL 	= "/SciMiner1.1/SciMiner/Images/cytoicon.jpg";
    my $EIcon			= "/SciMiner1.1/SciMiner/Images/E.jpg";


	#  Load top 10 results
	open (SUMMARY, $finalResultWebDir."SciMinerBase.MerSum.sorted.txt");
	LogQuery("Summary is $finalResultWebDir SciMinerBase.MerSum.sorted.txt");
	my @top10GeneContents			= ();
	my $lineCount					= 0;
	while(<SUMMARY>)
	{	my $line		= $_;
		$line			=~ s/\r|\n//g;
		if ($line =~ /^\#/)
		{	next;
		}
		my @tmpSplit	= split(/\t/, $line);
		push @top10GeneContents, \@tmpSplit;
		$lineCount++;
		if ($lineCount == 10)
		{	last;
		}
	}
	close SUMMARY;

	my $top10genesArrRef			= \@top10GeneContents;
   

    # Merge
    if (-f "$finalResultWebDir/SciMinerBase.Both.txt")
    {   $mergedBeforeCount 		= get_file_line_count("$finalResultWebDir/SciMinerBase.Both.txt");
    }
    if (-f "$finalResultWebDir/SciMinerBase.Both.Remain.txt")
    {   $mergedAfterCount		= get_file_line_count("$finalResultWebDir/SciMinerBase.Both.Remain.txt");
    }
    if (-f "$finalResultWebDir/SciMinerBase.Both.Summary.txt")
    {   $finalMergedGeneCount 	= get_file_line_count("$finalResultWebDir/SciMinerBase.Both.Summary.txt");
    }
    
    open (FULLMESHRESULTHTML, ">$finalResultWebDir/MeSHCodeDistribution.html");
	
    open (RESULT, ">".$resultHTMLFile);
	print RESULT "  <head>
			        <title>SciMiner Result Report Page</title>
			        <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
			        <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
			        <script language=\"JavaScript1.2\" src=\"$sciminerJScriptFileName\"></script>
			        <style type=\"text/css\"> body {	margin-left:10px;	}</style>
			        </head>
			        <body bgcolor=\"#EAF4F4\">
			        <script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
			        <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Result Report Page</b></p>
			        <p class='titleBarName1'> <b>Congratulation! Your query with SciMiner has been successfully completed. Your query and search options were </b></p>

			        <a id=\"flag1\" href=\"#\" onclick=\"showhide('div1','flag1', 'search option summary');\" class=\"smallTextBold2\">[ HIDE search option summary ]</a>
					<div id=\"div1\" style=\"display:inline\">
			
			        <table border=\"1\" width=\"850\">
			        ";
				        
     
     print FULLMESHRESULTHTML "<head>
                <title>SciMiner Full MeSH Enrichment</title>
                <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
                <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
                <script language=\"JavaScript1.2\" src=\"$sciminerJScriptFileName\"></script>
                <style type=\"text/css\"> body {	margin-left:10px;	}</style>
                </head>
                <body bgcolor=\"#EAF4F4\">
				<script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
                <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Full MeSH Enrichment</b></p>
     						";
     						         
                
    # Running condition (options)
    my %itemContent		= ();
    my $otherOption		= '';
    my $enrichmentTest	= '';
    my $ppiSelection	= '';
    foreach my $keyTerm (sort(keys %{$currentQueueEnvRef}))
    {   if ((defined $keyTerm) && ($keyTerm ne "") && (defined $$currentQueueEnvRef{$keyTerm}))
        {   if ($keyTerm eq 'queryID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Query ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'analID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Analysis ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'userName')
        	{   $itemContent{1}		=	print_tmpKey_tmpTerm_for_selected_option('User name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'email')
        	{	$itemContent{2}		=	print_tmpKey_tmpTerm_for_selected_option('Email', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Query information
        	elsif ($keyTerm eq 'queryName')
        	{   $itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Query name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'queryString')
        	{   $itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Query string', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'count')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('PMID count #', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Some analysis information
        	elsif ($keyTerm eq 'targetQueryNumber')
        	{   $itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Target Query #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'bgQueryNumber')
        	{   $itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Background Query #', $$currentQueueEnvRef{$keyTerm});
        	}
        	elsif ($keyTerm eq 'PValueThreshold')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('P-value Threshold', $$currentQueueEnvRef{$keyTerm});
        	}

        	elsif (($keyTerm eq 'GeneEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene list";
        	}elsif (($keyTerm eq 'GOEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene Ontology";
        	}elsif (($keyTerm eq 'MeSHEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"MeSH term";
        	}elsif (($keyTerm eq 'PathwayEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}$enrichmentTest		.=	"Pathway";
        	}elsif (($keyTerm eq 'PPICheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Protein-Protein Interaction";
        	}elsif ($keyTerm eq 'PPISelection') 
        	{   $ppiSelection		.=	"(PPI Selection: ".$$currentQueueEnvRef{$keyTerm}.')';
        	}
        	
			#  Check for other options
        	elsif ($keyTerm eq 'phenotypeOnlyFilter')
        	{   $otherOption		.= "Remove_phenotype_gene, ";
        	}elsif ($keyTerm eq 'useLengthOption')
        	{   $otherOption		.= "Use_symbol_length_option, ";
        	}elsif ($keyTerm eq 'wordLengthThreshold')
        	{   $otherOption		.= "Always_accept_symbol_longer_than: $$currentQueueEnvRef{$keyTerm}";
        	}
        }
    }
    
    #  Print out sorted query/analysis options
    my @sortedKey	= sort {$a <=> $b} keys %itemContent;
    foreach my $sortedTermKey (@sortedKey)
    {   if (defined $itemContent{$sortedTermKey})
    	{	print RESULT $itemContent{$sortedTermKey};
    	}
    }

	#  Process enrichment options
	if ($enrichmentTest)
    {   if (($ppiSelection) && ($$currentQueueEnvRef{"PPICheck"} =~ /on/i))
    	{	$enrichmentTest	.= $ppiSelection;
    	}
    	print RESULT print_tmpKey_tmpTerm_for_selected_option('Enrichment tests', $enrichmentTest);
    }
    
    #  Score Threshold
    if ((defined $$currentQueueEnvRef{useScoreThreshold}) && ($$currentQueueEnvRef{useScoreThreshold}))
    {   print RESULT print_tmpKey_tmpTerm_for_selected_option('Score threshold', $$currentQueueEnvRef{scoreThreshold});
    }
    
    #  Process other options
    if ($otherOption)
    {   print RESULT print_tmpKey_tmpTerm_for_selected_option('Other', $otherOption);
    }

    print RESULT "</table><br>
            	  </div>
            	  ";
            
            
    #  Update the query table for numGene ($finalMergedGeneCount)
    $dbh->do("UPDATE query SET numGene=$finalMergedGeneCount WHERE queryID = $queryID");
    LogQuery("UPDATE query SET numGene=$finalMergedGeneCount WHERE queryID = $queryID");


            
    # Result summary
    print RESULT " <p align=\"center\" class=\"sectionTitleName1\">Summary</p>

	<p class='titleBarName1'><b>SciMiner has analyzed ($$currentQueueEnvRef{count}) &nbsp;articles. </b>&nbsp;&nbsp;&nbsp;&nbsp;<a href=\"pmidList.html\" onmouseover=\"Tip('Click here to view list of <b>document-based</b> summary result page')\" onmouseout=\"UnTip()\"><b>[Documents Summary]</b></a>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<a href=\"$fileNameBase"."_list.txt\" onmouseover=\"Tip('Click here to get the list of retrieved PMIDs.')\" onmouseout=\"UnTip()\">[PMIDs]</a>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<a href=\"javascript:retrieveDocumentScript('all','1','enw','$fileNameBase','none');\" onmouseover=\"Tip('You can download all of the above citations at once click. <br>For individual document, please go to <b>Documents Summary</b><br>')\" onmouseout=\"UnTip()\"><img src=\"$EIcon\">Citations</a></p>

<table border=\"1\" width=\"450\">";
