                    <a id=\"flag2\" href=\"#top10gene\" onclick=\"showhide('div2','flag2', 'Top 10 most frequent targets');\" class=\"smallTextBold2\">[ HIDE Top 10 most frequent targets ]</a>
					<div id=\"div2\" style=\"display:inline\">
                    <table border=\"1\" width=\"800\">
                        <tr class='titleBarName1'>
