                                MiMI
                            </th>
                        </tr>\n";
                        
    for (my $j=0; $j <10; $j++)    
    {   if (defined $$top10genesArrRef[$j])
        {   # there are legitimate genes
            
            print RESULT "<tr><td>".($j+1)."</td><td><a href=\"$hgncLinkURL$$top10genesArrRef[$j]->[1]\">".($$top10genesArrRef[$j]->[1])."</a></td><td>";
            if (defined $$symbol2ncbiEntrezGeneIDRef{$$top10genesArrRef[$j]->[0]})
