            print RESULT  "</td><td>".($$top10genesArrRef[$j]->[2])."</td><td>".($$top10genesArrRef[$j]->[3])."</td><td>".($$top10genesArrRef[$j]->[4])."</td><td>";
            if ((defined $$symbol2ncbiEntrezGeneIDRef{$$top10genesArrRef[$j]->[0]}) && ($$symbol2ncbiEntrezGeneIDRef{$$top10genesArrRef[$j]->[0]} ne ""))
            {	print RESULT "<a href=\"$mimiNameLink$$symbol2ncbiEntrezGeneIDRef{$$top10genesArrRef[$j]->[0]}\"><img src=\"$mimiIconURL\"></a>";
            }else
            {	print RESULT "&nbsp;";
            }
				print RESULT "</td></tr>";
        }else
        {   print RESULT "<tr><td>".($j+1)."</td><td>&nbsp;</td><td>&nbsp;<td>&nbsp;</td><td>&nbsp;</td><td>&nbsp;</td><td>&nbsp;</td></tr>\n";
        }
    }
    print RESULT "</table>";
    
    #  Generate a random number for symbol list file name
    my $tmpRandomNumber = int(rand(1000000000));
    my $RelPath			= "FinalResults/$fileNameBase/";
    my $MerSumFileName	= "SciMinerBase.MerSum.sorted.txt";
    
    print RESULT "<p class=\"titleBarName1\">
    				Full result (<a href=\"$resultSummaryHTML\">HTML</a>,&nbsp;&nbsp;
				  <a href=\"SciMinerBase.MerSum.sorted.txt\">TXT</a>,&nbsp;&nbsp;
                  <a href=\"SciMinerBase.MerSum.sorted.xls\">EXCEL)</a></p><p>&nbsp;</p>
                  
                  <a name=\"viewNetwork\"></a>
                  </div>
    			  <p>&nbsp;</p><hr>
    			  
				  <form action='../../generateNetwork.cgi' method='POST' ENCTYPE='multipart/form-data'>
                  <p align=\"center\" class=\"sectionTitleName2\">View the interaction network (MiMI data)</p>
                  <p class=\"titleBarName1\">You can create an interaction network of the targets found above. Interaction data is based on the MiMI (Michigan Molecular Interactions) database. The network will be visualized by Cytoscape with the support of MiMI plugin.</p>
                  <select name=\"MinPaperMethod\" size=\"1\" onmouseover=\"Tip('Only identified targets satisfying the following criteria will be used.<br><br><b>Minimum # Paper</b>: Minimum number of papers per target<br>&nbsp;&nbsp;eg) Any target identified from 1 or 2 papers will be excluded <br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;when the threshold is set to 3<br><b>Minimum % Paper</b>: Minimum percentage of papers per target<br><b>Top # Target</b>: Only the top # ranked targets<br><b>Top % Target</b>: Only the top % percentage ranked targets')\" onmouseout=\"UnTip()\">
