    #  Read the MeSH term distribution
    if (-f "$finalResultWebDir/MeSHCodeDistribution.txt")
    {   # Make a link to the file
        #`ln -s $finalResultDir/MeSHCodeDistribution $finalResultWebDir/MeSHCodeDistribution.txt`;
        #`ln -s $finalResultDir/MeSHCodeDistribution $finalResultWebDir/MeSHCodeDistribution.xls`;        
		`ln -s $finalResultWebDir/MeSHCodeDistribution.txt $finalResultWebDir/MeSHCodeDistribution.xls`;        	
    	
    	
        open (MESH, "$finalResultWebDir/MeSHCodeDistribution.txt");
