									$WholePMID
								</td>
								<th width='300' style='text-align= right;'>
									<a style=\"background-color:#F5CCF4;\" id='meshTableSwitch' onclick=\"javascript:show_hide_column('top10MeSHTable','3_4_5_8');\" onmouseover=\"Tip('Click here to toggle table details.')\" onmouseout=\"UnTip()\"><u>Switch table detail</u></a>
