                                    t+
                                </th>
                                <th width=\"50\" bgcolor=\"$tgCColor\" onmouseover=\"Tip('</b>t-</t>: # of papers <b>without</b> the selected MeSH term in the <b>test</b> set.<br>Click each number to view a detailed paper list.')\" onmouseout=\"UnTip()\">
                                    t-
                                </th>
                                <th width=\"50\" bgcolor=\"$bgCColor\" onmouseover=\"Tip('</b>b+</t>: # of papers <b>with</b> the selected MeSH term in the <b>background</b> set.<br>Click each number to view a detailed paper list.')\" onmouseout=\"UnTip()\">
                                    b+
                                </th>
                                <th width=\"50\" bgcolor=\"$bgCColor\" onmouseover=\"Tip('</b>b-</t>: # of papers <b>without</b> the selected MeSH term in the <b>background</b> set.<br>Click each number to view a detailed paper list.')\" onmouseout=\"UnTip()\">
                                    b-
                                </th>
                                <th width=\"70\" onmouseover=\"Tip('P-value by Fishers Exact Test on 2x2 table<br><br><img src=&quot;/SciMiner1.1/SciMiner/Images/2x2Table.jpg&quot; width=&quot;50&quot; height=&quot;50&quot;><br><br>P-values lower than the specified threshold will be in <font color=&quot;red&quot;>red</font>')\" onmouseout=\"UnTip()\">
                                    p-value
                                </th>
                                <th width=\"50\" onmouseover=\"Tip('Ratio of t+ in the test set')\" onmouseout=\"UnTip()\">
                                    t-ratio
                                </th>
                                <th width=\"50\" onmouseover=\"Tip('Ratio of b+ in the background set')\" onmouseout=\"UnTip()\">
                                    b-ratio
                                </th>
                                <th width=\"70\" onmouseover=\"Tip('This implies the enrichment folds in the test set, calculated by<br>&nbsp;&nbsp;&nbsp;(t-ratio)&nbsp;&nbsp;/&nbsp;&nbsp;(b-ratio)<br><br>You may find <b>enrichment folds greater than 2 to be interesting</b>.<br><br><p style=&quot;background-color:$tgCColor&quot;>Enrichment in <b>test</b> set</p><p style=&quot;background-color:$bgCColor&quot;>Enrichment in <b>background</b> set</p><p style=&quot;background-color:$tgCColor&quot;>bZero: There is <b>NO</b> document associated with this MeSH term in the background set.</p>')\" onmouseout=\"UnTip()\">
									enrichment<br>folds
                                </th>
                            </tr>";

        for (my $j=0; $j < scalar @top10MeSHLine; $j++)    
        {   if (defined $top10MeSHLine[$j])
            {   # there are legitimate MeSH
                @tmpSplit 		= split (/\t/, $top10MeSHLine[$j]);
                $tmpMeSHString 	= "<tr><td width=\"40\">".($j+1)."</td><td width=\"330\"><a href=\"$ncbiMeSHLinkURL$tmpSplit[1]\">$tmpSplit[1]</a></td>";
                $tmpMeSHString 	.= "<td width=\"50\">".print_if_not_zero($tmpSplit[3], "<a href=\"javascript:generate_pmid_list_from_mesh_html_simplified('$tmpSplit[3]','t_plus','2','$fileNameBase','$fileNameBase','$tmpSplit[0]');\">$tmpSplit[3]</a>")."</td>";
                $tmpMeSHString 	.= "<td width=\"50\">".print_if_not_zero($tmpSplit[4], "<a href=\"javascript:generate_pmid_list_from_mesh_html_simplified('$tmpSplit[4]','t_minus','3','$fileNameBase','$fileNameBase','$tmpSplit[0]');\">$tmpSplit[4]</a>")."</td>";
                $tmpMeSHString 	.= "<td width=\"50\"><a href=\"javascript:openNewWindow('$ncbiPubMedURL$tmpSplit[1]".'[Mesh:NoExp]'."');\">$tmpSplit[5]</a></td>";
                $tmpMeSHString 	.= "<td width=\"50\"><a href=\"javascript:openNewWindow('$ncbiPubMedURL"."All[Filter] NOT $tmpSplit[1]".'[Mesh:NoExp]'."');\">$tmpSplit[6]</a></td>";
                $tmpMeSHString 	.= "<td width=\"70\">";
                if ($tmpSplit[11] >= 0.01)
			    {	$tmpMeSHString .=  sprintf("%.2f",$tmpSplit[11]);
			    }elsif ($tmpSplit[11] == 0)
			    {	$tmpMeSHString .=  '0';
			    }else
			    {	$tmpMeSHString .=  sprintf("%.2e",$tmpSplit[11]);
			    }
                $tmpMeSHString 	.= "</td>";
                
                $tmpMeSHString	.= "<td width=\"50\">".sprintf("%.2f",$tmpSplit[8])."</td>";
                $tmpMeSHString	.= "<td width=\"50\">".sprintf("%.2f",$tmpSplit[9])."</td>";
		        if ($tmpSplit[10] eq $tgZeroTag )
				{	$tmpMeSHString .= "<td bgcolor=\"$bgCColor\">";
				}elsif ($tmpSplit[10] eq $bgZeroTag)
				{	$tmpMeSHString .= "<td bgcolor=\"$tgCColor\">";
				}elsif ($tmpSplit[10] > 1)
				{	$tmpMeSHString .= "<td bgcolor=\"$tgCColor\">";
				}elsif ($tmpSplit[10] < 1)
				{	$tmpMeSHString .= "<td bgcolor=\"$bgCColor\">";
				}else
				{	$tmpMeSHString .= "<td>";
				}
				$tmpMeSHString	.= sprintf("%.1f",$tmpSplit[10])."</td></tr>\n";
                 
                 #  Print out the result
                 print FULLMESHRESULTHTML $tmpMeSHString;
                 
                 if ($j < 10)
                 {	print RESULT $tmpMeSHString;
                 }

            }else
            {   #  Do nothing if not defined
            }
        }    # for
        
        print RESULT "</table>";
        print RESULT "<p class=\"titleBarName1\">
        				Full result (<a href=\"MeSHCodeDistribution.html\">HTML</a>,&nbsp;&nbsp;
        						   <a href=\"MeSHCodeDistribution.txt\">TXT</a>,&nbsp;&nbsp;
                                   <a href=\"MeSHCodeDistribution.xls\">EXCEL)</a></p>
                      </div>";
		
		print FULLMESHRESULTHTML "</table><br>";
        print FULLMESHRESULTHTML "<p class=\"titleBarName1\">Full result (<a href=\"MeSHCodeDistribution.html\">HTML</a>,&nbsp;&nbsp;
        						   <a href=\"MeSHCodeDistribution.txt\">TXT</a>,&nbsp;&nbsp;
                                   <a href=\"MeSHCodeDistribution.xls\">EXCEL)</a><br></p>";
    }
    close FULLMESHRESULTHTML;

    print RESULT "
            <p>&nbsp;</p>
            <hr>
       
            <p>&nbsp;</p>
            <p><a href=\"../../main2.html\">SciMiner Homepage</a></p>
            </body>
            </html>";
    
    close RESULT;
}













sub generate_summary_html_from_merged_result
{	my $finalResultDir              = shift;
	my $finalResultWebDir			= shift;
    my $summaryFile                 = shift;
    my $resultHTMLFile              = shift;
    my $currentQueueEnvRef          = shift;
