        #  Generate pmid2List file	- Listing mined genes for each pmid
 #       generate_pmid2List_html($tmpSplit[1], $pmid2ListDir, $HUGOID2PMIDs{$tmpSplit[1]}, $pmid2ContDir, $tmpSplit[0], $tmpSplit[2], $tmpSplit[3], $tmpSplit[4], $serverURL, $pmid2TitleRef, $numPassGeneCountByPMIDRef, $medlineSymbolicLinkRef, $medlineEndnoteSymLinkRef, $htmlSymbolicLinkRef, $pmid2htmlSizeRef, $pmid2journalRef, $SciMinerURL, $cssFileName, $$currentQueueEnvRef{InstitutionCheck}, $tmpPMIDLinkURLRef, $symbol2ncbiEntrezGeneIDRef, $fileNameBase);

        #  Generate pmid2Cont file        
  #      generate_pmid2Cont_file($HUGOID2PMIDs{$tmpSplit[1]}, $pmid2ContDir, $pmid2ListDir, $hugoID2ContDir, $tmpSplit[1], $pmid2passContentRef, $serverURL, $pmid2TitleRef, $pmid2AbstractRef, $medlineSymbolicLinkRef, $medlineEndnoteSymLinkRef, $htmlSymbolicLinkRef, $pmid2htmlSizeRef, $SciMinerURL, $cssFileName, $$currentQueueEnvRef{InstitutionCheck}, $tmpPMIDLinkURLRef, $fileNameBase );
    }
    close SUMMARY;



	#  -------------------------------------------------------------------------    
    #  Start to write the result summary HTML file
	#  -------------------------------------------------------------------------    
    open (RESULT, ">".$resultHTMLFile);
	print RESULT    "<head>
		            <title>SciMiner Result Report Page</title>
		            <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
		            <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
		            <script language=\"JavaScript1.2\" src=\"sciminer.js\"></script>
		            <style type=\"text/css\"> body {	margin-left:10px;	}</style>
		            </head>
		            <body bgcolor=\"#EAF4F4\">
		            <script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
		            <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Mined Target Summary Page</b></p>
					<hr>
					<p class=\"titleBarName1\"><b>Here are the targets (genes/proteins) that SciMiner has mined.</b></p>
					";
  
    # Generate table for the actual gene
    print RESULT "  <table border=\"1\" width=\"950\">
                        <tr class=\"titleBarName1\">
                            <th width=\"40\">
                                Rank
                            </th>
                            <th width=\"40\" onmouseover=\"Tip('These are HUGO IDs. Click each ID to view the <b>HUGO detail</b>.')\" onmouseout=\"UnTip()\">
                                HUGO
                            </th>
                            <th width=\"60\" onmouseover=\"Tip('These are HUGO approved official symbols. Click each symbol to view the NCBI Entrez Gene record.')\" onmouseout=\"UnTip()\">
                                Symbol
                            </th>
                            <th width=\"400\" onmouseover=\"Tip('These are HUGO approved official gene names.')\" onmouseout=\"UnTip()\">
                                Target Name
                            </th>
                            <th width=\"50\" onmouseover=\"Tip('<b>#Occur</b>: These are the numbers of <b>identification</b> from the entire corpus.')\" onmouseout=\"UnTip()\">
                                #Occur
                            </th>
                            <th width=\"50\" onmouseover=\"Tip('<b>#Paper</b>: These are the numbers of <b>papers</b>.')\" onmouseout=\"UnTip()\">
                                #Paper
                            </th>
                            <th width=\"220\" onmouseover=\"Tip('<b>Matched_Terms</b>: These are terms that were matched in the text. Click each for more details.')\" onmouseout=\"UnTip()\">
                                Matched_Terms
                            </th>
                            <th width=\"40\" onmouseover=\"Tip('<b>MiMI</b>: This will bring up Cytoscape program and visualize protein-protein interaction network of the target.<br> Protein-Protein Interaction data is based on the MiMI (Michigan Molecular Interactions).<br> This network retrieval employes the Cytoscape MiMI plugin.')\" onmouseout=\"UnTip()\">
                                MiMI
                            </th>
                        </tr>";


    for (my $j=0; $j <= $#rankedHUGOIDs; $j++)    
    {   if (defined $rankedHUGOID2content{$rankedHUGOIDs[$j]})
        {   print RESULT "<tr><td width=\"40\">".($j+1)."</td><td width=\"40\"><a href=\"$hgncLinkURL$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[1]\">".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[1])."</a></td><td width=\"60\">";
            if (defined $$symbol2ncbiEntrezGeneIDRef{$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]})
            {	my $tmpNCBIID	= $$symbol2ncbiEntrezGeneIDRef{$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]};
            	print RESULT "<a href=\"$ncbiGeneLink$tmpNCBIID\">$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]</a>";
            }else
            {	print RESULT "<a href=\"$ncbiGeneSearch".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0])." AND Human[Orgn]\">$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]</a>";
            }
				
            print RESULT "</td><td width=\"400\">".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[2])."</td><td width=\"50\">".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[3])."</td><td width=\"50\">";
             
                            my $pmidListDir = "pmid2ListDir/$rankedHUGOIDs[$j].html";
             print RESULT   "<a href=\"$pmidListDir\">".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[4])."</a></td><td width=\"220\">";
                            
             #               my $detailResultURL = "hugoID2ContDir/$rankedHUGOIDs[$j].html";
                            my $tmpMatchedTerm	= $rankedHUGOID2content{$rankedHUGOIDs[$j]}->[5];
                            substr($tmpMatchedTerm, -3, 3) = '';
                            
             print RESULT  "<a href=\"javascript:generate_detailed_matrched_terms_new('$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[1]','$fileNameBase','$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[3]','$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[4]')\">".$tmpMatchedTerm."</a></td><td width=\"40\">";
#             print RESULT  "<a href=\"javascript:generate_detailed_matrched_terms('$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[1]','$fileNameBase','$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[3]','$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[4]')\">".$tmpMatchedTerm."</a></td><td width=\"40\">";
             
            if ((defined $$symbol2ncbiEntrezGeneIDRef{$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]}) && ($$symbol2ncbiEntrezGeneIDRef{$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]} ne ""))
            {	print RESULT "<a href=\"$mimiNameLink$$symbol2ncbiEntrezGeneIDRef{$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]}\"><img src=\"$mimiIconURL\"></a>";
            }else
            {	print RESULT "&nbsp;";
            }
				print RESULT "</td></tr>\n";
        }
    }


    print RESULT "</table><p>&nbsp;</p><p><a href=\"intro2.html\"><font class=\"sectionTitleName2\">SciMiner Homepage</font></a></p>
    </body>
    </html>";
    
    close RESULT;
}












sub calculate_new_document_count_ahead_of_query_grif
{	my $currentQueryID		= shift;
	my $annoENVRef			= shift;
	my $dbh					= shift;
	my $pmidArrRef			= shift;
	
	my $SciMinerPath 		= $$annoENVRef{SciMinerPath};
	
	#  Read pmid list files
	my @pmidFiles 		= glob ($SciMinerPath."Work/GRIFQuery_*.list");
	my %totalPMIDHash	= ();
	my @totalPMIDs		= ();
	my $line			= '';
	my $aheadFileCnt	= 0;
	
	foreach my $fileName (@pmidFiles)
	{	#  Check if it is ahead of the given query
		my @tmp1	= split(/\//, $fileName);
		my @tmp2	= split(/\_/, $tmp1[$#tmp1]);
		if ($tmp2[1] < $currentQueryID)
		{	$aheadFileCnt++;
			#  This file needs to be read
			open (LIST, $fileName);
			while(<LIST>)
			{	$line = $_;
				$line =~ s/\r|\n//g;
				$totalPMIDHash{$line}	= 1;
			}
			close LIST;
		}
	}	
	
	#  Mark overlapping
	my @currentNewPMID			= ();		# only in the given query
	foreach my $pmid (@{$pmidArrRef})
	{	if (not defined $totalPMIDHash{$pmid})
		{	push @currentNewPMID, $pmid;
			$totalPMIDHash{$pmid} = 2;
		}
	}
	
	#  Collect total PMIDs
	@totalPMIDs			= keys %totalPMIDHash;
	my $docString		= join (",", @totalPMIDs);
	my $sql         	= "SELECT pmid FROM documentpubmed WHERE pmid in ($docString)";
	my $sth         	= $dbh->prepare($sql);
	$sth->execute();
	my @row         	= ();
	my %pmidProcessed	= ();
	while(@row = $sth->fetchrow_array)
	{   $pmidProcessed{$row[0]}	= 1;
	}
	
	#  Calculate the number of new documents to be downloaded, processed for the current query
	my $completelyNewDocCount	= 0;
	foreach my $pmid (@currentNewPMID)
	{	if (not defined $pmidProcessed{$pmid})
		{	$completelyNewDocCount++;
		}
	}
	
	#  Calculate the number of new documents to be downloaded, processed for the ahead queries
	my $newAheadDocuments		= 0;
	foreach my $pmid (@totalPMIDs)
	{	if ((not defined $pmidProcessed{$pmid}) && ($totalPMIDHash{$pmid} == 1))
		{	$newAheadDocuments++;
		}
	}

	%pmidProcessed	= ();	undef %pmidProcessed;
	@totalPMIDs		= ();	undef @totalPMIDs;
	
	return($aheadFileCnt, $newAheadDocuments, $completelyNewDocCount);


}
sub calculate_new_document_count_ahead_of_query
{	my $currentQueryID		= shift;
	my $annoENVRef			= shift;
	my $dbh					= shift;
	my $pmidArrRef			= shift;
	
	my $SciMinerPath 		= $$annoENVRef{SciMinerPath};
	
	#  Read pmid list files
	my @pmidFiles 		= glob ($SciMinerPath."Work/Query_*.list");
	my %totalPMIDHash	= ();
	my @totalPMIDs		= ();
	my $line			= '';
	my $aheadFileCnt	= 0;
	
	foreach my $fileName (@pmidFiles)
	{	#  Check if it is ahead of the given query
		my @tmp1	= split(/\//, $fileName);
		my @tmp2	= split(/\_/, $tmp1[$#tmp1]);
		if ($tmp2[1] < $currentQueryID)
		{	$aheadFileCnt++;
			#  This file needs to be read
			open (LIST, $fileName);
			while(<LIST>)
			{	$line = $_;
				$line =~ s/\r|\n//g;
				$totalPMIDHash{$line}	= 1;
			}
			close LIST;
		}
	}	
	
	#  Mark overlapping
	my @currentNewPMID			= ();		# only in the given query
	foreach my $pmid (@{$pmidArrRef})
	{	if (not defined $totalPMIDHash{$pmid})
		{	push @currentNewPMID, $pmid;
			$totalPMIDHash{$pmid} = 2;
		}
	}
	
	#  Collect total PMIDs
	@totalPMIDs			= keys %totalPMIDHash;
	my $docString		= join (",", @totalPMIDs);
	my $sql         	= "SELECT pmid, statusProcessed, statusMined FROM document WHERE pmid in ($docString)";
	my $sth         	= $dbh->prepare($sql);
	$sth->execute();
	my @row         	= ();
	my %pmidProcessed	= ();
	while(@row = $sth->fetchrow_array)
	{   $pmidProcessed{$row[0]}	= 1;
		if ((defined $row[1]) && ($row[1] == 0))
		{	# downloading, processing, mining
			$pmidProcessed{$row[0]}	= 2;
		}elsif ((defined $row[2]) && ($row[2] == 0))
		{	# only mining is needed
			$pmidProcessed{$row[0]}	= 1;
		}else
		{	# completed
			$pmidProcessed{$row[0]}	= 0;
		}
	}

	
	#  Calculate the number of new documents to be downloaded, processed for the current query
	my $completelyNewDocCount	= 0;
	foreach my $pmid (@currentNewPMID)
	{	if (not defined $pmidProcessed{$pmid})
		{	$completelyNewDocCount++;
		}
	}
	
	#  Calculate the number of new documents to be downloaded, processed for the ahead queries
	my $newAheadDocuments		= 0;
	my $newMiningAheadDocuments	= 0;
	foreach my $pmid (@totalPMIDs)
	{	if (((not defined $pmidProcessed{$pmid}) && ($totalPMIDHash{$pmid} == 1)) ||
	        ((    defined $pmidProcessed{$pmid}) && ($pmidProcessed{$pmid} == 2)) )
		{	$newAheadDocuments++;
		}elsif ((    defined $pmidProcessed{$pmid}) && ($pmidProcessed{$pmid} == 1))
		{	$newMiningAheadDocuments++;
		}
	}

	%pmidProcessed	= ();	undef %pmidProcessed;
	@totalPMIDs		= ();	undef @totalPMIDs;
	
	return($aheadFileCnt, $newAheadDocuments, $newMiningAheadDocuments, $completelyNewDocCount);
}







################################################################################
#
#   SECTION_4   Query Queue Processing   
#
################################################################################
# -------------------------------------------------------------------------------------------------
# process_retrieved_PMIDs
# -------------------------------------------------------------------------------------------------
sub process_retrieved_PMIDs
{   my $email               = shift;
    my $userName            = shift;
    my $queryName           = shift;
    my $queryString         = shift;
    my $listText            = shift;
    my $count               = shift;
    my $pmidArrRef          = shift;
    my $queryType           = shift;
    my $ignoreName          = shift;
    my $ignoreCustomText    = shift;
    my $excludeSymbol       = shift;
    my $excludeCustomText   = shift;
    my $includeSymbol       = shift;
    my $includeCustomText   = shift;
    my $useLengthOption     = shift;
    my $wordLengthThreshold = shift;
    my $phenotypeOnlyFilter = shift;
    my $tmpLocalURL			= shift;
    my $newDocCount			= shift;
    my $useScoreThreshold	= shift;
    my $scoreThreshold		= shift;
    my $miningMode			= shift;
    my $speciesExtension 	= shift;
    use DBI;
  
    #  Load working environment for ANNOTATION
    my %annoENV 			= anno_environmental_file_open ( );
    my $annoBaseDir 		= $annoENV{ANNOPath};
    my %currentQueueEnv		= ();
		

	#  Update the SciMinerServerURL
	$annoENV{SciMinerServerURL}	= $tmpLocalURL;
		
    #  Database Access Information
    my $SciMinerDB   = "DBI:mysql:database=".$annoENV{DB} || return (-1, "!ERROR: No database specified");
    my $username    = $annoENV{username} || return (-1, "!ERROR: No username specified");
    my $password    = $annoENV{password} || return (-1, "!ERROR: No password specified");

    #  ------------------------------------------------------------------------
    #  Retrieve User Information from SciMinerDB
    #  ------------------------------------------------------------------------
    my $dbh         = DBI->connect($SciMinerDB, $username, $password, {PrintError => 0}) || return (-1, "!ERROR: Couldn't connect to database ".$DBI::errstr);

    my $sql         = "SELECT userID, passCode, institute FROM user where email = \"$email\"";
    my $sth         = $dbh->prepare($sql);
    $sth->execute();
    my @row         = $sth->fetchrow_array;
    my $userID      = $row[0];
    my $passCode    = $row[1];
    my $instCheck	= 0;
    if ((defined $row[2]) && ($row[2] ne "") && (defined $annoENV{Institution}) && ($annoENV{Institution} eq $row[2]))
    {	$instCheck	= 1;
    }
    
    #  ------------------------------------------------------------------------
    #  Update SciMinerDB for this query and get the queryID
    #  ------------------------------------------------------------------------
    my @tmpArr      = ($userID, $queryName, 1, $queryType);#, $listText);
    my $commands    = "\"".join("\",\"", @tmpArr)."\"";
    my $queryID     = '';
    my $numPMID     = scalar @{$pmidArrRef};
    
    #  Insert new query information 
    $dbh->do("INSERT INTO `query` (userID, queryName, status, listType, dateCreate, numPMID) VALUES ($commands, curdate(), $numPMID)") || print "!ERROR: $tmpArr[0] $DBI::errstr\n" ;   
    
    #  Retrieve the queryID of the recently inserted query
    $sth            = $dbh->prepare("SELECT queryID FROM query ORDER BY queryID DESC LIMIT 1");
    $sth->execute();
    @row            = $sth->fetchrow_array;#($result);
    $queryID        = $row[0];
    
    #  ------------------------------------------------------------------------
    #  Write the query info into a file
    #  ------------------------------------------------------------------------    
    my @tmpSplit        = split(/\@/, $email);
    my $fileNameBase    = 'Query_'.$queryID.'__'.$tmpSplit[0];
    my $confFileName    = "/tmp/".$fileNameBase.'.conf';
    my $listFileName    = "/tmp/".$fileNameBase.'.list';
    

    #  Final Result Directory
    mkdir ("$annoENV{SciMinerPath}Work/FinalResults/") 				|| print "";
    mkdir ("$annoENV{SciMinerPath}Work/FinalResults/$fileNameBase/") || print "";
    mkdir ("$annoENV{SciMinerWebPath}FinalResults/") 				|| print "";
    mkdir ("$annoENV{SciMinerWebPath}FinalResults/$fileNameBase/") 	|| print "";
  

    #  Check the number of PMID before actually writing and continuing to next step
    my $pmidCount       = scalar @{$pmidArrRef};
    if ($pmidCount <= 0)
    {   #  This query will not be processed
        print "<p> Your query resulted in 0 valid Pubmed document and will not be processed by SciMiner. <br><br>".
              "Please check your query and run again.</p>";
        return (0);
    }

    #  Write the PMID list into file
    open (LIST, ">".$listFileName) || print "! Can't write into file. Contact the admin<br>";    
    foreach my $pmid (@{$pmidArrRef})
    {   print LIST $pmid."\n";
    }       
    close (LIST);
    
    #  Write custom ignore list file
    my $ignoreFileName = '';
    if ($ignoreName)
    {   my $atLeastOneUniqueFound	= 0;
    	my @customIgnoreSplits = split (/\n/, $ignoreCustomText);
	    foreach (@customIgnoreSplits)
	    {   $_ =~ s/\r|\n//g;
	    }
	    
    	# Need to check for any overlapping
    	$dbh         			= DBI->connect($SciMinerDB, $username, $password, {PrintError => 0}) || 
	                      			return (-1, "!ERROR: Couldn't connect to database ".$DBI::errstr);
	    $sql         			= "SELECT ignoreTerm FROM ignorelist";
	    $sth         			= $dbh->prepare($sql);
	    $sth->execute();
	    
	    my @ignoreInDB			= ();
	    my $finalCustomIgnore	= '';
	    while(@row = $sth->fetchrow_array)
	    {   if (defined $row[0])
	        {   push @ignoreInDB, lc($row[0]);
	        }
	    }
	    
		#  Compare customary list with DB list
		foreach my $customaryIgnore (@customIgnoreSplits)
		{   my $sameFound	= 0;
			my $customaryTerm = lc ($customaryIgnore);
			foreach my $dbIgnore (@ignoreInDB)
			{	if ($dbIgnore eq $customaryTerm)		#	$dbIgnore term was already lowered
				{	$sameFound = 1;
					last;
				}
			}
			if (! $sameFound)
			{   $finalCustomIgnore .= $customaryIgnore."\n";
				$atLeastOneUniqueFound = 1;
			}
		}
		
		if ($atLeastOneUniqueFound)
		{   $ignoreFileName = "/tmp/".$fileNameBase.'.custom_ignore';
	        open (IGNORE, ">".$ignoreFileName);
	        print IGNORE $finalCustomIgnore;
	        close IGNORE;
	        `mv $ignoreFileName $annoENV{SciMinerPath}/Work/`;
		}else
		{	$ignoreFileName = "";
		}
    	
    }

    #  Write custom exclude list file
    my $excludeFileName = '';
    if ($excludeSymbol)
    {   my $oneUniqueLineEntered	= 0;
    	my @customExcludeSplits = split (/\n/, $excludeCustomText);
	    foreach (@customExcludeSplits)
	    {   $_ =~ s/\r|\n//g;
	    }
	    
    	# Need to check for any overlapping
    	$dbh         			= DBI->connect($SciMinerDB, $username, $password, {PrintError => 0}) || 
	                      			return (-1, "!ERROR: Couldn't connect to database ".$DBI::errstr);
	    $sql         			= "SELECT symbolToExclude, conditionToExclude FROM excludelist";
	    $sth         			= $dbh->prepare($sql);
	    $sth->execute();
	    
	    my %excludeDBHash		= ();
	    my $finalCustomExclude	= '';
	    while(@row = $sth->fetchrow_array)
	    {   if (not defined $excludeDBHash{lc($row[0])})
	    	{   my @tmpArray = ();
	    		push @tmpArray, lc($row[1]);
	    		$excludeDBHash{lc($row[0])} = \@tmpArray;
	    	}else
	    	{   push @{$excludeDBHash{lc($row[0])}}, lc($row[1]);
	    	}
	    }
	    
		#  Compare customary list with DB list
		foreach my $customaryExcludeLine (@customExcludeSplits)
		{   my @lineSplit = split (/\t/, $customaryExcludeLine);
			if (not defined $excludeDBHash{lc($lineSplit[0])})
			{   $finalCustomExclude .= $customaryExcludeLine."\n";
				$oneUniqueLineEntered = 1;
			}else
			{   # If there is same symbol in the database alreay, check the exclusion condition
				my $outlineString 	= $lineSplit[0];
				my $atleastOneUniq	= 0;
				for (my $l=1; $l <= $#lineSplit; $l++)
				{   my $sameFound	= 0;
					my @dbCondition = @{$excludeDBHash{lc($lineSplit[0])}};
					my $custumaryCond	= lc ($lineSplit[$l]);
					for (my $k=0; $k <= $#dbCondition; $k++)
					{   if ($custumaryCond eq $dbCondition[$k])
						{   $sameFound = 1;
							last;
						}
					}
					#  Add the customary condition to the final string
					if (!$sameFound)
					{   $outlineString .= "\t".$lineSplit[$l];
						$atleastOneUniq = 1;
					}
				}
				if ($atleastOneUniq)
				{   $finalCustomExclude .= $outlineString."\n";
					$oneUniqueLineEntered = 1;
				}
			}
		}
    
    	if ($oneUniqueLineEntered)
    	{   $excludeFileName = "/tmp/".$fileNameBase.'.custom_exclude';
	        open (EXCLUDE, ">".$excludeFileName);
	        print EXCLUDE $excludeCustomText;
	        close EXCLUDE;
	        `mv $excludeFileName $annoENV{SciMinerPath}/Work/`;
    	}else
    	{   # Remove the custom exclude conditions from the memory
    		$excludeFileName = "";
    	}
    	
    }
    
    #  Write custom include list file
    my $includeFileName = '';
    if ($includeSymbol)
    {   my $oneUniqueLineEntered	= 0;
    	my @customIncludeSplits = split (/\n/, $includeCustomText);
	    foreach (@customIncludeSplits)
	    {   $_ =~ s/\r|\n//g;
	    }
	    
    	# Need to check for any overlapping
    	$dbh         			= DBI->connect($SciMinerDB, $username, $password, {PrintError => 0}) || 
	                      			return (-1, "!ERROR: Couldn't connect to database ".$DBI::errstr);
	    $sql         			= "SELECT symbolToInclude, conditionToInclude FROM includelist";
	    $sth         			= $dbh->prepare($sql);
	    $sth->execute();
	    
	    my %includeDBHash		= ();
	    my $finalCustomInclude	= '';
	    while(@row = $sth->fetchrow_array)
	    {   if (not defined $includeDBHash{lc($row[0])})
	    	{   my @tmpArray = ();
	    		if (not defined $row[1])
	    		{   push @tmpArray, "UNDEF";
	    		}else
	    		{   push @tmpArray, lc($row[1]);
	    		}
	    		$includeDBHash{lc($row[0])} = \@tmpArray;
	    	}else
	    	{   push @{$includeDBHash{lc($row[0])}}, lc($row[1]);
	    	}
	    }
	    
		#  Compare customary list with DB list
		foreach my $customaryIncludeLine (@customIncludeSplits)
		{   my @lineSplit = split (/\t/, $customaryIncludeLine);
			if (not defined $includeDBHash{lc($lineSplit[0])})
			{   $finalCustomInclude .= $customaryIncludeLine."\n";
				$oneUniqueLineEntered = 1;
			}else
			{   # If there is same symbol in the database already, check the inclusion condition
				
				my $outlineString 	= $lineSplit[0];
				my $atleastOneUniq	= 0;
				
				# In case, DB has already broad inclusion (meaning every incident is include)
				if ($includeDBHash{lc($lineSplit[0])}->[0] eq 'UNDEF')
				{   # Skip the customary anyway
				}else
				{	if ((not defined $lineSplit[1]) || ($lineSplit[1] eq ""))
					{   # Customary inclusion condition is 'unconditional'
						# Add this to the finalString
						$finalCustomInclude .= $customaryIncludeLine."\n";
						$oneUniqueLineEntered = 1;
					}else
					{   # now, both db and customary are conditional
						for (my $l=1; $l <= $#lineSplit; $l++)
						{   my $sameFound	= 0;
							my @dbCondition = @{$includeDBHash{lc($lineSplit[0])}};
							my $custumaryCond	= lc ($lineSplit[$l]);
							for (my $k=0; $k <= $#dbCondition; $k++)
							{   my $dbCond = lc ($dbCondition[$k]);
								if ($custumaryCond eq $dbCond)
								{   $sameFound = 1;
									last;
								}
							}
							
							#  Add the customary condition to the final string
							if (!$sameFound)
							{   $outlineString .= "\t".$lineSplit[$l];
								$atleastOneUniq = 1;
							}
						}
						if ($atleastOneUniq)
						{   $finalCustomInclude .= $outlineString."\n";
							$oneUniqueLineEntered = 1;
						}
					}
				}
			}
		}
    
    	if ($oneUniqueLineEntered)
    	{   $includeFileName = "/tmp/".$fileNameBase.'.custom_include$excludeDBHash{lc($row[0])}';
	        open (INCLUDE, ">".$includeFileName);
	        print INCLUDE $includeCustomText;
	        close INCLUDE;
	        `mv $includeFileName $annoENV{SciMinerPath}/Work/`;
    	}else
    	{   # Remove the custom exclude conditions from the memory
    		$includeFileName = "";
    	}
    }

    
    #  Write configuration into file
    open (CONF, ">".$confFileName) || print "! Can't write into file. Contact the admin<br>";
    print CONF "queryID\t$queryID\n";
    print CONF "email\t$email\n";
    print CONF "userName\t$userName\n";
    print CONF "queryName\t$queryName\n";
    print CONF "count\t$count\n";
    print CONF "fileNameBase\t$fileNameBase\n";
    print CONF "ignoreName\t$ignoreFileName\n";
    print CONF "excludeSymbol\t$excludeFileName\n";
    print CONF "includeSymbol\t$includeFileName\n";
    my $queryAnalInfo	= 	"--Mining Query Info--\n".
							"Query ID     : $queryID\n".
    						"Query name   : $queryName\n".
    						"# of PMIDs   : $count\n";
    if (defined $queryString)
    {	$queryAnalInfo	.= "Query string : $queryString\n\n"; 
    }

    if (defined $useLengthOption)
    {   print CONF "useLengthOption\t$useLengthOption\n";
        print CONF "wordLengthThreshold\t$wordLengthThreshold\n";
    }
    if (defined $phenotypeOnlyFilter)
    {   print CONF "phenotypeOnlyFilter\t$phenotypeOnlyFilter\n";
    }
    print CONF "queryString\t$queryString\n";    
	print CONF "SciMinerServerURL\t$tmpLocalURL\n";
	print CONF "InstitutionCheck\t$instCheck\n";
	print CONF "useScoreThreshold\t$useScoreThreshold\n";
	print CONF "scoreThreshold\t$scoreThreshold\n";
	print CONF "miningMode\t$miningMode\n";
	print CONF "speciesExtension\t$speciesExtension\n";	
    close (CONF);    

	#  Creating currentQueueEnv hash 
	$currentQueueEnv{queryID}				= $queryID;
	$currentQueueEnv{email}					= $email;
	$currentQueueEnv{userName}				= $userName;
	$currentQueueEnv{queryName}				= $queryName;
	$currentQueueEnv{queryString}			= $queryString;
	$currentQueueEnv{count}					= $count;
	$currentQueueEnv{fileNameBase}			= $fileNameBase;
	$currentQueueEnv{miningMode}			= $miningMode;
	$currentQueueEnv{speciesExtension}		= $speciesExtension;	
	$currentQueueEnv{SciMinerServerURL}		= $tmpLocalURL;
	$currentQueueEnv{InstitutionCheck}		= $instCheck;
	$currentQueueEnv{ignoreName}			= $ignoreFileName;
    $currentQueueEnv{excludeSymbol}			= $excludeFileName;
    $currentQueueEnv{includeSymbol}			= $includeFileName;
	$currentQueueEnv{useLengthOption}		= $useLengthOption;
    $currentQueueEnv{wordLengthThreshold}	= $wordLengthThreshold;
    $currentQueueEnv{phenotypeOnlyFilter}	= $phenotypeOnlyFilter;
	$currentQueueEnv{useScoreThreshold}		= $useScoreThreshold;
	$currentQueueEnv{scoreThreshold}		= $scoreThreshold;

    #  Generate a temporary result html file
    generate_temporary_result_html ("$annoENV{SciMinerServerURL}/SciMiner/FinalResults/$fileNameBase/result.html",
                                	"$annoENV{SciMinerWebPath}FinalResults/$fileNameBase/result.html",
                                	\%currentQueueEnv, 
                                	"$annoENV{SciMinerServerURL}/SciMiner/");
                                		
    #  Move the created configuration files
    `mv $confFileName $annoENV{SciMinerPath}/Work/`;
    `mv $listFileName $annoENV{SciMinerPath}/Work/`;

    #  Initiate the SciMiner auto process if not running
    my $psResult = `ps -ef | grep 'MonitorSciMinerQueue.pl'`;
    my $SciMinerQueueMonitorStatus = 0;
    my @tmpLineSplit = split (/\n/, $psResult);

    foreach my $line (@tmpLineSplit)
    {   if ($line =~ /perl/)
        {   # There is a process running with 'MonitorSciMinerQueue.pl'
            $SciMinerQueueMonitorStatus = 1;
        }
    }
    
    #  Launch SciMinerQueueMonitor.pl only when it's not running
    if (! $SciMinerQueueMonitorStatus)
    {   #  If there is no MonitorSciMinerQueue running
    	#  Check and delete 'CurrentQueue' and 'CurrentList'
    	if (-f "$annoENV{SciMinerPath}/Work/CurrentList")
    	{   `rm $annoENV{SciMinerPath}/Work/CurrentList`;
    	}
    	if (-f "$annoENV{SciMinerPath}/Work/CurrentQueue")
    	{   `rm $annoENV{SciMinerPath}/Work/CurrentQueue`;
    	}    	
    	system ("$annoENV{Perl} $annoENV{SciMinerPath}/Scripts/Main/MonitorSciMinerQueue.pl &");
    }
    
    my ($aheadFileCnt, $newAheadDocuments, $newMiningAheadDocuments, $completelyNewDocCount)
    	= calculate_new_document_count_ahead_of_query ($queryID, \%annoENV, $dbh, $pmidArrRef);
	my $startProcessingTimeSeconds	= 	$aheadFileCnt*30 + 				# script, dictionary loading
										$aheadFileCnt*10 + 				# summarizing
										$newAheadDocuments*10 + 		# not processed
										$newMiningAheadDocuments*5; 	# only mining is required
	my $startProcessingTimeStr		=	'';
	if ($startProcessingTimeSeconds >= 3600)
	{	my $hours	= int($startProcessingTimeSeconds / 3600);
		$startProcessingTimeStr		= "within $hours hour(s)";
	}elsif ($startProcessingTimeSeconds <= 60)
	{	$startProcessingTimeStr		= "within 1 minute";
	}else
	{	my $minutes	= int($startProcessingTimeSeconds / 60);
		$startProcessingTimeStr		= "within $minutes minute(s)";
	}
	
	my $currentProcessingTime		= 	$completelyNewDocCount*10 + 30 + 10;
	my $currentProcessingTimeStr	= '';
	if ($currentProcessingTime >= 3600)
	{	my $hours	= int($currentProcessingTime / 3600);
		$currentProcessingTimeStr	= "~ $hours hours";
	}elsif ($currentProcessingTime <= 60)
	{	$currentProcessingTimeStr		= "less than 1 minute";
	}else
	{	my $minutes	= int($currentProcessingTime / 60);
		$currentProcessingTimeStr		= "~ $minutes minutes";
	}
	
										
	
    #  !_! New formatted table for result summary
    print 	"<table border='1' width='800' align='center' style=\"text-align: center\">
				<tr class='titleBarName1'>
					<th width='300'>User Email</th>
					<th width='500'>$email</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Query Name</th>
					<th>$queryName</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Query String</th>
					<th>";
	if ((defined $queryString) && ($queryString ne ""))
	{	print "$queryString</th>";
	}else
	{	print "&nbsp;</th>";
	}
	print 	"	</tr>
				<tr class='titleBarName1'>
					<th>Query ID #</th>
					<th>$queryID</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Number of total documents</th>
					<th>$count</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Number of new documents</th>
					<th>$completelyNewDocCount (These will take more time)</th>
				</tr>
				<tr class='titleBarName1'>	
					<th>
						&nbsp;
					</th>
					<th>
						&nbsp;
					</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Number of queued queries<br>ahead of your query</th>
					<th>$aheadFileCnt</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Submission Time</th>
					<th>".get_current_time_full()."</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Estimated initaition time</th>
					<th>$startProcessingTimeStr</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Estimated processing time</th>
					<th>$currentProcessingTimeStr</th>
				</tr>
    		</table>";
    		
    		
    		
   
     
    #  Give the order in the queue
    sleep(1);

    
    
    print "<p align='center' class='titleBarName1'><br> Note that your query resulted in <b>$count</b> documents, among which $completelyNewDocCount are new to SciMiner.<br>";
    print "There are <b>$aheadFileCnt queries</b> queued ahead of this query.<br>";
    
    my $resultHTMLURL = $annoENV{SciMinerServerURL}."SciMiner/FinalResults/$fileNameBase/result.html";
    my $shortResultHTMLURL = "FinalResults/$fileNameBase/result.html";
    print "Your result will be sent to <b>$email</b> when it's ready.<br>";
	print "<a href=\"$resultHTMLURL\">$resultHTMLURL</a><br>";

    print "You should expect your own query processed roughly at 500~1000 NEW documents / hour <br>
               But this can be significantly affected by the internet connection. </p>";
    

    #  Update query table for resultURL
    $dbh->do("UPDATE query SET resultURL=\"$shortResultHTMLURL\" WHERE queryID = $queryID");

    #  Send out initial email
    if (( defined $annoENV{'SendMail'}) && ($annoENV{'SendMail'}))
	{	send_initial_email($resultHTMLURL, $email, $fileNameBase, $queryAnalInfo );
	}
} 


































































































































































































































































































































































































































































































































































################################################################################
#
#   SECTION_5   Query Result Processing
#
################################################################################
sub generate_analysys_result_summary_with_noresult
{   my $finalResultWebDir       = shift;
    my $resultHTMLFile          = shift;
    my $pmidListHTMLFile        = shift;
    my $currentQueueEnvRef      = shift;
    my $serverBaseURL           = shift;
    my $dbh                     = shift;
    my $analID                 	= shift;
    my $errorMessage			= shift;
    my $tgQueryEnvRef			= shift;
    my $bgQueryEnvRef			= shift;

    my $fileNameBase    = $$currentQueueEnvRef{fileNameBase};
    my $serverURL       = $serverBaseURL."SciMiner/FinalResults/$fileNameBase/";
    my $SciMinerURL      = $serverBaseURL."SciMiner/";
    my $cssURL			= $SciMinerURL.'css/sciminer-modern.css';
    
    #  Begin to write the resultHTMLFile
    open (RESULT, ">".$resultHTMLFile);
    
    print RESULT "  <head>
                    <title>SciMiner Result Report Page</title>
                    <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
                    <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
                	<style type=\"text/css\"> body {	margin-left:10px;	}</style>
                    </head>
                    
                    <body bgcolor=\"#EAF4F4\">
                    <p class=\"pageName\" align=\"center\"><b>SciMiner Result Report Page</b></p>
                    <hr>
                    <p class='titleBarName1'><b>Your analysis encountered an error with the following message<b><br>
                    <b><i>$errorMessage</i></b><br><br>
                    Your query and search options were</font></p>
                    <table border=\"1\" width=\"850\">
                    ";


	my $bgPrintOut  = 0;
    if ((defined $tgQueryEnvRef) && ($tgQueryEnvRef ne ""))
    {	if ((($$currentQueueEnvRef{GeneEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{GeneEnrichmentSelection} eq 'Selected')) || 
		    (($$currentQueueEnvRef{GOEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{GOEnrichmentSelection} eq 'Selected')) || 
		    (($$currentQueueEnvRef{MeSHEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{MeSHEnrichmentSelection} eq 'Selected')) ||
		    (($$currentQueueEnvRef{PathwayEnrichmentCheck} eq "on") && ($$currentQueueEnvRef{PathwayEnrichmentSelection} eq 'Selected')) || 
		    (($$currentQueueEnvRef{PPICheck} eq "on") && ($$currentQueueEnvRef{PPISelection} eq 'Selected')))
		{   $bgPrintOut = 1;
		}
    }
    
    # Running condition (options)
    my %itemContent		= ();
    my $otherOption		= '';
    my $enrichmentTest	= '';
    my $ppiSelection	= '';
    foreach my $keyTerm (sort(keys %{$currentQueueEnvRef}))
    {   if ((defined $keyTerm) && ($keyTerm ne "") && (defined $$currentQueueEnvRef{$keyTerm}))
        {   if ($keyTerm eq 'queryID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Query ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'analID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Analysis ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'userName')
        	{   $itemContent{1}		=	print_tmpKey_tmpTerm_for_selected_option('User name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'email')
        	{	$itemContent{2}		=	print_tmpKey_tmpTerm_for_selected_option('Email', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Query information
        	elsif ($keyTerm eq 'queryName')
        	{   $itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Query name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'queryString')
        	{   $itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Query string', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'count')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('PMID count #', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Some analysis information
        	elsif ($keyTerm eq 'targetQueryNumber')
        	{   my $additionalString	= "&nbsp;&nbsp;(Name:&nbsp;'$$tgQueryEnvRef{queryName}',&nbsp;# of PMIDs:&nbsp;'$$tgQueryEnvRef{numPMID}',&nbsp;# of genes:&nbsp;'$$tgQueryEnvRef{numGene}')"."&nbsp;&nbsp;(<a href=\"../../$$tgQueryEnvRef{resultURL}\">Result Page</a>)&nbsp;&nbsp;$$currentQueueEnvRef{'MinPaperMethodTG'}&nbsp;($$currentQueueEnvRef{MinTopPaperTG})";
        		$itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Target Query #', $$currentQueueEnvRef{$keyTerm}.$additionalString);
        	}elsif ($keyTerm eq 'bgQueryNumber')
        	{   my $additionalString	= '';
        		if (!$bgPrintOut)
                {   next;
                }else
                { 	$additionalString   = "&nbsp;&nbsp;(Name:&nbsp;'$$bgQueryEnvRef{queryName}',&nbsp;# of PMIDs:&nbsp;'$$bgQueryEnvRef{numPMID}',&nbsp;# of genes:&nbsp;'$$bgQueryEnvRef{numGene}')"."&nbsp;&nbsp;(<a href=\"../../$$bgQueryEnvRef{resultURL}\">Result Page</a>)&nbsp;&nbsp;$$currentQueueEnvRef{'MinPaperMethodBG'}&nbsp;($$currentQueueEnvRef{MinTopPaperBG})";
                }
        		$itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Background Query #', $$currentQueueEnvRef{$keyTerm}.$additionalString);
        	}
        	#elsif ($keyTerm eq 'targetQueryNumber')
        	#{   $itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Target Query #', $$currentQueueEnvRef{$keyTerm});
        	#}elsif ($keyTerm eq 'bgQueryNumber')
        	#{   $itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Background Query #', $$currentQueueEnvRef{$keyTerm});
        	#}
        	elsif ($keyTerm eq 'PValueThreshold')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('P-value Threshold', $$currentQueueEnvRef{$keyTerm});
        	}

        	elsif (($keyTerm eq 'GeneEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene list";
        	}elsif (($keyTerm eq 'GOEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene Ontology";
        	}elsif (($keyTerm eq 'MeSHEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"MeSH term";
        	}elsif (($keyTerm eq 'PathwayEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}$enrichmentTest		.=	"Pathway";
        	}elsif (($keyTerm eq 'PPICheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Protein-Protein Interaction";
        	}elsif ($keyTerm eq 'PPISelection') 
        	{   $ppiSelection		.=	" (PPI Selection: ".$$currentQueueEnvRef{$keyTerm}.')';
        	}
        	
			#  Check for other options
        	elsif ($keyTerm eq 'phenotypeOnlyFilter')
        	{   $otherOption		.= "Remove_phenotype_gene, ";
        	}elsif ($keyTerm eq 'useLengthOption')
        	{   $otherOption		.= "Use_symbol_length_option, ";
        	}elsif ($keyTerm eq 'wordLengthThreshold')
        	{   $otherOption		.= "Always_accept_symbol_longer_than: $$currentQueueEnvRef{$keyTerm}";
        	}
        }
    }
    
    #  Print out sorted query/analysis options
    my @sortedKey	= sort {$a <=> $b} keys %itemContent;
    foreach my $sortedTermKey (@sortedKey)
    {   if (defined $itemContent{$sortedTermKey})
    	{	print RESULT $itemContent{$sortedTermKey};
    	}
    }

	#  Process enrichment options
	if ($enrichmentTest)
    {   if (($ppiSelection) && ($$currentQueueEnvRef{"PPICheck"} =~ /on/i))
    	{	$enrichmentTest	.= $ppiSelection;
    	}
    	print RESULT print_tmpKey_tmpTerm_for_selected_option('Enrichment tests', $enrichmentTest);
    }
    
    #  Process other options
    if ($otherOption)
    {   print RESULT print_tmpKey_tmpTerm_for_selected_option('Other', $otherOption);
    }
    
    
    print RESULT "</table>
            <p>&nbsp;</p>
            <hr>";
            
            
    #  Update the analysis table for numGene ($finalMergedGeneCount)
    # $dbh->do("UPDATE analysis SET numGene=0 WHERE queryID = $analID");
    # LogQuery("UPDATE query SET numGene=$finalMergedGeneCount WHERE queryID = $analID");

            
    # Result summary
    print RESULT "
            <p>&nbsp;</p>
            <p><a href=\"$SciMinerURL\"><font class=\"sectionTitleName2\">SciMiner Homepage</font></a></p>
            </body>
            </html>";
    
    close RESULT;
 
}










sub generate_result_summary_with_noresult
{   my $finalResultWebDir       = shift;
    my $resultHTMLFile          = shift;
    my $pmidListHTMLFile        = shift;
    my $currentQueueEnvRef      = shift;
    my $serverBaseURL           = shift;
    my $dbh                     = shift;
    my $queryID                 = shift;

    my $fileNameBase    = $$currentQueueEnvRef{fileNameBase};
    my $serverURL       = $serverBaseURL."SciMiner/FinalResults/$fileNameBase/";
    my $SciMinerURL      = $serverBaseURL."SciMiner/";
    my $cssURL			= $SciMinerURL.'css/sciminer-modern.css';
    
    #  Begin to write the resultHTMLFile
    open (RESULT, ">".$resultHTMLFile);
    print RESULT "  <head>
                    <title>SciMiner Result Report Page</title>
                    <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
                    <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
                	<style type=\"text/css\"> body {	margin-left:10px;	}</style>
                    </head>
                    
                    <body bgcolor=\"#EAF4F4\">
                    <p class=\"pageName\" align=\"center\"><b>SciMiner Result Report Page</b></p>
                    <hr>
                    <p class='titleBarName1'><b>SciMiner has processed your query and found no targets.<b><br>
                    If you think this is an error, please contact the system administrator.<br><br>
                    Your query and search options were</font></p>
                    <table border=\"1\" width=\"850\">
                    ";
    
    # Running condition (options)
    my %itemContent		= ();
    my $otherOption		= '';
    my $enrichmentTest	= '';
    my $ppiSelection	= '';
    foreach my $keyTerm (sort(keys %{$currentQueueEnvRef}))
    {   if ((defined $keyTerm) && ($keyTerm ne "") && (defined $$currentQueueEnvRef{$keyTerm}))
        {   if ($keyTerm eq 'queryID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Query ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'analID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Analysis ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'userName')
        	{   $itemContent{1}		=	print_tmpKey_tmpTerm_for_selected_option('User name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'email')
        	{	$itemContent{2}		=	print_tmpKey_tmpTerm_for_selected_option('Email', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Query information
        	elsif ($keyTerm eq 'queryName')
        	{   $itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Query name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'queryString')
        	{   $itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Query string', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'count')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('PMID count #', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Some analysis information
        	elsif ($keyTerm eq 'targetQueryNumber')
        	{   $itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Target Query #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'bgQueryNumber')
        	{   $itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Background Query #', $$currentQueueEnvRef{$keyTerm});
        	}
        	elsif ($keyTerm eq 'PValueThreshold')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('P-value Threshold', $$currentQueueEnvRef{$keyTerm});
        	}

        	elsif (($keyTerm eq 'GeneEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene list";
        	}elsif (($keyTerm eq 'GOEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene Ontology";
        	}elsif (($keyTerm eq 'MeSHEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"MeSH term";
        	}elsif (($keyTerm eq 'PathwayEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}$enrichmentTest		.=	"Pathway";
        	}elsif (($keyTerm eq 'PPICheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Protein-Protein Interaction";
        	}elsif ($keyTerm eq 'PPISelection') 
        	{   $ppiSelection		.=	" (PPI Selection: ".$$currentQueueEnvRef{$keyTerm}.')';
        	}
        	
			#  Check for other options
        	elsif ($keyTerm eq 'phenotypeOnlyFilter')
        	{   $otherOption		.= "Remove_phenotype_gene, ";
        	}elsif ($keyTerm eq 'useLengthOption')
        	{   $otherOption		.= "Use_symbol_length_option, ";
        	}elsif ($keyTerm eq 'wordLengthThreshold')
        	{   $otherOption		.= "Always_accept_symbol_longer_than: $$currentQueueEnvRef{$keyTerm}";
        	}
        }
    }
    
    #  Print out sorted query/analysis options
    my @sortedKey	= sort {$a <=> $b} keys %itemContent;
    foreach my $sortedTermKey (@sortedKey)
    {   if (defined $itemContent{$sortedTermKey})
    	{	print RESULT $itemContent{$sortedTermKey};
    	}
    }

	#  Process enrichment options
	if ($enrichmentTest)
    {   if (($ppiSelection) && ($$currentQueueEnvRef{"PPICheck"} =~ /on/i))
    	{	$enrichmentTest	.= $ppiSelection;
    	}
    	print RESULT print_tmpKey_tmpTerm_for_selected_option('Enrichment tests', $enrichmentTest);
    }
    
    #  Score Threshold
    if ((defined $$currentQueueEnvRef{useScoreThreshold}) && ($$currentQueueEnvRef{useScoreThreshold}))
    {   print RESULT print_tmpKey_tmpTerm_for_selected_option('Score threshold', $$currentQueueEnvRef{scoreThreshold});
    }
    
    #  Process other options
    if ($otherOption)
    {   print RESULT print_tmpKey_tmpTerm_for_selected_option('Other', $otherOption);
    }
    
    
    print RESULT "</table>
            <p>&nbsp;</p>
            <hr>";
            
            
    #  Update the query table for numGene ($finalMergedGeneCount)
    $dbh->do("UPDATE query SET numGene=0 WHERE queryID = $queryID");
    #LogQuery("UPDATE query SET numGene=$finalMergedGeneCount WHERE queryID = $queryID");

   
    # Result summary
    print RESULT "<p class='titleBarName1'><b>SciMiner has analyzed ($$currentQueueEnvRef{count}) &nbsp;articles. &nbsp;&nbsp;&nbsp;&nbsp;<a href=\"$serverURL"."pmidList.html"."\"><b>List of documents</b></a>, but found no targets.<br><br>
                  If you think this is an error, please contact the system administrator or try different corpus.</p>";

    print RESULT "
            <p>&nbsp;</p>
            <p><a href=\"$SciMinerURL\"><font class=\"sectionTitleName2\">SciMiner Homepage</font></a></p>
            </body>
            </html>";
    
    close RESULT;
 
}




















#  !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
#  This sub-routine just calls another Perl script
#  if there is any PMID file to be processed
#  !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
sub perform_SciMiner_mining_process
{   my $annoENVRef                  = shift;
    my $dicFileNameRef              = shift;
    my $pname                       = shift;
    my $pmidListRef                 = shift;
    my $pmidListToBeMinedRef        = shift;
    
    my $pmidListNotToBeMinedRef     = shift;
    my $pmid2docIDRef               = shift;
    my $dbh                         = shift;
    my $finalResultDir              = shift;
    my $finalResultWebDir           = shift;
    
    my $currentQueueEnvRef          = shift;
    my $pmid2TitleRef               = shift;
    my $pmid2AbstractRef            = shift;
    my $pmid2htmlSizeRef            = shift;
    my $queryID                     = shift;
    
	my $MeSHdescID2termRef			= shift;
	my $MeSHTerm2descIDRef			= shift;
	my $MeSHTerm2DistRef			= shift;

    my $pmid2journalRef				= shift;
    my $cssFileName					= shift;

    my $sciminerJScriptFileName		= shift;
    my $symbol2ncbiEntrezGeneIDRef	= shift;
    
    my $tmpPMIDLinkURLRef			= shift;
    
    my @pmidListToBeMined           = @{$pmidListToBeMinedRef};
    my $pmidListToBeMinedCount		= scalar @pmidListToBeMined;
    
    #  Create links to the original files
    my $docLinkDir              	= $finalResultWebDir.'Docs';
    mkdir ($docLinkDir) 			|| print "";
    my %medlineSymbolicLink     	= ();
    my %medlineEndnoteSymLink		= ();
    my %htmlSymbolicLink        	= ();
    
    my %userID2userName				= ();
    my $tmpSql						= "SELECT userID, name FROM user";
    my $tmpSth						= $dbh->prepare($tmpSql);
    my @tmpRow						= ();
    $tmpSth->execute();
    while(@tmpRow	= $tmpSth->fetchrow_array)
    {	if (defined $tmpRow[1])
    	{	$userID2userName{$tmpRow[0]}	= $tmpRow[1];
    	}
    }
    LogQuery("---------- Start mining process ----------");
    
    #  If there is no PMID to be mined again, then just fetch the results from the SciMinerDB
    if ($pmidListToBeMinedCount == 0)
    {   #  Fetch all the sentence2gene matching the given PMIDs
        open (RESULT, ">$$annoENVRef{SciMinerPath}/Work/Temp/SciMinerBase.out");
        LogQuery("- No document needs additional mining.");
		
        #  Generate PMID list string for DB Query
        my $pmidFull    = join (',', @{$pmidListRef});
		my $sql         = "SELECT * from sentence2gene where pmid in ($pmidFull)";
        my $sth         = $dbh->prepare($sql);
        my @row         = ();
        $sth->execute();
        my $outString   = '';
            
        while(@row = $sth->fetchrow_array)
        {   print RESULT join ("\t", @row)."\n";
        }
        close RESULT;
        LogQuery("- Temp/SciMinerBase.out file has been created.");
		
    }else
    {   #  Launch the mining script. Why not in this sub-routine but a independent script?
        #  During the development process, I would frequently change the ways of actual mining. 
        my $command             = "$$annoENVRef{SciMinerPath}/Scripts/Main/SciMiner_FullMedline_Mining.pl -pname=$pname";
        foreach my $tag ( keys %{$dicFileNameRef} )
        {   $command .= " -$tag=$$dicFileNameRef{$tag}";
        }
        
        #  Call the mining script
		LogQuery("Mining script has been called.");
		LogQuery($command);
		
		#  Delete existing temporary file
		unlink ("$$annoENVRef{SciMinerPath}/Work/Temp/SciMinerBase.out");
        `$command`;
		LogQuery("Mining script has completed.");
        
        #  Fetch the remaining PMIDs results in NotToBeMined list
	    my $pmidListNotToBeMinedRefCnt  = scalar @{$pmidListNotToBeMinedRef};
        if ($pmidListNotToBeMinedRefCnt > 0)
        {   #  Retrieve the not to be mined sentene2gene data
            open (RESULT, ">>$$annoENVRef{SciMinerPath}/Work/Temp/SciMinerBase.out");
            
            #  Generate PMID list string for DB Query
            my $pmidFull    = join (',', @{$pmidListNotToBeMinedRef});
            my $sql         = "SELECT * from sentence2gene where pmid in ($pmidFull)";
            my $sth         = $dbh->prepare($sql);
            my @row         = ();
            $sth->execute();
            my $outString   = '';
                
            while(@row = $sth->fetchrow_array)
            {   print RESULT join ("\t", @row)."\n";
            }
            close RESULT;
        }else
		{   # No more fetching is necessary.
		}
    }
    
    
    #  ----------------------------------------------------------------------------------
    #  Load the result into memory when the file exists and not empty
    #  ----------------------------------------------------------------------------------
    my %sen2geneIDsCheckForExclusion        = ();
    my %sen2geneID2Result                   = ();
    my %name2sen2geneID                     = ();
    my %symbol2sen2geneID                   = ();

	#  Set the total number of mined result lines (sen2geneID)
    my 	$totalSentence2GeneCnt				= 0;
    
    #  Create an temporary array for sentence splitting
	my @tmpWorkingSplit						= ();
	
	
	#  -------------------------------------------------------------------------
	#  <TODO> FUTURE IMPROVEMENT - TO BE IMPLEMENTED WHEN NECESSARY
	#  -------------------------------------------------------------------------
	#  OUTBOTH file is created on-the-fly and hash usage is required for
	#  $sen2geneID2Result. This is necessary when the memory shortage is 
	#  a big issue for a extremely large corpus
	#  -------------------------------------------------------------------------
	
	
	#  -------------------------------------------------------------------------
	#  New strategy for efficient memory handling	(03/15/2008)
	#  -------------------------------------------------------------------------
	#  If the size of the corpus increase significantly, 
	#  the file size of SciMinerBase.out is increasing rapidly
	#  which can halt the SciMiner Process due to the limited memory.
	#  -------------------------------------------------------------------------
	#  New strategy is not to assign $sen2geneID2Result{$tmpSplit[0]} fully
	#  at the time of file reading. Instead, it will only have a few elements
	#  -------------------------------------------------------------------------	
	#  	sen2geneID	:	ID of the sentence2gene table
	
	#  -------------------------------------------------------------------------
	#  Check the SciMinerBase.out file for existence and size    
    if ((-f "$$annoENVRef{SciMinerPath}/Work/Temp/SciMinerBase.out") && (-s "$$annoENVRef{SciMinerPath}/Work/Temp/SciMinerBase.out" != 0))  
    {   open (INFILE, "$$annoENVRef{SciMinerPath}/Work/Temp/SciMinerBase.out");
        while(<INFILE>)
        {   $totalSentence2GeneCnt++;
            my $line                            = $_;
            $line                               =~ s/\r|\n//g;
            @tmpWorkingSplit					= split (/\t/, $line);
            
            #  -----------------------------------------------------------------
            #  @tmpSplit is used instead of @tmpWorkingSplit 
            #  in order to save the momory space.
            my @tmpSplit						= ($tmpWorkingSplit[1], $tmpWorkingSplit[9], $tmpWorkingSplit[15], $tmpWorkingSplit[16]);
            
            #  Assign a few key elements to @tmpSplit from @tmpWorkingSplit
            #  This is to save the memory space
            #$tmpSplit[1]						= $tmpWorkingSplit[1];
            #$tmpSplit[9]						= $tmpWorkingSplit[9];
            #$tmpSplit[15]						= $tmpWorkingSplit[15];
            #$tmpSplit[16]						= $tmpWorkingSplit[16];

            #  Assign the reference of @tmpSplit to $sen2geneID2Result
            $sen2geneID2Result{$tmpWorkingSplit[0]}	= \@tmpSplit;

            if (defined $tmpWorkingSplit[14])
            {   if ($tmpWorkingSplit[14] >= 4)
                {   #  This type is name matching
                    if (not defined $name2sen2geneID{$tmpWorkingSplit[7]})
                    {   $name2sen2geneID{$tmpWorkingSplit[7]}->[0] = $tmpWorkingSplit[0];
                    }else
                    {   push @{$name2sen2geneID{$tmpWorkingSplit[7]}}, $tmpWorkingSplit[0];
                    }
                }else
                {   #  This type is symbol matching
                    if (not defined $symbol2sen2geneID{$tmpWorkingSplit[6]})
                    {   $symbol2sen2geneID{$tmpWorkingSplit[6]}->[0] = $tmpWorkingSplit[0];
                    }else
                    {   push @{$symbol2sen2geneID{$tmpWorkingSplit[6]}}, $tmpWorkingSplit[0];
                    }
                }
            }else
            {   #  There is no method code, which is impossible.
                LogQuery("There is no method code, which is impossible. $line");
            }
        }
        close (INFILE);
    }elsif (-s "$$annoENVRef{SciMinerPath}/Work/Temp/SciMinerBase.out" == 0)
    {   #  Either the file doesn't exist or is an empty file. 
        #  No need to proceed any more.
        # TODO: give specific return value later.
        my $pmidListHTMLFile		= "$finalResultDir/pmidList.html";
        my %pmid2passedContent		= ();
        my %pmid2passGeneCount		= ();

        #  Copy the configuration and list files to the fileResultDir        
        `cp -f $$annoENVRef{SciMinerPath}/Work/$$currentQueueEnvRef{fileNameBase}.* $finalResultDir`;
        `cp -f $$annoENVRef{SciMinerPath}/Work/$$currentQueueEnvRef{fileNameBase}.* $finalResultWebDir`;
        
        #  Assign 0 to all pmid2passGeneCount    
        my @localPMIDs = @{$pmidListRef};
        foreach my $pmid (@localPMIDs)
        {   my %tmpHash = ();
            $pmid2passGeneCount{$pmid} = \%tmpHash;
        }
        
        #  Generate pmidList file
        my $numPassGeneCountByPMIDRef   = generate_base_pmid_list_html ($finalResultDir, $finalResultWebDir, $pmidListHTMLFile, 
        									\%pmid2passGeneCount, $$currentQueueEnvRef{fileNameBase}, $$annoENVRef{SciMinerServerURL}, 
        									$pmid2TitleRef, $docLinkDir, \%medlineSymbolicLink, \%medlineEndnoteSymLink, \%htmlSymbolicLink, 
        									$pmid2htmlSizeRef, $$annoENVRef{SciMinerPath}."CorpusData/Original/", $pmid2journalRef, $cssFileName, 
        									$$currentQueueEnvRef{InstitutionCheck}, $tmpPMIDLinkURLRef, $pmid2AbstractRef);
        `cp -f $pmidListHTMLFile $finalResultWebDir`;  

        #  Generate resultHTMLfile
        generate_result_summary_with_noresult(	$finalResultWebDir, "$finalResultWebDir/result.html", $pmidListHTMLFile, 
        									 	$currentQueueEnvRef, $$annoENVRef{SciMinerServerURL}, $dbh, $queryID );
        return();
    }else
    {   #  Either the file doesn't exist or is an empty file. 
        #  Generate a result page only with some message

        return();
    }
    
    

    
    
    
    
    
    #  ----------------------------------------------------------------------------------
    #  Step 1. Check user-specific ignore list
    #  ----------------------------------------------------------------------------------
    my @userSpecificIgnoreList      = ();
    LogQuery("! Checking user-specific ignore list, if any");
    if ((defined $$currentQueueEnvRef{"ignoreName"}) && ($$currentQueueEnvRef{"ignoreName"} ne ""))
    {   my $ignoreFilePathName = "$$annoENVRef{SciMinerPath}/Work/".$$currentQueueEnvRef{"ignoreName"};
        if ((defined $$currentQueueEnvRef{"ignoreName"}) && ($$currentQueueEnvRef{"ignoreName"} ne "") && (-f $ignoreFilePathName) && (-s $ignoreFilePathName > 0))
        {   open (IGNORE, $ignoreFilePathName);
            while(<IGNORE>)
            {   my $line = $_;
                $line =~ s/\r|\n//g;
                if ( $line =~ /\w/)
                {   push @userSpecificIgnoreList, $line;
                }
            }
            close IGNORE;
        }

        if (defined $userSpecificIgnoreList[0])
        {   for (my $i=0; $i <= $#userSpecificIgnoreList; $i++)
            {   if (defined $name2sen2geneID{$userSpecificIgnoreList[$i]})
                {   #  There are some mined results to be ignored by user-specific ignore list
                    foreach my $sen2geneIDToIgnore (@{$name2sen2geneID{$userSpecificIgnoreList[$i]}})
                    {   #  Set inExCode = 3 to exclude
                        $sen2geneID2Result{$sen2geneIDToIgnore}->[2] = 3;
                        $sen2geneID2Result{$sen2geneIDToIgnore}->[3] = "User-Specific-Ignore";
                    }
                }else
                {   # LogQuery("no mined result $userSpecificIgnoreList[$i]");
                }
            }
        }else
        {   # LogQuery("no defined a ignore list");
        }
    }else
    {   # LogQuery("ignore list not defined list");
    }
    
    
    
    
    
    #  ----------------------------------------------------------------------------------
    #  Step 2. Check user-specific inclusion list
    #  ----------------------------------------------------------------------------------    
    my %wholeTextContentHash    = ();

    #  For following hashes are only for user-specific inclusion/exclusion list
    my %exclusionStatus         = ();
    my %exclusionCond           = ();                       # only the first exclusion is enough if any
    my %inclusionStatus         = ();
    my %inclusionCond           = ();        
    my (@userSpecificInclusionSymbol, %INCLUDESYMBOLMODE, %INCLUDESYMBOLCOND, @pmidToBeAdditionallyTestedForInclusion);
    
    if ((defined $$currentQueueEnvRef{"includeSymbol"}) && ($$currentQueueEnvRef{"includeSymbol"} ne ""))
    {   my $includeFilePathName = "$$annoENVRef{SciMinerPath}/Work/".$$currentQueueEnvRef{"includeSymbol"};
        if ((-f $includeFilePathName) && (-s $includeFilePathName > 0))
        {   open (INCLUDE, $includeFilePathName);
            while(<INCLUDE>)
            {   my $line = $_;
                $line =~ s/\r|\n//g;
                my @tmpSplit = split (/\t/, $line);
                if ((defined $tmpSplit[0]) && ($tmpSplit[0] ne ""))
                {   if ((defined $tmpSplit[1]) && ($tmpSplit[1] ne ""))
                    {   $INCLUDESYMBOLMODE{$tmpSplit[0]} = 1;
                        shift(@tmpSplit);
                        $INCLUDESYMBOLCOND{$tmpSplit[0]} = \@tmpSplit;
                    }else
                    {   $INCLUDESYMBOLMODE{$tmpSplit[0]} = 0;
                    }
                }
            }
            close INCLUDE;
            @userSpecificInclusionSymbol = keys %INCLUDESYMBOLMODE;
        }else
        {   # write_to_tmp_file("file not exist for inclusion");
        }
        
        #LogQuery("Now performing additional exclusion test");
        if (defined $userSpecificInclusionSymbol[0])
        {   for (my $i=0; $i <= $#userSpecificInclusionSymbol; $i++)
            {   if (defined $symbol2sen2geneID{$userSpecificInclusionSymbol[$i]})
                {   my @pmidsToBeChecked = ();
                    #  if the mode is 0, then just include, no need to further download the sentences
                    if ($INCLUDESYMBOLMODE{$userSpecificInclusionSymbol[$i]} == 0)
                    {   foreach my $sen2geneIDToInclude(@{$symbol2sen2geneID{$userSpecificInclusionSymbol[$i]}})
                        {   #  Set inExCode = 1 to include
                            $sen2geneID2Result{$sen2geneIDToInclude}->[2] = 1;
                            $sen2geneID2Result{$sen2geneIDToInclude}->[3] = "User-Specific-Inclusion: $userSpecificInclusionSymbol[$i]";
                        }
                    }else
                    {   #  If not zero, then it's conditional inclusion. This document should be tested again.
                        #  Fetch the preSciMiner document, 
                        foreach my $sen2geneIDToInclude (@{$symbol2sen2geneID{$userSpecificInclusionSymbol[$i]}})
                        {   #  Mark these pmid sentences to be fetched and processed
                            #  Only when    1) score == 0 
                            #               2) score > 0 && marked for exclusion
                            if ( (($sen2geneID2Result{$sen2geneIDToInclude}->[1] == 0) && ($sen2geneID2Result{$sen2geneIDToInclude}->[2] == 0)) || 
                                 (($sen2geneID2Result{$sen2geneIDToInclude}->[1] > 0) && ($sen2geneID2Result{$sen2geneIDToInclude}->[2] == 2)) ) 
                            {   generate_missing_preSciMiner_document_additional ($dbh, $sen2geneID2Result{$sen2geneIDToInclude}->[0], \%wholeTextContentHash);
                                if (defined $inclusionStatus{$sen2geneID2Result{$sen2geneIDToInclude}->[0]}->{$userSpecificInclusionSymbol[$i]})
                                {   #  Use predefined status
                                }else
                                {   #  Calcuate the status
                                    ($inclusionStatus{$sen2geneID2Result{$sen2geneIDToInclude}->[0]}->{$userSpecificInclusionSymbol[$i]},
                                     $inclusionCond{$sen2geneID2Result{$sen2geneIDToInclude}->[0]}->{$userSpecificInclusionSymbol[$i]}) = 
                                           SciMiner_check_inclusion_list_additional (\%wholeTextContentHash, $sen2geneID2Result{$sen2geneIDToInclude}->[0] , $INCLUDESYMBOLCOND{$userSpecificInclusionSymbol[$i]});
                                }
                                
                                #  Now update the result if it was in the inclusion condition
                                if ($inclusionStatus{$sen2geneID2Result{$sen2geneIDToInclude}->[0]}->{$userSpecificInclusionSymbol[$i]} == 1)
                                {   $sen2geneID2Result{$sen2geneIDToInclude}->[2] = 1;
                                    $sen2geneID2Result{$sen2geneIDToInclude}->[3] = "User-Specific-Inclusion: ".$inclusionCond{$sen2geneID2Result{$sen2geneIDToInclude}->[0]}->{$userSpecificInclusionSymbol[$i]};
                                }
                            }
                        }
                    }
                }else
                {   #  If not defined here, there is nothing to do
                }
            }   # End of for (my $i=0
        }else
        {   #  There is no additional inclusion step required
        }
    }else
    {   # LogQuery(" no inclusion file");
    }
    
    
 
    #  ----------------------------------------------------------------------------------
    #  Step 3. Check user-specific EXCLUSION list
    #  ---------------------------------------------------------------------------------- 
    my (@userSpecificExclusionSymbol, %EXCLUDESYMBOLMODE, %EXCLUDESYMBOLCOND, @pmidToBeAdditionallyTestedForExclusion);
    if ((defined $$currentQueueEnvRef{"excludeSymbol"}) && ($$currentQueueEnvRef{"excludeSymbol"} ne ""))
    {   my $excludeFilePathName = "$$annoENVRef{SciMinerPath}/Work/".$$currentQueueEnvRef{"excludeSymbol"};
        if ((-f $excludeFilePathName) && (-s $excludeFilePathName > 0))
        {   open (EXCLUDE, $excludeFilePathName);
            while(<EXCLUDE>)
            {   my $line = $_;
                $line =~ s/\r|\n//g;
                my @tmpSplit = split (/\t/, $line);
                if ((not defined $tmpSplit[0]) || ($tmpSplit[0] eq ""))
                {   next;
                }
                
                my $tmpSymbolKey = $tmpSplit[0];
                if ((defined $tmpSplit[1]) && ($tmpSplit[1] ne ""))
                {   $EXCLUDESYMBOLMODE{$tmpSymbolKey} = 1;
                    shift(@tmpSplit);
                    $EXCLUDESYMBOLCOND{$tmpSymbolKey} = \@tmpSplit;

                }else
                {   #  If the condition is not specified.... What should we do?
                    #  Let's use the symbol as condition as well ==> remove every case of this symbol. un-conditional
                    push @tmpSplit, $tmpSymbolKey;
                    shift @tmpSplit;
                    $EXCLUDESYMBOLCOND{$tmpSymbolKey} = \@tmpSplit;
                }
            }
            close EXCLUDE;
            @userSpecificExclusionSymbol = keys %EXCLUDESYMBOLMODE;
        }
        
        LogQuery("! Checking user-specific exclusion list");
        if (defined $userSpecificExclusionSymbol[0])
        {   for (my $i=0; $i <= $#userSpecificExclusionSymbol; $i++)
            {   if (defined $symbol2sen2geneID{$userSpecificExclusionSymbol[$i]})
                {   my @pmidsToBeChecked = ();
                    
                    #  Check every sentence2gene in the user-specific exclusion list.
                    foreach my $sen2geneIDToExclude (@{$symbol2sen2geneID{$userSpecificExclusionSymbol[$i]}})
                    {   #  Select sentence2gene only with the following conditions
                        #   1) score = 0 && inexcode = 1
                        #   2) score > 0 && inexcode = 0, 1 (< 2)
                        if ( ( ($sen2geneID2Result{$sen2geneIDToExclude}->[1] == 0) && ($sen2geneID2Result{$sen2geneIDToExclude}->[2] == 1)) || 
                             ( ($sen2geneID2Result{$sen2geneIDToExclude}->[1] > 0)  && ($sen2geneID2Result{$sen2geneIDToExclude}->[2] < 2)) ) 
                        {   generate_missing_preSciMiner_document_additional ($dbh, $sen2geneID2Result{$sen2geneIDToExclude}->[0], \%wholeTextContentHash);
                            if (defined $exclusionStatus{$sen2geneID2Result{$sen2geneIDToExclude}->[0]}->{$userSpecificExclusionSymbol[$i]})
                            {   #  Use predefined status
                                # LogQuery("This was already in the exclusion status...\n");
                            }else
                            {   #  Calcuate the status
                                ($exclusionStatus{$sen2geneID2Result{$sen2geneIDToExclude}->[0]}->{$userSpecificExclusionSymbol[$i]},
                                    $exclusionCond{$sen2geneID2Result{$sen2geneIDToExclude}->[0]}->{$userSpecificExclusionSymbol[$i]}) = 
                                        SciMiner_check_exclusion_list_additional (\%wholeTextContentHash, $sen2geneID2Result{$sen2geneIDToExclude}->[0] , $EXCLUDESYMBOLCOND{$userSpecificExclusionSymbol[$i]});
                            }
                            
                            #  Now update the result if it was in the exclusion condition
                            if ($exclusionStatus{$sen2geneID2Result{$sen2geneIDToExclude}->[0]}->{$userSpecificExclusionSymbol[$i]} == 2)
                            {   $sen2geneID2Result{$sen2geneIDToExclude}->[2] = 2;
                                $sen2geneID2Result{$sen2geneIDToExclude}->[3] = "User-Specific-Exclusion: ".$exclusionCond{$sen2geneID2Result{$sen2geneIDToExclude}->[0]}->{$userSpecificExclusionSymbol[$i]};
                            }
                        }
                        # LogQuery("end Checking exclusion $sen2geneIDToExclude");
                    }
                }else
                {   #  If not defined here, there is no such sentence2gene to check again
                }
            }   # End of for (my $i=0
        }else
        {   #  There is no additional inclusion step required
        }    
    }else
    {   # LogQuery("no exclusion performed");
    }
    
    
    
    #  ----------------------------------------------------------------------------------
    #  Step 4. Check user-specific re-assignment list  (To_Be_IMPLEMENTED)
    #  ---------------------------------------------------------------------------------- 
    #  TODO: This function is todo in the next version. 
    #  my (@userSpecificReAssignmentSymbols, %EXCLUDESYMBOLMODE, %EXCLUDESYMBOLCOND, @pmidToBeAdditionallyTestedForExclusion);
    

  
    #  ----------------------------------------------------------------------------------
    #  Step 5. Create Result Files
    #  ---------------------------------------------------------------------------------- 
	#  Due to the recent changes in the $sen2geneID2Result
	#  The original SciMinerBase.out file should be read again and 
	#  $sen2geneID2Result content should be used to update them. 
	#  -------------------------------------------------------------------------
	
	#  -------------------------------------------------------------------------
	#  <TODO> FUTURE IMPROVEMENT - TO BE IMPLEMENTED WHEN NECESSARY
	#  -------------------------------------------------------------------------
	#  The current file saving strategy (OUTBOTH, OUTSYMBOL, and OUTNAME) at the 
	#  same time is expected to significantly degrade the I/O performance.
	#  -------------------------------------------------------------------------

	#  Open out file handles
    my $newSciMinerBaseOutFileBoth 	= "$finalResultWebDir/SciMinerBase.Both";
    my $newSciMinerBaseOutFileSymbol = "$finalResultWebDir/SciMinerBase.Symbol";
    my $newSciMinerBaseOutFileName 	= "$finalResultWebDir/SciMinerBase.Name";

	open (OUTBOTH, 		">".$newSciMinerBaseOutFileBoth.'.txt');
    open (OUTSYMBOL, 	">".$newSciMinerBaseOutFileSymbol.'.txt');
    open (OUTNAME, 		">".$newSciMinerBaseOutFileName.'.txt');
    
    #  Print header
    print OUTBOTH 	"#sen2geneID\tpmid\tsenID\tgeneID\thgncID\tapprovedSymbol\tmatchString\tactualString\tstartPos\tscore\tflankingText\t".
    				"matchCodeID\ttag\tSciMinerVersion\tSciMinerMethod\tinExClude\tinExCludeCond\tphenotypeOnly\tconflictCode\t".
    				"hgncIDbyNR\tNRText\teditTag\teditUser\toldGeneID\toldHgncID\toldApprovedSymbol\toldInExClude\toldInExCludeCond\n";
    print OUTSYMBOL 	"#sen2geneID\tpmid\tsenID\tgeneID\thgncID\tapprovedSymbol\tmatchString\tactualString\tstartPos\tscore\tflankingText\t".
    				"matchCodeID\ttag\tSciMinerVersion\tSciMinerMethod\tinExClude\tinExCludeCond\tphenotypeOnly\tconflictCode\t".
    				"hgncIDbyNR\tNRText\teditTag\teditUser\toldGeneID\toldHgncID\toldApprovedSymbol\toldInExClude\toldInExCludeCond\n";
    print OUTNAME 	"#sen2geneID\tpmid\tsenID\tgeneID\thgncID\tapprovedSymbol\tmatchString\tactualString\tstartPos\tscore\tflankingText\t".
    				"matchCodeID\ttag\tSciMinerVersion\tSciMinerMethod\tinExClude\tinExCludeCond\tphenotypeOnly\tconflictCode\t".
    				"hgncIDbyNR\tNRText\teditTag\teditUser\toldGeneID\toldHgncID\toldApprovedSymbol\toldInExClude\toldInExCludeCond\n";
    
	#  Declare temporary output string variable to be re-used
	my $resultOutputString		= '';
	
	#  Open the SciMinerBase.out again and check with $sen2geneID2Result content
	open (INFILE, "$$annoENVRef{SciMinerPath}/Work/Temp/SciMinerBase.out");
    while(<INFILE>)
    {   my $line				= $_;
        $line					=~ s/\r|\n//g;
        @tmpWorkingSplit		= split (/\t/, $line);
        
        #  Update them with the current $sen2geneID2Result content
        $tmpWorkingSplit[15]	= $sen2geneID2Result{$tmpWorkingSplit[0]}->[2];
        $tmpWorkingSplit[16]	= $sen2geneID2Result{$tmpWorkingSplit[0]}->[3];
        
        #  Generate output string 
        $resultOutputString		= join("\t",@tmpWorkingSplit)."\n";

		#  Save results to OUTBOTH file
      	print OUTBOTH $resultOutputString;        	
        
        #  Print content into outfiles by method code
        if ($tmpWorkingSplit[14] == 2)
        {	#  This is by name matching
        	print OUTNAME $resultOutputString;
        }else
        {	#  This is by symbol matching
        	print OUTSYMBOL $resultOutputString;        	
        }
    }
    close (INFILE);
    close (OUTBOTH);
    close (OUTSYMBOL);
    close (OUTNAME);
    
    #  -------------------------------------------------------------------------
    #  Step 6. Summarization and merge the results
    #  -------------------------------------------------------------------------
    #  This is important field
    my %HUGO2ApprovedGeneName           = ();

    #  After the summarization process, we now have the pmid2passGeneCount hash
	my %pmid2passGeneCount      		= ();
    
    if (-s "$newSciMinerBaseOutFileSymbol.txt" > 0)
    {   SciMiner_Summarize_Symbol_Result (\%HUGO2ApprovedGeneName, $finalResultWebDir, $newSciMinerBaseOutFileSymbol, $dbh, \%pmid2passGeneCount, $currentQueueEnvRef );
    }

    if (-s "$newSciMinerBaseOutFileName.txt" > 0)
    {   SciMiner_Summarize_Name_Result (\%HUGO2ApprovedGeneName, $finalResultWebDir, $newSciMinerBaseOutFileName, $$currentQueueEnvRef{"phenotypeOnlyFilter"}, 
    									$dbh, \%pmid2passGeneCount, $$currentQueueEnvRef{scoreThreshold} );
    }
	
	#  -------------------------------------------------------------------------
    #  Merge the two result files
    my $mergedSummaryFileName   = "$finalResultWebDir/SciMinerBase.MerSum";
    my $top10genesArrRef        = '';
    if (-s "$newSciMinerBaseOutFileBoth.txt" > 0 )
    {   $top10genesArrRef = SciMiner_Symbol_Name_Summary_Merge ($newSciMinerBaseOutFileSymbol.'.Summary.txt', $newSciMinerBaseOutFileName.'.Summary.txt', $mergedSummaryFileName);
    
        # Move the configuration files
        # First copy the list and conf files
        `cp -f $$annoENVRef{SciMinerPath}/Work/$$currentQueueEnvRef{fileNameBase}.* $finalResultDir`;
        `cp -f $$annoENVRef{SciMinerPath}/Work/$$currentQueueEnvRef{fileNameBase}.* $finalResultWebDir`;

		#  Create symbolic links        
        #`ln -s $newSciMinerBaseOutFileBoth $finalResultWebDir/SciMinerBase.Both.txt`;
        #`ln -s $newSciMinerBaseOutFileName $finalResultWebDir/SciMinerBase.Name.txt`;
        #`ln -s $newSciMinerBaseOutFileSymbol $finalResultWebDir/SciMinerBase.Symbol.txt`;
        
        #`ln -s $finalResultWebDir/SciMinerBase.MerSum $finalResultWebDir/SciMinerBase.MerSum.txt`;
        #`ln -s $finalResultWebDir/SciMinerBase.MerSum.sorted $finalResultWebDir/SciMinerBase.MerSum.sorted.txt`;
        `ln -s $finalResultWebDir/SciMinerBase.MerSum.sorted.txt $finalResultWebDir/SciMinerBase.MerSum.sorted.xls`;
        
        #`ln -s $finalResultWebDir/SciMinerBase.Name.Optout $finalResultWebDir/SciMinerBase.Name.Optout.txt`;
        #`ln -s $finalResultWebDir/SciMinerBase.Name.Remain $finalResultWebDir/SciMinerBase.Name.Remain.txt`;
        #`ln -s $finalResultWebDir/SciMinerBase.Name.Summary $finalResultWebDir/SciMinerBase.Name.Summary.txt`;
        
        
        #`ln -s $finalResultWebDir/SciMinerBase.Symbol.Optout $finalResultWebDir/SciMinerBase.Symbol.Optout.txt`;
        #`ln -s $finalResultWebDir/SciMinerBase.Symbol.Remain $finalResultWebDir/SciMinerBase.Symbol.Remain.txt`;
        #`ln -s $finalResultWebDir/SciMinerBase.Symbol.Summary $finalResultWebDir/SciMinerBase.Symbol.Summary.txt`;

        `cp $finalResultWebDir/SciMinerBase.Symbol.Remain.txt $finalResultWebDir/SciMinerBase.Both.Remain.txt`;
        `cat $finalResultWebDir/SciMinerBase.Name.Remain.txt >> $finalResultWebDir/SciMinerBase.Both.Remain.txt`;

        `cp $finalResultWebDir/SciMinerBase.Symbol.Optout.txt $finalResultWebDir/SciMinerBase.Both.Optout.txt`;
        `cat $finalResultWebDir/SciMinerBase.Name.Optout.txt >> $finalResultWebDir/SciMinerBase.Both.Optout.txt`;

        #`ln -s $finalResultWebDir/SciMinerBase.Both.Remain $finalResultWebDir/SciMinerBase.Both.Remain.txt`;	
    }





    #  ----------------------------------------------------------------------------------
    #  Step 7. Create remaining (passed filter) files
    #  ----------------------------------------------------------------------------------     
    #  Create hash for pmids and actual matches
    my %hgncID2passedContent	= ();
    my %hgncID2passedCount		= ();
    my %pmid2passedContent		= ();
    my %pmid2passedCount		= ();
    my $maxRecordPerItem		= 3;
    
    #  Check the total number of $totalSentence2GeneCnt
    #  Roughly speaking, 1 million of such records will require approximately 1GB of ram
    #  In such case of total records being more than 1 million, 
    #  only 5 records per actualstring per pmid / per hugoID will be retained
    #  in generating HTML result files
    
    if ($totalSentence2GeneCnt > 1000000)
    {	#  Use only five records per actualString per pmid
    	if (-f "$finalResultWebDir/SciMinerBase.Both.Remain.txt")
		{   open (FILE, "$finalResultWebDir/SciMinerBase.Both.Remain.txt");
		    while(<FILE>)
		    {   my $tmpLine = $_;
		        $tmpLine    =~ s/\r|\n//g;
		        my @tmpSplit = split (/\t/, $tmpLine);
		        #   [0]     ==> sen2geneID
		        #   [1]     ==> pmid
		        #   [2]     ==> senID
		        #   [3]     ==> geneID
		        #   [4]     ==> hgncID
		        #   [5]     ==> approvedSymbol
		        #   [6]     ==> matchString
		        #   [7]     ==> actualString
		        #   [8]     ==> startPos
		        #   [9]     ==> score
		        #   [10]    ==> flankingText
		        #   [11]    ==> matchCode
		        #   [12]    ==> tag            
		        #   [13]    ==> SciMinerVersion            
		        #   [14]    ==> SciMinerMethod            
		        #   [15]    ==> inExClude            
		        #   [16]    ==> InExCondition
		        #   [17]    ==> phenotypeOnly
		        #   [18]    ==> ConflictResolvingCode
		        #   [19]    ==> ConflictResolvingResult
		        
		        
		        #  -------------------------------------------------------------
		        #  Check the current count of this hgncID for pmid and actualSymbol
		        #  Use matchString not actualString
		        #  -------------------------------------------------------------
				#  $hgncID2passedCount	/ $hgncID2passedContent
		        #  -------------------------------------------------------------

		        # <TODO> In order to get back to InExCondition, change 19 -> 16
		        #my @tmpOccurrence = ($tmpSplit[1], $tmpSplit[6], $tmpSplit[7], $tmpSplit[9], $tmpSplit[10], $tmpSplit[15], $tmpSplit[19]);
				my @tmpOccurrence = ($tmpSplit[1], $tmpSplit[6], $tmpSplit[7], $tmpSplit[9], $tmpSplit[10], $tmpSplit[0], $tmpSplit[22]); #$tmpSplit[15], $tmpSplit[19]);
				
		        if (not defined $hgncID2passedCount{$tmpSplit[4]})
		        {   $hgncID2passedCount{$tmpSplit[4]}->{$tmpSplit[6]}		= 1;
		        	$hgncID2passedContent{$tmpSplit[4]}->[0] = \@tmpOccurrence;
		        }else
		        {   if (not defined $hgncID2passedCount{$tmpSplit[4]}->{$tmpSplit[6]})
		        	{   $hgncID2passedCount{$tmpSplit[4]}->{$tmpSplit[6]}	= 1;
		        		push @{$hgncID2passedContent{$tmpSplit[4]}}, \@tmpOccurrence;
		        	}else
		        	{	#  Check the current count
		        		if ($hgncID2passedCount{$tmpSplit[4]}->{$tmpSplit[6]} == $maxRecordPerItem)
		        		{	#  Simply skip this record
		        		}else
		        		{	$hgncID2passedCount{$tmpSplit[4]}->{$tmpSplit[6]}++;
		        			push @{$hgncID2passedContent{$tmpSplit[4]}}, \@tmpOccurrence;
		        		}
		        	}
		        }
		        
		        #  -------------------------------------------------------------
				#  $pmid2passedCount	/ $pmid2passedContent
		        #  -------------------------------------------------------------				
		        #my @tmpByPMID   = ($tmpSplit[4], $tmpSplit[5], $HUGO2ApprovedGeneName{$tmpSplit[4]}, $tmpSplit[7], $tmpSplit[9], $tmpSplit[10], $tmpSplit[15], $tmpSplit[19]);
		        my @tmpByPMID   = ($tmpSplit[4], $tmpSplit[5], $HUGO2ApprovedGeneName{$tmpSplit[4]}, $tmpSplit[7], $tmpSplit[9], $tmpSplit[10], $tmpSplit[0]); #$tmpSplit[15], $tmpSplit[19]);
		        
				if (not defined $pmid2passedCount{$tmpSplit[1]})
		        {   $pmid2passedCount{$tmpSplit[1]}->{$tmpSplit[6]}		= 1;
		        	$pmid2passedContent{$tmpSplit[1]}->[0] = \@tmpByPMID;
		        }else
		        {   if (not defined $pmid2passedCount{$tmpSplit[1]}->{$tmpSplit[6]})
		        	{   $pmid2passedCount{$tmpSplit[1]}->{$tmpSplit[6]}	= 1;
		        		push @{$pmid2passedContent{$tmpSplit[1]}}, \@tmpByPMID;
		        	}else
		        	{	#  Check the current count
		        		if ($pmid2passedCount{$tmpSplit[1]}->{$tmpSplit[6]} == $maxRecordPerItem)
		        		{	#  Simply skip this record
		        		}else
		        		{	$pmid2passedCount{$tmpSplit[1]}->{$tmpSplit[6]}++;
		        			push @{$pmid2passedContent{$tmpSplit[1]}}, \@tmpByPMID;
		        		}
		        	}
		        }
		    }
		    close FILE;
    	}
    }else
    {	#  Use all the data in the SciMinerBase.Both.Remain
    	#  This amount of data can be handled by regular system. (Ram =1.5GB)
    	if (-f "$finalResultWebDir/SciMinerBase.Both.Remain.txt")
		{   open (FILE, "$finalResultWebDir/SciMinerBase.Both.Remain.txt");
		    while(<FILE>)
		    {   my $tmpLine = $_;
		        $tmpLine    =~ s/\r|\n//g;
		        my @tmpSplit = split (/\t/, $tmpLine);
		        #   [0]     ==> sen2geneID
		        #   [1]     ==> pmid
		        #   [2]     ==> senID
		        #   [3]     ==> geneID
		        #   [4]     ==> hgncID
		        #   [5]     ==> approvedSymbol
		        #   [6]     ==> matchString
		        #   [7]     ==> actualString
		        #   [8]     ==> startPos
		        #   [9]     ==> score
		        #   [10]    ==> flankingText
		        #   [11]    ==> matchCode
		        #   [12]    ==> tag            
		        #   [13]    ==> SciMinerVersion            
		        #   [14]    ==> SciMinerMethod            
		        #   [15]    ==> inExClude            
		        #   [16]    ==> InExCondition
		        #   [17]    ==> phenotypeOnly
		        #   [18]    ==> ConflictResolvingCode
		        #   [19]    ==> ConflictResolvingResult
		        
		        # TTTTTTTTTTTTTTTTTTTTTTTTTTTTTT  19-->16
		        # In order to get back to InExCondition, change 19 -> 16
		        #my @tmpOccurrence = ($tmpSplit[1], $tmpSplit[6], $tmpSplit[7], $tmpSplit[9], $tmpSplit[10], $tmpSplit[15], $tmpSplit[19]);
		        my @tmpOccurrence = ($tmpSplit[1], $tmpSplit[6], $tmpSplit[7], $tmpSplit[9], $tmpSplit[10], $tmpSplit[0], $tmpSplit[22]);
		        
		        if (not defined $hgncID2passedContent{$tmpSplit[4]})
		        {   $hgncID2passedContent{$tmpSplit[4]}->[0] = \@tmpOccurrence;
		        }else
		        {   push @{$hgncID2passedContent{$tmpSplit[4]}}, \@tmpOccurrence;
		        }
		        
		        #my @tmpByPMID   = ($tmpSplit[4], $tmpSplit[5], $HUGO2ApprovedGeneName{$tmpSplit[4]}, $tmpSplit[7], $tmpSplit[9], $tmpSplit[10], $tmpSplit[15], $tmpSplit[19]);
		        my @tmpByPMID   = ($tmpSplit[4], $tmpSplit[5], $HUGO2ApprovedGeneName{$tmpSplit[4]}, $tmpSplit[7], $tmpSplit[9], $tmpSplit[10], $tmpSplit[0]); #$tmpSplit[15], $tmpSplit[19]);
		        
		        if (not defined $pmid2passedContent{$tmpSplit[1]})
		        {   $pmid2passedContent{$tmpSplit[1]}->[0] = \@tmpByPMID;
		        }else
		        {   push @{$pmid2passedContent{$tmpSplit[1]}}, \@tmpByPMID;
		        }
		    }
		    close FILE;
		}
    }
    





    #  ----------------------------------------------------------------------------------
    #  Step 7-2. MeSH statistics handling
    #  ----------------------------------------------------------------------------------     
    LogQuery("! Generating MeSH distribution from corpus");
#    generate_mesh_distribution_from_corpus ($mtreeID2descIDRef, $mtreeID2treeCodeRef, $treeCode2mtreeIDRef, $treeCode2descIDRef, $MeSHdescID2termRef, $descID2treeCodesRef, $MeSHTerm2descIDRef, $MeSHCode2DistRef, $dbh, $pmidListRef, $$annoENVRef{"WholePMID"}, $finalResultDir, $finalResultWebDir); 
    generate_mesh_distribution_from_corpus (
    	$MeSHdescID2termRef, $MeSHTerm2descIDRef, $MeSHTerm2DistRef,
    	$dbh, $pmidListRef, $$annoENVRef{"WholePMID"}, $finalResultDir, $finalResultWebDir); 


    #  -------------------------------------------------------------------------
    #  Step 8-1. Generate the base PMID list html
    #  -------------------------------------------------------------------------
    LogQuery("! Generating base PMID list -- pmidlist.html");
    my $pmidListHTMLFile            = "$finalResultWebDir/pmidList.html";
    my $numPassGeneCountByPMIDRef   = generate_base_pmid_list_html ($finalResultDir, $finalResultWebDir, $pmidListHTMLFile, \%pmid2passGeneCount, $$currentQueueEnvRef{fileNameBase}, $$annoENVRef{SciMinerServerURL}, $pmid2TitleRef, $docLinkDir, \%medlineSymbolicLink, \%medlineEndnoteSymLink, \%htmlSymbolicLink, $pmid2htmlSizeRef, $$annoENVRef{SciMinerPath}."CorpusData/Original/", $pmid2journalRef, $cssFileName, $$currentQueueEnvRef{InstitutionCheck}, $tmpPMIDLinkURLRef, $pmid2AbstractRef);
    # `cp -f $pmidListHTMLFile $finalResultWebDir`;  
    


    #  -------------------------------------------------------------------------
    #  Step 8-2. Generate the gene summary html
    #  -------------------------------------------------------------------------
    LogQuery("! Generating the summary html -- geneSummary.html");
    my $resultSummaryHTML   = "$finalResultWebDir/geneSummary.html";
    generate_summary_html(
    	$finalResultDir, $finalResultWebDir, "$finalResultWebDir/SciMinerBase.MerSum.sorted.txt", $resultSummaryHTML, 
		$currentQueueEnvRef, $totalSentence2GeneCnt, $top10genesArrRef, $$currentQueueEnvRef{fileNameBase}, 
		$$annoENVRef{SciMinerServerURL}, \%hgncID2passedContent, \%pmid2passedContent, $pmid2TitleRef, 
		$pmid2AbstractRef, \%medlineSymbolicLink, \%medlineEndnoteSymLink, \%htmlSymbolicLink, 
		$pmid2htmlSizeRef, $numPassGeneCountByPMIDRef, $pmid2journalRef, $maxRecordPerItem, $cssFileName, $sciminerJScriptFileName,
        $symbol2ncbiEntrezGeneIDRef, $tmpPMIDLinkURLRef, \%userID2userName);
    # `cp -f $resultSummaryHTML $finalResultWebDir`;    
                                        
    

    #  ----------------------------------------------------------------------------------
    #  Step 9. Generate result email and simple html for display.
    #  ----------------------------------------------------------------------------------     
    my $resultHTMLFile      = "$finalResultWebDir/result.html";
	my $tmpResultHTMLFile	= "$finalResultWebDir/result.tmp";
    LogQuery("! Generating the primary result file -- result.html");
    SciMiner_Generate_Final_Result_File ($finalResultDir, $finalResultWebDir, $tmpResultHTMLFile, "geneSummary.html", "pmidList.html", 
    									$currentQueueEnvRef, $top10genesArrRef, $$currentQueueEnvRef{fileNameBase}, $$annoENVRef{SciMinerServerURL}, 
    									$dbh, $queryID, $$annoENVRef{WholePMID}, $cssFileName, $sciminerJScriptFileName, $symbol2ncbiEntrezGeneIDRef,
    									$tmpPMIDLinkURLRef);
	`mv -f $tmpResultHTMLFile $resultHTMLFile`;
    
    #  Generate $queryAnalInfo string
    my $queryAnalInfo	= 	"--Mining Query Info--\n".
							"Query ID     : $$currentQueueEnvRef{queryID}\n".
    						"Query name   : $$currentQueueEnvRef{queryName}\n".
    						"# of PMIDs   : $$currentQueueEnvRef{count}\n";
    if (defined $$currentQueueEnvRef{queryString})
    {   $queryAnalInfo .=   "Query string : $$currentQueueEnvRef{queryString}\n\n";
    }
    

    #  Send result by email
    if (( defined $$annoENVRef{'SendMail'}) && ($$annoENVRef{'SendMail'}))
	{	send_result_email($$annoENVRef{SciMinerServerURL}."SciMiner/FinalResults/".$$currentQueueEnvRef{fileNameBase}.'/result.html', $$currentQueueEnvRef{email}, $queryAnalInfo );
	}
}










sub generate_mesh_distribution_from_corpus
{   use Text::NSP::Measures::2D::Fisher::twotailed;

	my $MeSHdescID2termRef		= shift;
	my $MeSHTerm2descIDRef		= shift;
	my $MeSHTerm2DistRef		= shift;
    my $dbh                     = shift;
    my $pmidListRef             = shift;
    my $wholePMIDCnt            = shift;
    my $finalResultDir          = shift;
    my $finalResultWebDir       = shift;
    
    #  Retrieve all docMeSH data for the given PMIDs
    my %pmid2treeCodeHash            = ();
    my %corpusTreeCode2Dist         = ();
    #my %corpusDescID2Dist           = ();
    #my %pmidDiscIDCheck             = ();
    my %treeCode2PMID				= ();		# Hash for hash of pmid and tree code
    my %meshDescID2PMID				= ();
    
    my $pmidFull                    = join (',', @{$pmidListRef});
    my $pmidCntCorpus               = scalar @{$pmidListRef};
    my $sql                         = "SELECT pmid, descIDString FROM docmesh WHERE pmid in ($pmidFull) and explicit like 'E'";
    my $sth                         = $dbh->prepare($sql);
    my @row                         = ();
    $sth->execute();


    #  TODO: Remove $corpusDescID2Dist if not needed to enhance the overall performance

	my %corpusDescID2Dist			= ();
	my %descID2PMID					= ();
	my %pmid2DescIDList				= ();
	my @tmpDescIDArray				= ();
	
    #  Handling the retrieved results
    while(@row=$sth->fetchrow_array)
    {   if ((defined $row[1]) && ($row[1] ne ""))
        {   $pmid2DescIDList{$row[0]}	= $row[1];
        	@tmpDescIDArray	= split (/\;/, $row[1]);
        	foreach my $tmpDescID (@tmpDescIDArray)
        	{	if (not defined $corpusDescID2Dist{$tmpDescID})
			    {   $corpusDescID2Dist{$tmpDescID} = 1;
			    }else
			    {   $corpusDescID2Dist{$tmpDescID}++;
			    }
        	
		        #  Add descID2PMID
		        if (not defined $descID2PMID{$tmpDescID})
		        {	$descID2PMID{$tmpDescID}	= $row[0].',';
		        }elsif ($descID2PMID{$tmpDescID} !~ /\b$row[0],/)
		        {	$descID2PMID{$tmpDescID}	.= $row[0].',';
		        }
        	}
        }
    }
    
    
    # TATATA TODO .. 
    #  Sort the distribution by occurrence
    my @sortedMeSHTreeDescID			= sort {$corpusDescID2Dist{$b} <=> $corpusDescID2Dist{$a}} keys %corpusDescID2Dist;
    my %descID2Pvalue					= ();
    my %descID2Matrix					= ();

    my %tPlusString						= ();
    my %tMinusString					= ();
    my %commonString					= ();
    my %bPlusString						= ();
    my %bMinusString					= ();
    my %commonCount						= ();
    my %tUniqCount						= ();
    my %bUniqCount						= ();
    my %tUniqString						= ();
    my %bUniqString						= ();

    LogQuery("! Generating t-minus string for MeSH distribution");
	foreach my $descID (@sortedMeSHTreeDescID)
	{	foreach my $tmpPmidID (@{$pmidListRef})
        {	# create the t-minus string
        	if ($pmid2DescIDList{$tmpPmidID} !~ /\b$descID;/)
        	{	$tMinusString{$descID}	.= $tmpPmidID.',';
        	}
        }
	}
	undef %pmid2DescIDList;
	
	LogQuery("! Performing Fisher's Exact test on MeSH terms.");
    
    #  $wholePMIDCnt
    my $np2 = $wholePMIDCnt;            # number of whole PMIDs that were used to generate the whole distribution
    my $np1 = $pmidCntCorpus;           # number of PMIDs in the current corpus
    my $npp = $np1 + $np2;
    my $n1p = 0;                        # number of PMIDs with the given code
    my $n11 = 0;                        # number of PMIDs common
    my $n12 = 0;
    my $n21 = 0;
    my $n22 = 0;
    my $twotailedPvalue = 0;
    my $errorCode = "";
    my $ratioCorpus = 0;
    my $ratioFull   = 0;
     
    
	#          word2   ~word2                       corpus         full
	#  word1    n11      n12 | n1p       MeSH+        n11          n12     n1p
	# ~word1    n21      n22 | n2p       MeSH-        n21          n22     n2p
	#           --------------
	#           np1      np2   npp                    np1          np2     npp
 

    #  Perform chi-square // Fisher-exact test .. Since it's 2 by 2, stay with fisher-exact test
    #  This calculation is done through Text::NSP package
    foreach my $descID (@sortedMeSHTreeDescID)
    {   #  Initialize string and count
    	#$tPlusString{$descID}	= join(',', keys %{$descID2PMID{$descID}});
        #$tMinusString{$descID}	= '';
        
    	$n11 = $corpusDescID2Dist{$descID};
        $n12 = $$MeSHTerm2DistRef{$$MeSHdescID2termRef{$descID}};
        $n1p = $n11 + $n12;                             # Note that n1p = n11 + n12
        $n21 = $np1 - $n11;
        $n22 = $np2 - $n12;
        
        $twotailedPvalue = calculateStatistic (n11 => $n11, 
                                               n1p => $n1p,
                                               np1 => $np1,
                                               npp => $npp);
        if ( ($errorCode = getErrorCode()))
        {   $descID2Pvalue{$descID} = -1;
        }else
        {   $descID2Pvalue{$descID} = sprintf("%.3e",$twotailedPvalue);
        }
        
        $descID2Matrix{$descID} = $np1."\t".$n11."\t".$n21."\t".$n12."\t".$n22."\t".$np2."\t";
        $ratioCorpus    = $n11/$np1;
        $ratioFull      = $n12/$np2;
            
        if (($n12 != 0) && ($n11 != 0))
        {   $descID2Matrix{$descID} .= sprintf("%.2f\t%.2f\t%.1f",$ratioCorpus, $ratioFull, ($ratioCorpus)/($ratioFull));
        }else
        {   # This is very unlike to happen. But in case it happens. 
        	my $tmpTag		= $tgZeroTag;
        	if ($n12 == 0)
        	{	$tmpTag		= $bgZeroTag;
        	}
            $descID2Matrix{$descID} .= sprintf("%.2f\t%.2f\t",$ratioCorpus, $ratioFull).$tmpTag;
        }
    }
    
    #  Creating corpus MeSH distribution
    my @sortedDescIDCodes = sort {$descID2Pvalue{$a} <=> $descID2Pvalue{$b}} keys %descID2Pvalue;
    
    open (TMP, ">$finalResultWebDir/MeSHCodeDistribution.txt");
    open (PMID, ">$finalResultWebDir/MeSHCodeDistribution.pmid");
    #  Print out the header first
    print TMP "#DescID\tMeSH\tCorpusSize\tt+\tt-\tb+\tb-\tWholeSize\tt-Ratio\tb-Ratio\tt-ratio/b-ratio\tP-value\n";
    
    foreach my $descID (@sortedDescIDCodes)
    {   print TMP 	$descID."\t".$$MeSHdescID2termRef{$descID}."\t".$descID2Matrix{$descID}."\t".$descID2Pvalue{$descID}."\n";
    	print PMID 	$descID."\t".$$MeSHdescID2termRef{$descID}."\t".$descID2PMID{$descID}."\t".$tMinusString{$descID}."\n";
    
    }
    close PMID;
    close TMP;
}





sub generate_mesh_distribution_from_corpus_Backup
{   use Text::NSP::Measures::2D::Fisher::twotailed;

	my $MeSHdescID2termRef		= shift;
	my $MeSHTerm2descIDRef		= shift;
	my $MeSHTerm2DistRef		= shift;
    my $dbh                     = shift;
    my $pmidListRef             = shift;
    my $wholePMIDCnt            = shift;
    my $finalResultDir          = shift;
    my $finalResultWebDir       = shift;
    
    #  Retrieve all docMeSH data for the given PMIDs
    my %pmid2treeCodeHash            = ();
    my %corpusTreeCode2Dist         = ();
    #my %corpusDescID2Dist           = ();
    #my %pmidDiscIDCheck             = ();
    my %treeCode2PMID				= ();		# Hash for hash of pmid and tree code
    my %meshDescID2PMID				= ();
    
    my $pmidFull                    = join (',', @{$pmidListRef});
    my $pmidCntCorpus               = scalar @{$pmidListRef};
    my $sql                         = "SELECT pmid, descIDString FROM docmesh WHERE pmid in ($pmidFull) and explicit like 'E'";
    my $sth                         = $dbh->prepare($sql);
    my @row                         = ();
    $sth->execute();


    #  TODO: Remove $corpusDescID2Dist if not needed to enhance the overall performance

	my %pmid2descIDHash				= ();
	my %corpusDescID2Dist			= ();
	my %descID2PMID					= ();
	my @tmpDescIDArray				= ();
	
    #  Handling the retrieved results
    while(@row=$sth->fetchrow_array)
    {   if ((defined $row[1]) && ($row[1] ne ""))
        {   @tmpDescIDArray	= split (/\;/, $row[1]);
        	foreach my $tmpDescID (@tmpDescIDArray)
        	{	if (not defined $pmid2descIDHash{$row[0]})
		        {   my %tmpHash					= ();
		        	$tmpHash{$tmpDescID}		= 1;
		            $pmid2descIDHash{$row[0]} 	= \%tmpHash;
		            if (not defined $corpusDescID2Dist{$tmpDescID})
				    {   $corpusDescID2Dist{$tmpDescID} = 1;
				    }else
				    {   $corpusDescID2Dist{$tmpDescID}++;
				    }
		        }else
		        {   if (not defined $pmid2descIDHash{$row[0]}->{$tmpDescID})
		        	{	$pmid2descIDHash{$row[0]}->{$tmpDescID}	= 1;
		        		if (not defined $corpusDescID2Dist{$tmpDescID})
						{   $corpusDescID2Dist{$tmpDescID} = 1;
						}else
						{   $corpusDescID2Dist{$tmpDescID}++;
						}
		        	}
		        }
		        
		        #  Add descID2PMID
		        if (not defined $descID2PMID{$tmpDescID})
		        {	my %hashTmp				= ();
		        	$hashTmp{$row[0]}		= 1;
		        	$descID2PMID{$tmpDescID}	= \%hashTmp;
		        }else
		        {	$descID2PMID{$tmpDescID}->{$row[0]}	= 1;
		        }
        	}
        }
    }
    

    #  Sort the distribution by occurrence
    my @sortedMeSHTreeDescID			= sort {$corpusDescID2Dist{$b} <=> $corpusDescID2Dist{$a}} keys %corpusDescID2Dist;
    my %descID2Pvalue					= ();
    my %descID2Matrix					= ();
    
    #  $wholePMIDCnt
    my $np2 = $wholePMIDCnt;            # number of whole PMIDs that were used to generate the whole distribution
    my $np1 = $pmidCntCorpus;           # number of PMIDs in the current corpus
    my $npp = $np1 + $np2;
    my $n1p = 0;                        # number of PMIDs with the given code
    my $n11 = 0;                        # number of PMIDs common
    my $n12 = 0;
    my $n21 = 0;
    my $n22 = 0;
    my $twotailedPvalue = 0;
    my $errorCode = "";
    my $ratioCorpus = 0;
    my $ratioFull   = 0;
     
    # TATATA TODO .. This section seems to be for SciMiner result page  
    my %tPlusString		= ();
    my %tMinusString	= ();
    my %commonString	= ();
    my %bPlusString		= ();
    my %bMinusString	= ();
    my %commonCount		= ();
    my %tUniqCount		= ();
    my %bUniqCount		= ();
    my %tUniqString		= ();
    my %bUniqString		= ();
    
	#          word2   ~word2                       corpus         full
	#  word1    n11      n12 | n1p       MeSH+        n11          n12     n1p
	# ~word1    n21      n22 | n2p       MeSH-        n21          n22     n2p
	#           --------------
	#           np1      np2   npp                    np1          np2     npp
 

    #  Perform chi-square // Fisher-exact test .. Since it's 2 by 2, stay with fisher-exact test
    #  This calculation is done through Text::NSP package
    foreach my $descID (@sortedMeSHTreeDescID)
    {   #  Initialize string and count
    	$tPlusString{$descID}	= join(',', keys %{$descID2PMID{$descID}});
        $tMinusString{$descID}	= '';
        
        foreach my $tmpPmidID (@{$pmidListRef})
        {	if (not defined $descID2PMID{$descID}->{$tmpPmidID})
        	{	$tMinusString{$descID}	.= $tmpPmidID.',';
        	}
        }
        
    	$n11 = $corpusDescID2Dist{$descID};
        $n12 = $$MeSHTerm2DistRef{$$MeSHdescID2termRef{$descID}};
        $n1p = $n11 + $n12;                             # Note that n1p = n11 + n12
        $n21 = $np1 - $n11;
        $n22 = $np2 - $n12;
        
        $twotailedPvalue = calculateStatistic (n11 => $n11, 
                                               n1p => $n1p,
                                               np1 => $np1,
                                               npp => $npp);
        if ( ($errorCode = getErrorCode()))
        {   $descID2Pvalue{$descID} = -1;
        }else
        {   $descID2Pvalue{$descID} = sprintf("%.3e",$twotailedPvalue);
        }
        
        $descID2Matrix{$descID} = $np1."\t".$n11."\t".$n21."\t".$n12."\t".$n22."\t".$np2."\t";
        $ratioCorpus    = $n11/$np1;
        $ratioFull      = $n12/$np2;
            
        if (($n12 != 0) && ($n11 != 0))
        {   $descID2Matrix{$descID} .= sprintf("%.2f\t%.2f\t%.1f",$ratioCorpus, $ratioFull, ($ratioCorpus)/($ratioFull));
        }else
        {   # This is very unlike to happen. But in case it happens. 
        	my $tmpTag		= $tgZeroTag;
        	if ($n12 == 0)
        	{	$tmpTag		= $bgZeroTag;
        	}
            $descID2Matrix{$descID} .= sprintf("%.2f\t%.2f\t",$ratioCorpus, $ratioFull).$tmpTag;
        }
    }
    
    #  Creating corpus MeSH distribution
    my @sortedDescIDCodes = sort {$descID2Pvalue{$a} <=> $descID2Pvalue{$b}} keys %descID2Pvalue;
    
    open (TMP, ">$finalResultWebDir/MeSHCodeDistribution.txt");
    open (PMID, ">$finalResultWebDir/MeSHCodeDistribution.pmid");
    #  Print out the header first
    print TMP "#DescID\tMeSH\tCorpusSize\tt+\tt-\tb+\tb-\tWholeSize\tt-Ratio\tb-Ratio\tt-ratio/b-ratio\tP-value\n";
    
    foreach my $descID (@sortedDescIDCodes)
    {   print TMP 	$descID."\t".$$MeSHdescID2termRef{$descID}."\t".$descID2Matrix{$descID}."\t".$descID2Pvalue{$descID}."\n";
    	print PMID 	$descID."\t".$$MeSHdescID2termRef{$descID}."\t".$tPlusString{$descID}."\t".$tMinusString{$descID}."\n";
    
    }
    close PMID;
    close TMP;
}




sub SciMiner_Summarize_Both_Result
{	my $HUGO2ApprovedGeneNameRef		= shift;
	my $finalResultWebDir				= shift;
	my $bothFileName					= shift;
	my $dbh								= shift;
	my $pmid2passGeneCountRef			= shift;
	my $threshold						= shift;
	my $queryID							= shift;
	
	#  Symbol Summarization
    open (FILE, $finalResultWebDir.$bothFileName.'.txt') 				|| LogQuery( "!ERROR!:  Can't open $finalResultWebDir$bothFileName.txt");
    open (RESULT, ">".$finalResultWebDir.$bothFileName.'.Summary.txt')	|| LogQuery( "!ERROR!:  Can't open $finalResultWebDir$bothFileName.Summary.txt");
    open (OPTOUT, ">".$finalResultWebDir.$bothFileName.'.Optout.txt') 	|| LogQuery( "!ERROR!:  Can't open $finalResultWebDir$bothFileName.Optout.txt");
    open (REMAIN, ">".$finalResultWebDir.$bothFileName.'.Remain.txt') 	|| LogQuery( "!ERROR!:  Can't open $finalResultWebDir$bothFileName.Remain.txt");
    
    my %discardedGene			= ();
    
    my %uniqSymActualSym 		= ();
    my %uniqSymOccurTotal 		= ();
    my %uniqSymOccurPaper 		= ();
    my %hugoID2Symbol 			= ();
    my %symbol2hugoID			= ();
    my %uniqSymActualSymHash	= ();
    my %uniqSymSen2GeneID		= ();
    
    my @temp					= ();
    my $line					= '';
    my $phenotypeOnlyFilter		= 1;
    my $useLengthOption			= 1;
    my $wordLengthThreshold		= 6;
    
    while(<FILE>)
    {   $line=$_;   
    	$line =~ s/\r|\n//g;
        @temp = split (/\t/, $line);
        
        $hugoID2Symbol{$temp[4]} = $temp[5];
        $symbol2hugoID{$temp[5]} = $temp[4];
        
        #  Check Symbol mode 
        #  Print content into outfiles by method code
        if ($temp[14] == 2)
        {	#  This is by name matching
        	if (($phenotypeOnlyFilter) && ($temp[17]))
		    {   # This is not to be included due to phenotype restriction.
		        # add_optoutLine (\%optoutLine, $temp[4], $line);
		        print OPTOUT $line."\n";
		        $discardedGene{$temp[4]}	= 1;
		    }elsif ($temp[15] == 3)
		    {   #  This is to be excluded (actually ignored)
		        # add_optoutLine (\%optoutLine, $temp[4], $line);
		        print OPTOUT $line."\n";
		        $discardedGene{$temp[4]}	= 1;
		    }elsif ($temp[15] == 2)
		    {   #  This is to be excluded 
		        # add_optoutLine (\%optoutLine, $temp[4], $line);
		        print OPTOUT $line."\n";
		        $discardedGene{$temp[4]}	= 1;
		    }elsif ($temp[15] == 1)    #  name mining result will not have code 2 
		    {   #  This is to be included.
		        add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
		        add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
		        add_uniqSymActualSym  (\%uniqSymActualSym, $temp[4], $temp[7]);
		        add_uniqSymSen2GeneID (\%uniqSymSen2GeneID, $temp[4], $temp[0]);
		        #add_optoutLine (\%remainLine, $temp[4], $line);
		        print REMAIN $line."\n";
		    }else
		    {   #  Check the score
		        if ($temp[9] > $threshold)
		        {   add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
		            add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
		            add_uniqSymActualSym  (\%uniqSymActualSym, $temp[4], $temp[7]);
		            add_uniqSymSen2GeneID (\%uniqSymSen2GeneID, $temp[4], $temp[0]);
		            #add_optoutLine (\%remainLine, $temp[4], $line);
		            print REMAIN $line."\n";
		        }else
		        {   #add_optoutLine (\%optoutLine, $temp[4], $line);
		        	print OPTOUT $line."\n";
		        	$discardedGene{$temp[4]}	= 1;
		        }
		    }
        }else
        {	#  This is by symbol matching
        	if (($phenotypeOnlyFilter) && ($temp[17]))
		    {   # This is not to be included due to phenotype restriction.
		    }else
		    {   #  Check inclusion / exclusion status
		        if ($temp[15] == 1)
		        {   # This is to be included
		            # But check the with length option
		            if ($temp[16] eq '12')
		            {   if ($useLengthOption)
		                {   # This is to be included
		                    add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
		                    add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
		                    add_uniqSymActualSymHash  (\%uniqSymActualSymHash, $temp[4], $temp[7]);
		                    add_uniqSymSen2GeneID (\%uniqSymSen2GeneID, $temp[4], $temp[0]);
		                    # add_optoutLine (\%remainLine, $temp[4], $line);
		                    print REMAIN $line."\n";
		                }else
		                {   # add_optoutLine (\%optoutLine, $temp[4], $line);
		                	print OPTOUT $line."\n";
		                	$discardedGene{$temp[4]}	= 1;
		                }   
		            }else
		            {   add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
		                add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
		                add_uniqSymActualSymHash  (\%uniqSymActualSymHash, $temp[4], $temp[7]);
		                add_uniqSymSen2GeneID (\%uniqSymSen2GeneID, $temp[4], $temp[0]);
		                # add_optoutLine (\%remainLine, $temp[4], $line);
		                print REMAIN $line."\n";
		            }
		        }elsif ($temp[15] == 2)
		        {   # This is to be excluded
		            # add_optoutLine (\%optoutLine, $temp[4], $line);
		            print OPTOUT $line."\n";
		            $discardedGene{$temp[4]}	= 1;
		        }else
		        {   # For any genes with inExCode == 0, check the score
		            if ($temp[9] >= $threshold)
		            {   # This is to be included
		                add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
		                add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
		                add_uniqSymActualSymHash  (\%uniqSymActualSymHash, $temp[4], $temp[7]);
		                add_uniqSymSen2GeneID (\%uniqSymSen2GeneID, $temp[4], $temp[0]);
		                # add_optoutLine (\%remainLine, $temp[4], $line);
		                print REMAIN $line."\n";
		            }else
		            {   # This is to be excluded, unless if the length of gene symbol was used.
		                if ($useLengthOption)
		                {   if (length($temp[6]) >= $wordLengthThreshold)
		                    {   add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
		                        add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
		                        add_uniqSymActualSymHash  (\%uniqSymActualSymHash, $temp[4], $temp[7]);
		                        add_uniqSymSen2GeneID (\%uniqSymSen2GeneID, $temp[4], $temp[0]);
		                        # add_optoutLine (\%remainLine, $temp[4], $line);
		                		print REMAIN $line."\n";
		                    }else
		                    {   # add_optoutLine (\%optoutLine, $temp[4], $line);
		            			print OPTOUT $line."\n";
		            			$discardedGene{$temp[4]}	= 1;
		                    }
		                }
		            }
		        }
		    }
        }
    }   
    close FILE;
    
    #  Process unique symbol actual symbol
    foreach my $tmpHugoID (keys %uniqSymActualSymHash)
    {	foreach my $tmpKey (keys %{$uniqSymActualSymHash{$tmpHugoID}})
    	{   add_uniqSymActualSym (\%uniqSymActualSym, $tmpHugoID, $tmpKey);
    	}
    }
    
    my @sortedSymbol = sort {$hugoID2Symbol{$a} cmp $hugoID2Symbol{$b}} (keys %uniqSymOccurPaper);
    if (scalar @sortedSymbol == 0)
    {   close RESULT;
        close OPTOUT;
        close REMAIN;
        return();
    }

    #  Get the HUGO2ApprovedGeneName
    #my %HUGO2ApprovedGeneName   = ();
    my $hugoIDFull              = join (",", keys %uniqSymOccurPaper);
    my $sql                     = "SELECT hgncID, approvedName FROM gene where hgncID in ($hugoIDFull)";
    my $sth                     = $dbh->prepare($sql);
    my @row                     = ();
    $sth->execute();
    while(@row=$sth->fetchrow_array)
    {   $$HUGO2ApprovedGeneNameRef{$row[0]} = $row[1];
    }

	my %uniqSymPaperCount		= ();
    #  Print out the result
    foreach (@sortedSymbol)
    {   if ((not defined $hugoID2Symbol{$_}) || 
            (not defined $$HUGO2ApprovedGeneNameRef{$_}) ||
            (not defined $uniqSymOccurTotal{$_}) ||
            (not defined $uniqSymOccurPaper{$_}))
        {   # print "!!! Missing data for $_\n";
        }else
        {   print RESULT $hugoID2Symbol{$_}."\t";
            print RESULT $_."\t";
            print RESULT $$HUGO2ApprovedGeneNameRef{$_}."\t";
            print RESULT $uniqSymOccurTotal{$_}."\t";
            my @pubMedID = split (/\,/, $uniqSymOccurPaper{$_});
            $uniqSymPaperCount{$_}	= scalar @pubMedID;
            print RESULT $uniqSymPaperCount{$_}."\t".$uniqSymActualSym{$_}."\t".$uniqSymOccurPaper{$_}."\n";
        }
    }   
	close RESULT;
    close OPTOUT;
    close REMAIN;




	#  Generate MerSum.sorted.txt
	open (MERSUMSORTED, ">".$finalResultWebDir.'SciMinerBase.MerSum.sorted.txt');

    # Sorting by paper and occurrence 
    my %symbolPaperOccurrence 	= ();
    my $totalGeneCount			= scalar @sortedSymbol;
    
    foreach my $symbol (@sortedSymbol)
    {	if (not defined $symbolPaperOccurrence{$uniqSymPaperCount{$symbol}})
    	{   my @newArray = ();
    		push @newArray, $symbol;
    		$symbolPaperOccurrence{$uniqSymPaperCount{$symbol}} = \@newArray;
    	}else
    	{   push @{$symbolPaperOccurrence{$uniqSymPaperCount{$symbol}}}, $symbol;
    	}
    }
    
    my @newSortedSymbols = ();
    my @sortedCounts = sort {$b <=> $a} keys %symbolPaperOccurrence;
    foreach my $sortedCount ( @sortedCounts)
    {   my @countSortedSymbols = sort {$uniqSymOccurTotal{$b} <=> $uniqSymOccurTotal{$a}} @{$symbolPaperOccurrence{$sortedCount}};
    	push @newSortedSymbols, @countSortedSymbols;
    }
    
    
    my @top10genes  = ();
    my $rank        = 1;

	open (SEN2GENEIDFILE, ">".$finalResultWebDir.$bothFileName.'.sen2geneID.txt') 	|| LogQuery( "!ERROR!:  Can't open $finalResultWebDir$bothFileName.sen2geneID.txt");
	my @tmpArray	= ();
	
    foreach (@newSortedSymbols)
    {   print MERSUMSORTED 	$hugoID2Symbol{$_}."\t".$_."\t".
    						$$HUGO2ApprovedGeneNameRef{$_}."\t".
    						$uniqSymOccurTotal{$_}."\t".$uniqSymPaperCount{$_}."\t".
                    		$uniqSymActualSym{$_}."\t".$uniqSymOccurPaper{$_}."\n";
		if (defined $uniqSymSen2GeneID{$_})
		{	print SEN2GENEIDFILE $_."\t".join(",",@{$uniqSymSen2GeneID{$_}})."\n";	
		}
    }
    close MERSUMSORTED;
	close SEN2GENEIDFILE;
    
    #  Update the total count of gene
    $dbh->do("UPDATE query set numGene = $totalGeneCount WHERE queryID = $queryID");
}



















# ------------------------------------------------------------------------------
# sub SciMiner_Summarize_Symbol_Result
# ------------------------------------------------------------------------------
# Last modified	: 03/18/2008
# Description	: This subroutin perform the summarizing task.
# Changes		: * Less memory is required.
# ------------------------------------------------------------------------------
sub SciMiner_Summarize_Symbol_Result
{   my $HUGO2ApprovedGeneNameRef        = shift;   
    my $finalResultDir                  = shift;
    my $newSciMinerBaseOutFileSymbol    = shift;
    my $dbh                             = shift;
    my $pmid2passGeneCountRef			= shift;  
    my $currentQueueEnvRef				= shift;  

	my $phenotypeOnlyFilter             = $$currentQueueEnvRef{"phenotypeOnlyFilter"};
    my $useLengthOption                 = $$currentQueueEnvRef{"useLengthOption"};
    my $wordLengthThreshold             = $$currentQueueEnvRef{"wordLengthThreshold"};
    my $useScoreThreshold				= $$currentQueueEnvRef{"useScoreThreshold"};
    my $scoreThreshold					= $$currentQueueEnvRef{"scoreThreshold"};

	my $localScoreThreshold				= 0.1;
	if ($useScoreThreshold)
	{	$localScoreThreshold			= $scoreThreshold;
	}

    my %uniqSymActualSym 		= ();
    my %uniqSymActualSymHash	= ();
    my %uniqSymOccurTotal 		= ();
    my %uniqSymOccurPaper 		= ();
    my %hugoID2Symbol 			= ();
    # my %optoutLine 			= ();
    # my %remainLine  			= ();
    my %discardedGene			= ();
 
    open (FILE, $newSciMinerBaseOutFileSymbol.'.txt') 				|| LogQuery( "!ERROR!:  Can't open $newSciMinerBaseOutFileSymbol.txt");
    open (RESULT, ">".$newSciMinerBaseOutFileSymbol.'.Summary.txt')	|| LogQuery( "!ERROR!:  Can't open $newSciMinerBaseOutFileSymbol.Summary.txt");
    open (OPTOUT, ">".$newSciMinerBaseOutFileSymbol.'.Optout.txt') 	|| LogQuery( "!ERROR!:  Can't open $newSciMinerBaseOutFileSymbol.Optout.txt");
    open (REMAIN, ">".$newSciMinerBaseOutFileSymbol.'.Remain.txt') 	|| LogQuery( "!ERROR!:  Can't open $newSciMinerBaseOutFileSymbol.Remain.txt");
    
    #  Print header
    print RESULT 	"#Symbol\tHUGOID\tName\t#Occur\t#Paper\tMatchString\tPMIDs\n";
    print OPTOUT 	"#sen2geneID\tpmid\tsenID\tgeneID\thgncID\tapprovedSymbol\tmatchString\tactualString\tstartPos\tscore\tflankingText\t".
    				"matchCodeID\ttag\tSciMinerVersion\tSciMinerMethod\tinExClude\tinExCludeCond\tphenotypeOnly\tconflictCode\t".
    				"hgncIDbyNR\tNRText\teditTag\teditUser\toldGeneID\toldHgncID\toldApprovedSymbol\toldInExClude\toldInExCludeCond\n";
    print REMAIN 	"#sen2geneID\tpmid\tsenID\tgeneID\thgncID\tapprovedSymbol\tmatchString\tactualString\tstartPos\tscore\tflankingText\t".
    				"matchCodeID\ttag\tSciMinerVersion\tSciMinerMethod\tinExClude\tinExCludeCond\tphenotypeOnly\tconflictCode\t".
    				"hgncIDbyNR\tNRText\teditTag\teditUser\toldGeneID\toldHgncID\toldApprovedSymbol\toldInExClude\toldInExCludeCond\n";
    				
    while(<FILE>)
    {   my $line=$_;   
		if ($line =~ /^\#/)
        {	next;
        }
        $line =~ s/\r|\n//g;
        my @temp = split (/\t/, $line);
        
        $hugoID2Symbol{$temp[4]} = $temp[5];
        
        # $temp[15] inExCode
        # $temp[1]  pmid
        # $temp[9]  score
        # $temp[4]  hugoID
        # $temp[5]  symbol (approved)
        # $REMOVEREMOVE
        # $temp[7]  actualString
        
        #  1) check phenotype option
        
        if (($phenotypeOnlyFilter) && ($temp[17]))
        {   # This is not to be included due to phenotype restriction.
        }else
        {   #  Check inclusion / exclusion status
            if ($temp[15] == 1)
            {   # This is to be included
                # But check the with length option
                if ($temp[16] eq '12')
                {   if ($useLengthOption)
                    {   # This is to be included
                        add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
                        add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
                        add_uniqSymActualSymHash  (\%uniqSymActualSymHash, $temp[4], $temp[7]);
                        # add_optoutLine (\%remainLine, $temp[4], $line);
                        print REMAIN $line."\n";
                    }else
                    {   # add_optoutLine (\%optoutLine, $temp[4], $line);
                    	print OPTOUT $line."\n";
                    	$discardedGene{$temp[4]}	= 1;
                    }   
                }else
                {   add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
                    add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
                    add_uniqSymActualSymHash  (\%uniqSymActualSymHash, $temp[4], $temp[7]);
                    # add_optoutLine (\%remainLine, $temp[4], $line);
                    print REMAIN $line."\n";
                }
            }elsif ($temp[15] == 2)
            {   # This is to be excluded
                # add_optoutLine (\%optoutLine, $temp[4], $line);
                print OPTOUT $line."\n";
                $discardedGene{$temp[4]}	= 1;
            }else
            {   # For any genes with inExCode == 0, check the score
                if ($temp[9] >= $localScoreThreshold)
                {   # This is to be included
                    add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
                    add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
                    add_uniqSymActualSymHash  (\%uniqSymActualSymHash, $temp[4], $temp[7]);
                    # add_optoutLine (\%remainLine, $temp[4], $line);
                    print REMAIN $line."\n";
                }else
                {   # This is to be excluded, unless if the length of gene symbol was used.
                    if ($useLengthOption)
                    {   if (length($temp[6]) >= $wordLengthThreshold)
                        {   add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
                            add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
                            add_uniqSymActualSymHash  (\%uniqSymActualSymHash, $temp[4], $temp[7]);
                            # add_optoutLine (\%remainLine, $temp[4], $line);
                    		print REMAIN $line."\n";
                        }else
                        {   # add_optoutLine (\%optoutLine, $temp[4], $line);
                			print OPTOUT $line."\n";
                			$discardedGene{$temp[4]}	= 1;
                        }
                    }
                }
            }
        }
    }   
    close FILE;
    
    #  Process unique symbol actual symbol
    foreach my $tmpHugoID (keys %uniqSymActualSymHash)
    {	foreach my $tmpKey (keys %{$uniqSymActualSymHash{$tmpHugoID}})
    	{   add_uniqSymActualSym (\%uniqSymActualSym, $tmpHugoID, $tmpKey);
    	}
    }
    
    
    my @sortedSymbol = sort {$hugoID2Symbol{$a} cmp $hugoID2Symbol{$b}} (keys %uniqSymOccurPaper);
    if (scalar @sortedSymbol == 0)
    {   close RESULT;
        close OPTOUT;
        close REMAIN;
        return();
    }

    #  Get the HUGO2ApprovedGeneName
    #my %HUGO2ApprovedGeneName   = ();
    my $hugoIDFull              = join (",", keys %uniqSymOccurPaper);
    my $sql                     = "SELECT hgncID, approvedName FROM gene where hgncID in ($hugoIDFull)";
    my $sth                     = $dbh->prepare($sql);
    my @row                     = ();
    $sth->execute();
    while(@row=$sth->fetchrow_array)
    {   $$HUGO2ApprovedGeneNameRef{$row[0]} = $row[1];
    }



    #  Print out the result
    foreach (@sortedSymbol)
    {   if ((not defined $hugoID2Symbol{$_}) || 
            (not defined $$HUGO2ApprovedGeneNameRef{$_}) ||
            (not defined $uniqSymOccurTotal{$_}) ||
            (not defined $uniqSymOccurPaper{$_}))
        {   # print "!!! Missing data for $_\n";
        }else
        {   print RESULT $hugoID2Symbol{$_}."\t";
            print RESULT $_."\t";
            print RESULT $$HUGO2ApprovedGeneNameRef{$_}."\t";
            print RESULT $uniqSymOccurTotal{$_}."\t";
            my @pubMedID = split (/\,/, $uniqSymOccurPaper{$_});
            print RESULT ($#pubMedID+1)."\t".$uniqSymActualSym{$_}."\t".$uniqSymOccurPaper{$_}."\n";
        }
    }   
	close RESULT;
    close OPTOUT;
    close REMAIN;

    my $totalNumSymbol = scalar @sortedSymbol;
    LogQuery("\tNum of Mined Symbols                : $totalNumSymbol"); 
    LogQuery("\tNum of discarded Symbols            : ".(scalar keys %discardedGene));
}










# ------------------------------------------------------------------------------
# sub SciMiner_Summarize_Name_Result
# ------------------------------------------------------------------------------
# Last modified	: 03/18/2008
# Description	: This subroutin perform the summarizing task.
# Changes		: * Less memory is required.
# ------------------------------------------------------------------------------
sub SciMiner_Summarize_Name_Result
{   my $HUGO2ApprovedGeneNameRef        = shift;   
    my $finalResultDir                  = shift;
    my $newSciMinerBaseOutFileName      = shift;
    my $phenotypeOnlyFilter             = shift;
    my $dbh                             = shift;
    my $pmid2passGeneCountRef			= shift;
    my $scoreThreshold					= shift;
    
    
    my %uniqSymActualSym 	= ();
    my %uniqSymOccurTotal 	= ();
    my %uniqSymOccurPaper 	= ();
    my %hugoID2Symbol 		= ();
    # my %optoutLine 		= ();
    # my %remainLine  		= ();
    my %discardedGene		= ();

    open (FILE, $newSciMinerBaseOutFileName.'.txt')                  || LogQuery( "!ERROR!:  Can't open $newSciMinerBaseOutFileName.txt");
    open (RESULT, ">".$newSciMinerBaseOutFileName.'.Summary.txt')    || LogQuery( "!ERROR!:  Can't open $newSciMinerBaseOutFileName.Summary.txt");
    open (OPTOUT, ">".$newSciMinerBaseOutFileName.'.Optout.txt')     || LogQuery( "!ERROR!:  Can't open $newSciMinerBaseOutFileName.Optout.txt");
    open (REMAIN, ">".$newSciMinerBaseOutFileName.'.Remain.txt')     || LogQuery( "!ERROR!:  Can't open $newSciMinerBaseOutFileName.Remain.txt");
    
    #  Print header
    print RESULT 	"#Symbol\tHUGOID\tName\t#Occur\t#Paper\tMatchString\tPMIDs\n";
    print OPTOUT 	"#sen2geneID\tpmid\tsenID\tgeneID\thgncID\tapprovedSymbol\tmatchString\tactualString\tstartPos\tscore\tflankingText\t".
    				"matchCodeID\ttag\tSciMinerVersion\tSciMinerMethod\tinExClude\tinExCludeCond\tphenotypeOnly\tconflictCode\t".
    				"hgncIDbyNR\tNRText\teditTag\teditUser\toldGeneID\toldHgncID\toldApprovedSymbol\toldInExClude\toldInExCludeCond\n";
    print REMAIN 	"#sen2geneID\tpmid\tsenID\tgeneID\thgncID\tapprovedSymbol\tmatchString\tactualString\tstartPos\tscore\tflankingText\t".
    				"matchCodeID\ttag\tSciMinerVersion\tSciMinerMethod\tinExClude\tinExCludeCond\tphenotypeOnly\tconflictCode\t".
    				"hgncIDbyNR\tNRText\teditTag\teditUser\toldGeneID\toldHgncID\toldApprovedSymbol\toldInExClude\toldInExCludeCond\n";
    
    while(<FILE>)
    {   my $line=$_;   
		if ($line =~ /^\#/)
        {	next;
        }
        $line =~ s/\r|\n//g;
        my @temp = split (/\t/, $line);
        
        $hugoID2Symbol{$temp[4]} = $temp[5];
        
        # $temp[15] inExCode
        # $temp[1]  pmid
        # $temp[9]  score
        # $temp[4]  hugoID
        # $temp[5]  symbol (approved)
        # $temp[7]  actualString
        # LogQuery("! Checking $temp[4]\t$temp[7]");
        #  1) check exclusion option
        if (($phenotypeOnlyFilter) && ($temp[17]))
        {   # This is not to be included due to phenotype restriction.
            # add_optoutLine (\%optoutLine, $temp[4], $line);
            print OPTOUT $line."\n";
            $discardedGene{$temp[4]}	= 1;
        }elsif ($temp[15] == 3)
        {   #  This is to be excluded (actually ignored)
            # add_optoutLine (\%optoutLine, $temp[4], $line);
            print OPTOUT $line."\n";
            $discardedGene{$temp[4]}	= 1;
        }elsif ($temp[15] == 2)
        {   #  This is to be excluded 
            # add_optoutLine (\%optoutLine, $temp[4], $line);
            print OPTOUT $line."\n";
            $discardedGene{$temp[4]}	= 1;
        }elsif ($temp[15] == 1)    #  name mining result will not have code 2 
        {   #  This is to be included.
            add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
            add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
            add_uniqSymActualSym  (\%uniqSymActualSym, $temp[4], $temp[7]);
            #add_optoutLine (\%remainLine, $temp[4], $line);
            print REMAIN $line."\n";
        }else
        {   #  Check the score
            if ($temp[9] >= $scoreThreshold)
            {   add_uniqSymOccurTotal (\%uniqSymOccurTotal, $temp[4]);
                add_uniqSymOccurPaper (\%uniqSymOccurPaper, $temp[4], $temp[1], $pmid2passGeneCountRef);
                add_uniqSymActualSym  (\%uniqSymActualSym, $temp[4], $temp[7]);
                #add_optoutLine (\%remainLine, $temp[4], $line);
                print REMAIN $line."\n";
            }else
            {   #add_optoutLine (\%optoutLine, $temp[4], $line);
            	print OPTOUT $line."\n";
            	$discardedGene{$temp[4]}	= 1;
            }
        }
    }   
    close FILE;
    
    my @sortedSymbol = sort {$hugoID2Symbol{$a} cmp $hugoID2Symbol{$b}} (keys %uniqSymOccurPaper);
    if (scalar @sortedSymbol == 0)
    {   close RESULT;
        close OPTOUT;
        close REMAIN;
        return();
    }

    #  Get the HUGO2ApprovedGeneName
    my %HUGO2ApprovedGeneName   = ();
    my @hugoIDsToGetNames       = ();
    foreach my $id (keys %uniqSymOccurPaper)
    {   if (not defined $$HUGO2ApprovedGeneNameRef{$id})
        {   push @hugoIDsToGetNames, $id;
        }
    }
    my $hugoIDFull              = join (",", @hugoIDsToGetNames);

    my $sql                     = "SELECT hgncID, approvedName FROM gene where hgncID in ($hugoIDFull)";
    my $sth                     = $dbh->prepare($sql);
    my @row                     = ();
    $sth->execute();
    while(@row=$sth->fetchrow_array)
    {   $$HUGO2ApprovedGeneNameRef{$row[0]} = $row[1];
    }

	LogQuery("! Loading Name result completed");
    #  Print out the result        
    foreach (@sortedSymbol)
    {   if ((not defined $hugoID2Symbol{$_}) || 
            (not defined $$HUGO2ApprovedGeneNameRef{$_}) ||
            (not defined $uniqSymOccurTotal{$_}) ||
            (not defined $uniqSymOccurPaper{$_}))
        {   LogQuery( "! NameSummary - Missing data for $_");
        }else
        {   print RESULT $hugoID2Symbol{$_}."\t";
            print RESULT $_."\t";
            print RESULT $$HUGO2ApprovedGeneNameRef{$_}."\t";
            print RESULT $uniqSymOccurTotal{$_}."\t";
            my @pubMedID = split (/\,/, $uniqSymOccurPaper{$_});
            print RESULT ($#pubMedID+1)."\t".$uniqSymActualSym{$_}."\t".$uniqSymOccurPaper{$_}."\n";
        }
    }   
    close RESULT; 
    close OPTOUT;
    close REMAIN;

    my $totalNumSymbol = scalar @sortedSymbol;
    LogQuery("\tNum of Mined Symbols by name        : $totalNumSymbol"); 
    LogQuery("\tNum of discarded Symbols by name    : ".(scalar keys %discardedGene));
}



# ---------------------------------------------------------------------------
# sub SciMiner_Symbol_Name_Summary_Merge
# ---------------------------------------------------------------------------
# Last modified: 07/16/2008
# Description: This subroutin will merge two summary files; one for symbol
#              and the other for name mining. 
# ---------------------------------------------------------------------------
sub SciMiner_Symbol_Name_Summary_Merge
{   my ($symSumFile, $namSumFile, $merSumFile) = @_;
    open (SYMBOL, $symSumFile)      || LogQuery("! Can't open $symSumFile");
    open (NAME, $namSumFile)        || LogQuery("! Can't open $namSumFile");
    open (MERGE, ">".$merSumFile.'.txt')   || LogQuery("! Can't open $merSumFile");

    
    my (@symbol, %symbol2ID, %symbol2Desc, %symbol2Occurence, %symbol2Papers, 
    	%symbol2MatchStr, %symbol2PMID);
    while(<SYMBOL>)
    {   my $line = $_;      
    	if ($line =~ /^\#/)
    	{	next;
    	}
    	$line =~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        push @symbol, $tmp[0];
        $symbol2ID{$tmp[0]} = $tmp[1];
        $symbol2Desc{$tmp[0]} = $tmp[2];
        $symbol2Occurence{$tmp[0]} = $tmp[3];
        $symbol2Papers{$tmp[0]} = $tmp[4];
        $symbol2MatchStr{$tmp[0]} = $tmp[5];
        $symbol2PMID{$tmp[0]} = $tmp[6];
    }   close SYMBOL;

    while(<NAME>)
    {   my $line = $_;      
    	if ($line =~ /^\#/)
    	{	next;
    	}$line =~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        if (not defined $symbol2ID{$tmp[0]})
        {   push @symbol, $tmp[0];
            $symbol2ID{$tmp[0]} = $tmp[1];
            $symbol2Desc{$tmp[0]} = $tmp[2];
            $symbol2Occurence{$tmp[0]} = $tmp[3];
            $symbol2Papers{$tmp[0]} = $tmp[4];
            $symbol2MatchStr{$tmp[0]} = $tmp[5];
            $symbol2PMID{$tmp[0]} = $tmp[6];
        }else
        {   # Add occurrence
            $symbol2Occurence{$tmp[0]} += $tmp[3];
            # $symbol2Papers{$tmp[0]} += $tmp[4];

            # PMID check
            my @PMIDSplit = split (/\,/, $tmp[6]);
            foreach my $checkKey (@PMIDSplit)
            {   if ( $symbol2PMID{$tmp[0]} =~ /\b$checkKey\b/)
                {   # No need to add
                }else
                {   $symbol2PMID{$tmp[0]} .= $checkKey.',';
                    $symbol2Papers{$tmp[0]}++;
                }   
            }
            
            # Matched String check
            my @MatchStrSplit = split (/ \| /, $tmp[5]);
            foreach my $checkKey (@MatchStrSplit)
            {   # LogQuery("Checking $checkKey for term merging");
            	if ($checkKey =~ /\+/)
            	{	my $originalKey	= $checkKey;
            		$checkKey		=~ s/\+/\\\+/g;
            		
   	            	if (( $symbol2MatchStr{$tmp[0]} =~ /^$checkKey \| / ) ||
		        		( $symbol2MatchStr{$tmp[0]} =~ / \| $checkKey \| /))
		            {   # No need to add
		            }else
		            {   $symbol2MatchStr{$tmp[0]} .= $originalKey.' | ';
		            }   
            	}else
            	{	if (( $symbol2MatchStr{$tmp[0]} =~ /^$checkKey \| / ) ||
		        		( $symbol2MatchStr{$tmp[0]} =~ / \| $checkKey \| /))
		            {   # No need to add
		            }else
		            {   if ($checkKey =~ /\\/)
		            	{   my @tmpKeys = split (/ \| /, $symbol2MatchStr{$tmp[0]});
		            		my $sameFound = 0;
		            		foreach (my @tmpKeys)
		            		{   if ($_ eq $checkKey)
		            			{   $sameFound = 1;
		            				last;
		            			}
		            		}
		            		if (! $sameFound)
		            		{   $symbol2MatchStr{$tmp[0]} .= $checkKey.' | ';
		            		}
		            	}else
		            	{   $symbol2MatchStr{$tmp[0]} .= $checkKey.' | ';
		            	}
		            }   
            	}
            }
        }
    }   close NAME;

    @symbol = sort (@symbol);
    foreach (@symbol)
    {   print MERGE $_."\t".$symbol2ID{$_}."\t".$symbol2Desc{$_}."\t".
                    $symbol2Occurence{$_}."\t".$symbol2Papers{$_}."\t".
                    $symbol2MatchStr{$_}."\t".$symbol2PMID{$_}."\n";
    }
    close MERGE;
    # print "\n\tNum of Total Merged Symbols: ".(scalar @symbol)."\n\n";
    
    #  Create # of paper sorted result file
    open (MERGESORTED, ">".$merSumFile.'.sorted.txt')   || LogQuery("! Can't open $merSumFile.sorted.txt");
    # my @sortedSymbol = sort {$symbol2Papers{$b} <=> $symbol2Papers{$a}} @symbol;
    print MERGESORTED "#Symbol\tID\tName\tOccur\tPaper\tMatchStr\tPMID\n";
    
    # Sorting by paper and occurrence 
    my %symbolPaperOccurrence = ();
    foreach my $symbol (@symbol)
    {	if (not defined $symbolPaperOccurrence{$symbol2Papers{$symbol}})
    	{   my @newArray = ();
    		push @newArray, $symbol;
    		$symbolPaperOccurrence{$symbol2Papers{$symbol}} = \@newArray;
    	}else
    	{   push @{$symbolPaperOccurrence{$symbol2Papers{$symbol}}}, $symbol;
    	}
    }
    
    my @newSortedSymbols = ();
    my @sortedCounts = sort {$b <=> $a} keys %symbolPaperOccurrence;
    foreach my $sortedCount ( @sortedCounts)
    {   my @countSortedSymbols = sort {$symbol2Occurence{$b} <=> $symbol2Occurence{$a}} @{$symbolPaperOccurrence{$sortedCount}};
    	push @newSortedSymbols, @countSortedSymbols;
    }
    
    
    my @top10genes  = ();
    my $rank        = 1;
    foreach (@newSortedSymbols)
    {   print MERGESORTED $_."\t".$symbol2ID{$_}."\t".$symbol2Desc{$_}."\t".
                    $symbol2Occurence{$_}."\t".$symbol2Papers{$_}."\t".
                    $symbol2MatchStr{$_}."\t".$symbol2PMID{$_}."\n";
        if ($rank <= 10)
        {   my @resultArr = ($_, $symbol2ID{$_}, $symbol2Desc{$_}, $symbol2Occurence{$_}, $symbol2Papers{$_});
            push @top10genes, \@resultArr;
            $rank++;
        }
    }
    close MERGESORTED;
    return (\@top10genes);
}



sub add_uniqSymSen2GeneID
{	my $uniqSymSen2GeneIDRef		= shift;
	my $hugoID						= shift;
	my $sen2geneID					= shift;
	
	if (not defined $$uniqSymSen2GeneIDRef{$hugoID})
	{	my @tmpArray				= ();
		push @tmpArray, $sen2geneID;
		$$uniqSymSen2GeneIDRef{$hugoID}	= \@tmpArray;
	}
	else
	{	push @{$$uniqSymSen2GeneIDRef{$hugoID}}, $sen2geneID;
	}
}


sub add_uniqSymOccurTotal
{   my $uniqSymOccurTotalRef    = shift;
    my $hugoID                  = shift;
    
    if (defined $$uniqSymOccurTotalRef{$hugoID})
    {   $$uniqSymOccurTotalRef{$hugoID}++;
    }else
    {   $$uniqSymOccurTotalRef{$hugoID} = 1;
    }
}   






sub add_optoutLine
{   my $optoutLineRef           = shift;
    my $hugoID                  = shift;
    my $optoutLine              = shift;
    
    if (defined $$optoutLineRef{$hugoID})
    {   $$optoutLineRef{$hugoID} .= $optoutLine."\n";
    }else
    {   $$optoutLineRef{$hugoID} = $optoutLine."\n";
    }
}   





sub add_uniqSymOccurPaper
{   my $uniqSymOccurPaperRef    = shift;
    my $hugoID                  = shift;
    my $pmid                    = shift;
    my $pmid2passGeneCountRef	= shift;
    
    if (defined $$uniqSymOccurPaperRef{$hugoID})
    {   if ($$uniqSymOccurPaperRef{$hugoID} =~ /\b$pmid\b/)
        {   #  No need to add this paper entry
        }else
        {   $$uniqSymOccurPaperRef{$hugoID} .= $pmid.',';
        }
    }else
    {   $$uniqSymOccurPaperRef{$hugoID} = $pmid.',';
    }
    
    if (not defined $$pmid2passGeneCountRef{$pmid})
    {   $$pmid2passGeneCountRef{$pmid}->{$hugoID} = 1;
    }else
    {   $$pmid2passGeneCountRef{$pmid}->{$hugoID} = 1;
    }
}
        
        
        
        
        
sub add_uniqSymActualSym
{   my $uniqSymActualSymRef     = shift;
    my $hugoID                  = shift;
    my $actualString            = shift;
    
    if (defined $$uniqSymActualSymRef{$hugoID})
    {   if ($actualString =~ /\+/)
    	{	my $originalString	= $actualString;
    		$actualString		=~ s/\+/\\\+/g;
    		
    		if ($$uniqSymActualSymRef{$hugoID} =~ /\b$actualString\b/)
		    {   #  No need to add this paper entry
		    }else
		    {   $$uniqSymActualSymRef{$hugoID} .= $originalString.' | ';
		    }
    	}else
    	{	if ($$uniqSymActualSymRef{$hugoID} =~ /\b$actualString\b/)
		    {   #  No need to add this paper entry
		    }else
		    {   if ($actualString =~ /\\/)
		    	{	$actualString =~ s/\\//g;
		    		$$uniqSymActualSymRef{$hugoID} .= $actualString.' | ';
		    	}else
		    	{	$$uniqSymActualSymRef{$hugoID} .= $actualString.' | ';
		    	}
		    }
    	}
    }else
    {   if ($actualString =~ /\\/)
    	{	$actualString =~ s/\\//g;
    		$$uniqSymActualSymRef{$hugoID} = $actualString.' | ';
    	}else
    	{	$$uniqSymActualSymRef{$hugoID} = $actualString.' | ';
    	}
    }
}






sub add_uniqSymActualSymHash
{   my $uniqSymActualSymRef     		= shift;
    my $hugoID                  		= shift;
    my $actualString            		= shift;
    
    if (defined $$uniqSymActualSymRef{$hugoID})
    {   if (not defined $$uniqSymActualSymRef{$hugoID}->{$actualString})
    	{	$$uniqSymActualSymRef{$hugoID}->{$actualString}	= 1;
    	}
    }else
    {   my %tmpHash						= ();
    	$tmpHash{$actualString}			= 1;
    	$$uniqSymActualSymRef{$hugoID}	= \%tmpHash;
    }
}










