sub generate_missing_preSciMiner_document_additional
{   my $dbh                     = shift;   
    my $pmid                    = shift;
    my $wholeTextContentHashRef = shift;

    my $sth                 = ''; 
    my @row                 = ();
    
    if (defined $pmid)
    {   if (defined $$wholeTextContentHashRef{$pmid})
        {   #  There is already full text content for this pmid in the memory. So skip fetching
        }else
        {   $$wholeTextContentHashRef{$pmid} = '';
            $sth = $dbh->prepare("SELECT senID, secAnchor, paraNum, pNum, sentence FROM sentence WHERE pmid = $pmid");
            $sth->execute();
            while(@row = $sth->fetchrow_array)
            {   if ($row[1] ne "REFERENCES")
                {   $$wholeTextContentHashRef{$pmid} .= $row[4].' ';
                }
            }
        }
    }
}










sub create_PMID_list_for_SciMiner_process
{   my $listFile        = shift;
    my $listArrRef      = shift;
    my $pmid2docIDRef   = shift;
    
    open (LIST, ">$listFile") || LogQuery("!ERROR: List file for mining $listFile can't be created");
    foreach my $pmid (@{$listArrRef})
    {   
        print LIST $pmid."\t".$$pmid2docIDRef{$pmid}."\n";
    }
    close (LIST);
}










sub create_SciMiner_default_files
{   my $dbh         = shift;
    my $annoENVRef  = shift;
    my $dicNameRef  = shift;
    
    my @row         = ();
    my $sth         = '';
    
    my $DESTDIR     = $$annoENVRef{SciMinerPath}."Work/Dictionary/";
    mkdir ($DESTDIR) || print "";
    my $geneID2hgncID   = ();
    my $hgncID2geneID   = ();
    
    #  Generate 'HUGO_trimmed_final_default' in DB_Working_I/HUGO/
    $$dicNameRef{"trim"} = "HUGO_trimmed_final_default";
    if (! -f "$DESTDIR/HUGO_trimmed_final_default")
    {   open (RESULT, ">$DESTDIR/HUGO_trimmed_final_default");
        $sth = $dbh->prepare("SELECT * FROM gene");
        $sth->execute();
        while(@row = $sth->fetchrow_array)
        {   print RESULT join("\t",@row),"\n";
        }
        close RESULT;
    }
    
    #  Generate 'HUGO_2_external_default' in DB_Working_I/HUGO/
    $$dicNameRef{"external"} = "HUGO_2_external_default";    
    if (! -f "$DESTDIR/HUGO_2_external_default")
    {   open (RESULT, ">$DESTDIR/HUGO_2_external_default");
        $sth = $dbh->prepare("SELECT * FROM gene2external");
        $sth->execute();
        while(@row = $sth->fetchrow_array)
        {   print RESULT join("\t",@row),"\n";
        }
        close RESULT;
    }
    
    #  Generate 'EXCLUDE_default' 
    $$dicNameRef{"exclude"} = "EXCLUDE_default";    
    if (! -f "$DESTDIR/EXCLUDE_default")
    {   open (RESULT, ">$DESTDIR/EXCLUDE_default");
        $sth = $dbh->prepare("SELECT symbolToExclude, conditionToExclude FROM excludelist");
        $sth->execute();
        my %excludeCondition = ();
        
        while(@row = $sth->fetchrow_array)
        {	$row[0]	= lc($row[0]);
			if (not defined $excludeCondition{$row[0]})
            {   $excludeCondition{$row[0]}->[0] = $row[1];
            }else
            {   push @{$excludeCondition{$row[0]}}, $row[1];
            }
        }
        
        foreach my $excludeSymbol (keys %excludeCondition)
        {   print RESULT $excludeSymbol;
            foreach my $conditionTerm (@{$excludeCondition{$excludeSymbol}})
            {   print RESULT "\t".$conditionTerm;
            }
            print RESULT "\n";
        }
        close RESULT;
    }
    
    #  Generate 'INCLUDE_default' 
    $$dicNameRef{"include"} = "INCLUDE_default";    
    if (! -f "$DESTDIR/INCLUDE_default")
    {   open (RESULT, ">$DESTDIR/INCLUDE_default");
        $sth = $dbh->prepare("SELECT symbolToInclude, conditionToInclude FROM includelist");
        $sth->execute();
        my %includeCondition = ();
        
        while(@row = $sth->fetchrow_array)
        {	$row[0]	= lc($row[0]);
			if (not defined $includeCondition{$row[0]})
            {   $includeCondition{$row[0]}->[0] = $row[1];
            }else
            {   push @{$includeCondition{$row[0]}}, $row[1];
            }
        }
        
        foreach my $includeSymbol (keys %includeCondition)
        {   print RESULT $includeSymbol;
            foreach my $conditionTerm (@{$includeCondition{$includeSymbol}})
            {   print RESULT "\t".$conditionTerm;
            }
            print RESULT "\n";
        }
        close RESULT;
    }
    
    #  Generate 'IGNORE_default' 
    $$dicNameRef{"ignore"} = "IGNORE_default";    
    if (! -f "$DESTDIR/IGNORE_default")
    {   open (RESULT, ">$DESTDIR/IGNORE_default");
        $sth = $dbh->prepare("SELECT ignoreTerm FROM ignorelist");
        $sth->execute();
        my %includeCondition = ();
        
        while(@row = $sth->fetchrow_array)
        {   print RESULT $row[0]."\n";
        }
        close RESULT;
    }

    #  Generate 'ENGDICTIONARY_default' 
    $$dicNameRef{"eng"} = "ENGDICTIONARY_default";    
    if (! -f "$DESTDIR/ENGDICTIONARY_default")
    {   open (RESULT, ">$DESTDIR/ENGDICTIONARY_default");
        $sth = $dbh->prepare("SELECT dictionaryWord FROM engdictionary");
        $sth->execute();
        my %includeCondition = ();
        
        while(@row = $sth->fetchrow_array)
        {   print RESULT $row[0]."\n";
        }
        close RESULT;
    }    

    #  Generate 'UNIQUESYMBOL_default' 
    $$dicNameRef{"uniqsym"} = "UNIQUESYMBOL_default";    
    if (! -f "$DESTDIR/UNIQUESYMBOL_default")
    {   open (RESULT, ">$DESTDIR/UNIQUESYMBOL_default");
        $sth = $dbh->prepare("SELECT uniqueSymbol, hgncID, symbolSource FROM uniquesymbol");
        $sth->execute();
       
        while(@row = $sth->fetchrow_array)
        {   print RESULT join("\t",@row),"\n";
        }
        close RESULT;
    }    

    #  Generate 'UNIQUENAME_default' 
    $$dicNameRef{"uniqname"} 	= "UNIQUENAME_default";    
    if (! -f "$DESTDIR/UNIQUENAME_default")
    {   open (RESULT, ">$DESTDIR/UNIQUENAME_default");
        $sth = $dbh->prepare("SELECT uniqueName, hgncID, nameSource FROM uniquename");
        $sth->execute();
        
        while(@row = $sth->fetchrow_array)
        {   print RESULT join("\t",@row),"\n";
        }
        close RESULT;
    }   
    
    #  Generate 'DUPLICATESYMBOL_default' 
    $$dicNameRef{"dupsym"} = "DUPLICATESYMBOL_default";    
    if (! -f "$DESTDIR/DUPLICATESYMBOL_default")
    {   open (RESULT, ">$DESTDIR/DUPLICATESYMBOL_default");
        $sth = $dbh->prepare("SELECT duplicateSymbol, hgncID, firstNameCheckTag FROM duplicatesymbol");
        $sth->execute();
        my %dupSymbol2hgncID            = ();
        my %dupSymbol2firstNameCheck    = ();
        
        while(@row = $sth->fetchrow_array)
        {   if (not defined $dupSymbol2hgncID{$row[0]})
            {   $dupSymbol2hgncID{$row[0]}->[0] = $row[1];
                $dupSymbol2firstNameCheck{$row[0]}->[0] = $row[2];
            }else
            {   push @{$dupSymbol2hgncID{$row[0]}}, $row[1];
                push @{$dupSymbol2firstNameCheck{$row[0]}}, $row[2];
            }
        }
        
        foreach my $dupSymbol (keys %dupSymbol2hgncID)
        {   print RESULT $dupSymbol."\t";
            for (my $j=1; $j < scalar @{$dupSymbol2hgncID{$dupSymbol}}; $j++)
            {   print RESULT $dupSymbol2hgncID{$dupSymbol}->[0]."__".
                             $dupSymbol2hgncID{$dupSymbol}->[$j]."__".
                             $dupSymbol2firstNameCheck{$dupSymbol}->[$j]."<_>";
            }
            print RESULT "\n";
        }
        close RESULT;
    } 

    
    #  Generate 'DUPLICATENAME_default' 
    $$dicNameRef{"dupname"} = "DUPLICATENAME_default";    
    if (! -f "$DESTDIR/DUPLICATENAME_default")
    {   open (RESULT, ">$DESTDIR/DUPLICATENAME_default");
        $sth = $dbh->prepare("SELECT duplicateName, hgncID FROM duplicatename");
        $sth->execute();
        my %dupName2hgncID            = ();
        my %dupName2firstNameCheck    = ();
        
        while(@row = $sth->fetchrow_array)
        {   if (not defined $dupName2hgncID{$row[0]})
            {   $dupName2hgncID{$row[0]}->[0] = $row[1];
                # $dupName2firstNameCheck{$row[0]}->[0] = $row[2];
            }else
            {   push @{$dupName2hgncID{$row[0]}}, $row[1];
                # push @{$dupSymbol2firstNameCheck{$row[0]}}, $row[2];
            }
        }
        
        foreach my $dupName (keys %dupName2hgncID)
        {   print RESULT $dupName."\t";
            for (my $j=1; $j < scalar @{$dupName2hgncID{$dupName}}; $j++)
            {   print RESULT $dupName2hgncID{$dupName}->[0]."__".
                             $dupName2hgncID{$dupName}->[$j]."<_>";
                             # $dupName2firstNameCheck{$dupName}->[$j]."<_>";
            }
            print RESULT "\n";
        }
        close RESULT;
    }        
    
    #  Generate 'GENERIF_default' 
    $$dicNameRef{"generif"} = "GENERIF_default";    
    if (! -f "$DESTDIR/GENERIF_default")
    {   open (RESULT, ">$DESTDIR/GENERIF_default");
        $sth = $dbh->prepare("SELECT entrezGeneID, sentence FROM generif where taxID = 9606");
        $sth->execute();
        
        while(@row = $sth->fetchrow_array)
        {   print RESULT $row[0]."\t".$row[1]."\n";
        }
        close RESULT;
    }        
    
    
    #  WARNINGS -----------------------------------------------------------------------------------------------------------
    #  This section would normally take up to 100 minutes. Thus, you always better have this done by separate script given
    #  --------------------------------------------------------------------------------------------------------------------
    #  Create parts_names_dictionary_files
    #  One for begin and another for middle
	$$dicNameRef{"partbegin"} = "PARTNAMEBEGIN_default";   		#  this file for gene names in part of other gene names 
	$$dicNameRef{"partmiddle"} = "PARTNAMEMIDDLE_default";    	#  this file for gene names in part of other gene names
	if ((! -f "$DESTDIR/PARTNAMEBEGIN_default") || (! -f "$DESTDIR/PARTNAMEMIDDLE_default"))
    {   #  Start to process four character hash code now
		#  NOTE: even though the variable name has 'four' but the actual length of the code used here is 'three'
	    my %fourLetterHash		= ();
		my %fourLetterHashHUGO	= ();
		my %termByLength		= ();
		my %hugoIDByLength		= ();
		
		LogQuery("Processing unique name content for part_name finding");
		open (UNIQNAME, "$DESTDIR/UNIQUENAME_default");
		my $lineCount = 0;
		while(<UNIQNAME>)
		{   my $line = $_;
			my @tmpSplit = split (/\t/, $line);
			$lineCount++;
		    my $termHashable = special_character_handling_for_hash_key($tmpSplit[0]);
		    my $curFirstFourChr = substr($tmpSplit[0], 0, 3);
		    my $lengthOfTerm	= length ($tmpSplit[0]);
		    $curFirstFourChr = special_character_handling_for_hash_key($curFirstFourChr);   

		    if (not defined $fourLetterHash{$curFirstFourChr}->{$lengthOfTerm})
		    {	my @array1 		= ();
		    	my @array2		= ();
		    	push @array1, $termHashable;
		    	push @array2, $tmpSplit[1];
		    	$fourLetterHash{$curFirstFourChr}->{$lengthOfTerm} = \@array1;
		    	$fourLetterHashHUGO{$curFirstFourChr}->{$lengthOfTerm} = \@array2;    	
		    }else
		    {   push @{$fourLetterHash{$curFirstFourChr}->{$lengthOfTerm}}, $termHashable;
		    	push @{$fourLetterHashHUGO{$curFirstFourChr}->{$lengthOfTerm}}, $tmpSplit[1];
		    }
		    
		    if (not defined $termByLength{$lengthOfTerm})
		    {   my @array1			= ();
		    	my @array2			= ();
		    	push @array1, $termHashable;
		    	push @array2, $tmpSplit[1];
		    	
		    	$termByLength{$lengthOfTerm} = \@array1;
		    	$hugoIDByLength{$lengthOfTerm} = \@array2;    	
		    }else
		    {   push @{$termByLength{$lengthOfTerm}}, $termHashable;
		    	push @{$hugoIDByLength{$lengthOfTerm}}, $tmpSplit[1];
		    }
		}
		close UNIQNAME;

		LogQuery("Processing unique name content for part_name finding completed");
		if (! -f "$DESTDIR/PARTNAMEBEGIN_default")
		{	LogQuery("Started to create PARTNAMEBEGIN_default file. This would take a couple of minutes...");
			#  Check the overlapping for same starting position
			open (RESULTBEGIN, ">"."$DESTDIR/PARTNAMEBEGIN_default");
			my @fourLetterHashKeys = keys %fourLetterHash;
			for (my $i=0; $i <= $#fourLetterHashKeys; $i++)
			{	my @lengthKeys		= keys %{$fourLetterHash{$fourLetterHashKeys[$i]}};
				my $lengthKeyCount	= scalar @lengthKeys;
				for (my $j=0; $j < $lengthKeyCount; $j++)
				{   my @baitBaseTerms 	= @{$fourLetterHash{$fourLetterHashKeys[$i]}->{$lengthKeys[$j]}};
					my @baitHUGOIDs		= @{$fourLetterHashHUGO{$fourLetterHashKeys[$i]}->{$lengthKeys[$j]}};
							
					for (my $k=0; $k < $lengthKeyCount; $k++)
					{   if ($lengthKeys[$j] < $lengthKeys[$k])
						{	my @prayBaseTerms	= @{$fourLetterHash{$fourLetterHashKeys[$i]}->{$lengthKeys[$k]}};
							my @prayHUGOIDs		= @{$fourLetterHashHUGO{$fourLetterHashKeys[$i]}->{$lengthKeys[$k]}};
							
							for (my $bait=0; $bait <= $#baitBaseTerms; $bait++)
							{	for (my $pray=0; $pray <= $#prayBaseTerms; $pray++)
								{	if ($prayBaseTerms[$pray] =~ /^$baitBaseTerms[$bait]\b/i)
									{	print RESULTBEGIN "$baitBaseTerms[$bait]\t$baitHUGOIDs[$bait]\t$prayBaseTerms[$pray]\t$prayHUGOIDs[$pray]\t";
										if ($baitHUGOIDs[$bait] == $prayHUGOIDs[$pray])
										{   print RESULTBEGIN "SAME\n";
										}else
										{   print RESULTBEGIN "DIFF\n";
										}
									}
									
								}
							}			
						}
					}
				}
			}
			close RESULTBEGIN;
		}
		
		if (! -f "$DESTDIR/PARTNAMEMIDDLE_default")
		{	LogQuery("Started to create PARTNAMEMIDDLE_default file. This would take hours...");
			open (RESULTMIDDLE, ">"."$DESTDIR/PARTNAMEMIDDLE_default");
			my @lengthKeys = keys %termByLength;
			for (my $i=0; $i <= $#lengthKeys; $i++)
			{   my @baitBaseTerms 	= @{$termByLength{$lengthKeys[$i]}};
				my @baitHUGOIDs		= @{$hugoIDByLength{$lengthKeys[$i]}};

				for (my $j=0; $j <= $#lengthKeys; $j++)
				{	if (($i == $j) || ($lengthKeys[$i] >= $lengthKeys[$j]))
					{   next;
					}
					
					my @prayBaseTerms	= @{$termByLength{$lengthKeys[$j]}};
					my @prayHUGOIDs		= @{$hugoIDByLength{$lengthKeys[$j]}};
					
					for (my $bait=0; $bait <= $#baitBaseTerms; $bait++)
					{	for (my $pray=0; $pray <= $#prayBaseTerms; $pray++)
						{	if ($prayBaseTerms[$pray] =~ /^\S.*\b$baitBaseTerms[$bait]\b/i)
							{	print RESULTMIDDLE "$baitBaseTerms[$bait]\t$baitHUGOIDs[$bait]\t$prayBaseTerms[$pray]\t$prayHUGOIDs[$pray]\t";
								if ($baitHUGOIDs[$bait] == $prayHUGOIDs[$pray])
								{   print RESULTMIDDLE "SAME\n";
								}else
								{   print RESULTMIDDLE "DIFF\n";
								}
							}
						}
					}		
				}
			}
			close RESULTMIDDLE;
		}
    }
}













sub generate_missing_preSciMiner_document
{   my $dbh                     = shift;   
    my $WORKDIR                 = shift;
    my $pmid2docIDRef           = shift;
    my $PMIDToBeMinedArrayRef   = shift;

    my $sth                 = ''; 
    my @row                 = ();
    
    #  First create a list of missing PMIDs
    my @missingPMIDs            = ();
    foreach my $pmid (@{$PMIDToBeMinedArrayRef})
    {   if (! -f "$WORKDIR/$pmid.preSciMiner")
        {   #  If there is no preSciMiner, one should be created.
            push @missingPMIDs, $pmid;
        }
    }
    
    #  Check any missing PMID. If not, just go back to mom
    if (not defined $missingPMIDs[0])
    {   return;
    }
    
    foreach my $pmid (@missingPMIDs)
    {   open (PRESCIMINER, ">$WORKDIR/$pmid.preSciMiner");
        $sth = $dbh->prepare("SELECT senID, secAnchor, paraNum, pNum, sentence FROM sentence WHERE pmid = $pmid");
        $sth->execute();
        while(@row = $sth->fetchrow_array)
        {   if ($row[1] ne "REFERENCES")
            {   print PRESCIMINER "$row[0] $pmid $row[1] $row[2] p $row[3] $row[4]\n";
            }
        }
        close PRESCIMINER;
    }
}



















































































































































































































































































































































































































































































































sub insert_update_processed_documents_into_SciMiner_sentence
{   my $dbh                     = shift;   
    my $WORKDIR                 = shift;
    my $pmid2docIDRef           = shift;
    my $PMIDToBeMinedArrayRef   = shift;
    
    my $sentence                = "";
    my $cnt = scalar @{$PMIDToBeMinedArrayRef};
    
    my $sth                     = '';
    my @row                     = ();
    my $senID                   = '';
    my $secAnchor               = '';
    my $paraNum                 = '';
    my $pNum                    = '';
    
    foreach my $pmid (@{$PMIDToBeMinedArrayRef})
    {   if ((! -f "$WORKDIR/$pmid.preSciMiner") || (-s "$WORKDIR/$pmid.preSciMiner" == 0))
        {   next;
        }
        open (FILE, "$WORKDIR/$pmid.preSciMiner") || LogQuery("Can't open the file $WORKDIR/$pmid.preSciMiner");
        my @lineContents = <FILE>;
        close FILE;
        
        #  Replace the original preSciMiner file with senID from SciMinerDB
        open (OUTFILE, ">$WORKDIR/$pmid.preSciMiner") || LogQuery("Can't open the file $WORKDIR/$pmid.preSciMiner");
        foreach my $line (@lineContents)
        {   $line =~ s/\r|\n//g;
            if ($line =~ /^(\d+) (\w+) (\d+) p (\d+) /)
            {   $sentence   = $';       #'
                $secAnchor  = $2;
                $paraNum    = $3;
                $pNum       = $4;
                $sentence   =~ s/\"/\\\"/g;
                $dbh->do("INSERT INTO sentence (docID, pmid, secAnchor, paraNum, pNum, sentence) VALUES ($$pmid2docIDRef{$pmid}, $pmid, \"$secAnchor\", $paraNum, $pNum, \"$sentence\")");   #'
                
                #  Retrieve the senID for this sentence
                if ($secAnchor ne "REFERENCES")
                {   $sth            = $dbh->prepare("SELECT senID FROM sentence ORDER BY senID DESC LIMIT 1");
                    $sth->execute();
                    @row            = $sth->fetchrow_array;#($result);
                    $senID          = $row[0];
        
                    print OUTFILE $senID.' '.$line."\n";
                }
            }else
            {   LogQuery("$pmid sentence updating/inserting has failed");
            }
        }
        close (OUTFILE);
    }
}


sub update_document_source_processed
{   my $dbh                 = shift;
    my $pmid2docIDRef       = shift;
    my $documentSourceRef   = shift;
    my $processedStatusRef  = shift; 
    my $pmid2TitleRef       = shift;
    my $pmid2AbstractRef    = shift;
    my $pmid2langRef        = shift;
    my $pmid2journalRef		= shift;
    
    #  First handle pmids from Medline, then take care of HTML only
    foreach my $pmid (keys %{$documentSourceRef})
    {   #  There must be a corresponding record in SciMiner, otherwise this doesn't make sense at all.
        $dbh->do("UPDATE document SET source=$$documentSourceRef{$pmid}, statusProcessed=$$processedStatusRef{$pmid}, title=\"$$pmid2TitleRef{$pmid}\", abstract=\"$$pmid2AbstractRef{$pmid}\", lang=\"$$pmid2langRef{$pmid}\", journal=\"$$pmid2journalRef{$pmid}\" WHERE docID = $$pmid2docIDRef{$pmid}") || LogQuery("Failed to update document table for abstract and lang");
    }
}



