sub insert_update_newly_downloaded_documents_into_SciMiner
{   my $dbh                         = shift;
    my $pmid2docIDRef               = shift;
    my $medlineToBeFetchedRef       = shift;
    my $htmlToBeFetchedRef          = shift;
    my $tmpMedLineStatusRef         = shift;
    my $tmpMedLineSizeRef           = shift; 
    my $tmpHTMLStatusRef            = shift;
    my $tmpHTMLSizeRef              = shift;
    my $tmpPMIDLinkURLRef           = shift;
    my $tmpPMIDLinkURLUpdateRef     = shift;
    my $tmpPMIDJournalTypeRef       = shift;
    


	my %pmidsCheck          = ();
    my $medline             = 0;
    my $medlineSize         = 0;
    my $html                = 0;
    my $htmlSize            = 0;
    my $originalURL			= '';  
    
    my $sth                 = ''; 
    my @row                 = ();

    #  First handle pmids from Medline, then take care of HTML only
    foreach my $pmid (keys %{$tmpMedLineStatusRef})
    {   if (defined $$tmpMedLineStatusRef{$pmid})
        {   $medline = $$tmpMedLineStatusRef{$pmid};
        }else
        {   $medline = 0;
        }

        if (defined $$tmpMedLineSizeRef{$pmid})
        {   $medlineSize = $$tmpMedLineSizeRef{$pmid};
        }else
        {   $medlineSize = 0;
        }
        
        if (defined $$tmpHTMLStatusRef{$pmid})
        {   $html = $$tmpHTMLStatusRef{$pmid};
        }else
        {   $html = 0;
        }
        
        if (defined $$tmpHTMLSizeRef{$pmid})
        {   $htmlSize = $$tmpHTMLSizeRef{$pmid};
        }else
        {   $htmlSize = 0;
        }
        
        
        # Document updating
        if (defined $$pmid2docIDRef{$pmid})
        {   # There is pre-existing records. Thus 'Update' is required.
            if (defined $$tmpPMIDJournalTypeRef{$pmid})
            {   $dbh->do("UPDATE document SET medline=$medline, medlineSize=$medlineSize, html=$html, htmlSize=$htmlSize, journalType=\"$$tmpPMIDJournalTypeRef{$pmid}\", linkURL=\"$$tmpPMIDLinkURLUpdateRef{$pmid}\", linkURLOriginal=\"$$tmpPMIDLinkURLRef{$pmid}\" WHERE docID = $$pmid2docIDRef{$pmid}") || LogQuery("!Error in updating document for $pmid");
            }else
            {   $dbh->do("UPDATE document SET medline=$medline, medlineSize=$medlineSize, html=$html, htmlSize=$htmlSize WHERE docID = $$pmid2docIDRef{$pmid}") || LogQuery("!Error in updating document for $pmid");
            }
        }else
        {   #  This is a completely new record, requiring new docID
            if (defined $$tmpPMIDJournalTypeRef{$pmid})
            {   $dbh->do("INSERT INTO document (pmid, medline, medlineSize, html, htmlSize, journalType, linkURL, statusProcessed, statusMined, linkURLOriginal) VALUES ($pmid, $medline, $medlineSize, $html, $htmlSize, \"$$tmpPMIDJournalTypeRef{$pmid}\", \"$$tmpPMIDLinkURLUpdateRef{$pmid}\", 0, 0, \"$$tmpPMIDLinkURLRef{$pmid}\")") || LogQuery("!Error in creating new document info for $pmid");
            }else
            {   $dbh->do("INSERT INTO document (pmid, medline, medlineSize, html, htmlSize, statusProcessed, statusMined) VALUES ($pmid, $medline, $medlineSize, $html, $htmlSize, 0, 0)") || LogQuery("!Error in creating new document info for $pmid");
            }
            
            #  Retrieve the docID for this pmid
            $sth                    = $dbh->prepare("SELECT docID FROM document ORDER BY docID DESC LIMIT 1");
            $sth->execute();
            @row                    = $sth->fetchrow_array;#($result);
            $$pmid2docIDRef{$pmid}  = $row[0];
        }
    }
    
    
    #  Processed HTML     
    foreach my $pmid (keys %{$tmpHTMLStatusRef})
    {   if (defined $$tmpMedLineStatusRef{$pmid})
        {   #  This has been taken care of by above medline part
            next;
        }else
        {   #  This is where only the HTML has been fetched case
            if (defined $$pmid2docIDRef{$pmid})
            {   #  If there is preexisting record, just update HTML part
                $dbh->do("UPDATE document SET html=$$tmpHTMLStatusRef{$pmid}, htmlSize=$$tmpHTMLSizeRef{$pmid}, journalType=\"$$tmpPMIDJournalTypeRef{$pmid}\", linkURL=\"$$tmpPMIDLinkURLUpdateRef{$pmid}\", linkURLOriginal=\"$$tmpPMIDLinkURLRef{$pmid}\" WHERE docID = $$pmid2docIDRef{$pmid}");
            }else
            {   #  This is new document records that needs to be created
                $dbh->do("INSERT INTO document (pmid, medline, medlineSize, html, htmlSize, journalType, linkURL, linkURLOriginal) VALUES ($pmid, 0, 0, $$tmpHTMLStatusRef{$pmid}, $$tmpHTMLSizeRef{$pmid}, \"$$tmpPMIDJournalTypeRef{$pmid}\", \"$$tmpPMIDLinkURLUpdateRef{$pmid}\",\"$$tmpPMIDLinkURLRef{$pmid}\" )");

                #  Retrieve the docID for this pmid
                $sth                    = $dbh->prepare("SELECT docID FROM document ORDER BY docID DESC LIMIT 1");
                $sth->execute();
                @row                    = $sth->fetchrow_array;#($result);
                $$pmid2docIDRef{$pmid}  = $row[0];
            }
        }
    }
}


sub ReFetch_A_MEDLINE
{   use LWP::UserAgent;                 
    use LWP::Simple;
    
    my $pmid					= shift;
	my $url						= shift;            
    my $fileName           		= shift;
    my $reserviorOrigDir    	= shift;
    my $pmid2langRef        	= shift;
    my $pmid2journalRef			= shift;
    my $PMIDMedlineStatusRef	= shift;
    my $PMIDMedLineSizeRef		= shift;

    #  Initialize Web UserAgent
    my $ua = LWP::UserAgent->new;
    $ua->agent('Mozilla/5.0');
    $ua->timeout(60);
    push @{$ua->requests_redirectable }, 'POST';
    
    my $status				= 'fail';

	#  Try to refetch three more times
	for (my $i=0; $i < 3; $i++)
	{	sleep(10);	# wait 10 seconds between each trial
		my $req = HTTP::Request->new( GET => $url );
    	my $res = $ua->request($req);
    	
		if( $res->is_success )
		{   open (OUTFILE, ">".$fileName);
			if ($res->as_string =~ /LA  - (\S+)/)
		    {	$$pmid2langRef{$pmid}   = $1;
		    	my $remaining	= $';
		    	if ($remaining =~ /TA  - (.*)/)
				{   $$pmid2journalRef{$pmid} = $1;
				}else
				{   $$pmid2journalRef{$pmid}   = ' ';
				}
		    }

			print OUTFILE $res->content;
		    $$PMIDMedlineStatusRef{$pmid} = 1;
		    close OUTFILE;
		    $$PMIDMedLineSizeRef{$pmid} = -s $fileName;
		    `cp -f $fileName $reserviorOrigDir$pmid.medline`;
		}
		
		#  Check the file size and exit only it's bigger than 100 Byte
		if ((-s $fileName) >= 100)
		{	$status			= 'success';
			last;
		}
	}
	
	if ($status eq 'success')
	{	return(1);
	}else
	{	return(0);
	}
}



sub Fetch_MEDLINE_From_PMID_List_Backup
{   use LWP::UserAgent;                 
    use LWP::Simple;
    
    my $pmidListRef         = shift;
    my $outputDir           = shift;
    my $reserviorOrigDir    = shift;
    my $corpusRefetchOption = shift;
    my $pmid2langRef        = shift;
    my $pmid2journalRef		= shift;
    
    #  Initialize Web UserAgent
    my $ua = LWP::UserAgent->new;
    $ua->agent('Mozilla/5.0');
    $ua->timeout(60);
    push @{$ua->requests_redirectable }, 'POST';

    #  Links and directories
    my $EFETCH      = 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi?';

    #  Fetch MEDLINE records
    my @PMIDList            = @{$pmidListRef};
    my %PMIDMedlineStatus   = ();
    my %PMIDMedLineSize     = ();
    
    foreach my $pmid (@PMIDList)
    {   LogQuery("! Processing MEDLINE $pmid");
        #  check refetch option
        if ((defined $corpusRefetchOption) && ($corpusRefetchOption))
        {   #  Re-fetch the document
            my $url = $EFETCH."db=pubmed&id=$pmid&retmode=text&rettype=medline";
            my $req = HTTP::Request->new( GET => $url );
            my $res = $ua->request($req);
        	if( $res->is_success )
        	{   my $fileName = $outputDir.$pmid.'.medline';
        	    open (OUTFILE, ">".$fileName);
        	    if ($res->as_string =~ /LA  - (\S+)/)
                {	$$pmid2langRef{$pmid}   = $1;
                	my $remaining	= $';
                	if ($remaining =~ /TA  - (.*)/)
					{   $$pmid2journalRef{$pmid} = $1;
					}else
					{   $$pmid2journalRef{$pmid}   = ' ';
					}
                }

            	print OUTFILE $res->content;
                $PMIDMedlineStatus{$pmid} = 1;
                close OUTFILE;
                $PMIDMedLineSize{$pmid} = -s $fileName;
                `cp -f $fileName $reserviorOrigDir$pmid.medline`;
                
                # --------------------------------------------------------------
                my $tmpStatus	= 1;
                if ($PMIDMedLineSize{$pmid} < 100)
                {	$PMIDMedlineStatus{$pmid} = 0;
                	$tmpStatus 	= ReFetch_A_MEDLINE ($pmid, $url, $fileName, 
                					$reserviorOrigDir, $pmid2langRef,
                					$pmid2journalRef, \%PMIDMedlineStatus, \%PMIDMedLineSize );
                }
				if ($tmpStatus)
				{	$PMIDMedlineStatus{$pmid} = 1;
					# Convert the downloaded medline file to endnote format
			        convert_medline_2_endnote("$reserviorOrigDir$pmid.medline", 
			        						  "$reserviorOrigDir$pmid.enw", $pmid);
				}
        	}else
        	{   #  If the fetch was not successful for MEDLINE record
        		#  Just try it one more time.
	            my $url = $EFETCH."db=pubmed&id=$pmid&retmode=text&rettype=medline";
		        my $req = HTTP::Request->new( GET => $url );
		        my $res = $ua->request($req);
		    	if( $res->is_success )
		    	{   my $fileName = $outputDir.$pmid.'.medline';
		    	    open (OUTFILE, ">".$fileName);
		    	    if ($res->as_string =~ /LA  - (\S+)/)
		            {	$$pmid2langRef{$pmid}   = $1;
		            	my $remaining	= $';
		            	if ($remaining =~ /TA  - (.*)/)
						{   $$pmid2journalRef{$pmid} = $1;
						}else
						{   $$pmid2journalRef{$pmid}   = ' ';
						}
		            }

		        	print OUTFILE $res->content;
		            $PMIDMedlineStatus{$pmid} = 1;
		            close OUTFILE;
		            $PMIDMedLineSize{$pmid} = -s $fileName;
		            `cp -f $fileName $reserviorOrigDir$pmid.medline`;
		            
		            # ----------------------------------------------------------
		            my $tmpStatus	= 1;
		            if ($PMIDMedLineSize{$pmid} < 100)
		            {	$PMIDMedlineStatus{$pmid} = 0;
		            	$tmpStatus = ReFetch_A_MEDLINE ($pmid, $url, $fileName, 
		            					$reserviorOrigDir, $pmid2langRef,
		            					$pmid2journalRef, \%PMIDMedlineStatus, \%PMIDMedLineSize );
		            }
					if ($tmpStatus)
					{	$PMIDMedlineStatus{$pmid} = 1;
						# Convert the downloaded medline file to endnote format
					    convert_medline_2_endnote("$reserviorOrigDir$pmid.medline", 
					    						  "$reserviorOrigDir$pmid.enw", $pmid);
					}
		    	}else
		    	{   $PMIDMedlineStatus{$pmid}   = 0;
		    	    #$PMIDMedLineSize{$pmid}     = 0;
		        }
            }
        }else
        {   if (-f $reserviorOrigDir.$pmid.'.medline')
            {   `cp -f $reserviorOrigDir$pmid.medline $outputDir$pmid.medline`;
                $PMIDMedlineStatus{$pmid} = 1;
                $PMIDMedLineSize{$pmid} = -s $outputDir.$pmid.'.medline';
                # Read the medline content for language
                open (MEDLINE, $outputDir.$pmid.'.medline');
                while(<MEDLINE>)
                {   if ($_ =~ /^LA  - (\S+)/)
                    {   $$pmid2langRef{$pmid}   = $1;
                    }
                    if ($_ =~ /^TA  - (\S.*)/)
		            {   $$pmid2journalRef{$pmid}   = $1;
		            	last;
		            }
                }
                close MEDLINE;
                
                if (! -f $reserviorOrigDir.$pmid.'.enw')
                {	# Convert the downloaded medline file to endnote format
		            convert_medline_2_endnote("$reserviorOrigDir$pmid.medline", 
		            						  "$reserviorOrigDir$pmid.enw", $pmid);
                }
                next;
            }else
            {   #  If there is no pre-existing file, then just fetch a new one
                my $url = $EFETCH."db=pubmed&id=$pmid&retmode=text&rettype=medline";
                my $req = HTTP::Request->new( GET => $url );
                my $res = $ua->request($req);
                
            	if( $res->is_success )
            	{   my $fileName = $outputDir.$pmid.'.medline';
            	    open (OUTFILE, ">".$fileName);
            	    
                    if ($res->as_string =~ /LA  - (\S+)/)
                    {	$$pmid2langRef{$pmid}   = $1;
                    	my $remaining	= $';
                    	if ($remaining =~ /TA  - (.*)/)
						{   $$pmid2journalRef{$pmid} = $1;
						}else
						{   $$pmid2journalRef{$pmid}   = ' ';
						}
                    }

            	    print OUTFILE $res->content;
                    $PMIDMedlineStatus{$pmid} = 1;
                    close OUTFILE;
                    $PMIDMedLineSize{$pmid} = -s $fileName;
                    `cp -f $fileName $reserviorOrigDir$pmid.medline`;
                    
                    # ----------------------------------------------------------
		            my $tmpStatus	= 1;
		            if ($PMIDMedLineSize{$pmid} < 100)
		            {	$PMIDMedlineStatus{$pmid} = 0;
		            	$tmpStatus = ReFetch_A_MEDLINE ($pmid, $url, $fileName, 
		            					$reserviorOrigDir, $pmid2langRef,
		            					$pmid2journalRef, \%PMIDMedlineStatus, \%PMIDMedLineSize );
		            }
					if ($tmpStatus)
					{	$PMIDMedlineStatus{$pmid} = 1;
						# Convert the downloaded medline file to endnote format
					    convert_medline_2_endnote("$reserviorOrigDir$pmid.medline", 
					    						  "$reserviorOrigDir$pmid.enw", $pmid);
					}
            	}else
            	{   #  If the fetch was not successful, just try once again
            		my $url = $EFETCH."db=pubmed&id=$pmid&retmode=text&rettype=medline";
		            my $req = HTTP::Request->new( GET => $url );
		            my $res = $ua->request($req);
		            
		        	if( $res->is_success )
		        	{   my $fileName = $outputDir.$pmid.'.medline';
		        	    open (OUTFILE, ">".$fileName);
		        	    
		                if ($res->as_string =~ /LA  - (\S+)/)
		                {	$$pmid2langRef{$pmid}   = $1;
		                	my $remaining	= $';
		                	if ($remaining =~ /TA  - (.*)/)
							{   $$pmid2journalRef{$pmid} = $1;
							}else
							{   $$pmid2journalRef{$pmid}   = ' ';
							}
		                }

		        	    print OUTFILE $res->content;
		                $PMIDMedlineStatus{$pmid} = 1;
		                close OUTFILE;
		                $PMIDMedLineSize{$pmid} = -s $fileName;
		                `cp -f $fileName $reserviorOrigDir$pmid.medline`;
		                
		                # --------------------------------------------------------------
				        my $tmpStatus	= 1;
				        if ($PMIDMedLineSize{$pmid} < 100)
				        {	$PMIDMedlineStatus{$pmid} = 0;
				        	$tmpStatus = ReFetch_A_MEDLINE ($pmid, $url, $fileName, 
				        					$reserviorOrigDir, $pmid2langRef,
				        					$pmid2journalRef, \%PMIDMedlineStatus, \%PMIDMedLineSize );
				        }
						if ($tmpStatus)
						{	$PMIDMedlineStatus{$pmid} = 1;
							# Convert the downloaded medline file to endnote format
							convert_medline_2_endnote("$reserviorOrigDir$pmid.medline", 
													  "$reserviorOrigDir$pmid.enw", $pmid);
						}
		        	}else
		        	{   $PMIDMedlineStatus{$pmid}   = 0;
		        	    #$PMIDMedLineSize{$pmid}    = 0;
		            }
                }
            }
        }
    }
    return (\%PMIDMedlineStatus, \%PMIDMedLineSize);
}


#  Fetch_MEDLINE_From_PMID_List
#  The way of fetching MEDLINE document has been changed to
#  bulk-download mode instead of individual documents
sub Fetch_MEDLINE_From_PMID_List
{   use LWP::UserAgent;                 
    use LWP::Simple;
    
    my $pmidListRef         = shift;
    my $outputDir           = shift;
    my $reserviorOrigDir    = shift;
    my $corpusRefetchOption = shift;
    my $pmid2langRef        = shift;
    my $pmid2journalRef		= shift;
    my $fileCopyRequired	= shift;
    my $annoENVRef			= shift;
    
    #  Initialize Web UserAgent
    my $ua = LWP::UserAgent->new;
    $ua->agent('Mozilla/5.0');
    $ua->timeout(60);
    
    if ((defined $$annoENVRef{HTTPProxyServer}) && ($$annoENVRef{HTTPProxyServer} ne ""))
    {	$ua->proxy('http', $$annoENVRef{HTTPProxyServer});
    }
    
    push @{$ua->requests_redirectable }, 'POST';

    #  Links and directories
    my $EFETCH      = 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi?';

    # ---- NCBI API Key Support (added 2026-03) ----
    # NCBI E-utilities rate limits: 3 req/sec without API key, 10 req/sec with key.
    # Set NCBI_API_KEY environment variable for higher throughput.
    my $api_key_param = '';
    if (defined $ENV{NCBI_API_KEY} && $ENV{NCBI_API_KEY} ne '')
    {   $api_key_param = "&api_key=$ENV{NCBI_API_KEY}";
    }
    # Rate limiting: delay between batch requests to stay within NCBI limits
    my $rate_limit_delay = ($api_key_param ne '') ? 0.15 : 0.4;  # seconds
    # ---- End NCBI API Key Support ----

    #  Fetch MEDLINE records
    my @PMIDList            = @{$pmidListRef};
    my %PMIDMedlineStatus   = ();
    my %PMIDMedLineSize     = ();


	#  Check the current PMID status and determine which PMIDs to be retrieved
	#  Retrieval is performed twice in case there is any missed PMID
	my @PMIDToBeFetched			= ();
	my @PMIDToBeProcessedFile	= ();
#	if ($outputDir =~ /GRIFQuery/)
#	{	LogGRIFQuery("! Checking medline files in the reservior directory...");
#	}else
#	{	LogQuery("! Checking medline files in the reservior directory...");
#	}
	
	foreach my $pmid (@PMIDList)
	{	if (-f $reserviorOrigDir.$pmid.'.medline')
		{	#  This PMID does not need to be processed.
			#  Check whether EndNote file exits and process it from here
			#  But it is unlikely that there is any medline without .enw file
			#  However, these files are definitely to be copied to the temporary folder
			push @PMIDToBeProcessedFile, $pmid;
		}else
		{	push @PMIDToBeFetched, $pmid;
			#  LogQuery("There is no $pmid in the reservior.");
		}
	}
	
	my $documentsPerRetrieval	= 200;
	my $totalPMIDToBeFetched	= scalar @PMIDToBeFetched;
	my @errorneousPMIDs			= ();
	
	for (my $i=0; $i < $totalPMIDToBeFetched; $i += $documentsPerRetrieval)
	{	my $uppderLimit		= 0;
		if ($totalPMIDToBeFetched < ($i + $documentsPerRetrieval))
		{	$uppderLimit	= $totalPMIDToBeFetched;
		}else
		{	$uppderLimit	= $i + $documentsPerRetrieval;
		}
		
		my @PMIDSet			= ();
		for (my $j=$i; $j < $uppderLimit; $j++)
		{	push @PMIDSet, $PMIDToBeFetched[$j];
		}
		my $idString		= join (",", @PMIDSet);

		# ---- Rate limiting between batch requests (added 2026-03) ----
		if ($i > 0)
		{   select(undef, undef, undef, $rate_limit_delay);  # sleep fractional seconds
		}

		#  Try to fetch MEDLINE (API key appended if available, added 2026-03)
		my $url = $EFETCH."db=pubmed&retmode=text&rettype=medline&id=$idString".$api_key_param;
        my $req = HTTP::Request->new( GET => $url );
        my $res = $ua->request($req);

        # ---- Improved error handling (added 2026-03) ----
        # Check HTTP status and retry once on transient failures
        if (!$res->is_success && ($res->code == 429 || $res->code >= 500))
        {   # Rate limited or server error - wait and retry once
            select(undef, undef, undef, 2.0);  # wait 2 seconds before retry
            $res = $ua->request($req);
        }

    	if( $res->is_success )
    	{   #  Split the retrieved into different PMIDs
    		my @blocks		= split (/\n\n/, $res->content);
    		my $fileName	= '';
    		
    		for (my $p=0; $p <= $#blocks; $p++)
    		{	#  Check if there is any errorneous PMID
    			my $tmpPMID	= 0;
    			
    			if ($blocks[$p] =~ /id: (\d+) Error/)
    			{	my @lines	= split (/\n/, $blocks[$p]);
    				for (my $l=0; $l <= $#lines; $l++)
    				{	if ($lines[$l] =~ /id: (\d+) Error/)
    					{	push @errorneousPMIDs, $1;
    					}elsif ($lines[$l] =~ /^PMID- (\d+)/)
    					{	$tmpPMID		= $1;
    						$fileName 		= $outputDir.$tmpPMID.'.medline';
							open (OUTFILE, ">".$fileName);
							print OUTFILE $lines[$l]."\n";
    					}else
    					{	print OUTFILE $lines[$l]."\n";
    					}
    				}	
    				close OUTFILE;
    			}elsif ($blocks[$p] =~ /^PMID- (\d+)/)
    			{	#  This block contains one PMID content
    				$tmpPMID		= $1;
					$fileName 		= $outputDir.$tmpPMID.'.medline';
					open (OUTFILE, ">".$fileName);
					print OUTFILE $blocks[$p]."\n";
    				close OUTFILE;
    			}
    			
    			
    			if ($tmpPMID)
    			{	#  Check for LA and TA information
    				if ($blocks[$p] =~ /LA  - (\S+)\n/)
					{	$$pmid2langRef{$tmpPMID}   = $1;
						my $remaining	= $';
						if ($remaining =~ /TA  - (.*)\n/)
						{   $$pmid2journalRef{$tmpPMID} = $1;
						}else
						{   $$pmid2journalRef{$tmpPMID}   = ' ';
						}
					}
    			
    				#  Assign pmid status and size
    				$PMIDMedlineStatus{$tmpPMID} 	= 1;
				    $PMIDMedLineSize{$tmpPMID} 		= -s $fileName;
				    `cp -f $fileName $reserviorOrigDir$tmpPMID.medline`;
    				
    				#  Try to convert to EndNote file
    				if ($PMIDMedLineSize{$tmpPMID} >= 100)
    				{	# Convert the downloaded medline file to endnote format
		        		convert_medline_2_endnote(	"$reserviorOrigDir$tmpPMID.medline", 
		        						  			"$reserviorOrigDir$tmpPMID.enw", $tmpPMID);
    				}
    			}
    		}
    	}else
    	{   #  Try to refetch (with rate limiting delay, updated 2026-03)
    	    select(undef, undef, undef, 1.0);  # wait 1 second before retry
    		my $req2 = HTTP::Request->new( GET => $url );
		    my $res2 = $ua->request($req2);
			if( $res2->is_success )
			{   #  Split the retrieved into different PMIDs
				my @blocks		= split (/\n\n/, $res2->content);
				my $fileName	= '';
				
				for (my $p=0; $p <= $#blocks; $p++)
				{	#  Check if there is any errorneous PMID
					my $tmpPMID	= 0;
					
					if ($blocks[$p] =~ /id: (\d+) Error/)
					{	my @lines	= split (/\n/, $blocks[$p]);
						for (my $l=0; $l <= $#lines; $l++)
						{	if ($lines[$l] =~ /id: (\d+) Error/)
							{	push @errorneousPMIDs, $1;
							}elsif ($lines[$l] =~ /^PMID- (\d+)/)
							{	$tmpPMID		= $1;
								$fileName 		= $outputDir.$tmpPMID.'.medline';
								open (OUTFILE, ">".$fileName);
								print OUTFILE $lines[$l]."\n";
							}else
							{	print OUTFILE $lines[$l]."\n";
							}
						}	
						close OUTFILE;
					}elsif ($blocks[$p] =~ /^PMID- (\d+)/)
					{	#  This block contains one PMID content
						$tmpPMID		= $1;
						$fileName 		= $outputDir.$tmpPMID.'.medline';
						open (OUTFILE, ">".$fileName);
						print OUTFILE $blocks[$p]."\n";
						close OUTFILE;
					}
					
					if ($tmpPMID)
					{	#  Check for LA and TA information
						if ($blocks[$p] =~ /LA  - (\S+)\n/)
						{	$$pmid2langRef{$tmpPMID}   = $1;
							my $remaining	= $';
							if ($remaining =~ /TA  - (.*)\n/)
							{   $$pmid2journalRef{$tmpPMID} = $1;
							}else
							{   $$pmid2journalRef{$tmpPMID}   = ' ';
							}
						}
					
						#  Assign pmid status and size
						$PMIDMedlineStatus{$tmpPMID} 	= 1;
						$PMIDMedLineSize{$tmpPMID} 		= -s $fileName;
						`cp -f $fileName $reserviorOrigDir$tmpPMID.medline`;
						
						#  Try to convert to EndNote file
						if ($PMIDMedLineSize{$tmpPMID} >= 100)
						{	# Convert the downloaded medline file to endnote format
				    		convert_medline_2_endnote(	"$reserviorOrigDir$tmpPMID.medline", 
				    						  			"$reserviorOrigDir$tmpPMID.enw", $tmpPMID);
						}
					}
				}
			}else
			{	push @errorneousPMIDs, @PMIDSet;
			}
        }
	}
	
	#  If there are any errorneous PMIDs
	if (defined $errorneousPMIDs[0])
	{	foreach my $errPMID (@errorneousPMIDs)
		{	$PMIDMedlineStatus{$errPMID}	= 0;
			$PMIDMedLineSize{$errPMID}		= 0;
			LogQuery("!Error PMID MEDLINE : $errPMID");
		}
	}
	
	#  Now process @PMIDToBeProcessedFile
	foreach my $pmid (@PMIDToBeProcessedFile)
	{	if (-f $reserviorOrigDir.$pmid.'.medline')
        {   if ($fileCopyRequired)
        	{	`cp -f $reserviorOrigDir$pmid.medline $outputDir$pmid.medline`;
        	}
            $PMIDMedlineStatus{$pmid} = 1;
            $PMIDMedLineSize{$pmid} = -s $reserviorOrigDir.$pmid.'.medline';
            
            # Read the medline content for language
            open (MEDLINE, $reserviorOrigDir.$pmid.'.medline');
            while(<MEDLINE>)
            {   if ($_ =~ /^LA  - (\S+)/)
                {   $$pmid2langRef{$pmid}   = $1;
                }
                if ($_ =~ /^TA  - (\S.*)/)
	            {   $$pmid2journalRef{$pmid}   = $1;
	            	last;
	            }
            }
            close MEDLINE;
            
            if (! -f $reserviorOrigDir.$pmid.'.enw')
            {	# Convert the downloaded medline file to endnote format
	            convert_medline_2_endnote("$reserviorOrigDir$pmid.medline", 
	            						  "$reserviorOrigDir$pmid.enw", $pmid);
            }
        }
	}
    return (\%PMIDMedlineStatus, \%PMIDMedLineSize);
}




sub Fetch_HTML_From_PMID_List
{
    my $pmidListRef         = shift;
    my $outputDir           = shift;
    my $reserviorOrigDir    = shift;
    my $corpusRefetchOption = shift;
    my $pmid2langRef        = shift;
    my $tmpMedLineStatusRef	= shift;
    my $annoENVRef			= shift;
    
    #  Fetch HTML records
    my @PMIDList            = @{$pmidListRef};
    my %PMIDHTMLStatus      = ();
    my %PMIDHTMLSize        = ();
    my %PMIDJournalType     = ();
    my %PMIDLinkURL         = ();
    my %PMIDLinkURLUpdate   = ();

    foreach my $pmid (@PMIDList)
    {   if (((defined $$pmid2langRef{$pmid}) && ($$pmid2langRef{$pmid} ne 'eng')) ||
    		((defined $$tmpMedLineStatusRef{$pmid}) && ($$tmpMedLineStatusRef{$pmid} eq '0'))	)
        {   # No need to download html for this document.
            # LogQuery("!! HTML for $pmid is being skipped because of language $$pmid2langRef{$pmid}!\n");
            next;
        }

        if ((defined $corpusRefetchOption) && ($corpusRefetchOption))
        {   ($PMIDHTMLStatus{$pmid}, $PMIDHTMLSize{$pmid}, $PMIDLinkURL{$pmid}, $PMIDLinkURLUpdate{$pmid}, $PMIDJournalType{$pmid}) = Fetch_HTML_From_SINGLE_PMID ($pmid, $outputDir, $annoENVRef);
            if ($PMIDHTMLStatus{$pmid} == 1)
            {   #  Copy it to the reservior directory
                `cp -f $outputDir$pmid.html $reserviorOrigDir$pmid.html`;
            }
        }else
        {   if (-f $reserviorOrigDir.$pmid.".html")
            {   #LogQuery("!!! checking $reserviorOrigDir$pmid.html exists");
                #  If there is the HTML in the reservior directory, just copy that
                `cp -f $reserviorOrigDir$pmid.html $outputDir$pmid.html`;
                $PMIDHTMLStatus{$pmid}  = 1;
                $PMIDHTMLSize{$pmid}    = -s "$outputDir$pmid.html";
                ($PMIDLinkURL{$pmid}, $PMIDLinkURLUpdate{$pmid}, $PMIDJournalType{$pmid}) = read_sciminer_html_header($reserviorOrigDir.$pmid.".html", $pmid);
            }else
            {   #LogQuery("!!! There is no html file for $pmid in the original directory $reserviorOrigDir$pmid.html");
                ($PMIDHTMLStatus{$pmid}, $PMIDHTMLSize{$pmid}, $PMIDLinkURL{$pmid}, $PMIDLinkURLUpdate{$pmid}, $PMIDJournalType{$pmid}) = Fetch_HTML_From_SINGLE_PMID ($pmid, $outputDir,$annoENVRef);
                if ($PMIDHTMLStatus{$pmid} == 1)
                {   #  Copy it to the reservior directory
                    `cp -f $outputDir$pmid.html $reserviorOrigDir$pmid.html`;
                }
            }
        }
        #LogQuery("!!! fetched document $pmid status is $PMIDHTMLStatus{$pmid}");
    }
    return (\%PMIDHTMLStatus, \%PMIDHTMLSize, \%PMIDLinkURL, \%PMIDLinkURLUpdate, \%PMIDJournalType );
}


sub read_sciminer_html_header
{   my $htmlFile    = shift;
	my $pmid		= shift;
	
	my $elinkURL	= 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils/elink.fcgi?dbfrom=pubmed&cmd=prlinks&id='.$pmid;
    
    if (-f $htmlFile)
    {   open (FILE, $htmlFile) || return ($elinkURL, $elinkURL, "");
        my $firstLine   = <FILE>;
        $firstLine      =~ s/\r|\n//g;
        close FILE;
        if ((not defined $firstLine) || ($firstLine eq ""))
        {   return ($elinkURL, $elinkURL, file_determine_document_format($htmlFile));
        }
        
        my @tmpSplit = split (/\t/, $firstLine);
        if ($tmpSplit[0] =~ /^#SciMiner/)
        {   if (defined $tmpSplit[3])
        	{	return ($tmpSplit[3], $tmpSplit[2], $tmpSplit[1]); 
        	}elsif (defined $tmpSplit[2])
        	{	return ($elinkURL, $tmpSplit[2], $tmpSplit[1]); 
        	}elsif (defined $tmpSplit[1])
        	{	return ($elinkURL, $elinkURL, $tmpSplit[1]); 
        	}else
        	{	return ($elinkURL, $elinkURL, ""); 
        	}
        }else
        {   return ($elinkURL, $elinkURL, file_determine_document_format($htmlFile));
        }
    }else
    {   return($elinkURL, $elinkURL,"");
    }
}


sub Fetch_HTML_From_SINGLE_PMID
{   use LWP::UserAgent;                 
    use LWP::Simple;
    
    
    my $pmid        = shift;
    my $outputDir   = shift;
	my $annoENVRef	= shift;

	LogQuery("! Processing HTML $pmid");
    #  Initialize Web UserAgent
    my $ua = LWP::UserAgent->new;
    $ua->agent('Mozilla/5.0');
    $ua->timeout(60);
    
    if ((defined $$annoENVRef{HTTPProxyServer}) && ($$annoENVRef{HTTPProxyServer} ne ""))
    {	$ua->proxy('http', $$annoENVRef{HTTPProxyServer});
    }
    
    my $cookieFile  = "/tmp/.cookie.txt";
    `rm -f $cookieFile`;
    $ua->cookie_jar({ file => $cookieFile, autosave => 1});
    push @{ $ua->requests_redirectable }, 'POST';

    #  Links and directories
    my $EFETCH      = 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi?';
    my $ELINK       = 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils/elink.fcgi?';
		
    #  Fetch HTML records
    my $PMIDHTMLStatus      = 0;
    my $PMIDHTMLSize        = 0;
    
    #  Initialize the web connection
    my $url = $ELINK."dbfrom=pubmed&id=$pmid&cmd=llinks";
    #my $url = $ELINK."dbfrom=pubmed&id=$pmid&retmode=ref&cmd=prlinks";
    my $req = HTTP::Request->new( GET => $url );
    my $res = $ua->simple_request($req);

    #  Check retrieved contenct for URL
    my $PMCLink         = '';
    my $PrimaryLink     = '';
    my $articleType     = '';
    my $articleURL      = $res->header("Location");

    if ($res->is_success)
    {   #  Get the PMC link
        my $content	= $res->content;
        $content	=~ s/\r|\n//g;
        $content	=~ s/&amp;/&/g;
    
        if ($content =~ /(http:\/\/www.pubmedcentral\.nih\.gov\/articlerender\.fcgi\?\S+)<\/Url>/)
        {   $PMCLink    = $1;
        }else
        {   #  Get the primary link
		    while()
		    {   if ($content =~ /<ObjUrl>(.*?)<\/ObjUrl>/)
		    	{   $content = $';
		    		my $localString	= $1;

		    		if ($localString =~ /<Url>(http:\/\/\S+)<\/Url>.*?<SubjectType>(.*?)<\/SubjectType>.*?<NameAbbr>(.*?)<\/NameAbbr>/)
		    		{	my $tmpURL	    = $1;
		    			my $tmpType	    = $2;
		    			my $nameAbbr    = $3;
		    			
			    		if (($tmpType =~ /publishers/i) || ($tmpType =~ /providers/i))
		    			{	# Only care the first publisher/provider type URL
		    				if ($PrimaryLink eq "")
		    				{   $PrimaryLink	= $tmpURL;
		    				}else
		    				{   #  Replace the current PrimaryLink when 'HighWire' is available
		    				    if ($nameAbbr eq 'HighWire')
		    				    {   $PrimaryLink    = $tmpURL;
		    				    }
		    				}
		    			}   
		    		}else
		    		{   #  Wrong format. Ignore
		    		}
		    	}else
		    	{   last;
		    	}
		    }
        }
    }else
    {   #  There was an error in retrieving link information
        LogQuery("! ERROR! in retrieving PMID document $pmid");
        return (5, $PMIDHTMLSize, $articleURL, "", "FAILED");
    }
    

    #  PMC is always in html format.
    if ($PMCLink eq "")
    {   if ($PrimaryLink eq "")
        {   #  If there is no link available, then use elink_primary
        	my $urlPrimary 	= $ELINK."dbfrom=pubmed&id=$pmid&cmd=prlinks";
        	my $reqPrimary	= HTTP::Request->new( GET => $urlPrimary);
			$res			= $ua->simple_request($reqPrimary);
			
			#  Get the URL for article if specified by PubMed
			$PrimaryLink          = $res->header("Location");

            #  Check if the link is PDF only file
			if ($PrimaryLink =~ /\.pdf\b/i)
			{   $PMIDHTMLStatus     = 2;
				return ($PMIDHTMLStatus, $PMIDHTMLSize, $PrimaryLink, $PrimaryLink, "PDFONLY");
			}

			#  Check errorneous link         
			if (not defined $PrimaryLink)
			{   $PMIDHTMLStatus     = 3;
				return ($PMIDHTMLStatus, $PMIDHTMLSize);
			}elsif ($PrimaryLink =~ /linkinghub.elsevier.com/i)
			{   $articleType = 'elsevier';
			}
        }else
        {   #  PMC is empty but Primary is defined
            #  Check if the link is PDF only file
            if ($PrimaryLink =~ /\.pdf\b/i)
            {   $PMIDHTMLStatus     = 2;
                return ($PMIDHTMLStatus, $PMIDHTMLSize, $PrimaryLink, $PrimaryLink, "PDFONLY");
            }
            
            #  Check elsevier
            if ($PrimaryLink =~ /linkinghub.elsevier.com/i)
            {   $articleType = 'elsevier';
            }
        }
    }else
    {	$articleType = 'pubmedcentral';
    }
    

    # ----------------------------------------------------------
    #  docID2html code
    # ----------------------------------------------------------
    #   1   :   success
    #   2   :   pdf (skipped)
    #   3   :   no link was found
    #   4   :   there is link but failed to fetch
    #   5   :   there was an error in checking the link
    #   6   :   max reached. try later
    #   0   :   not tried yet
    #
    #   Thus, code 4,5, and 0 should be regularily re-tried
    
    #  ----------------------------------------------------------
    #  Start to retrieve the actual HTML
    #  ----------------------------------------------------------
    # NOTE: For now, failed PMCLink is not checked against primary link
    # NOTE: But, this might be proper way to enforce our html sets
	
	
	if ($PMCLink ne "")
    {   $articleURL = $PMCLink;
    }else
    {   $articleURL = $PrimaryLink;        
    }
    
    $req = HTTP::Request->new( GET => $articleURL );
    $res = $ua->request($req);
    if( $res->is_success )
    {   my $currentURL = $res->request->url;
        
        #  Check for any PDF only document
        if ($res->as_string =~ /<a HREF=\"([\w\d\/\.]+)\" onClick=\"cancelLoadPDF\(\)\">Begin manual download<\/a>/msgi)
        {   # This is a page linking to a PDF document
            $PMIDHTMLStatus     = 2;
            return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, "PDFONLY" );
        }elsif (($res->as_string =~ /citation\_pdf\_url.*(http\:\/\/.*\.pdf)/i) && ($res->as_string !~ /citation_fulltext_html_url.*(http\:\/\/.*\")/i))
        {   $PMIDHTMLStatus     = 2;
            return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, "PDFONLY" );
        }
        
        
        # Further retrieve if there is a full text html available
        # Nature articles
        if ($currentURL =~ /http:\/\/www\.nature\.com\//)
        {   $articleType        = 'nature';
            ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL) = retrieve_full_html_from_abs_url ($articleURL, $currentURL, $articleType, $outputDir, $pmid, $res, $ua);
            return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, $articleType);                                       
        }
        
        # blackwell-synergy articles
        elsif ($currentURL =~ /blackwell-synergy\.com\//)
        {   $articleType        = 'bwsynergy';
            ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL) = retrieve_full_html_from_abs_url ($articleURL, $currentURL, $articleType, $outputDir, $pmid, $res, $ua);
            return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, $articleType);      
        }
        
        # springerlink articles
        elsif ($currentURL =~ /http:\/\/www\.springerlink\.com\//)
        {   $articleType        = 'springer';
            ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL) = retrieve_full_html_from_abs_url ($articleURL, $currentURL, $articleType, $outputDir, $pmid, $res, $ua);
            return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, $articleType);      
        }
        
        # ovid gateway
        elsif (($res->as_string =~ /<a href="http:\/\/gateway.ovid.com">Ovid Gateway<\/a>/) && ($res->as_string =~ /Select your preferred full/))
        {   $articleType        = 'ovid';
            
            #  Generate a new URL for ovid document through ovid.gateway
            my $ovidFullTextURL	= generate_new_html_URL_for_ovid_document ($currentURL);
            # LogQuery("Ovid\t$ovidFullTextURL\n");
            #  Try to retrieve 
            if ($ovidFullTextURL ne "")
            {   # Try to retrieve the full text html
                ($PMIDHTMLStatus, $PMIDHTMLSize)    =   auto_secondary_html_retrive($ovidFullTextURL, $articleType, $outputDir.$pmid.'.html', $ua, $articleURL);
                if ($PMIDHTMLStatus == 1)
                {   return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $ovidFullTextURL, $articleType);
                }else
                {   # No proper ovid type was retrieved, then use the current html content
                    ($PMIDHTMLStatus, $PMIDHTMLSize) = auto_save_current_html_file($res, $outputDir.$pmid.'.html', $articleType, $currentURL, $articleURL);
                    return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, $articleType);
                }                            
            }else
            {   # No proper ovid type was retrieved, then use the current html content
                ($PMIDHTMLStatus, $PMIDHTMLSize) = auto_save_current_html_file($res, $outputDir.$pmid.'.html', $articleType, $currentURL, $articleURL);
                return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, $articleType);
            }
        }
        
        # informaworld.com
        elsif ($currentURL =~ /http:\/\/www\.informaworld\.com\/smpp\/content?/) 
        {   $articleType            = 'informa';
            
            #  This one needs tripple jumping to find refreshed content
            my $baseURL             = "http://www.informaworld.com/smpp/";
            my $informaFullTextURL  = $baseURL;
            if ($res->as_string =~ /<a href="\.\/(.*?)" .*title="View Article \(HTML\)">/)
            {   $informaFullTextURL    .= $1;
                # Try to retrieve the full text html
                ($PMIDHTMLStatus, $PMIDHTMLSize)    =   auto_tertiary_html_retrive($informaFullTextURL, $articleType, $baseURL, $outputDir.$pmid.'.html', $ua, $articleURL);
                if ($PMIDHTMLStatus == 1)
                {   return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $informaFullTextURL, $articleType);
                }else
                {   # No proper informa full type was retrieved, then use the current html content
                    ($PMIDHTMLStatus, $PMIDHTMLSize) = auto_save_current_html_file($res, $outputDir.$pmid.'.html', $articleType, $currentURL, $articleURL);
                    return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, $articleType);
                }    
            }else
            {   # No proper informa full type was retrieved, then use the current html content
                ($PMIDHTMLStatus, $PMIDHTMLSize) = auto_save_current_html_file($res, $outputDir.$pmid.'.html', $articleType, $currentURL, $articleURL);
                return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, $articleType);
            
            }
        }
        # ELSEVIER journals with selection.
        elsif ($articleType eq 'elsevier')
        {   if ($res->as_string =~ /\<a HREF\=\"(http\:\/\/www\.sciencedirect\.com\/science\?\_ob\=GatewayURL\S+)\"\>/)
            {   # This is the actual URL for the ELSEVIER Fulltext
                my $elsevierHTMLURL = $1;
                $elsevierHTMLURL =~ s/\&amp\;/\&/g;
                ($PMIDHTMLStatus, $PMIDHTMLSize)    =   auto_secondary_html_retrive($elsevierHTMLURL, $articleType, $outputDir.$pmid.'.html', $ua, $articleURL);
                if ($PMIDHTMLStatus == 1)
                {   return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $elsevierHTMLURL, $articleType);
                }else
                {   ($PMIDHTMLStatus, $PMIDHTMLSize) = auto_save_current_html_file($res, $outputDir.$pmid.'.html', $articleType, $currentURL, $articleURL);
                    return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, $articleType);
                }                            
            }else
            {   # No proper elsevier fulltext type was retrieved, then use the current html content
                ($PMIDHTMLStatus, $PMIDHTMLSize) = auto_save_current_html_file($res, $outputDir.$pmid.'.html', $articleType, $currentURL, $articleURL);
                return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, $articleType);
            }
        }
        #  All other cases
        else
        {   # Check document type first
            my $resultContent   = $res->content;
            if ($articleType ne 'pubmedcentral')
            {	$articleType        = determine_document_format(\$resultContent);
            }
            
            if ($articleType eq 'highwire')
            {   #  Just go ahead with current html content
            }
            elsif ($currentURL =~ /\/abs\//)
            {   #  Check for any '/abs/' and '/full/'
                ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL) = retrieve_full_html_from_abs_url ($articleURL, $currentURL, $articleType, $outputDir, $pmid, $res, $ua);
                return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, $articleType);      
            }

            # This page is already a fulltext HTML
            open (OUTFILE, ">".$outputDir.$pmid.'.html' );
            print OUTFILE "#SciMiner\t$articleType\t$currentURL\t$articleURL\n".$resultContent;
            close (OUTFILE);
            $PMIDHTMLStatus     = 1;
            $PMIDHTMLSize       = -s $outputDir.$pmid.'.html';
            return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL, $articleType );
        }
    }else
    {   # Repeat the retrieval was not successful. Mark the status 4 and try it later
        $PMIDHTMLStatus     = 4;
        return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $articleURL, "FAILED");
    }
    

  	LogQuery("!!! THIS SHOULD NOT BE SEEN IN THE LOG. $pmid htmlStatus $PMIDHTMLStatus");
}



sub generate_new_html_URL_for_ovid_document
{   my $articleURL		= shift;

	my @urlSplit    = split (/\?/, $articleURL);
    my @paramSplit  = split (/\&/, $urlSplit[1]);
    
    my $issn        = '';
    my $volume      = '';
    my $issue       = '';
    my $spage       = '';
    
    my $ovidAnID    = '';
    my $doi         = '';
    
    #  Check for parameters
    foreach my $param (@paramSplit)
    {   my @detailSplit     = split (/\=/, $param);
        if (lc($detailSplit[0]) eq 'issn')      {   $issn   	= $detailSplit[1];  }
        if (lc($detailSplit[0]) eq 'volume')    {   $volume   	= $detailSplit[1];  }
        if (lc($detailSplit[0]) eq 'issue')     {   $issue   	= $detailSplit[1];  }
        if (lc($detailSplit[0]) eq 'spage')     {   $spage   	= $detailSplit[1];  }
        if (lc($detailSplit[0]) eq 'pii')       {   $ovidAnID	= $detailSplit[1];  }
        if (lc($detailSplit[0]) eq 'pid')       {   $ovidAnID	= $detailSplit[1];  }
        if (lc($detailSplit[0]) eq 'id')        {   $ovidAnID	= $detailSplit[1];  }
        if (lc($detailSplit[0]) eq 'an')        {   $ovidAnID	= $detailSplit[1];  }
        if (lc($detailSplit[0]) eq 'doi')       {   $doi		= $detailSplit[1];  }
    }
	
	#  Take params and craft JumpStart URL to Ovid Gateway
	my $baseOvidURL		= "http://gateway.ovid.com/ovidweb.cgi?T=JS&MODE=ovid&NEWS=n&PAGE=fulltext&D=ovft&SEARCH=";
	my $newOvidURL		= '';

	#  If accession number specified in request, this takes precedence over others
	#  Build redirection leveraging accession number
	if (length($ovidAnID) > 0) 
	{	$newOvidURL		= $baseOvidURL.$ovidAnID.'.an.';
	}

	#  If DOI specified in request, this takes precedence over issn/vol/iss/pg
	#  Build redirection leveraging DOI
	elsif (length($doi) > 0) 
	{	$newOvidURL		= $baseOvidURL."%22".$doi."%22".'.di.';
	}
	
	#  Must be issn/volume/issue/spage situation
	#  But must have the following params to ensure article can be found in Ovid Gateway
	elsif ((length($issn) > 0) && (length($spage) > 0))
	{	$newOvidURL		= $baseOvidURL.$issn.".is.+and+"; 
	
		#  Volume param optional
		if (length($volume) > 0)
		{	$newOvidURL		.= $volume.'.vo.+and+';
		}
		
		#  issue param optional
		if (length($issue) > 0)
		{	$newOvidURL		.= $issue.'.ip.+and+';
		}
		
		#  Starting page
		$newOvidURL		.= $spage.'.pg.';
	}

	return($newOvidURL);
}

sub auto_tertiary_html_retrive
{   my $url                 = shift;
    my $articleType         = shift;
    my $baseURL             = shift;
    my $outputFileName      = shift;
    my $ua                  = shift;
    my $articleURL			= shift;
    
    my $PMIDHTMLStatus      = 0;
    my $PMIDHTMLSize        = 0;
    
    my $request = HTTP::Request->new (GET => $url);
    my $result  = $ua->simple_request ($request);
    
    if ($result->is_success)
    {   # Get the refresh link
        if ($result->as_string =~ /<meta http-equiv="refresh" .*?url=\.\/(.*?)"\s+\/>/)
        {   # here is the actual final html document
            my $finalHTMLURL    = $baseURL.$1;
            $finalHTMLURL       =~ s/&amp;/&/g;
            ($PMIDHTMLStatus, $PMIDHTMLSize)    =   auto_secondary_html_retrive($finalHTMLURL, $articleType, $outputFileName, $ua, $articleURL);
            return ($PMIDHTMLStatus, $PMIDHTMLSize);
        }else
        {   $PMIDHTMLStatus = 4;    # To be retried in next trial
            return ($PMIDHTMLStatus, $PMIDHTMLSize);
        }
    }else
    {   $PMIDHTMLStatus     = 4;    # To be retried in next trial
        return ($PMIDHTMLStatus, $PMIDHTMLSize);
    }
}




sub auto_secondary_html_retrive
{   my $url                 = shift;
    my $articleType         = shift;
    my $outputFileName      = shift;
    my $ua                  = shift;
    my $articleURL			= shift;
    
    my $PMIDHTMLStatus      = 0;
    my $PMIDHTMLSize        = 0;
    
    my $request = HTTP::Request->new (GET => $url);
    my $result  = $ua->request ($request);
    if ($result->is_success)
    {   open (OUTFILE, ">".$outputFileName );
        $result->remove_header();
        print OUTFILE "#SciMiner\t$articleType\t$url\t$articleURL\n";
        print OUTFILE $result->content;
        close (OUTFILE);
        $PMIDHTMLStatus     = 1;
        $PMIDHTMLSize       = -s $outputFileName;
        return ($PMIDHTMLStatus, $PMIDHTMLSize);
    }else
    {   $PMIDHTMLStatus     = 4;    # To be retried in next trial
        return ($PMIDHTMLStatus, $PMIDHTMLSize);
    }
}



sub auto_save_current_html_file
{   my $res             = shift;
    my $outputFileName  = shift;
    my $articleType     = shift;
