}



sub retrieve_full_html_from_abs_url
{   my $articleURL          = shift;
    my $currentURL          = shift;
    my $journalTypeName     = shift;
    my $outputDir           = shift;
    my $pmid                = shift;
    my $res                 = shift;    # from the previous running
    my $ua                  = shift;
    
    my $newFullTextURL      = $currentURL;
    
    if ($journalTypeName eq 'springer')
    {   $newFullTextURL         .= "fulltext.html";
    }else
    {   $newFullTextURL         =~ s/\/abs\//\/full\//;
    }
    

    my $PMIDHTMLStatus      = 0;
    my $PMIDHTMLSize        = 0;
    
    LogQuery("Trying to retrive full text with $currentURL\n$newFullTextURL");
    #  Check currentURL and newFullTextURL
    if ($currentURL eq $newFullTextURL)
    {   # just print out the current content since there is no full text
        open (OUTFILE, ">".$outputDir.$pmid.'.html' );
        $res->remove_header();
        print OUTFILE "#SciMiner\t$journalTypeName\t$currentURL\t$articleURL\n";
        print OUTFILE $res->content;
        close (OUTFILE);
        $PMIDHTMLStatus     = 1;
        $PMIDHTMLSize       = -s $outputDir.$pmid.'.html';
        return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL);
    }else
    {   LogQuery("At least different URL");
        if ($newFullTextURL =~ /(http:\/\/.*)/)
        {   my $fullTextURL = $1;
            $fullTextURL =~ s/\&amp\;/\&/g;
            
            LogQuery("Processing full retrieval $fullTextURL");
            my $newFullRequest  = HTTP::Request->new (GET => $fullTextURL);
            my $newResult       = $ua->request ($newFullRequest);
            if ($newResult->is_success)
            {   LogQuery("Full retrieval was successful");
                open (OUTFILE, ">".$outputDir.$pmid.'.html' );
                $newResult->remove_header();
                print OUTFILE "#SciMiner\t$journalTypeName\t$fullTextURL\t$articleURL\n";
                print OUTFILE $newResult->content;
                close (OUTFILE);
                $PMIDHTMLStatus     = 1;
                $PMIDHTMLSize       = -s $outputDir.$pmid.'.html';
                return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $fullTextURL);
            }else
            {   LogQuery("Full retrieval was NOT successful");
                
                # just print out the current content since there is no full text
                open (OUTFILE, ">".$outputDir.$pmid.'.html' );
                $res->remove_header();
                print OUTFILE "#SciMiner\t$journalTypeName\t$currentURL\t$articleURL\n";
                print OUTFILE $res->content;
                close (OUTFILE);
                $PMIDHTMLStatus     = 1;
                $PMIDHTMLSize       = -s $outputDir.$pmid.'.html';
                return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL);
            }
        }else
        {   # No new full text html is available
            # just print out the current content since there is no full text
            LogQuery("NO Full retrieval was successful");
                
            open (OUTFILE, ">".$outputDir.$pmid.'.html' );
            $res->remove_header();
            print OUTFILE "#SciMiner\t$journalTypeName\t$currentURL\t$articleURL\n";
            print OUTFILE $res->content;
            close (OUTFILE);
            $PMIDHTMLStatus     = 1;
            $PMIDHTMLSize       = -s $outputDir.$pmid.'.html';
            return ($PMIDHTMLStatus, $PMIDHTMLSize, $articleURL, $currentURL);
        }
    }
}  






sub get_file_timestamp
{   use File::stat;
    use Time::localtime;
    
    my ($file) = @_;
    if ((not defined $file) || (not -f $file))
    {   return ("");
    }
    return( ctime(stat($file)->mtime));
}







sub generate_XML_from_article_hash
{   my $pmid            = shift;
    my $articleHashRef  = shift;
    
    my %article         = %{$articleHashRef};
    my $xmlContent      = "<DOC>\n<PMID>$pmid<\/PMID>\n";
    
    foreach my $section( sort( { $article{$a}->{order} <=> $article{$b}->{order} } keys( %article) ) )
    {   my $modified = $article{$section}->{text};
        if (defined $modified)
        {   $modified =~ s/ \< / \&lt; /g;
        	$modified =~ s/ \& / \&amp\; /g;
        	$xmlContent .= "<$section>\n$modified<\/$section>\n\n";
        }
    }

    $xmlContent .= "</DOC>";
    return (\$xmlContent);
}














sub parse_html_master
{   my $hwParseCmd     	= shift;
    my $htmlFile        = shift;
    my $pmid            = shift;
    my $outputXMLFile   = shift;

    open (FILE, $htmlFile);
    
    # Why didn't remove the end line character?
    my @tmpLines        = <FILE>;
    foreach my $line (@tmpLines)
    {   $line =~ s/\r|\n//g;
    }
    
	
	
    my $htmlContent     = join(" ", @tmpLines);
    close (FILE);
    my $htmlFormat      = determine_document_format (\$htmlContent);
    
    my $parsingStatus   = 0;
    my $parsedXMLRef    = ''; 
    
    if ($htmlFormat eq 'pubmedcentral' || $htmlFormat eq 'biomedcentral')
    {   # ParsePMC_SciMiner now auto-detects JATS XML and routes internally (2026-03)
        my ($parsedStatus, $articleHash) = ParsePMC_SciMiner(\$htmlContent);
        auto_generate_xml_from_html_or_generic_parser ($pmid, $htmlFile, $parsedStatus, $articleHash, $outputXMLFile, $hwParseCmd, \$parsingStatus);

    }
    elsif ($htmlFormat eq 'nature')
    {	my ($parsedStatus, $articleHash) = Parse_Nature(\$htmlContent);
    	auto_generate_xml_from_html_or_generic_parser ($pmid, $htmlFile, $parsedStatus, $articleHash, $outputXMLFile, $hwParseCmd, \$parsingStatus);

    }
    elsif ($htmlFormat eq 'science')
    {	my ($parsedStatus, $articleHash) = Parse_Science(\$htmlContent);
    	auto_generate_xml_from_html_or_generic_parser ($pmid, $htmlFile, $parsedStatus, $articleHash, $outputXMLFile, $hwParseCmd, \$parsingStatus);
    }
    elsif ($htmlFormat eq 'bwsynergy')
    {	my ($parsedStatus, $articleHash) = Parse_Blackwell_Synergy(\$htmlContent);
    	auto_generate_xml_from_html_or_generic_parser ($pmid, $htmlFile, $parsedStatus, $articleHash, $outputXMLFile, $hwParseCmd, \$parsingStatus);
    }
    elsif ($htmlFormat eq 'ovid')
    {	my ($parsedStatus, $articleHash) = Parse_Ovid(\$htmlContent);
    	auto_generate_xml_from_html_or_generic_parser ($pmid, $htmlFile, $parsedStatus, $articleHash, $outputXMLFile, $hwParseCmd, \$parsingStatus);
    }
    elsif ($htmlFormat eq 'informa')
    {	my ($parsedStatus, $articleHash) = Parse_Informa(\$htmlContent);
    	auto_generate_xml_from_html_or_generic_parser ($pmid, $htmlFile, $parsedStatus, $articleHash, $outputXMLFile, $hwParseCmd, \$parsingStatus);
    }
    elsif ($htmlFormat eq 'springer')
    {	my ($parsedStatus, $articleHash) = Parse_Springer(\$htmlContent);
    	auto_generate_xml_from_html_or_generic_parser ($pmid, $htmlFile, $parsedStatus, $articleHash, $outputXMLFile, $hwParseCmd, \$parsingStatus);
    }
    elsif ($htmlFormat eq 'portland')
    {	my ($parsedStatus, $articleHash) = Parse_Portland(\$htmlContent);
    	auto_generate_xml_from_html_or_generic_parser ($pmid, $htmlFile, $parsedStatus, $articleHash, $outputXMLFile, $hwParseCmd, \$parsingStatus);
    }
    elsif (($htmlFormat eq 'ingenta') || ($htmlFormat eq 'liebert') || ($htmlFormat eq 'ncbi') || ($htmlFormat eq 'wiley'))
    {   return (0, $htmlFormat);
    }
    elsif ($htmlFormat eq 'elsevier')
    {   # my ($parseSDStatus, $parseSDXML) = generate_XML_from_article_hash($pmid, ParseSD(\$htmlContent));
        my ($elsevierStatus, $elsevierArticleHash) = ParseElseVier(\$htmlContent);
        if ($elsevierStatus == 1)
        {   $parsedXMLRef   = generate_XML_from_article_hash($pmid, $elsevierArticleHash);
            if (length($$parsedXMLRef) > 100)
            {   # If longer than 100, it's likely that the parsing was successful.
                $parsingStatus = 1;
                open (OUT, ">".$outputXMLFile);
                $$parsedXMLRef =~ s/<p><\/p>//g;
                $$parsedXMLRef =~ s/\&hyp\;/\'/g;
                print OUT $$parsedXMLRef;
                close OUT;
            }else
            {  
            }
        }else
        {   #  Try another parser? This is to be decided.
        }
    }else    # ($htmlFormat eq 'highwire') or 'other'
    {   #  Use the hwParse.pl script.
        
        `$hwParseCmd $htmlFile > $outputXMLFile`;
        if ((-f $outputXMLFile) && (-s $outputXMLFile > 100))   ### 
         {   $parsingStatus = 1;
        }
    }
    
    return ($parsingStatus, $htmlFormat);
}










sub parse_medline
{
    my $medlineFile         = shift;
    my $pmid                = shift;
    my $outputXMLFile       = shift;
    my $pmid2TitleRef       = shift;
    my $pmid2AbstractRef    = shift;
    
    open (FILE, $medlineFile);
    my $previousField   = '';
    my $titleString     = '';
    my $abstractString  = '';
    
    my %article         = ();
    my $setToExtract    = 0;
    while(<FILE>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        if ($line eq "")
        {   next;
        }elsif (substr($line,4,1) eq '-')
        {   $setToExtract   = 0;
        }
        
        
        if ( $line =~ /^TI  - / )
        {   $previousField  = 'TI';
            $article{$previousField} = $';  #'
            $setToExtract   = 1;
        }elsif ( $line =~ /^AB  - / )
        {   $previousField  = 'AB';
            $article{$previousField} = $';  #'
            $setToExtract   = 1;
        }elsif ($line =~ /^     /)
        {   $article{$previousField} .= $';  #'
        }
    }
    close RESULT;
    
    #  Generate XML
    my $parsedStr                   = "<DOC>\n<PMID>$pmid</PMID>\n";
    $parsedStr                      .= "<TITLE>\n<p>\n";
    if ((defined $article{TI}) && ($article{TI} ne ""))
    {   process_medline_ti_ab(\$article{TI});
        $parsedStr                  .= "$article{TI}\n</p>\n</TITLE>\n";
        $article{TI}                =~ s/\"/\\\"/g;
        $$pmid2TitleRef{$pmid}      = $article{TI};
    }else
    {   $parsedStr                  .= " \n</p>\n</TITLE>\n";
        $$pmid2TitleRef{$pmid}      = "";
    }
    $parsedStr                      .= "<ABSTRACT>\n<p>\n";
    
    if ((defined $article{AB}) && ($article{AB} ne ""))
    {   process_medline_ti_ab(\$article{AB});
        $parsedStr                  .= "$article{AB}\n</p>\n</ABSTRACT>\n";
        $article{AB}                =~ s/\"/\\\"/g;
        $$pmid2AbstractRef{$pmid}   = $article{AB};
    }else
    {   $parsedStr                  .= " \n</p>\n</ABSTRACT>\n";
        $$pmid2AbstractRef{$pmid}   = "";
    }
    $parsedStr                      .= "</DOC>\n";

    open (OUT, ">".$outputXMLFile);
#    $parsedStr =~ s/<p><\/p>//g;
#    $parsedStr =~ s/\&hyp\;/\'/g;
    print OUT $parsedStr;
    close OUT;
    
}    
    
    

sub parse_medline_with_tree_simplified
{	my $medlineFile         = shift;
    my $pmid                = shift;
    my $outputXMLFile       = shift;
    my $pmid2TitleRef       = shift;
    my $pmid2AbstractRef    = shift;
    
	my $MeSHdescID2termRef	= shift;
	my $MeSHTerm2descIDRef	= shift;
	my $MeSHTerm2DistRef	= shift;
	
	my $dbh					= shift;
	my $pmid2docIDRef		= shift;
    
    open (FILE, $medlineFile);
    my $previousField   = '';
    my $titleString     = '';
    my $abstractString  = '';
    
    my %article         = ();
    my $setToExtract    = 0;
    
    my @MeSHTermInDoc	= ();
    my $MeSHRnInDoc     = '';
    while(<FILE>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        if ($line eq "")
        {   next;
        }elsif (substr($line,4,1) eq '-')
        {   $setToExtract   = 0;
        }
        
        if (substr($line,4,1) eq '-')
        {	if ( $line =~ /^TI  - / )
		    {   $previousField  = 'TI';
		        $article{$previousField} = $';  #'
		        $setToExtract   = 1;
		    }elsif ( $line =~ /^AB  - / )
		    {   $previousField  = 'AB';
		        $article{$previousField} = $';  #'
		        $setToExtract   = 1;
		    }elsif ( $line =~ /^RN  - \*?(\S.*)/ )
		    {	$previousField  = 'RN';
				my @tmpSplit 	= split (/\(/, $1);   
				chop($tmpSplit[1]);
		        $MeSHRnInDoc .= $tmpSplit[1].'|';
		    }elsif ( $line =~ /^MH  - \*?(\S.*)/ )
		    {	$previousField  = 'MH';
				my @tmpSplit 	= split (/\//, $1);   
				push @MeSHTermInDoc, $tmpSplit[0];
		    }else
		    {	$previousField	= 'OTHER';
		    	$article{$previousField} = '';
		    }
        }else
        {	$article{$previousField} .= substr($line,5);  #'
        }
    }
    close RESULT;
    
    #  Generate XML
    my $parsedStr                   = "<DOC>\n<PMID>$pmid</PMID>\n";
    $parsedStr                      .= "<TITLE>\n<p>\n";
    if ((defined $article{TI}) && ($article{TI} ne ""))
    {   process_medline_ti_ab(\$article{TI});
        $parsedStr                  .= "$article{TI}\n</p>\n</TITLE>\n";
        $article{TI}                =~ s/\"/\\\"/g;
        $$pmid2TitleRef{$pmid}      = $article{TI};
    }else
    {   $parsedStr                  .= " \n</p>\n</TITLE>\n";
        $$pmid2TitleRef{$pmid}      = "";
    }
    $parsedStr                      .= "<ABSTRACT>\n<p>\n";
    
    if ((defined $article{AB}) && ($article{AB} ne ""))
    {   process_medline_ti_ab(\$article{AB});
        $parsedStr                  .= "$article{AB}\n</p>\n</ABSTRACT>\n";
        $article{AB}                =~ s/\"/\\\"/g;
        $$pmid2AbstractRef{$pmid}   = $article{AB};
    }else
    {   $parsedStr                  .= " \n</p>\n</ABSTRACT>\n";
        $$pmid2AbstractRef{$pmid}   = "";
    }
    $parsedStr                      .= "</DOC>\n";


    open (OUT, ">".$outputXMLFile);
#    $parsedStr =~ s/<p><\/p>//g;
#    $parsedStr =~ s/\&hyp\;/\'/g;
    print OUT $parsedStr;
    close OUT;
    
    #  Explore MeSH tree to extract implicit MeSH Terms
    my %DocMeshTreeCode2ExplicitCode= ();
    my @codeSplit					= ();
    my $tmpCode						= '';
    my $tmpDescIDString				= '';
    
    #  DocMeSHCode2ExplicitCode E == explict, I == implicit
    if (defined $MeSHTermInDoc[0])
    {   foreach my $localMeSHTerm (@MeSHTermInDoc)
    	{   if (defined $$MeSHTerm2descIDRef{$localMeSHTerm})
    		{	$tmpDescIDString .= $$MeSHTerm2descIDRef{$localMeSHTerm}.';';
    			
    			#print "!ERROR: $pmid $DBI::errstr\n" ;   
    		}
    	}
    	if( $tmpDescIDString ne "")
    	{	if (defined $$pmid2docIDRef{$pmid})
    		{	$dbh->do("INSERT INTO `docmesh` (docID, pmid, explicit, descIDString) VALUES ($$pmid2docIDRef{$pmid}, $pmid, \"E\", \"$tmpDescIDString\")") || LogQuery("!ERROR: docmesh insertion $pmid");
    		}
    	}
    }
    return(1, \$MeSHRnInDoc);
}    

	
	
	
	    
    
sub process_medline_ti_ab
{   my $stringRef   = shift;
    
    $$stringRef =~ s/ \< / \&lt; /g;
    if ($$stringRef  =~ /\</) 
    {   #  Unmatched greater than signs are handled
        $$stringRef  =~ s/([p|P] ?)\<([\.|\d|\=| |\/])/$1\&lt\;$2/g;
    	$$stringRef  =~ s/([^pP])\<(\/?[^pP])/$1\&lt\;$2/g;
    }

    if ($$stringRef  =~ /\&/)
    {   my @tmpSplit = split (/ /, $$stringRef );
        for(my $j=0; $j <= $#tmpSplit; $j++)
        {   if ($tmpSplit[$j] =~ /\;/)
            {   # This is legal one
            }else
            {   # This is stand alone one
                $tmpSplit[$j] =~ s/\&/\&amp\;/;
            }
        }
        $$stringRef = join (' ', @tmpSplit);
    }
    
    $$stringRef =~ s/<p><\/p>//g;
    $$stringRef =~ s/\&hyp\;/\'/g;
}
    





sub parse_medline_old
{   use Boulder::Medline;
    no warnings 'uninitialized';
    
    my $medlineFile     = shift;
    my $pmid            = shift;
    my $outputXMLFile   = shift;
    
    my $ml              = '';
    my $parsedStr       = "<DOC>\n<PMID>$pmid</PMID>\n";
    
    open (ML, $medlineFile);
    while( my $line = <ML> )
    { 	$line =~ s/   +/ /g;
    	$ml .= $line;
    }
    close (ML);
    
    my $s = Boulder::Medline->parse($ml);
    $parsedStr .= "<ABSTRACT>\n<p>\n";
    
    my $AbstractContent = $s->Abstract;
    $AbstractContent =~ s/ \< / \&lt; /g;

    if ($AbstractContent =~ /\</) 
    {   #  Unmatched greater than signs are handled
        $AbstractContent =~ s/([p|P] ?)\<([\.|\d|\=| |\/])/$1\&lt\;$2/g;
    	$AbstractContent =~ s/([^pP])\<(\/?[^pP])/$1\&lt\;$2/g;
    }

    if ($AbstractContent =~ /\&/)
    {   my @tmpSplit = split (/ /, $AbstractContent);
        for(my $j=0; $j <= $#tmpSplit; $j++)
        {   if ($tmpSplit[$j] =~ /\;/)
            {   # This is legal one
            }else
            {   # This is stand alone one
                $tmpSplit[$j] =~ s/\&/\&amp\;/;
            }
        }
        $AbstractContent = join (' ', @tmpSplit);
    }

    $parsedStr .= $AbstractContent;
    $parsedStr .= "\n</p>\n</ABSTRACT>\n";

    #foreach my $mh ( $s->Meshheading )
    #{
    #	$parsedStr .= "<MESH>$mh</MESH>\n";
    #}

    $parsedStr .= "</DOC>\n";

    open (OUT, ">".$outputXMLFile);
    $parsedStr =~ s/<p><\/p>//g;
    $parsedStr =~ s/\&hyp\;/\'/g;
    print OUT $parsedStr;
    close OUT;
    
    return (1);
}




sub process_medline_html_document_with_mesh_tree_simplified
{	my $FILESDIR                = shift;
    my $DESTDIR                 = shift;
    my $annoENVRef              = shift;
    my $pmid2TitleRef           = shift;
    my $pmid2AbstractRef        = shift;
    
	my $MeSHdescID2termRef		= shift;
	my $MeSHTerm2descIDRef		= shift;
	my $MeSHTerm2DistRef		= shift;
	
	my $dbh					    = shift;
	my $pmid2docIDRef		    = shift;
	my $pmid2langRef            = shift;
	my $tmpPMIDJournalTypeRef   = shift;
	
	my @files           = `ls -r $FILESDIR | grep -P "[0-9]+.medline"`;
    my $root            = '';
    my %documentSource  = ();
    my %processedStatus = ();
    my $htmlFormat      = '';
    
    my %journalNotToBeHTMLMined = ('ncbi', 1, 'liebert', 1, 'ingenta', 1, 'wiley', 1);
    
    foreach my $medlineFile (@files)
    {   $medlineFile                =~ s/\r|\n//g;
        my @tmpSplit                = split (/\.medline/, $medlineFile);
        $root                       = $tmpSplit[0];
        my $parsingStatus           = 0;
        
        if (-f "$FILESDIR/$root.html")
        {   if ((defined $$pmid2langRef{$root}) && ($$pmid2langRef{$root} ne 'eng'))
            {   # Do not parse the html. In fact, there should not be any html
            }else
            {   # Check for journnalNotToBeHTMLMined
                if ((defined $$tmpPMIDJournalTypeRef{$root}) && (defined $journalNotToBeHTMLMined{$$tmpPMIDJournalTypeRef{$root}}))
                {   # Do not try to parse this html
                    $htmlFormat = $$tmpPMIDJournalTypeRef{$root};
                }else
                {   ($parsingStatus, $htmlFormat) = parse_html_master("$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/hwParse.pl", $FILESDIR.$root.".html", $root, $DESTDIR.$root.'.xml');
                }
                
            }
        }
        
        #  New change in SciMiner v2.2
        #  Medline records are processed any way to find reliable title and abstract
        # my $medlineParsingStatus    = parse_medline				($FILESDIR.$root.".medline", $root, $DESTDIR.$root.'.medline.xml', $pmid2TitleRef, $pmid2AbstractRef);
        my ($medlineParsingStatus, $MeSHRNStringRef)    = parse_medline_with_tree_simplified	(
        	$FILESDIR.$root.".medline", $root, $DESTDIR.$root.'.medline.xml', $pmid2TitleRef, $pmid2AbstractRef, 
        	$MeSHdescID2termRef, $MeSHTerm2descIDRef, $MeSHTerm2DistRef,
        	$dbh, $pmid2docIDRef );
        
        
        #  Parser Medline Article in case of htmlParsingStatus == 0
        if ((! $parsingStatus) || (defined $journalNotToBeHTMLMined{$htmlFormat}))
        {   $documentSource{$root}  = 1;      # 1 means medline record
            $parsingStatus          = $medlineParsingStatus;
            if (-f "$DESTDIR$root.medline.xml")
            {   `mv $DESTDIR$root.medline.xml $DESTDIR$root.xml`;
            }
        }else
        {   $documentSource{$root}  = 2;      # 2 means html
        }

        #  Create prelink file for parsed content.
        if ($parsingStatus)
        {   #  Step#1: Xml Tagging by xml2parse
            `$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/xml2parse.pl $DESTDIR/$root.xml $DESTDIR/$root.tag.xml`;
            
            #  Step#2: verify we didn't shrink in size from tag.xml to xml; if so, indicate an error
    		if( ! -s "$DESTDIR/$root.tag.xml"  )
    		{   # Try to convert the Unicode to ANSI
    		    # LogQuery("Trying unicode to ascii conversion for xml2parse.pl");
    		    my $uni2asciiStatus = convert_file_unicode_to_ascii ( "$DESTDIR/$root.xml");

    		    # Try again with xml2parse.pl
    		    if ($uni2asciiStatus)
    		    {   # LogQuery("Unicode conversion was successful for $root html");
    		        `$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/xml2parse.pl $DESTDIR/$root.xml $DESTDIR/$root.tag.xml`;
    		    }
    		    
                if (! -s "$DESTDIR/$root.tag.xml"  )   		    
                {   # Simply copy the xml file to tag.xml     
    		        `cp $DESTDIR/$root.xml $DESTDIR/$root.tag.xml`;
                }else
                {   # Great we have succeeded in xml2parse
                }
    		}
    		
    		#  Step3: Split the tagged XML by sentence
    		`$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/sentence-boundary2.pl $$annoENVRef{SciMinerPath}/Scripts/Main/HONORIFICS $DESTDIR/$root.tag.xml $DESTDIR/$root.split2.xml $root`;
    		
    		#  Step4: remove bracelet characters and multiple spaces
            open (SPLITFILE2, "$DESTDIR/$root.split2.xml");
            open (SPLITFILE, ">$DESTDIR/$root.split.xml");
            while(<SPLITFILE2>)
            {   my $line = $_;  
                $line =~ s/\r|\n//g;
                #$line =~ s/\(|\)|\[|\]|\{|\}/ /g;
                $line =~ s/\s+/ /g;
                $line = xmlCleanUp($line);
                print SPLITFILE $line."\n";
            }   
            close SPLITFILE;        
            close SPLITFILE2;

            #  Step5: Create prelink file from split.xml file
            `$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/LinkPreProcess.pl $DESTDIR/$root.split.xml $DESTDIR/$root.prelink`;
            
            #  Step6: Create SciMinerDB suitable file
            `$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/preSciMinerProcess.pl $DESTDIR/$root.prelink $DESTDIR/$root.preSciMiner`;
            open (PRELINK, "$DESTDIR/$root.prelink");
            open (PRESCIMINER, ">"."$DESTDIR/$root.preSciMiner");
            my $anchor  = '';
            my $ppn     = 0;
            while(<PRELINK>)
            {   my $line = $_;
                $line =~ s/\r|\n//g;
                if ($line =~ /^\%<(\w+)>/)
                {   $anchor = $1;
                }elsif ($line =~ /^\%<p ppn=\"(\d+)\">/)
                {   $ppn    = $1;
                }elsif ($line =~ /^(\d+) (.*)/)
                {   print PRESCIMINER "$1 $anchor $ppn $2\n";
                }
            }
            
            #  Print the MeSHRN
            $ppn++;
            print PRESCIMINER "$root MESHRN 0 p 0 $$MeSHRNStringRef\n";
            close PRELINK;
            close PRESCIMINER;
            
            #  Step7: Remove temporary files
            unlink( "$DESTDIR/$root.xml");
            unlink( "$DESTDIR/$root.tag.xml");
            unlink( "$DESTDIR/$root.split.xml");
            unlink( "$DESTDIR/$root.split2.xml");
            unlink( "$DESTDIR/$root.prelink");
            unlink( "$DESTDIR/$root.medline.xml");
            $processedStatus{$root} = 1;
        }else
        {   #  Even the medline parsing was unsuccessful.
            $processedStatus{$root} = 0;
        }
    }
    return (\%documentSource, \%processedStatus);
}




sub process_medline_html_document
{   my $FILESDIR            = shift;
    my $DESTDIR             = shift;
    my $annoENVRef          = shift;
    my $pmid2TitleRef       = shift;
    my $pmid2AbstractRef    = shift;
    
    my @files           = `ls -r $FILESDIR | grep -P "[0-9]+.medline"`;
    my $root            = '';
    my %documentSource  = ();
    my %processedStatus = ();
    foreach my $medlineFile (@files)
    {   $medlineFile                =~ s/\r|\n//g;
        my @tmpSplit                = split (/\.medline/, $medlineFile);
        $root                       = $tmpSplit[0];
        my $parsingStatus           = 0;
        
        if (-f "$FILESDIR/$root.html")
        {   $parsingStatus = parse_html_master("$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/hwParse.pl", $FILESDIR.$root.".html", $root, $DESTDIR.$root.'.xml');
        }
        
        
        #  New change in SciMiner v2.2
        #  Medline records are processed any way to find reliable title and abstract
        my $medlineParsingStatus    = parse_medline($FILESDIR.$root.".medline", $root, $DESTDIR.$root.'.medline.xml', $pmid2TitleRef, $pmid2AbstractRef);
                
        #  Parser Medline Article in case of htmlParsingStatus == 0
        if (! $parsingStatus)
        {   $documentSource{$root}  = 1;      # 1 means medline record
            $parsingStatus          = $medlineParsingStatus;
            if (-f "$DESTDIR$root.medline.xml")
            {   `mv $DESTDIR$root.medline.xml $DESTDIR$root.xml`;
            }
        }else
        {   $documentSource{$root}  = 2;      # 2 means html
        }

        #  Create prelink file for parsed content.
        if ($parsingStatus)
        {   #  Step#1: Xml Tagging by xml2parse
            `$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/xml2parse.pl $DESTDIR/$root.xml $DESTDIR/$root.tag.xml`;
            
            #  Step#2: verify we didn't shrink in size from tag.xml to xml; if so, indicate an error
    		if( ! -s "$DESTDIR/$root.tag.xml"  )
    		{   `cp $DESTDIR/$root.xml $DESTDIR/$root.tag.xml`;
    		}
    		
    		#  Step3: Split the tagged XML by sentence
    		`$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/sentence-boundary2.pl $$annoENVRef{SciMinerPath}/Scripts/Main/HONORIFICS $DESTDIR/$root.tag.xml $DESTDIR/$root.split2.xml $root`;
    		
    		#  Step4: remove bracelet characters and multiple spaces
            open (SPLITFILE2, "$DESTDIR/$root.split2.xml");
            open (SPLITFILE, ">$DESTDIR/$root.split.xml");
            while(<SPLITFILE2>)
            {   my $line = $_;  
                $line =~ s/\r|\n//g;
                #$line =~ s/\(|\)|\[|\]|\{|\}/ /g;
                $line =~ s/\s+/ /g;
                $line = xmlCleanUp($line);
                print SPLITFILE $line."\n";
            }   
            close SPLITFILE;        
            close SPLITFILE2;

            #  Step5: Create prelink file from split.xml file
            `$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/LinkPreProcess.pl $DESTDIR/$root.split.xml $DESTDIR/$root.prelink`;
            
            #  Step6: Create SciMinerDB suitable file
            `$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/preSciMinerProcess.pl $DESTDIR/$root.prelink $DESTDIR/$root.preSciMiner`;
            open (PRELINK, "$DESTDIR/$root.prelink");
            open (PRESCIMINER, ">"."$DESTDIR/$root.preSciMiner");
            my $anchor  = '';
            my $ppn     = 0;
            while(<PRELINK>)
            {   my $line = $_;
                $line =~ s/\r|\n//g;
                if ($line =~ /^\%<(\w+)>/)
                {   $anchor = $1;
                }elsif ($line =~ /^\%<p ppn=\"(\d+)\">/)
                {   $ppn    = $1;
                }elsif ($line =~ /^(\d+) (.*)/)
                {   print PRESCIMINER "$1 $anchor $ppn $2\n";
                }
            }
            close PRELINK;
            close PRESCIMINER;
            
            #  Step7: Remove temporary files
            unlink( "$DESTDIR/$root.xml");
            unlink( "$DESTDIR/$root.tag.xml");
            unlink( "$DESTDIR/$root.split.xml");
            unlink( "$DESTDIR/$root.split2.xml");
            unlink( "$DESTDIR/$root.prelink");
            unlink( "$DESTDIR/$root.medline.xml");
            $processedStatus{$root} = 1;
        }else
        {   #  Even the medline parsing was unsuccessful.
            $processedStatus{$root} = 0;
        }
    }
    return (\%documentSource, \%processedStatus);
}



sub process_medline_html_document_single
{   my $FILESDIR            = shift;
    my $DESTDIR             = shift;
    my $root                = shift;
    my $annoENVRef          = shift;
    my $pmid2TitleRef       = shift;
    my $pmid2AbstractRef    = shift;
    
    my %documentSource  = ();
    my %processedStatus = ();
    my $parsingStatus  = 0;

    #  Process HTML first
    LogQuery("! Started to process single document pmid is $root");
    if (-f "$FILESDIR/$root.html")
    {   #LogQuery("HTML processing started");
        $parsingStatus = parse_html_master("$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/hwParse.pl", $FILESDIR.$root.".html", $root, $DESTDIR.$root.'.xml');
        #LogQuery("HTML processing Ended");
        
    }
    
    #  New change in SciMiner v2.2
    #  Medline records are processed any way to find reliable title and abstract
    my $medlineParsingStatus    = parse_medline($FILESDIR.$root.".medline", $root, $DESTDIR.$root.'.medline.xml', $pmid2TitleRef, $pmid2AbstractRef);
            
    #  Parser Medline Article in case of htmlParsingStatus == 0
    if (! $parsingStatus)
    {   $documentSource{$root}  = 1;      # 1 means medline record
        $parsingStatus          = $medlineParsingStatus;
        if (-f "$DESTDIR$root.medline.xml")
        {   `mv $DESTDIR$root.medline.xml $DESTDIR$root.xml`;
        }
    }else
    {   $documentSource{$root}  = 2;      # 2 means html
    }
        

    #  Create prelink file
    if ($parsingStatus)
    {   #  Step#1: Xml Tagging by xml2parse
        #LogQuery("XML2Parse.pl running");
        #print "Running XML2parse.pl\n";
        `$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/xml2parse.pl $DESTDIR/$root.xml $DESTDIR/$root.tag.xml`;
        
        #  Step#2: verify we didn't shrink in size from tag.xml to xml; if so, indicate an error
		if( ! -s "$DESTDIR/$root.tag.xml"  )
		{   `cp $DESTDIR/$root.xml $DESTDIR/$root.tag.xml`;
		}
		
		#  Step3: Split the tagged XML by sentence
		#LogQuery("sentence-boundary2.pl running");
        #print "Running sentence-bound2.pl\n";
		`$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/sentence-boundary2.pl $$annoENVRef{SciMinerPath}/Scripts/Main/HONORIFICS $DESTDIR/$root.tag.xml $DESTDIR/$root.split2.xml $root`;
		
		#  Step4: remove bracelet characters and multiple spaces
        open (SPLITFILE2, "$DESTDIR/$root.split2.xml");
        open (SPLITFILE, ">$DESTDIR/$root.split.xml");
        while(<SPLITFILE2>)
        {   my $line = $_;  
            $line =~ s/\r|\n//g;
            #$line =~ s/\(|\)|\[|\]|\{|\}/ /g;
            $line =~ s/\s+/ /g;
            $line = xmlCleanUp($line);
            print SPLITFILE $line."\n";
        }   
        close SPLITFILE;        
        close SPLITFILE2;

        #  Step5: Create prelink file from split.xml file
        #LogQuery("LinkPreProcess.pl running");
        #print "Running LinkPreProcess.pl\n";
        `$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/LinkPreProcess.pl $DESTDIR/$root.split.xml $DESTDIR/$root.prelink`;
        
        #  Step6: Create SciMinerDB suitable file
        #LogQuery("preSciMinerProcess.pl running");        
        #        print "Running preSciMinerProcess.pl\n";
        `$$annoENVRef{Perl} $$annoENVRef{SciMinerPath}/Scripts/Main/preSciMinerProcess.pl $DESTDIR/$root.prelink $DESTDIR/$root.preSciMiner`;
        open (PRELINK, "$DESTDIR/$root.prelink");
        open (PRESCIMINER, ">"."$DESTDIR/$root.preSciMiner");
        my $anchor  = '';
        my $ppn     = 0;
        while(<PRELINK>)
        {   my $line = $_;
            $line =~ s/\r|\n//g;
            if ($line =~ /^\%<(\w+)>/)
            {   $anchor = $1;
            }elsif ($line =~ /^\%<p ppn=\"(\d+)\">/)
            {   $ppn    = $1;
            }elsif ($line =~ /^(\d+) (.*)/)
            {   print PRESCIMINER "$1 $anchor $ppn $2\n";
            }
        }
        close PRELINK;
        close PRESCIMINER;
        
        #  Step7: Remove temporary files
        unlink( "$DESTDIR/$root.xml");
        unlink( "$DESTDIR/$root.tag.xml");
        unlink( "$DESTDIR/$root.split.xml");
        unlink( "$DESTDIR/$root.split2.xml");
        unlink( "$DESTDIR/$root.prelink");
        unlink( "$DESTDIR/$root.medline.xml");
        $processedStatus{$root} = 1;
    }else
    {   #  Even the medline parsing was unsuccessful.
        $processedStatus{$root} = 0;
    }
 
    return ($documentSource{$root}, $processedStatus{$root});
}









