sub file_determine_document_format
{   my $file        = shift;
    open (FILE, $file) || return ("");
    my @content = <FILE>;
    my $contentString   = join (" ", @content);
    return (determine_document_format(\$contentString));
}




sub determine_document_format()
{   my $html = shift;

    my $format = '';

    # ---- JATS XML Detection (highest priority, added 2026-03) ----
    # JATS XML articles from PMC OA subset have <article> root with <body>
    if ($$html =~ /<article[\s>].*?article-type/si &&
        ($$html =~ /<body[\s>]/si || $$html =~ /<front[\s>]/si))
    {   $format = 'pubmedcentral';
        return $format;
    }
    # Also detect JATS content by article-meta presence
    if ($$html =~ /<article-meta>/si && $$html =~ /<article-title>/si)
    {   $format = 'pubmedcentral';
        return $format;
    }

    # ---- PMC Detection (original + modern patterns, updated 2026-03) ----
    if ($$html =~ /content=\"?https?:\/\/www\.pubmedcentral\.nih\.gov\//i)
    {   $format = 'pubmedcentral';
    }elsif ($$html =~ /content=\"?https?:\/\/(?:www\.)?ncbi\.nlm\.nih\.gov\/pmc\//i)
    {   # Modern PMC URL pattern (added 2026-03)
        $format = 'pubmedcentral';
    }elsif ($$html =~ /\&gt\; PubMed Central/)
    {   $format = 'pubmedcentral';
    }elsif ($$html =~ /europepmc\.org/i)
    {   # Europe PMC (added 2026-03)
        $format = 'pubmedcentral';
    }elsif ($$html =~ /pmc\.ncbi\.nlm\.nih\.gov/i)
    {   # New PMC domain (added 2026-03)
        $format = 'pubmedcentral';

    # ---- BioMed Central / BMC ----
    }elsif ($$html =~ /<meta name\s*=\s*\"dc\.publisher\"\s+content=\"Biomed Central\"/i)
    {   $format = 'biomedcentral';
    }elsif ($$html =~ /biomedcentral\.com/i)
    {   # Modern BMC URL pattern (added 2026-03)
        $format = 'biomedcentral';

    # ---- Blackwell / Wiley ----
    }elsif($$html =~ /<title>Blackwell Synergy/)
	{   $format = 'bwsynergy';
    }elsif($$html =~ /<title>Wiley InterScience/ || $$html =~ /onlinelibrary\.wiley\.com/i)
	{   # Updated Wiley pattern (added 2026-03)
        $format = 'wiley';

    # ---- Elsevier / ScienceDirect ----
	}elsif( $$html =~ /www\.sciencedirect\.com/i || $$html =~ /sciencedirect\.com/i )
	{   # Updated ScienceDirect pattern (added 2026-03)
        $format = 'elsevier';
	}elsif( $$html =~ /elsevier\.com/i )
	{   $format = 'elsevier';

    # ---- Nature ----
	}elsif( $$html =~ /naturejobs\.nature\.com/ || $$html =~ /Nature Publishing Group/ ||
		    $$html =~ /npg\.nature\.com/ || $$html =~ /www\.nature\.com/ ||
		    $$html =~ /nature\.com\/articles\//i )
	{   # Added modern nature.com/articles/ pattern (2026-03)
        $format = 'nature';

    # ---- Science / AAAS ----
	}elsif( $$html =~ /content="http:\/\/www\.sciencemag\.org\/cgi\// ||
	        $$html =~ /science\.org\/doi\//i ||
	        $$html =~ /www\.science\.org/i )
	{   # Added modern science.org pattern (2026-03)
        $format = 'science';

    # ---- Liebert ----
	}elsif(( $$html =~ /liebertonline\.com/ ) || ( $$html =~ /www\.liebertpub\.com/))
	{   $format = 'liebert';

    # ---- Landes ----
	}elsif( $$html =~ /X-Meta-Description: Landes Bioscience/ )
	{   $format = 'landes';

    # ---- Springer / SpringerLink ----
	}elsif( $$html =~ /SpringerLink/i || $$html =~ /link\.springer\.com/i )
	{   # Added modern link.springer.com pattern (2026-03)
        $format = 'springer';

    # ---- Ingenta ----
	}elsif( $$html =~ /ingentaconnect\.com/ )
	{   $format = 'ingenta';

    # ---- Ovid ----
	}elsif( $$html =~ /<meta name="OvidPageId"/ )
	{   $format = 'ovid';

    # ---- Informa / Taylor & Francis ----
	}elsif( $$html =~ /content="Informa Healthcare"/ ||
	        $$html =~ /tandfonline\.com/i )
	{   # Added Taylor & Francis pattern (2026-03)
        $format = 'informa';

    # ---- Karger ----
	}elsif( $$html =~ /(?:https?:\/\/)?(?:www\.)?karger\.com/i )
	{   $format = 'karger';

    # ---- Portland Press ----
	}elsif( $$html =~ /CONTENT="Portland Press Ltd\."/ )
	{   $format = 'portland';

    # ---- NCBI / PubMed ----
	}elsif( $$html =~ /pubmeddev/ || $$html =~ /pubmed\.ncbi\.nlm\.nih\.gov/i )
	{   # Added modern PubMed URL (2026-03)
        $format = 'ncbi';

    # ---- HighWire ----
	}elsif( $$html =~ /HIGHWIRE ID="/i )
	{   $format = 'highwire';

    # ---- DOI redirect detection (added 2026-03) ----
    }elsif( $$html =~ /doi\.org\/10\./i )
    {   # DOI redirects - try to determine actual publisher from content
        # This is a fallback; the redirect should have been resolved before parsing
        $format = 'other';

    # ---- Error / Fallback ----
	}elsif( $$html eq '0' )
	{   $format = 'error';
	}else
	{   $format = 'other';
	}

    return $format;
}




sub convert_file_unicode_to_ascii
{   use Unicode::String;

    my $fileName    = shift;
    if (! -f $fileName)
    {   return (-1);
    }
    
    open (INFILE, $fileName);
    my @lines = <INFILE>;
    close INFILE;
    
    open (OUTFILE, ">".$fileName);
    foreach my $line (@lines)
    {   $line =~ s/(.)/Unicode::String::utf8($1)->latin1()/eg;
        print OUTFILE $line;
    }
    close OUTFILE;
    return (1);
}
















































































































































































































































































































































































































































































































































































































































































































































































################################################################################
#
#   SECTION_7   Parser Collection
#
################################################################################
# ParseElseVier
sub ParseElseVier()
{   my $htmlArticleRef      = shift;
    my %article             = (); 
    my @sideTables          = (); 
    my %sectionAnchors      = ();

    # Step#0, Check whether the HTML has a title starting with ScienceDirect
    if ($$htmlArticleRef !~ /title>ScienceDirect/)
    {   return (-1);
    }
    
    # Step#1, check whether the HTML is a fulltext HTML or not. Fulltext ElseVier HTML seems to have 'Article outline'
    if ($$htmlArticleRef !~ /Article Outline/)
    {   return (-1);
    }
    
    #  Check for error
	if ($$htmlArticleRef =~ /<p class="error">/)
	{   return (-1);
	}    
	
    my $priorArticleOutline = $`;           #`
    my $postArticleOutline = $';            #'


    # Step#2, extract the title of the paper
    my $remainingPriorArticleOutline = '';
    if ($priorArticleOutline =~ /articleTitle\">/)
    {   my $tmpString = $';                 #'
        # LogQuery($tmpString);
        if ($tmpString =~ /<p>(\S.*?)<\/span>/)
        {   $article{ TITLE }->{text} = CleanUp($1);
            $remainingPriorArticleOutline = $';     #'
        }else
        {   $article{ TITLE }->{text} = "";
            $remainingPriorArticleOutline = $tmpString;
        }
    }else
    {   $article{ TITLE }->{text} = "";
        $remainingPriorArticleOutline = $priorArticleOutline;
    }
    $article{ TITLE }->{order} = 0;


    # Step#3, extract abstract or background before 'Article outline'
    # <p><span class="h3">
    if ($remainingPriorArticleOutline =~ /<(span|h3) class=\"h3\">/)
    {   if ($' =~ /<\/div>/)                #'
        {   my $tmpAbstract = $`;           #`
            $tmpAbstract =~ s/<i>|<\/i>//g;
            $article{ABSTRACT}->{text} = CleanUp($tmpAbstract);
            # print "\n\nHere is the abstract part\n".$tmpAbstract."\n";
        }
    }else
    {   $article{ABSTRACT}->{text} = "";
    }
    $article{ABSTRACT}->{order} = 1;


    # Step#4: Find '>References</span>'
    my $bodyContent = '';
    my $referenceContent = '';
    if ($postArticleOutline =~ /<span class=\"h\d\">References<\/span><p>/)
    {   # The remaining section is for REFERENCES
        $bodyContent = $`.$&;               #`
        $referenceContent = $';             #'
    }elsif ($postArticleOutline =~ /<h3 class=\"h\d\">References</)   #<span class=\"h\d\">References<\/span><p>/)
    {   # The remaining section is for REFERENCES
        $bodyContent = $`.$&;               #`
        $referenceContent = $';             #'
    }else
    {   # If there is no 'References</span>', parsing is aborted since
        # it's also likely that the html is not a full text document. 
        return (-1);
    }


    # Step#5: Extract figures and tables 
    # Figures and Tables start with 'blockquote'
    # or <\/div><!--graphText--> in a new version of ElseVier documents (08/20/2008)
    my $newBodyContent 		= $bodyContent;
    my $figureTableFound	= 0;
    my $textWithoutFigure	= '';
    if ($newBodyContent =~ /blockquote/)
    {	while($newBodyContent =~ /<blockquote>(.*?)<\/blockquote>/)
		{   $newBodyContent = $`.$';            #`   
		    my $tmpContent = $1;
		    my $tmpTableText = '';

		    if ($tmpContent =~ /<p>\s*Fig/i)
		    {   # This is a figure
		        if ($tmpContent =~ /<p>\s*(Fig.*?)(<\/p>|<p>)/i)
				{   # This is a figure
					$article{FIGURE}->{text} .= CleanUp($&);  #'
		            $article{FIGURE}->{order} = 99;
				}
		    }
		}
		$figureTableFound	= 1;
    }elsif ($newBodyContent	=~ /<\/div><!--graphText-->/)
    {	while($newBodyContent =~ /<div class="graphText">(.*?)<\/div><!--graphText-->/)
		{   $newBodyContent = $`.$';            #`   
		    my $tmpContent = $1;
		    my $tmpTableText = '';
			
		    if ($tmpContent =~ /<p>\s*(Fig.*?)(<\/p>|<p>)/i)
		    {   # This is a figure
				$article{FIGURE}->{text} .= CleanUp("\n".$&."\n");  #'
	            $article{FIGURE}->{order} = 99;
		    }
		}
		$figureTableFound	= 2;
    }
    
    
    
    # Step#6: Handle remaining main body; methods, results, and discussion
    my $currentH3Anchor = '';
    my $order = 2;
    
    #  If there is no appropriate H3 level section, check only if there is probable
    #  candidate section, and put it as OTHER section.
    if ($newBodyContent =~ /<span class=\"h(\d+)\"(>.*?)(<span class=\"h\d+\">)/)
    {   while($newBodyContent =~ /<span class=\"h(\d+)\"(>.*?)(<span class=\"h\d+\">)/)
        {   my $tmpMatch = $2;
            my $spanClassLevel = $1;
            $newBodyContent = $3.$';        #'
            
            if ($tmpMatch =~ /.*>(.*?)<\/span>/)
            {   my $anchorCandidate = $1;
                my $tmpRemainingBody = $';  #'
                if ($tmpRemainingBody =~ /<a name=\"^b/i)
                {   $tmpRemainingBody = $`; #`
                }
                if ($spanClassLevel == 3)
                {   $currentH3Anchor = $anchorCandidate;
                    my $originalH3Anchor = $anchorCandidate;
                    $currentH3Anchor =~ s/\d+|\.//g;
                    $currentH3Anchor = NormalizeName($currentH3Anchor);
                    $article{$currentH3Anchor}->{text} .= CleanUp("<p>$originalH3Anchor<p>\n".$tmpRemainingBody."\n");
                    $article{$currentH3Anchor}->{order} = $order;
                    $order++;
                }elsif ($spanClassLevel == 4)
                {   $article{$currentH3Anchor}->{text} .= CleanUp("<p>$1<p>\n".$tmpRemainingBody."\n");
                }
            }
        }
    }else
    {	$currentH3Anchor	= "INTRODUCTION";
    	if ($newBodyContent =~ /<div class="articleText">.*?<\/div>/)
    	{	while($newBodyContent =~ /<div class="articleText">(.*?)<\/div>/)
    		{	$newBodyContent		= $';
    			my @tmpSplit		= split(/<h3 class="h3">/, $1);
    			foreach my $text (@tmpSplit)
    			{	if ($text =~ /<\/h3>/)
    				{	my $originalH3Anchor 	= $`;
    					my $tmpRemainingBody	= $';
    					$currentH3Anchor		= NormalizeName($originalH3Anchor);
    					$article{$currentH3Anchor}->{text} .= CleanUp("<p>$originalH3Anchor<p>\n".$tmpRemainingBody."\n");
		                $article{$currentH3Anchor}->{order} = $order;
		                $order++;
		                $tmpRemainingBody		= '';
    				}else
    				{	$article{$currentH3Anchor}->{text} .= CleanUp($text."\n");
		                $article{$currentH3Anchor}->{order} = $order;
    				}
    			}
    		}
    	}else	#if ($newBodyContent !~ /<span class=\"h(\d+)\"(>.*?)(<span class=\"h\d+\">)/)
		{   #  There is no appropriate section found. Chances are
		    #  1) there is really nothing
		    #  2) there is something without section anchor

		    #  If there is something meaningful, put them into INTRODUCTION section.
		    #  This might miss any section coming after </div>
		    if ($newBodyContent =~ /<div class=.*?>(.*?)<\/div>/)
		    {   $currentH3Anchor = "INTRODUCTION";
		        $article{$currentH3Anchor}->{text} .= CleanUp("<p>$currentH3Anchor<p>\n".$1."\n");
		        $article{$currentH3Anchor}->{order} = $order;
		    }
		}
    }
    

    # Step#7: Take care the remaining reference section
    # In fact, Reference section IS NOT USED FOR SciMiner. 
    # thus, this functionality will not be implemented.


    # Step#8: Check the key. If we have only one key then there was an error during parsing
    if( scalar( keys(%article) ) <= 1 )
    {   return (-1);
    }
    
    return (1, \%article);
}




sub ParseSD()
{   my $htmlArticleRef = shift;
    my %article = ();
    my $order = 0;

    while( $$htmlArticleRef =~ m|<h2>(.*?)(?=<h2>\|</div>)|msgi )
    {   my $sectionContents = $1;
        LogQuery($sectionContents);
        if( $sectionContents =~ m|(.*)</h2>(.*)| )
        {
            my $sectionAnchor = $1;
            my $sectionText = $2;

            $sectionAnchor = NormalizeName($sectionAnchor, $order);

            $sectionText=~ s/<\/*(br|p)>/\n/gi;
            $sectionText=~ s/<\/*(.*?)>//g;
            $sectionText =~ s/&nbsp;/ /gi;
            $sectionText =~ s/&amp;/&/gi;

            $article{$sectionAnchor}->{text} = $sectionText;
            $article{$sectionAnchor}->{order} = $order++;
            $article{$sectionAnchor}->{sectionName} = $sectionAnchor;
        }
    }

    foreach my $anchor( sort( { $article{$a}->{order} <=> $article{$b}->{order} } keys( %article) ) )
    {
        #print "FOUND!!!!!!!!!!!!!! $anchor: $article{$anchor}->{sectionName}\n";
    }

    return \%article;
}










# sub Parse_Portland
# A full html parser for Porland journal articles
# As of 02/29/2008, working in good state but excludes references, figures, 
# and tables in the current version.
sub Parse_Portland
{	my $htmlArticleRef  = shift;
    
    my %article 			= ();
    my $htmlContent   		= '';
    my $secAnchor       	= '';
    my $order           	= 0;
    my $originalSecAnchor	= '';
    
    # Check for error
	if ($$htmlArticleRef =~ /<p class="error">/)
	{   return (-1);
	}
	
	#  Use only <!--- ARTICLE --->
	if ($$htmlArticleRef =~ /<!--- ARTICLE --->(.*?)<!--- END ARTICLE --->/)
	{	$htmlContent	= $1;
	}else
	{   return(-1);
	}
	
	#  Remove Reference section
	if ($htmlContent 	=~ /<B>References<\/B>/i)
	{	$htmlContent	= $`;
	}
	
	#  Table content should be removed.
	$htmlContent =~ s/<table.*?<\/table>/ /gi;
	
	my @docSplit	= split (/<P>/, $htmlContent);
	foreach my $line (@docSplit)
	{	if ($line =~ /To whom correspondence should/)
		{	#  Skip this line
		}elsif ($line =~ /<B>(.*?)<\/B><\/P>/)
		{	#  Check section anchor
			$originalSecAnchor	= section_title_tag_remove_only($1);
			my $tmpName			= NormalizeName($originalSecAnchor);
			if (($secAnchor eq "") || ($tmpName ne "UNKNOWN"))
			{   $secAnchor	= $tmpName;
			}
			
			$article{$secAnchor}->{text}	.= CleanUp($originalSecAnchor."\n");
			if (not defined $article{$secAnchor}->{order})
			{	$article{$secAnchor}->{order}	= $order++;
			}
		}else
		{	if ((defined $secAnchor) && ($secAnchor ne ""))
			{	$article{$secAnchor}->{text}	.= CleanUp($line);
			}else
			{	$article{UNKNOWN}->{text}	.= CleanUp($line);
				$article{UNKNOWN}->{order}	= 97;
			}
		}
	}
	
	#  Check the status and return 
	if ($order == 0)
	{   return (-1);
	}else
	{   return (1, \%article);
	}
}










# sub Parse_Generic
# As of 02/21/2008
# This module is not used. hwParse.pl is doing its job.
sub Parse_Generic
{   my $htmlArticleRef  = shift;
    
    my %article 			= ();
    my $remainingText   	= '';
    my $secAnchor       	= '';
    my $order           	= 0;
    my $originalSecAnchor	= '';
        
	#  Clear Top of page link
	my $htmlContent			= '';
	my $textFound           = 0;
	
	#  Check for error
	if ($$htmlArticleRef =~ /<p class="error">/)
	{   return (-1);
	}    
	
    #  <font size="5">(   )</font> removed
    $$htmlArticleRef    =~ s/<font size="\d">(.*?)<\/font>/$1/g;

    #  <P> and <p> tag capitalization
    $$htmlArticleRef    =~ s/<p>/<P>/g;
    $$htmlArticleRef    =~ s/<\/p>/<\/P>/g;
    $$htmlArticleRef    =~ s/<\\p>/<\\P>/g;
    
    #  Remove reference
    if (($$htmlArticleRef =~ /(>?)ACKNOWLEDGMENTS<.*?$/i) || 
        ($$htmlArticleRef =~ /(>?)REFERENCES<.*?$/i))
    {   $htmlContent    = $`.$1;
    }else
    {   $htmlContent    = $$htmlArticleRef;
    }

    my @docSplit = split (/<P>/, $htmlContent);
    foreach my $line (@docSplit)
    {   $article{"UNKNOWN"}->{text} .= CleanUp($line);
        $article{"UNKNOWN"}->{order} = 97;
    }
    
    if (defined $article{"UNKNOWN"}->{order})
    {   return(1,\%article);
    }else
    {   return(-1);
    }
}











sub Parse_Springer
{   my $htmlArticleRef  = shift;
    
    my %article 			= ();
    my $remainingText   	= '';
    my $secAnchor       	= '';
    my $order           	= 0;
    my $originalSecAnchor	= '';
        
	#  Clear Top of page link
	my $htmlContent			= '';
	my $textFound           = 0;
	
	#  Check for error
	if ($$htmlArticleRef =~ /<p class="error">/)
	{   return (-1);
	}    
	
	#  Reduce the text size a little bit
	if ($$htmlArticleRef =~ />\s*References\s*?<\/h/i)
	{   $htmlContent        = $`.'>';
	}else
	{   $htmlContent        = $$htmlArticleRef;
	}
	
	#  Table content should be removed.
	$htmlContent =~ s/<table.*?<\/table>/ /gi;
	
	#  Convert &nbsp; to simple space
	$htmlContent =~ s/&nbsp;/ /gi;
	#$htmlContent =~ s/(.)/Unicode::String::utf8($1)->latin1()/eg || print "";
	
	#  Split by <div class=
	my @docSplit = split (/<div class=/, $htmlContent);
	foreach my $line (@docSplit)
    {   if ($line =~ /^\"(.*?)\">(.*?)<\/div>/)
        {   my $header      = $1;
            my $secHeader   = $2;
            my $content     = $2.' '.$';
            
            if ($header =~ /Abstract/i)
            {   $secAnchor  = NormalizeName($header);
            	if (not defined $article{$secAnchor}->{order})
            	{   $article{$secAnchor}->{order} = $order++;
            	}
                $article{ABSTRACT}->{text}   .= CleanUp($content);
            }elsif ($header eq "heading2")
            {   $originalSecAnchor  = section_title_tag_remove_only($secHeader);
                $secAnchor  = NormalizeName($originalSecAnchor);
            	
                if (not defined $article{$secAnchor}->{order})
            	{   $article{$secAnchor}->{order} = $order++;
            	}
                $article{$secAnchor}->{text}   .= CleanUp($content);
            }else
            {   if ((not defined $secAnchor) || ($secAnchor eq ""))
                {   #$article{"UNKNOWN"}->{text}     .= CleanUp($content);
                    #$article{"UNKNOWN"}->{order}    .= 97;
                }else
                {	$article{$secAnchor}->{text}   .= CleanUp($content);
                }
            }
        }else
        {   #  Check for section anchor
        	if ($line =~ /^\"(.*?)\">/)
            {	my $tmpHeader	= $1;
            	my $tmpText		= $';
            	if ($tmpHeader ne "")
            	{   my $tmpAnchor	= NormalizeName($tmpHeader);
            		if ($tmpHeader eq 'AbstractPara')
            		{	$article{$secAnchor}->{text}	.= CleanUp($tmpText);
            		}elsif (($tmpAnchor ne 'UNKNOWN') || ($secAnchor eq 'UNKNOWN'))
            		{	$secAnchor	= $tmpAnchor;
            			$article{$secAnchor}->{text}	.= CleanUp($tmpText);
            			
		        		$secAnchor	= $tmpAnchor;
		        		if (not defined $article{$secAnchor}->{order})
		        		{ 	$article{$secAnchor}->{order} = $order++;
		        		}
            		}
            	}else
            	{   if ($secAnchor ne "")
            		{	$article{$secAnchor}->{text}	.= CleanUp($tmpText);
            		}
            	}
            }elsif ($secAnchor ne "")
            {   $line =~ s/^"\S*?">//g;
                $article{$secAnchor}->{text}   .= CleanUp($line);
                if (not defined $article{$secAnchor}->{order})
                {   $article{$secAnchor}->{order} = $order;
                    $order++;
                }
            }else
            {   # print "^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^\n";
            }
        }
    }
    
    if ($order > 0)
    {   return (1, \%article);
    }else
    {   return (-1);
    }
}






sub Parse_Informa
{   my $htmlArticleRef  = shift;
    
    my %article 			= ();
    my $remainingText   	= '';
    my $secAnchor       	= '';
    my $order           	= 0;
    my $originalSecAnchor	= '';
        
	#  Clear Top of page link
	my $htmlContent			= '';
	my $textFound           = 0;
	
	#  Check for error
	if ($$htmlArticleRef =~ /<p class="error">/)
	{   return (-1);
	}    
	
	#  Reduce the text size a little bit
	if ($$htmlArticleRef =~ />\s*References\s*<\/h2>/i)
	{   $htmlContent        = $`.'>';
	}else
	{   if ($$htmlArticleRef =~ />\s*List of Figures\s*<\/h2>/i)
	    {   $htmlContent        = $`.'>';
	    }else
	    {   $htmlContent        = $$htmlArticleRef;
	    }
	}
	
	my @docSplit    = split (/<h2 id=/, $htmlContent);
	foreach my $line (@docSplit)
	{   if ($line =~ /^".*?">\s*(\S.*?)<\/h2>/)
	    {   $originalSecAnchor  = section_title_tag_remove_only($1);
	        $secAnchor          = NormalizeName($originalSecAnchor);
	        $article{$secAnchor}->{order}   = $order;
	        $order++;
	        
	        if ($line =~ /<h3 id=/)
	        {   my @lineSplit   = split (/<h3 id=/, $line);
	            foreach my $shortLine (@lineSplit)
	            {   if ($shortLine =~ /^".*?">\s*(\S.*?)<\/h3>/)
	                {   $originalSecAnchor  = section_title_tag_remove_only($1);
	                    $article{$secAnchor}->{text} .= CleanUp($originalSecAnchor." \n".$');
	                }else
	                {   $article{$secAnchor}->{text} .= CleanUp($shortLine);
	                }
	            }
	        }else
	        {   $article{$secAnchor}->{text} .= CleanUp($originalSecAnchor." \n".$');
	        }
	    }else
	    {   #  Look for any abstract
            if ($line =~ /<h2>\s*(\S.*\S)\s*<\/h2>/)
            {   $secAnchor  = NormalizeName($1);
                $article{$secAnchor}->{order} = $order;
                $order++;
                $article{$secAnchor}->{text} .= CleanUp($');
            }elsif ($line =~ /<div class="(\S.*?)">(.*?)<\/div>/)
            {   $secAnchor  = NormalizeName($1);
                $article{$secAnchor}->{order} = $order;
                $order++;
                $article{$secAnchor}->{text} .= CleanUp($2);
            }
	    }
	}

    if ($order > 0)
    {   return (1, \%article);
    }else
    {   return (-1);
    }
}










sub Parse_Karger
{   my $htmlArticleRef  = shift;
    
    my %article 			= ();
    my $remainingText   	= '';
    my $secAnchor       	= '';
    my $order           	= 0;
    my $originalSecAnchor	= '';
    
    #  Check for error
	if ($$htmlArticleRef =~ /<p class="error">/)
	{   return (-1);
	}    
	
	#  Clear Top of page link
	my $htmlContent			= '';
	my $textFound           = 0;
	
	#  Reduce the text size a little bit
	if (($$htmlArticleRef =~ /<b class="section1">References</) ||
	    ($$htmlArticleRef =~ /<b class="section1">Author Contacts</))
	{   $htmlContent        = $`;
	}else
	{   $htmlContent        = $$htmlArticleRef;
	}
	
	my @docSplit    = split (/<b class="section/, $htmlContent);
	foreach my $line (@docSplit)
	{   if ($line =~ /^(\d)">(.*?)<\/b>/)
	    {   $originalSecAnchor  = section_title_tag_remove_only($2);
	        if ($1  == 1)
	        {   # Only for section1, change the section anchor
	            $secAnchor          = NormalizeName($originalSecAnchor);
	            $article{$secAnchor}->{order}   = $order;
	            $order++;
	        }
	        $article{$secAnchor}->{text}    .= CleanUp($originalSecAnchor."\n".$');
	    }
	}

    if ($order > 0)
    {   return (1, \%article);
    }else
    {   return (-1);
    }
}










# sub Parse_Ovid
# This parses html documents from Ovid gateway
# Figures and references are excluded.
sub Parse_Ovid
{   my $htmlArticleRef  = shift;
    
    my %article 			= ();
    my $remainingText   	= '';
    my $secAnchor       	= '';
    my $order           	= 0;
    my $originalSecAnchor	= '';
        
	#  Clear Top of page link
	my $htmlContent			= '';
	my $textFound           = 0;
	
	#  Check for error
	if ($$htmlArticleRef =~ /<p class="error">/)
	{   return (-1);
	}    
	
	#  Reduce the text size a little bit
	if ($$htmlArticleRef =~ /<div class="fulltext-LEVEL1">References/)
	{   $htmlContent        = $`;
	}else
	{   if ($htmlContent =~ /<div class="fulltext-LEVEL1">Recommended reading/)
	    {   $htmlContent    = $`;
	    }else
	    {   $htmlContent    = $$htmlArticleRef;
	    }
	}
	
	#  Split by fulltext-LEVEL1
	my @docSplit = split (/<div class="fulltext-LEVEL1"/, $htmlContent);
	foreach my $line (@docSplit)
	{   if ($line =~ /^>(\S.*?)</)
	    {   $originalSecAnchor  = $1;
            my $remainingText   = $';	        
	        $secAnchor          = NormalizeName (section_title_tag_remove_only($originalSecAnchor));
	        $article{$secAnchor}->{text}    .= '';
	        $article{$secAnchor}->{order}   = $order;
	        $order++;
	        
	        while()
	        {   if ($remainingText =~ /<p class="fulltext-(ABSTRACT|TEXT).*?>(.*?)<\/p>/)
	            {   $article{$secAnchor}->{text}    .= CleanUp($2);
	                $remainingText  = $';
	            }else
	            {   last;
	            }
	        }
	    }else
	    {   # There is no level1 section anchor but still there some valid text to be procesed.
	        #LogQuery("Single $line\n\n\n\n\n");
	        if ((not defined $secAnchor) || ($secAnchor eq ""))
	        {   $secAnchor  = "UNKNOWN";
	            $order      = 97;
	        }
	        
	        while()
	        {   if ($line =~ /<p class="fulltext-(ABSTRACT|TEXT).*?>(.*?)<\/p>/)
	            {   $article{$secAnchor}->{text}    .= CleanUp($2);
                    $line = $';
	            }else
	            {   last;
	            }
	        }
	    }
	}
    
    if ($order > 0)
    {   return (1, \%article);
    }else
    {   return (-1);
    }
}











# sub Parse_Blackwell_Synergy
# A full html parser for Science journal articles
# As of 02/20/2008, working in good state but excludes references, figures, 
# and tables in the current version.
sub Parse_Blackwell_Synergy
{   my $htmlArticleRef  = shift;
    
    my %article 			= ();
    my $remainingText   	= '';
    my $secAnchor       	= '';
    my $order           	= 0;
    my $originalSecAnchor	= '';
        
	#  Clear Top of page link
	my $htmlContent			= '';
	my $textFound           = 0;
	
	#  Check for error
	if ($$htmlArticleRef =~ /<p class="error">/)
	{   return (-1);
	}
	
    #  	
	if ($$htmlArticleRef =~ /<div class="reference">/)
	{   $htmlContent        = $`;
	}else
	{   $htmlContent        = $$htmlArticleRef;
	}
	
    my @docSplit = split (/<div class="header_divide">/, $htmlContent);
	foreach my $line (@docSplit)
	{   #  Process when there is header
	    if ($line =~ /<h3 id.*?>(.*?)<\/h3>/)
	    {   $originalSecAnchor  = $1;
	        $remainingText      = $';
	        $secAnchor          = NormalizeName(section_title_tag_remove_only($originalSecAnchor));
	        if ($secAnchor eq "UNKNOWN")
	        {   $article{UNKNOWN}->{text} 	    .= CleanUp($originalSecAnchor."\n".$remainingText);
		        $article{UNKNOWN}->{order}      = 97;
	        }else
	        {   $article{$secAnchor}->{text} 	.= CleanUp($remainingText);
		        $article{$secAnchor}->{order}   = $order;
		        $order++;
	        }
	        $textFound  = 1;
	    }
    }

    if ($textFound)
    {   return (1, \%article);
    }else
    {   return (-1);
    }
}










# sub Parse_Science
# A full html parser for Science journal articles
# As of 02/20/2008, working in good state but excludes references, figures, 
# and tables in the current version.
sub Parse_Science
{	my $htmlArticleRef  = shift;
    
    my %article 			= ();
    my $remainingText   	= '';
    my $secAnchor       	= '';
    my $order           	= 0;
    my $originalSecAnchor	= '';
    
    # Check for error
	if ($$htmlArticleRef =~ /<p class="error">/)
	{   return (-1);
	}
	    
	#  Clear Top of page link
	my $htmlContentPriorE	= '';		# text before email corres
	my $htmlContentAfterE	= '';		# text after email corres
	my $htmlContent			= '';
	if ($$htmlArticleRef =~ /<div id="LegacyContent">/)
	{   $htmlContent	= $';
		
		#  Further remove after "THIS ARTICLE HAS BEEN CITED BY OTHER ARTICLES" if any
		if (($htmlContent =~ /<div class=\"?References\"?>/i) ||
		    ($htmlContent =~ /THIS ARTICLE HAS BEEN CITED BY OTHER ARTICLES/))
		{	$htmlContent = $`;
		}
		
		$htmlContent	=~ s/\s+/ /g;
		if ($htmlContent =~ /To whom correspondence should be addressed/)
		{   $htmlContentPriorE	= $`;
			$htmlContentAfterE	= $';
		}else
		{   $htmlContentAfterE	= $htmlContent;
		}
	}else
	{   return(-1);
	}
	
	#  As of 02/19/2008, the html format of the science magazine is horrible.
	#  It's far from being in a good structure, which make it almost impossible
	#  to parse all of the contect it has. 
	#  => The current parse wouldn't be expected to take care of everything.
	#  The following items are possibly missed by the current parser.
	#  Table, Figures, and references
	
	#  Process PriorE section at first
	if ($htmlContentPriorE ne "")
	{	#  There was such correspondece section
		#  Get the abstract if any
		my @priorSplit	= split (/<P>/, $htmlContentPriorE);
		$article{ABSTRACT}->{text} 	.= "";
		$article{ABSTRACT}->{order} = $order;
		$order++;
			
		#  Skip any text before the first <P>
		#  Check only the content after the first <P>
		if (defined $priorSplit[1])
		{   #  the first block contains some information.
			if ($priorSplit[1] =~ /\w/)
			{   $article{ABSTRACT}->{text} .= CleanUp($priorSplit[1]);
			}else
			{   # Check the second one, it should be an abstract
				if (defined $priorSplit[2]) 
				{   $article{ABSTRACT}->{text} .= CleanUp($priorSplit[2]);
				}
			}
		}
	}
	
	#  Now process the main text
	if ($htmlContentAfterE ne "")
	{	# Basically split by <P>
		my @afterSplit 		= split (/<P>/, $htmlContentAfterE);
		my $afterSplitCount	= scalar @afterSplit;
		
		$article{UNKNOWN}->{text} 	.= "";
		$article{UNKNOWN}->{order}	= 97;
		$order++;
		
		# Ignore the very first array content
		for (my $i=1; $i < $afterSplitCount; $i++)
		{   if ($afterSplit[$i] =~ /^\s*</)
			{
			}else
			{	$article{UNKNOWN}->{text} .= CleanUp($afterSplit[$i]);
			}
		}
	}
	
	#  Check the status and return 
	if ($order == 0)
	{   return (-1);
	}else
	{   return (1, \%article);
	}
}










# sub Parse_Nature()
# This parses the full text Nature html.
# Working good as of 02/19/2008
sub Parse_Nature
{   my $htmlArticleRef  = shift;
    
    my %article 			= ();
    my $remainingText   	= '';
    my $secAnchor       	= '';
    my $order           	= 0;
    my $originalSecAnchor	= '';
    
    #  Check for error
	if ($$htmlArticleRef =~ /<p class="error">/)
	{   return (-1);
	}    
	
	#  Clear Top of page link
	my $htmlContent	= ${$htmlArticleRef};
	$htmlContent =~ s/<a href="#top" class="backtotop">Top<span class="hidden"> of page<\/span><\/a>//gi;


	#  Clear any part before "page-header"
	if ($htmlContent =~ /"page-header"/)
	{	$htmlContent = $';
	}
	
	#  Clear "More links ~"  <div id="more-like-this">
	#  Discard any remaining from this 'more-like-this' part
	if ($htmlContent =~ /<div id="more-like-this">/)
	{	$htmlContent = $`;
	}
	
	#  Check for "abs" or "articlebody"
	if (($htmlContent =~ /<div id="abs">/) || ($htmlContent =~ /div id="articlebody"/))
	{
	}else
	{   return (-1);
	}

	#  Remove parts from references
	if ($htmlContent =~ /<div id="References">/)
	{   $htmlContent	= $`;
	}	


    my @docSplit = split (/<div id="/, $htmlContent);
    foreach my $line (@docSplit)
    {   #  Check for proper heading
    	# LogQuery($line."\n\n\n\n\n");
    	# LogQuery(substr($line, 0, 50));
    	# my $aaa = <STDIN>;
    	if (($line =~ /^>/) || ($line =~ /^affiliations/i))
    	{   # skip this, which belongs to the "page-header"
    	}
    	
    	elsif (($line =~ /^abs">/) || ($line =~ /^abstract">/))
    	{	$secAnchor	= 'ABSTRACT';
    		$article{$secAnchor}->{text}	.= CleanUp($');
    		$article{$secAnchor}->{order}	= 0;
    	}
    	# h3 section
    	elsif ($line =~ /^(\S+?)">(<a.*?<\/a>)?<h3(.*?)>(\S.*?)<\/h3>/)
    	{   #$originalSecAnchor	= $3;
    		$originalSecAnchor 	= section_title_tag_remove_only($4);
    		$secAnchor	  = NormalizeName($originalSecAnchor);
    		
    		$article{$secAnchor}->{text} .= CleanUp("<p>$originalSecAnchor<p>\n".$'."\n");
    		if (not defined $article{$secAnchor}->{order})
    		{   $article{$secAnchor}->{order} = $order;
    			$order++;
    		}
    	}
    	
    	# h4 section
    	elsif ($line =~ /^(\S+?)">(<a.*?<\/a>)?<h4(.*?)>(\S.*?)<\/h4>/)
    	{   my $newSecTitle	= section_title_tag_remove_only($4);
    		$article{$secAnchor}->{text} .= CleanUp("<p>".$newSecTitle."<p>\n".$'."\n");
    	}
    	
    	# Text body follows the figure (including the legend)
    	elsif ($line =~ /^(\S+?)" class="figure-table">(.*?)<\/div>/)
    	{   #  Process figure legend
			my $atTableCleaned	= CleanUp($2);
			
			#  Process tailing text first and figure/table
		  	$article{$secAnchor}->{text} .= CleanUp($');
			$article{$secAnchor}->{order} = $order;
    	
			if (substr($1,0,1) eq 'f')
			{   $article{FIGURES}->{text} .= $atTableCleaned;
				$article{FIGURES}->{order} = 98;
			}else
			{	$article{TABLES}->{text} .= $atTableCleaned;
				$article{TABLES}->{order} = 99;
			}
    	}
    	
    	#  remaining such as articlebody
    	elsif ($line =~ /^articlebody">/)
		{   $secAnchor	= 'BACKGROUND';
			$article{$secAnchor}->{text} .= CleanUp($');
    		if (not defined $article{$secAnchor}->{order})
    		{   $article{$secAnchor}->{order} = $order;
    			$order++;
    		}
		}
		
		else
    	{   $article{UNKNOWN}->{text} .= CleanUp($line);
    		$article{UNKNOWN}->{order} = 97;
    	}
    }
    
    
    return (1, \%article);
}










sub ParsePMC_SciMiner()
{   my $htmlArticleRef  = shift;

    my %article = ();
    my $remainingText   	= '';
    my $secAnchor       	= '';
    my $order           	= 0;
    my $originalSecAnchor	= '';

    #  Check for error
	if ($$htmlArticleRef =~ /<p class="error">/)
	{   return (-1);
	}

    # ---- JATS XML Detection (added 2026-03) ----
    # Modern PMC articles use JATS XML format with <article> root element.
    # Detect this format and route to the dedicated JATS parser.
    if ($$htmlArticleRef =~ /<article[\s>]/ &&
        ($$htmlArticleRef =~ /<body[\s>]/ || $$htmlArticleRef =~ /<front[\s>]/))
    {   return ParsePMC_JATS($htmlArticleRef);
    }
    # Also detect JATS-style content embedded in HTML wrappers
    # (some PMC pages wrap JATS content in HTML)
    if ($$htmlArticleRef =~ /<article-meta>/ && $$htmlArticleRef =~ /<article-title>/)
    {   return ParsePMC_JATS($htmlArticleRef);
    }
    # ---- End JATS XML Detection ----

    $$htmlArticleRef    =~ s/\s+/ /g;
        
    if ($$htmlArticleRef =~ /<td class=/)
    {	my @docSplit = split (/<td class=/, $$htmlArticleRef);
        foreach my $line (@docSplit)
        {   #  check against section-title. This is what we need
        	if ($line =~ /^\"?content-cell\"?>/)
            {   $remainingText	= $';
                $secAnchor 		= 'UNKNOWN';
                
                while($remainingText)
                {  	if ($remainingText =~ /<div class=\"?head(\S.*?)>(.*?)<\/div>/)
                    {   $originalSecAnchor	= $2;
                    	$secAnchor = NormalizeName($originalSecAnchor);
                    	
                    	#  Assign the remainder to $remainingText
						$remainingText = $';
						
						if ($remainingText =~ /<div class=\"?section-content\"?>(.*)<\/div>/)
                        {	# print "! Section content exists\n";
                        	$remainingText = $1;
							
                        	#  Process abstract subsections
							if ($remainingText =~ /class=\"?abs-head/)
							{   #print "! Abstract exist\n\n";
								my @tmpAbsSplit = split (/<div class=\"abs-head/, $remainingText);
								foreach my $absLine (@tmpAbsSplit)
								{   if ($absLine =~ /^.*?>(\S.*?)<\/div>/)
									{   $article{$secAnchor}->{text} .= CleanUp($1." ".$');
									}else
									{   $article{$secAnchor}->{text} .= CleanUp($absLine);
									}
								}
								$article{$secAnchor}->{order} = $order;
				                last;
							}
							
							#  Process non-abstract content
							else
							{   # print "! Non-abstract\n";
								# Continue with the remaining process
							}
                        }else
						{	LogQuery("!ERROR. No section content is found !!!");
							last;
						}
                        
                        #  Check for any new table section
                        #  This could be table, figure and whatever
                        
                        my @subtitles   = split (/<div class=\"?head2 head-separate\">/, $remainingText);
                        
                        foreach my $line (@subtitles)
                        {	#  Check for table
                        	if ($line =~ /<table.*<\/table>/)
                        	{   while()
		                        {   if ($line =~ /<table.*?<\/table>/)
		                            {   # process matched text
		                                my $beforeTable		= $`;
		                                my $atTableCleaned	= CleanUp($&);
		                                my $afterTable		= $';
		                                $article{$secAnchor}->{text} .= CleanUp($originalSecAnchor." ".$beforeTable);

										# Process table content
										if ($atTableCleaned =~ /^<p> figure/i)
										{   $article{FIGURES}->{text} .= $atTableCleaned;
											$article{FIGURES}->{order} = 98;
										}else
										{	$article{TABLES}->{text} .= $atTableCleaned;
											$article{TABLES}->{order} = 99;
										}
										$line = $afterTable;
		                            }else
		                            {   $article{$secAnchor}->{text} .= CleanUp($originalSecAnchor." ".$line);
		                                last;
		                            }
		                        }
		                        $article{$secAnchor}->{order} = $order;
                        	}else
                        	{   # if there is no table format, then just add and process
                        		$article{$secAnchor}->{text} .= CleanUp($originalSecAnchor." ".$line);
                        		$article{$secAnchor}->{order} = $order;
                        	}
                        }
                        last;
                    }else
                    {	
                    	#  Skip the last portion of the pubmed central document for non-section
                    	if ($remainingText =~ /<div class="footer-section">/)
                    	{   # skip
                    		last;
                    	}else
                    	{   $article{$secAnchor}->{text} .= CleanUp($originalSecAnchor." ".$remainingText);
		            		$article{$secAnchor}->{order} = $order;
		            		last;
                    	}
                    }
                }
                $order++;
                    	
                # print $article{$secAnchor}->{text}."\n\n\n";
            }else
            {	#  If it does not have 'content-cell', just skip it.
            }
        }
        
        my @secAnchors = keys %article;
        if (defined $secAnchors[0])
        {	# Then the file is in the old format. 
        	# Just proceed.
        }else
        {	
        	##############################################################        
        	# The file might be in the new format
        	##############################################################
        	my @docSplit = split (/<div class="section-content"/, $$htmlArticleRef);
		    foreach my $line (@docSplit)
		    {   # This format is not easy to capture the section titme
		    	$remainingText	= $line;
	            $secAnchor 		= 'UNKNOWN';
	            
	            if ($remainingText =~ /<div class="fm-footnote"/)
	            {	next;
	            }	
	            
	            
	            while($remainingText)
	            {  	if ($remainingText =~ /<div class=\"p.*?>(.*?)<\/div>/)
	            	{	$remainingText = $';
	            		my $paragraph			= $1;
	                	
	                	if (($paragraph =~ /<div class="footer-section/) || ($paragraph =~ /<div>Footnotes<\/div>/))
	                	{	next;
	                	}
	            		$originalSecAnchor 	= 'UNKNOWN';

	                	$article{$secAnchor}->{text} .= CleanUp($paragraph)."\n";
			        	$article{$secAnchor}->{order} = $order;
			        }
			        #  Skip the last portion of the pubmed central document for non-section
	                #elsif ($remainingText =~ /<div class="footer-section">/)
                	#{   # skip
                	#	last;
                	#}
                	else
                	{	last;
                	}
                }
		    }
        }
        #  Return the processed text
       	return(1, \%article);
    }else
    {	return (-1);
    }
}


# =============================================================================
# ParsePMC_JATS()
#
# Parses modern PMC articles in JATS (Journal Article Tag Suite) XML format.
# JATS XML is the standard format used by PubMed Central Open Access subset.
#
# Input:  Reference to string containing JATS XML content
# Output: (status, reference to %article hash)
#         status = 1 on success, -1 on failure
#         %article keys are normalized section names (ABSTRACT, METHODS, etc.)
#         Each key has {text} (cleaned text) and {order} (sort order) fields
#
# Added 2026-03 to handle modern PMC JATS XML format.
# The old ParsePMC_SciMiner handles legacy PMC HTML format as fallback.
# =============================================================================
sub ParsePMC_JATS
{   my $xmlRef = shift;

    my %article = ();
    my $order   = 0;

    # Work on a copy to avoid modifying the original
    my $xml = $$xmlRef;

    # Normalize whitespace for easier regex matching
    $xml =~ s/\r\n|\r/\n/g;

    # ---- Extract Title from <front> section ----
    if ($xml =~ /<article-title>(.*?)<\/article-title>/si)
    {   my $title = $1;
        $title = _jats_strip_inline_markup($title);
        $title =~ s/\s+/ /g;
        $title =~ s/^\s+|\s+$//g;
        if ($title ne '')
        {   $article{TITLE}->{text}  = "<p>$title</p>\n";
            $article{TITLE}->{order} = $order++;
        }
    }

    # ---- Extract Abstract ----
    # JATS abstracts can be structured (with <sec> subsections) or unstructured
    if ($xml =~ /<abstract[^>]*>(.*?)<\/abstract>/si)
    {   my $absContent = $1;
        my $absText = '';

        # Check for structured abstract with sections
        if ($absContent =~ /<sec/)
        {   # Structured abstract: extract each sub-section
            while ($absContent =~ /<sec[^>]*>(.*?)<\/sec>/sig)
            {   my $absSec = $1;
                my $subTitle = '';
                if ($absSec =~ /<title>(.*?)<\/title>/si)
                {   $subTitle = _jats_strip_inline_markup($1);
                    $subTitle =~ s/^\s+|\s+$//g;
                }
                # Collect paragraph text
                while ($absSec =~ /<p[^>]*>(.*?)<\/p>/sig)
                {   my $pText = _jats_strip_inline_markup($1);
                    $pText =~ s/\s+/ /g;
                    $pText =~ s/^\s+|\s+$//g;
                    if ($subTitle ne '')
                    {   $absText .= "<p>$subTitle: $pText</p>\n";
                    }else
                    {   $absText .= "<p>$pText</p>\n";
                    }
                }
            }
        }else
        {   # Unstructured abstract: extract paragraphs directly
            while ($absContent =~ /<p[^>]*>(.*?)<\/p>/sig)
            {   my $pText = _jats_strip_inline_markup($1);
                $pText =~ s/\s+/ /g;
                $pText =~ s/^\s+|\s+$//g;
                $absText .= "<p>$pText</p>\n";
            }
            # If no <p> tags, treat entire content as one paragraph
            if ($absText eq '' && $absContent =~ /\S/)
            {   my $pText = _jats_strip_inline_markup($absContent);
                $pText =~ s/\s+/ /g;
                $pText =~ s/^\s+|\s+$//g;
                $absText = "<p>$pText</p>\n" if $pText ne '';
            }
        }

        if ($absText ne '')
        {   $article{ABSTRACT}->{text}  = $absText;
            $article{ABSTRACT}->{order} = $order++;
        }
    }

    # ---- Extract Body Sections ----
    if ($xml =~ /<body[^>]*>(.*)<\/body>/si)
    {   my $bodyContent = $1;

        # Process top-level <sec> elements in the body
        # We use a non-greedy approach: find each <sec> at the top level
        # by tracking nesting depth
        my @topSections = _jats_split_top_level_sections($bodyContent);

        foreach my $secContent (@topSections)
        {   # Extract section title
            my $secTitle = 'UNKNOWN';
            if ($secContent =~ /<title>(.*?)<\/title>/si)
            {   $secTitle = _jats_strip_inline_markup($1);
                $secTitle =~ s/^\s+|\s+$//g;
            }

            # Normalize section name using existing NormalizeName()
            my $normalizedName = NormalizeName($secTitle, $order);

            # Skip references and supplementary material sections
            if ($normalizedName eq 'REFERENCES' ||
                $secTitle =~ /supplement/i ||
                $secTitle =~ /supporting\s+information/i ||
                $secTitle =~ /conflict.*interest/i ||
                $secTitle =~ /data\s+availability/i ||
                $secTitle =~ /author\s+contrib/i ||
                $secTitle =~ /funding/i)
            {   next;
            }

            # Collect text from this section and its subsections
            my $sectionText = _jats_extract_section_text($secContent, $secTitle);

            if ($sectionText ne '')
            {   $article{$normalizedName}->{text}  .= $sectionText;
                $article{$normalizedName}->{order} = $order
                    unless defined $article{$normalizedName}->{order};
                $order++;
            }
        }

        # If no <sec> elements found, try extracting paragraphs directly from body
        if (scalar(@topSections) == 0)
        {   my $bodyText = '';
            while ($bodyContent =~ /<p[^>]*>(.*?)<\/p>/sig)
            {   my $pText = _jats_strip_inline_markup($1);
                $pText =~ s/\s+/ /g;
                $pText =~ s/^\s+|\s+$//g;
                $bodyText .= "<p>$pText</p>\n" if $pText ne '';
            }
            if ($bodyText ne '')
            {   $article{UNKNOWN}->{text}  = $bodyText;
                $article{UNKNOWN}->{order} = $order++;
            }
        }
    }

    # ---- Extract figure and table captions ----
    # Figure captions
    my $figText = '';
    while ($xml =~ /<fig[^>]*>(.*?)<\/fig>/sig)
    {   my $figContent = $1;
        if ($figContent =~ /<caption>(.*?)<\/caption>/si)
        {   my $caption = $1;
            while ($caption =~ /<p[^>]*>(.*?)<\/p>/sig)
            {   my $pText = _jats_strip_inline_markup($1);
                $pText =~ s/\s+/ /g;
                $pText =~ s/^\s+|\s+$//g;
                $figText .= "<p>$pText</p>\n" if $pText ne '';
            }
            # Also extract <title> from caption if present
            if ($caption =~ /<title>(.*?)<\/title>/si)
            {   my $figTitle = _jats_strip_inline_markup($1);
                $figTitle =~ s/\s+/ /g;
                $figTitle =~ s/^\s+|\s+$//g;
                $figText .= "<p>$figTitle</p>\n" if $figTitle ne '';
            }
        }
    }
    if ($figText ne '')
    {   $article{FIGURES}->{text}  = $figText;
        $article{FIGURES}->{order} = 98;
    }

    # Table captions
    my $tableText = '';
    while ($xml =~ /<table-wrap[^>]*>(.*?)<\/table-wrap>/sig)
    {   my $tableContent = $1;
        if ($tableContent =~ /<caption>(.*?)<\/caption>/si)
        {   my $caption = $1;
            while ($caption =~ /<p[^>]*>(.*?)<\/p>/sig)
            {   my $pText = _jats_strip_inline_markup($1);
                $pText =~ s/\s+/ /g;
                $pText =~ s/^\s+|\s+$//g;
                $tableText .= "<p>$pText</p>\n" if $pText ne '';
            }
            if ($caption =~ /<title>(.*?)<\/title>/si)
            {   my $tblTitle = _jats_strip_inline_markup($1);
                $tblTitle =~ s/\s+/ /g;
                $tblTitle =~ s/^\s+|\s+$//g;
                $tableText .= "<p>$tblTitle</p>\n" if $tblTitle ne '';
            }
        }
    }
    if ($tableText ne '')
    {   $article{TABLES}->{text}  = $tableText;
        $article{TABLES}->{order} = 99;
    }

    # Check if we actually parsed anything meaningful
    my $totalKeys = scalar(keys %article);
    if ($totalKeys < 1)
    {   return (-1, \%article);
    }

    return (1, \%article);
}


# =============================================================================
# _jats_split_top_level_sections($bodyContent)
#
# Splits JATS XML body content into top-level <sec> elements.
# Handles nested <sec> by tracking depth.
# Returns array of section content strings (including the outer <sec> tags).
#
# Added 2026-03 for JATS XML parsing support.
# =============================================================================
sub _jats_split_top_level_sections
{   my $content = shift;
    my @sections = ();

    my $pos = 0;
    my $len = length($content);

    while ($pos < $len)
    {   # Find next <sec at current level
        my $secStart = index($content, '<sec', $pos);
        last if $secStart == -1;

        # Make sure this is a real <sec> tag (not <section> or similar)
        my $afterSec = substr($content, $secStart + 4, 1);
        if ($afterSec ne '>' && $afterSec ne ' ' && $afterSec ne "\n" && $afterSec ne "\t")
        {   $pos = $secStart + 4;
            next;
        }

        # Find the matching </sec> by tracking depth
        my $depth = 1;
        my $searchPos = index($content, '>', $secStart) + 1;

        while ($depth > 0 && $searchPos < $len)
        {   my $nextOpen  = index($content, '<sec', $searchPos);
            my $nextClose = index($content, '</sec>', $searchPos);

            # No more closing tags found - bail out
            last if $nextClose == -1;

            if ($nextOpen != -1 && $nextOpen < $nextClose)
            {   # Check if it's a real <sec> tag
                my $nextChar = substr($content, $nextOpen + 4, 1);
                if ($nextChar eq '>' || $nextChar eq ' ' || $nextChar eq "\n" || $nextChar eq "\t")
                {   $depth++;
                }
                $searchPos = $nextOpen + 5;
            }else
            {   $depth--;
                if ($depth == 0)
                {   # Found the matching close tag
                    my $secEnd = $nextClose + 6; # length of '</sec>'
                    my $secContent = substr($content, $secStart, $secEnd - $secStart);
                    push @sections, $secContent;
                    $pos = $secEnd;
                }else
                {   $searchPos = $nextClose + 6;
                }
            }
        }

        # If we didn't close properly, advance past this opening tag
        if ($depth > 0)
        {   $pos = $secStart + 5;
        }
    }

    return @sections;
}


# =============================================================================
# _jats_extract_section_text($secContent, $sectionTitle)
#
# Extracts clean text from a JATS <sec> element, including nested subsections.
# Recursively processes nested <sec> elements.
# Returns formatted text string with <p> tags.
#
# Added 2026-03 for JATS XML parsing support.
# =============================================================================
sub _jats_extract_section_text
{   my $secContent   = shift;
    my $sectionTitle = shift;

    my $text = '';

    # Remove the outer <sec> and </sec> tags
    $secContent =~ s/^<sec[^>]*>//si;
    $secContent =~ s/<\/sec>\s*$//si;

    # Remove the <title> tag (already extracted by caller)
    $secContent =~ s/<title>.*?<\/title>//si;

    # Remove figure and table-wrap elements (processed separately)
    $secContent =~ s/<fig[^>]*>.*?<\/fig>//sig;
    $secContent =~ s/<table-wrap[^>]*>.*?<\/table-wrap>//sig;

    # Remove supplementary-material elements
    $secContent =~ s/<supplementary-material[^>]*>.*?<\/supplementary-material>//sig;

    # Check for nested <sec> subsections
    if ($secContent =~ /<sec[\s>]/)
    {   # Process content before the first nested <sec>
        my $beforeSec = $secContent;
        if ($beforeSec =~ /^(.*?)(?=<sec[\s>])/si)
        {   my $preSec = $1;
            while ($preSec =~ /<p[^>]*>(.*?)<\/p>/sig)
            {   my $pText = _jats_strip_inline_markup($1);
                $pText =~ s/\s+/ /g;
                $pText =~ s/^\s+|\s+$//g;
                $text .= "<p>$pText</p>\n" if $pText ne '';
            }
        }

        # Process each nested <sec>
        my @subSections = _jats_split_top_level_sections($secContent);
        foreach my $subSec (@subSections)
        {   my $subTitle = '';
            if ($subSec =~ /<title>(.*?)<\/title>/si)
            {   $subTitle = _jats_strip_inline_markup($1);
                $subTitle =~ s/^\s+|\s+$//g;
            }
            my $subText = _jats_extract_section_text($subSec, $subTitle);
            if ($subTitle ne '' && $subText ne '')
            {   $text .= "<p>$subTitle</p>\n" . $subText;
            }else
            {   $text .= $subText;
            }
        }
    }else
    {   # No nested sections - extract paragraphs directly
        while ($secContent =~ /<p[^>]*>(.*?)<\/p>/sig)
        {   my $pText = _jats_strip_inline_markup($1);
            $pText =~ s/\s+/ /g;
            $pText =~ s/^\s+|\s+$//g;
            $text .= "<p>$pText</p>\n" if $pText ne '';
        }
    }

    return $text;
}


# =============================================================================
# _jats_strip_inline_markup($text)
#
# Strips JATS XML inline markup elements while preserving text content.
# Handles: italic, bold, sup, sub, xref, ext-link, named-content, etc.
# Removes bibliography reference citations (<xref ref-type="bibr">).
# Converts Greek letter entity references to text equivalents.
#
# Added 2026-03 for JATS XML parsing support.
# =============================================================================
sub _jats_strip_inline_markup
{   my $text = shift;
    return '' unless defined $text;

    # Remove bibliography citation references entirely
    # These appear as <xref ref-type="bibr" rid="ref1">1</xref>
    $text =~ s/<xref[^>]*ref-type\s*=\s*"bibr"[^>]*>.*?<\/xref>//sig;

    # Remove footnote references
    $text =~ s/<xref[^>]*ref-type\s*=\s*"fn"[^>]*>.*?<\/xref>//sig;

    # Keep text content of other xref types (fig, table, etc.)
    $text =~ s/<xref[^>]*>(.*?)<\/xref>/$1/sig;

    # Preserve text in formatting elements
    $text =~ s/<italic>(.*?)<\/italic>/$1/sig;
    $text =~ s/<bold>(.*?)<\/bold>/$1/sig;
    $text =~ s/<underline>(.*?)<\/underline>/$1/sig;
    $text =~ s/<monospace>(.*?)<\/monospace>/$1/sig;
    $text =~ s/<sc>(.*?)<\/sc>/$1/sig;
    $text =~ s/<named-content[^>]*>(.*?)<\/named-content>/$1/sig;
    $text =~ s/<styled-content[^>]*>(.*?)<\/styled-content>/$1/sig;

    # Handle superscript and subscript - keep the text
    $text =~ s/<sup>(.*?)<\/sup>/$1/sig;
    $text =~ s/<sub>(.*?)<\/sub>/$1/sig;

    # Handle external links - keep display text
    $text =~ s/<ext-link[^>]*>(.*?)<\/ext-link>/$1/sig;

    # Handle email elements
    $text =~ s/<email>(.*?)<\/email>/$1/sig;

    # Handle inline-formula - try to extract meaningful text
    $text =~ s/<inline-formula>.*?<\/inline-formula>/ [formula] /sig;

    # Handle disp-formula blocks
    $text =~ s/<disp-formula[^>]*>.*?<\/disp-formula>/ [formula] /sig;

    # Remove any remaining XML/HTML tags
    $text =~ s/<[^>]+>//g;

    # Decode common XML entities
    $text =~ s/&amp;/&/g;
    $text =~ s/&lt;/</g;
    $text =~ s/&gt;/>/g;
    $text =~ s/&quot;/"/g;
    $text =~ s/&apos;/'/g;
    $text =~ s/&#x0*a0;/ /gi;      # non-breaking space
    $text =~ s/&#160;/ /g;          # non-breaking space (decimal)
    $text =~ s/&#x0*2013;/-/gi;     # en-dash
    $text =~ s/&#x0*2014;/-/gi;     # em-dash
    $text =~ s/&#x0*2212;/-/gi;     # minus sign
    $text =~ s/&#x0*2018;/'/gi;     # left single quote
    $text =~ s/&#x0*2019;/'/gi;     # right single quote
    $text =~ s/&#x0*201C;/"/gi;     # left double quote
    $text =~ s/&#x0*201D;/"/gi;     # right double quote

    # Greek letters (common in biomedical text)
    $text =~ s/&#x0*3B1;/alpha/gi;
    $text =~ s/&#x0*3B2;/beta/gi;
    $text =~ s/&#x0*3B3;/gamma/gi;
    $text =~ s/&#x0*3B4;/delta/gi;
    $text =~ s/&#x0*3B5;/epsilon/gi;
    $text =~ s/&#x0*3BA;/kappa/gi;
    $text =~ s/&#x0*3BC;/mu/gi;
    $text =~ s/&#x0*3C0;/pi/gi;
    $text =~ s/&#x0*3C3;/sigma/gi;
    $text =~ s/&#x0*3C4;/tau/gi;

    # Re-encode ampersand for XML output compatibility (must be after entity decoding)
    $text =~ s/&/&amp;/g;
    $text =~ s/&amp;amp;/&amp;/g;  # fix double-encoding

    # Clean up whitespace
    $text =~ s/\s+/ /g;

    return $text;
}








