sub ParsePMC()
{   my $htmlArticleRef = shift;

    my %article = (); 
    while( $$htmlArticleRef =~ /<a class=\"side-section\" href=\"#(.*?)\">([\w\s]+)<\/a>/msgi )
    {   my $sectionAnchor= $1;
        my $sectionName= $2;
        $article{$sectionAnchor}->{sectionName} = $sectionName ;
    }

    my $order = 0;
    while( $$htmlArticleRef =~ /<a id=\"(.*?)\" name=\"\1\"><\/a>(.*?)<\/table>/msg )
    {   my $tableAnchor = $1;
        my $tableContent = $2;

        #save the ones we found in the side-section
        if( exists( $article{$tableAnchor} ) )
        {   $tableContent =~ s/<\/*(br|p)>/\n/gi;
            $tableContent =~ s/<\/*(.*?)>//g;
            $tableContent =~ s/&nbsp;/ /gi;
            $tableContent =~ s/&amp;/&/gi;
            $article{$tableAnchor}->{text} = $tableContent;
            $article{$tableAnchor}->{order} = $order++;
        }
    }
    return \%article;
}










sub ParseHighWire()
{   my $htmlArticle = shift;

    my %article = (); 
    my @sideTables = (); 

    # Throw away footnotes for now!
    $htmlArticle =~ s/<a name=\"R(FN\d+)\">.*?<a href=\"#FN\d+\">//msgi;

    # Throw away <p>. Not correctly done in TREC highwire
    # $htmlArticle =~ s/<\/*p>//msgi;

    #
    # First...we go through and find the left-aligned tables...to get the meaningful section anchors
    #
    my %sectionAnchors = ();
    while( $htmlArticle =~ /<table align=right.*?>(.*?)<\/table>/msgi ) 
    {   
        my $sideTable = $1;
        while( $sideTable =~ /<a +href=\"#(\w+?)\">(<img.*?arrow.gif\">)((\w|\s)+).*?<\/a>/msgi )  
        {   
            my $sectionAnchor= $1;
            my $sectionName= $3;
            $sectionAnchors{$sectionAnchor} = $sectionName;
        }
    }

    foreach my $anchor( keys(%sectionAnchors) )
    {   #print "KEY $anchor Name: $sectionAnchors{$anchor}\n";
    }


    #
    # Figures and tables get special treatment...they also go at the end (order=99)
    #

    while( $htmlArticle =~ /<center>.*?<table(.*?)\[in a new window\].*?<td align=left valign=top>(.*?)<\/td><\/tr><\/table>/msgi )
    {   
        #my $figKey = $tableAnchor;
        my $figKey = "table$1";
        my $figText= $2;

        $figText = CleanUp( $figText );

        if( $figText =~ /^<p>\s+Fig/i )
        {   
            $figKey = "FIGURES";
        }
        elsif( $figText =~ /^<p>\s+Tab/i )
        {   
            $figKey = "TABLES";
        }
        else
        {   
            #print STDERR "\n\nFIGURE TEXT WAS!!!!!!!!!!!! <$figText>\n\n";
            $figKey = "ADDITIONALTEXT";
        }
        
        $article{ $figKey }->{text} .= "\n$figText\n";
        $article{ $figKey }->{order} = 99;
        # print "FOUND \n***$figKey *******\n$figText\n****\n\n";
    }


    # Get the References, typically anchors beginning with a B
    while( $htmlArticle =~ /<a name=\"(B\w+)\">(.*?)(?=<a name)/msgi )
    {   
        my $tableAnchor = $1;
        my $refText = $2;

        $refText = CleanUp( $refText );

        $article{ REFERENCES }->{text} .= "\n$refText\n\n";
        $article{ REFERENCES }->{order} = 90;
    }


    # Strip out tables (mostly figures, etc) which should have been parsed out already
    $htmlArticle =~ s/<table[^>]+>.*?<\/table>//msgi;

    # Anchor-wise parse through the document...from one anchor to the next, keeping
    # track of the $CurrentSection, since not all anchors are created equal (e.g. only the
    # ones from the sidebars above are the meaningful ones...when we pass one, we update
    # $CurrentSection and the $order

    my $order = 0;
    my $CurrentSection = "";

    while( $htmlArticle =~ /<a name=\"(\w+)\">(.*?)(?=<a name)/msgi )
    {   
        my $tableAnchor = $1;
        my $tableContent = $2;


        #Check to see if we've triggered a major section change (these are from the side bar)
        if( exists( $sectionAnchors{$tableAnchor} ) )
        {   
            $CurrentSection = NormalizeName( $sectionAnchors{$tableAnchor} , $order);
            $article{$CurrentSection}->{order} = $order++;
            #	print "$CurrentSection GOT AN ORDER OF $article{$CurrentSection}->{order}\n";
        }

        #            print "\n\n-------- $tableAnchor - MajorSection $CurrentSection ------\n\n";

        #Save only the paragraphs
        while( ($tableContent =~ /<(p|br).*?>(.*?)(?=(<\/p>|$))/msgi ) && $CurrentSection)
        {   
            my $secText = $2;
            $secText = CleanUp( $secText );
            $article{$CurrentSection}->{text} .= "$secText\n";
        }
        # print "\n##########\n$article{$CurrentSection}->{text}\n########\n\n";
    }
    return \%article;
}










sub ParseOldHighWire()
{   my $htmlArticleRef = shift;
    my %article = (); 
    my @sideTables = (); 

    #
    # First...we go through and find the left-aligned tables...to get the meaningful section anchors
    #
    my %sectionAnchors = ();

    # Throw away footnotes for now!
    $$htmlArticleRef =~ s/<a name=\"R(FN\d+)\">.*?<a href=\"#FN\d+\">//msgi;

    if( $$htmlArticleRef =~ /<!--\s*#+\s+ARTICLE NAV\s+#+\s*-->.*?<dl>(.*?)<\/dl>/msgi ) 
    {   my $navTable = $1;
        while( $navTable=~ /<a href=\"?#(\w+?)\"?>(<img.*?.gif\">)((\w|\s)+).*?<\/a>/msgi )  
        {   my $sectionAnchor= $1;
            my $sectionName= $3;
            #print "ADDING SECTION: $sectionAnchor -- $sectionName\n";
            $sectionAnchors{$sectionAnchor} = $sectionName;
        }
    }

    #
    # Figures and tables get special treatment...they also go at the end (order=99)
    #
    while( $$htmlArticleRef =~ /<strong>(?>.*?)(fig.*?)<\/strong>(.*?)<hr>/msgi )
    {   #my $figKey = $tableAnchor;
        my $figKey = "table$1";
        my $figText= $2;

        $figText = CleanUp( $figText );

        if( $figText =~ /^<p>\s+Fig/i )
        {
            $figKey = "FIGURES";
        }
        elsif( $figText =~ /^<p>\s+Tab/i )
        {
            $figKey = "TABLES";
        }
        else
        {   #print STDERR "\n\nFIGURE TEXT WAS!!!!!!!!!!!! <$figText>\n\n";
            $figKey = "ADDITIONALTEXT";
        }

        $article{ $figKey }->{text} .= "\n$figText\n";
        $article{ $figKey }->{order} = 99;
        # print "FOUND \n***$figKey *******\n$figText\n****\n\n";
    }

    # Get the References, typically anchors beginning with a B
    while( $$htmlArticleRef =~ /<a name=\"(B\w+)\">(.*?)(?=<a name)/msgi )
    {   my $tableAnchor = $1;
        my $refText = $2;

        $refText = CleanUp( $refText );

        $article{ REFERENCES }->{text} .= "\n$refText\n\n";
        $article{ REFERENCES }->{order} = 90;
    }


    # Strip out tables (mostly figures, etc) which should have been parsed out already

    $$htmlArticleRef =~ s/<table[^>]+>.*?<\/table>//msgi;

    # Anchor-wise parse through the document...from one anchor to the next, keeping
    # track of the $CurrentSection, since not all anchors are created equal (e.g. only the
    # ones from the sidebars above are the meaningful ones...when we pass one, we update
    # $CurrentSection and the $order

    my $order = 0;
    my $CurrentSection = "";

    while( $$htmlArticleRef =~ /<a name\s*=\s*\"(\w+)\">(.*?)(?=<a name)/msgi )
    {   
        my $tableAnchor = $1;
        my $tableContent = $2; 

        #Check to see if we've triggered a major section change (these are from the side bar)
        if( exists( $sectionAnchors{$tableAnchor} ) )
        {
            $CurrentSection = NormalizeName( $sectionAnchors{$tableAnchor}, $order );
            $article{$CurrentSection}->{order} = $order++;
            #	print "$CurrentSection GOT AN ORDER OF $article{$CurrentSection}->{order}\n";
        }

        #            print "\n\n-------- $tableAnchor - MajorSection $CurrentSection ------\n\n";

        #Save only the paragraphs

        while( ($tableContent =~ /<(p|br).*?>(.*?)(?=(<\/p>|$))/msgi ) && $CurrentSection)
        {   
            my $secText = $2;

            $secText = CleanUp( $secText );
            $article{$CurrentSection}->{text} .= "$secText\n";
        }
        # print "\n##########\n$article{$CurrentSection}->{text}\n########\n\n";
    }
    return \%article;
}










# sub CleanUp
# This subroutine cleans the HTML text and convert it to a regular text file
sub CleanUp()
{   my $text = shift; 
    
    $text =~ s/<h(\d)>(.*?)<\/h(\d)>/<p>$2<\/p>/msgi;
    $text =~ s/<\/*(br|p)>/\n/gi;
    $text =~ s/<SUP>.*?<\/SUP>/ /g;
    $text =~ s/<img.*?alt=\"[ \{]*(~|alpha|beta|gamma|delta|epsilon|kappa|phi|psi|zeta)[ \}]*.*?>/ $1/gi;

    $text =~ s/\&hyp\;/\'/g;
    $text =~ s/\&hyphen\;/\'/gi;

    $text =~ s/\&#x0*3B1\;/alpha/gi;	# alpha
    $text =~ s/\&#x0*3B2\;/beta/gi;		# beta  
    $text =~ s/\&#x0*df\;/beta/gi;		# beta  
    $text =~ s/\&#223\;/beta/gi;		# beta  
    $text =~ s/\&#x0*3B3\;/gamma/gi;	# gamma
    $text =~ s/\&#x0*3B4\;/delta/gi;	# delta
    $text =~ s/\&#x0*3BA\;/kappa/gi;	# kappa
    
    $text =~ s/\&#x0*2010\;/-/g;		# dash
    $text =~ s/\&#x0*2013\;/ /g;		# ndash
    $text =~ s/\&#x0*2014\;/ /g;		# longdash    
    
    $text =~ s/\&#x0*2212\;/-/g;		# minus
    $text =~ s/\&#x0*2b\;/\+/g;			# plus
    $text =~ s/\&#x0*25\;/\%/g;			# plus    

    $text =~ s/\&#x0*3bc\;/u/g;			# micro
    $text =~ s/\&#x0*a0\;/ /g;			# non-breaking space but will be replaced with a space
    $text =~ s/\&#x0*b0\;/o/g;			# degree. such as in celciuos    

	$text =~ s/\&#x0*d7\;/x/g;			# degree. such as in celciuos   	
    
    $text =~ s/\&#x0*7B\;/\{/gi;
    $text =~ s/\&#x0*5B\;/\[/gi;
    $text =~ s/\&#x0*28\;/\(/g;
    $text =~ s/\&#x0*7D\;/\}/gi;
    $text =~ s/\&#x0*7D\;/\]/gi;
    $text =~ s/\&#x0*29\;/\)/g;
    $text =~ s/\&#x0*29\;/\)/g;
	# '
    $text =~ s/\&#x0*2032\;/\'/g;
    $text =~ s/\&#x0*2019\;/\'/g;
    $text =~ s/\&#x0*2018\;/\'/g;
    $text =~ s/\&#8242\;/\'/g;
    $text =~ s/\&#8217\;/\'/g;
    $text =~ s/\&#180\;/\'/g;
    $text =~ s/\&#37\;/\%/g;                            
    $text =~ s/\&#215\;/x/g;                            
    $text =~ s/\&#58\;/\:/g;                            
    $text =~ s/\&#91\;/\[/g;                            
    
    
	# "
    $text =~ s/\&#x0*201D\;/\"/gi;
    $text =~ s/\&#x0*201C\;/\"/gi;

    $text =~ s/&nbsp;/ /gi;


    $text =~ s/<\/*(.*?)>/ /g;

    $text =~ s/&/&amp;/g;
    $text =~ s/&amp;lt;/&lt;/gi;
    $text =~ s/&amp;gt;/&gt;/gi;
#    $text =~ s/&#176;/degree/gi;
#    $text =~ s/&#160;/ /gi;
#    $text =~ s/&#150;/-/gi;
#    $text =~ s/&#8211;/-/gi;
#    $text =~ s/&#146;/'/gi;
#    $text =~ s/&#145;/'/gi;
#    $text =~ s/&#181;/micro/gi;
#    
#    # alpha
#    $text =~ s/&amp;#x03B1;/A/gi;
#    $text =~ s/&amp;#945;/A/gi;    
#    
#    # beta
#    $text =~ s/&amp;#x03B2;/B/gi;
#    $text =~ s/&amp;#946;/B/gi;    
#    
#    # gamma
#    $text =~ s/&amp;#x03B3;/G/gi;
#    $text =~ s/&amp;#947;/G/gi;    
#
#    # Kappa
#    $text =~ s/&amp;#954;/kappa/gi;
#    $text =~ s/&amp;#x03Ba;/kappa/gi;
    
    my @paragraphs = split( /\n/, $text );
    $text = "";
    foreach my $paragraph (@paragraphs)
    {
        $text .= "<p>$paragraph<\/p>\n";
    }
    $text =~ s/\s+/ /g;
    $text =~ s/<p>\s+<\/p>//g;

    return $text;
}





