sub section_title_tag_remove_only
{   my $text		= shift;
	$text =~ s/<\w.*?>(.*?)<\/\w+>/$1/g;
	$text =~ s/&/&amp;/g;
	$text =~ s/&amp;#176;/degree/gi;
    $text =~ s/&amp;#160;/ /gi;
    $text =~ s/&amp;#150;/-/gi;
    $text =~ s/&amp;#8211;/-/gi;
    $text =~ s/&amp;#146;/'/gi;
    $text =~ s/&amp;#145;/'/gi;
    $text =~ s/&amp;#181;/micro/gi;
    #  ' 
    $text =~ s/&amp;#8216;/'/gi;
    $text =~ s/&amp;#8217;/'/gi;
    
    # alpha
    $text =~ s/&amp;#x03B1;/A/gi;
    $text =~ s/&amp;#945;/A/gi;    
    
    # beta
    $text =~ s/&amp;#x03B2;/B/gi;
    $text =~ s/&amp;#946;/B/gi;    
    
    # gamma
    $text =~ s/&amp;#x03B3;/G/gi;
    $text =~ s/&amp;#947;/G/gi;    

    # Kappa
    $text =~ s/&amp;#954;/kappa/gi;
    $text =~ s/&amp;#x03Ba;/kappa/gi;
    
    $text =~ s/<\w.*?>//g;
    
    $text =~ s/&amp;nbsp;//g;
    $text =~ s/&nbsp;//g;
    
	return ($text);
}










sub xmlCleanUp
{   my ($text) = @_;
    $text =~ s/&amp;amp;/&/g;

    $text =~ s/&amp;nbsp;/ /gi;
    $text =~ s/&amp;lt;/&lt;/gi;
    $text =~ s/&amp;gt;/&gt;/gi;

    $text =~ s/&amp;#176;/degree/gi;
    $text =~ s/&amp;#160;/ /gi;
    $text =~ s/&amp;#150;/-/gi;
    $text =~ s/&amp;#146;/'/gi;
    $text =~ s/&amp;#145;/'/gi;
    $text =~ s/&amp;#151;/-/gi;     #Em-Dash
    $text =~ s/&amp;#181;/micro/gi;
    $text =~ s/&amp;#183;/-/gi;     #Middle-Dot
    return ($text);
}




