sub NormalizeName()
{   my $sectionName = shift;
    my $order       = shift;

	my $knownName = 0;

 	if( $sectionName =~ /abstract/i ) 		            	{ $sectionName = "ABSTRACT"; $knownName = 1; }
	elsif( $sectionName =~ /material|method|implementation|procedure/i ) 	
															{ $sectionName = "METHODS"; $knownName = 1; }
	elsif( $sectionName =~ /reference/i ) 		            { $sectionName = "REFERENCES"; $knownName = 1; }
	elsif( $sectionName =~ /conclusion/i ) 		        	{ $sectionName = "CONCLUSION"; $knownName = 1; }
	elsif( $sectionName =~ /discussion/i ) 		        	{ $sectionName = "DISCUSSION"; $knownName = 1; }
	elsif( $sectionName =~ /result/i ) 		            	{ $sectionName = "RESULTS"; $knownName = 1; }
	elsif( $sectionName =~ /background/i ) 	            	{ $sectionName = "INTRODUCTION"; $knownName = 1; }
	elsif( $sectionName =~ /introduction/i ) 	            { $sectionName = "INTRODUCTION"; $knownName = 1; }
	elsif( $sectionName =~ /outline/i ) 		            { $sectionName = "OUTLINE"; $knownName = 1; }
	elsif( $sectionName =~ /author/i ) 		            	{ $sectionName = "AUTHORS"; $knownName = 1; }
	elsif( $sectionName =~ /acknowledge?ment/i ) 		    { $sectionName = "ACKNOWLEDGMENTS"; $knownName = 1; }
	elsif( $sectionName =~ /footnote/i ) 		    		{ $sectionName = "FOOTNOTES"; $knownName = 1; }
	elsif( $sectionName =~ /abbreviation/i ) 		   		{ $sectionName = "ABBREVIATIONS"; $knownName = 1; }
	elsif( $sectionName =~ /<p>/i && $order == 0) 	        { $sectionName = "TITLE"; $knownName = 1; }
	else
	{   $sectionName = "UNKNOWN";
	}
    return $sectionName;
}










sub auto_generate_xml_from_html_or_generic_parser
{   my $pmid                = shift;
    my $htmlFile            = shift;
    my $passedStatus        = shift;
    my $articleHash         = shift;
    my $outputXMLFile       = shift;
    my $genericParser       = shift;
    my $parsingStatusRef    = shift;

    if ($passedStatus == 1)
    {   my $parsedXMLRef   = generate_XML_from_article_hash($pmid, $articleHash);
        if (length($$parsedXMLRef) > 100)
        {   # If longer than 100, it's likely that the parsing was successful.
            $$parsingStatusRef = 1;
            open (OUT, ">".$outputXMLFile);
            $$parsedXMLRef =~ s/<p><\/p>//g;
			print OUT $$parsedXMLRef;
            close OUT;
        }else
        {	`$genericParser $htmlFile > $outputXMLFile`;
			if ((-f $outputXMLFile) && (-s $outputXMLFile > 100))
			{   $$parsingStatusRef = 1;
			}else
			{   # ---- HTML5 Fallback Parser (added 2026-03) ----
			    # Try to extract text from modern HTML5 semantic elements
			    my $html5Result = _html5_fallback_extract($htmlFile, $pmid);
			    if (defined $html5Result && length($$html5Result) > 100)
			    {   $$parsingStatusRef = 1;
			        open (OUT, ">".$outputXMLFile);
			        print OUT $$html5Result;
			        close OUT;
			    }else
			    {   $$parsingStatusRef = 0;
			    }
			}
        }
    }else
    {   # ---- Attempt HTML5 fallback for failed primary parsers (added 2026-03) ----
        `$genericParser $htmlFile > $outputXMLFile`;
		if ((-f $outputXMLFile) && (-s $outputXMLFile > 100))
		{   $$parsingStatusRef = 1;
		}else
		{   my $html5Result = _html5_fallback_extract($htmlFile, $pmid);
		    if (defined $html5Result && length($$html5Result) > 100)
		    {   $$parsingStatusRef = 1;
		        open (OUT, ">".$outputXMLFile);
		        print OUT $$html5Result;
		        close OUT;
		    }else
		    {   $$parsingStatusRef = 0;
		    }
		}
    }
}


# =============================================================================
# _html5_fallback_extract($htmlFile, $pmid)
#
# Fallback parser for modern HTML5 publisher pages.
# Extracts text from semantic HTML5 elements: <article>, <main>, <section>.
# Strips navigation, footer, sidebar, and non-content elements.
# Returns reference to XML string in SciMiner format, or undef on failure.
#
# Added 2026-03 to handle modern publisher HTML5 pages.
# =============================================================================
sub _html5_fallback_extract
{   my $htmlFile = shift;
    my $pmid     = shift;

    return undef unless (-f $htmlFile);

    open (HTMLIN, $htmlFile) || return undef;
    my @lines = <HTMLIN>;
    close HTMLIN;

    my $html = join(' ', @lines);
    $html =~ s/\r\n|\r/\n/g;
    $html =~ s/\s+/ /g;

    # Try to find main content area using HTML5 semantic elements
    my $contentArea = '';

    # Priority 1: <article> element (most specific)
    if ($html =~ /<article[^>]*>(.*?)<\/article>/si)
    {   $contentArea = $1;
    }
    # Priority 2: <main> element
    elsif ($html =~ /<main[^>]*>(.*?)<\/main>/si)
    {   $contentArea = $1;
    }
    # Priority 3: role="main" attribute
    elsif ($html =~ /<div[^>]*role\s*=\s*"main"[^>]*>(.*?)<\/div>/si)
    {   $contentArea = $1;
    }
    # Priority 4: Common CSS class names for content areas
    elsif ($html =~ /<div[^>]*class\s*=\s*"[^"]*(?:article-content|content-body|article-body|fulltext-view|paper-content)[^"]*"[^>]*>(.*?)<\/div>/si)
    {   $contentArea = $1;
    }
    # Priority 5: Just use body content
    elsif ($html =~ /<body[^>]*>(.*?)<\/body>/si)
    {   $contentArea = $1;
    }

    return undef if ($contentArea eq '');

    # Remove non-content elements
    $contentArea =~ s/<nav[^>]*>.*?<\/nav>//sig;
    $contentArea =~ s/<footer[^>]*>.*?<\/footer>//sig;
    $contentArea =~ s/<header[^>]*>.*?<\/header>//sig;
    $contentArea =~ s/<aside[^>]*>.*?<\/aside>//sig;
    $contentArea =~ s/<script[^>]*>.*?<\/script>//sig;
    $contentArea =~ s/<style[^>]*>.*?<\/style>//sig;
    $contentArea =~ s/<noscript[^>]*>.*?<\/noscript>//sig;
    $contentArea =~ s/<iframe[^>]*>.*?<\/iframe>//sig;
    # Remove elements with typical non-content class names
    $contentArea =~ s/<div[^>]*class\s*=\s*"[^"]*(?:sidebar|nav|menu|footer|header|banner|advert|cookie|popup|modal|overlay)[^"]*"[^>]*>.*?<\/div>//sig;

    # Extract text from sections
    my %article = ();
    my $order   = 0;

    # Try to extract sections from <section> or <div> with heading elements
    while ($contentArea =~ /<(?:section|div)[^>]*>(.*?)<\/(?:section|div)>/sig)
    {   my $secContent = $1;
        my $secTitle   = 'UNKNOWN';

        # Look for heading elements
        if ($secContent =~ /<h[1-6][^>]*>(.*?)<\/h[1-6]>/si)
        {   $secTitle = $1;
            $secTitle =~ s/<[^>]+>//g;  # strip tags
            $secTitle =~ s/^\s+|\s+$//g;
        }

        my $normalizedName = &NormalizeName($secTitle, $order);

        # Extract paragraph text
        my $secText = '';
        while ($secContent =~ /<p[^>]*>(.*?)<\/p>/sig)
        {   my $pText = $1;
            $pText =~ s/<[^>]+>//g;  # strip all tags
            $pText =~ s/&nbsp;/ /gi;
            $pText =~ s/&amp;/&/g;
            $pText =~ s/&lt;/</g;
            $pText =~ s/&gt;/>/g;
            $pText =~ s/\s+/ /g;
            $pText =~ s/^\s+|\s+$//g;
            if ($pText ne '' && length($pText) > 20)
            {   $secText .= "<p>$pText</p>\n";
            }
        }

        if ($secText ne '')
        {   $article{$normalizedName}->{text}  .= $secText;
            $article{$normalizedName}->{order} = $order
                unless defined $article{$normalizedName}->{order};
            $order++;
        }
    }

    # If no sections found, just extract all paragraphs
    if (scalar(keys %article) == 0)
    {   my $allText = '';
        while ($contentArea =~ /<p[^>]*>(.*?)<\/p>/sig)
        {   my $pText = $1;
            $pText =~ s/<[^>]+>//g;
            $pText =~ s/&nbsp;/ /gi;
            $pText =~ s/&amp;/&/g;
            $pText =~ s/\s+/ /g;
            $pText =~ s/^\s+|\s+$//g;
            if ($pText ne '' && length($pText) > 20)
            {   $allText .= "<p>$pText</p>\n";
            }
        }
        if ($allText ne '')
        {   $article{UNKNOWN}->{text}  = $allText;
            $article{UNKNOWN}->{order} = 0;
        }
    }

    # Generate XML output
    if (scalar(keys %article) > 0)
    {   return generate_XML_from_article_hash($pmid, \%article);
    }

    return undef;
}




































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































































# ---------------------------------------------------------------------------
# sub Name_Symbol_Summary_Merge
# ---------------------------------------------------------------------------
# Last modifed: 08/11/2007
# Last modified: 11/30/2006
# Description: This subroutin will merge two summary files; one for symbol
#              and the other for name mining. 
# ---------------------------------------------------------------------------
sub Name_Symbol_Summary_Merge
{   my ($symSumFile, $namSumFile, $merSumFile) = @_;
    open (SYMBOL, $symSumFile) || die "! Can't open $symSumFile\n\n";
    open (MERGE, ">".$merSumFile) || die "! Can't open $merSumFile\n\n";
    open (NAME, $namSumFile) || die "! Can't open $namSumFile\n\n";
    
    my (@symbol, %symbol2ID, %symbol2Desc, %symbol2Occurence, 
        %symbol2Papers, %symbol2MatchStr, %symbol2PMID);
    while(<SYMBOL>)
    {   my $line = $_;      $line =~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        push @symbol, $tmp[0];
        $symbol2ID{$tmp[0]} = $tmp[1];
        $symbol2Desc{$tmp[0]} = $tmp[2];
        $symbol2Occurence{$tmp[0]} = $tmp[3];
        $symbol2Papers{$tmp[0]} = $tmp[4];
        $symbol2MatchStr{$tmp[0]} = $tmp[5];
        $symbol2PMID{$tmp[0]} = $tmp[6];
    }   close SYMBOL;

    while(<NAME>)
    {   my $line = $_;      $line =~ s/\r|\n//g;
        my @tmp = split (/\t/, $line);
        if (not defined $symbol2ID{$tmp[0]})
        {   push @symbol, $tmp[0];
            $symbol2ID{$tmp[0]} = $tmp[1];
            $symbol2Desc{$tmp[0]} = $tmp[2];
            $symbol2Occurence{$tmp[0]} = $tmp[3];
            $symbol2Papers{$tmp[0]} = $tmp[4];
            $symbol2MatchStr{$tmp[0]} = $tmp[5];
            $symbol2PMID{$tmp[0]} = $tmp[6];
        }else
        {   # Add occurrence
            $symbol2Occurence{$tmp[0]} += $tmp[3];
            # $symbol2Papers{$tmp[0]} += $tmp[4];

            # PMID check
            my @PMIDSplit = split (/\<_\>/, $tmp[6]);
            foreach (@PMIDSplit)
            {   my $checkKey = $_.'<_>';
                if ( $symbol2PMID{$tmp[0]} =~ /$checkKey/)
                {   # No need to add
                }else
                {   $symbol2PMID{$tmp[0]} .= $checkKey;
                    $symbol2Papers{$tmp[0]}++;
                }   
            }
            
            # Matched String check
            my @MatchStrSplit = split (/\<_\>/, $tmp[5]);
            foreach (@MatchStrSplit)
            {   my $checkKey = $_.'<_>';
                if ( $symbol2MatchStr{$tmp[0]} =~ /$checkKey/)
                {   # No need to add
                }else
                {   $symbol2MatchStr{$tmp[0]} .= $checkKey;
                }   
            }
        }
    }   close NAME;

    @symbol = sort (@symbol);
    foreach (@symbol)
    {   print MERGE $_."\t".$symbol2ID{$_}."\t".$symbol2Desc{$_}."\t".
                    $symbol2Occurence{$_}."\t".$symbol2Papers{$_}."\t".
                    $symbol2MatchStr{$_}."\t".$symbol2PMID{$_}."\n";
    }

    print "\n\tNum of Total Merged Symbols: ".(scalar @symbol)."\n\n";
}


























































































