# ---------------------------------------------------------------------------
# sub conjunctionPrepositionRemovalForSymbol
# ---------------------------------------------------------------------------
# Last modified: 09/26/2006
# Description: This subroutin replaces special characters with a space. 
# Return: A processed string
# ---------------------------------------------------------------------------
sub conjunctionPrepositionRemovalForSymbol
{   my ( $localString ) = @_;
	$localString =~ s/\,|\.|\)|\(|\*|\[|\]|\!|\?/ /g;
	return ( $localString );
}






# ---------------------------------------------------------------------------
# sub Converter_MEDLINE2Simple
# ---------------------------------------------------------------------------
# Last modified: 09/25/2006
# Description: This subroutin read a Medline formatted document file and 
#              convertes it into a simple format only with Title and Abstract
# Input: $inFile : Medline formatted document file
#        $outFile : Target file for simplified format
# Return: None
# ---------------------------------------------------------------------------
sub Converter_MEDLINE2Simple
{   my ( $inFile, $outFile)  = @_;
    open ( FILE, $inFile ) || die "!Converter_MEDLINE2Simple can't read \n\t$inFile\n\n";
    open ( RESULT, ">".$outFile) || die "!Converter_MEDLINE2Simple can't write to \n\t$outFile\n\n";
	my $previousField = '';
	while ( <FILE> )
	{   my $MedLineLine=$_;   $MedLineLine =~ s/\r|\n//g;
	    if ($MedLineLine eq "")
	    {   next;
	    }elsif (substr($MedLineLine,4, 1) eq '-')
        {   $previousField = '';
        }
	    if ( $MedLineLine =~ /^PMID\-\s+(\d+)/ )
		{   print RESULT "\n\#$MedLineLine";
            #$currentPMID=$1;  
			$previousField=''; 	 
		}elsif ( $MedLineLine eq "\n" )
		{    # do nothing	   	
		}elsif (( substr($MedLineLine,0,5) eq 'TI  -' ) || ( substr($MedLineLine,0,5) eq 'AB  -' ))   
		{    print RESULT "\n\#$MedLineLine";
			 $previousField = substr($MedLineLine,0,5);			  
		}elsif (( substr($MedLineLine,0,6) eq '      ' ) && (( $previousField eq 'TI  -' ) || ( $previousField eq 'AB  -' )) )   # ������ �ƴϰ�, �տ� 6ĭ�� ����ִ� ��� 
		{    substr($MedLineLine,0,5 ) ='';
			 print RESULT $MedLineLine;
		}
	}   
	print RESULT "\n#PMID- 9999999\n";
	close FILE;   close RESULT;
}


#'
# ---------------------------------------------------------------------------
# sub eutils_Search_Download
# ---------------------------------------------------------------------------
# Last modified: 09/25/2006
# Description: This subroutin perform a search against NCBI databases through 
#              eUtilities and fetch the resulting documents to a designated
#              file. 
# Input: $db : DB name such as Pubmed)
#        $query : search term(s) like Reactive Oxygen Species[MeSH]
#        $outDire : directory for result file
#        $report : output document format
#        $retmax : number of documents per single fetching
#        $displayProgress : option to refresh the progress
#        $OSType : windows or linux
# Return: $count : Number of the total searched documents
# ---------------------------------------------------------------------------
sub eutils_Search_Download
{   my $db = $_[0];
    my $query = $_[1];
	my $report = $_[2];
	my $outDir = $_[3];
	my $retmax = $_[4];
	my $displayProgress = $_[5];
	my $OSType = $_[6];
    my $tmpFileName = $_[7];

	my $outFile = '';
	my $utils = "http://www.ncbi.nlm.nih.gov/entrez/eutils";
	my $eSearch = $utils."/esearch.fcgi?".
	              "db=$db&retmax=1&usehistory=y&term=";
	my $eSearch_result = get($eSearch . $query);

	# Check if eSearch request succeeded
	if (!defined $eSearch_result || $eSearch_result eq '') {
	    warn "eutils_Search_Download: eSearch request failed for query: $query";
	    return (0);
	}

	# Check total number of documents to download
	$eSearch_result =~ m|<Count>(\d+)</Count>.*<QueryKey>(\d+)</QueryKey>.*<WebEnv>(\S+)</WebEnv>|s;
	my $count = $1;	    my $queryKey = $2;	    my $webEnv = $3;

	if ((not defined $count) || ($count eq ""))
	{   return (0);
	}
	#else
	#{   print "\nNumber of documents to be downloaded ".$count." articles to be downloaded.\n";
	#}

	my $retstart = 0;
    # Parameter check
	if((not defined $retmax) || ($retmax eq ""))
	{   $retmax = 250;
	}

	if ((not defined $tmpFileName) || ($tmpFileName eq ""))
	{   my $tmpQuery = $query;
        $tmpQuery =~ s/\//\_/g;
		$outFile = $tmpQuery."_".$report."_".$count.'.raw';
	}else
	{   $outFile = $tmpFileName."_".$report."_".$count.'.raw';
	}

	open ( RESULT, ">".$outDir.$outFile ) || die "Can't write to $outFile\n\n";
	for ($retstart = 0; $retstart < $count; $retstart += $retmax)
	{   my $efetch = "$utils/efetch.fcgi?" .
				     "rettype=$report&retmode=text&retstart=$retstart&retmax=$retmax&" .
				     "db=$db&query_key=$queryKey&WebEnv=$webEnv";
    	my $efetch_result = get($efetch);
		# Skip failed fetches instead of writing undef
		if (!defined $efetch_result) {
		    warn "eutils_Search_Download: efetch request failed at retstart=$retstart";
		    next;
		}
		print RESULT $efetch_result."\n";
		if ($displayProgress eq 'True')
		{   my $percentCompleted= int ($retstart / $count * 100 );
		    display_clear($OSType);
		    print_menu_title_bar("PubMed Download Progress");
		    print "\tQuery               : ".$query."\n".
		          "\tTotal articles      : ".$count."\n".
		          "\tDownloaded articles : ".($retstart + $retmax)."\n".
		          "\tComplete percentage : ".$percentCompleted.'%'."\n\n";
		}
		sleep(3);
	}	close RESULT;
	
	return ($count, $outFile);
}   #end sub eutils_NCBI_search

sub fileListDisply {
 
        my ( $shortFileName ) = @_;
        my $totalFileNumber = scalar ( @$shortFileName );
 
        use strict;
        use warnings;
 
        print     "\n\t###############################################################\n";
        print "\t\t\tTarget File Selection Menu\n";
        print     "\t###############################################################\n\n";
        print "\tNumber\tFileName\n\n";
        for ( my $i=0;  $i < $totalFileNumber ; $i++ )
        {
                print "\t$i\t@$shortFileName[$i]\n";
        }
 
}

sub FileListDisplayAndSelection
{
	my ($OriginalShortFile) = @_;
	my $OriginalFileCount = scalar @$OriginalShortFile;
#	print @$OriginalShortFile[0];
	
	InitialOriginalFileListDisplay:     	  #Location Marker for Display Init.
	my @finalTargetFileCheck=();
	
	OriginalFileListDisplay:
	display_clear();						   	  #Clear the screen.		
	print "###############################################################################\n";
	print "\t\tList of MEDLINE Files in a MEDLINE Format\n";
	print "###############################################################################\n\n";
	
	for ( my $i=0; $i < $OriginalFileCount ; $i++ )
	{
	 	  print "   $i\t".@$OriginalShortFile[$i];
		  my $leftStringLength = length ( "\t$1\t@$OriginalShortFile[$i]" );
		  my $totalLength = 70;
		  if ( $finalTargetFileCheck[$i] eq "" )
		  {	   $finalTargetFileCheck[$i] = 'NO';  }
		  my $outputStringLength = length ( $finalTargetFileCheck[$i] );
		  my $centralBlankLength = $totalLength - $leftStringLength -  $outputStringLength ;
	
		  for ( my $j=0; $j < $centralBlankLength ; $j++ )
		  {
		   	  	print " ";
		  }
		  print $finalTargetFileCheck[$i]."\n";
	}
	print "\n   A.\tProcess All Files.\t";
	print "   S.\tStop the current process\n";
	print "   R.\tReset to none\t\t";
	print "   E.\tExecute the queud files \n\n";
	
	print "   Please select a target MEDLINE file: ";
	chomp ( my $resultFileUserSelection =<STDIN>);
	if (   lc($resultFileUserSelection) eq 's' )
	{
	   	   print "Process was stopped by user interupt...\n";    exit;
	}elsif ( lc($resultFileUserSelection) eq 'a' )
	{
	 	   my $i=0;
	 	   for ( $i=0; $i < $OriginalFileCount ; $i++ )
		   {
		   	   	 $finalTargetFileCheck[$i]='EXE';
		   }
		   #$finalTargetFileNumber=$i;
		   goto OriginalFileListDisplay;
	}elsif ( lc($resultFileUserSelection) eq 'r' )
	{
	 	   goto InitialOriginalFileListDisplay;
	}elsif ( lc($resultFileUserSelection) eq 'e' ) 
	{
	 	   return ( @finalTargetFileCheck );
	}else   
	{
	 	   if ( $finalTargetFileCheck[$resultFileUserSelection] eq 'EXE' )
		   {
		   	  	$finalTargetFileCheck[$resultFileUserSelection]='NO';
		   }else
		   {
		   		$finalTargetFileCheck[$resultFileUserSelection]='EXE';
		   }
	 	   goto OriginalFileListDisplay;	   					
	}	
}


# ---------------------------------------------------------------------------
# sub special_character_handling_for_hash_key
# ---------------------------------------------------------------------------
# Last modified: 10/08/2006
# Description: This subroutin takes care of special character for hash keys
# Return: Modified hash key
# ---------------------------------------------------------------------------
sub special_character_handling_for_hash_key
{   my ($transferred) = @_;
    $transferred =~ s/\+/\\\+/g;
	#$transferred =~ s/\-/\\\-/g;
	$transferred =~ s/\?/\\\?/g;
	$transferred =~ s/\'/\\\'/g;
	$transferred =~ s/\"/\\\"/g;
	$transferred =~ s/\`/\\\`/g;
	$transferred =~ s/\./\\\./g;
	$transferred =~ s/\,/\\\,/g;
	$transferred =~ s/\*/\\\*/g;
	$transferred =~ s/\%/\\\%/g;
	$transferred =~ s/\$/\\\$/g;
	$transferred =~ s/\[/\\\[/g;
	$transferred =~ s/\]/\\\]/g;
	$transferred =~ s/\@/\\\@/g;
	$transferred =~ s/\#/\\\#/g;
	$transferred =~ s/\//\\\//g;
	$transferred =~ s/\(/\\\(/g;
	$transferred =~ s/\)/\\\)/g;    
	$transferred =~ s/\^/\\\^/g;
    $transferred =~ s/\|/\\\|/g;
	return ($transferred);
}


sub braket_character_replaced_by_space
{   my ($transferred) = @_;
    $transferred =~ s/[\(|\)|\{|\}|\[|\]|\+|\?|\!|\,|\;|\:|\||\/]/ /g;
    return ($transferred);
}



