}




# ---------------------------------------------------------------------------
# sub eutils_Search_Count_Only
# ---------------------------------------------------------------------------
# Last modified: 10/01/2006
# Description: This subroutin returns the total number of articles per 
#              PubMed search with given query terms. No actual retrieval.
# Return: The number of searched article. 
# --------------------------------------------------------------------------- 
sub eutils_Search_Count_Only
{   my $db = $_[0];
    my $query = $_[1];
    my $utils = "http://www.ncbi.nlm.nih.gov/entrez/eutils";
    my $eSearch = $utils."/esearch.fcgi?".
                      "db=$db&retmax=1&usehistory=y&term=";
    my $eSearch_result = get($eSearch . $query);

    # Check if eSearch request succeeded
    if (!defined $eSearch_result || $eSearch_result eq '') {
        warn "eutils_Search_Count_Only: eSearch request failed for query: $query";
        return (0);
    }

    # Check total number of documents to download
    $eSearch_result =~ m|<Count>(\d+)</Count>.*<QueryKey>(\d+)</QueryKey>.*<WebEnv>(\S+)</WebEnv>|s;
    my $count = $1;            my $queryKey = $2;            my $webEnv = $3;
    if ((not defined $count) || ($count eq ""))
    {   return (0);
    }else
    {   return ($count);
    }
}   #end sub eutils_NCBI_search

sub mined_symbol_result_printout
{   my ($pubmedID, $miningSource, $contents, $ID2SymbolHash, $UNIQSYM2IDHash, 
        $UNIQSYMHASHLOWKEY2HUGO, $UNIQSYMHASHLOWKEY2ORIGINAL, $FILEHANDLE ) = @_;
    print $FILEHANDLE $pubmedID."\t".$miningSource."\t";
    my @localTempSplit=split(/\<\_\>/,$contents);
    print RESULT $$ID2SymbolHash{$$UNIQSYM2IDHash{$localTempSplit[0]}}."\t".
                 $localTempSplit[1]."\t".$localTempSplit[2]."\t".
                 $localTempSplit[0]."\n";
    
}









# ---------------------------------------------------------------------------
# sub HUGO_Name_Parsing_Only
# ---------------------------------------------------------------------------
# Last modified: 10/10/2006
# Description: This subroutin parses out gene symbol or names.
# Return: An array of matched result
# ---------------------------------------------------------------------------
sub HUGO_Name_Parsing_Only
{   my ($searchTargetFileName, $finalResultFileName,
		$ID2SymbolHash, $ID2NameHash,
		$ID2GeneIDHash, $ID2PubMedHash, $ID2UniProtHash,
		$UNIQSYMArray, $UNIQSYM2IDHash, $UNIQNAMEArray, $UNIQNAME2IDHash,
		$SEARCHMODE, $UNIQNAME2ORIGINAL) = @_;
	my ($pubmedID, $abstract, $title, @titleSplit,
		@abstractLineSplit, @foundHUGOContent, $foundHUGONumber);

    # ------------------------------------------------------------------------
	#      Gene Name Search Mode 
	# ------------------------------------------------------------------------
	my $numOfFoundGeneNames = 0;
	if ($SEARCHMODE eq 'Name' )
	{	print "Processing Gene Names\n";
	    open ( FILE, $searchTargetFileName );
		open ( RESULT, ">".$finalResultFileName);
		while ( <FILE> )
		{   my $line=$_;   $line =~ s/\r|\n//g;
			if ( $line=~ /^\#PMID\-\s+(\d+)/ )
			{   $pubmedID=$1;
				$abstract='';			$title='';
				@titleSplit=();			@abstractLineSplit=();
				@foundHUGOContent=();	$foundHUGONumber=0;
			}elsif ($line=~ /^\#TI\s+\-\s+(\S.*)$/ )
			{	$title = $1;
				@foundHUGOContent = Compare_GeneName_New(\$title,
					$UNIQNAMEArray, $UNIQNAME2IDHash, $ID2NameHash, $ID2SymbolHash, $UNIQNAME2ORIGINAL );
				if (defined $foundHUGOContent[0])
				{   for ( my $l=0; $l < scalar ( @foundHUGOContent ) ; $l++ )
					{   print RESULT $pubmedID."\tTITLE\tNAME\t";
						my @localTempSplit=split(/\<\_\>/,$foundHUGOContent[$l]);
						foreach (@localTempSplit)
						{   print RESULT $_."\t";
						}   print RESULT "\n";
					}
				}
			}elsif ( $line=~ /^\#AB\s+\-\s+(\S.*)$/ ) 
			{   $abstract = $1;
			    # Splitting by '. ' is not a perfect way for symbol matching
				# this would not make any difference from complicated splitter.
				@foundHUGOContent = Compare_GeneName_New(\$abstract,
					$UNIQNAMEArray, $UNIQNAME2IDHash, $ID2NameHash, $ID2SymbolHash, $UNIQNAME2ORIGINAL );
				if (defined $foundHUGOContent[0])
				{   for ( my $l=0; $l < scalar ( @foundHUGOContent ) ; $l++ )
					{   print RESULT $pubmedID."\tABSTRACT\tNAME\t";
						my @localTempSplit=split(/\<\_\>/,$foundHUGOContent[$l]);
						foreach (@localTempSplit)
						{   print RESULT $_."\t";
						}   print RESULT "\n";
						$numOfFoundGeneNames += 1;
						print "\t$numOfFoundGeneNames\t".$foundHUGOContent[$l]."\n";
					}
				}
			}
		}   close FILE;		close RESULT;
	}
	return(@foundHUGOContent);
}  # End of Subroutin HUGO_Symbol_Name_Parsing



sub first_chr_keep_upper_other_lower_case
{   my ($transferred) = @_;
    my $firstChr = substr($transferred, 0, 1);
    substr($transferred, 0, 1) = '';
    $transferred =~ tr/[A-Z]/[a-z]/;
    $firstChr .= $transferred;
    return ($firstChr);

}
















# ---------------------------------------------------------------------------
# sub check_exclusion_list
# sub check_inclusion_list
# ---------------------------------------------------------------------------
# This version use a word-bounday (\b) in the regular expression
# TODO: Need to check why only this sub-routine use the word boundary (\b)
sub SciMiner_check_exclusion_list
{   my ($wholeTextContentRef, $EXCLUDESYMBOLCOND) = @_;
    my $exclusionFound = 0;
    foreach my $excKey ( @{$EXCLUDESYMBOLCOND} )
    {   my $NewExcKey = special_character_handling_for_hash_key($excKey);
        if ($$wholeTextContentRef =~ /\b$NewExcKey/i)
        {   # If there is any EXCLUSION word(s) in the whole text
            $exclusionFound = 2;
            return ($exclusionFound, $NewExcKey);
        }
    }   return ($exclusionFound, "");
}

sub SciMiner_check_inclusion_list
{   my ($wholeTextContentRef, $INCLUDESYMBOLCOND) = @_;
    my $inclusionFound = 0;
    foreach my $incKey ( @{$INCLUDESYMBOLCOND} )
    {   if ((defined $incKey) && ($incKey ne ""))
        {   my $NewIncKey = special_character_handling_for_hash_key($incKey);
            if ($$wholeTextContentRef =~ /$NewIncKey/i)
            {   # If there is any EXCLUSION word(s) in the whole text
                $inclusionFound = 1;
                return ($inclusionFound, $NewIncKey);
            }
        }
    }   return ($inclusionFound, "");
}







sub get_file_size_in_human_readable_format
{   my $fileName	= shift;
	if (-e $fileName)
	{	my $fileSize	= -s $fileName;
		my $kb			= 1024;
		my $mb			= $kb*1024;
		my $gb			= $mb*1024;
		if ((0< $fileSize) && ($fileSize < $kb))
		{   return ($fileSize.'B');
		}elsif (($kb <= $fileSize) && ($fileSize < $mb))
		{   $fileSize = (int($fileSize/$kb));
			return ($fileSize.'KB');
		}elsif (($mb <= $fileSize) && ($fileSize < $gb))
		{   $fileSize = (int($fileSize/$mb));
			return ($fileSize.'MB');
		}else
		{   $fileSize = (int($fileSize/$gb));
			return ($fileSize.'GB');
		}
	}else
	{   return ("0B");
	}



}


















































































































































































































































































































