    {   $initialSymbolCount = get_file_line_count("$finalResultWebDir/SciMinerBase.Symbol.txt") -1;
    }
    if (-f "$finalResultWebDir/SciMinerBase.Symbol.Optout.txt")
    {   $optoutSymbolCount = get_file_line_count("$finalResultWebDir/SciMinerBase.Symbol.Optout.txt") -1;
