    {   $finalMergedGeneCount = get_file_line_count("$finalResultWebDir/SciMinerBase.MerSum.sorted.txt") -1;
    }
    
    open (FULLMESHRESULTHTML, ">$finalResultWebDir/MeSHCodeDistribution.html");
	
    open (RESULT, ">".$resultHTMLFile);
