			        <title>SciMiner Result Report Page</title>
			        <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
			        <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
			        <script language=\"JavaScript1.2\" src=\"$sciminerJScriptFileName\"></script>
			        <style type=\"text/css\"> body {	margin-left:10px;	}</style>
			        </head>
			        <body bgcolor=\"#EAF4F4\" onload=\"switch_to_simple_mode_on_load()\">
			        <script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
			        <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Result Report Page</b></p>
			        <p class='titleBarName1'> <b>Congratulation! Your query with SciMiner has been successfully completed. Your query and search options were </b></p>

			        <a id=\"flag1\" href=\"#\" onclick=\"showhide('div1','flag1', 'search option summary');\" class=\"smallTextBold2\">[ HIDE search option summary ]</a>
					<div id=\"div1\" style=\"display:inline\">
			
			        <table border=\"1\" width=\"850\">
			        ";
				        
     
     print FULLMESHRESULTHTML "<head>
                <title>SciMiner Full MeSH Enrichment</title>
                <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
                <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
                <script language=\"JavaScript1.2\" src=\"$sciminerJScriptFileName\"></script>
                <style type=\"text/css\"> body {	margin-left:10px;	}</style>
                </head>
                <body bgcolor=\"#EAF4F4\" onload=\"switch_to_simple_mode_on_load()\">
                <script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
                <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Full MeSH Enrichment</b></p>
     						";
     						         
                
    # Running condition (options)
    my %itemContent		= ();
