            <p align =\"center\" class=\"sectionTitleName2\">Result files</p> 
            <p class=\"titleBarName1\">Here are the raw result files of SciMiner mining. If you are interested in seeing all the individual identification results, these files are useful to you. These files can also be useful in your generating customary filters. For example, check the <b>Filtered out</b> results, to see any targets you are quite certain that should be included in the result. Put such targets into your <b>INCLUDE</b> filter list and run the same query again. <br><br>These files are usually large and we recommend you save these files and  load them in a text editor or in EXCEL. Check <a href=\"../../Files/SciMinerResultFileFormat.html\"><b>File Format</b></a> of these files.<br>
            
            <table width=\"550\" border=\"1\">
		        <tr class='titleBarName1'>
		            <th width=\"150\">&nbsp;</th>
		            <th width=\"100\" onmouseover=\"Tip('The <b>original</b> SciMiner identification result <b>before</b> applying any filters and score threshold.')\" onmouseout=\"UnTip()\">Before filtering</th>
		            <th width=\"100\" onmouseover=\"Tip('The SciMiner identification result <b>after</b> applying any filters and score threshold.')\" onmouseout=\"UnTip()\">After filtering</th>
		            <th width=\"100\" onmouseover=\"Tip('The SciMiner identification result <b>after</b> that were <b>removed</b> by filters and score threshold.')\" onmouseout=\"UnTip()\">Filtered out</th>
		            <th width=\"100\" onmouseover=\"Tip('Target based summary after applying any filters and score threshold.')\" onmouseout=\"UnTip()\">Unique targets</th>
		        </tr>
		        <tr class='titleBarName1'>
		            <th width=\"150\" onmouseover=\"Tip('SciMiner target recognition system uses two different approaches; <br>one based on single word acronyms (symbols) and another based on longer description (gene/protein names). <br> This row is the result by <b>Symbol</b> based approach.')\" onmouseout=\"UnTip()\">Symbol-based mining</th>
		            <td width=\"100\"><a href=\"SciMinerBase.Symbol.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.Symbol.txt")."</a></td>
		            <td width=\"100\"><a href=\"SciMinerBase.Symbol.Remain.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.Symbol.Remain.txt")."</a></td>
		            <td width=\"100\"><a href=\"SciMinerBase.Symbol.Optout.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.Symbol.Optout.txt")."</a></td>
		            <td width=\"100\"><a href=\"SciMinerBase.Symbol.Summary.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.Symbol.Summary.txt")."</a></td>
		        </tr>
		        <tr class='titleBarName1'>
		            <th width=\"150\" onmouseover=\"Tip('SciMiner target recognition system uses two different approaches; <br>one based on single word acronyms (symbols) and another based on longer description (gene/protein names). <br> This row is the result by <b>Name</b> based approach.')\" onmouseout=\"UnTip()\">Name-based mining</th>
		            <td width=\"100\"><a href=\"SciMinerBase.Name.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.Name.txt")."</a></td>
		            <td width=\"100\"><a href=\"SciMinerBase.Name.Remain.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.Name.Remain.txt")."</a></td>
		            <td width=\"100\"><a href=\"SciMinerBase.Name.Optout.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.Name.Optout.txt")."</a></td>
		            <td width=\"100\"><a href=\"SciMinerBase.Name.Summary.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.Name.Summary.txt")."</a></td>
		        </tr>
		        <tr class='titleBarName1'>
		            <th width=\"150\" onmouseover=\"Tip('<b>Merged or Total</b>: SciMiner target recognition system uses two different approaches; <br>one based on single word acronyms (symbols) and another based on longer description (gene/protein names). <br> This row is the summed or merged results of symbol- and name-based methods. <b>Merged row and Unique targets column</b> is the final SciMiner-generated summary of users corpus.')\" onmouseout=\"UnTip()\">Merged</th>
		            <td width=\"100\"><a href=\"SciMinerBase.Both.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.Both.txt")."</a></td>
		            <td width=\"100\"><a href=\"SciMinerBase.Both.Remain.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.Both.Remain.txt")."</a></td>
		            <td width=\"100\"><a href=\"SciMinerBase.Both.Optout.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.MerSum.txt")."</a></td>
		            <td width=\"100\"><a href=\"SciMinerBase.MerSum.sorted.txt\">".get_file_size_in_human_readable_format("$finalResultWebDir/SciMinerBase.MerSum.sorted.txt")."</a></td>
		        </tr>
        	</table>
        
            <p>&nbsp;</p>
            <p><a href=\"../../main2.html\">SciMiner Homepage</a></p>
            </body>
            </html>";
    
    close RESULT;
}



# ----------------------------------------------------------------------------
#  Modules related to generating SciMiner HTML results
# ----------------------------------------------------------------------------
sub generate_summary_html
{	my $finalResultDir              = shift;
	my $finalResultWebDir			= shift;
    my $summaryFile                 = shift;
    my $resultHTMLFile              = shift;
    my $currentQueueEnvRef          = shift;
    my $totalSentence2GeneCnt       = shift;
    my $top10genesArrRef            = shift;
    my $fileNameBase                = shift;
    my $serverBaseURL               = shift;
    my $hgncID2passedContentRef     = shift;
    my $pmid2passContentRef         = shift;
    my $pmid2TitleRef               = shift;
    my $pmid2AbstractRef            = shift;
    my $medlineSymbolicLinkRef      = shift;
    my $medlineEndnoteSymLinkRef	= shift;
    my $htmlSymbolicLinkRef         = shift;
    my $pmid2htmlSizeRef            = shift;
    my $numPassGeneCountByPMIDRef   = shift;
    my $pmid2journalRef				= shift;
	my $maxRecordPerItem			= shift;
	my $cssFileName					= shift;
	my $sciminerJScriptFileName		= shift;
	my $symbol2ncbiEntrezGeneIDRef	= shift;
	my $tmpPMIDLinkURLRef			= shift;
	my $userID2userNameRef			= shift;
	    
    #  Read the summary file 
    my @rankedHUGOIDs           = ();
    my %rankedHUGOID2content    = ();
    my %HUGOID2PMIDs            = ();

    #  Create temporary directory for HUGOID2Content, PMID2Content
    my $hugoID2ContDir          = $finalResultWebDir.'hugoID2ContDir/';
    my $pmid2ContDir            = $finalResultWebDir.'pmid2ContDir/';
    my $pmid2ListDir            = $finalResultWebDir.'pmid2ListDir/';  
    my $tmpWorkingDir			= $finalResultWebDir.'Temp/';  
    mkdir ($hugoID2ContDir)     || print "";
    mkdir ($pmid2ContDir)       || print "";   
    mkdir ($pmid2ListDir)       || print ""; 
    mkdir ($tmpWorkingDir)		|| print "";

    #  Specify the URL links
    my $serverURL   	= $serverBaseURL."SciMiner/FinalResults/$fileNameBase/";
    my $SciMinerURL  	= $serverBaseURL."SciMiner/";
    my $cssURL			= $cssFileName;
    my $mimiIconURL 	= "/SciMiner1.1/SciMiner/Images/cytoicon.jpg";

    #  Generate individual result files
    open (SUMMARY, $summaryFile);
    while(<SUMMARY>)
    {   my $line = $_;
    	if ($line =~ /^#/)
    	{	next;
    	}
        $line =~ s/\r|\n//g;
        my @tmpSplit = split (/\t/, $line);

        $HUGOID2PMIDs{$tmpSplit[1]} = $tmpSplit[6];
        pop @tmpSplit;
        $rankedHUGOID2content{$tmpSplit[1]} = \@tmpSplit;
        push @rankedHUGOIDs, $tmpSplit[1];
        
        #  Generate hugoID2Cont file
        generate_hugoID2Cont_file($hugoID2ContDir, $tmpSplit[1], $hgncID2passedContentRef, $rankedHUGOID2content{$tmpSplit[1]}, $serverURL, $totalSentence2GeneCnt, $maxRecordPerItem, $SciMinerURL, $cssFileName, $symbol2ncbiEntrezGeneIDRef, $fileNameBase, $userID2userNameRef);
        
        #  Generate pmid2List file	- Listing mined genes for each pmid
        generate_pmid2List_html($tmpSplit[1], $pmid2ListDir, $HUGOID2PMIDs{$tmpSplit[1]}, $pmid2ContDir, $tmpSplit[0], $tmpSplit[2], $tmpSplit[3], $tmpSplit[4], $serverURL, $pmid2TitleRef, $numPassGeneCountByPMIDRef, $medlineSymbolicLinkRef, $medlineEndnoteSymLinkRef, $htmlSymbolicLinkRef, $pmid2htmlSizeRef, $pmid2journalRef, $SciMinerURL, $cssFileName, $$currentQueueEnvRef{InstitutionCheck}, $tmpPMIDLinkURLRef, $symbol2ncbiEntrezGeneIDRef, $fileNameBase);

        #  Generate pmid2Cont file        
        generate_pmid2Cont_file($HUGOID2PMIDs{$tmpSplit[1]}, $pmid2ContDir, $pmid2ListDir, $hugoID2ContDir, $tmpSplit[1], $pmid2passContentRef, $serverURL, $pmid2TitleRef, $pmid2AbstractRef, $medlineSymbolicLinkRef, $medlineEndnoteSymLinkRef, $htmlSymbolicLinkRef, $pmid2htmlSizeRef, $SciMinerURL, $cssFileName, $$currentQueueEnvRef{InstitutionCheck}, $tmpPMIDLinkURLRef, $fileNameBase, $symbol2ncbiEntrezGeneIDRef );
    }
    close SUMMARY;



	#  -------------------------------------------------------------------------    
    #  Start to write the result summary HTML file
	#  -------------------------------------------------------------------------    
    open (RESULT, ">".$resultHTMLFile);
	print RESULT    "<head>
		            <title>SciMiner Result Report Page</title>
		            <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
		            <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
		            <script language=\"JavaScript1.2\" src=\"sciminer.js\"></script>
		            <style type=\"text/css\"> body {	margin-left:10px;	}</style>
		            </head>
		            <body bgcolor=\"#EAF4F4\">
		            <script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
		            <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Mined Target Summary Page</b></p>
					<hr>
					<p class=\"titleBarName1\"><b>Here are the targets (genes/proteins) that SciMiner has mined.</b></p>
					";
  
    # Generate table for the actual gene
    print RESULT "  <table border=\"1\" width=\"950\">
                        <tr class=\"titleBarName1\">
                            <th width=\"40\">
                                Rank
                            </th>
                            <th width=\"40\" onmouseover=\"Tip('These are HUGO IDs. Click each ID to view the <b>HUGO detail</b>.')\" onmouseout=\"UnTip()\">
                                HUGO
                            </th>
                            <th width=\"60\" onmouseover=\"Tip('These are HUGO approved official symbols. Click each symbol to view the NCBI Entrez Gene record.')\" onmouseout=\"UnTip()\">
                                Symbol
                            </th>
                            <th width=\"400\" onmouseover=\"Tip('These are HUGO approved official gene names.')\" onmouseout=\"UnTip()\">
                                Target Name
                            </th>
                            <th width=\"50\" onmouseover=\"Tip('<b>#Occur</b>: These are the numbers of <b>identification</b> from the entire corpus.')\" onmouseout=\"UnTip()\">
                                #Occur
                            </th>
                            <th width=\"50\" onmouseover=\"Tip('<b>#Paper</b>: These are the numbers of <b>papers</b>.')\" onmouseout=\"UnTip()\">
                                #Paper
                            </th>
                            <th width=\"220\" onmouseover=\"Tip('<b>Matched_Terms</b>: These are terms that were matched in the text. Click each for more details.')\" onmouseout=\"UnTip()\">
                                Matched_Terms
                            </th>
                            <th width=\"40\" onmouseover=\"Tip('<b>MiMI</b>: This will bring up Cytoscape program and visualize protein-protein interaction network of the target.<br> Protein-Protein Interaction data is based on the MiMI (Michigan Molecular Interactions).<br> This network retrieval employes the Cytoscape MiMI plugin.')\" onmouseout=\"UnTip()\">
                                MiMI
                            </th>
                                                      
                        </tr>";


    for (my $j=0; $j <= $#rankedHUGOIDs; $j++)    
    {   if (defined $rankedHUGOID2content{$rankedHUGOIDs[$j]})
        {   print RESULT "<tr><td width=\"40\">".($j+1)."</td><td width=\"40\"><a href=\"$hgncLinkURL$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[1]\">".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[1])."</a></td><td width=\"60\">";
            if (defined $$symbol2ncbiEntrezGeneIDRef{$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]})
            {	my $tmpNCBIID	= $$symbol2ncbiEntrezGeneIDRef{$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]};
            	print RESULT "<a href=\"$ncbiGeneLink$tmpNCBIID\">$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]</a>";
            }else
            {	print RESULT "<a href=\"$ncbiGeneSearch".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0])." AND Human[Orgn]\">$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]</a>";
            }
				
            print RESULT "</td><td width=\"400\">".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[2])."</td><td width=\"50\">".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[3])."</td><td width=\"50\">";
             
                            my $pmidListDir = "pmid2ListDir/$rankedHUGOIDs[$j].html";
             print RESULT   "<a href=\"$pmidListDir\">".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[4])."</a></td><td width=\"220\">";
                            
                            my $detailResultURL = "hugoID2ContDir/$rankedHUGOIDs[$j].html";
                            my $tmpMatchedTerm	= $rankedHUGOID2content{$rankedHUGOIDs[$j]}->[5];
                            substr($tmpMatchedTerm, -3, 3) = '';
                            
             print RESULT  "<a href=\"$detailResultURL\">".$tmpMatchedTerm."</a></td><td width=\"40\">";
            if ((defined $$symbol2ncbiEntrezGeneIDRef{$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]}) && ($$symbol2ncbiEntrezGeneIDRef{$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]} ne ""))
            {	print RESULT "<a href=\"$mimiNameLink$$symbol2ncbiEntrezGeneIDRef{$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]}\"><img src=\"$mimiIconURL\"></a>";
            }else
            {	print RESULT "&nbsp;";
            }
				print RESULT "</td></tr>\n";
        }
    }


    print RESULT "</table><p>&nbsp;</p><p><a href=\"intro2.html\"><font class=\"sectionTitleName2\">SciMiner Homepage</font></a></p>
    </body>
    </html>";
    
    close RESULT;
}




sub generate_base_pmid_list_html
{   my $finalResultDir          = shift;
    my $finalResultWebDir       = shift;
    my $pmidListHTMLFile        = shift;
    my $pmid2passGeneCountRef   = shift;
    my $fileNameBase            = shift;
    my $serverBaseURL           = shift;
    my $pmid2TitleRef           = shift;
    my $docLinkDir              = shift;
    my $medlineSymbolicLinkRef  = shift;
    my $medlineEndnoteSymLinkRef= shift;
    my $htmlSymbolicLinkRef     = shift;
    my $pmid2htmlSizeRef        = shift;
    my $corpusDataOriginalDir   = shift;
    my $pmid2journalRef			= shift;
    my $cssFileName				= shift;
    my $InstitutionCheck		= shift;
    my $tmpPMIDLinkURLRef		= shift;
    my $pmid2AbstractRef		= shift;

    my $serverURL   = $serverBaseURL."SciMiner/FinalResults/$fileNameBase/";
    my $cssURL		= $cssFileName;
	my $MIcon		= "/SciMiner1.1/SciMiner/Images/M.jpg";
	my $PIcon		= "/SciMiner1.1/SciMiner/Images/P.jpg";
	my $EIcon		= "/SciMiner1.1/SciMiner/Images/E.jpg";
	my $HHIcon		= "/SciMiner1.1/SciMiner/Images/HL.jpg";
	my $HMIcon		= "/SciMiner1.1/SciMiner/Images/HL.jpg";			
	my $HLIcon		= "/SciMiner1.1/SciMiner/Images/HL.jpg";	
	my $BLANK		= "/SciMiner1.1/SciMiner/Images/BLANK.jpg";							

	# Load SciMinerBase.MerSum.sorted.txt
	open (MERSUM, $finalResultWebDir.'SciMinerBase.MerSum.sorted.txt') || LogQuery("!ERROR! Can't open SciMinerBase.MerSum.sorted.txt file");
	my %hugoID2symbol	= ();
	while(<MERSUM>)
	{	my $line 		=	$_;
		$line			=~ s/\r|\n//g;
		my @tmpSplit	= split(/\t/, $line);
		$hugoID2symbol{$tmpSplit[1]}	= $tmpSplit[0];
	}
	close MERSUM;

	# Initialize an Excel file
	use Spreadsheet::WriteExcel;
	
	my $workbook 	= Spreadsheet::WriteExcel->new($pmidListHTMLFile.'.xls');
	my $worksheet	= $workbook->add_worksheet('PMIDList');
	$worksheet->write(0,0,"PMID");
	$worksheet->write(0,1,"Title");
	$worksheet->write(0,2,"Abstract");	
	$worksheet->write(0,3,"#Genes");	
	$worksheet->write(0,4,"Symbols");
	$worksheet->write(0,5,"FullTextLink");					
	$worksheet->write(0,6,"PubMedLink");
	$worksheet->write(0,7,"Journal");

	$worksheet->set_column(0,0,10);
	$worksheet->set_column(1,1,30);
	$worksheet->set_column(2,2,50);
	$worksheet->set_column(3,3,10);
	$worksheet->set_column(4,4,25);
	$worksheet->set_column(5,6,20);
	$worksheet->set_column(7,7,20);
	
    open (RESULT, ">".$pmidListHTMLFile);
    
	print RESULT    "<head>
		            <title>PMID list for your query</title>
		            <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
		            <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
		            <script language=\"JavaScript1.2\" src=\"sciminer.js\"></script>
		            <style type=\"text/css\"> body {	margin-left:10px;	}</style>
		            </head>
		            <body bgcolor=\"#EAF4F4\">
		            <script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
		            <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>Here are the PMIDs for your query</b></p>
					<hr>
		            <table border=\"1\" width=\"850\">
                        <tr class=\"titleBarName1\">
                            <th width=\"80\">
                                PMID
                            </th>
                            <th width=\"480\">
                                TITLE
                            </th>
                            <th width=\"90\" onmouseover=\"Tip('Click here to view the identified targets from this paper.')\" onmouseout=\"UnTip()\">
                                # of Targets
                            </th>
                            <th width=\"90\" onmouseover=\"Tip('<b>Links</b>: Provides links to the following resources<br><img src=&quot;/SciMiner1.1/SciMiner/Images/M.jpg&quot;>: <b>M</b>EDLINE Record<br><img src=&quot;/SciMiner1.1/SciMiner/Images/E.jpg&quot;>: <b>E</b>ndNote citation<br><img src=&quot;/SciMiner1.1/SciMiner/Images/HL.jpg&quot;>: (full) <b>H</b>TML page<br><img src=&quot;/SciMiner1.1/SciMiner/Images/P.jpg&quot;>: NCBI <b>P</b>ubMed<br><br><b>Make sure that your browser pop-up is not blocked.</b>')\" onmouseout=\"UnTip()\">
                                Links
                            </th>
                            <th width=\"110\" onmouseover=\"Tip('Name of the journal')\" onmouseout=\"UnTip()\">
                                Journal
                            </th>
                        </tr>\n";
    

    #  open the origial list file
    open (LIST, $finalResultWebDir.$fileNameBase."_list.txt") || LogQuery("! Can't find $finalResultWebDir $fileNameBase"."_list.txt");
    my @pmidLists               = ();
    my %numPassGeneCountByPMID  = ();

	my @tmpKeys					= ();
	my $links					= '';
	my $endnotelinks			= '';
	my %identifiedGeneList		= ();
    while(<LIST>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        push @pmidLists, $line;
		
        if (defined $$pmid2passGeneCountRef{$line})
        {   @tmpKeys                     	= keys %{$$pmid2passGeneCountRef{$line}};
            $numPassGeneCountByPMID{$line}  = scalar @tmpKeys;
            my @symbols						= ();
            foreach my $tmpKeylll (@tmpKeys)
            {	if (defined $hugoID2symbol{$tmpKeylll})
            	{	push @symbols, $hugoID2symbol{$tmpKeylll};
            	}
            }
            $identifiedGeneList{$line}	= join (",", @symbols);
        }else
        {   $numPassGeneCountByPMID{$line}  = 0;
        	$identifiedGeneList{$line}	= "";
        }
        
        #TATATATA
        #  Convert medline file to endnote .enw file and create symbolic links
        #if (-f $corpusDataOriginalDir.$line.'.medline')
        #{   $links                       = $finalResultWebDir."Docs/$line.medline.txt";
        #	$endnotelinks				= $finalResultWebDir."Docs/$line.medline.enw";
        #    $$medlineSymbolicLinkRef{$line} = "Docs/$line.medline.txt";
        #    `ln -s $corpusDataOriginalDir$line.medline $links`;
        #    
        #    $$medlineEndnoteSymLinkRef{$line} = "Docs/$line.medline.enw";
        #    `ln -s $corpusDataOriginalDir$line.enw $endnotelinks`;
        #    
        #}
        
        ##  Make symbolic links to the original files
        #if (-f $corpusDataOriginalDir.$line.'.medline')
        #{   my $links                       = $finalResultWebDir."Docs/$line.medline.txt";
        #	my $endnotelinks				= $finalResultWebDir."Docs/$line.medline.enw";
        #    $$medlineSymbolicLinkRef{$line} = $serverURL."Docs/$line.medline.txt";
        #    `ln -s $corpusDataOriginalDir$line.medline $links`;
        #    
        #    $$medlineEndnoteSymLinkRef{$line} = $serverURL."Docs/$line.medline.enw";
        #    `ln -s $corpusDataOriginalDir$line.medline $endnotelinks`;
        #}
        
        #if ((-f $corpusDataOriginalDir.$line.'.html') && ( $InstitutionCheck))
        #{   $links                       = $finalResultWebDir."Docs/$line.html";
        #    $$htmlSymbolicLinkRef{$line}    = "Docs/$line.html";
        #    `ln -s $corpusDataOriginalDir$line.html $links`;
        #}
    }
    close LIST;
    
    #  Sort the list of PMIDs by the number of genes found by SciMiner
    my @sortedPMIDsByGeneCount		= sort {$numPassGeneCountByPMID{$b} <=> $numPassGeneCountByPMID{$a}} @pmidLists;
    my $genesBySciMinerFile			= '';		
    my $rowCount					= 1;
    
    if (defined $sortedPMIDsByGeneCount[0])
    {   foreach my $pmid (@sortedPMIDsByGeneCount)
        {   #  Check if there is any gene identified by SciMiner
            $genesBySciMinerFile = "pmid2ContDir/$pmid.html";
            print RESULT "<tr><td width=\"80\">$pmid</td><td width=\"480\">$$pmid2TitleRef{$pmid}</td><td width=\"90\">";
            
            # Write Excel content
            $worksheet->write($rowCount,0,"$pmid");
            $worksheet->write($rowCount,1,"$$pmid2TitleRef{$pmid}");
            $worksheet->write($rowCount,2,"$$pmid2AbstractRef{$pmid}");
            
                                
            if ($numPassGeneCountByPMID{$pmid} == 0)
            {   print RESULT  "&nbsp;";
            	$worksheet->write($rowCount,3,0);
            	$worksheet->write($rowCount,4,"");
            }else
            {   print RESULT  "<a href=\"$genesBySciMinerFile\" onmouseover=\"Tip('Click here to view the identified targets from this paper PMID:$pmid.')\" onmouseout=\"UnTip()\">$numPassGeneCountByPMID{$pmid}</a>";
            	$worksheet->write($rowCount,3,$numPassGeneCountByPMID{$pmid});
            	$worksheet->write($rowCount,4,$identifiedGeneList{$pmid});
            }

			# PubMed link and Full text links
			$worksheet->write($rowCount,5,$$tmpPMIDLinkURLRef{$pmid});
			$worksheet->write($rowCount,6,"http://www.pubmed.com/$pmid");			
			
			$$tmpPMIDLinkURLRef{$pmid} =~ s/\&/-_-/g;
            print RESULT "</td><td width=\"90\">";
