            print RESULT "<a href=\"javascript:retrieveDocumentScript('single','$pmid','enw','$fileNameBase','none');\" onmouseover=\"Tip('<img src=&quot;/SciMiner1.1/SciMiner/Images/E.jpg&quot;>: <b>E</b>ndNote citation<br><br><b>Make sure that your browser pop-up is not blocked.</b>')\" onmouseout=\"UnTip()\"><img src=\"$EIcon\"></a>";
            if ($InstitutionCheck)
