            	$$tmpPMIDLinkURLRef{$pmid} =~ s/-_-/\&/g;
            }else
            {	$$tmpPMIDLinkURLRef{$pmid} =~ s/-_-/\&/g;
            	print RESULT "<a href=\"javascript:openNewWindow('$$tmpPMIDLinkURLRef{$pmid}');\" onmouseover=\"Tip('<img src=&quot;/SciMiner1.1/SciMiner/Images/HL.jpg&quot;>: (full) <b>H</b>TML page<br><br><br><b>Make sure that your browser pop-up is not blocked.</b>')\" onmouseout=\"UnTip()\"><img src=\"$HHIcon\"></a>";
            }
            print RESULT "<a href=\"javascript:openPubMedForPMID($pmid);\" onmouseover=\"Tip('<img src=&quot;/SciMiner1.1/SciMiner/Images/P.jpg&quot;>: NCBI <b>P</b>ubMed<br><br><b>Make sure that your browser pop-up is not blocked.</b>')\" onmouseout=\"UnTip()\"><img src=\"$PIcon\"></a>
				          </td>";            
            
            #TATATATA
            #if (defined $$medlineSymbolicLinkRef{$pmid})
            #{   print RESULT "<a href=\"$$medlineSymbolicLinkRef{$pmid}\"><img src=\"$MIcon\"></a>";
            #}else
            #{   print RESULT "<img src=\"$BLANK\">";
            #}
            #if (defined $$medlineSymbolicLinkRef{$pmid})
            #{   print RESULT "<a href=\"$$medlineSymbolicLinkRef{$pmid}\"><img src=\"$MIcon\"></a>";
            #}else
            #{   print RESULT "<a href=\"javascript:retrieveDocumentScript('single','$pmid','medline','$fileNameBase','none');\"><img src=\"$MIcon\"></a>";
            #}
            #
            #if (defined $$medlineEndnoteSymLinkRef{$pmid})
            #{   print RESULT "<a href=\"$$medlineEndnoteSymLinkRef{$pmid}\"><img src=\"$EIcon\"></a>";
            #}else
            #{   print RESULT "<img src=\"$BLANK\">";
            #}
            #
            #
            #if ((defined $$htmlSymbolicLinkRef{$pmid}) && ($InstitutionCheck) &&
            #	(($$tmpPMIDLinkURLRef{$pmid} !~ /www\.ncbi\.nlm\.nih\.gov/) && ($$tmpPMIDLinkURLRef{$pmid} ne "")))
            #{   if ($$pmid2htmlSizeRef{$pmid} >= 157000)
            #    {   print RESULT "<a href=\"$$htmlSymbolicLinkRef{$pmid}\"><img src=\"$HHIcon\"></a>";
            #    }elsif (($$pmid2htmlSizeRef{$pmid} < 157000) &&($$pmid2htmlSizeRef{$pmid} >= 88000))
            #    {   print RESULT "<a href=\"$$htmlSymbolicLinkRef{$pmid}\"><img src=\"$HMIcon\"></a>";
            #    }else
            #    {   print RESULT "<a href=\"$$htmlSymbolicLinkRef{$pmid}\"><img src=\"$HLIcon\"></a>";
            #    }
            #}elsif ($$tmpPMIDLinkURLRef{$pmid} eq "")
            #{	print RESULT "<img src=\"$BLANK\">";
            #}else
            #{   print RESULT "<a href=\"$$tmpPMIDLinkURLRef{$pmid}\"><img src=\"$HLIcon\"></a>";
            #}
            #
            #print RESULT "<a href=\"javascript:openPubMedForPMID($pmid);\"><img src=\"$PIcon\"></a>
			#	          </td>";
			

            
            	                        
            if (defined $$pmid2journalRef{$pmid})
            {   print RESULT "<td width=\"110\">$$pmid2journalRef{$pmid}</td></tr>\n";
            	$worksheet->write($rowCount,7,$$pmid2journalRef{$pmid});
            }else
            {   print RESULT "</td><td width=\"110\">&nbsp;</td></tr>\n";
            	$worksheet->write($rowCount,7,"");
            }
            
            # Increase the row count by 1
            $rowCount++;
        }
    }

	#`cat $finalResultWebDir/Docs/*.enw > $finalResultWebDir/AllCitation.enw`;
			
    print RESULT "</table>\n
        <p class=\"titleBarName1\">Click <a href=\"javascript:retrieveDocumentScript('all','1','enw','$fileNameBase','none');\"  onmouseover=\"Tip('You can download all of the above citations at once click.')\" onmouseout=\"UnTip()\">here <img src=\"$EIcon\"></a> to download all of the citations to EndNote!&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
        You can download this page as an <a href=\"pmidList.html.xls\"><b>EXCEL</b></a> file with hyperlinks.</p>
        </body>
        </html>";

    close RESULT;
	$workbook->close();    
    return (\%numPassGeneCountByPMID);
}






sub generate_hugoID2Cont_file
{   my $hugoID2ContDir              = shift;
    my $hugoID                      = shift;
    my $hgncID2passedContentRef     = shift;
    my $hugoID2ContentArrRef        = shift;
    my $serverURL                   = shift;
    my $totalSentence2GeneCnt		= shift;
    my $maxRecordPerItem			= shift;
    my $SciMinerURL					= shift;
    my $cssFileName					= shift;
    my $symbol2ncbiEntrezGeneIDRef	= shift;
    my $fileNameBase				= shift;
    my $userID2userNameRef			= shift;
    
    
    my $cssURL						= $cssFileName;
    my $tmpNCBIID					= '';
    my $genesBySciMinerFile			= '';
    my $EDITIcon					= '../Images/EDIT.jpg';
    
    if (not defined $$hgncID2passedContentRef{$hugoID})
    {   # This is impossible
        LogQuery("!!! No content is assigned to $hugoID hugoID. This is impossible");
        open (RESULT, ">".$hugoID2ContDir.$hugoID.'.html');
        print RESULT " ";
        close (RESULT);
    }else
    {   
        open (RESULT, ">".$hugoID2ContDir.$hugoID.'.html');
        print RESULT "<head>
                    <title>HUGO ID Detailed Result $hugoID</title>
                    <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
                    <link rel=\"stylesheet\" href=\"../$cssURL\" type=\"text/css\" />
                    <script language=\"JavaScript1.2\" src=\"../sciminer.js\"></script>
                	<style type=\"text/css\"> body {	margin-left:10px;	}</style>
                    </head>
                    <body bgcolor=\"#EAF4F4\">
                    <script language=\"JavaScript1.2\" src=\"../wz_tooltip.js\"></script>
                    <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>HUGO ID Detailed Result $hugoID</b></p>";

        if ($totalSentence2GeneCnt > 1000000)
        {   print RESULT "<font color=\"red\">NOTE: Only $maxRecordPerItem records per actualString per document are shown here!<br>
        				  Full record is available <a href=\"$serverURL/SciMinerBase.Both.Remain.txt\"> HERE </a>";
        }
        
        print RESULT "                   
                    <hr><p></p>";

    	# Generate table for the actual gene
        print RESULT "<table border=\"1\" width=\"600\">
                        <tr class=\"titleBarName1\">
                            <th width=\"100\">
                                HUGO ID
                            </th>
                            <td width=\"500\">
                                <a href=\"$hgncLinkURL$$hugoID2ContentArrRef[1]\">$$hugoID2ContentArrRef[1]</a>
                            </td>
                        </tr>
                        <tr class=\"titleBarName1\">
                            <th width=\"100\">
                                Symbol
                            </th>
                            <td width=\"500\">
                      ";
              
        if (defined $$symbol2ncbiEntrezGeneIDRef{$$hugoID2ContentArrRef[0]})
        {	$tmpNCBIID	= $$symbol2ncbiEntrezGeneIDRef{$$hugoID2ContentArrRef[0]};
        	print RESULT "<a href=\"$ncbiGeneLink$tmpNCBIID\">$$hugoID2ContentArrRef[0]</a>
         				 ";
        }else
        {	print RESULT "<a href=\"$ncbiGeneSearch".($$hugoID2ContentArrRef[0])." AND Human[Orgn]\">$$hugoID2ContentArrRef[0]</a>
         				";
        }
        print RESULT "      </td>
                        </tr>
                        <tr class=\"titleBarName1\">
                            <th width=\"100\">
                                Name
                            </th>
                            <td width=\"500\">
                                $$hugoID2ContentArrRef[2]
                            </td>
                        </tr>
                        <tr class=\"titleBarName1\">
                            <th width=\"100\">
                                #Occurrence
                            </th>
                            <td width=\"500\">
                                $$hugoID2ContentArrRef[3]
                            </td>
                        </tr>
                        <tr class=\"titleBarName1\">
                            <th width=\"100\">
                                #Paper
                            </th>
                            <td width=\"500\">
                                $$hugoID2ContentArrRef[4]
                            </td>
                        </tr>                        
                     </table>
                  <p>&nbsp;</p>
                  <hr>
                  ";        
                     
                     
                     
            print RESULT "<table border=\"1\" width=\"960\">
                        <tr class=\"titleBarName1\">
                            <th width=\"70\">
                                PMID
                            </th>
                            <th width=\"125\" onmouseover=\"Tip('<b>Match String</b>: Matched string as in the SciMiner dictionary.')\" onmouseout=\"UnTip()\">
                                Match String
                            </th>
                            <th width=\"125\" onmouseover=\"Tip('<b>Actual String</b>: Actual string as in the text.')\" onmouseout=\"UnTip()\">
                                Actual String
                            </th>
                            <th width=\"50\" onmouseover=\"Tip('<b>Score</b>: SciMiner confidence score for this identification.')\" onmouseout=\"UnTip()\">
                                Score
                            </th>
                            <th width=\"430\" onmouseover=\"Tip('<b>Flanking text</b>: Flanking text around the identified target in the text.')\" onmouseout=\"UnTip()\">
                                Flanking text
                            </th>
                            <th width=\"100\" onmouseover=\"Tip('<b>Edited by</b>: The name of SciMiner user who edited (corrected) this identification.')\" onmouseout=\"UnTip()\">
                                Edited by
                            </th>
                            <th width=\"60\" onmouseover=\"Tip('<b>Edit</b>: Click here to edit (correct) the identification. You can delete or assign to different HUGO gene.')\" onmouseout=\"UnTip()\">
                                Edit
                            </th>
                        </tr>\n";

#                            <td width=\"100\">
#                                inExCode
#                            </td>
#                            <td width=\"100\">
#                                inExCond.
#                            </td>


        foreach my $ref (@{$$hgncID2passedContentRef{$hugoID}})
        {   $genesBySciMinerFile = "../pmid2ContDir/$$ref[0].html";
            print RESULT "<tr><td><a href=\"$genesBySciMinerFile\">$$ref[0]</a></td><td>$$ref[1]</td><td>$$ref[2]</td><td>$$ref[3]</td><td>$$ref[4]</td>";
            if ((not defined $$ref[6]) || ($$ref[6] == 0))
            {	print RESULT "<td>&nbsp;</td>";
            }else
            {	if (defined $$userID2userNameRef{$$ref[6]})
            	{	print RESULT "<td>$$userID2userNameRef{$$ref[6]}</td>";
            	}else
            	{	print RESULT "<td>UserID:$$ref[6]</td>";
            	}
            }	
            print RESULT "<td><a href=\"javascript:editSciMinerFinding('$$ref[5]','$fileNameBase','$$ref[1]','$$ref[2]','$hugoID');\"><img src=\"$EDITIcon\"></a></td></tr>\n";
        }
        
        
        print RESULT "</table>\n
            <p>&nbsp;</p>
            </body>
            </html>";
    
        close RESULT;
    }
}   








sub generate_pmid2List_html
{   my $hugoID                      = shift;
    my $pmid2ListDir                = shift;
    my $pmidFullString              = shift;
    my $pmid2ContDir                = shift;
    my $symbol                      = shift;
    my $name                        = shift;
    my $numOccur                    = shift;
    my $numPaper                    = shift;
    my $serverURL                   = shift;
    my $pmid2TitleRef               = shift;
    my $numPassGeneCountByPMIDRef   = shift;
    my $medlineSymbolicLinkRef      = shift;
    my $medlineEndnoteSymLinkRef	= shift;
    my $htmlSymbolicLinkRef         = shift;
    my $pmid2htmlSizeRef            = shift;
    my $pmid2journalRef				= shift;
    my $SciMinerURL					= shift;
    my $cssFileName					= shift;
    my $InstitutionCheck			= shift;
    my $tmpPMIDLinkURLRef			= shift;
    my $symbol2ncbiEntrezGeneIDRef	= shift;
    my $fileNameBase				= shift;
        
    my $cssURL						= $cssFileName;    
    my $tmpNCBIID					= '';
    my @splitPMID           		= split (/\,/, $pmidFullString);
    
	my $MIcon		= "../Images/M.jpg";
	my $PIcon		= "../Images/P.jpg";
	my $EIcon		= "../Images/E.jpg";
	my $HHIcon		= "../Images/HL.jpg";
	my $HMIcon		= "../Images/HL.jpg";			
	my $HLIcon		= "../Images/HL.jpg";	
	my $BLANK		= "../Images/BLANK.jpg";
	
    open (RESULT, ">".$pmid2ListDir."$hugoID".'.html');
    
    print RESULT "<head>
                <title>SciMiner Result Report Page</title>
                <meta http-equiv=\"Content-Type\" content=\"text/html; charset=iso-8859-1\" />
                <link rel=\"stylesheet\" href=\"../$cssURL\" type=\"text/css\" />
                <script language=\"JavaScript1.2\" src=\"../sciminer.js\"></script>
                <style type=\"text/css\"> body {	margin-left:10px;	}</style>
                </head>
                <body bgcolor=\"#EAF4F4\">
                <script language=\"JavaScript1.2\" src=\"../wz_tooltip.js\"></script>
                <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>List of PMIDs</b></p>
				";                

    # Generate table for the actual gene
    print RESULT "<p class=\"titleBarName1\"><b>Current Target Information</b></p>
                    <table border=\"1\" width=\"600\">
                        <tr class=\"titleBarName1\">
                            <th width=\"100\">
                                HUGO ID
                            </th>
                            <td width=\"500\">
                                <a href=\"$hgncLinkURL$hugoID\">$hugoID</a>
                            </td>
                        </tr>
                        <tr class=\"titleBarName1\">
                            <th width=\"100\">
                                Symbol
                            </th>
                            <td width=\"500\">
                                ";
                                
    if (defined $$symbol2ncbiEntrezGeneIDRef{$symbol})
    {	$tmpNCBIID	= $$symbol2ncbiEntrezGeneIDRef{$symbol};
    	print RESULT "<a href=\"$ncbiGeneLink$tmpNCBIID\">$symbol</a>
     				 ";
    }else
    {	print RESULT "<a href=\"$ncbiGeneSearch".($symbol)." AND Human[Orgn]\">$symbol</a>
     				";
    }
    print RESULT  "
                            </td>
                        </tr>
                        <tr class=\"titleBarName1\">
                            <th width=\"100\">
                                Name
                            </th>
                            <td width=\"500\">
                                $name
                            </td>
                        </tr>
                        <tr class=\"titleBarName1\">
                            <th width=\"100\">
                                #Occurrence
                            </th>
                            <td width=\"500\">
                                $numOccur
                            </td>
                        </tr>
                        <tr class=\"titleBarName1\">
                            <th width=\"100\">
                                #Paper
                            </th>
                            <td width=\"500\">
                                $numPaper
                            </td>
                        </tr>                        
                     </table><br>
                     <hr>
                     <br>
                     ";
     
     
     
    print RESULT "  <table border=\"1\" width=\"850\">
                        <tr class=\"titleBarName1\">
                            <th width=\"80\">
                                PMID
                            </th>
                            <th width=\"480\">
                                TITLE
                            </th>
                            <th width=\"90\" onmouseover=\"Tip('Click each number to view all of the identified targets.')\" onmouseout=\"UnTip()\">
                                # of Targets
                            </th>
                            <th width=\"90\">
                                Links
                            </th>
                            <th width=\"110\">
                                Journal
                            </th>
                        </tr>\n";


    #  Sort the list of PMIDs by the number of genes found by SciMiner
    my @sortedPMIDsByGeneCount		= sort {$$numPassGeneCountByPMIDRef{$b} <=> $$numPassGeneCountByPMIDRef{$a}} @splitPMID;
    
    my $genesBySciMinerFile			= '';
    if (defined $sortedPMIDsByGeneCount[0])
    {   foreach my $pmid (@sortedPMIDsByGeneCount)
        {   #  Check if there is any gene identified by SciMiner
            $genesBySciMinerFile	= "../pmid2ContDir/$pmid.html";
            print RESULT "  <tr><td width=\"80\">$pmid</td><td width=\"480\">$$pmid2TitleRef{$pmid}</td><td width=\"90\">";
            if ($$numPassGeneCountByPMIDRef{$pmid} == 0)
            {   print RESULT  "&nbsp;";
            }else
            {   print RESULT  "<a href=\"$genesBySciMinerFile\" onmouseover=\"Tip('Click here to view all of the identified targets from the document PMID <b>$pmid</b>.')\" onmouseout=\"UnTip()\"><u>$$numPassGeneCountByPMIDRef{$pmid}</u></a>";
            }
            
			$$tmpPMIDLinkURLRef{$pmid} =~ s/\&/-_-/g;
            print RESULT "</td><td width=\"90\" onmouseover=\"Tip('<b>Links</b>: Provides links to the following resources<br><img src=&quot;$MIcon&quot;>: <b>M</b>EDLINE Record<br><img src=&quot;$EIcon&quot;>: <b>E</b>ndNote citation<br><img src=&quot;$HLIcon&quot;>: (full) <b>H</b>TML page<br><img src=&quot;$PIcon&quot;>: NCBI <b>P</b>ubMed<br><br><b>Make sure that your browser pop-up is not blocked.</b>')\" onmouseout=\"UnTip()\">";
			print RESULT "<a href=\"javascript:retrieveDocumentScript('single','$pmid','medline','$fileNameBase','none');\" ><img src=\"$MIcon\"></a>";
            print RESULT "<a href=\"javascript:retrieveDocumentScript('single','$pmid','enw','$fileNameBase','none');\"><img src=\"$EIcon\"></a>";
            if (($InstitutionCheck) && ($$tmpPMIDLinkURLRef{$pmid} !~ /www\.ncbi\.nlm\.nih\.gov/))
            {	print RESULT "<a href=\"javascript:retrieveDocumentScript('single','$pmid','html','$fileNameBase','$$tmpPMIDLinkURLRef{$pmid}');\"><img src=\"$HHIcon\"></a>";
            	$$tmpPMIDLinkURLRef{$pmid} =~ s/-_-/\&/g;
            }else
            {	$$tmpPMIDLinkURLRef{$pmid} =~ s/-_-/\&/g;
            	print RESULT "<a href=\"javascript:openNewWindow('$$tmpPMIDLinkURLRef{$pmid}');\"><img src=\"$HHIcon\"></a>";
            }
            print RESULT "<a href=\"javascript:openPubMedForPMID($pmid);\"><img src=\"$PIcon\"></a></td>";    
			
            if (defined $$pmid2journalRef{$pmid})
            {   print RESULT "<td width=\"110\">$$pmid2journalRef{$pmid}</td></tr>\n";
            }else
            {   print RESULT "</td><td width=\"110\">&nbsp;</td></tr>\n";
            }
        }
    }
    
    
    
    
    print RESULT "</table>\n
        <p>&nbsp;</p>
        </body>
        </html>";

    close RESULT;

}





sub generate_pmid2Cont_file
{   my $pmidFullString      		= shift;
    my $pmid2ContDir        		= shift;
    my $pmid2ListDir        		= shift;
    my $hugoID2ContDir      		= shift;
    my $hugoID              		= shift;
    my $pmid2passContentRef 		= shift;
    my $serverURL           		= shift;
    my $pmid2TitleRef       		= shift;
    my $pmid2AbstractRef    		= shift;
    my $medlineSymbolicLinkRef      = shift;
    my $medlineEndnoteSymLinkRef	= shift;
    my $htmlSymbolicLinkRef         = shift;
    my $pmid2htmlSizeRef            = shift;
    my $SciMinerURL					= shift;
    my $cssFileName					= shift;
    my $InstitutionCheck			= shift;
    my $tmpPMIDLinkURLRef			= shift;
    my $fileNameBase				= shift;
    my $symbol2ncbiEntrezGeneIDRef	= shift;
    
       
    my @splitPMID   = split (/\,/, $pmidFullString);
	my $cssURL		= $cssFileName;
	
	my $MIcon		= "../Images/M.jpg";
	my $PIcon		= "../Images/P.jpg";
	my $EIcon		= "../Images/E.jpg";
	my $HHIcon		= "../Images/HL.jpg";
	my $HMIcon		= "../Images/HL.jpg";			
	my $HLIcon		= "../Images/HL.jpg";
	my $BLANK		= "../Images/BLANK.jpg";

    foreach my $pmid (@splitPMID)
    {   if ((defined $pmid) && ($pmid ne ""))
        {   if (! -f "$pmid2ContDir/$pmid.html")
            {   open (RESULT, ">"."$pmid2ContDir/$pmid.html");
                print RESULT "<head>
                            <title>SciMiner Result Report Page</title>
                            <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
                            <link rel=\"stylesheet\" href=\"../$cssURL\" type=\"text/css\" />
							<script language=\"JavaScript1.2\" src=\"../sciminer.js\"></script>
                			<style type=\"text/css\"> body {	margin-left:10px;	}</style>
                            </head>
                            <body bgcolor=\"#EAF4F4\">
                            <script language=\"JavaScript1.2\" src=\"../wz_tooltip.js\"></script>
                            <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>Document Information</b></p>
                            <hr>
                            <p></p>";
                            
                print RESULT "<table border=\"1\" width=\"800\">
                                <tr class=\"titleBarName1\" onmouseover=\"Tip('<b>Links</b>: Provides links to the following resources<br><img src=&quot;$MIcon&quot;>: <b>M</b>EDLINE Record<br><img src=&quot;$EIcon&quot;>: <b>E</b>ndNote citation<br><img src=&quot;$HLIcon&quot;>: (full) <b>H</b>TML page<br><img src=&quot;$PIcon&quot;>: NCBI <b>P</b>ubMed<br><br><b>Make sure that your browser pop-up is not blocked.</b>')\" onmouseout=\"UnTip()\">
                                    <th width=\"100\">
                                        PMID
                                    </th>
                                    <td width=\"700\">
                                        $pmid&nbsp;&nbsp;(&nbsp;";
                                        
				#  Icon links
				
				
				$$tmpPMIDLinkURLRef{$pmid} =~ s/\&/-_-/g;
		        print RESULT "<a href=\"javascript:retrieveDocumentScript('single','$pmid','medline','$fileNameBase','none');\"><img src=\"$MIcon\"></a>";
		        print RESULT "<a href=\"javascript:retrieveDocumentScript('single','$pmid','enw','$fileNameBase','none');\"><img src=\"$EIcon\"></a>";
		        if (($InstitutionCheck) && ($$tmpPMIDLinkURLRef{$pmid} !~ /www\.ncbi\.nlm\.nih\.gov/))
		        {	print RESULT "<a href=\"javascript:retrieveDocumentScript('single','$pmid','html','$fileNameBase','$$tmpPMIDLinkURLRef{$pmid}');\"><img src=\"$HHIcon\"></a>";
		        	$$tmpPMIDLinkURLRef{$pmid} =~ s/-_-/\&/g;
		        }else
		        {	$$tmpPMIDLinkURLRef{$pmid} =~ s/-_-/\&/g;
		        	print RESULT "<a href=\"javascript:openNewWindow('$$tmpPMIDLinkURLRef{$pmid}');\"><img src=\"$HHIcon\"></a>";
		        }
                
		        print RESULT "<a href=\"javascript:openPubMedForPMID($pmid);\"><img src=\"$PIcon\"></a>&nbsp;)</td></tr>\n";
						      
						      
                                
                           
		        #  Generate paper specific count summary
		        my %localActualStringHash				= ();
		        my %localActualString					= ();					
		        my %localOccurCount						= ();
		        my %localHUGOID2name					= ();
		        my %localHUGOID2symbol					= ();
		        my %actualSymbolFullHashSymbol			= ();
	            
	            
		        foreach my $ref(@{$$pmid2passContentRef{$pmid}})
		        {	if (not defined $localHUGOID2symbol{$$ref[0]})
		        	{	$localHUGOID2symbol{$$ref[0]} 			= $$ref[1];
		        		$localHUGOID2name{$$ref[0]} 			= $$ref[2];
		        		$localOccurCount{$$ref[0]} 				= 1;
		        		add_uniqSymActualSymHash(\%localActualStringHash, $$ref[0], $$ref[3]);
		        		$actualSymbolFullHashSymbol{$$ref[3]}	= $$ref[1];
		        	}else
		        	{	$localOccurCount{$$ref[0]}++;
		        		add_uniqSymActualSymHash(\%localActualStringHash, $$ref[0], $$ref[3]);
		        		$actualSymbolFullHashSymbol{$$ref[3]}	= $$ref[1];
		        		#if (( $localActualString{$$ref[0]} =~ /^$$ref[3] \| / ) ||
            			#	( $localActualString{$$ref[0]} =~ / \| $$ref[3] \| /))
            			#{	# This actual string is redundant
            			#}else
            			#{	$localActualString{$$ref[0]}	.= $$ref[3].' | ';
            			#}
		        	}
		        }
		        
		        #  For redundant symbol processing, use the following two
		        #  add_uniqSymActualSymHash	(already used at the above step)
		        #  add_uniqSymActualSym
		        
	            #  Process unique symbol actual symbol
	            my %actualSymbolFullHash		= ();
	            
				foreach my $tmpHugoID (keys %localActualStringHash)
				{	foreach my $tmpKey (keys %{$localActualStringHash{$tmpHugoID}})
					{   add_uniqSymActualSym (\%localActualString, $tmpHugoID, $tmpKey);
						$actualSymbolFullHash{$tmpKey}			= 1
					}
				}
		
		        my @sortedHUGOIDs		= sort {$localOccurCount{$b} <=> $localOccurCount{$a}} keys %localOccurCount;
                my @fullActualSymbols	= keys %actualSymbolFullHash;
                
                #  ---------------------------------------------------------------
                #	MARK identified targets from the abstract
                #  ---------------------------------------------------------------

                my $tmpWorkingAbs		= '';
                my $newHTMLAbst			= '';
                my $absLength			= length($$pmid2AbstractRef{$pmid});
                my @positionMark		= ();
                my @positionChar		= split (//, $$pmid2AbstractRef{$pmid});
                my $curPosition			= 0;
                my $curLength			= 0;
                my $prevStatus			= 0;
                my %positionSymbol		= ();
                
                for (my $pos=0; $pos < $absLength; $pos++)
                {	$positionMark[$pos]	= 0;
                }
                
                foreach my $tmpKey (@fullActualSymbols)
                {	$tmpWorkingAbs		= $$pmid2AbstractRef{$pmid};
                	$curPosition		= 0;
                	while($tmpWorkingAbs =~ /\b$tmpKey\b/)
                	{	$tmpWorkingAbs	= $';
                		$curPosition	+= length($`);
                		$curLength		= length($&);
                		
                		for (my $curPos = $curPosition; $curPos < ($curPosition + $curLength); $curPos++)
                		{	$positionMark[$curPos] 			= 1;
                			if (defined $actualSymbolFullHashSymbol{$tmpKey})
                			{	$positionSymbol{$curPos}	= $actualSymbolFullHashSymbol{$tmpKey};
                			}
                		}
                		$curPosition	= $curPosition + $curLength;
                	}
                }
				
				
				my $preLinkUsed			= 0;
				#  Generate abstract for HTML with color coded
				for (my $pos=0; $pos < $absLength; $pos++)
                {	if (($prevStatus == 0) && ($positionMark[$pos] == 1))
                	{	if (defined $positionSymbol{$pos})
                		{	if (defined $$symbol2ncbiEntrezGeneIDRef{$positionSymbol{$pos}})
		            		{	$newHTMLAbst	.= "<a href=\"$ncbiGeneLink$$symbol2ncbiEntrezGeneIDRef{$positionSymbol{$pos}}\" style=\"background-color:#F5CCF4;\"><u>".$positionChar[$pos];
		            		}else
		            		{	$newHTMLAbst	.= "<a href=\"$positionSymbol{$pos} AND Human[Orgn]\" style=\"background-color:#F5CCF4;\"><u>".$positionChar[$pos];
		            		}
                			$preLinkUsed	= 1;
                		}else
                		{	$newHTMLAbst	.= "<u>".$positionChar[$pos];
		            		$preLinkUsed	= 0;
                		}
                	}elsif (($prevStatus == 1) && ($positionMark[$pos] == 0))
                	{	if ($preLinkUsed)
		            	{	$newHTMLAbst	.= '</a></u>'.$positionChar[$pos];
		            	}else
		            	{	$newHTMLAbst	.= '</u>'.$positionChar[$pos];
		            	}
                	}else
                	{	$newHTMLAbst	.= $positionChar[$pos];
                	}
                	$prevStatus	= $positionMark[$pos];
                }
                
                
				print RESULT   "<tr class=\"titleBarName1\">
								    <th width=\"100\">
								        Title
								    </th>
								    <td width=\"700\">
								        $$pmid2TitleRef{$pmid}
								    </td>
								</tr>
								<tr class=\"titleBarName1\">
								    <th width=\"100\">
								        Abstract
								    </th>
								    <td width=\"700\">
								        $newHTMLAbst
								    </td>
								</tr>
								</table>\n
								<p class=\"titleBarName1\">NOTE: <font color='RED' style=\"background-color:#F5CCF4;\"><u>Color highlight</u></font> is limited to the <b>abstract</b> and <b>SciMiner text-mining mode</b>. If you see much more identified targets below from &quot;Targets by SciMiner Summary&quot; and &quot;Targets by SciMiner Full list&quot;, they may have been identified from the <b>full text</b>.</p>
								<hr>";


                #  Display counting summary first
                print RESULT "<br>
                                <p align=\"center\" class=\"sectionTitleName1\"> <b>Targets by SciMiner Summary</b></p>
                                <table border=\"1\" width=\"800\">
                                    <tr class=\"titleBarName1\">
                                        <th width=\"50\">
                                           HUGO ID
                                        </th>
                                        <th width=\"60\">
                                           Symbol
                                        </th>
                                        <th width=\"400\">
                                           Target Name
                                        </th>
                                        <th width=\"50\">
                                           #Occur
                                        </th>
                                        <th width=\"240\">
                                           ActualStr
                                        </th>
                                    </tr>";    
                foreach my $hugoID (@sortedHUGOIDs)
                {	if (defined $localHUGOID2symbol{$hugoID})
		            {	print RESULT "<tr><td width=\"50\" onmouseover=\"Tip('Click here to view the details of <b>$localHUGOID2symbol{$hugoID}</b> at HGNC.')\" onmouseout=\"UnTip()\"><a href=\"$hgncLinkURL$hugoID\">$hugoID</a></td><td width=\"60\" onmouseover=\"Tip('Click here to view the details of <b>$localHUGOID2symbol{$hugoID}</b> at Entrez Gene database.')\" onmouseout=\"UnTip()\">";
		            	if (defined $$symbol2ncbiEntrezGeneIDRef{$localHUGOID2symbol{$hugoID}})
			            {	print RESULT "<a href=\"$ncbiGeneLink$$symbol2ncbiEntrezGeneIDRef{$localHUGOID2symbol{$hugoID}}\" onmouseover=\"Tip('Click here to view the details of <b>$localHUGOID2symbol{$hugoID}</b> at Entrez Gene.')\" onmouseout=\"UnTip()\">$localHUGOID2symbol{$hugoID}</a></td>";
			            }else
			            {	print RESULT "<a href=\"$ncbiGeneSearch$localHUGOID2symbol{$hugoID} AND Human[Orgn]\" onmouseover=\"Tip('Click here to view the details of <b>$localHUGOID2symbol{$hugoID}</b> at Entrez Gene.')\" onmouseout=\"UnTip()\">$localHUGOID2symbol{$hugoID}</a></td>";
			            }
			            print RESULT "<td width=\"400\">$localHUGOID2name{$hugoID}</td><td width=\"50\">$localOccurCount{$hugoID}</td><td width=\"240\">$localActualString{$hugoID}</td></tr>";
		            }else
		            {	print RESULT "<tr><td width=\"50\"><a href=\"$hgncLinkURL$hugoID\">$hugoID</a></td><td width=\"60\">$localHUGOID2symbol{$hugoID}</td><td width=\"400\">$localHUGOID2name{$hugoID}</td><td width=\"50\">$localOccurCount{$hugoID}</td><td width=\"240\">$localActualString{$hugoID}</td></tr>";
		            }
                }
                print RESULT "</table>";
                                
                                
                print RESULT "  <p>&nbsp;</p> <hr>
                                <p align=\"center\" class=\"sectionTitleName1\"> <b>Targets by SciMiner Full list</b></p>
                                <table border=\"1\" width=\"800\">
                                    <tr class=\"titleBarName1\">
                                        <th width=\"50\">
                                            HUGO ID
                                        </th>
                                        <th width=\"60\">
                                            Symbol
                                        </th>
                                        <th width=\"220\">
                                            Name
                                        </th>
                                        <th width=\"100\">
                                            ActualStr
                                        </th>
                                        <th width=\"40\">
                                            Score
                                        </th>
                                        <th width=\"330\">
                                            FlankingText
                                        </th>
                                    </tr>";                        


#  There are removed from the above section
#                                        <th width=\"50\">
#                                            inExClude
#                                        </th>
#                                        <th width=\"50\">
#                                            inExCond
#                                        </th>
                    
                    foreach my $ref (@{$$pmid2passContentRef{$pmid}})
                    {  	print RESULT "<tr><td width=\"50\" onmouseover=\"Tip('Click here to view the details of <b>$$ref[1]</b> at HGNC.')\" onmouseout=\"UnTip()\"><a href=\"$hgncLinkURL$$ref[0]\">$$ref[0]</a></td><td width=\"60\" onmouseover=\"Tip('Click here to view the details of <b>$$ref[1]</b> at Entrez Gene database.')\" onmouseout=\"UnTip()\">";
                    
                    	if (defined $$symbol2ncbiEntrezGeneIDRef{$$ref[1]})
		                {	print RESULT "<a href=\"$ncbiGeneLink$$symbol2ncbiEntrezGeneIDRef{$$ref[1]}\" onmouseover=\"Tip('Click here to view the details of <b>$$ref[1]</b> at Entrez Gene.')\" onmouseout=\"UnTip()\">$$ref[1]</a></td>";
		                }else
		                {	print RESULT "<a href=\"$ncbiGeneSearch$$ref[1] AND Human[Orgn]\" onmouseover=\"Tip('Click here to view the details of <b>$$ref[1]</b> at Entrez Gene.')\" onmouseout=\"UnTip()\">$$ref[1]</a></td>";
		                }
		                
		                print RESULT "<td width=\"220\">$$ref[2]</td><td width=\"100\">$$ref[3]</td><td width=\"40\">$$ref[4]</td><td width=\"330\">$$ref[5]</td></tr>\n"; 
                    }
                    print RESULT "</table>\n
                <p>&nbsp;</p>
                </body>
                </html>";   
                close RESULT;       
                
                
                @positionMark		= ();	undef @positionMark;
                @positionChar		= ();	undef @positionChar;
                %positionSymbol		= ();	undef %positionSymbol;
                @fullActualSymbols	= ();	undef @fullActualSymbols;
            }
        }
    }
}


















sub send_result_email
{   my $resultHTMLURL       = shift;
    my $emailAddress        = shift;
    my $queryAnalInfo   	= shift;
    
    my $resultFile			= "/tmp/".int(rand(1000000000)).'.result';
    
    if ($resultHTMLURL =~ /Query/)
    {   LogQuery("! Sending final result email $resultHTMLURL");
		if ($emailAddress =~ /\@/)
		{   # Probably correct form
		    open (TMP, ">$resultFile");
		    print TMP "\n\nYour SciMiner Mining result is ready at \n\n".
		    		  "Result URL\n\t$resultHTMLURL\n\n".
		              "$queryAnalInfo\n".
		              "\n\n\n! Do not reply ot this email.\n\nPlease, email to $adminEmail if you have any question.\n\n";
		    close TMP;

		    `mail -s \"Your SciMiner Mining results is ready\" \"$emailAddress\" < $resultFile`;
		    unlink ($resultFile);
		    LogQuery("! Email! The mining result has been sent to \"$emailAddress\"");
		}else
		{   LogQuery("! Email! Email could not be sent. Your email address seems to be wrong.");
		}
	}elsif ($resultHTMLURL =~ /Analysis/)
	{	LogAnalysis("! Sending final resultemail $resultHTMLURL");
		if ($emailAddress =~ /\@/)
		{   # Probably correct form
		    open (TMP, ">$resultFile");
		    print TMP "\n\nYour SciMiner Analysis result is ready at \n\n".
		    		  "Result URL\n\t$resultHTMLURL\n\n".
		              "$queryAnalInfo\n\n".
		              "\n\n\n! Do not reply ot this email.\n\nPlease, email to $adminEmail if you have any question.\n\n";
		    close TMP;

		    `mail -s \"Your SciMiner Mining results is ready\" \"$emailAddress\" < $resultFile`;
		    unlink ($resultFile);
		    LogAnalysis("! Email! The analysis result has been sent to \"$emailAddress\"");
		}else
		{   LogAnalysis("! Email! Email could not be sent. Your email address seems to be wrong.");
		}
	}
}



