sub shrink_by_hugoID_2_new_html 
{	my $hugoIDListFile				= shift;
	my $originalGeneSummaryHtml		= shift;
	my $newGeneSummaryHtml			= shift;
	my $baseDir						= shift;
	
	open (HUGOLIST, $hugoIDListFile) || return(-1);
	open (ORIHTML, $originalGeneSummaryHtml) || return(-1);
	if (-f $newGeneSummaryHtml)
	{	return(-1);
	}
	open (NEWHTML, ">".$newGeneSummaryHtml) || return (-1);
	
	my %hugoCheck			= ();
	while(<HUGOLIST>)
	{	my $line 			= $_;
		$line				=~ s/\r|\n//g;
		$hugoCheck{$line}	= 1;
	}	close HUGOLIST;
	
	my @origLines			= <ORIHTML>;
	close ORIHTML;
	
	my $oriString			= join (" ", @origLines);
	$oriString				=~ s/\r|\n//g;

	#  Get hearder and footer string
	my $header				= '';
	my $footer				= '';
	
	if ($oriString			=~ /<tr class/)
	{	$header				= $`;
	}
	if ($oriString			=~ /<\/table>/)
	{	$footer				= $&.$';
	}
	
	# Now start to split the file into blocks'
	my $finalString			= $header;
	$finalString			.= "
                        <tr class=\"titleBarName1\">
                            <th width=\"40\">
                                Rank
                            </th>
                            <th width=\"40\">
                                HUGO
                            </th>
                            <th width=\"60\">
                                Symbol
                            </th>
                            <th width=\"400\">
                                Target Name
                            </th>
                            <th width=\"50\">
                                #Occur
                            </th>
                            <th width=\"50\">
                                #Paper
                            </th>
                            <th width=\"220\">
                                Matched_Terms
                            </th>
                            <th width=\"40\">
                                MiMI
                            </th>                            
                        </tr>\n";
                        
                        
                        
	# Now start to split the file into blocks'
	my @stringSplit			= split(/<\/tr>/, $oriString);
	my $splitCount			= scalar @stringSplit;
	
	
	for (my $i=0; $i < $splitCount; $i++)
	{	if ($stringSplit[$i] =~ /hgnc_id=(\d+)?/)
		{	if (defined $hugoCheck{$1})
			{	$stringSplit[$i]		=~ s/pmid2ListDir/\.\.\/$baseDir\/pmid2ListDir/g;
				$stringSplit[$i]		=~ s/hugoID2ContDir/\.\.\/$baseDir\/hugoID2ContDir/g;
				$finalString			.= $stringSplit[$i]."</tr>\n";
			}
		}
	}	
	
	$finalString	.= $footer."\n";
	print NEWHTML $finalString;
	close NEWHTML;
	return(1);
}





sub load_merged_summary_file_with_parameters
{   my $fileName            = shift;
    my $hugoID2SymbolRef    = shift;
    my $hugoSymbol2IDRef	= shift;
    my $hugoID2NameRef      = shift;
    my $hugoIDsRef          = shift;
    my $hugoIDCntRef        = shift;
    my $hugoIDCntTotalRef	= shift; 
    my $hugoID2OccurRef     = shift;
    my $hugoID2PaperRef     = shift;
    my $MinTopCheck			= shift;
    my $TotalPMID			= shift;
    my $minTopPaper			= shift;
    my $minTopMethod 		= shift;
    my $hugoID2PMIDHashRef	= shift;	
    my $TGBGListFileContent	= shift;
    
    my $TGBGListFileCheck	= 0;
    my %TGBGListFileHash	= ();
    
    #  Process TGBGListFile
    if ((defined $TGBGListFileContent) && ($TGBGListFileContent ne "") && ($TGBGListFileContent =~ /\,/))
    {	my @tmpSplit = split(/\,/, $TGBGListFileContent);
    	foreach (@tmpSplit)
    	{	$TGBGListFileHash{$_}	= 1;
    		LogAnalysis("$_ loaded...");
    	}
    	$TGBGListFileCheck	= 1;
    }	

	$$hugoIDCntTotalRef		= 0;
	LogAnalysis("Loading file $fileName");
	#  If not checking MinTop, then just read and process the file
	if (($MinTopCheck eq 'false') || (not defined $MinTopCheck))
	{	if (-f $fileName)
		{   open (FILENAME, $fileName) || LogAnalysis("Merged Summary file $fileName does not exist");
		    while(<FILENAME>)
		    {   my $line = $_;
		    	if ($line =~ /^#/)
		    	{   next;
		    	}
		        $line =~ s/\r|\n//g;
		        my @tmpSplit = split(/\t/, $line);

		        if (($TGBGListFileCheck) && (not defined $TGBGListFileHash{$tmpSplit[0]}) )
		        {	next;
		        }
		        
		        $$hugoIDCntTotalRef++;
		        push @{$hugoIDsRef}, $tmpSplit[1]; 
		        if (not defined $$hugoID2SymbolRef{$tmpSplit[1]})
		        {   $$hugoID2SymbolRef{$tmpSplit[1]} = $tmpSplit[0];
		        }
		        if (not defined $$hugoSymbol2IDRef{$tmpSplit[0]})
		        {	$$hugoSymbol2IDRef{$tmpSplit[0]} = $tmpSplit[1];
		        }
		        if (not defined $$hugoID2NameRef{$tmpSplit[1]})
		        {   $$hugoID2NameRef{$tmpSplit[1]} = $tmpSplit[2];
		        }
		        $$hugoID2OccurRef{$tmpSplit[1]} = $tmpSplit[3];
		        $$hugoID2PaperRef{$tmpSplit[1]} = $tmpSplit[4];
		        # Process PMID string
		        my @tmpSplit2 	= split (/\,/, $tmpSplit[6]);
		        my %tmpHash		= ();
		        foreach my $tmpPMID (@tmpSplit2)
		        {	$tmpHash{$tmpPMID}	= 1;
		        }
		        $$hugoID2PMIDHashRef{$tmpSplit[1]}	= \%tmpHash;
		    }
		    close FILENAME;
		    $$hugoIDCntRef = scalar @{$hugoIDsRef};
		}
	}
	
	#  or, if checking MinTop, be sure to pay attention to the method
	else
	{	if ((not defined $minTopPaper) || ($minTopPaper eq ""))
		{   $minTopPaper		= 1;
		}
		
		if ((not defined $minTopMethod)  || ($minTopMethod eq ""))
		{	$minTopMethod		= 'MinPaperCount';
		}
	
		#  MinPaperCount Process
		if (($minTopMethod eq 'MinPaperCount') || ($minTopMethod eq 'MinPaperPercentage'))
		{	my $tmpThreshold	= $minTopPaper;
			if ($minTopMethod eq 'MinPaperPercentage')
			{	$tmpThreshold	= $TotalPMID*$minTopPaper/100;
			}
		
			if (-f $fileName)
			{   open (FILENAME, $fileName) || LogAnalysis("Merged Summary file $fileName does not exist");
				while(<FILENAME>)
				{   my $line = $_;
					if ($line =~ /^#/)
					{	next;
					}
				    $line =~ s/\r|\n//g;
				    my @tmpSplit = split(/\t/, $line);
				    
					if (($TGBGListFileCheck) && (not defined $TGBGListFileHash{$tmpSplit[0]}) )
				    {	next;
				    }
				    $$hugoIDCntTotalRef++;
				
					# Only load targets with at least the minimum number of papers
				    if ($tmpSplit[4] < $tmpThreshold)
				    {   next;
				    }
				    
				    push @{$hugoIDsRef}, $tmpSplit[1]; 
				    if (not defined $$hugoID2SymbolRef{$tmpSplit[1]})
				    {   $$hugoID2SymbolRef{$tmpSplit[1]} = $tmpSplit[0];
				    }
				    if (not defined $$hugoSymbol2IDRef{$tmpSplit[0]})
				    {	$$hugoSymbol2IDRef{$tmpSplit[0]} = $tmpSplit[1];
				    }
				    if (not defined $$hugoID2NameRef{$tmpSplit[1]})
				    {   $$hugoID2NameRef{$tmpSplit[1]} = $tmpSplit[2];
				    }
				    $$hugoID2OccurRef{$tmpSplit[1]} = $tmpSplit[3];
				    $$hugoID2PaperRef{$tmpSplit[1]} = $tmpSplit[4];
				    # Process PMID string
				    my @tmpSplit2 	= split (/\,/, $tmpSplit[6]);
				    my %tmpHash		= ();
				    foreach my $tmpPMID (@tmpSplit2)
				    {	$tmpHash{$tmpPMID}	= 1;
				    }
				    $$hugoID2PMIDHashRef{$tmpSplit[1]}	= \%tmpHash;
				}
				close FILENAME;
				
				$$hugoIDCntRef = scalar @{$hugoIDsRef};
			}
		}
		
		#  TopPaperCount Process and others
		else 
		{	if (-f $fileName)
			{   open (FILENAME, $fileName) || LogAnalysis("Merged Summary file $fileName does not exist");
				my %symbol2Occurence			= ();
				my %symbol2Papers				= ();
				my @symbol						= ();
				my %symbol2Name					= ();
				my %symbol2ID					= ();
				my %symbol2PMID					= ();
				while(<FILENAME>)
				{   my $line 					= $_;
					if ($line =~ /^#/)
					{	next;
					}
				    $line 						=~ s/\r|\n//g;
				    my @tmp 					= split(/\t/, $line);
				    if (($TGBGListFileCheck) && (not defined $TGBGListFileHash{$tmp[0]}) )
				    {	next;
				    }
				    
				    $$hugoIDCntTotalRef++;
					$symbol2Occurence{$tmp[0]} 	= $tmp[3];
					$symbol2Papers{$tmp[0]} 	= $tmp[4];
					push @symbol, 				$tmp[0];
					$symbol2Name{$tmp[0]}		= $tmp[2];
					$symbol2ID{$tmp[0]}			= $tmp[1];
					$symbol2PMID{$tmp[0]}		= $tmp[6];
				}	close FILENAME;
				
			    # Sorting by paper and occurrence 
				my %symbolPaperOccurrence = ();
				foreach my $symbol (@symbol)
				{	if (not defined $symbolPaperOccurrence{$symbol2Papers{$symbol}})
					{   my @newArray = ();
						push @newArray, $symbol;
						$symbolPaperOccurrence{$symbol2Papers{$symbol}} = \@newArray;
					}else
					{   push @{$symbolPaperOccurrence{$symbol2Papers{$symbol}}}, $symbol;
					}
				}
				my @newSortedSymbols = ();
				my @sortedCounts = sort {$b <=> $a} keys %symbolPaperOccurrence;
				foreach my $sortedCount ( @sortedCounts)
				{   my @countSortedSymbols = sort {$symbol2Occurence{$b} <=> $symbol2Occurence{$a}} @{$symbolPaperOccurrence{$sortedCount}};
					push @newSortedSymbols, @countSortedSymbols;
				}
				
				# Calculate the threshold
				if (($minTopMethod eq 'TopPaperCount') || ($minTopMethod eq 'TopPaperPercentage'))
				{	my $tmpThreshold	= $minTopPaper;
					if ($minTopMethod eq 'TopPaperCount')
					{	if ($minTopPaper > scalar (@newSortedSymbols))
						{	$tmpThreshold	= scalar (@newSortedSymbols);
						}
					}elsif ($minTopMethod eq 'TopPaperPercentage')
					{	$tmpThreshold	= int((scalar @newSortedSymbols)*$minTopPaper/100);
					} 
					
					for (my $i=0; $i < $tmpThreshold; $i++)
					{   push @{$hugoIDsRef}, $symbol2ID{$newSortedSymbols[$i]}; 
						if (not defined $$hugoID2SymbolRef{$symbol2ID{$newSortedSymbols[$i]}})
						{   $$hugoID2SymbolRef{$symbol2ID{$newSortedSymbols[$i]}} = $newSortedSymbols[$i];
						}
						if (not defined $$hugoSymbol2IDRef{$newSortedSymbols[$i]})
						{	$$hugoSymbol2IDRef{$newSortedSymbols[$i]} = $symbol2ID{$newSortedSymbols[$i]};
						}
						if (not defined $$hugoID2NameRef{$symbol2ID{$newSortedSymbols[$i]}})
						{   $$hugoID2NameRef{$symbol2ID{$newSortedSymbols[$i]}} = $symbol2Name{$newSortedSymbols[$i]};
						}
						$$hugoID2OccurRef{$symbol2ID{$newSortedSymbols[$i]}} = $symbol2Occurence{$newSortedSymbols[$i]};
						$$hugoID2PaperRef{$symbol2ID{$newSortedSymbols[$i]}} = $symbol2Papers{$newSortedSymbols[$i]};

						# Process PMID string
						my @tmpSplit2 	= split (/\,/, $symbol2PMID{$newSortedSymbols[$i]});
						my %tmpHash		= ();
						foreach my $tmpPMID (@tmpSplit2)
						{	$tmpHash{$tmpPMID}	= 1;
						}
						$$hugoID2PMIDHashRef{$symbol2ID{$newSortedSymbols[$i]}}	= \%tmpHash;
					}
				}
				$$hugoIDCntRef = scalar @{$hugoIDsRef};
			}
		}
	}
}






















































































































































































































































































































































































































































































































































































































































































































































































































################################################################################
#
#   SECTION_8   Gene2PubMed Query Queue Processing   
#
################################################################################
# ------------------------------------------------------------------------------
# queue_gene2pubmed_query
# ------------------------------------------------------------------------------
sub queue_gene2pubmed_generif_query
{	my $email               	= shift;
    my $userName            	= shift;
    my $queryName           	= shift;
    my $queryString         	= shift;
    my $listText            	= shift;
    my $count               	= shift;
    my $pmidArrRef          	= shift;
    my $queryType           	= shift;
    my $miningMode				= shift;
    my $speciesExtension		= shift;
    my $tmpLocalURL				= shift;
    
    use DBI;
  
    #  Load working environment for ANNOTATION
    my %annoENV 				= anno_environmental_file_open ( );
    my $annoBaseDir 			= $annoENV{ANNOPath};
	my %currentQueueEnv			= ();
	
	#  Update the SciMinerServerURL
	$annoENV{SciMinerServerURL}	= $tmpLocalURL;
		
    #  Database Access Information
    my $SciMinerDB   = "DBI:mysql:database=".$annoENV{DB} || return (-1, "!ERROR: No database specified");
    my $username    = $annoENV{username} || return (-1, "!ERROR: No username specified");
    my $password    = $annoENV{password} || return (-1, "!ERROR: No password specified");

    #  ------------------------------------------------------------------------
    #  Retrieve User Information from SciMinerDB
    #  ------------------------------------------------------------------------
    my $dbh         = DBI->connect($SciMinerDB, $username, $password, {PrintError => 0}) || return (-1, "!ERROR: Couldn't connect to database ".$DBI::errstr);

    my $sql         = "SELECT userID, passCode, institute FROM user where email = \"$email\"";
    my $sth         = $dbh->prepare($sql);
    $sth->execute();
    my @row         = $sth->fetchrow_array;
    my $userID      = $row[0];
    my $passCode    = $row[1];
    my $instCheck	= 0;
    if ((defined $row[2]) && ($row[2] ne "") && (defined $annoENV{Institution}) && ($annoENV{Institution} eq $row[2]))
    {	$instCheck	= 1;
    }
    
    #  ------------------------------------------------------------------------
    #  Update SciMinerDB for this query and get the queryID
    #  ------------------------------------------------------------------------
    my @tmpArr      = ($userID, $queryName, 1, $queryType);#, $listText);
    my $commands    = "\"".join("\",\"", @tmpArr)."\"";
    my $queryID     = '';
    my $numPMID     = scalar @{$pmidArrRef};
    
    #  Insert new query information 
    $dbh->do("INSERT INTO `query` (userID, queryName, status, listType, dateCreate, numPMID, miningMode) VALUES ($commands, curdate(), $numPMID, \"$miningMode\")") || print "!ERROR: $tmpArr[0] $DBI::errstr\n" ;   
    
    #  Retrieve the queryID of the recently inserted query
    $sth            = $dbh->prepare("SELECT queryID FROM query ORDER BY queryID DESC LIMIT 1");
    $sth->execute();
    @row            = $sth->fetchrow_array;#($result);
    $queryID        = $row[0];
    
    #  ------------------------------------------------------------------------
    #  Write the query info into a file
    #  ------------------------------------------------------------------------    
    my @tmpSplit        = split(/\@/, $email);
    my $fileNameBase    = 'GRIFQuery_'.$queryID.'__'.$tmpSplit[0];
    my $confFileName    = "/tmp/".$fileNameBase.'.conf';
    my $listFileName    = "/tmp/".$fileNameBase.'.list';
    
	#  Final Result Directory
    mkdir ("$annoENV{SciMinerPath}Work/FinalResults/") 				|| print "";
    mkdir ("$annoENV{SciMinerPath}Work/FinalResults/$fileNameBase/") || print "";
    mkdir ("$annoENV{SciMinerWebPath}FinalResults/") 				|| print "";
    mkdir ("$annoENV{SciMinerWebPath}FinalResults/$fileNameBase/") 	|| print "";
    

    
    #  Check the number of PMID before actually writing and continuing to next step
    my $pmidCount       = scalar @{$pmidArrRef};
    if ($pmidCount <= 0)
    {   #  This query will not be processed
        print "<p> Your query resulted in 0 valid Pubmed document and will not be processed by SciMiner. <br><br>".
              "Please check your query and run again.</p>";
        return (0);
    }

    #  Write the PMID list into file
    open (LIST, ">".$listFileName) || print "! Can't write into file. Contact the admin<br>";    
    foreach my $pmid (@{$pmidArrRef})
    {   print LIST $pmid."\n";
    }       
    close (LIST);
    
    #  Write configuration into file
    open (CONF, ">".$confFileName) || print "! Can't write into file. Contact the admin<br>";
    print CONF "queryID\t$queryID\n";
    print CONF "email\t$email\n";
    print CONF "userName\t$userName\n";
	print CONF "queryString\t$queryString\n";
    print CONF "queryName\t$queryName\n";
    print CONF "count\t$count\n";
    print CONF "fileNameBase\t$fileNameBase\n";
    my $queryAnalInfo	= 	"-- SciMiner NCBI GeneRIF Mining Query Info--\n".
							"Query ID     : $queryID\n".
    						"Query name   : $queryName\n".
    						"# of PMIDs   : $count\n";
    if (defined $queryString)
    {	$queryAnalInfo	.= "Query string : $queryString\n\n"; 
    }

	print CONF "miningMode\t$miningMode\n";
	print CONF "speciesExtension\t$speciesExtension\n";
	print CONF "SciMinerServerURL\t$tmpLocalURL\n";
	print CONF "InstitutionCheck\t$instCheck\n";
    close (CONF);    

	#  Creating currentQueueEnv hash 
	$currentQueueEnv{queryID}			= $queryID;
	$currentQueueEnv{email}				= $email;
	$currentQueueEnv{userName}			= $userName;
	$currentQueueEnv{queryName}			= $queryName;
	$currentQueueEnv{queryString}		= $queryString;
	$currentQueueEnv{count}				= $count;
	$currentQueueEnv{fileNameBase}		= $fileNameBase;
	$currentQueueEnv{miningMode}		= $miningMode;
	$currentQueueEnv{speciesExtension}	= $speciesExtension;	
	$currentQueueEnv{SciMinerServerURL}	= $tmpLocalURL;
	$currentQueueEnv{InstitutionCheck}	= $instCheck;			
	
    #  Generate a temporary result html file
    generate_temporary_result_html ("$annoENV{SciMinerServerURL}/SciMiner/FinalResults/$fileNameBase/result.html",
                                	"$annoENV{SciMinerWebPath}FinalResults/$fileNameBase/result.html",
                                	\%currentQueueEnv, 
                                	"$annoENV{SciMinerServerURL}/SciMiner/");
                                	
                                	
    #  Move the created configuration files
    `mv $confFileName $annoENV{SciMinerPath}/Work/`;
    `mv $listFileName $annoENV{SciMinerPath}/Work/`;


    #  Initiate the SciMiner auto process if not running
    my $psResult = `ps -ef | grep 'MonitorSciMinerGRIFQueue.pl'`;
    my $SciMinerQueueMonitorStatus = 0;
    my @tmpLineSplit = split (/\n/, $psResult);

    foreach my $line (@tmpLineSplit)
    {   if ($line =~ /perl/)
        {   # There is a process running with 'MonitorSciMinerGRIFQueue.pl'
            $SciMinerQueueMonitorStatus = 1;
        }
    }
    
    #  Launch SciMinerG2PQueueMonitor.pl only when it's not running
    if (! $SciMinerQueueMonitorStatus)
    {   #  If there is no SciMinerQueueMonitor running
    	#  Check and delete 'CurrentQueue' and 'CurrentList'
    	if (-f "$annoENV{SciMinerPath}/Work/CurrentGRIFList")
    	{   `rm $annoENV{SciMinerPath}/Work/CurrentGRIFList`;
    	}
    	if (-f "$annoENV{SciMinerPath}/Work/CurrentGRIFQueue")
    	{   `rm $annoENV{SciMinerPath}/Work/CurrentGRIFQueue`;
    	}    	
    	system ("$annoENV{Perl} $annoENV{SciMinerPath}/Scripts/Main/MonitorSciMinerGRIFQueue.pl &");
    }
    
    

	my ($aheadFileCnt, $newAheadDocuments, $completelyNewDocCount)
    	= calculate_new_document_count_ahead_of_query_grif ($queryID, \%annoENV, $dbh, $pmidArrRef);

	my $startProcessingTimeSeconds	= 	$aheadFileCnt*5 + 				# query processing
										$aheadFileCnt*20 + 				# summarizing
										$newAheadDocuments*0.03; 		# new document

	my $startProcessingTimeStr		=	'';
	if ($startProcessingTimeSeconds >= 3600)
	{	my $hours	= int($startProcessingTimeSeconds / 3600);
		$startProcessingTimeStr		= "within $hours hour(s)";
	}elsif ($startProcessingTimeSeconds <= 60)
	{	$startProcessingTimeStr		= "within 1 minute";
	}else
	{	my $minutes	= int($startProcessingTimeSeconds / 60);
		$startProcessingTimeStr		= "within $minutes minute(s)";
	}
	
	my $currentProcessingTime		= 	$completelyNewDocCount*0.03 + 30 + 20;
	my $currentProcessingTimeStr	= '';
	if ($currentProcessingTime >= 3600)
	{	my $hours	= int($currentProcessingTime / 3600);
		$currentProcessingTimeStr	= "~ $hours hours";
	}elsif ($currentProcessingTime <= 60)
	{	$currentProcessingTimeStr		= "less than 1 minute";
	}else
	{	my $minutes	= int($currentProcessingTime / 60);
		$currentProcessingTimeStr		= "~ $minutes minutes";
	}
	
	
    #  !_! New formatted table for result summary
    print 	"<table border='1' width='800' align='center' style=\"text-align: center\">
				<tr class='titleBarName1'>
					<th width='300'>User Email</th>
					<th width='500'>$email</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Query Name</th>
					<th>$queryName</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Query String</th>
					<th>";
	if ((defined $queryString) && ($queryString ne ""))
	{	print "$queryString</th>";
	}else
	{	print "&nbsp;</th>";
	}
	print 	"	</tr>
				<tr class='titleBarName1'>
					<th>Query ID #</th>
					<th>$queryID</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Number of total documents</th>
					<th>$count</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Number of new documents</th>
					<th>$completelyNewDocCount (these will take more time)</th>
				</tr>
				<tr class='titleBarName1'>	
					<th>
						&nbsp;
					</th>
					<th>
						&nbsp;
					</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Number of queued queries<br>ahead of your query</th>
					<th>$aheadFileCnt</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Submission Time</th>
					<th>".get_current_time_full()."</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Estimated initaition time</th>
					<th>$startProcessingTimeStr</th>
				</tr>
				<tr class='titleBarName1'>
					<th>Estimated processing time</th>
					<th>$currentProcessingTimeStr</th>
				</tr>
    		</table>";
    		
    		
	print "<p align=\"center\" class=\"titleBarName1\"> Note that your query resulted in <b>$count</b> documents.<br>";
    print "Your result will be sent to <b>$email</b> when it's ready.<br><br>";

    #  Give the order in the queue
    sleep(1);
    my $difference = 0;
    if (-f "$annoENV{SciMinerPath}/Work/CurrentGRIFQueue")
    {   open (CURRENT, "$annoENV{SciMinerPath}/Work/CurrentGRIFQueue");
        my $currentQueryNumber = <CURRENT>;
        close CURRENT;
        $currentQueryNumber =~ s/\r|\n//g;
        $difference = $queryID - $currentQueryNumber;
    }
    
    
    print "There are <b>$difference queries</b> queued ahead of this query. <br>";
	print "Your result will be sent to $currentQueueEnv{email} when it's ready.<br>";
    
    my $resultHTMLURL = $annoENV{SciMinerServerURL}."SciMiner/FinalResults/$fileNameBase/result.html";
    my $shortResultHTMLURL = "FinalResults/$fileNameBase/result.html";
    print "Result will be at <a href=\"$resultHTMLURL\">$resultHTMLURL</a><br><br>";
    print "You should expect your own query processed at <b>2,000 NEW documents / minute</b> <br>
               But this can be slightly affected by the internet connection. <br>";

    #  Update query table for resultURL
    $dbh->do("UPDATE query SET resultURL=\"$shortResultHTMLURL\" WHERE queryID = $queryID");

    #  Send out initial email
    if (( defined $annoENV{'SendMail'}) && ($annoENV{'SendMail'}))
	{	send_initial_email($resultHTMLURL, $email, $fileNameBase, $queryAnalInfo );
	}

    print "An email with this link has been sent out for your convenience</p>"; 
    

}



















# -------------------------------------------------------------------------------------------------
#                   process_current_grifquery_queue
# -------------------------------------------------------------------------------------------------
sub process_current_grifquery_queue
{	my $pname                           = 'SciMiner_v2.2';
    my $corpusRefetchOption             = 0;
    my $cssFileName						= 'sciminer-modern.css';
    my $sciminerJScriptFileName			= 'sciminer.js';
	my $tooltipScriptFileName			= 'wz_tooltip.js';
	
		        

    #  Load working environment for ANNOTATION
    my %annoENV = anno_environmental_file_open ( );
    my $annoBaseDir = $annoENV{ANNOPath};

	#  MeSH tree/dist file names
	my $MeSHTreeFile	= "$annoENV{SciMinerPath}/Work/MeSH/mtrees2008.bin";
	my $MeSHDistFile	= "$annoENV{SciMinerPath}/Work/MeSH/NCIBIDBXMeSHDistExplicit.txt";
	
    #  Initialize variables, hashes, arrays
    my $currentQueue                    = '';
    my $CorpusReserviorOriginalDoc      = "$annoENV{SciMinerPath}/CorpusData/Original/";
    my $CorpusReserviorProcessedDoc     = "$annoENV{SciMinerPath}/CorpusData/Processed/";
    my $CorpusReserviorTmpOriginalDoc   = "$annoENV{SciMinerPath}/CorpusData/TmpOriginal/";
    my $CorpusReserviorTmpProcessedDoc  = "$annoENV{SciMinerPath}/CorpusData/TmpProcessed/";
    my $fileCopyRequired				= 0;
    
    #  Read the 'CurrentQueue' file
    open (QUEUE, "$annoENV{SciMinerPath}/Work/CurrentGRIFQueue" ) || return (-1, "No GeneRIF Queue file");
    $currentQueue   = <QUEUE>;
    $currentQueue   =~ s/\r|\n//g;
    close (QUEUE);
    
    #  Read the current PMID list from queued file
    my @confFileList    = glob ("$annoENV{SciMinerPath}/Work/GRIFQuery_".$currentQueue."__*.conf");
    my @listFileList    = glob ("$annoENV{SciMinerPath}/Work/GRIFQuery_".$currentQueue."__*.list");
    my %currentQueueEnv = ();
    my @PMIDList        = ();
    my @tmpSplit		= ();
    
    open (CONF, $confFileList[0]);
    while(<CONF>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        my @tmpSplit = split (/\t/, $line);
        $currentQueueEnv{$tmpSplit[0]} = $tmpSplit[1];
    }
    close (CONF);
    
    
    # Reset the current URL from the configuration
    if (defined $currentQueueEnv{SciMinerServerURL})
    {   $annoENV{SciMinerServerURL}	= $currentQueueEnv{SciMinerServerURL};
    }
       	
    open (LIST, $listFileList[0]);
    while(<LIST>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        push @PMIDList, $line;
    }
    close (LIST);
    
    #  Mark the starting of the query process
   	LogGRIFQuery("~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~");
    LogGRIFQuery("--- Processing GRIFQuery_$currentQueue is initiated!");
 
    #  Generate PMID list string for DB Query
    my $pmidFull    = join (',', @PMIDList);
        
    #  Final Result Directory
    my @nameSplit1          = split (/\//, $confFileList[0]);
    my @nameSplit2          = split (/\.conf/, $nameSplit1[$#nameSplit1]);
    my $finalResultDir      = "$annoENV{SciMinerPath}Work/FinalResults/$nameSplit2[0]/";
    my $finalResultWebDir   = "$annoENV{SciMinerWebPath}FinalResults/$nameSplit2[0]/";
    mkdir ("$annoENV{SciMinerPath}Work/FinalResults/") || print "";
    mkdir ($finalResultDir) || print "";
    mkdir ("$annoENV{SciMinerWebPath}FinalResults/") || print "";
    mkdir ($finalResultWebDir) || print "";
    `cp -f $annoENV{SciMinerPath}/Work/$currentQueueEnv{fileNameBase}.* $finalResultDir`;
    `cp -f $annoENV{SciMinerPath}/Work/$currentQueueEnv{fileNameBase}.* $finalResultWebDir`;

	#  Copy the PMID list file to the web result directory
	LogGRIFQuery("~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~");
	`cp $annoENV{SciMinerPath}/Work/$nameSplit2[0].list $finalResultWebDir/$nameSplit2[0]_list.txt`;
	LogGRIFQuery("PMID list file at $annoENV{SciMinerPath}Work/$nameSplit2[0].list");
	LogGRIFQuery("Configuration  at $finalResultWebDir/$nameSplit2[0]_list.txt");

	    
    #  Copy css and java script file to the final result directory
    `cp /home/hurlab/apache-tomcat-9.0.37/webapps/SciMiner1.1/css/sciminer-modern.css $finalResultWebDir/`;
    `cp $annoENV{SciMinerWebPath}/$sciminerJScriptFileName $finalResultWebDir/`;
	`cp $annoENV{SciMinerWebPath}/$tooltipScriptFileName $finalResultWebDir/`;
	
    #  Copy the Image directory
    `cp -R $annoENV{SciMinerWebPath}/Images $finalResultWebDir/`;

    #  Connect to the SciMiner DB
    my $SciMinerDB   = "DBI:mysql:database=".$annoENV{DB} || return (-1, "!ERROR: No database specified");
    my $username    = $annoENV{username} || return (-1, "!ERROR: No username specified");
    my $password    = $annoENV{password} || return (-1, "!ERROR: No password specified");
    my $dbh = DBI->connect($SciMinerDB, $username, $password, {PrintError => 0});
    if (!$dbh) {
        warn "Could not open database: " . ($DBI::errstr || 'unknown error');
        return (-1, "!ERROR: Couldn't connect to database " . ($DBI::errstr || 'unknown error'));
    }

    #  Update Query table current status of the db
    $dbh->do("UPDATE query SET dateStart=curdate(), timestampStart=curtime(), status=2 WHERE queryID = $currentQueue");

    #  Retrieve the status of documents
    LogGRIFQuery("Retrieving pmid2journal info from SciMinerDB");
	my (%pmid2journal, %pmid2Title, %pmid2Abstract, %pmid2lang);
    my $sql = "SELECT pmid, journal, title, abstract FROM documentpubmed WHERE pmid in ($pmidFull)";
    my $sth = $dbh->prepare($sql);
    my @row = ();
    $sth->execute();

	my %processedPMID			= ();
    while(@row = $sth->fetchrow_array)
    {   $processedPMID{$row[0]}	= 1;

    	if (defined $row[1])
    	{	$pmid2journal{$row[0]}	= $row[1];
    	}else
    	{	$pmid2journal{$row[0]}	= "";
    	}
    	
    	if (defined $row[2])
    	{	$pmid2Title{$row[0]}	= $row[2];
    	}else
    	{	$pmid2Title{$row[0]}	= "";
    	}
    	
    	if (defined $row[3])
    	{	$pmid2Abstract{$row[0]}	= $row[3];
    	}else
    	{	$pmid2Abstract{$row[0]}	= "";
    	}
    }
    my @PMIDToBeProcessed		= ();

    #  -------------------------------------------------------------------------
	for (my $i=0; $i <= $#PMIDList; $i++)
	{	if (not defined $processedPMID{$PMIDList[$i]})
		{	push @PMIDToBeProcessed, $PMIDList[$i];
		}
	}
    
    #  -------------------------------------------------------------------------
	LogGRIFQuery("! Downloading MEDLINE records if needed");
   	my ($tmpMedLineStatusRef, $tmpMedLineSizeRef)   = Fetch_MEDLINE_From_PMID_List (\@PMIDToBeProcessed, $CorpusReserviorTmpOriginalDoc, $CorpusReserviorOriginalDoc, $corpusRefetchOption, \%pmid2lang, \%pmid2journal, $fileCopyRequired, \%annoENV); 


    #  ----------------------------------------------------------------------------------
    #  Load MeSH Data
    #  ----------------------------------------------------------------------------------
    LogGRIFQuery("! Loading MeSH data tree structure");
#	my ($mtreeID2descIDRef, $mtreeID2treeCodeRef, $treeCode2mtreeIDRef, $treeCode2descIDRef, $descID2treeCodesRef, $MeSHdescID2termRef, $MeSHTerm2descIDRef) 									= load_mesh_tree_data_from_SciMinerDB ($dbh, $currentQueue);
	my ($MeSHdescID2termRef, $MeSHTerm2descIDRef)	= load_mesh_tree_data_from_SciMinerDB_simplified ($dbh, $currentQueue);
    #my ($MeSHCode2DistRef) 		= load_mesh_term_distribution ($MeSHDistFile, $currentQueue);
    my ($MeSHTerm2DistRef) 		= load_mesh_term_distribution_simplified ($MeSHDistFile, $currentQueue);
    

    #  ----------------------------------------------------------------------------------
    #  Process medline file with mesh tree information
    #  ----------------------------------------------------------------------------------
    LogGRIFQuery("! Processing MEDLINE documents with mesh tree grif");
    #process_medline_html_document_with_mesh_tree_grif(
    #	$CorpusReserviorOriginalDoc, \@PMIDToBeProcessed, \%annoENV, \%pmid2Title, \%pmid2Abstract, 
    #	$mtreeID2descIDRef, $mtreeID2treeCodeRef, $treeCode2mtreeIDRef, $treeCode2descIDRef, 
    #	$MeSHdescID2termRef, $descID2treeCodesRef, 
    #	$MeSHTerm2descIDRef, $MeSHCode2DistRef, $dbh, \%pmid2lang);
    
    process_medline_html_document_with_mesh_tree_grif_simplified(
    	$CorpusReserviorOriginalDoc, \@PMIDToBeProcessed, \%annoENV, \%pmid2Title, \%pmid2Abstract, 
    	$MeSHdescID2termRef, $MeSHTerm2descIDRef, $MeSHTerm2DistRef, $dbh, \%pmid2lang);
    
    
	#  ----------------------------------------------------------------------------------
    #  Insert processed medline document into SciMiner database
    #  ----------------------------------------------------------------------------------
    foreach my $pmid (@PMIDToBeProcessed)
    {	$dbh->do("INSERT INTO documentpubmed (pmid, journal, title, abstract) 
    						  VALUES ($pmid, \"$pmid2journal{$pmid}\", \"$pmid2Title{$pmid}\", \"$pmid2Abstract{$pmid}\")") || 
    		  LogGRIFQuery("!Error in creating new documentpubmed info for $pmid");
    }
    
    
    #  ----------------------------------------------------------------------------------
    #  Retrieve ncbiEntrezGeneID and hugo ID // generifpmid2ncbi data
    #  ----------------------------------------------------------------------------------
    #  This depends on the speciesExtension selection.
    #  If human only is selected, first check `ncbigene2hgnc` table to select
    #  only taxID = 9606 data
    my %entrezGeneID2hgncID				= ();
    my %hgncID2entrezGeneID				= ();
    my %hgncID2pmidGRIFubmed			= ();
    my %pmid2hgncIDContent				= ();
    my %pmid2hgncIDCount				= ();
    my %hgncID2pmidCount				= ();
    my %hgncID2approvedSymbol			= ();
    my %hgncID2approvedName				= ();
    
    if ($currentQueueEnv{'speciesExtension'} eq 'humanOnly')
    {	$sql	= "SELECT entrezGeneID, taxID, hgncID 
	   			   FROM ncbigene2hgnc 
	   			   WHERE taxID = 9606";
    }else
    {	$sql	= "SELECT entrezGeneID, taxID, hgncID 
	   			   FROM ncbigene2hgnc";
    }
    
    $sth	= $dbh->prepare($sql); 
	$sth->execute();
	while(@row = $sth->fetchrow_array)
	{   $entrezGeneID2hgncID{$row[0]}	= $row[2];
		if ($row[1] eq '9606')
		{	#  Only assign human entrezGeneID from hgncID
			$hgncID2entrezGeneID{$row[2]}	= $row[0];
		}
	}
	
	
	#  -------------------------------------------------------------------------
	#	Retrieve either generifpmid2ncbi or pmid2ncbi (gene2pubmed)
	#  -------------------------------------------------------------------------
	if ($currentQueueEnv{'miningMode'} eq 'NCBIGeneRIF')
	{	$sql	= "SELECT pmid, ncbiIDString 
	   			   FROM generifpmid2ncbi 
	   			   WHERE pmid in ($pmidFull)";
	}else	# miningMode is NCBIGene2PubMed
	{	$sql	= "SELECT pmid, ncbiIDString 
	   			   FROM pmid2ncbi 
	   			   WHERE pmid in ($pmidFull)";
	}
	$sth	= $dbh->prepare($sql); 
	$sth->execute();
	
	while(@row = $sth->fetchrow_array)
	{   @tmpSplit	= split (/;/, $row[1]);
		for (my $i = 0; $i <= $#tmpSplit; $i++)
		{	if (defined $entrezGeneID2hgncID{$tmpSplit[$i]})
			{	if (defined $hgncID2pmidGRIFubmed{$entrezGeneID2hgncID{$tmpSplit[$i]}})
				{	$hgncID2pmidGRIFubmed{$entrezGeneID2hgncID{$tmpSplit[$i]}}->{$row[0]}	= 1;
				}else
				{	my %newTmpHash	= ();
					$newTmpHash{$row[0]}	= 1;
					$hgncID2pmidGRIFubmed{$entrezGeneID2hgncID{$tmpSplit[$i]}}->{$row[0]}	= \%newTmpHash;
				}
				
				if (defined $pmid2hgncIDContent{$tmpSplit[0]})
				{	$pmid2hgncIDContent{$tmpSplit[0]}->{$entrezGeneID2hgncID{$tmpSplit[$i]}}	= 1;
				}else
				{	my %newTmpHash				= ();
					$newTmpHash{$tmpSplit[$i]}	= 1;
					$pmid2hgncIDContent{$row[0]}->{$entrezGeneID2hgncID{$tmpSplit[$i]}}	= \%newTmpHash;
				}
			}else
			{	# UPDATE-POINT: For non-hgnc ncbi genes to be included.
			}
		}
	}
	
	#  Calculate pmid2hgncIDCount
	foreach my $tmpPMID (@PMIDList)
	{	if (defined $pmid2hgncIDContent{$tmpPMID})
		{	@tmpSplit	= keys %{$pmid2hgncIDContent{$tmpPMID}};
			$pmid2hgncIDCount{$tmpPMID}	= scalar @tmpSplit;
		}else
		{	$pmid2hgncIDCount{$tmpPMID}	= 0;
		}
	}
	#%pmid2hgncIDContent	= ();		# Erase from the memory    

    #  Retrieve hgnc symbol and name
    my $hgncIDString	= join(",", keys %hgncID2pmidGRIFubmed);
   	$sql	= "SELECT hgncID, approvedSymbol, approvedName 
   			   FROM gene 
   			   WHERE hgncID in ($hgncIDString)";
	$sth	= $dbh->prepare($sql); 
	$sth->execute();
	while(@row = $sth->fetchrow_array)
    {   if (defined $row[2])
        {   $hgncID2approvedSymbol{$row[0]}	= $row[1];
        	$hgncID2approvedName{$row[0]}	= $row[2];	
        }
    }
    
    #  Generate summary data
    open (MERSUM, ">".$finalResultWebDir."SciMinerBase.MerSum.txt") || LogGRIFQuery("!ERROR Can't create SciMinerBase.MerSum.sorted.txt");
    print MERSUM "#Symbol\tID\tName\tOccur\tPaper\tMatchStr\tPMID\n";
    my $tmpPMIDString	= '';
    foreach my $tmpHGNCID (keys %hgncID2pmidGRIFubmed)
    {	@tmpSplit						= keys %{$hgncID2pmidGRIFubmed{$tmpHGNCID}};
    	$hgncID2pmidCount{$tmpHGNCID}	= scalar @tmpSplit;
    	$tmpPMIDString					= join(",", @tmpSplit);
    	
    	print MERSUM 	$hgncID2approvedSymbol{$tmpHGNCID}."\t".$hgncID2approvedSymbol{$tmpHGNCID}."\t".
    					$hgncID2approvedName{$tmpHGNCID}."\t"."1\t".$hgncID2pmidCount{$tmpHGNCID}."\t".
    					" \t".$tmpPMIDString."\n";
    }
    close MERSUM;
   	
	#  Generate sorted mersum data file
	my @sortedHGNCID	= sort {$hgncID2pmidCount{$b} <=> $hgncID2pmidCount{$a}} keys %hgncID2pmidCount;
	open (MERSUM, ">".$finalResultWebDir."SciMinerBase.MerSum.sorted.txt") || LogGRIFQuery("!ERROR Can't create SciMinerBase.MerSum.sorted.txt");
    print MERSUM "#Symbol\tID\tName\tOccur\tPaper\tMatchStr\tPMID\n";
    foreach my $tmpHGNCID (@sortedHGNCID)
    {	@tmpSplit						= keys %{$hgncID2pmidGRIFubmed{$tmpHGNCID}};
    	$hgncID2pmidCount{$tmpHGNCID}	= scalar @tmpSplit;
    	$tmpPMIDString					= join(",", @tmpSplit);
    	
    	print MERSUM 	$hgncID2approvedSymbol{$tmpHGNCID}."\t".$tmpHGNCID."\t".
    					$hgncID2approvedName{$tmpHGNCID}."\t"."1\t".$hgncID2pmidCount{$tmpHGNCID}."\t".
    					" \t".$tmpPMIDString."\n";
    }
    close MERSUM;
    
   
    #  ----------------------------------------------------------------------------------
    #  Generate result html
    #  ----------------------------------------------------------------------------------

	generate_grif_result_pages (
		\%annoENV, $pname, \@PMIDList, $dbh,
		$cssFileName, $sciminerJScriptFileName, 
		$finalResultDir, $finalResultWebDir, \%currentQueueEnv, 
		$currentQueue, 

		$MeSHdescID2termRef, $MeSHTerm2descIDRef, $MeSHTerm2DistRef,

		\%pmid2journal, \%pmid2Title, \%pmid2Abstract,
		\%hgncID2entrezGeneID, \%entrezGeneID2hgncID, \%hgncID2pmidCount, \%pmid2hgncIDCount, 
		\%hgncID2pmidGRIFubmed, \%pmid2hgncIDContent,
		\%hgncID2approvedSymbol, \%hgncID2approvedName
		);


    #  ----------------------------------------------------------------------------------
    #  Remove completed files and update the status
    #  ----------------------------------------------------------------------------------
    LogGRIFQuery("! Deleting the completed grifquery $currentQueueEnv{fileNameBase}");
    remove_completed_grifqueue_update_status (\%annoENV, $currentQueueEnv{fileNameBase}, $dbh, $currentQueue);


}









sub remove_completed_grifqueue_update_status
{   my $annoENVRef      = shift;
    my $fileNameBase    = shift;
    my $dbh             = shift;
    my $queryNumber     = shift;
    
    `rm -Rf $$annoENVRef{SciMinerPath}/Work/$fileNameBase.*`;
    `rm -Rf $$annoENVRef{SciMinerPath}/Work/CurrentGRIFQueue`;
    `rm -Rf $$annoENVRef{SciMinerPath}/Work/CurrentGRIFList`;
    
    #  Update Query table current status of the db
    $dbh->do("UPDATE query SET dateEnd=curdate(), timestampEnd=curtime(), status=3 WHERE queryID = $queryNumber");
    
}







sub grif_generate_mesh_distribution_from_corpus_simplified
{   use Text::NSP::Measures::2D::Fisher::twotailed;

    my $MeSHdescID2termRef			= shift;
    my $MeSHTerm2descIDRef			= shift;
    my $MeSHTerm2DistRef			= shift;
    my $dbh                         = shift;
    my $pmidListRef                 = shift;
    my $wholePMIDCnt                = shift;
    my $finalResultDir              = shift;
    my $finalResultWebDir           = shift;
    
    
    #  Retrieve all docMeSH data for the given PMIDs
    my %pmid2treeCodeHash            = ();
    my %corpusTreeCode2Dist         = ();
    #my %corpusDescID2Dist           = ();
    #my %pmidDiscIDCheck             = ();
    my %treeCode2PMID				= ();		# Hash for hash of pmid and tree code
    my %meshDescID2PMID				= ();
    
    my $pmidFull                    = join (',', @{$pmidListRef});
    my $pmidCntCorpus               = scalar @{$pmidListRef};
    my $sql                         = "SELECT pmid, descIDString FROM docmeshg2p WHERE pmid in ($pmidFull) and explicit like 'E'";
    my $sth                         = $dbh->prepare($sql);
    my @row                         = ();
    $sth->execute();


    #  TODO: Remove $corpusDescID2Dist if not needed to enhance the overall performance

	
	my %pmid2descIDHash				= ();
	my %corpusDescID2Dist			= ();
	my %descID2PMID					= ();
	my @tmpDescIDArray				= ();
	
    #  Handling the retrieved results
    while(@row=$sth->fetchrow_array)
    {   if ((defined $row[1]) && ($row[1] ne ""))
        {   @tmpDescIDArray	= split (/\;/, $row[1]);
        	foreach my $tmpDescID (@tmpDescIDArray)
        	{	if (not defined $pmid2descIDHash{$row[0]})
		        {   my %tmpHash					= ();
		        	$tmpHash{$tmpDescID}			= 1;
		            $pmid2descIDHash{$row[0]} 	= \%tmpHash;
		            if (not defined $corpusDescID2Dist{$tmpDescID})
				    {   $corpusDescID2Dist{$tmpDescID} = 1;
				    }else
				    {   $corpusDescID2Dist{$tmpDescID}++;
				    }
		        }else
		        {   if (not defined $pmid2descIDHash{$row[0]}->{$tmpDescID})
		        	{	$pmid2descIDHash{$row[0]}->{$tmpDescID}	= 1;
		        		if (not defined $corpusDescID2Dist{$tmpDescID})
						{   $corpusDescID2Dist{$tmpDescID} = 1;
						}else
						{   $corpusDescID2Dist{$tmpDescID}++;
						}
		        	}
		        }
		        
		        #  Add descID2PMID
		        if (not defined $descID2PMID{$tmpDescID})
		        {	my %hashTmp				= ();
		        	$hashTmp{$row[0]}		= 1;
		        	$descID2PMID{$tmpDescID}	= \%hashTmp;
		        }else
		        {	$descID2PMID{$tmpDescID}->{$row[0]}	= 1;
		        }
        	}
        }
    }
    

    #  Sort the distribution by occurrence
    my @sortedMeSHTreeDescID			= sort {$corpusDescID2Dist{$b} <=> $corpusDescID2Dist{$a}} keys %corpusDescID2Dist;
    my %descID2Pvalue					= ();
    my %descID2Matrix					= ();
    my %descID2Ratio					= ();
    
    #  $wholePMIDCnt
    my $np2 = $wholePMIDCnt;            # number of whole PMIDs that were used to generate the whole distribution
    my $np1 = $pmidCntCorpus;           # number of PMIDs in the current corpus
    my $npp = $np1 + $np2;
    my $n1p = 0;                        # number of PMIDs with the given code
    my $n11 = 0;                        # number of PMIDs common
    my $n12 = 0;
    my $n21 = 0;
    my $n22 = 0;
    my $twotailedPvalue = 0;
    my $errorCode = "";
    my $ratioCorpus = 0;
    my $ratioFull   = 0;
     
    # TATATA TODO .. This section seems to be for SciMiner result page  
    my %tPlusString		= ();
    my %tMinusString	= ();
    my %commonString	= ();
    my %bPlusString		= ();
    my %bMinusString	= ();
    my %commonCount		= ();
    my %tUniqCount		= ();
    my %bUniqCount		= ();
    my %tUniqString		= ();
    my %bUniqString		= ();
    
	#          word2   ~word2                       corpus         full
	#  word1    n11      n12 | n1p       MeSH+        n11          n12     n1p
	# ~word1    n21      n22 | n2p       MeSH-        n21          n22     n2p
	#           --------------
	#           np1      np2   npp                    np1          np2     npp
 

    #  Perform chi-square // Fisher-exact test .. Since it's 2 by 2, stay with fisher-exact test
    #  This calculation is done through Text::NSP package
    
    my $sortedMeSHCount	= scalar @sortedMeSHTreeDescID;
    LogGRIFQuery("! Total MeSH term count is $sortedMeSHCount");

    foreach my $descID (@sortedMeSHTreeDescID)
	{   #  Initialize string and count
		$tPlusString{$descID}	= join(',', keys %{$descID2PMID{$descID}});
	    $tMinusString{$descID}	= '';
	    
	    foreach my $tmpPmidID (@{$pmidListRef})
	    {	if (not defined $descID2PMID{$descID}->{$tmpPmidID})
	    	{	$tMinusString{$descID}	.= $tmpPmidID.',';
	    	}
	    }
	    
		$n11 = $corpusDescID2Dist{$descID};
	    $n12 = $$MeSHTerm2DistRef{$$MeSHdescID2termRef{$descID}};
	    $n1p = $n11 + $n12;                             # Note that n1p = n11 + n12
	    $n21 = $np1 - $n11;
	    $n22 = $np2 - $n12;
	    
	    $twotailedPvalue = calculateStatistic (n11 => $n11, 
	                                           n1p => $n1p,
	                                           np1 => $np1,
	                                           npp => $npp);
	    if ( ($errorCode = getErrorCode()))
	    {   $descID2Pvalue{$descID} = -1;
	    }else
	    {   $descID2Pvalue{$descID} = sprintf("%.3e",$twotailedPvalue);
	    }
	    
	    $descID2Matrix{$descID} = $np1."\t".$n11."\t".$n21."\t".$n12."\t".$n22."\t".$np2."\t";
	    $ratioCorpus    = $n11/$np1;
	    $ratioFull      = $n12/$np2;
	        
	    if (($n12 != 0) && ($n11 != 0))
	    {   $descID2Matrix{$descID} .= sprintf("%.2f\t%.2f\t%.1f",$ratioCorpus, $ratioFull, ($ratioCorpus)/($ratioFull));
	    }else
	    {   # This is very unlike to happen. But in case it happens. 
	    	my $tmpTag		= $tgZeroTag;
	    	if ($n12 == 0)
	    	{	$tmpTag		= $bgZeroTag;
	    	}
	        $descID2Matrix{$descID} .= sprintf("%.2f\t%.2f\t",$ratioCorpus, $ratioFull).$tmpTag;
	    }
	}


    #  Creating corpus MeSH distribution
    my @sortedDescIDCodes = sort {$descID2Pvalue{$a} <=> $descID2Pvalue{$b}} keys %descID2Pvalue;
    
    open (TMP, ">$finalResultWebDir/MeSHCodeDistribution.txt");
    open (PMID, ">$finalResultWebDir/MeSHCodeDistribution.pmid");
    #  Print out the header first
    print TMP "#DescID\tMeSH\tCorpusSize\tt+\tt-\tb+\tb-\tWholeSize\tt-Ratio\tb-Ratio\tt-ratio/b-ratio\tP-value\n";
    
    foreach my $descID (@sortedDescIDCodes)
    {   print TMP 	$descID."\t".$$MeSHdescID2termRef{$descID}."\t".$descID2Matrix{$descID}."\t".$descID2Pvalue{$descID}."\n";
    	print PMID 	$descID."\t".$$MeSHdescID2termRef{$descID}."\t".$tPlusString{$descID}."\t".$tMinusString{$descID}."\n";
    
    }
    close PMID;
    close TMP;
}



















































































































































































































































































































































































































































































#  !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
#  This sub-routine just calls another Perl script
#  if there is any PMID file to be processed
#  !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
sub generate_grif_result_pages
{   my $annoENVRef                  = shift;
    my $pname                       = shift;
    my $pmidListRef                 = shift;
    my $dbh                         = shift;
    
    my $cssFileName					= shift;
	my $sciminerJScriptFileName		= shift;        
    
    my $finalResultDir              = shift;
    my $finalResultWebDir           = shift;
    my $currentQueueEnvRef          = shift;
    my $queryID                     = shift;
    
    my $MeSHdescID2termRef			= shift;
    my $MeSHTerm2descIDRef			= shift;
    my $MeSHTerm2DistRef			= shift;

	my $pmid2journalRef				= shift;
    my $pmid2TitleRef				= shift;
    my $pmid2AbstractRef			= shift;
    
    my $hgncID2entrezGeneIDRef		= shift;
    my $entrezGeneID2hgncIDRef		= shift;
    my $hgncID2pmidCountRef			= shift;
	my $pmid2hgncIDCountRef			= shift;
	my $hgncID2pmidGRIFubmedRef		= shift;
	my $pmid2hgncIDContentRef		= shift;
	
	my $hgncID2approvedSymbolRef	= shift;
	my $hgncID2approvedNameRef		= shift;
	

    #  Create links to the original files
    my $docLinkDir              = $finalResultWebDir.'Docs';
    mkdir ($docLinkDir) 		|| print "";
    my %medlineSymbolicLink     = ();
    my %medlineEndnoteSymLink	= ();
    my %htmlSymbolicLink        = ();
    


    #  ----------------------------------------------------------------------------------
    #  Step 7-2. MeSH statistics handling
    #  ----------------------------------------------------------------------------------     
    LogGRIFQuery("! Generating MeSH distribution from corpus");
    #grif_generate_mesh_distribution_from_corpus ($mtreeID2descIDRef, $mtreeID2treeCodeRef, $treeCode2mtreeIDRef, $treeCode2descIDRef, $MeSHdescID2termRef, $descID2treeCodesRef, $MeSHTerm2descIDRef, $MeSHCode2DistRef, $dbh, $pmidListRef, $$annoENVRef{"WholePMID"}, $finalResultDir, $finalResultWebDir);
    grif_generate_mesh_distribution_from_corpus_simplified (
    	$MeSHdescID2termRef, $MeSHTerm2descIDRef, $MeSHTerm2DistRef,
    	$dbh, $pmidListRef, $$annoENVRef{"WholePMID"}, $finalResultDir, $finalResultWebDir);  


    #  -------------------------------------------------------------------------
    #  Step 8-1. Generate the base PMID list html
    #  -------------------------------------------------------------------------
    LogGRIFQuery("! Generating base PMID list -- pmidlist.html");
    my $pmidListHTMLFile            = "$finalResultWebDir/pmidList.html";
    grif_generate_base_pmid_list_html (
    	$finalResultDir, $finalResultWebDir, $pmidListHTMLFile, $pmid2hgncIDCountRef, $$currentQueueEnvRef{fileNameBase}, 
    	$$annoENVRef{SciMinerServerURL}, $pmid2TitleRef, $docLinkDir, $$annoENVRef{SciMinerPath}."CorpusData/Original/", $pmid2journalRef, 
    	$cssFileName, $$currentQueueEnvRef{InstitutionCheck});
    
    

    #  -------------------------------------------------------------------------
    #  Step 8-2. Generate the gene summary html
    #  -------------------------------------------------------------------------
    LogGRIFQuery("! Generating the summary html -- geneSummary.html");
    my $resultSummaryHTML   = "$finalResultWebDir/geneSummary.html";
        
    my ($rankedHUGOID2contentRef, $rankedHUGOIDsArrayRef)	= grif_generate_summary_html(
    	$finalResultDir, $finalResultWebDir, "$finalResultWebDir/SciMinerBase.MerSum.sorted.txt", $resultSummaryHTML, 
    	$currentQueueEnvRef, $$currentQueueEnvRef{fileNameBase}, $$annoENVRef{SciMinerServerURL}, 
    	$pmid2journalRef, $pmid2TitleRef, $pmid2AbstractRef, 
    	$pmid2hgncIDCountRef,  
    	$cssFileName, $sciminerJScriptFileName, $hgncID2entrezGeneIDRef, $entrezGeneID2hgncIDRef, $hgncID2pmidGRIFubmedRef,
    	$pmid2hgncIDContentRef, $hgncID2approvedSymbolRef, $hgncID2approvedNameRef, $hgncID2pmidCountRef
	);


    #  ----------------------------------------------------------------------------------
    #  Step 9. Generate result email and simple html for display.
    #  ----------------------------------------------------------------------------------     
    my $resultHTMLFile      = "$finalResultWebDir/result.html";
	my $tmpResultHTMLFile	= "$finalResultWebDir/result.tmp";
    LogGRIFQuery("! Generating the primary result file -- result.html");
    grif_SciMiner_Generate_Final_Result_File ($finalResultDir, $finalResultWebDir, $tmpResultHTMLFile, "geneSummary.html", "pmidList.html", 
    									$currentQueueEnvRef, $rankedHUGOID2contentRef, $rankedHUGOIDsArrayRef, $$currentQueueEnvRef{fileNameBase}, 
    									$$annoENVRef{SciMinerServerURL}, 
    									$dbh, $queryID, $$annoENVRef{WholePMID}, $cssFileName, $sciminerJScriptFileName, $hgncID2entrezGeneIDRef);
    `mv -f $tmpResultHTMLFile $resultHTMLFile`;


    #  Generate $queryAnalInfo string
    my $queryAnalInfo	= 	"--Mining Query Info--\n".
							"Query ID     : $$currentQueueEnvRef{queryID}\n".
    						"Query name   : $$currentQueueEnvRef{queryName}\n".
    						"# of PMIDs   : $$currentQueueEnvRef{count}\n";
    if (defined $$currentQueueEnvRef{queryString})
    {   $queryAnalInfo .=   "Query string : $$currentQueueEnvRef{queryString}\n\n";
    }

	#  Send result by email
    if (( defined $$annoENVRef{'SendMail'}) && ($$annoENVRef{'SendMail'}))
	{	send_result_email($$annoENVRef{SciMinerServerURL}."SciMiner/FinalResults/".$$currentQueueEnvRef{fileNameBase}.'/result.html', $$currentQueueEnvRef{email}, $queryAnalInfo );
	}

}










sub grif_SciMiner_Generate_Final_Result_File
{   my $finalResultDir          	= shift;
    my $finalResultWebDir       	= shift;
    my $resultHTMLFile         	 	= shift;
    my $resultSummaryHTML      	 	= shift;
    my $pmidListHTMLFile        	= shift;
    my $currentQueueEnvRef      	= shift;
    my $rankedHUGOID2contentRef     = shift;
	my $rankedHUGOIDsArrayRef    	= shift;
    my $fileNameBase            	= shift;
    my $serverBaseURL           	= shift;
    my $dbh                     	= shift;
    my $queryID                 	= shift;
    my $WholePMID               	= shift;
    my $cssFileName					= shift;
    my $sciminerJScriptFileName		= shift;
    my $hgncID2entrezGeneIDRef		= shift;

	my @foundHUGOIDs				= @{$rankedHUGOIDsArrayRef};
	my $totalGeneCount				= scalar (@foundHUGOIDs);
	
    #  Calculate line count
    my $initialNameCount        	= 0;
    my $optoutNameCount         	= 0;
    my $finalNameGeneCount      	= 0;
    my $initialSymbolCount      	= 0;
    my $optoutSymbolCount       	= 0;
    my $finalSymbolGeneCount    	= 0;
    my $finalMergedGeneCount    	= $totalGeneCount;
 
    my $serverURL   = $serverBaseURL."SciMiner/FinalResults/$fileNameBase/";
    my $SciMinerURL  = $serverBaseURL."SciMiner/";
    my $cssURL		= $cssFileName;
    my $mimiIconURL = "/SciMiner1.1/SciMiner/Images/cytoicon.jpg";
    my $EIcon		= "/SciMiner1.1/SciMiner/Images/E.jpg";

	open (FULLMESHRESULTHTML, ">$finalResultWebDir/MeSHCodeDistribution.html");
    open (RESULT, ">".$resultHTMLFile);
	
	print RESULT "  <head>
			        <title>SciMiner Result Report Page</title>
			        <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
			        <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
			        <script language=\"JavaScript1.2\" src=\"$sciminerJScriptFileName\"></script>
			        <style type=\"text/css\"> body {	margin-left:10px;	}</style>
			        </head>
			        <body bgcolor=\"#EAF4F4\">
			        <script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
			        <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Result Report Page</b></p>
			        <p class='titleBarName1'> <b>Congratulation! Your query with SciMiner has been successfully completed. Your query and search options were </b></p>

			        <a id=\"flag1\" href=\"#\" onclick=\"showhide('div1','flag1', 'search option summary');\" class=\"smallTextBold2\">[ HIDE search option summary ]</a>
					<div id=\"div1\" style=\"display:inline\">
			
			        <table border=\"1\" width=\"850\">
			        ";
				        
     
     print FULLMESHRESULTHTML "<head>
                <title>SciMiner Full MeSH Enrichment</title>
                <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
                <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
                <script language=\"JavaScript1.2\" src=\"$sciminerJScriptFileName\"></script>
                <style type=\"text/css\"> body {	margin-left:10px;	}</style>
                </head>
                <body bgcolor=\"#EAF4F4\">
				<script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
                <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Full MeSH Enrichment</b></p>
     						";
     						         
                

    # Running condition (options)
    my %itemContent		= ();
    my $otherOption		= '';
    my $enrichmentTest	= '';
    my $ppiSelection	= '';
    foreach my $keyTerm (sort(keys %{$currentQueueEnvRef}))
    {   if ((defined $keyTerm) && ($keyTerm ne "") && (defined $$currentQueueEnvRef{$keyTerm}))
        {   if ($keyTerm eq 'queryID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Query ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'analID')
        	{   $itemContent{0}		=	print_tmpKey_tmpTerm_for_selected_option('Analysis ID #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'userName')
        	{   $itemContent{1}		=	print_tmpKey_tmpTerm_for_selected_option('User name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'email')
        	{	$itemContent{2}		=	print_tmpKey_tmpTerm_for_selected_option('Email', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	#  Query information
        	elsif ($keyTerm eq 'queryName')
        	{   $itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Query name', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'queryString')
        	{   $itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Query string', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'count')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('PMID count #', $$currentQueueEnvRef{$keyTerm});
        	}

			#  Mining Mode / Species Extension information
        	elsif ($keyTerm eq 'speciesExtension')
        	{   $itemContent{6}		=	print_tmpKey_tmpTerm_for_selected_option('Species Extension', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'miningMode')
        	{   $itemContent{7}		=	print_tmpKey_tmpTerm_for_selected_option('Mining Mode', $$currentQueueEnvRef{$keyTerm});
        	}
        	
        	        	
        	#  Some analysis information
        	elsif ($keyTerm eq 'targetQueryNumber')
        	{   $itemContent{3}		=	print_tmpKey_tmpTerm_for_selected_option('Target Query #', $$currentQueueEnvRef{$keyTerm});
        	}elsif ($keyTerm eq 'bgQueryNumber')
        	{   $itemContent{4}		=	print_tmpKey_tmpTerm_for_selected_option('Background Query #', $$currentQueueEnvRef{$keyTerm});
        	}
        	elsif ($keyTerm eq 'PValueThreshold')
        	{   $itemContent{5}		=	print_tmpKey_tmpTerm_for_selected_option('P-value Threshold', $$currentQueueEnvRef{$keyTerm});
        	}

        	elsif (($keyTerm eq 'GeneEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene list";
        	}elsif (($keyTerm eq 'GOEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Gene Ontology";
        	}elsif (($keyTerm eq 'MeSHEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"MeSH term";
        	}elsif (($keyTerm eq 'PathwayEnrichmentCheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}$enrichmentTest		.=	"Pathway";
        	}elsif (($keyTerm eq 'PPICheck') && ($$currentQueueEnvRef{$keyTerm} =~ /on/i))
        	{   if ($enrichmentTest)
        		{	$enrichmentTest	.= ', ';
        		}
        		$enrichmentTest		.=	"Protein-Protein Interaction";
        	}elsif ($keyTerm eq 'PPISelection') 
        	{   $ppiSelection		.=	"(PPI Selection: ".$$currentQueueEnvRef{$keyTerm}.')';
        	}
        	
			#  Check for other options
        	elsif ($keyTerm eq 'phenotypeOnlyFilter')
        	{   $otherOption		.= "Remove_phenotype_gene, ";
        	}elsif ($keyTerm eq 'useLengthOption')
        	{   $otherOption		.= "Use_symbol_length_option, ";
        	}elsif ($keyTerm eq 'wordLengthThreshold')
        	{   $otherOption		.= "Always_accept_symbol_longer_than: $$currentQueueEnvRef{$keyTerm}";
        	}
        }
    }
    
    #  Print out sorted query/analysis options
    my @sortedKey	= sort {$a <=> $b} keys %itemContent;
    foreach my $sortedTermKey (@sortedKey)
    {   if (defined $itemContent{$sortedTermKey})
    	{	print RESULT $itemContent{$sortedTermKey};
    	}
    }

	#  Process enrichment options
	if ($enrichmentTest)
    {   if (($ppiSelection) && ($$currentQueueEnvRef{"PPICheck"} =~ /on/i))
    	{	$enrichmentTest	.= $ppiSelection;
    	}
    	print RESULT print_tmpKey_tmpTerm_for_selected_option('Enrichment tests', $enrichmentTest);
    }
    
    #  Score Threshold
    if ((defined $$currentQueueEnvRef{useScoreThreshold}) && ($$currentQueueEnvRef{useScoreThreshold}))
    {   print RESULT print_tmpKey_tmpTerm_for_selected_option('Score threshold', $$currentQueueEnvRef{scoreThreshold});
    }
    
    #  Process other options
    if ($otherOption)
    {   print RESULT print_tmpKey_tmpTerm_for_selected_option('Other', $otherOption);
    }

    print RESULT "</table><br>
            	  </div>
            	  ";
            
            
    #  Update the query table for numGene ($finalMergedGeneCount)
    $dbh->do("UPDATE query SET numGene=$finalMergedGeneCount WHERE queryID = $queryID");

            
    # Result summary
    print RESULT " <p align=\"center\" class=\"sectionTitleName1\">Summary</p>

	<p class='titleBarName1'><b>SciMiner has analyzed ($$currentQueueEnvRef{count}) &nbsp;articles. </b>&nbsp;&nbsp;&nbsp;&nbsp;<a href=\"pmidList.html\" onmouseover=\"Tip('Click here to view list of <b>document-based</b> summary result page')\" onmouseout=\"UnTip()\"><b>[Documents Summary]</b></a>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<a href=\"$fileNameBase"."_list.txt\" onmouseover=\"Tip('Click here to get the list of retrieved PMIDs.')\" onmouseout=\"UnTip()\">[PMIDs]</a>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<a href=\"javascript:retrieveDocumentScript('all','1','enw','$fileNameBase','none');\" onmouseover=\"Tip('You can download all of the above citations at once click. <br>For individual document, please go to <b>Documents Summary</b><br>')\" onmouseout=\"UnTip()\"><img src=\"$EIcon\">Citations</a></p>    
					";
    print RESULT " <p>
    					<font class='sectionTitleName2'>Number of found target : <a href=\"$resultSummaryHTML\"><b>$totalGeneCount</b></a></font>
    			   </p>
        ";


    # Top 10 most frequent genes
    print RESULT "  <a name=\"top10gene\"></a>
					<hr>
                    <p align=\"center\" class=\"sectionTitleName2\">Top 10 most frequent targets ... <a href=\"$resultSummaryHTML\">(All $totalGeneCount genes)</a></p>
                    <a id=\"flag2\" href=\"#top10gene\" onclick=\"showhide('div2','flag2', 'Top 10 most frequent targets');\" class=\"smallTextBold2\">[ HIDE Top 10 most frequent targets ]</a>
					<div id=\"div2\" style=\"display:inline\">
                    <table border=\"1\" width=\"740\">
                        <tr class='titleBarName1'>
                            <th width=\"45\">
                                Rank
                            </th>
                            <th width=\"55\" onmouseover=\"Tip('These are HUGO IDs. Click each ID to view the <b>HUGO detail</b>')\" onmouseout=\"UnTip()\">
                                HUGO
                            </th>
                            <th width=\"80\" onmouseover=\"Tip('These are HUGO approved official symbols. Click each symbol to view the NCBI Entrez Gene record.')\" onmouseout=\"UnTip()\">
                                Symbol
                            </th>
                            <th width=\"460\" onmouseover=\"Tip('These are HUGO approved official gene names.')\" onmouseout=\"UnTip()\">
                                Target Name
                            </th>
                            <th width=\"60\" onmouseover=\"Tip('<b>#Paper</b>: These are the numbers of <b>papers</b>.')\" onmouseout=\"UnTip()\">
                                #Paper
                            </th>
                            <th width=\"40\" onmouseover=\"Tip('<b>MiMI</b>: This will bring up Cytoscape program and visualize protein-protein interaction network of the target.<br> Protein-Protein Interaction data is based on the MiMI (Michigan Molecular Interactions).<br> This network retrieval employes the Cytoscape MiMI plugin.')\" onmouseout=\"UnTip()\">
                                MiMI
                            </th>
                        </tr>\n";
    for (my $j=0; $j <10; $j++)    
    {   if (defined $foundHUGOIDs[$j])
        {   # there are legitimate genes
            print RESULT "<tr><td>".($j+1)."</td><td><a href=\"$hgncLinkURL$$rankedHUGOID2contentRef{$foundHUGOIDs[$j]}->[1]\">".($$rankedHUGOID2contentRef{$foundHUGOIDs[$j]}->[1])."</a></td><td>";
            if (defined $$hgncID2entrezGeneIDRef{$foundHUGOIDs[$j]})
            {	my $tmpNCBIID	= $$hgncID2entrezGeneIDRef{$foundHUGOIDs[$j]};
            	print RESULT "<a href=\"$ncbiGeneLink$tmpNCBIID\">$$rankedHUGOID2contentRef{$foundHUGOIDs[$j]}->[0]</a>";
            }else
            {	print RESULT "<a href=\"$ncbiGeneSearch".($$rankedHUGOID2contentRef{$foundHUGOIDs[$j]}->[0])." AND Human[Orgn]\">$$rankedHUGOID2contentRef{$foundHUGOIDs[$j]}->[0]</a>";
            }
            
            
            my $pmidListDir = "pmid2ListDir/$foundHUGOIDs[$j].html";
            print RESULT  "</td><td>".($$rankedHUGOID2contentRef{$foundHUGOIDs[$j]}->[2])."</td><td><a href=\"$pmidListDir\">".($$rankedHUGOID2contentRef{$foundHUGOIDs[$j]}->[4])."</a></td><td>";
            if ((defined $$hgncID2entrezGeneIDRef{$foundHUGOIDs[$j]}) && ($$hgncID2entrezGeneIDRef{$foundHUGOIDs[$j]} ne ""))
            {	print RESULT "&nbsp;<a href=\"$mimiNameLink$$hgncID2entrezGeneIDRef{$foundHUGOIDs[$j]}\"><img src=\"$mimiIconURL\"></a>";
            }else
            {	print RESULT "&nbsp;";
            }
				print RESULT "</td></tr>\n";
        }else
        {   
        }
    }
    print RESULT "</table>";
    
    #  Generate a random number for symbol list file name
    my $tmpRandomNumber = int(rand(1000000000));
    my $RelPath			= "FinalResults/$fileNameBase/";
    my $MerSumFileName	= "SciMinerBase.MerSum.sorted.txt";
    
    print RESULT "<p class=\"titleBarName1\">Full result (<a href=\"$resultSummaryHTML\">HTML</a>,&nbsp;&nbsp;
				  <a href=\"SciMinerBase.MerSum.sorted.txt\">TXT</a>,&nbsp;&nbsp;
                  <a href=\"SciMinerBase.MerSum.sorted.xls\">EXCEL)</a></p><p>&nbsp;</p>
                  
                  <a name=\"viewNetwork\"></a>
                  </div>
    			  <p>&nbsp;</p><hr>
    			  
				  <form action='../../generateNetwork.cgi' method='POST' ENCTYPE='multipart/form-data'>
                  <p align=\"center\" class=\"sectionTitleName2\">View the interaction network (MiMI data)</p>
                  <p class=\"titleBarName1\">You can create an interaction network of the targets found above. Interaction data is based on the MiMI (Michigan Molecular Interactions) database. The network will be visualized by Cytoscape with the support of MiMI plugin.</p>
                  <select name=\"MinPaperMethod\" size=\"1\" onmouseover=\"Tip('Only identified targets satisfying the following criteria will be used.<br><br><b>Minimum # Paper</b>: Minimum number of papers per target<br>&nbsp;&nbsp;eg) Any target identified from 1 or 2 papers will be excluded <br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;when the threshold is set to 3<br><b>Minimum % Paper</b>: Minimum percentage of papers per target<br><b>Top # Target</b>: Only the top # ranked targets<br><b>Top % Target</b>: Only the top % percentage ranked targets')\" onmouseout=\"UnTip()\">
				        <option selected value=\"MinPaperCount\">Minimum # Paper</option>
				        <option value=\"MinPaperPercentage\">Minimum % Paper</option>
				        <option value=\"TopPaperCount\">Top # Paper</option>
				        <option value=\"TopPaperPercentage\">Top % Paper</option>
				  </select>
				  <input type=\"text\" name=\"MinTopPaper\" size=\"3\" value=\"1\" style=\"text-align: right\">
				  <input type=\"hidden\" name=\"RelPath\" value=\"$RelPath\">
				  <input type=\"hidden\" name=\"MerSumFileName\" value=\"$MerSumFileName\">
				  <input type=\"hidden\" name=\"RandomNumber\" value=\"$tmpRandomNumber\">
				  <input type=\"hidden\" name=\"TotalPMID\" value=\"$$currentQueueEnvRef{count}\">&nbsp;&nbsp;&nbsp;
				  <a href=\"javascript:network_generate_open_window();\"><b>Generate_Network</b></a>&nbsp;&nbsp;&nbsp;
				  <a href=\"javascript:download_symbols_open_window();\"><b>Download Symbols</b></a>
                  </form>
                        ";

    #  Read the MeSH term distribution
    if (-f "$finalResultWebDir/MeSHCodeDistribution.txt")
    {   # Make a link to the file
        #`ln -s $finalResultDir/MeSHCodeDistribution $finalResultWebDir/MeSHCodeDistribution.txt`;
        #`ln -s $finalResultDir/MeSHCodeDistribution $finalResultWebDir/MeSHCodeDistribution.xls`;        
		`ln -s $finalResultWebDir/MeSHCodeDistribution.txt $finalResultWebDir/MeSHCodeDistribution.xls`;        	
    	
    	
        open (MESH, "$finalResultWebDir/MeSHCodeDistribution.txt");
        my @top10MeSHLine = ();
        my $lineCnt = 0;
        while(<MESH>)
        {   my $line = $_;
            $line =~ s/\r|\n//g;
            if ($line =~ /^\#/)
            {   # This is a header line to be skipped
                next;
            }
            push @top10MeSHLine, $line;
            $lineCnt++;
        }
        close MESH;
        
        
        #  ---------------------------------------------------------------------
        my $resultString		= '';
        my $resultFullString	= '';
        my $tmpMeSHString		= '';
        my @tmpSplit			= ();
        # Top 10 most MeSH terms genes
        print RESULT "  <p>&nbsp;</p>
        				<hr>
			            <p align=\"center\" class=\"sectionTitleName2\">Top 10 most enriched <b>MeSH terms</b> (sorted by p-value)</p>
			            
			            <a id=\"flag3\" href=\"#flag3\" onclick=\"showhide('div3','flag3', 'Top 10 most enriched MeSH terms');\" class=\"smallTextBold2\">[ HIDE Top 10 most enriched MeSH terms ]</a>
						<div id=\"div3\" style=\"display:inline\">
						
						<table border=\"0\"  id=\"top10MeSHStatus\">
							<tr class='titleBarName1'>
								<th width='100'>
									Corpus size
								</th>
								<td width='60'>
									$$currentQueueEnvRef{count}
								</td>
								<th width='100'>
									Background(MedLine)
								</th>
								<td width='60'>
									$WholePMID
								</td>
								<th width='300' style='text-align= right;'>
									<a style=\"background-color:#F5CCF4;\" id='meshTableSwitch' onclick=\"javascript:show_hide_column('top10MeSHTable','3_4_5_8');\" onmouseover=\"Tip('Click here to toggle table details.')\" onmouseout=\"UnTip()\"><u>Switch table detail</u></a>
								</th>
							</tr>
						</table>

                        <table border=\"1\" id=\"top10MeSHTable\">
                            <tr class='titleBarName1'>
                                <th width=\"40\">
                                    Rank
                                </th>
                                <th width=\"300\" onmouseover=\"Tip('Click each term to view the <b>MeSH term detail</b>.')\" onmouseout=\"UnTip()\">
                                    MeSH Term
                                </th>
                                <th width=\"50\" bgcolor=\"$tgCColor\" onmouseover=\"Tip('</b>t+</t>: # of papers <b>with</b> the selected MeSH term in the <b>test</b> set.<br>Click each number to view a detailed paper list.')\" onmouseout=\"UnTip()\">
                                    t+
                                </th>
                                <th width=\"50\" bgcolor=\"$tgCColor\" onmouseover=\"Tip('</b>t-</t>: # of papers <b>without</b> the selected MeSH term in the <b>test</b> set.<br>Click each number to view a detailed paper list.')\" onmouseout=\"UnTip()\">
                                    t-
                                </th>
                                <th width=\"50\" bgcolor=\"$bgCColor\" onmouseover=\"Tip('</b>b+</t>: # of papers <b>with</b> the selected MeSH term in the <b>background</b> set.<br>Click each number to view a detailed paper list.')\" onmouseout=\"UnTip()\">
                                    b+
                                </th>
                                <th width=\"50\" bgcolor=\"$bgCColor\" onmouseover=\"Tip('</b>b-</t>: # of papers <b>without</b> the selected MeSH term in the <b>background</b> set.<br>Click each number to view a detailed paper list.')\" onmouseout=\"UnTip()\">
                                    b-
                                </th>
                                <th width=\"70\" onmouseover=\"Tip('P-value by Fishers Exact Test on 2x2 table<br><br><img src=&quot;/SciMiner1.1/SciMiner/Images/2x2Table.jpg&quot; width=&quot;50&quot; height=&quot;50&quot;><br><br>P-values lower than the specified threshold will be in <font color=&quot;red&quot;>red</font>')\" onmouseout=\"UnTip()\">
                                    p-value
                                </th>
                                <th width=\"50\" onmouseover=\"Tip('Ratio of t+ in the test set')\" onmouseout=\"UnTip()\">
                                    t-ratio
                                </th>
                                <th width=\"50\" onmouseover=\"Tip('Ratio of b+ in the background set')\" onmouseout=\"UnTip()\">
                                    b-ratio
                                </th>
                                <th width=\"70\" onmouseover=\"Tip('This implies the enrichment folds in the test set, calculated by<br>&nbsp;&nbsp;&nbsp;(t-ratio)&nbsp;&nbsp;/&nbsp;&nbsp;(b-ratio)<br><br>You may find <b>enrichment folds greater than 2 to be interesting</b>.<br><br><p style=&quot;background-color:$tgCColor&quot;>Enrichment in <b>test</b> set</p><p style=&quot;background-color:$bgCColor&quot;>Enrichment in <b>background</b> set</p><p style=&quot;background-color:$tgCColor&quot;>bZero: There is <b>NO</b> document associated with this MeSH term in the background set.</p>')\" onmouseout=\"UnTip()\">
		                                    enrichment<br>folds
		                                </th>
                            </tr>\n";
        
        
    	print FULLMESHRESULTHTML "<table border=\"0\"  id=\"top10MeSHStatus\">
							<tr class='titleBarName1'>
								<th width='100'>
									Corpus size
								</th>
								<td width='60'>
									$$currentQueueEnvRef{count}
								</td>
								<th width='100'>
									Background(MedLine)
								</th>
								<td width='60'>
									$WholePMID
								</td>
								<th width='300' style='text-align= right;'>
									<a id='meshTableSwitch' onclick=\"javascript:show_hide_column('top10MeSHTable','3_4_5_8');\" onmouseover=\"Tip('Click here to toggle table details.')\" onmouseout=\"UnTip()\"><u>Switch table detail</u></a>
								</th>
							</tr>
						</table>

                        <table border=\"1\" id=\"top10MeSHTable\">
                            <tr class='titleBarName1'>
                                <th width=\"40\">
                                    Rank
                                </th>
                                <th width=\"300\" onmouseover=\"Tip('Click each term to view the <b>MeSH term detail</b>.')\" onmouseout=\"UnTip()\">
                                    MeSH Term
                                </th>
                                <th width=\"50\" bgcolor=\"$tgCColor\" onmouseover=\"Tip('</b>t+</t>: # of papers <b>with</b> the selected MeSH term in the <b>test</b> set.<br>Click each number to view a detailed paper list.')\" onmouseout=\"UnTip()\">
                                    t+
                                </th>
                                <th width=\"50\" bgcolor=\"$tgCColor\" onmouseover=\"Tip('</b>t-</t>: # of papers <b>without</b> the selected MeSH term in the <b>test</b> set.<br>Click each number to view a detailed paper list.')\" onmouseout=\"UnTip()\">
                                    t-
                                </th>
                                <th width=\"50\" bgcolor=\"$bgCColor\" onmouseover=\"Tip('</b>b+</t>: # of papers <b>with</b> the selected MeSH term in the <b>background</b> set.<br>Click each number to view a detailed paper list.')\" onmouseout=\"UnTip()\">
                                    b+
                                </th>
                                <th width=\"50\" bgcolor=\"$bgCColor\" onmouseover=\"Tip('</b>b-</t>: # of papers <b>without</b> the selected MeSH term in the <b>background</b> set.<br>Click each number to view a detailed paper list.')\" onmouseout=\"UnTip()\">
                                    b-
                                </th>
                                <th width=\"70\" onmouseover=\"Tip('P-value by Fishers Exact Test on 2x2 table<br><br><img src=&quot;/SciMiner1.1/SciMiner/Images/2x2Table.jpg&quot; width=&quot;50&quot; height=&quot;50&quot;><br><br>P-values lower than the specified threshold will be in <font color=&quot;red&quot;>red</font>')\" onmouseout=\"UnTip()\">
                                    p-value
                                </th>
                                <th width=\"50\" onmouseover=\"Tip('Ratio of t+ in the test set')\" onmouseout=\"UnTip()\">
                                    t-ratio
                                </th>
                                <th width=\"50\" onmouseover=\"Tip('Ratio of b+ in the background set')\" onmouseout=\"UnTip()\">
                                    b-ratio
                                </th>
                                <th width=\"70\" onmouseover=\"Tip('This implies the enrichment folds in the test set, calculated by<br>&nbsp;&nbsp;&nbsp;(t-ratio)&nbsp;&nbsp;/&nbsp;&nbsp;(b-ratio)<br><br>You may find <b>enrichment folds greater than 2 to be interesting</b>.<br><br><p style=&quot;background-color:$tgCColor&quot;>Enrichment in <b>test</b> set</p><p style=&quot;background-color:$bgCColor&quot;>Enrichment in <b>background</b> set</p><p style=&quot;background-color:$tgCColor&quot;>bZero: There is <b>NO</b> document associated with this MeSH term in the background set.</p>')\" onmouseout=\"UnTip()\">
		                                    enrichment<br>folds
		                                </th>
                            </tr>\n";

        for (my $j=0; $j < scalar @top10MeSHLine; $j++)    
        {   if (defined $top10MeSHLine[$j])
            {   # there are legitimate MeSH
                @tmpSplit 		= split (/\t/, $top10MeSHLine[$j]);
                $tmpMeSHString 	= "<tr><td width=\"40\">".($j+1)."</td><td width=\"330\"><a href=\"$ncbiMeSHLinkURL$tmpSplit[1]\">$tmpSplit[1]</a></td>";
                $tmpMeSHString 	.= "<td width=\"50\">".print_if_not_zero($tmpSplit[3], "<a href=\"javascript:generate_pmid_list_from_mesh_html_simplified('$tmpSplit[3]','t_plus','2','$fileNameBase','$fileNameBase','$tmpSplit[0]');\">$tmpSplit[3]</a>")."</td>";
                $tmpMeSHString 	.= "<td width=\"50\">".print_if_not_zero($tmpSplit[4], "<a href=\"javascript:generate_pmid_list_from_mesh_html_simplified('$tmpSplit[4]','t_minus','3','$fileNameBase','$fileNameBase','$tmpSplit[0]');\">$tmpSplit[4]</a>")."</td>";
                $tmpMeSHString 	.= "<td width=\"50\"><a href=\"javascript:openNewWindow('$ncbiPubMedURL$tmpSplit[1]".'[Mesh:NoExp]'."');\">$tmpSplit[5]</a></td>";
                $tmpMeSHString 	.= "<td width=\"50\"><a href=\"javascript:openNewWindow('$ncbiPubMedURL"."All[Filter] NOT $tmpSplit[1]".'[Mesh:NoExp]'."');\">$tmpSplit[6]</a></td>";
               
                $tmpMeSHString 	.= "<td width=\"70\">";
                if ($tmpSplit[11] >= 0.01)
			    {	$tmpMeSHString .=  sprintf("%.2f",$tmpSplit[11]);
			    }elsif ($tmpSplit[11] == 0)
			    {	$tmpMeSHString .=  '0';
			    }else
			    {	$tmpMeSHString .=  sprintf("%.2e",$tmpSplit[11]);
			    }
                $tmpMeSHString 	.= "</td>";
                
                $tmpMeSHString 	.= "<td width=\"50\">".sprintf("%.2f",$tmpSplit[8])."</td>";
                $tmpMeSHString 	.= "<td width=\"50\">".sprintf("%.2f",$tmpSplit[9])."</td>";
		        if ($tmpSplit[10] eq $tgZeroTag )
				{	$tmpMeSHString .= "<td bgcolor=\"$bgCColor\">";
				}elsif ($tmpSplit[10] eq $bgZeroTag)
				{	$tmpMeSHString .= "<td bgcolor=\"$tgCColor\">";
				}elsif ($tmpSplit[10] > 1)
				{	$tmpMeSHString .= "<td bgcolor=\"$tgCColor\">";
				}elsif ($tmpSplit[10] < 1)
				{	$tmpMeSHString .= "<td bgcolor=\"$bgCColor\">";
				}else
				{	$tmpMeSHString .= "<td>";
				}
				$tmpMeSHString	.= sprintf("%.1f",$tmpSplit[10])."</td></tr>\n";
                 
                 #  Print out the result
                 print FULLMESHRESULTHTML $tmpMeSHString;
                 
                 if ($j < 10)
                 {	print RESULT $tmpMeSHString;
                 }

            }else
            {   #  Do nothing if not defined
            }
        }    # for
        
        print RESULT "</table>";
        print RESULT "<p class=\"titleBarName1\">Full result (<a href=\"MeSHCodeDistribution.html\">HTML</a>,&nbsp;&nbsp;
        						   <a href=\"MeSHCodeDistribution.txt\">TXT</a>,&nbsp;&nbsp;
                                   <a href=\"MeSHCodeDistribution.xls\">EXCEL)</a></p>
                      </div>";
		
		print FULLMESHRESULTHTML "</table><br>";
        print FULLMESHRESULTHTML "<p class=\"titleBarName1\">Full result (<a href=\"MeSHCodeDistribution.html\">HTML</a>,&nbsp;&nbsp;
        						   <a href=\"MeSHCodeDistribution.txt\">TXT</a>,&nbsp;&nbsp;
                                   <a href=\"MeSHCodeDistribution.xls\">EXCEL)</a><br></p>";
    }
    close FULLMESHRESULTHTML;

    print RESULT "
            <p>&nbsp;</p>
            <hr>
            <p><a href=\"../../main2.html\">SciMiner Homepage</a></p>
            </body>
            </html>";
    
    close RESULT;
}









# ----------------------------------------------------------------------------
#  Modules related to generating SciMiner HTML results
# ----------------------------------------------------------------------------
sub grif_generate_summary_html
{	my $finalResultDir              = shift;
	my $finalResultWebDir			= shift;
    my $summaryFile                 = shift;
    my $resultHTMLFile              = shift;
    
    my $currentQueueEnvRef          = shift;
    my $fileNameBase                = shift;
    my $serverBaseURL               = shift;
    
    my $pmid2journalRef				= shift;
    my $pmid2TitleRef               = shift;
    my $pmid2AbstractRef            = shift;
    
    my $numPassGeneCountByPMIDRef   = shift;

	my $cssFileName					= shift;
	my $sciminerJScriptFileName		= shift;
	my $hgncID2entrezGeneIDRef		= shift;
	my $entrezGeneID2hgncIDRef		= shift;
	my $hgncID2pmidGRIFubmedRef     	= shift;
	my $pmid2hgncIDContentRef		= shift;

	my $hgncID2approvedSymbolRef	= shift;
	my $hgncID2approvedNameRef		= shift;
	my $hgncID2pmidCountRef			= shift;

    
    #  Read the summary file 
    my @rankedHUGOIDs           	= ();
    my %rankedHUGOID2content    	= ();
    my %HUGOID2PMIDs            	= ();

    #  Create temporary directory for HUGOID2Content, PMID2Content
    my $hugoID2ContDir          = $finalResultWebDir.'hugoID2ContDir/';
    my $pmid2ContDir            = $finalResultWebDir.'pmid2ContDir/';
    my $pmid2ListDir            = $finalResultWebDir.'pmid2ListDir/';  
    my $tmpWorkingDir			= $finalResultWebDir.'Temp/';  
    mkdir ($hugoID2ContDir)     || print "";
    mkdir ($pmid2ContDir)       || print "";   
    mkdir ($pmid2ListDir)       || print ""; 
    mkdir ($tmpWorkingDir)		|| print "";

    #  Specify the URL links
    my $serverURL   	= $serverBaseURL."SciMiner/FinalResults/$fileNameBase/";
    my $SciMinerURL  	= $serverBaseURL."SciMiner/";
    my $cssURL			= $cssFileName;
    my $mimiIconURL 	= "/SciMiner1.1/SciMiner/Images/cytoicon.jpg";

    #  Generate individual result files
    open (SUMMARY, $summaryFile);
    while(<SUMMARY>)
    {   my $line = $_;
    	if ($line =~ /^#/)
    	{	next;
    	}
        $line =~ s/\r|\n//g;
        my @tmpSplit = split (/\t/, $line);

        $HUGOID2PMIDs{$tmpSplit[1]} = $tmpSplit[6];
        pop @tmpSplit;
        $rankedHUGOID2content{$tmpSplit[1]} = \@tmpSplit;
        push @rankedHUGOIDs, $tmpSplit[1];
        
        #  Generate hugoID2Cont file
        grif_generate_hugoID2Cont_file(
        		$hugoID2ContDir, $tmpSplit[1], $hgncID2pmidGRIFubmedRef, $rankedHUGOID2content{$tmpSplit[1]}, 
        		$serverURL, $SciMinerURL, $cssFileName, $hgncID2entrezGeneIDRef);
        
        #  Generate pmid2List file	- Listing mined genes for each pmid
        grif_generate_pmid2List_html(
        	$tmpSplit[1], $pmid2ListDir, $HUGOID2PMIDs{$tmpSplit[1]}, $pmid2ContDir, 
        	$tmpSplit[0], $tmpSplit[2], $tmpSplit[3], $tmpSplit[4], 
        	$serverURL, $pmid2TitleRef, $numPassGeneCountByPMIDRef, 
        	$pmid2journalRef, $SciMinerURL, $cssFileName, $$currentQueueEnvRef{InstitutionCheck}, 
        	$hgncID2entrezGeneIDRef, $fileNameBase);

        #  Generate pmid2Cont file        
        grif_generate_pmid2Cont_file(
        	$HUGOID2PMIDs{$tmpSplit[1]}, $pmid2ContDir, $pmid2ListDir, $hugoID2ContDir, 
        	$tmpSplit[1], $pmid2hgncIDContentRef, $serverURL, $pmid2TitleRef, 
        	$pmid2AbstractRef, $SciMinerURL, $cssFileName, $$currentQueueEnvRef{InstitutionCheck}, 
        	$fileNameBase, $hgncID2approvedSymbolRef, $hgncID2approvedNameRef, $hgncID2pmidCountRef, $hgncID2entrezGeneIDRef);
    }
    close SUMMARY;


	#  -------------------------------------------------------------------------    
    #  Start to write the result summary HTML file
	#  -------------------------------------------------------------------------    
    open (RESULT, ">".$resultHTMLFile);
	print RESULT    "<head>
		            <title>SciMiner Result Report Page</title>
		            <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
		            <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
		            <script language=\"JavaScript1.2\" src=\"sciminer.js\"></script>
		            <style type=\"text/css\"> body {	margin-left:10px;	}</style>
		            </head>
		            <body bgcolor=\"#EAF4F4\">
		            <script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
		            <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>SciMiner Mined Target Summary Page</b></p>
					<hr>
					<p class=\"titleBarName1\"><b>Here are the targets (genes/proteins) that SciMiner has found from NCBI resources (Gene2PubMed or GeneRIF).</b></p>
					";
  
    # Generate table for the actual gene
    print RESULT "  <table border=\"1\" width=\"700\">
                        <tr class=\"titleBarName1\">
                            <th width=\"40\">
                                Rank
                            </th>
                            <th width=\"40\" onmouseover=\"Tip('These are HUGO IDs. Click each ID to view the <b>HUGO detail</b>.')\" onmouseout=\"UnTip()\">
                                HUGO
                            </th>
                            <th width=\"60\" onmouseover=\"Tip('These are HUGO approved official symbols. Click each symbol to view the NCBI Entrez Gene record.')\" onmouseout=\"UnTip()\">
                                Symbol
                            </th>
                            <th width=\"420\" onmouseover=\"Tip('These are HUGO approved official gene names.')\" onmouseout=\"UnTip()\">
                                Target Name
                            </th>
                            <th width=\"50\" onmouseover=\"Tip('<b>#Paper</b>: These are the numbers of <b>papers</b>.')\" onmouseout=\"UnTip()\">
                                #Paper
                            </th>
                            <th width=\"40\" onmouseover=\"Tip('<b>MiMI</b>: This will bring up Cytoscape program and visualize protein-protein interaction network of the target.<br> Protein-Protein Interaction data is based on the MiMI (Michigan Molecular Interactions).<br> This network retrieval employes the Cytoscape MiMI plugin.')\" onmouseout=\"UnTip()\">
                                MiMI
                            </th>
                            
                            
                        </tr>\n";


    for (my $j=0; $j <= $#rankedHUGOIDs; $j++)    
    {   if (defined $rankedHUGOID2content{$rankedHUGOIDs[$j]})
        {   print RESULT "<tr><td>".($j+1)."</td><td><a href=\"$hgncLinkURL$rankedHUGOIDs[$j]\">".($rankedHUGOIDs[$j])."</a></td><td>";
            if (defined $$hgncID2entrezGeneIDRef{$rankedHUGOIDs[$j]})
            {	my $tmpNCBIID	= $$hgncID2entrezGeneIDRef{$rankedHUGOIDs[$j]};
            	print RESULT "<a href=\"$ncbiGeneLink$tmpNCBIID\">$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]</a>";
            }else
            {	print RESULT "<a href=\"$ncbiGeneSearch".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0])." AND Human[Orgn]\">$rankedHUGOID2content{$rankedHUGOIDs[$j]}->[0]</a>";
            }
				
            print RESULT "</td><td>".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[2])."</td><td>";
             
             my $pmidListDir = "pmid2ListDir/$rankedHUGOIDs[$j].html";
             print RESULT   "<a href=\"$pmidListDir\">".($rankedHUGOID2content{$rankedHUGOIDs[$j]}->[4])."</a></td><td>";
            if ((defined $$hgncID2entrezGeneIDRef{$rankedHUGOIDs[$j]}) && ($$hgncID2entrezGeneIDRef{$rankedHUGOIDs[$j]} ne ""))
            {	print RESULT "<a href=\"$mimiNameLink$$hgncID2entrezGeneIDRef{$rankedHUGOIDs[$j]}\"><img src=\"$mimiIconURL\"></a>";
            }else
            {	print RESULT "&nbsp;";
            }
				print RESULT "</td></tr>\n";
        }
    }


    print RESULT "</table>\n
            <p>&nbsp;</p>
            <p><a href=\"intro2.html\"><font class=\"sectionTitleName2\">SciMiner Homepage</font></a></p>
            </body>
            </html>";
    
    close RESULT;
    LogGRIFQuery("! Generating summary.html is completed");
    return(\%rankedHUGOID2content, \@rankedHUGOIDs);
}






sub grif_generate_base_pmid_list_html
{   my $finalResultDir          = shift;
    my $finalResultWebDir       = shift;
    my $pmidListHTMLFile        = shift;
    my $pmid2hgncIDCountRef   	= shift;
    my $fileNameBase            = shift;
    
    my $serverBaseURL           = shift;
    my $pmid2TitleRef           = shift;
    my $docLinkDir              = shift;
    my $corpusDataOriginalDir   = shift;
    my $pmid2journalRef			= shift;
    my $cssFileName				= shift;
    my $InstitutionCheck		= shift;

    my $serverURL   = $serverBaseURL."SciMiner/FinalResults/$fileNameBase/";
    my $cssURL		= $cssFileName;
	my $MIcon		= "/SciMiner1.1/SciMiner/Images/M.jpg";
	my $PIcon		= "/SciMiner1.1/SciMiner/Images/P.jpg";
	my $EIcon		= "/SciMiner1.1/SciMiner/Images/E.jpg";
	my $HHIcon		= "/SciMiner1.1/SciMiner/Images/HL.jpg";
	my $HMIcon		= "/SciMiner1.1/SciMiner/Images/HL.jpg";			
	my $HLIcon		= "/SciMiner1.1/SciMiner/Images/HL.jpg";	
	my $BLANK		= "/SciMiner1.1/SciMiner/Images/BLANK.jpg";							

	
    open (RESULT, ">".$pmidListHTMLFile);
    
	print RESULT    "<head>
		            <title>PMID list for your query</title>
		            <meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\" />
		            <link rel=\"stylesheet\" href=\"$cssURL\" type=\"text/css\" />
		            <script language=\"JavaScript1.2\" src=\"sciminer.js\"></script>
		            <style type=\"text/css\"> body {	margin-left:10px;	}</style>
		            </head>
		            
		            <body bgcolor=\"#EAF4F4\">
		            <script language=\"JavaScript1.2\" src=\"wz_tooltip.js\"></script>
		            <p class=\"pageName\" align=\"center\"> <b><a name=\"TOP\"></a>Here are the PMIDs for your query</b></p>
					<hr>
		            <table border=\"1\" width=\"850\">
                        <tr class=\"titleBarName1\">
                            <th width=\"80\">
                                PMID
                            </th>
                            <th width=\"480\">
                                TITLE
                            </th>
                            <th width=\"90\" onmouseover=\"Tip('Click here to view the identified targets from this paper.')\" onmouseout=\"UnTip()\">
                                # of Targets
                            </th>
                            <th width=\"90\" onmouseover=\"Tip('<b>Links</b>: Provides links to the following resources<br><img src=&quot;/SciMiner1.1/SciMiner/Images/M.jpg&quot;>: <b>M</b>EDLINE Record<br><img src=&quot;/SciMiner1.1/SciMiner/Images/E.jpg&quot;>: <b>E</b>ndNote citation<br><img src=&quot;/SciMiner1.1/SciMiner/Images/HL.jpg&quot;>: (full) <b>H</b>TML page<br><img src=&quot;/SciMiner1.1/SciMiner/Images/P.jpg&quot;>: NCBI <b>P</b>ubMed<br><br><b>Make sure that your browser pop-up is not blocked.</b>')\" onmouseout=\"UnTip()\">
                                Links
                            </th>
                            <th width=\"110\" onmouseover=\"Tip('Name of the journal')\" onmouseout=\"UnTip()\">
                                Journal
                            </th>
                        </tr>\n";
    

    #  open the origial list file
    open (LIST, $finalResultWebDir.$fileNameBase."_list.txt") || LogGRIFQuery("! Can't find $finalResultWebDir $fileNameBase"."_list.txt");
    my @pmidLists               = keys %{$pmid2hgncIDCountRef};

	my $tmpLineCount			= 1;
	my @tmpKeys					= ();
	my $links					= '';
	my $endnotelinks			= '';
    
    #  Sort the list of PMIDs by the number of genes found by SciMiner
    my @sortedPMIDsByGeneCount		= sort {$$pmid2hgncIDCountRef{$b} <=> $$pmid2hgncIDCountRef{$a}} @pmidLists;
    my $genesBySciMinerFile			= '';		
    if (defined $sortedPMIDsByGeneCount[0])
    {   foreach my $pmid (@sortedPMIDsByGeneCount)
        {   #  Check if there is any gene identified by SciMiner
            $genesBySciMinerFile = "pmid2ContDir/$pmid.html";
            print RESULT "  <tr><td width=\"80\">$pmid</td><td width=\"480\">$$pmid2TitleRef{$pmid}</td><td width=\"90\">";
                                
            if ($$pmid2hgncIDCountRef{$pmid} == 0)
            {   print RESULT  "&nbsp;";
            }else
            {   print RESULT  "<a href=\"$genesBySciMinerFile\">$$pmid2hgncIDCountRef{$pmid}</a>";
            }

            print RESULT "</td><td width=\"90\" width=\"90\" onmouseover=\"Tip('<b>Links</b>: Provides links to the following resources<br><img src=&quot;/SciMiner1.1/SciMiner/Images/M.jpg&quot;>: <b>M</b>EDLINE Record<br><img src=&quot;/SciMiner1.1/SciMiner/Images/E.jpg&quot;>: <b>E</b>ndNote citation<br><img src=&quot;/SciMiner1.1/SciMiner/Images/HL.jpg&quot;>: (full) <b>H</b>TML page<br><img src=&quot;/SciMiner1.1/SciMiner/Images/P.jpg&quot;>: NCBI <b>P</b>ubMed<br><br><b>Make sure that your browser pop-up is not blocked.</b>')\" onmouseout=\"UnTip()\">";
			print RESULT "<a href=\"javascript:retrieveDocumentScript('single','$pmid','medline','$fileNameBase','none');\"><img src=\"$MIcon\"></a>";
