sub process_medline_html_document_with_mesh_tree_grif_simplified
{	my $FILESDIR                = shift;
	my $PMIDListRef				= shift;
    my $annoENVRef              = shift;
    my $pmid2TitleRef           = shift;
    my $pmid2AbstractRef        = shift;

	my $MeSHdescID2termRef	    = shift;
	my $MeSHTerm2descIDRef	    = shift;
	my $MeSHTerm2DistRef	    = shift;
	
	my $dbh					    = shift;
	my $pmid2langRef            = shift;
	
    my %documentSource  = ();
    my %processedStatus = ();
    my $htmlFormat      = '';
    
    foreach my $pmid (@{$PMIDListRef})
    {   parse_medline_for_grif_simplified (
        		$FILESDIR.$pmid.".medline", $pmid, $pmid2TitleRef, $pmid2AbstractRef, 
        		$MeSHdescID2termRef, $MeSHTerm2descIDRef, $MeSHTerm2DistRef,
         		$dbh);
    }
}





sub parse_medline_for_grif_simplified
{	my $medlineFile			= shift;
	my $pmid                = shift;
    my $pmid2TitleRef       = shift;
    my $pmid2AbstractRef    = shift;
    
    my $MeSHdescID2termRef	= shift;
	my $MeSHTerm2descIDRef	= shift;
	my $MeSHTerm2DistRef	= shift;
	
	my $dbh					= shift;
    
    open (FILE, $medlineFile);
    my $previousField   = '';
    my $titleString     = '';
    my $abstractString  = '';
    
    my %article         = ();
    my $setToExtract    = 0;
    
    my @MeSHTermInDoc	= ();
    while(<FILE>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        if ($line eq "")
        {   next;
        }elsif (substr($line,4,1) eq '-')
        {   $setToExtract   = 0;
        }
        
        if (substr($line,4,1) eq '-')
        {	if ( $line =~ /^TI  - / )
		    {   $previousField  = 'TI';
		        $article{$previousField} = $';  #'
		        $setToExtract   = 1;
		    }elsif ( $line =~ /^AB  - / )
		    {   $previousField  = 'AB';
		        $article{$previousField} = $';  #'
		        $setToExtract   = 1;
		    }elsif ( $line =~ /^MH  - \*?(\S.*)/ )
		    {	$previousField  = 'MH';
				my @tmpSplit 	= split (/\//, $1);   
				push @MeSHTermInDoc, $tmpSplit[0];
		    }else
		    {	$previousField	= 'OTHER';
		    	$article{$previousField} = '';
		    }
        }else
        {	$article{$previousField} .= substr($line,5);  #'
        }
    }
    close FILE;
    
	#  Assign title and abstract
	if ((defined $article{TI}) && ($article{TI} ne ""))
	{	$article{TI}			=~ s/\"/\\\"/g;
		$$pmid2TitleRef{$pmid}	= $article{TI};
	}
	if ((defined $article{AB}) && ($article{AB} ne ""))
	{	$article{AB}			=~ s/\"/\\\"/g;
		$$pmid2AbstractRef{$pmid}	= $article{AB};
	}
	
    #  Explore MeSH tree to extract implicit MeSH Terms
    #my %DocMeSHDescID2ExplicitCode 	= ();
    my %DocMeshTreeCode2ExplicitCode= ();
    my @codeSplit					= ();
    my $tmpCode						= '';
    my $tmpDescIDString				= '';
    
    #  DocMeSHCode2ExplicitCode E == explict, I == implicit
    if (defined $MeSHTermInDoc[0])
    {   foreach my $localMeSHTerm (@MeSHTermInDoc)
    	{   if (defined $$MeSHTerm2descIDRef{$localMeSHTerm})
    		{	$tmpDescIDString .= $$MeSHTerm2descIDRef{$localMeSHTerm}.';';
    			
    			#print "!ERROR: $pmid $DBI::errstr\n" ;   
    		}
    	}
    	if( $tmpDescIDString ne "")
    	{	$dbh->do("INSERT INTO `docmeshg2p` (pmid, explicit, descIDString) VALUES ($pmid, \"E\", \"$tmpDescIDString\")") || LogGRIFQuery("!ERROR: docmeshg2p insertion $pmid");
    	}
    }
    return(1);
}   










