         		$MeSHTerm2descIDRef, $MeSHCode2DistRef, $dbh);
    }
}










sub parse_medline_for_grif
{	my $medlineFile			= shift;
	my $pmid                = shift;
    my $pmid2TitleRef       = shift;
    my $pmid2AbstractRef    = shift;
    my $mtreeID2descIDRef	= shift;
    
	my $mtreeID2treeCodeRef	= shift;
	my $treeCode2mtreeIDRef	= shift;
	my $treeCode2descIDRef	= shift;
	my $MeSHdescID2termRef	= shift;
	my $descID2treeCodesRef	= shift;
	
	my $MeSHTerm2descIDRef	= shift;
	my $MeSHCode2DistRef	= shift;
	my $dbh					= shift;
    
    open (FILE, $medlineFile);
    my $previousField   = '';
    my $titleString     = '';
    my $abstractString  = '';
    
    my %article         = ();
    my $setToExtract    = 0;
    
    my @MeSHTermInDoc	= ();
    while(<FILE>)
    {   my $line = $_;
        $line =~ s/\r|\n//g;
        if ($line eq "")
        {   next;
        }elsif (substr($line,4,1) eq '-')
        {   $setToExtract   = 0;
        }
        
        if (substr($line,4,1) eq '-')
        {	if ( $line =~ /^TI  - / )
		    {   $previousField  = 'TI';
		        $article{$previousField} = $';  #'
		        $setToExtract   = 1;
		    }elsif ( $line =~ /^AB  - / )
		    {   $previousField  = 'AB';
		        $article{$previousField} = $';  #'
		        $setToExtract   = 1;
		    }elsif ( $line =~ /^MH  - \*?(\S.*)/ )
		    {	$previousField  = 'MH';
				my @tmpSplit 	= split (/\//, $1);   
				push @MeSHTermInDoc, $tmpSplit[0];
		    }else
		    {	$previousField	= 'OTHER';
		    	$article{$previousField} = '';
		    }
        }else
        {	$article{$previousField} .= substr($line,5);  #'
        }
    }
    close FILE;
    
	#  Assign title and abstract
	if ((defined $article{TI}) && ($article{TI} ne ""))
	{	$article{TI}			=~ s/\"/\\\"/g;
		$$pmid2TitleRef{$pmid}	= $article{TI};
	}
	if ((defined $article{AB}) && ($article{AB} ne ""))
	{	$article{AB}			=~ s/\"/\\\"/g;
		$$pmid2AbstractRef{$pmid}	= $article{AB};
	}
	
    #  Explore MeSH tree to extract implicit MeSH Terms
    #my %DocMeSHDescID2ExplicitCode 	= ();
    my %DocMeshTreeCode2ExplicitCode= ();
    my @codeSplit					= ();
    my $tmpCode						= '';
    
    #  DocMeSHCode2ExplicitCode E == explict, I == implicit
    if (defined $MeSHTermInDoc[0])
    {   foreach my $localMeSHTerm (@MeSHTermInDoc)
    	{   if (defined $$MeSHTerm2descIDRef{$localMeSHTerm})
    		{	my @tmpTreeCodes = @{$$descID2treeCodesRef{$$MeSHTerm2descIDRef{$localMeSHTerm}}};
    			foreach my $code (@tmpTreeCodes)
				{   #$DocMeSHDescID2ExplicitCode{$$treeCode2descIDRef{$code}}	= 'E';
				    $DocMeshTreeCode2ExplicitCode{$code}                        = 'E';
				    # ----------------------------------------------------------
					# 08/15/2008: In order to use ExplicitOnly, no tree traversing
					#             is done any more
					# ----------------------------------------------------------
					#@codeSplit = split (/\./, $code);
					#pop @codeSplit;
					#
					#while(defined $codeSplit[0])
					#{   $tmpCode = join ('.', @codeSplit);
					#	#if (not defined $DocMeSHDescID2ExplicitCode{$$treeCode2descIDRef{$tmpCode}})
					#	#{   $DocMeSHDescID2ExplicitCode{$$treeCode2descIDRef{$tmpCode}} = 'I';
					#	#}
					#	if (not defined $DocMeshTreeCode2ExplicitCode{$tmpCode})
					#	{   $DocMeshTreeCode2ExplicitCode{$tmpCode}                     = 'I';
					#	}
					#	pop @codeSplit;
					#}
				}
    		}else
    		{ 	#  Insert MeSH terms without current descID assigned
    			$dbh->do("INSERT INTO `docmeshg2p` (pmid, explicit, descID, descTermNoTree) VALUES ($pmid, \"E\", 0, \"$localMeSHTerm\")") || LogGRIFQuery("!ERROR: docmeshg2p insertion $pmid $localMeSHTerm -- no treecode term"); 
    		}
    	}
    	
    	#  Update the SciMinerDB 'docmesh' table for newly processed medline documents;
    	foreach my $code (keys %DocMeshTreeCode2ExplicitCode)
    	{	#LogGRIFQuery("INSERT INTO `docmeshg2p` (pmid, explicit, descID, treeCode) VALUES ($pmid, \"$DocMeshTreeCode2ExplicitCode{$code}\", $$treeCode2descIDRef{$code}, \"$code\")");
    		$dbh->do("INSERT INTO `docmeshg2p` (pmid, explicit, descID, treeCode) VALUES ($pmid, \"$DocMeshTreeCode2ExplicitCode{$code}\", $$treeCode2descIDRef{$code}, \"$code\")") || LogGRIFQuery("!ERROR: docmeshg2p insertion $pmid $code");
    			#print "!ERROR: $pmid $DBI::errstr\n" ;   
    	}
    }
    return(1);
}   











1;
